window.IDW_ITEMS_TR=window.IDW_ITEMS_TR||{};window.IDW_ITEMS_TR["de"]={"ICON-0001":{"nm":"Fußabdruck","de":"Ein einzelner Erdfleck auf dem Holzboden. Jemand ist lange hin und her gegangen – und hat dann doch einen Schritt weitergesetzt. Was ein Fußabdruck festhält, ist nicht die Zeit des Verweilens, sondern der eine Moment, in dem die Entscheidung fiel zu gehen."},"ICON-0002":{"nm":"Laterne","de":"Kaum berührt die Flamme den Docht, weicht die Dunkelheit Schritt für Schritt zurück. Die kleine Wärme, die Fingerspitzen aufwärmt – auf ihr ließen einst Menschen Wünsche davonschweben. Eine Laterne wird nicht angezündet, um zu leuchten, sondern um einfach da zu sein."},"ICON-0003":{"nm":"Schleife","de":"Ein einziger Knoten verpackt ein Gefühl sorgfältig ein. Die gebende Hand bindet ihn locker, die empfangende möchte ihn langsam lösen. Was eine Schleife zusammenhält, ist nicht die Schachtel – sondern das aufgeregte Kribbeln kurz vor dem Überreichen."},"ICON-0004":{"nm":"Briefkasten","de":"Mit weit geöffnetem rotem Mund steht er an der Straßenecke. Auch in Zeiten, in denen handgeschriebene Briefe selten geworden sind, wartet dieser kleine Kasten bis zuletzt auf jemandes Nachricht. Das Gefäß, das in dem Moment am hellsten strahlt, wenn es sich leert."},"ICON-0005":{"nm":"Insel-Minikarte","de":"Zusammengefaltet passt sie in die Hosentasche, ausgebreitet liegen Meer und Höhenzüge nebeneinander auf einem Blatt. Für den, der zum ersten Mal landet, ist jede Ecke noch ein ungeöffnetes Versprechen. Wer sie entfaltet, macht selbst aus einer kleinen Insel eine weite Welt."},"ICON-0006":{"nm":"Mikrofon","de":"Ein halber Takt, in dem man vor dem ersten Ton kurz durchatmet. Wenn man weiß, dass der Blick des Saals an einem einzigen Wort hängt, zittern die Fingerspitzen. Ein Mikrofon verstärkt nicht nur den Klang – es trägt dieses Zittern bis ans Ende."},"ICON-0007":{"nm":"Uhr","de":"Der Sekundenzeiger rastet nie aus, doch niemand drängt dich. Wie viele Nächte bis zum Debüt, wie viele Minuten bis zur Bühne – auf dem Zifferblatt drehen sich Warten und Vorfreude im gleichen Tempo. Die Zeit im Blick zu behalten heißt, das eigene Herz zu beruhigen."},"ICON-0008":{"nm":"Notizheft","de":"Das Ding mit den meisten leeren Seiten. Choreografie-Wege, nächtliche Vorsätze, nie abgeschickte Worte – all das sammelt sich hier. Wer es aufschlägt, hört, wie das gestrige Ich das heutige leise anspricht."},"ICON-0009":{"nm":"Stempel","de":"Einmal in rote Stempelfarbe tauchen und fest aufdrücken – ein Versprechen ist klar vermerkt. Schwerer als Schrift und deutlicher als Worte. Am Ende jedes Dokuments haben Menschen ihr Herz in diesen kleinen Stempel gelegt, statt ihren Namen zu schreiben."},"ICON-0010":{"nm":"Untersetzer","de":"Er senkt sich so tief wie möglich, um anderes zu tragen. Ganz unten, still ausharrend, damit das darüber Stehende nicht wankt. Auch ohne zu glänzen steckt in ihm eine stille Fürsorge, die verhindert, dass etwas fällt."},"ICON-0011":{"nm":"Briefmarke","de":"Ein kleines Bild, das man einst mit einem Lecken an die Ecke klebte. Der ehrlichste Preis, den man für ein Gefühl auf Reisen zahlt. Eine briefmarkengroße Landschaft begleitet den Brief bis ans andere Ende des Meeres."},"ICON-0012":{"nm":"Fähnchen-Pin","de":"In eine Karte gesteckt bedeutet er: ‚Ich bin bis hierher gekommen.' Keine Eroberung, sondern ein Protokoll – und eine stille Ermutigung für alle, die nach einem kommen. Dieses Fähnchen schiebt einem wortlos den Rücken zu: Noch einen Schritt weiter."},"ICON-0013":{"nm":"Ast","de":"Ein Ast, der sich einmal gebogen hat, vergisst nicht mehr, wie man nicht bricht. Jede Stelle, an der er dem Wind nachgegeben hat, trägt einen harten Knorren – und der alte Wald flüstert im Wind: wahre Stärke kommt von dem, was man gut überstanden hat."},"ICON-0014":{"nm":"Knopf","de":"Geöffnet und wieder geschlossen hält er den Kragen zusammen. Ein kleiner Kreis, der leise die Morgenkälte und ein plötzliches Schamgefühl abhält. Erst wenn er abspringt, merkt man, wie viel Platz er einnahm."},"ICON-0015":{"nm":"Umschlag","de":"In dem Moment, in dem man ihn verschließt, wird er zum Geheimnis. Was darin steckt, weiß nur der Empfänger. Eine einzige Papierschicht – die dünnste und liebevollste Tür zwischen einem Herz und der Welt."},"ICON-0016":{"nm":"Schachtel","de":"Mit vier ordentlichen Ecken nimmt sie großzügig alles auf. Beim Umzug birgt sie Erinnerungen, an Feiertagen Geschenke, sonst allerlei Kleinkram. Das Innere eines geschlossenen Deckels ist stets voll mit jemandes ‚Später'."},"ICON-0017":{"nm":"Türgriff","de":"Das erste, das zwischen Tür und Mensch die Hand ausstreckt. Erst ein Zug, und Innen und Außen sind verbunden. Jede Entscheidung, hinein- oder hinauszugehen, verabschiedet sich mit einem einmaligen Druck dieser kühlen Hand."},"ICON-0018":{"nm":"Löffel","de":"Mit der hohlen Mulde hebt er still warme Brühe an. Ein Werkzeug, das an den einen Schluck Wärme erinnert, den die Mutter pustend als Erste reichte. Der am häufigsten den Mund berührende, zärtlichste Helfer am Tisch."},"ICON-0019":{"nm":"Hausschuhe","de":"Kaum hat man die Schwelle überquert, holt der Fuß erstmals tief Luft. Der Klang eines Abends, an dem man das harte Klacken des Tages abstreift und in kleinen Schritten wandert. Ein ordentlich abgestelltes Paar vor der Tür sagt: ‚Du bist jetzt zu Hause.'"},"ICON-0020":{"nm":"Schlüssel","de":"Man lernt erst öffnen, dann schließen. Wärmt sich in der Handfläche auf und hält dann unversehens vor einer fremden neuen Tür inne. Das Ding, das die Wärme einer fortgegangenen Person am längsten bewahrt."},"ICON-0021":{"nm":"Glas","de":"Leer wirkt es adrett, gefüllt ist es unendlich warm. Wenn zwei Gläser aneinanderklingen, liegt in dem hellen Ton ein wortloses Versprechen. Ein Gefäß, das erst zu zweit wirklich leuchtet."},"ICON-0022":{"nm":"Teller","de":"Innerhalb des runden Rands steckt ein ganzer Tag an Sorgfalt. Ein Leben lang leeren, abwaschen, wieder füllen – am häufigsten glänzend und am häufigsten vergessen. Auf ihm wird die Bühne des Esstischs gedeckt."},"ICON-0023":{"nm":"Lampe","de":"Ein einziger Schalter verändert den Ausdruck eines Raums. Hell ist Alltag, gedämpft ist Trost. Ein Licht, das für jemanden, der spät kommt, bis zuletzt brennt, wird zum wärmsten Empfangskomitee der Welt."},"ICON-0024":{"nm":"Teelöffel","de":"Eine langsame Runde im Tee, und Blätter und Wasser durchdringen sich gegenseitig. Eine Handbewegung ohne Eile, ein kleines Warten, bis der Duft sich entfaltet. Ein silberner Löffel, der das Tempo eines Nachmittags sanft verlangsamt."},"ICON-0025":{"nm":"Lesezeichen","de":"Ein stilles Versprechen, zwischen halbgelesene Seiten gelegt: ‚Ich war hier – ich komme zurück.' Die Geschichte schließt sich, doch das Herz bleibt an dieser einen Zeile klar markiert."},"ICON-0026":{"nm":"Kissen","de":"Wortlos nimmt es müde Rücken und Knie auf. Es drückt sich ein, füllt sich langsam wieder auf und saugt die Erschöpfung des Tages auf. Das Ding, das die faulste Haltung am großzügigsten gestattet."},"ICON-0027":{"nm":"Bilderrahmen","de":"Ein viereckiger Rand bindet einen einzigen Augenblick an die Ewigkeit. Was einmal darin war, verblasst nicht, egal wie viel Zeit vergeht. Eine liebevolle Entscheidung – nicht nur, was man darin festhält, sondern was man damit bewahren wollte."},"ICON-0028":{"nm":"Karte","de":"In jeder Falte steckt die Spur von jemandem, der sich verirrt und wieder gefunden hat. Ausgebreitet kann man selbst Orte, an denen man nie war, mit dem Finger abwandern. Jedes Abenteuer beginnt mit dem kleinen Mut, dieses eine Blatt zu entfalten."},"ICON-0029":{"nm":"Postkarte","de":"Die Rückseite halb Foto, halb Leerzeile. Jemand, der weit weg ist, schickt fünf Worte – ‚Mir geht's gut' – zusammen mit der Landschaft dort. Ein ehrliches Stück Papier, auf dem Grüße keine Hülle brauchen."},"ICON-0030":{"nm":"Ausweis","de":"Sobald man ihn um den Hals hängt, betritt man eine andere Welt. Der eigene Name auf einem kleinen Kärtchen flüstert: ‚Hier, das ist dein Platz.' Kein bloßer Berechtigungsnachweis – ein Zeichen der Zugehörigkeit."},"ICON-0031":{"nm":"Buchstabe B","de":"Der Buchstabe, der mitten im Wort am häufigsten aufgerufen wird. Man muss die Lippen einmal schließen und dann aufploppen lassen, damit der Laut entsteht. Nicht Anfang, nicht Ende – aber der verlässliche zweite Platz, der den Rhythmus hält."},"ICON-0032":{"nm":"Visitenkarte","de":"Mit beiden Händen reichen, mit Blickkontakt empfangen. Ein Tag, ein ganzer Stolz – auf einem einzigen Stück Papier still verdichtet. Im schmalen Zwischenraum zwischen Name und Titel nistet sich ein erster Eindruck ein."},"ICON-0033":{"nm":"Einband","de":"An der äußersten Seite der Geschichte empfängt er als Erster Wind und Regen. Seine Ecken verschleißen, um die Buchstaben darin zu schützen. Die Vorfreude kurz vor dem Aufschlagen beginnt stets mit diesem einen Blatt."},"ICON-0034":{"nm":"Lehrbuch","de":"Unterstreichungen und Textmarker zeigen den Kampf, den jemand ausgefochten hat. Am Anfang wirkt es entmutigend, am Ende ist es der verlässlichste Freund. Auf jeder Seite liegt das dichte Wissen von dem, was man einst nicht gewusst hat."},"ICON-0035":{"nm":"Tanzpass","de":"Dieses eine Blatt öffnet die Tür des Übungsraums weit auf. Ein Spiegel überall, Stampfen auf dem Boden, die ersten 8 Takte, die man lernt. Auch wenn der Tanz noch holprig ist, schiebt das kleine Stück Papier zitternd den Rücken an: Es ist in Ordnung."},"ICON-0036":{"nm":"Aktenmappe","de":"Einzelne Blätter, die umherflatterten, finden in einem Rücken ordentlich ihre Reihenfolge und bekommen endlich eine Ordnung. Aus Reihenfolge wird eine Geschichte, und je dicker sie wird, desto zärtlicher ist der Beweis, dass jemand so viel gelebt hat."},"ICON-0037":{"nm":"Prüfungsbogen","de":"Fingerspitzen, die einen Moment zittern, bevor man auf eine leere Zeile schreibt. Schlimmer als die falsche Antwort ist es, dem Unbekannten direkt ins Gesicht zu sehen. Wenn die Korrektur fertig ist, bleibt in jedem falsch angekreuzten Feld still ein freier Raum, in dem Neues wachsen kann."},"ICON-0038":{"nm":"Buchstabe A","de":"Der erste Laut, für den man den Mund weit öffnen muss. Steht häufig an der Spitze einer Zeile, am Anfang eines Namens. Weil bei allem ein Anfang mit diesem Buchstaben gemacht wird – ist er immer ein bisschen mutiger."},"ICON-0039":{"nm":"Buchstabe D","de":"Mit sanft gebogenem Rücken stützt er ein Wort behutsam. Das runde Ende hängt ordentlich am Ende von jemandes Namen. Nicht auffällig, aber wenn er fehlt, vermisst man ihn – ein stilles Gegenüber im Alphabet."},"ICON-0040":{"nm":"Übungsblatt","de":"Das einzige Papier der Welt, auf dem Fehler ausdrücklich erlaubt sind. Es lässt zu, dieselbe Bewegung, denselben Satz, dutzende Male neu zu schreiben. So viele zerknüllte Blätter im Papierkorb – und doch ist jemand ganz sicher ein Stück besser geworden."},"ICON-0041":{"nm":"Notenpapier","de":"Zwei Uhr nachts weckt ein gemummtes Thema den Schlaf. Der Bleistift zögert über dem Liniensystem, weil die Melodie schneller ist als die Hand. In jeder radierten und neu gesetzten Note wächst leise ein noch namenloser Song."},"ICON-0042":{"nm":"Backstage-Pass","de":"Sobald man ihn sich umhängt, wird ein gewöhnlicher Flur zu einer anderen Welt. Kabel schlängeln sich wie Schlangen durch die Dunkelheit, und hinter der Bühne beginnt ein Countdown, den das Publikum nicht hört. Das Recht, diesen Ort zu betreten, spricht dieser eine Ausweis stellvertretend aus."},"ICON-0043":{"nm":"Kontaktbogen","de":"In jedem kleinen Feld hält ein anderer Gesichtsausdruck inne. Lachen, zurückblicken, die Augen schließen. Wenn man sie Bild für Bild abtastet, kehrt das Herzpochen des Tages, an dem der Verschluss klickte, in die Fingerspitzen zurück. Selbst die Wahl eines einzigen Bildes ist bereits ein Dokument."},"ICON-0044":{"nm":"Drehplan","de":"Morgen um wie viel Uhr, wo, was. Ein einziges Blatt zeichnet die Wege eines ganzen Tages im Voraus. In den dichten Minutenfeldern geht jemand Schritt für Schritt in Richtung Traum, genau in der hier notierten Reihenfolge."},"ICON-0045":{"nm":"Preisschild","de":"Auf der Rückseite hängt still die Zeit des Machers. Die kurze Handbewegung des Abziehens – und erst dann gehört es einem. Was an der abgetrennten Stelle bleibt, ist Neuwarenduft und eine Prise Vorfreude."},"ICON-0046":{"nm":"Portfolio","de":"Schlägt man die erste Seite um, liegt der bisherige Weg auf einen Blick ausgebreitet. Neben einem selbstsicheren Blatt steht beschämt das erste holprige Experiment. Wenn man sich jemandem zum ersten Mal vorstellt, gibt es keine ehrlichere Selbstbeschreibung."},"ICON-0047":{"nm":"Planer","de":"Heute eintragen, nächste Woche planen, manchmal ein Feld schwarz ausmalen. Auch wenn nie alles wie geplant läuft, hört die Hand nicht auf, die Felder zu füllen. Eine kleine Zeremonie, bei der man die Zukunft einmal im Voraus durchlebt."},"ICON-0048":{"nm":"Playlist","de":"Zwischen einem langsamen Stück und einem schnellen Rhythmus ordnet man die Lieder dem Wetter des jeweiligen Tages entsprechend in einer Reihe. Wenn man sich vorstellt, dass jemandes Tag genau in dieser Reihenfolge verläuft, wird sogar die Stille zwischen den Liedern warm."},"ICON-0049":{"nm":"Schülerausweis","de":"Name, Foto und ein paar Zahlen. Ein einziges Blatt als Beweis für die Zeit zwischen Klassenraum und Übungsraum. In der Karte, deren Ecken vom Hin und Her in der Hosentasche abgewetzt sind, steckt ein unvergänglicher frischer Alltag."},"ICON-0050":{"nm":"Armband","de":"Erinnerst du dich, wie man damals die Farbe des Tages ans Handgelenk band? Der gemeinsam gerufene Schlachtruf, eine gemeinsam verregnete Konzertnacht. Die Schnur trägt man weiter, auch wenn sie ausgeblichen ist – weil man diesen Sommer auf dem Handgelenk weiterleben lassen will."},"ICON-0051":{"nm":"Armbinde","de":"In dem Moment, in dem man sie anlegt, liegt das Gewicht der Verantwortung sanft auf der Schulter. Das Zeichen des Menschen, der ganz vorn in der Reihe steht und als Letzter geht. Ein Stück Stoff lässt jemanden einen kleinen Schritt wachsen."},"ICON-0052":{"nm":"Ring","de":"Eine Linie ohne Unterbrechung, vollständig rund. Anfang und Ende berühren sich, weshalb die Menschen hier die Form der Ewigkeit sehen. Legt man die Hände still aneinander, nimmt ein Versprechen Form an, bevor Worte kommen."},"ICON-0053":{"nm":"Orden","de":"In dem kleinen Metallstück, das an der Brust hängt, sind die überstandenen Tage eingraviert. Was glänzt, ist nicht das Metall, sondern die vielen Übungsnächte dahinter. Was zuerst aufsteigt, ist nicht Stolz, sondern irgendwie Dankbarkeit."},"ICON-0054":{"nm":"Schürze","de":"Sobald man die Bänder um den Hals knüpft, werden die Hände frei. Das Signal, dass man bereit ist, in etwas einzutauchen – ob in Mehl oder Farbe. Je mehr Flecken entstehen, desto tiefer ist die Sorgfalt, die man an diesem Tag verschenkt hat."},"ICON-0055":{"nm":"Ohren-Kapuze","de":"Zieht man sie über die Ohren, rückt der Lärm von draußen einen Schritt zurück. Ein kleiner Zufluchtsort im weichen Inneren auf dem Schulweg im schneidenden Wind. Manchmal beginnt die Wärme des Winters genau an den Ohrspitzen."},"ICON-0056":{"nm":"Kostüm","de":"Vor dem Vorhang hängt ein Kleidungsstück stumm und hält den Atem an. In jede Naht ist eine Choreografie eingefaltet. Sobald man den Arm hineinsteckt, wird man zur Rolle – und die Bühne wird zur zweiten Haut dieses Gewands."},"ICON-0057":{"nm":"Krone","de":"In dem Moment, in dem sie aufgesetzt wird, richtet sich der gebeugte Rücken von selbst auf. Goldener Glanz flüstert erst von Verantwortung, dann von Macht. Das kühle Gewicht an der Stirn sagt: Je strahlender der Platz, desto schwerer ist er."},"ICON-0058":{"nm":"Umhang","de":"Über die Schultern gelegt, flattert der Stoff im Wind. Bei jedem Laufen zieht eine Hälfte hinterher. Weniger das Zeichen eines Helden als das echte Gefühl eines Kindes, das einfach cool aussehen wollte."},"ICON-0059":{"nm":"Maske","de":"Das Gesicht verbergen macht seltsamerweise ehrlicher. Wie auf den alten Marktbühnen, wo man hinter der Larve ungezügelt weinte und lachte. Hinter dem verborgenen Ausdruck erklingt die echte Stimme, die man sonst schluckt, umso lauter."},"ICON-0060":{"nm":"Lippenstift","de":"Den Deckel abdrehen und einen einzigen Strich ziehen – und schon steht ein kleiner Entschluss auf den Lippen. Der letzte Check vor dem Spiegel, ein roter Strich über das Zögern. In diesem kurzen Moment zieht sich die Angst leise zurück."},"ICON-0061":{"nm":"Jackett","de":"Wenn die Schulterlinie genau passt, wird man einen Moment lang ein wenig fester. Ärmel hochgekrempelt heißt Arbeitslust, Kragen aufgestellt heißt Mut zum Auftreten. Ein einziges Stück legt die Haltung eines Tages sanft fest."},"ICON-0062":{"nm":"Taekwondo-Gürtel","de":"Jedes Mal, wenn die Farbe wechselt, hat sich darunter auch die Menge an Schweiß verändert. Der Morgen in der Halle, wenn man den Gürtel knotet und sich verbeugt. In dem Moment, in dem man ihn bindet, sammelt sich der zerstreute Geist neu."},"ICON-0063":{"nm":"Schutzbrille","de":"Sobald man sie sich aufzieht, wird die Welt eine Nuance klarer. Hinter dem runden Schutzschild gegen Wind und Staub funkelt selbst ein gewöhnlicher Weg wie eine Startlinie."},"ICON-0064":{"nm":"Handschuh","de":"Hat man ihn angezogen, kommt der Mut, alles fest anzupacken. Finger, die zögerlich eingezogen waren, strecken sich jetzt bereit aus. Geschützt wird die Hand – doch was wirklich bewahrt wird, ist die nächste Herausforderung."},"ICON-0065":{"nm":"Maske (Mundschutz)","de":"Bedeckt man den Mund, spricht das Auge umso mehr. In der belebten Straße – ein kleines Stück anonymer Freiheit. Deshalb strahlt das Lächeln, das an der abgenommenen Stelle zurückbleibt, umso heller."},"ICON-0066":{"nm":"Mütze","de":"Den Schirm leicht heruntergezogen – und Sonnenlicht wie Blicke weichen einen Schritt zur Seite. Unter dem kleinen Dach auf dem Kopf darf man heute mit entspannter Miene schlendern. Die leichteste Verwandlung beginnt hier."},"ICON-0067":{"nm":"Hemd","de":"Knistern – frisch gebügelter Kragen, Morgenduft. Während man Knopf für Knopf von oben schließt, ordnet sich auch das aufgewühlte Innere Feld für Feld. Ein weißes Stück Stoff eröffnet den ersten Satz des Tages."},"ICON-0068":{"nm":"Schal","de":"Einmal um den Hals gewickelt, ist der Durchzug des Windes versperrt. Während das Ende auf der Schulter sanft wippt, kommt die Kälte nicht mehr bis nach innen. Ein Stück Stoff – irgendwo zwischen Schönheit und Wärme."},"ICON-0069":{"nm":"Handschuhe","de":"Bis in die Fingerspitzen warmgebettet fürchtet man auch das Kälteste nicht mehr. Eine kleine Winterschwelgerei, bei der sich die einst gepusteten Hände langsam wärmen. Ein abgezogener Handschuh kann manchmal auch jemand anderen wärmen."},"ICON-0070":{"nm":"Erkennungsmarke","de":"Zwei dünne Plättchen sehen einander still an. Name und ein paar Zahlen – genug, damit jemand bis zum Ende erinnert wird. Kaltes Metall, das irgendwie dem wärmsten Versprechen ähnelt."},"ICON-0071":{"nm":"Grip-Ring","de":"Hat man den Finger hindurchgesteckt, verschwindet die Angst, etwas fallen zu lassen. Mit einer Hand bequem zu halten und zu schwenken – ein kleines Stück Sicherheit. Wenn man den Arm lang ausstreckt, um ein Foto zu machen, hält er still die Handfläche."},"ICON-0072":{"nm":"Blumenkranz","de":"Setzt man ihn auf, kommt der Frühling mit. Vom Feld gepflückte Blüten, rund geflochten und sachte um die Stirn gelegt. Über dem strahlenden Lächeln im Foto liegt noch lange ein leiser Grasduft."},"ICON-0073":{"nm":"Schlafmaske","de":"Bedeckt man die Augen, rücken Licht und Geräusch auf einmal weit weg. Ohne Sicht hört man nur den eigenen Atem. Schaltet man kurz die Welt aus und tritt in die innere Stille, schließt sich hinter einem leise eine kleine Tür."},"ICON-0074":{"nm":"Schal (Woll)","de":"Einmal, zweimal – bei jedem Wickeln wird der Winter ein wenig sanfter. Irgendwo zwischen den Wollfäden steckt vielleicht das Herz der Person, die ihn gestrickt hat. Vergräbt man die Nasenspitze darin, wird die Welt ein wenig geborgener."},"ICON-0075":{"nm":"Halbmaske","de":"Das halbe Gesicht verdeckt, beginnt die Ballnacht. Der sichtbare Mund lächelt, die verborgenen Augen hüten ein Geheimnis. Dieser schmale Abstand zwischen Erkennbar und Rätselhaft lässt die Luft nach Mitternacht vibrieren."},"ICON-0076":{"nm":"Baskenmütze","de":"Schief aufgesetzt, schleicht sich etwas Stimmungsvolles in einen gewöhnlichen Tag. Ein rundes, flaches Stück Stoff legt einem stille Künstler-Attitüde auf die Schultern. Sogar die paar Sekunden, in denen man vor dem Spiegel den Winkel sucht, macht Freude."},"ICON-0077":{"nm":"Choker","de":"Eng um den Hals gelegt, zieht sie die Aufmerksamkeit von ganz allein nach oben. Ein einziges schmales Band verändert die Ausstrahlung im Ganzen. Klein, aber klar – wie ein Schloss, das das Selbstbewusstsein des Tages einrastet."},"ICON-0078":{"nm":"Parka","de":"Zieht man den Reißverschluss ganz hoch, macht auch ein Schneesturm einen Rückzieher. Schiebt man die Hände tief in das dicke Innenfutter, verstummt der Lärm der Welt. Im rauen Wind trotzdem warm – ein kleines Haus aus Stoff."},"ICON-0079":{"nm":"Hose","de":"Beide Beine hinein, den Bund geschlossen – jetzt ist man bereit aufzubrechen. Bei jedem Schritt bewegt sich der Stoff weich in seiner Struktur. Irgendwo zwischen Bequemlichkeit und Ordentlichkeit beginnt der Tag."},"ICON-0080":{"nm":"Piercing","de":"Selbst für einen kleinen Punkt braucht man ein wenig Mut. Ein glänzendes Metallstück setzt am schlichten Ohr einen deutlichen Schlusspunkt. Winzig – und doch leuchtet er zurück auf das heutige Ich, das sich klar verändert hat."},"ICON-0081":{"nm":"Wellenform","de":"Für den Tontechniker ist ein Lied nicht etwas, das man hört – sondern etwas, das man sieht. In den Höhen und Tiefen auf dem Bildschirm liest er, wo an diesem Tag der Atem gezittert hat. Eine unsichtbare Stimme liegt als Gebirgszug ausgestreckt und legt das Gelände eines ganzen Songs offen."},"ICON-0082":{"nm":"Stimmgerät","de":"Kurz vor dem Auftritt streicht man der Reihe nach über alle sechs Saiten und bringt jeden gerutschten Ton an seinen Platz. Weicht etwas um einen halben Ton ab, merkt das Publikum es sofort. Alles so genau stimmen, dass es niemand bemerkt – das ist die Fürsorge, die der Bühne gilt."},"ICON-0083":{"nm":"Tragegurt","de":"Einmal ums Handgelenk gewickelt, löst sich die Angst, etwas zu lassen. Auf der Bühne ist das Schlimmste, was passieren kann, etwas aus der Hand zu verlieren – deshalb kann man mit diesem kleinen Band endlich aufatmen."},"ICON-0084":{"nm":"Becken","de":"Ein einziger Aufprall setzt am letzten Satz des Stücks einen klaren Punkt. Die goldene Scheibe weiß, wie man kurz klingt und lange nachhallt. Das Ende soll so hell geschlossen werden."},"ICON-0085":{"nm":"Gitarre","de":"Gleiten die Finger über die sechs Saiten, wird ein kleines Zimmer mit einem Mal zur Bühne. Jemandes erste Melodie, das Selbstgespräch einer schlaflosen Nacht – all das hat in diesem runden Holzkörper zum allerersten Mal Atem bekommen."},"ICON-0086":{"nm":"Klang-Wolke","de":"Noten ballen sich wie Watte am Himmel und treiben dahin. Fährt der Wind einmal hindurch, soll statt Tropfen eine Melodie fallen – und die Kinder der Insel gehen ohne Schirm hinaus, um sie zu empfangen."},"ICON-0087":{"nm":"Schritt","de":"Die Bühnenbewegungen sind Arithmetik, gelöst mit den Zehenspitzen. Hier ein Schritt, dort ein halber Takt – Fehler sind erlaubt, einfach langsam machen. Hunderte Male eingestampft und im Körper verankert, formen diese Felder zusammen die Karte eines einzigen Songs."},"ICON-0088":{"nm":"Verstärker","de":"Eine Kiste, die Flüstern in Jubel verwandelt. Und doch hält die Hand inne, bevor sie die Lautstärke einen Schritt höher dreht. Diese Kiste weiß, dass nicht ein lauterer, sondern ein präziserer Klang bis in die letzte Reihe trägt."},"ICON-0089":{"nm":"Notenknäuel","de":"Notenköpfe häufen sich zu einem Wollknäuel – so weich wie ein Kopfkissen. Legt man sich still darauf, soll angeblich ein kaum hörbares Schlaflied herausrieseln – das freundlichste Gerücht auf der Insel."},"ICON-0090":{"nm":"Kassette","de":"Drückt man Zurückspulen, surrt das Band langsam zurück zum ersten Lied jenes Sommers. In der kleinen Schachtel, um die sich eine ganze Epoche gewickelt hat, schläft eine Zeit, die man nie mehr anfassen kann."},"ICON-0091":{"nm":"Stimmgabel","de":"Tippt man leicht die zwei Zinken an, entsteht in der Luft ein Referenzton. Alle Instrumente neigen still den Kopf zu diesem kleinen Zittern. Alles beginnt mit einem so zarten Vibrieren."},"ICON-0092":{"nm":"Klang-Chip","de":"Ein Klangsplitter wird sacht in einem fingernagelgroßen Chip eingesperrt. Ein nicht absichtlich aufgenommenes Einwurf-Geräusch, das Lachen von jemandem, der verschwunden schien – all das lebt hier noch immer warm und atmend."},"ICON-0093":{"nm":"Schallplatte","de":"Setzt die Nadel zum ersten Mal auf die Rillen, hört man zuerst ein leises Rauschen wie ein flaches Atemholen. Weil selbst dieses kleine Knistern liebenswert ist, legen manche diese schwarze Scheibe bis zuletzt nie aus der Hand."},"ICON-0094":{"nm":"Tasche","de":"Was man am meisten schätzt, trägt man stets am nächsten am Herzen. Ein einziges handtellergroßes Stoffsäckchen wird mal Handwärmer, mal Talisman, mal geheimes Schatzkästchen."},"ICON-0095":{"nm":"Pflaster","de":"An langen Übungsnächten klebt sich an jede Ferse ein kleiner Orden. Eines, das man klebt, weil man nicht Bescheid sagen will – ein stilles Versprechen, das niemand kennt: Ich tanze morgen trotzdem."},"ICON-0096":{"nm":"Kissen (Schlaf)","de":"Der Ort, wo man alle Bühnen eines ganzen Tages ablegt, ist schließlich dieses weiche Viereck. Legt man den Kopf still ab, klingt das Applaus-Echo im Ohr langsam aus – und auf der Insel senkt sich endlich die Nacht."},"ICON-0097":{"nm":"Glocke","de":"Kling – ein kurzer Ton, und jemand drückt die Tür auf. Signal, dass ein Gast kommt; Gruß, dass ein Tag beginnt. Ein kleines Metall, das den ganzen Tag nichts als Herzlichkeit läutet."},"ICON-0098":{"nm":"Etui","de":"Je wertvoller etwas ist, desto eigens wird ihm ein festes Zuhause gebaut. Die Hand, die das Etui öffnet und schließt, wird jedes Mal behutsamer – weil das Darin kein bloßes Ding ist, sondern ein Herzstück, das man nicht verlieren will."},"ICON-0099":{"nm":"Bürste","de":"Streicht man jeden Faden in seiner Richtung glatt, weicht der Schmutz in den Ecken leise zurück. Weil es eine Hand gibt, die auch die unsichtbaren Stellen nicht auslässt, kann der Raum jeden Morgen neu beginnen."},"ICON-0100":{"nm":"Skizze","de":"Die Linien vor der Vollendung verstecken ihr Zögern nicht. In jeder radierten und neu gezogenen Spur bleibt ehrlich, was sie werden wollte. Je holpriger der Anfang, desto aufrichtiger ist er."},"ICON-0101":{"nm":"Puppe","de":"Manchmal tröstet schon allein das Wort, lautlos in den Arm genommen zu werden. Die Wattekugel-Freundin, die hinter der Bühne zitterte, wenn die Hände zitterten, und am Kopfkissen zuhörte – irgendjemand trägt sie in seinem Herzen."},"ICON-0102":{"nm":"Glocke (Tempel)","de":"Die Tempelglocke läutet einmal und trägt das ganze Tal hinüber. Es ist der Wunsch des Eisens, weit, noch weiter zu reichen, der so lang weint – und dieser Klang sinkt langsam in die Brust derer, die ihn hören."},"ICON-0103":{"nm":"Regenschirm","de":"Wenn zwei darunter gehen, wird eine Schulter zwangsläufig nass. Unter dem sachte geneigten Schirm ist die nasse Schulter der deutlichste Beweis von Zuneigung. Der kurze gemeinsame Weg unter einem Dach bleibt lange im Herzen."},"ICON-0104":{"nm":"Matte","de":"Breitet man sie auf dem nackten Boden aus, wird der Ort sofort zum Übungsraum. Sie nimmt jeden Sturz und jedes Rollen wortlos auf – auf ihr haben unzählige Bewegungen zum ersten Mal ihren Weg in den Körper gefunden."},"ICON-0105":{"nm":"Rassel","de":"Schüttelt man sie sanft, kollert ein heller Klang aus der Handfläche. Eine kleine runde Freude, die einst an der Ärmelborte des Kindesgewands hing, wenn Kinder über den Hof sprangen – jetzt erwacht auf der Handfläche neu."},"ICON-0106":{"nm":"Schlangenspielzeug","de":"Das lang hingezogene Ding erschreckt die Leute auf durchtriebene Weise. Erschrecken, davonlaufen, am Ende doch losprusten – auch dieser Schabernack ist ein Zweig derselben Zuneigung füreinander."},"ICON-0107":{"nm":"Spielzeug","de":"Jeder hat irgendwo eine Schachtel, die er auch als Erwachsener nicht weggeben konnte. Darin ist das Lachen der strahlendsten Zeit noch so fest aufgezogen wie eine Spieluhr."},"ICON-0108":{"nm":"Esstisch","de":"Klappt man die Beine aus, ist überall sofort ein Platz für die Familie. Das Klirren der Löffel rings herum – dieses schlichte Konzert ist der wärmste Klang des ganzen Tages."},"ICON-0109":{"nm":"Seife","de":"Wird in der Hand kleiner und kleiner und bringt still jemanden sauber. Sich selbst abzutragen, um andere zu waschen – erst lange nach dem letzten Schaum bemerkt man dieses stille Herz."},"ICON-0110":{"nm":"Kamm","de":"Wie man verfilztes Haar Strähne für Strähne entwirrt, ordnet sich auch ein verwirrter Tag nach und nach. Diese kurze Hand am Spiegel richtet heimlich auch das Durcheinander hinter dem Haar."},"ICON-0111":{"nm":"Vogelkäfig","de":"Es gibt Vögel, die singen und bleiben, auch wenn die Tür weit offen steht. Nicht eingesperrt, sondern weil sie bleiben wollen – diesen feinen Unterschied erkennt dieser Käfig vor allen anderen."},"ICON-0112":{"nm":"Handwärmer","de":"In der Warteschlange vor dem Winterkonzert wärmt die kleine Wärme in der Tasche die steifen Finger. Von jemandem im Voraus geschüttelt und warm gemacht, weil er an dein Frieren gedacht hat – eine handtellergroße Freundlichkeit."},"ICON-0113":{"nm":"Taschentuch","de":"Es nimmt Tränen wie Schweiß wortlos auf. Die kleine Stickerei an der Ecke bleibt dort still wie der letzte Gruß eines Menschen, der früh gegangen ist: Vergiss mich nicht."},"ICON-0114":{"nm":"Sprühflasche","de":"Ein Zischen – und der Klang der Luft verändert sich schlagartig. Der Nebel, der über die Bühne zieht, die Zimmerpflanze am Morgenfenster – in diesen feinen Wassertropfen funkelt für einen Augenblick eine andere Welt."},"ICON-0115":{"nm":"Duftteststreifen","de":"Einen Duft wählen ähnelt seltsam dem Wählen einer Erinnerung. Ein Hauch an der Spitze des schmalen Papierstreifens bringt eine Jahreszeit, die man vergessen zu haben glaubte, sachte an die Nasenspitze zurück."},"ICON-0116":{"nm":"Esstisch (groß)","de":"In jeder Maserung sind die gemeinsamen Mahlzeiten still eingraviert. Der lärmende Abend in geselliger Runde, die späte Nacht ganz allein – dieses Viereck hat alles schweigend aufgenommen und dabei Glanz bekommen."},"ICON-0117":{"nm":"Wollknäuel","de":"Zieht man am einen Ende sachte, rollt es sich auf, und mit einem einzigen Stich ist es wieder verbunden. Etwas Getrenntes zusammenzufügen beginnt immer so still, mit einem einzigen Faden."},"ICON-0118":{"nm":"Regenmantel","de":"Was einen selbst bei strömendem Regen trotzdem nach draußen treibt, ist dieses eine Stück Kleidung. Wer das Vergnügen kennt, platschend durch den Regen zu gehen, bleibt nicht unter dem Vorwand des Regens zu Hause."},"ICON-0119":{"nm":"Beutel","de":"Zieht man den Rand rund zusammen, wird das Innere endlich sicher. In dem kleinen abgenutzten Beutel schaukeln Münzen, Erinnerungen eines Tages und ein nie gesagtes Wort zusammen."},"ICON-0120":{"nm":"Bücherregal","de":"Streicht man langsam mit dem Finger die Buchrücken entlang, berührt man die vergangenen Jahreszeiten. Gelesene Bücher wegzuwerfen fällt so schwer, weil das damalige Ich noch darin wohnt."},"ICON-0121":{"nm":"Bücherstapel","de":"Gelesene Bücher legt man auf die Seite, ungelesene stapelt man nach oben. Auch wenn das Versprechen, sie irgendwann alle zu lesen, bis zur Decke schwankt – weil dieses Schwanken selbst schön ist, legt man heute noch eines oben drauf."},"ICON-0122":{"nm":"Laufrad","de":"Auch wenn es sich anfühlt, als träte man auf der Stelle, übt der kleine Fuß gerade den Rhythmus seiner Zehenspitzen ein. Alle gestrigen Tage, an denen man nicht aufgehört hat, leuchten an einem bestimmten Tag hell auf dem echten Weg."},"ICON-0123":{"nm":"Schutzhülle","de":"Damit kein Staub ansetzt, damit es nicht in der Sonne verblasst – selbst das Abdecken braucht die Sorgfalt der Fingerspitzen. Je mehr man etwas schätzt, desto liebevoller wird es an unsichtbarer Stelle beschützt."},"ICON-0124":{"nm":"Wollgarn","de":"Ein Faden, der auf Großmutters Knie aufgerollt herausrollte. Auch wenn er verfilzt aussieht, folgt er einem, wenn man behutsam das Ende sucht und zieht. Winterabende wurden so Stich für Stich länger."},"ICON-0125":{"nm":"Täschchen","de":"Lippenbalsam, Haargummi, ein sorgfältig gefalteter Brief – so klein und doch steckt ein ganzer Tagesherzensinhalt darin. Mit dem Zischen des Reißverschlusses werden alle geliebten Kleinigkeiten auf einmal sicher."},"ICON-0126":{"nm":"Armlehne","de":"Ein schlafender Nachmittag beim Lesen, ein Abend beim Herumwandern während eines Telefonats. Je länger man sitzt, desto tiefer wird die Patina – alle Pausen, die der Ellbogen kennt, haben sich einen Atemzug breit still gesammelt."},"ICON-0127":{"nm":"Packung","de":"Bis man sie öffnet, gehört sie noch niemandem. In dem versiegelten Päckchen steckt ungelebte Erwartung, sodass die Fingerspitzen am Eck leicht zittern. Das ist die Vorfreude des Öffnens."},"ICON-0128":{"nm":"Geschenkpapier","de":"Ein Herz, das vor dem Geschenk ankommt. Während man die Ecken faltet und eine Schleife bindet, erstrahlt das lächelnde Gesicht des Empfängers in der Hand schon hell."},"ICON-0129":{"nm":"Gamepad","de":"Knöpfe, die der Daumen schneller kennt als der Kopf. Auch wenn man verliert, noch eine Runde – und am Ende ist es diese eine Runde, die die Nacht durchzieht. Das vertraute Gewicht in der Hand hebt das Abenteuer dieser Nacht sanft empor."},"ICON-0130":{"nm":"Signal","de":"Rot bedeutet kurz warten, Grün bedeutet jetzt darfst du. Mit einem einzigen simplen Übereinkommen fließen unzählige Wege, ohne sich zu verknoten. Das blinkende Licht erklärt sanft: Auch im Warten gibt es eine Reihenfolge."},"ICON-0131":{"nm":"Pfeil","de":"Die freundlichste Form für jemanden, der sich verirrt hat. Wenn man nicht weiß, wohin man soll, gibt eine einzige Richtung, die jemand zuvor eingezeichnet hat, dem stehenden Fuß neuen Halt."},"ICON-0132":{"nm":"Koordinate","de":"Zwei Zahlen reichen, um jeden Punkt der Welt zu benennen. Einen Treffpunkt, einen Sandplatz, wo man einen Schatz vergraben hat. Ein kleiner Punkt hält das Versprechen, damit es sich nicht verirrt."},"ICON-0133":{"nm":"Kachel","de":"Allein ein schmales Viereck. Doch wenn sie Schulter an Schulter nebeneinanderliegen, werden sie Boden und Wand. Kleine Dinge, die zusammen einen Platz schaffen, auf dem jemand getrost seinen Fuß aufsetzen kann."},"ICON-0134":{"nm":"Sanduhr","de":"Wenn das obere Fach leer ist, füllt sich das untere langsam. Beim Zuschauen, wie der Sand rieselt, glaubt man, die Zeit vergeht. Umdrehen, und es beginnt von vorn – das ist die freundliche Lüge des Sandes."},"ICON-0135":{"nm":"Ball","de":"Geworfen kommt er zurück, getreten rollt er davon. Weil er rund ist und niemand weiß, wohin er springt, liegt sein größter Reiz darin. Mitten auf dem Schulhof begann das Lachen stets als kleiner Kreis von diesem runden Ding."},"ICON-0136":{"nm":"Schalter","de":"Klick – einmal an, einmal aus. Das kleine Geräusch beim Betreten eines dunklen Zimmers teilt Anfang und Ende eines aufgewirbelten Tages mit einer klaren Linie."},"ICON-0137":{"nm":"Fragezeichen","de":"Etwas nicht zu wissen, ist keine Schande. Ein willkommenes Zeichen, dass die Neugier noch lebt. Wenn dieser kleine Haken im Kopf anklopft, macht das Lernen seinen ersten Schritt."},"ICON-0138":{"nm":"Streichholz","de":"Ein Holzstäbchen, das sich selbst anreibt und Feuer weitergibt. Brennt kurz und verschwindet still, doch in dieser kurzen Spanne geht eine Kerze an und ein Herd wärmt. Ein kleines Hergeben ist der erste Knopf von Wärme."},"ICON-0139":{"nm":"Tritthocker","de":"Steigt man auf ihn, reicht die Hand jetzt auch an das hohe Regal. Jemandes Körpergröße für einen Moment vergrößern. Ein freundlicher Platz, der sich niederkniet und uns behutsam ein Stück höher hebt."},"ICON-0140":{"nm":"Armbanduhr","de":"Das Erste, was man sich am Tag, an dem man mit dem Sport angefangen hat, ums Handgelenk gelegt hat. Ein kleiner Coach, der Herzschlag und Schritte zählt, tippt einen an: Heute bist du ein bisschen weiter gegangen als gestern."},"ICON-0141":{"nm":"Wecker","de":"Der gewissenhafteste Freund, der jeden Morgen gehasst wird. Weil er jeden Kampf mit der Versuchung der fünf Minuten mehr im Bett stellvertretend austrägt, kommen weder Termine noch Träume zu spät. Dieser ärgerliche Klang ist in Wirklichkeit Anfeuerung."},"ICON-0142":{"nm":"Kern","de":"Das Innerste, das ganz unten bleibt, wenn man alles abzieht. Der Apfelkern, die echte Überzeugung im Herzen – in jeder Mitte steckt das Härteste. Ein einziger Punkt, der bleibt, egal wie sehr er ins Schwanken kommt."},"ICON-0143":{"nm":"Stift","de":"Die Spur, die die Handkante streifte, bevor die Tinte trocknete. Ob es gut fließt oder nicht – für den ersten Strich auf weißem Papier braucht es immer ein bisschen Mut. Eine Brücke, auf der Gedanken in die Fingerspitzen hinüberwechseln."},"ICON-0144":{"nm":"Pinsel","de":"Wenn er Tusche aufnimmt und über Reispapier gleitet, bleibt selbst ein zögerndes Zittern vollständig erhalten. Wer aus Gier zu schnell schreiben will, fliegt sofort auf. Der Pinsel kennt die Ehrlichkeit, die in den Fingerspitzen wohnt, als Erster."},"ICON-0145":{"nm":"Sprechblase","de":"Bevor das Wort den Mund verlässt, schwebt es rund über dem Kopf. Ein Gedanke, den man sagen möchte, findet hier seinen Platz. Wenn sie leer ist, wählt man gerade, womit man sie füllen will."},"ICON-0146":{"nm":"Kontrollkästchen","de":"Zwei kurze Striche in das leere Viereck – und das Herz wird leichter. Ein kleines Abzeichen, das man sich selbst für Erledigtes verleiht. Am Ende des Tages beim Blick auf die gefüllten Felder atmet man auf: Heute war gut."},"ICON-0147":{"nm":"Tablet","de":"Wo der Finger hinstreicht, breitet sich Farbe aus, fließen Buchstaben. Legt man es ruhig auf den Schoß, leuchtet eine ganze Welt auf. Leicht – doch was darin steckt, ist alles andere als dünn."},"ICON-0148":{"nm":"Fernbedienung","de":"Sie hat ein natürliches Talent dafür, im Sofaspalt zu verschwinden. Wer sie in der Hand hält, hat die Macht über den Kanal. Auf diesem einen Handbreit entbrennt der kleinste und herzlichste Streit in der Familie."},"ICON-0149":{"nm":"Gegengewicht","de":"Das Gewicht, das sich selbst am tiefsten gesenkt hat, um das Schwankende zu halten. Auch wenn oben alles tobt, fällt nichts um, wenn unten genug Schwere ist. Balance hält immer dort, wo man sie nicht sieht."},"ICON-0150":{"nm":"Puzzle","de":"Eine Nacht, in der man unter dem Sofa tastete, um das letzte Puzzlestück zu finden. Das lautlose Vergnügen, wenn es genau passt. Wenn das Verstreute seinen Platz findet, ist das Bild endlich fertig."},"ICON-0151":{"nm":"Lineal","de":"Messen bedeutet auch, ein Versprechen zu halten. Damit eine Handbreit für alle gleich bleibt, reihen sich die Striche unbestechlich aneinander. Eine einzige gerade Linie kann sogar ein aus der Bahn geratenes Gemüt wieder in Ordnung bringen."},"ICON-0152":{"nm":"Leinwand","de":"Die leere weiße Fläche ist das Beängstigendste und zugleich das Aufregendste. Solange der erste Punkt noch nicht gesetzt ist, kann alles daraus werden. Die Leere ist kein Ende – sie ist ein anderes Wort für den Anfang."},"ICON-0153":{"nm":"Zauberwürfel","de":"Nicht wenige haben über das Lösen aller sechs Seiten die Nacht durchgemacht. Die hartnäckigen Finger, die immer weiterdrehen. In dem Moment, in dem die bunten Felder endlich an ihren Platz fallen, ordnet sich ein kleines Universum."},"ICON-0154":{"nm":"Spielkonsole","de":"In den Ferien steckten die Köpfe der Cousins und Cousinen gemeinsam über diesem kleinen Bildschirm. Eine Abenteuerwelt, die in die Handfläche passte. Schon beim ersten Ton der Einschaltmelodie kehrt jener Sommer vollständig zurück."},"ICON-0155":{"nm":"Griff","de":"Das Gefühl, wenn er sich beim festen Zupacken perfekt in die Hand schmiegt, schenkt einem ganz still ein Stück Selbstvertrauen. Damit nichts abrutscht und nichts verloren geht – in den wichtigsten Momenten verbindet er Hand und Werkzeug zu einer festen Einheit."},"ICON-0156":{"nm":"Füllfederhalter","de":"Während man Tinte einfüllt und schreibt, wird sogar die Handschrift ein wenig ordentlicher. Beim kratzenden Klang der Feder sammelt sich der Geist, und ganz leise erinnert er an jene Sorgfalt, mit der man einst die erste Zeile eines Briefes bedächtig begann."},"ICON-0157":{"nm":"Farbpalette","de":"Rot neben Blau, Gelb unter Grün. Auf diesem kleinen Brett, auf dem die Farben friedlich nebeneinanderliegen, gewinnt ein Bild erst seinen Ausdruck. Jedes Abenteuer des Mischens und Übermalens nimmt hier seinen ersten Schritt."},"ICON-0158":{"nm":"Set","de":"Für sich genommen mögen die Teile gewöhnlich sein, doch nebeneinander erzählen sie eine Geschichte. Das Gefühl von Vollständigkeit, wenn kein Stück fehlt. Im Zusammenbringen des Verstreuten liegt eine stille, kleine Freude."},"ICON-0159":{"nm":"Federball","de":"Der sanfte Windhauch, den die Federn beim Aufschlag erzeugen. So leicht, dass man kaum glaubt, er fliege weit – doch mit entschlossenem Schwung fliegt er schnurgerade bis ans andere Ende des Feldes. Leichtigkeit ist auch eine Art von Stärke."},"ICON-0160":{"nm":"Antenne","de":"Unbeweglich dem Himmel zugewandt, um unsichtbare Signale zu empfangen. Die Geduld, die ferne Stimmen schließlich doch heranzieht. An Tagen, an denen der Empfang schlecht ist, genügt eine kleine Änderung des Winkels, damit alles wieder klar wird."},"ICON-0161":{"nm":"Stethoskop","de":"Das runde Metall berührt kalt die Brust, und der Atem stockt für einen Moment. Wer lauscht, wie ein kleines Trommeln dort pocht, spürt mit den Fingerspitzen den ältesten Rhythmus des Lebens. Ein Werkzeug, das zuerst zuhört."},"ICON-0162":{"nm":"Schachfigur","de":"Die kleine Figur, die nur langsam, ein Feld nach dem anderen, voranschreitet. Doch sobald sie die letzte Reihe erreicht, kann sie alles werden. Den schleppenden Schritten, die das ganze Brett umkehren – das alte Schachbrett schaut ruhig zu."},"ICON-0163":{"nm":"Controller","de":"Erinnerst du dich an die Nächte, in denen zwei Daumen das Universum durchstreiften? Der abgegriffene Griff, den man nach dem Hinwerfen vor Verlegenheit wieder aufhob. Das längste, wärmste Gespräch, das man schweigend mit jemandem jenseits des Bildschirms geführt hat."},"ICON-0164":{"nm":"Konsole","de":"Beim Einschalten begrüßt einen ein kleiner Startton wie ein Freund. Die viereckige Box, die die ganzen Ferien über unter der Bettdecke ein- und ausgeschaltet wurde. Das erste Kindheitsabenteuer begann immer im Schein dieses Bildschirms."},"ICON-0165":{"nm":"Zeitstrahl","de":"Ganz links der Anfang, ganz rechts ein Tag, der noch nicht gekommen ist. Zieht man dazwischen irgendwo einen Punkt, entfaltet sich ein Moment, den man schon vergessen geglaubt hatte. Ein Ort, an dem die Zeit auf einer einzigen Linie liegt."},"ICON-0166":{"nm":"Prisma","de":"Dass das klare Licht in Wirklichkeit sieben Farben in sich trug. Im Augenblick, in dem es durch ein Stück Glas fällt, löst sich das Geheimnis als Regenbogen. Je makelloser etwas wirkt, desto mehr Farben verbirgt es in seinem Innern."},"ICON-0167":{"nm":"Golf-Tee","de":"Ein kleiner Ständer, der den Ball ruhig aufnimmt. Je weiter man schlagen will, desto mehr braucht man zuerst eine feste Stütze. Dieser winzige Stift im Gras trägt den allerersten Schritt."},"ICON-0168":{"nm":"Stricknadeln","de":"Eine Masche, noch eine Masche. Lässt man eine aus, muss man alles auftrennen und von vorne beginnen. Der Schal, der einen ganzen Winter lang auf dem Schoß langsam länger wurde – ein Ort, an dem die Geduld der Hände zu Wärme gestrickt wurde."},"ICON-0169":{"nm":"Melodielinie","de":"Bevor die Worte kommen, entweicht schon ein Summen von den Lippen. In dieser verschwommenen Melodie ohne Text steckt das ehrlichste erste Gesicht eines Liedes."},"ICON-0170":{"nm":"Radar","de":"Man sendet ein Signal in die unsichtbare Dunkelheit und wartet still auf den einen zurückkehrenden Punkt. Die Geduld des grünen Kreises, der glaubt, dass dort draußen etwas ist, auch wenn man nichts sehen kann."},"ICON-0171":{"nm":"Rhythm-Pad","de":"Ein leichtes Antippen, und Licht und Klang springen gleichzeitig auf. Der Ort, an dem die Hände den Rhythmus früher auswendig lernen als der Kopf. Die kleinste und herzlichste Bühne, die in die Handfläche passt."},"ICON-0172":{"nm":"Farbe","de":"Die alten Maler mahlten Steine und Erde zu Farbe. Blau aus Pflanzen, Rot aus der Erde. In jedem Tropfen, der heute aus der Tube kommt, fließt noch die alte Sorgfalt, mit der die Natur behutsam übertragen wurde."},"ICON-0173":{"nm":"Linie","de":"Sie entsteht erst in dem Moment, in dem man beschließt, zwei Punkte zu verbinden. Kurz oder lang, gebogen oder gerade – sie ist die schlichteste Spur, die der Wunsch hinterlässt, irgendwohin zu gehen. Der Beginn jedes Bildes."},"ICON-0174":{"nm":"Verschluss","de":"Dieses kurze Dunkel eines einzigen Klicks hält eine Szene für immer fest. Selbst ein Gesichtsausdruck, der in einem Wimpernschlag verloren wäre, wird von einem kleinen Schnitt des Lichts zur Erinnerung erstarrt."},"ICON-0175":{"nm":"Sicherungsseil","de":"Das Seil, das noch vor dem Kletterer fest verankert ist. Es hält stellvertretend das bange Herz, damit es nicht fällt, und wacht unsichtbar an der Seite. Es ist immer hinter einem da."},"ICON-0176":{"nm":"Schloss","de":"Das schwere Eisenschloss, das man früher an den Speicher hing. Nicht um etwas einzusperren, sondern um etwas Wertvolles sorglos verwahren zu können. Selbst im Schließen lag Fürsorge – die behagliche Geborgenheit eines alten Hauses."},"ICON-0177":{"nm":"Waage","de":"Wird eine Seite schwerer, wird die andere von selbst leichter. In dem Moment des Zögerns, wie viel man auflegen soll, lernt der Mensch die Fairness. Zwei Arme, die sich wiegend das Gleichgewicht lehren."},"ICON-0178":{"nm":"Spaltwerkzeug","de":"Auch das Festeste lässt sich schließlich spalten, wenn man der Maserung folgt. Ein kleines Werkzeug, das alles in zwei Teile teilt und ins Innere blickt. Für neugierige Hände, die das Verbundene wieder trennen und verstehen möchten."},"ICON-0179":{"nm":"Zähler","de":"Eins, zwei, drei. Ein kleiner Helfer, der still für einen zählt, statt der Finger. Er verwandelt die Nervosität, etwas zu verpassen, Klick für Klick in beruhigende Sicherheit – der freundliche Begleiter des Zählens."},"ICON-0180":{"nm":"Cursor","de":"Er blinkt irgendwo auf dem Bildschirm und wartet auf den nächsten Befehl. Auch während man zögert, verlässt er seinen Platz nicht und winkt einem leise zu: Fang einfach an. Das Ende eines Lichtstrahls."},"ICON-0181":{"nm":"Griff-Hold","de":"Der eine Punkt, an dem man sich kurz vor dem letzten Kraftverlust noch festhält. Dass es Momente gibt, in denen man allein durch den Willen, nicht loszulassen, besteht – das sagt der kleine Vorsprung an der Wand, ganz still."},"ICON-0182":{"nm":"Kieselstein","de":"Ein Stein, der so lange im Bach gerollt ist, bis alle Kanten verteilt sind. Runder zu werden ist ein anderer Name für die Zeit, die abgetragen hat. Hält man ihn ruhig in der Handfläche, fühlt man die Geduld des fließenden Wassers."},"ICON-0183":{"nm":"Wappen","de":"Alte Adelsgeschlechter ließen Tiere und Sterne in ihr Banner einweben, um sich bekannt zu machen. Ein Bild, das das Herz früher als Worte erreichte. Ein altes Zeichen, das den Stolz eines Menschen in einem kleinen Feld konzentriert."},"ICON-0184":{"nm":"Schild","de":"Sich in den Weg zu stellen bedeutete immer, für jemanden hinter einem zu kämpfen. Fliegende Pfeile abzufangen und den gewöhnlichen Alltag von jemandem zu schützen – eine schwere und zugleich herzliche Mauer."},"ICON-0185":{"nm":"Wiedergeburt","de":"Es gibt ein Herz, das erlischt und wieder entflammt. Erst nach einmaligem Scheitern lernt man, wieder aufzustehen. An dem Ort, den man für das Ende hielt, steigt ein zweiter Atemzug still empor."},"ICON-0186":{"nm":"Bogen","de":"Wer etwas weit schicken will, muss die Sehne zuerst bis zum Äußersten zurückziehen. Um etwas loszuschicken, muss man es erst nah an sich heranziehen – das sagt die gespannte Bogenwölbung lautlos."},"ICON-0187":{"nm":"Herz","de":"Das Wort „Ich mag dich“ schrumpft immer wieder zu einer kleinen Form. Es erscheint am Ende des Leuchtstabes und zwischen den aneinandergelegten Fingern. Die häufigste und ehrlichste Abkürzung des Herzens."},"ICON-0188":{"nm":"Wolke","de":"Langsam in die Richtung des Windes treibend, nimmt sie jedes Mal ein anderes Gesicht an. Mal Hase, mal Watte – sie hält nichts fest und lässt alles ziehen. Das leichteste Gemüt des Himmels."},"ICON-0189":{"nm":"Labyrinth","de":"Ein Ort, an dem man lernt, vor einer Sackgasse umzukehren. Auch während man sich verirrt, wächst der Schritt ein wenig in Richtung Ausgang. Erst wer sich einmal verirrt hat, bekommt einen Sinn für den Weg."},"ICON-0190":{"nm":"Zahn","de":"Es gab den Brauch, den ausgefallenen Zahn aufs Dach zu werfen. Ein kleiner Wunsch, dass der neue gerade nachwächst. Was man einmal verliert, holt man etwas Stärkeres zurück – das freundliche Versprechen der Kindheit."},"ICON-0191":{"nm":"Planet","de":"Ein runder Körper, der die Sonne umkreist, ohne jemals von seinem Kurs abzuweichen. Einsam wirkend und doch mit seiner Schwerkraft immer etwas um sich in Bewegung haltend. Schweigend seinen Platz zu hüten ist selbst eine Welt."},"ICON-0192":{"nm":"Stern","de":"In verirrten Nächten blickten Menschen zum hellsten Punkt auf. So unerreichbar fern und doch so klar die Richtung weisend. Ein Versprechen, das mit der Entfernung nur fester wird."},"ICON-0193":{"nm":"Silhouette","de":"Stellt man sich gegen das Licht, bleibt vom Menschen nur der Umriss. Eine schwarze Form, der Name und Ausdruck genommen sind. Gerade weil sie leer ist, lässt sie umso mehr Raum für die Vorstellung."},"ICON-0194":{"nm":"Ohr","de":"Wer gut singen will, muss zuerst gut zuhören. Rhythmus wie Gefühl beginnen letztlich im Hören. Die kleine, offen gerundete Tür, an der alle Klänge der Welt zuerst ankommen und verweilen."},"ICON-0195":{"nm":"Herbstblatt","de":"Es gibt Blätter, die im Moment des Falls am schönsten leuchten. Den grünen Sommer vollständig in Rot verbrannt, legen sie sich leise hin. Auch ein Ende kann so schön sein – das zeigt der Herbst."},"ICON-0196":{"nm":"Mond","de":"Es gab Nächte, in denen man unter dem runden Licht des Herbstmondfestes mit gefalteten Händen Wünsche schickte. Immer wechselnd und doch nie dasselbe Gesicht tragend. Eine Laterne, die leuchtet, indem sie sich verändert und dabei stets an ihrem Platz bleibt."},"ICON-0197":{"nm":"Herz","de":"Auch auf der Bühne ist dieses Pochen am Ende das Ehrlichste. Es hört nicht auf zu schlagen, auch wenn man zittert, und schlägt stärker, wenn es einem zu viel wird. Die kleine rote Trommel, die stellvertretend all die Unterstützung pocht, die man nicht in Worte fassen kann."},"ICON-0198":{"nm":"Schatten","de":"Solange es Licht gibt, lässt dieser Begleiter einen nie los. Je heller es ist, desto dunkler wird er; je trüber, desto blasser. Ein weiteres Ich, das einem am längsten gefolgt ist. Einer, der an einsamen Tagen an der Seite steht."},"ICON-0199":{"nm":"Schwanz","de":"Bei Freude wedelt er von selbst, bei Angst ringelt er sich leise ein. Auch wenn der Mund fest verschlossen bleibt, kann er das Innere nicht verbergen – ein ehrliches Ende. Was der Körper zuerst verrät."},"ICON-0200":{"nm":"Schwanzband","de":"Ein kleines Band, das wie ein Haarband am Ende zusammenbindet und abschließt. Ein letzter fester Knoten, damit nichts aufgeht. Etwas Leicht-Zerstreuliches wird sanft zusammengehalten und aufgeräumt – ein liebevolles Finishing."},"ICON-0201":{"nm":"Augapfel","de":"Worte kann man wählen, doch den Blick kann man nicht verbergen. Der Ort, an dem ein ertapptes Herz zuerst aufscheint – tief in diesem schwarzen Kreis. Auch wenn man das Wort „Ich mag dich“ schluckt, richtet sich der Blick schon längst auf dich."},"ICON-0202":{"nm":"Hufeisen","de":"Ein Stück Eisen, das an abgelaufenen Beinen aus weiten Reisen immer fester wurde. Hängt man es verkehrt herum über die Tür, soll das Glück sich darin sammeln. Es trägt still für jemandes sichere Heimkehr."},"ICON-0203":{"nm":"Inschriftenstein","de":"Auch wenn Regen und Wind die Buchstaben allmählich glattschleifen, leben die eingravierten Rillen auf, sobald man sie mit den Fingern erfühlt. Das Gewicht eines Herzens, das nicht vergessen werden wollte. So lange hält ein Stein einen Namen in sich."},"ICON-0204":{"nm":"Schwimmhäute","de":"Mit der dünnen Haut zwischen den Zehen lernt man, das Wasser zu schieben. Ein kleines Ruder, das die Natur dem Ungeübten heimlich mitgegeben hat. Langsam, aber sicher ans andere Ufer – ein herzliches Design."},"ICON-0205":{"nm":"Glitzer","de":"Alle schimpfen, dass er tagelang an den Händen klebt, und doch greift man an Festtagen als erstes zu diesen Lichtkörnchen. Streut man eine Handvoll Sternenstaub, funkelt sogar das gewöhnlichste Papier – heute wird dieser Tag besonders."},"ICON-0206":{"nm":"Kralle","de":"Das Tier im Wald ritzt mit der Kralle die Erde auf und hinterlässt seinen Weg. Keine Drohung, sondern eine Spur – die stille Unterschrift: Ich bin hier vorbeigekommen. Ein scharfes Ende kann auch ein freundlicher Wegweiser sein."},"ICON-0207":{"nm":"Blitz","de":"Der Moment, in dem der Himmel kurz seine Handlinien zeigt – das Licht kommt dem Donner zuvor. Als solle man einmal tief durchatmen, bevor das Laute ankommt. Furcht und Staunen werden stets im selben Licht geboren."},"ICON-0208":{"nm":"Amulett","de":"Ein Wunsch, mit Tusche fest in rotes Papier gedrückt. Man glaubte, unters Kopfkissen gelegt halte es schlechte Träume fern. Das Herz, das für jemandes Wohlergehen bittet, ist sogar auf dünnstem Papier so warm."},"ICON-0209":{"nm":"Pinselflügel","de":"Es gibt Momente, in denen die Pinselspitze zu einem Flügel wird. Die Leichtigkeit, mit der sie beim Ziehen eines Striches über das Papier gleitet. Die alten Hände, die Tusche rieben, ahnten wohl, dass Schreiben gleichbedeutend mit Fliegen ist."},"ICON-0210":{"nm":"Knochen","de":"Was erst bleibt, wenn alles Fleisch vergangen ist. Das weiße Skelett, das sich als Härtestes bis zuletzt gehalten hat. Selbst wenn die Zeit alles mitnimmt, erinnert die Form noch – ein stilles Zeugnis."},"ICON-0211":{"nm":"Nase","de":"Geruch ist die schnellste Abkürzung zur Erinnerung. Der Duft von Öl in der Festtagsküche, die kalte Luft eines ersten Schneemorgens – die Nase erkennt es zuerst, und das Herz folgt einen Takt später."},"ICON-0212":{"nm":"Toast","de":"Die Mahlzeit, die man an einem beschäftigten Morgen am schnellsten in die Hand nimmt. Beißt man in die goldbraune Seite, zerbricht ein ganzer Tagesvorrat an Mut krachend. Dinge, die unscheinbar sind und trotzdem stärken, bringen Menschen wieder auf die Beine."},"ICON-0213":{"nm":"Keks","de":"Wer am längsten vor dem Ofen gewartet hat, bekommt den ersten Bissen. Die Wärme der frischen Kante, der kurze Augenblick der Süße. Wer jemanden beim Backen im Sinn hatte, dem schmeckt er seltsamerweise noch süßer."},"ICON-0214":{"nm":"Snack","de":"An langen Nachmittagsproben, aus der Tiefe der Tasche gezogen. Teilt man ihn, wird die Sättigung auf wundersame Weise doppelt so groß. Eine Hand voll Herzlichkeit, die den Hunger zuletzt füllt und das Herz zuerst."},"ICON-0215":{"nm":"Kapsel","de":"Bis man sie öffnet, weiß es niemand. In der runden Hülle steckt immer dasselbe Kribbeln. Das ehrlichste Kribbeln der Welt – ein kleiner Zufall, der ge- und verkauft wird."},"ICON-0216":{"nm":"Türgriff","de":"Der Ort, den unzählige Hände als erstes berühren, wenn sie eine Tür öffnen oder schließen. Kalt beim ersten Kontakt und dann in der Handfläche warmgeworden – der erste Gruß eines Hauses. Je mehr Hände ihn polieren, desto mehr wird dieser Raum zu jemandes Zuhause."},"ICON-0217":{"nm":"Spaziergang","de":"Auch das Gehen ohne Ziel hat seinen Grund. Die Zeit, in der sich verworrene Gedanken Schritt für Schritt entwirren. Wenn man zurückkommt, ist die Antwort dieselbe, doch das Gemüt ist um einiges leichter geworden."},"ICON-0218":{"nm":"Roller","de":"Zwei Räder, die durch enge Gassen gleiten. Auch wenn man nicht schnell ist, nimmt man den Wind mit dem ganzen Körper auf. Kein weiter Weg nötig – an manchen Tagen möchte man einfach frisch und frei drauflosfahren."},"ICON-0219":{"nm":"Sicherheitsbügel","de":"Bevor man einsteigt, senkt sich der Bügel fest vor die Brust. Ein zuverlässiges Versprechen, das den Angst-Abschnitt bis zum Ende gemeinsam aushält. Er sagt lautlos und kalt: Es ist in Ordnung, fest zuzuhalten."},"ICON-0220":{"nm":"Treppe","de":"Wer Stufe für Stufe steigt, stellt irgendwann fest, dass sich die Aussicht verändert hat. Die Füße lernen zuerst, dass keine Höhe auf Anhieb erreichbar ist. Das Rauf- und Runtergehen selbst war für jemanden der Schritt eines ganzen Tages."},"ICON-0221":{"nm":"Terrarium","de":"Man sperrt keinen Wald hinter Glas, sondern pflegt eine ganze Welt mit Hingabe. Ein Universum in Handflächengröße, in dem Moos wuchert und Wassertropfen perlen. Je länger man hineinschaut, desto langsamer färbt sich das Gemüt grün."},"ICON-0222":{"nm":"Podium","de":"Schon eine Handbreit höher stehend, verändert sich die Sicht. Der Ort, an dem Angst und Stolz auf derselben Höhe aufeinandertreffen. Je nach dem, wer dort steht, wird diese eine Stufe jedes Mal eine andere Bühne."},"ICON-0223":{"nm":"Flugzeug","de":"Im Moment, in dem Wolken unter einem liegen, vermisst man erst den Ort, den man verlassen hat. Es ist kein Weggehen, sondern ein Größerwerden der Welt. Selbst ein auf einer kleinen Insel gewachsener Traum überquert so den Himmel."},"ICON-0224":{"nm":"Skateboard","de":"Man muss erst das Fallen lernen, bevor man fahren kann. Mit jedem aufgeschürften Knie graviert sich ein wenig mehr Gleichgewicht in den Körper. Vier ehrliche Räder, die umso weiter rollen, je öfter man hingefallen ist."},"ICON-0225":{"nm":"Reisepass","de":"Schlägt man den Umschlag auf, sind die Seiten leer. Jeder Stempel, der darauf landet, wird zum Beweis gelebter Zeit. Ein kleines Buch, das weniger fragt, wie weit man war, sondern die Möglichkeit birgt, überall hinzugehen."},"ICON-0226":{"nm":"Wegskizze","de":"Ohne genaue Entfernungen oder Maßstäbe, aber weil der Weg mit der Hand gezeichnet wurde, kann man sich kaum verirren. Eine Karte, auf der Gassen und Ladennamen vertraut durcheinandergeraten. Eine Anleitung mit Herz ist immer wärmer als der Weg selbst."},"ICON-0227":{"nm":"Bühnenplan","de":"Ein Papier, auf dem jeder einzelne Schritt auf der Bühne als Linie eingezeichnet ist. Wo man anhält und wo man sich dreht – Pfeile haben das schon im Voraus vereinbart. Selbst ein Tanz, der frei aussieht, beginnt auf diesem einen Blatt."},"ICON-0228":{"nm":"Sitzplan","de":"An einem fremden Ort sucht man als erstes seinen eigenen Platz. Reihe und Nummer folgend, erreicht man schließlich dieses eine Feld. Ein einziges Blatt Papier setzt tausende aufgeregte Menschen ordentlich auf ihren Platz."},"ICON-0229":{"nm":"Gassenführungskarte","de":"Eine freundliche Handschrift, die jemand für all jene hinterließ, die sich im Labyrinth der Gassen verlieren könnten. Wie viele Ecken weiter abzubiegen ist. Die Herzlichkeit eines Viertels steckt Buchstabe für Buchstabe in einer kleinen Karte."},"ICON-0230":{"nm":"Ausweis","de":"Erst wenn man diese Karte um den Hals trägt, öffnet sich die Tür zur inneren Welt. Eine kleine Befugnis, die den Zutritt erlaubt, und ein stilles Zeugnis, dazuzugehören. Nur wer weiß, wie lange der Weg dahin war, kennt ihr Gewicht."},"ICON-0231":{"nm":"Tagesarmband","de":"Einmal ums Handgelenk gelegt, ist man bis zum Ablösen Teil des heutigen Tages. Ein einziges Papierband trennt Innen und Außen und wird zum Zeichen, denselben Tag geteilt zu haben. Selbst nach dem Abreißen bleibt der Abdruck noch lange."},"ICON-0232":{"nm":"Gastlabel","de":"Mit einem kleinen Namensschild auf der Brust wird an einem fremden Ort plötzlich ein eigener Platz. Wenn das Wort Willkommen auf einem Stück Papier überreicht wird, wird selbst ein Neuankömmling zum Gast."},"ICON-0233":{"nm":"Poster-Tube","de":"Der stabile Zylinder, der das aufgerollte Poster ohne eine einzige Falte schützt. Je wertvoller das Bild, desto gerader muss man es verschicken. Auch wenn man innen nichts sieht, macht er sich auf den Weg und trägt die Sorgfalt von jemandem."},"ICON-0234":{"nm":"Mappencover","de":"Das erste Blatt, das den dicken Unterlagenstapel umhüllt. Das Gesicht, das die Hände vor dem Inhalt berühren. Ist das Deckblatt ordentlich, wirkt auch die Haltung dahinter ordentlich – ein freundlicher Beginn kleiner Förmlichkeit."},"ICON-0235":{"nm":"Postkarte","de":"Man schickt einen Fetzen fernen Schauplatzes mit aufgeschriebenen Grüßen ab. Wenn er ankommt, ist auch das gesandte Herz ein wenig mitgereift und dadurch vertrauter geworden. Die langsame Wärme des Briefes, der digitale Nachrichten nie einholen können."},"ICON-0236":{"nm":"Geschenkanhänger","de":"Ein kleines Zettelchen, das man an ein Geschenk hängt. Allein die drei Wörter ‚Für dich' machen die Verpackung bereits vollständig. Der kürzeste Brief der Welt – nicht was man gibt, sondern an wen man dabei denkt."},"ICON-0237":{"nm":"Verpackungsaufkleberrolle","de":"Jedes Mal, wenn man einen Streifen abreißt, wird der Abschluss sauberer. Ein kleiner Knoten, der das aufreißwillige Ende ordentlich hält. Der letzte Handgriff einer liebevoll eingepackten Schachtel kommt stets von dieser aufgerollten Rolle."},"ICON-0238":{"nm":"Briefschutzhülle","de":"Eine transparente Lage, die den handgeschriebenen Brief vor dem Verblassen der Zeit schützt. Die Schrift bleibt sichtbar, nur Hände sollen sie nicht berühren. Eine unsichtbare Hülle, die leise schützt, was jemand am liebsten hegt."},"ICON-0239":{"nm":"Siegelaufkleber","de":"Der letzte Punkt, der den Umschlag verschließt – je kräftiger die Farbe, desto weniger entweicht das Herz. Das Versprechen, dass keine andere Hand ihn berührt hat, bevor der Empfänger ihn öffnet. Selbst Geheimnisse brauchen eine so hübsche Schnur."},"ICON-0240":{"nm":"Zettelblock für Nachrichten","de":"Ein kleines Buch, das kurze Zettel bündelt, die man jemandem zustecken möchte. Jedes Blatt ist ein Wort, das man weitergeben will. Sammelt man ungesagte Dinge Seite für Seite, wächst der Mut, sie eines Tages wirklich zu sagen."},"ICON-0241":{"nm":"Aufstellaufsteller","de":"'Hier entlang' wenn aufgestellt, 'Heute war's das' wenn zugeklappt. Breitbeinig an der Ecke stehend, hält er den ganzen Tag für jemanden wacht, der sich verlaufen könnte. Der zusammengeklappte Abend ist für mich die herzlichste Erholung."},"ICON-0242":{"nm":"Postsortierbänder","de":"Schlingt man ein Bündel Postkarten ein, werden aus den verstreuten Grüßen endlich ein herzlicher Strauß. Ein leichtes Band bündelt Worte, die weit reisen wollen, ordentlich zusammen und begleitet sie auf dem Weg ruhig von hinten."},"ICON-0243":{"nm":"Dankzettelset","de":"Weil Dankesworte so leicht von den Lippen gleiten, schreibt man sie auf ein handflächengroßes Stück Papier und hält sie behutsam zusammen. Je dicker das Bündel wird, desto mehr ist daneben auch die Tiefe des Herzens gewachsen, das man jemanden schuldet."},"ICON-0244":{"nm":"Fanchant-Musterblatt","de":"Ein Musterblatt mit dem Hinweis ‚Bitte so rufen'. Der noch nicht mit einer Stimme bekleidete Ruf ist so still aufregend wie eine leere Partitur, die auf den ersten Takt wartet."},"ICON-0245":{"nm":"Voraufzeichnungszettel","de":"Ein Zettel zur Voranmeldung für eine Aufzeichnung hängt stets im Fünf-Uhr-morgens-Feld. Den kleinen Zettel, der mitbekommt, wie man den Schlaf kürzt, um sich einen Platz zu sichern, weiß alles – und schreibt still mit."},"ICON-0246":{"nm":"Fansign-Ticket","de":"Ein Blatt, das festlegt, als wie vielter man seinen Gruß übermittelt. In der Reihe zu stehen bedeutet nicht, auf seine Reihe zu warten, sondern sich kurz eine Nummer zu leihen, weil man die Zuneigung nicht nummerieren konnte."},"ICON-0247":{"nm":"Wartearmband","de":"Eine einzige Zahl teilt die Reihenfolge des heutigen Tages auf. Ob vorn oder hinten – wer dieses leichte Band ums Handgelenk trägt, ist letztlich ein Gleichgesinnter, der zur selben Bühne gekommen ist."},"ICON-0248":{"nm":"Pokaordnungsliste","de":"Obwohl es dasselbe Gesicht ist, ordnet man es Feld für Feld auf und schreibt es auf. Je voller die Liste wird, desto geordneter das Gemüt – und das eine noch leere Feld lässt das Herz klopfen vor der Aufregung, es heute noch zu füllen."},"ICON-0249":{"nm":"Album-Checkliste","de":"Version, Fotokarte, Versiegelungszustand – eine Liste der Zuneigung in Zahlen heruntergeschrieben. Den Tag, an dem alles ausgefüllt ist, schon vorwegzudenken und heute einen weiteren Kreis sauber zu malen – diese Freude schreibt sich täglich fort."},"ICON-0250":{"nm":"Fanchant-Anleitung","de":"Handbewegung, Rufrhythmus, Atemzugpausen – alles steht drauf. Damit sogar Neulinge sofort mit einer Stimme mitsingen, wandert der kleine Zettel als freundlicher Wegweiser von Hand zu Hand."},"ICON-0251":{"nm":"Privates Notizbuch","de":"Hier schreibt man nur Sätze auf, die man niemandem zeigen wird. Die Seiten, die noch nie aufgeschlagen wurden, sind die aufrichtigsten – das weiß dieses Heft und bewahrt es schweigend, den Einband geschlossen."},"ICON-0252":{"nm":"Jubiläumsstempelkarte","de":"Drücken – schon wird ein weiterer Tag besonders. Mit einem kleinen Stempel auf einem gewöhnlichen Datum schreibt sich ‚Heute' still in die Liste der Tage ein, an die man sich erinnern möchte."},"ICON-0253":{"nm":"Klemmbrettcover","de":"Auch wenn Wind pfeift oder Regen einfährt, hält es die eingeklemmten Blätter bis zuletzt. Als selbst ernannte Rüstung des Bretts bin ich der zuverlässige Bodyguard der darauf geschriebenen Worte."},"ICON-0254":{"nm":"Dateiindex","de":"Damit man sich in dickem Datenmaterial nicht verirrt, streckt er sein kleines Zünglein heraus und zeigt: ‚Hier'. Ein einziges farbiges Blatt beherrscht auf einen Blick hundert Seiten."},"ICON-0255":{"nm":"Registerreiter","de":"Dies gehört in dieses Fach, jenes in jenes. Mein Job ist es, das Durcheinander der Welt Zeile für Zeile ordentlich zu sortieren. In dem Moment, in dem ein Etikett aufgeklebt wird, findet der Wirrwarr endlich seinen Platz."},"ICON-0256":{"nm":"Mini-Unterschriftenbrett","de":"Im Moment des Stempeldrucks fühlt man sich irgendwie wie ein richtiger Erwachsener. Klein, aber mit einer resoluten Autorität – ein einziger Genehmigungsstempel, und die aufgestapelte Arbeit ist ordentlich erledigt."},"ICON-0257":{"nm":"Dokumentenrolle","de":"Innen sieht man alles – nichts zu verbergen. Wichtige Papiere an sich haltend, schützt sie mit dem transparenten eigenen Körper vor Regen und Knicken und bringt sie sicher zum Bestimmungsort."},"ICON-0258":{"nm":"Anwesenheitsband","de":"Angekommen – ein weiteres Feld wird gefüllt. Wenn die täglichen Fußabdrücke sich entlang des Bandes reihen, wird eine unsichtbare Gewissenhaftigkeit endlich zu einem sichtbaren Muster."},"ICON-0259":{"nm":"Fehlerheft","de":"Fehler aufzuschreiben bedeutet nicht, Scham anzusammeln. Um nicht zweimal an derselben Stelle zu straucheln, macht man aus dem gestrigen Fehler den Wegweiser von heute. Die erste Seite auf dem Weg, das Schlingern schrittweise zu bändigen."},"ICON-0260":{"nm":"Terminplanungsstempel","de":"Drückt man auf einen leeren Terminplan, entsteht ein ‚Versprechen'. Die Magie, mit einem einzigen Handgelenksschwung den Tag zu bestimmen – diese Magie ist in Wirklichkeit ein anderer Name für fleißige Vorausplanung."},"ICON-0261":{"nm":"Rückenaufkleber","de":"Das Namensschild der Bücher, die dem Regal den Rücken zukehren. Die kurzen Buchstaben auf dem schmalen Rücken winken genau das eine gesuchte Buch unter Hunderten sofort heran."},"ICON-0262":{"nm":"Fotoschutzfolie","de":"Keine bloßen Hände. Nicht einmal ein Fingerabdruck soll bleiben – und so legt sie sich leise über den kostbaren Schnappschuss. Herzlichkeit schützt mit solch zarten Händen lange."},"ICON-0263":{"nm":"Filmindex","de":"Nummeriert man jeden Filmstreifen, finden die verstreuten Momente wieder ihre erzählerische Reihenfolge. Ein kleiner Wegweiser, der die ins Licht geschriebene Erinnerung vor Verwechslung bewahrt."},"ICON-0264":{"nm":"Fotohülle","de":"Ein transparentes Zuhause, in das man rechteckiges Glück Blatt für Blatt stellt. Keine Sorge um gedrückte Ecken – das liebste Gesicht strahlt darin alle vier Jahreszeiten ordentlich."},"ICON-0265":{"nm":"Mini-Fotobriefumschlag","de":"Bevor die Wärme des frisch entwickelten Fotos verblasst, nimmt der kleine Umschlag es mit weit ausgebreiteten Armen auf. Ein Schnappschuss, der durch den kleinen Eingang tritt, wird bald der Schatz in jemandes Tasche."},"ICON-0266":{"nm":"Lentikularcover","de":"Mein Auftrag ist es, die anspruchsvolle Aufnahme, die ihren Ausdruck beim Neigen wechselt, makellos zu schützen. Alle Gesichter aus jedem Winkel zu bewahren macht mich ganz schön geschäftig."},"ICON-0267":{"nm":"Schnittlabel","de":"Das Label zeigt, welcher von vier Schnitten der Beste ist. Diese kleine Alltagsarbeit, das Gelungene und das Witzige nebeneinander zu sortieren, ist das Geheimnis, die Erinnerung zweimal zu genießen."},"ICON-0268":{"nm":"Fotostreifenband","de":"Es bündelt das schmale, vierfeldige Andenken sauber zusammen. Das Lachen jenes Tages, das davonfliegen wollte, fest umschlungen, sicher bis in die Tiefe der Tasche getragen."},"ICON-0269":{"nm":"Fotoeck-Aufkleber","de":"Beim Einlegen eines Fotos ins Album hält der kleine Helfer behutsam alle vier Ecken. Kein Überhäufen mit Klebstoff, und es fällt trotzdem nicht heraus – Sorgfalt beginnt eben an den Ecken."},"ICON-0270":{"nm":"Druckkorrekturkarte","de":"Ein wenig wärmer, ein Hauch dunkler. Eine Tabelle, an deren Zahlen man solange dreht, bis die gewünschte Farbe erscheint – und ein gewöhnlicher Schnappschuss wird so ganz leise zum Kunstwerk."},"ICON-0271":{"nm":"Belegklammer","de":"Geknitterte Belege hält sie fest im Mund und lässt sie nicht los. Mit kleinem Mund brav die Tagesausgaben im Griff zu haben macht die Monatsabrechnung um einiges leichter."},"ICON-0272":{"nm":"Reservierungsbestätigung","de":"Ein einziger Satz ‚Ihre Reservierung ist bestätigt' lässt das Herz aufatmen. Ein Blatt Papier wird Beweis des Versprechens und bewahrt die Aufregung bis zu jenem Tag sorgfältig."},"ICON-0273":{"nm":"Rückgabebeleg","de":"Der kleine, aber aufrechte Beweis, dass man Geborgtes an seinen Platz zurückgebracht hat. In dem Moment, in dem dieses Blatt in die Hand gedrückt wird, ist eine Last, die auf dem Herzen lag, leicht abgehoben."},"ICON-0274":{"nm":"Aufbewahrungsscheinhalter","de":"Damit der Abholschein für das abgegebene Gepäck nicht verloren geht, halte ich ihn fest. Denn das Schicksal eines kleinen Zettels kann das Ende von jemandes Tag bestimmen."},"ICON-0275":{"nm":"Leihanhänger","de":"Ein kleines Anhängerchen, das an jedem verliehenen Gegenstand sanft wippt. Folgt man diesem Schwänzchen, offenbart sich sofort, wer was mitgenommen hat – und auch das ausgefeilteste Rätsel um vermisste Dinge löst sich schnell."},"ICON-0276":{"nm":"Kontrollliste","de":"Stück für Stück mit den Augen abtasten, ob nichts fehlt. Wenn die Häkchen sich aneinanderreihen, erhält das Unsichtbare endlich den Namen Vertrauen."},"ICON-0277":{"nm":"Abrechnungsrolle","de":"Schreibt man Einnahmen und Ausgaben auf den Umschlag, stellen sich die unordentlichen Zahlen ruhig in eine Reihe. Am Ende der Abrechnung ist es stets dieses kleine Memo, das leise den Schlusspunkt setzt."},"ICON-0278":{"nm":"Versandetikett","de":"Wohin die Reise geht und wer das Ziel ist, trägt es auf sich geschrieben, wenn es loszieht. Im Moment, in dem das Etikett aufgeklebt wird, wird der Karton zum aufgeregten Reisenden mit Bestimmungsort."},"ICON-0279":{"nm":"Empfangsband","de":"Ein ‚Gut erhalten' gebündelt zu einem Band zurückgeschickt. Erleichterung des Empfängers und Beruhigung des Absenders halten sich auf diesem kleinen Band still an den Händen."},"ICON-0280":{"nm":"Karteikarten-Ring","de":"Worte, die einzeln verstreut verloren gehen würden, hält ein kleiner Ring zusammen aufgefädelt. Blättert man durch sie hindurch, sind die einst fremden Wörter irgendwann vertraute Freunde geworden."},"ICON-0281":{"nm":"Aussprachenotizband","de":"An der Stelle, wo die Zunge immer wieder abrutscht, befestigt man ein kleines Merkzeichen. Auch fremde Laute, die sich im Mund verirren, finden ihrem Klang entlang. Die erste Seite, die einen schroffen Laut behutsam zähmt."},"ICON-0282":{"nm":"Übersetzungszettelbox","de":"Kleine Brücken, die zwischen Wort und Wort übersetzen, liegen sorgfältig gefaltet, eines nach dem anderen, darin. Reicht man ein mühsam gesuchtes Wort auf einem Zettel hinüber, kommt sich das zuvor unverständliche Herz mit einem einzigen Zettel dazwischen näher."},"ICON-0283":{"nm":"Satzschnipselblatt","de":"Ein Satz, der einem ins Herz trifft, bleibt länger, wenn man ihn mit der Hand abschreibt. Klebt man eine aus einem Buchrand ausgeschnittene Zeile an den Schreibtisch, hält dieser Text den heutigen Tag, der zu versinken drohte, still aufrecht."},"ICON-0284":{"nm":"Notizindex","de":"Bunte kleine Fähnchen, eingesteckt, um sich in einem dicken Buch nicht zu verirren. Wer weiß, wohin er zurückkehrt, kann weiter schweifen – das sagen die herausstehenden Reiter still zwischen den Buchseiten."},"ICON-0285":{"nm":"Lernchip","de":"Ein kleines Markierungszeichen, das man neben das Gelernte setzt. Ein kleiner Anker, der festhält, was nur kurz einkehren und wieder verschwinden wollte – in jedem geschwärzten Feld steckt die gestrige Nachtarbeit still vergraben."},"ICON-0286":{"nm":"Quizumschlagpack","de":"Bevor der Umschlag geöffnet wird, weiß niemand, was herauskommt. Die paar Sekunden, in denen man die verklebte Stelle betastet – ein Päckchen Aufregung, in dem eine ordentlich gefaltete Aufgabe steckt und das Kribbeln gleich mit versiegelt."},"ICON-0287":{"nm":"Grammatikheft mit Register","de":"Regeln lernt man nicht mit dem Kopf, sondern mit den Händen. Das Heft, dessen am häufigsten aufgeschlagene Seite zuerst weich wird – die abgeriebenen Ecken sind die Jahresringe der Zeit, die du durchgehalten hast."},"ICON-0288":{"nm":"Sprech-Übungsblatt","de":"Ein Blatt für diejenigen, für die Anfangen zu reden das Schwerste auf der Welt ist. Folgt man Feld für Feld mit dem Finger, findet auch das erste zitternde Wort tief im Hals schließlich seine eigene Stimme. Mut braucht eben auch seine Reihenfolge."},"ICON-0289":{"nm":"Farb-Rauhentwurf","de":"Die noch unfertigen Farben liegen rau nebeneinander und holen Atem. Kein Endzustand, sondern noch pure Möglichkeit – auf diesem einen ungefeilten Blatt stecken mehr Morgen als irgendwo sonst."},"ICON-0290":{"nm":"Moodboard-Schnipsel","de":"Sammelt man verstreute Eindrücke an einem Ort und klebt sie zusammen, nimmt die schwer greifbare Stimmung allmählich Kontur an. Die noch namenlosen Sinneseindrücke deuten sich gegenseitig stützend still an."},"ICON-0291":{"nm":"Musterbuch","de":"Das Gitter des Furoshiki und das Flechtwerk der Gitterstäbe sind ordentlich in einem Band zusammengefasst. Wo dasselbe Muster bis zum Ende wiederkehrt, steckt keine Gleichgültigkeit, sondern ein Versprechen – das feste Herz, das einen Faden durchhält."},"ICON-0292":{"nm":"Stoffmusterbuch","de":"Obwohl es dasselbe Licht ist, legt sich Haut und Schatten je nach Stoff anders. Die Nacht vor der Kostümwahl, in der man Dutzende Male mit den Fingern darüber strich und zögerte – diese eine Nacht steckt konserviert in jedem kleinen Musterstück."},"ICON-0293":{"nm":"Logo-Verbotsliste","de":"Ein Blatt, auf dem zuerst ordentlich aufgeschrieben steht, was nicht getan werden darf. In den Konturen, durch die rote Kreuzzeichen gezogen wurden, wird die Freiheit paradoxerweise klarer – und aus dem scheinbar toten Ende öffnet sich ein neuer Weg."},"ICON-0294":{"nm":"Farbreferenzchip","de":"Weil Farbe sich mit Worten schlicht nicht beschreiben lässt, hat man eigens Musterchips angefertigt. Den flüchtigsten Augenblick eines Abendrots auf eine kleine Handfläche einzufangen, damit man ihn dem Nächsten hält und sagen kann: ‚Genau diese Farbe.'"},"ICON-0295":{"nm":"Layout-Entwurf","de":"Ein erster locker gezeichneter Plan, was wohin kommt. Seinen Platz zu bestimmen ist gleichbedeutend damit, sich festzulegen – und zwischen den ungelenk verstreuten Linien erwacht das Gleichgewicht des Ganzen langsam."},"ICON-0296":{"nm":"Materialnotizbrett","de":"Holz, Ton, Stein – die Namen des Tastbaren stehen dicht an dicht geschrieben. Nur wer das Gefüge erst mit den Händen liest, kennt das Geheimnis: Was man als Material wählt, bestimmt schon zur Hälfte, was daraus werden wird."},"ICON-0297":{"nm":"Pauspapier","de":"Man legt das dünne Papier auf die Vorlage und folgt ruhig der Linie. Während man sich den Weg eines anderen kurz ausleiht, eignet die Hand ihn sich an – und zwischen den nachgezeichneten Linien schleicht sich leise eine eigene Linie herein."},"ICON-0298":{"nm":"Einlassführungsband","de":"Die Menschen reihen sich dem langen Band am Boden entlang an und treten ein. Eine stille Lenkung, damit aufgeregte Schritte nicht durcheinander geraten – eine unsichtbare, herzliche Hand, die die Aufregung trägt, ohne dass sie zusammenbricht."},"ICON-0299":{"nm":"Veranstaltungsschild","de":"Ein Schild, das stellvertretend ‚Hier entlang' hält. An jedem Knotenpunkt aufgestellt, führt diese kleine Freundlichkeit die Hand von jemandem, der einen fremden Tag zum ersten Mal erlebt."},"ICON-0300":{"nm":"Stand-Nummernschild","de":"Eine einzige Nummer an jedem Stand legt eindeutig fest, wer dieses Eck gehört. Nur eine kleine Zahl, aber sie ist das Versprechen ‚Hier ist dein Platz' – und an einem fremden Veranstaltungsort gibt es plötzlich einen Ort, an den man zurückkehren kann."},"ICON-0301":{"nm":"Mitarbeitereinverständnis","de":"Eine Unterschrift, die festhält, dass man gemeinsam an einem Strang ziehen will. Dieses dünne Blatt Papier trägt das Gewicht gegenseitigen Vertrauens in sich – und von hier aus beginnt jede helfende Hand bei der Veranstaltung."},"ICON-0302":{"nm":"Erlebnisticket-Bündel","de":"Ein handliches Bündel dicker Eintrittskarten. Je mehr man davon verteilt, desto mehr \"erste Male\" schenkt man anderen – ein warmherziges Paket, das sich beim Berühren weich anfühlt."},"ICON-0303":{"nm":"Warteschlangen-Markierung","de":"\"Bitte hier warten\", sagt der Boden leise. Wenn viele diesen stillen Aufruf befolgen, wird selbst eine lange Schlange zu einem ruhigen Anblick – ein kleines Schild, das Ungeduld in Gelassenheit verwandelt."},"ICON-0304":{"nm":"Abholschild","de":"Ein kleines Anhänger-Schild für vorbestellte Artikel zur Selbstabholung. In dem Moment, in dem man es in der Hand hält, löst sich die Anspannung von den Schultern – der lange ersehnte Moment bekommt endlich eine Form."},"ICON-0305":{"nm":"Überraschungsbox-Ticket","de":"Die Freude, eines von vielen zu wählen, ohne zu wissen, was darin steckt. Das Herz schlägt schneller beim Rascheln von innen – die kurze Sekunde vor dem Öffnen ist der aufregendste Moment des Tages."},"ICON-0306":{"nm":"Tausch-Aufkleber","de":"Ein kleiner runder Stempel, der den erfolgreichen Abschluss eines Tausches bestätigt. Ein sauberer Schlusspunkt zwischen zwei Händen – einmal aufgeklebt, wird das ganze Geschäft warm und rund."},"ICON-0307":{"nm":"Archiv-Siegelband","de":"Ein Band, das eine wertvolle Box behutsam umschlingt und versiegelt. Darin steckt die stille Bitte, sie nicht leichtfertig zu öffnen, und die zarteste Form der Wertschätzung für das, was darin liegt."},"ICON-0308":{"nm":"Geheimnotiz-Kapsel","de":"Worte, die man sagen wollte, sicher in einem kleinen Behälter verwahrt. Fest verschlossen wie ein begrabenes Geheimnis wartet diese winzige Schatulle in der Handfläche, bis der Tag kommt, an dem man sie wieder öffnet."},"ICON-0309":{"nm":"Kleine Scrapbook-Karte","de":"Ein ausgeschnittenes Stückchen, das die Stimmung jenes Tages sanft festhält. Leichter als ein Tagebuch, greifbarer als ein Foto – ein handtellergroßes Papier bewahrt die flüchtige Erinnerung an einen Tag."},"ICON-0310":{"nm":"Erster-Besuch-Aufzeichnung","de":"Das Kribbeln des allerersten Schritts auf diese Insel, festgehalten in einer kurzen Zeile. Kurz bevor das Fremde zum Vertrauten wird, bewahrt dieses Blatt das reinste erste Gefühl für alle Zeit."},"ICON-0311":{"nm":"Erinnerungs-Übersichtstabelle","de":"Eine Tabelle, in der Erinnerungen sorgfältig nach Art und Kategorie sortiert werden. Wer alles ungeordnet stapelt, riskiert, seinen liebsten Tag zu begraben – daher bekommt jedes Wertvolle seinen eigenen festen Platz."},"ICON-0312":{"nm":"Sprechblasen-Memo-Chip","de":"Worte, die man sagen wollte, schweben wie Sprechblasen auf dem Papier. Selbst die Dinge, die man kaum aussprechen konnte, finden innerhalb der runden Kontur ihren Mut – ein kleiner, warmer Kanal, durch den das Herz spricht."},"ICON-0313":{"nm":"Datumshalter","de":"Ein kleiner Ständer, der das heutige Datum aufrecht und direkt im Blick hält. Wählt man aus dem Strom der Tage einen einzigen heraus und stellt ihn in den Mittelpunkt, bekommt selbst ein gewöhnliches Datum eine besondere Wärme."},"ICON-0314":{"nm":"Sammlungsnummern-Anhänger","de":"Eine einzigartige Nummer, die jedem geliebten Stück einzeln zugewiesen wird. Etwas zu sammeln bedeutet, es als das einzige seiner Art auf der Welt zu benennen – auf dem kleinen Anhänger ist das Gewicht des Herzens deutlich eingeschrieben."},"ICON-0315":{"nm":"Archiv-Einlegeblatt","de":"Ein dünnes Zwischenblatt, in das man Dinge einlegt, die man lange betrachten möchte. Sie nur einen Hauch von Licht und Zeit fernzuhalten – etwas zu lieben bedeutet letztlich, es gut zu bewahren."},"ICON-0316":{"nm":"Fotocard-Toploader-Kordel","de":"Eine feine Kordel, die den Toploader zum Umhängen um den Hals ermöglicht. So trägt man seinen Liebling den ganzen Tag auf Herzhöhe bei sich – an diesem dünnen Faden hängt ein ganzer Tag voller Zuneigung."},"ICON-0317":{"nm":"Fotocard-Aufstell-Pin","de":"Ein kleiner Pin, der eine Fotocard aufrecht auf dem Schreibtisch hält. Liegend ist sie nur ein Blatt Papier, aufgestellt wird man zu einem Gegenüber – er schafft einen Ort, an dem der Blick gerne verweilt."},"ICON-0318":{"nm":"Holografische Fotocard-Folie","de":"Eine dünne Folie, über die je nach Blickwinkel ein Regenbogen fließt. Diese lichtgefangene Schicht verleiht gewöhnlichen Karten Sternenschimmer – bei jedem Kippen des Handgelenks erwacht ein anderer Ausdruck in einem kleinen Zauber."},"ICON-0319":{"nm":"Fotocard-Schutzhülle","de":"Als ob sich das Lieblingstück bereits biegt, wenn nur eine Ecke gedrückt wird. Diese transparente Rüstung umschließt ein wertvolles Einzelstück fest – echte Fürsorge geht stets mit dieser stillen Vorsicht einher."},"ICON-0320":{"nm":"Fotocard-Sortiertablett","de":"Ein flaches Tablett, in dem Dutzende Fotocards ordentlich nebeneinanderliegen. Ungeordnet ist es ein Haufen, doch in Reihe gelegt wird es zu einer Sammlung – bei jeder sorgfältigen Geste entstehen Schichten voller Zuneigung."},"ICON-0321":{"nm":"Fotocard-Tauschkuvert","de":"Wenn man eine Fotocard in ein Kuvert steckt und übergibt, zögert die Hand kurz. Es ist keine Verabschiedung, sondern die Bitte, zum Liebling von jemand anderem zu werden. Im Moment des Faltens wechselt eine kleine Verbindung leise die Hände."},"ICON-0322":{"nm":"Fotocard-Deko-Stift","de":"Was die Lücken füllt, ist kein Strich – es ist ein Gefühl. Wo die Stiftspitze hinzieht, sprießen kleine Herzen und Sterne, und ein gewöhnliches Blatt Papier erwacht als eine einzigartige Liebesbotschaft an die Welt. Verzieren ist ein anderes Wort für Bekennen."},"ICON-0323":{"nm":"Fotocard-Klemmenring","de":"Klick – das Geräusch der schließenden Klemme. Mit diesem kleinen Verschluss ordnen sich die verstreuten Karten in einer Reihe. Die ganze Schicht über in der Tasche geschüttelt, ohne eine Ecke zu beschädigen. Festigkeit kann so still sein."},"ICON-0324":{"nm":"Fotocard-Transport-Pouch","de":"Im Öffnen und Schließen des Reißverschlusses hat sich längst eine Gewohnheit eingeschliffen. Selbst beim Regenschauer, selbst im Gedränge bleibt das Innere trocken. Das Wertvollste an den tiefsten Ort zu legen – das ist die sanfte Arbeit des Transportierens."},"ICON-0325":{"nm":"Fanmeet-Armband-Kordel","de":"Die Hände des Staffmitglieds, das die Kordel ums Handgelenk knüpfte, waren warm – so erinnerte sich ein Fan noch lange danach. Mit einem einzigen Knoten gehört man zu diesem Ort. Die doppelt geschlungene Kordel hält ein ganzes Tage-Kribbeln fest."},"ICON-0326":{"nm":"Einlass-Armband","de":"Genau in dem Moment, in dem man den Eingang passiert, trennen sich drinnen und draußen deutlich. Den ganzen Tag getragen, schmiegt es sich irgendwann an die Haut – beim Abnehmen hinterlässt es einen blassen Abdruck, wie ein Beweis des Dagewesenseins."},"ICON-0327":{"nm":"Talkrunden-Chip","de":"Wenn die Talkrunde beginnt, rollt ein Chip heran. Wer zuerst spricht, welche Frage gezogen wird – dieser kleine Zufall verändert die Stimmung von Grund auf. Die Launen eines Chips sind liebenswerter als jedes durchgeplante Skript."},"ICON-0328":{"nm":"Autogrammstunden-Wartenummer","de":"Mit dem Zettel mit der Zahl in der Hand stellt man sich an. Nummer 142. Während man die 141 vor sich abzählt, taktet das Herz schon die Reihe mit. Die Wartezeit ist lang, aber dank dieses einen Blattes wird selbst sie zum Teil der Aufregung."},"ICON-0329":{"nm":"High-Touch-Handschuh","de":"Im flüchtigen Moment des Handaufeinanderschlagens fängt der Handschuh diese kurze Wärme stellvertretend auf. Die Hände, die den ganzen Tag in Erwartung dieses 0,5-Sekunden-Kontakts gewärmt wurden. Selbst durch den Stoff hindurch – das Zittern kann man damit nicht aufhalten, wie jeder dann merkt."},"ICON-0330":{"nm":"Erinnerungsfoto-Pin","de":"Klick – mit einem einzigen Geräusch ist der heutige Tag für immer festgehalten. Selbst der linkische Gesichtsausdruck im vom Pin fixierten Rahmen wird später zur sehnlichst vermissten Szene. Festhalten ist das zärtlichste Begehren des Augenblicks."},"ICON-0331":{"nm":"Sitzplatz-Schleifen-Anhänger","de":"Die kleine Schleife, die an der Stuhllehne hängt, wiegt sich, obwohl kein Wind weht. Ein Zeichen, das jemand befestigte – die Spur, dass hier ein Mensch war. Selbst auf dem leeren Platz nach dem Konzert scheint die Schleife noch den Takt zu kennen."},"ICON-0332":{"nm":"Geschenk-Prüfetikett","de":"Jedes einzelne Geschenk bekommt ein Etikett. Wurde es abgeschickt, überprüft, fehlt etwas? Auch das Empfangen von Zuneigung braucht Organisation – dieser kleine Aufkleber verbindet Sorgfalt mit Sorgfalt, lückenlos."},"ICON-0333":{"nm":"Erinnerungs-Slip","de":"Ein Zettel, auf dem man aufschrieb, was man lange behalten wollte. Das Wetter des Tages, die Platznummer, den Titel des letzten Liedes. Die Erinnerung verblasst, dieser Slip aber nicht. Auch Erinnerungen brauchen manchmal ein kleines Formular."},"ICON-0334":{"nm":"Fächer-Handtuch-Ring","de":"Wenn man einen Ring am Handtuchende befestigt, rutscht es nicht von der Schulter. Zwischen Abwischen, Über-dem-Kopf-Drehen und erneutem Umhängen. Diese kleine Verbindung hält die Geste der Unterstützung ununterbrochen am Laufen."},"ICON-0335":{"nm":"Slogan-Klemme","de":"Die Klemme hält beide Enden des Slogans fest. Egal wie hoch man die Arme reckt – die Buchstaben knicken nicht und wehen nicht davon. Hier, am unsichtbarsten Ort, sorgt jemand dafür, dass die Botschaft aufrecht bleibt: der stillste Nebendarsteller."},"ICON-0336":{"nm":"Geräuschloser Pouch","de":"Der Reißverschluss gleitet langsam und geräuschlos. Sorgfältig konstruierte Stille, damit an einem Ort, wo Ruhe versprochen ist, kein einziges Geräusch entweicht. Rücksichtnahme bedeutet manchmal, die Dinge unhörbar zu machen – das sagt dieser Pouch leise."},"ICON-0337":{"nm":"Klatsch-Rhythmus-Chip","de":"Jedes Mal, wenn die Handflächen aufeinandertreffen, zählt der Chip den Takt. Klat, klat, klat – die verstreuten Hände kommen irgendwann zu einem gemeinsamen Rhythmus zusammen. Der Zauber, dass Tausende von Klatschen zu einem Atemzug werden, wird von diesem kleinen Chip still unterstützt."},"ICON-0338":{"nm":"Fanchant-Mappe","de":"Aufgeklappt stehen die Fanchants Schritt für Schritt aufgeschrieben. Welche Farbe bei welcher Strophe, wann der Jubel eingesetzt wird. Selbst Neulinge werden mit dieser Mappe schnell zur Familie. Ein kleiner Leitfaden für geteilte Versprechen."},"ICON-0339":{"nm":"Sitzplatz-Fächer-Kordel","de":"Befestigt man eine Kordel am Fächergriff, fällt er auch beim Loslassen nicht zu Boden. Wenn man an einem heißen Tag wedelt und die Hände für Jubel freigibt, baumelt er am Handgelenk. Eine Kordel kühlt Hitze und Aufregung zugleich."},"ICON-0340":{"nm":"Glitzerndes Folienstückchen","de":"Im Licht bricht sich jedes Stück in einem anderen Winkel. In der Handfläche liegend schimmert ein kleiner Regenbogen, beim Bewegen lebt die Farbe auf. Glitzern ist vielleicht die Kunst, Licht in viele kleine Teile zu teilen."},"ICON-0341":{"nm":"Kleines Banner-Stab","de":"Entfaltet man den kleinen Stab, spannt der Stoff sich im Wind. Hoch in beiden Händen gehalten reicht die Schrift bis über die Zuschauermenge, zusammengeklappt passt er in eine Taschentasche. Die Größe des Herzens misst man nicht an der Länge des Stabes."},"ICON-0342":{"nm":"Fanchant-Aufkleber-Pack","de":"Auf jedem Aufkleber ist ein Unterstützungsspruch eingeprägt. Im Tagebuch, am Handy, an der Laptopecke – überall wo man klebt, färbt sich der Alltag mit Zuneigung. Das Mögen hinterlässt seine Spuren überall im Leben."},"ICON-0343":{"nm":"Album-Schutzhülle","de":"Die Hände, die das Album in eine Hülle stecken, sind behutsam. Damit die Ecken nicht abnutzen, die Sonne es nicht ausbleicht. Musik hört man mit den Ohren, aber dieses eine Blatt erinnert sich die Hand. Eine Rüstung aus Herzensliebe, um Geliebtes lange bei sich zu behalten."},"ICON-0344":{"nm":"Disc-Sleeve-Ring","de":"Steckt man die Disc in eine Hülle und bindet Ringe daran, entsteht ein ganzes Musikalbum-Heft. Das raschelnde Geräusch beim Umblättern gefällt. Verstreute Musik ordentlich in der Hand zu vereinen – das ist die stille Freude des Sammlers."},"ICON-0345":{"nm":"Merchandise-Trennwand","de":"Mit einer Trennwand findet jedes Merchandise seinen Platz. Hier die Fotocards, dort die Schlüsselanhänger, daneben die Leuchtstäbe. Ordnen bedeutet, den Dingen ein Zuhause zu bauen. Wenn die Fächer getrennt sind, wird Chaos zu Ordnung."},"ICON-0346":{"nm":"Überraschungspack-Siegelkordel","de":"Bindet man den Eingang des Überraschungspacks mit einer Kordel, ist noch niemandes Schicksal besiegelt. Solange man nicht öffnet, ist jeder der Hauptdarsteller der Erwartung. Das Zittern der Hand beim Lösen der Kordel – das ist die Freude, die diese Kordel all die Zeit bewahrt hat."},"ICON-0347":{"nm":"Spezial-Bonus-Sortierbox","de":"Die Bonus-Artikel stehen nach Art sortiert in der Box. Postkarten zu Postkarten, Lesezeichen zu Lesezeichen. Je voller die Fächer werden, desto klarer ist die gesammelte Zeit auf einen Blick zu sehen. Ordnen ist das Register der Erinnerungen."},"ICON-0348":{"nm":"Versions-Unterscheidungsetikett","de":"Es gibt Dinge, die ähnlich aussehen und doch nicht gleich sind. Ein Etikett trennt Version A von Version B, Erstauflage von Nachdruck. Dank dieses kleinen Zeichens verschwindet die Verwirrung, und die Welt des Sammelns bekommt ein weiteres klares Namensschild."},"ICON-0349":{"nm":"Erstwochenverkauf-Notiz","de":"In der ersten Woche nach der Veröffentlichung schwankt das Herz bei einer einzigen Zahl. Die säuberlich eingetragenen Häkchen auf dem Notizzettel. Sammeln sich die Aufzeichnungen der Tage, entsteht eine kleine Ergebnistabelle der Unterstützung. Eine sorgfältige Gewohnheit, Zuneigung in Zahlen zu übersetzen."},"ICON-0350":{"nm":"Poster-Schutzkappe","de":"Steckt man eine Kappe auf das Ende des aufgerollten Posters, bleibt es entrollt und still. Ob an die Wand hängen oder einrahmen – während man überlegt, knickt es nicht. Ein kleines Endstück, das die liebste Szene ordentlich schützt."},"ICON-0351":{"nm":"Stehfoto-Aufsteller","de":"Auf dem Aufsteller lehnt das Foto schräg. In einer Ecke des Schreibtischs, genau auf Augenhöhe. Eine Erfindung, die dafür sorgt, dass die Augen beim Vorbeigehen begegnen. Die einfachste Methode, ein geliebtes Gesicht in die alltägliche Landschaft zu holen."},"ICON-0352":{"nm":"Probeband-Rolle","de":"Mit Klebeband auf dem Boden werden die Standorte markiert. Ein Schritt, zwei Schritte, genau hier. Die Bewegungsabläufe werden durch das Betreten derselben Markierungen dutzende Male im Körper verankert. Unter dem glänzenden Bühnenbild liegt diese ehrliche Spur aus Klebeband."},"ICON-0353":{"nm":"Bühnen-Markierungspin","de":"Ein einziger Pin im Bühnenboden zeigt den nächsten Schritt an. Selbst im Dunkeln findet der Fußspitz diesen Ort zuerst. Ein Weg, der auch im Unsichtbaren genau ist – die unsichtbare Karte, die durch unzählige Proben gezeichnet wurde."},"ICON-0354":{"nm":"Mitarbeiter-Ohrstöpselschutz","de":"Mit dem Ohrstöpsel werden die Jubel aus dem Zuschauerraum etwas gedämpft, und nur die Stimme mit dem Einsatz-Signal kommt klar durch. Das Ohr des Backstage-Personals hört immer zwei Welten gleichzeitig. Ein kleines Hilfsmittel, das aus dem Lärm das Signal herausfiltert."},"ICON-0355":{"nm":"Garderobe-Kleiderhaken-Schild","de":"An jedem Kleiderbügel hängt ein Namensschild. Kostüm 1, Kostüm 2, Zugaben-Kostüm. Auf dem Schild mit der Reihenfolge des Umkleidens ist der gesamte Tag als Abfolge von Kleidungsstücken bereits vorgezeichnet. Die stille Ordnung, die die Hektik bändigt."},"ICON-0356":{"nm":"Requisiten-Prüfanhänger","de":"Bevor man die Bühne betritt, wird jede Requisite mit einem Anhänger versehen. Fehlt etwas, ist alles in Ordnung? Das Publikum weiß es nicht, aber diese kleine Kontrolle verhindert Unfälle. Hinter einer perfekten Bühne steckt immer eine sorgfältige Hand."},"ICON-0357":{"nm":"Einsatz-Zeichen-Chip","de":"Der Einsatz-Chip wandert von Hand zu Hand. Jetzt, rein. Im Moment, in dem das Timing ohne ein einziges Wort übermittelt wird. Dieses kleine Signal hält im Dunkeln neben der Bühne alle im Takt, ohne einen einzigen zu verlieren."},"ICON-0358":{"nm":"Backstage-Patch","de":"Es gibt Türen, die nur derjenige passieren darf, der diesen Patch trägt. Hinter der Bühne, wo der Jubel durch die Wände dringt. Ein kleines Stück Stoff trennt das glänzende Vorne vom geschäftigen Hinten. Das Erkennungszeichen der Menschen, die die Bühne tragen."},"ICON-0359":{"nm":"Prompter-Abschirmtafel","de":"Eine Abschirmtafel hält das Licht des Prompters so, dass es nicht in den Zuschauerraum leuchtet. Nur die Person auf der Bühne sieht es, die Zuschauer nicht. Dieser stille Hüter eines Geheimnisses, das die Bühne nicht verraten darf."},"ICON-0360":{"nm":"Garderobenspiegel-Abdeckung","de":"Nach dem Konzert wird der Spiegel in der Garderobe mit einem Tuch abgedeckt. Das Glas, das den ganzen Tag unzählige Ausdrücke widerspiegelte, schließt für einen Moment die Augen. Das ungeschminkte Gesicht begegnet am Ende nicht dem Spiegel, sondern der stillen Dunkelheit."},"ICON-0361":{"nm":"Voraufzeichnungs-Einlassarmband","de":"Ein kleines Band, das man einmal angelegt nicht mehr lösen kann, ohne es zu zerreißen. Für den einzigen Zutritt zur Voraufzeichnung hat jemand in der dunklen Morgendämmerung den ersten Zug genommen. Das Gewicht am Handgelenk ist das Kribbeln des ganzen Tages."},"ICON-0362":{"nm":"Aufnahme-Wartezettel","de":"Kurz bevor das rote Licht aufleuchtet, halte ich alle Atemzüge in einer Reihe. In der Stille des Wartens auf das Einsatzzeichen halte ich bis zuletzt still durch. Im Moment des Abnehmens geht der Vorhang der Sendung auf."},"ICON-0363":{"nm":"Kamerapositions-Chip","de":"Eine kleine Markierung auf dem Boden legt die Bewegungen von sechs Kameras präzise fest. Woher das Licht am schönsten fällt, weiß der Regisseur schon vor der Probe. Hände, die die Szene im Inneren der Leinwand im Voraus zeichnen."},"ICON-0364":{"nm":"Sound-Check-Anhänger","de":"Man klopft das Mikrofon in den leeren Zuschauerraum. Wenn der Nachhall zu lang ist, kommt eine weitere Schicht Schallschutzmaterial an die Decke. Die Sorgfalt, die den Klang zurechtrückt, bevor das Publikum es weiß, beginnt ganz leise mit diesem kleinen Anhänger."},"ICON-0365":{"nm":"Stempel-Sammelpass","de":"An jedem Ort sammelt man einen weiteren Stempel. In jedem verwischten Tintenfleck sind das Wetter und das Herzklopfen des Tages mitabgedrückt. Die vollgeschriebene Seite ist eine einzigartige, nur für mich gültige Landkarte meiner Fußspuren."},"ICON-0366":{"nm":"Sender-Besucher-Ausweiskordel","de":"Ohne diese Kordel öffnet sich das Eingangstor nicht. Während man mit ihr um den Hals Schritt für Schritt durch den Flur geht, kommt die Welt, die man bisher nur auf dem Bildschirm kannte, langsam in Reichweite der Hand."},"ICON-0367":{"nm":"Studio-Überschuh-Set","de":"Der Studioboden ist immer kalt und glatt. Zieht man die Schuhe aus und schlüpft in dünne Überschuhe, verschwinden die Schrittgeräusche. Da die Kamera den Tanz und nicht die Schritte einfängt, ist das Wegwischen des Geräuschs ebenfalls eine Höflichkeit gegenüber der Bühne."},"ICON-0368":{"nm":"Garderobe-Snack-Anhänger","de":"Zwischen Probe und Live-Sendung meldet sich der Hunger am ehrlichsten. Kleine Namensschilder an jedem Snack auf der Seite der Garderobe. Diese aufmerksame Fürsorge hilft dabei, den langen Tag bis zum Ende durchzuhalten."},"ICON-0369":{"nm":"Monitoring-Notizband","de":"Beim Abspielen der Aufnahme notiert man. Hier den Blick, da den halben Takt. Die voll beschriebene Schrift ist ein geheimer Brief an das morgige Ich. Das am Ende befestigte Band ist ein stilles Versprechen, morgen einen Schritt weiter zu kommen."},"ICON-0370":{"nm":"Showcase-Einladungs-Slip","de":"Ein einziges Blatt Papier kann für jemanden ein ganzes Jahr des Wartens bedeuten. Ein kurzer Satz, der zur Showcase einlädt – geboren als die kleinste Einladungskarte der Welt, das Zittern der Hand beim Öffnen des Umschlags mit inbegriffen."},"ICON-0371":{"nm":"Presse-Umhängeausweiskordel","de":"Um den Hals der Pressevertretenden hängend, bewegt sie sich mitten im Klingelkonzert der Kameraverschlüsse. Die geschäftigen Schritte auf der Suche nach dem besten Winkel sind der Kanal, durch den die Energie der Bühne in die Außenwelt getragen wird."},"ICON-0372":{"nm":"Bühnenverbeugung-Reihenfolgezettel","de":"Auch in dem Moment, wenn der Applaus hereinbricht, um nicht aus der Reihe zu fallen, wird aufgeschrieben, wer zuerst und wer danach kommt. Der letzte Gruß wird mit genauso viel Sorgfalt choreografiert wie der erste Auftritt."},"ICON-0373":{"nm":"Fotowand-Bodenmarkierung","de":"Vor der Fotowand ist die Stelle für die Fußspitzen schon im Voraus eingezeichnet. Tritt man auch nur einen Schritt daneben, wird das Hintergrundlogo abgeschnitten. Das Geheimnis, am strahlendsten abgelichtet zu werden, ist still am Boden markiert."},"ICON-0374":{"nm":"Vorpremieren-Armband","de":"Ein kleines Band, das ans Handgelenk gelegt wird, kurz bevor im Kino das Licht ausgeht. Wenn der Vorhang aufgeht, begegnen alle in derselben Dunkelheit zum allerersten Mal derselben Szene. Das kleine Zeichen, gemeinsam dabei gewesen zu sein."},"ICON-0375":{"nm":"Andenken-Vorhangs-Fragment","de":"Am letzten Vorstellungsabend senkte sich der Vorhang nach dem finalen Gruß langsam. Ein herausgeschnittenes Stück dieses Tuches, im Rahmen aufbewahrt. Im Stoff stecken die Wärme der Bühnenlichter und das Schwingen des Applauses – noch leicht lauwarm, noch nicht abgekühlt."},"ICON-0376":{"nm":"Erstveröffentlichungs-Stempel","de":"Ein Stempel, der für genau diesen einen Tag geprägt wurde, an dem sich etwas zum ersten Mal der Welt zeigte. Eine zweite Erstveröffentlichung gibt es nicht – selbst der kurze Moment, in dem die Tinte trocknet, ist eine Zeit, die nie wiederkehrt."},"ICON-0377":{"nm":"Bühnen-Momentkarte","de":"Der strahlendste Augenblick einer Bühne wurde ausgeschnitten und in eine Karte gefasst. Musik und Lichter haben aufgehört, aber der Moment, in dem man sie in die Hand nimmt, schwillt der Jubel jenes Tages erneut ans Ohr. Der kleine Zauber, den eingefrorenen Augenblick zum Leben zu erwecken."},"ICON-0378":{"nm":"Schlusspose-Notiz","de":"Im allerletzten Ton wird die Position der Fingerspitzen und der Blickwinkel aufgezeichnet, an dem man innehalten muss. Nur wer weiß, dass ein einziges Bild des Endings tagelang nachwirkt, legt diesen kleinen Zeichnung sorgfältig gefaltet zur Seite."},"ICON-0379":{"nm":"Tourstadt-Pin","de":"Auf der Karte steckt in jeder besuchten Stadt ein Pin. Der Meereswind von Busan und der Mittag von Gwangju stecken an der Spitze dieses kleinen Nagels. Verbindet man die Punkte still miteinander, zeichnet sich die lange Linie einer Reise durch eine ganze Jahreszeit ab."},"ICON-0380":{"nm":"Sitzbereichs-Clip","de":"Zehntausende Plätze werden in Bereiche unterteilt und der Weg wird gewiesen. Damit niemand sich verirrt, damit niemand anstößt. Wer mir folgt, findet seinen Platz. Ordnung ist letztlich eine kleine Freundlichkeit für alle."},"ICON-0381":{"nm":"Einlasstor-Anhänger","de":"Vor dem Eingangstor wird einer nach dem anderen geprüft. Das letzte Tor, durch das das Ticket haltende Herz eingelassen wird. Im Moment des Passierens endet das lange Warten und die heutige Vorstellung beginnt."},"ICON-0382":{"nm":"Armband-Aufbewahrungs-Kapsel","de":"Selbst wenn die Farbe verblasst, ist der Jubel jenes Tages noch immer versiegelt. Das Band vom Handgelenk bringt man nicht über sich wegzuwerfen und rollt es sorgfältig in eine kleine Kapsel. Auch das wertvollste Andenken verdient einen eigenen Ruheplatz."},"ICON-0383":{"nm":"Vor-Ort-Übergabestab","de":"Zwischen Fan und Bühne wandert etwas von Hand zu Hand. Vielleicht ein Brief, vielleicht ein kleines Geschenk. Ich bin die geschäftigste Brücke des Ortes, die dafür sorgt, dass diese Zuneigung sicher ankommt."},"ICON-0384":{"nm":"Konzertdatum-Siegel","de":"Das Datum jenes Tages ist in einem runden Siegel eingestanzt und steht für immer still. Der Kalender blättert weiter, aber nur dieser kleine Kreis bleibt auf jenem Tag. Für Tage, die man nicht vergessen möchte, versiegeln die Menschen stets irgendetwas."},"ICON-0385":{"nm":"Tour-Taschenpatch","de":"An der Tour-Tasche kommt nach jeder Stadt ein weiterer Patch dazu. Die eingenähten Städtenamen werden allmählich zu einem Lebenslauf. Selbst abgenutzte Ecken bleiben als Beweis, dass man überall dabei war."},"ICON-0386":{"nm":"Ticket-Board-Kordel","de":"Am Ende der Einlasswarteschlange schaukelt ein Board, dessen Ende von einer festen Kordel gehalten wird. Hände, die das Ticket hochhalten, reihen sich in einer langen Schlange auf – ich markiere still den Anfang dieser aufgereihten, kribbelnden Reihe."},"ICON-0387":{"nm":"Zugaben-Schleifen-Fragment","de":"In der Nacht, in der die Rufe nach Zugaben am lautesten waren, fiel ein Stück der Bühnendekoration herunter. Wie ein Lied, das man noch etwas länger gesungen hat, weil man sich nicht trennen wollte, ist in diesem Fragment auch das Herz des Abschiednehmens verknotet."},"ICON-0388":{"nm":"Nachrichtenkapsel-Fläschchen","de":"Ein sorgfältig gefaltetes Wort in eine Glasflasche gesteckt. Wie ein kleines Boot, das man aufs Wasser schickt und hofft, dass es jemanden erreicht – ich treibe langsam auf der Zeit, ein Herz in mir bergend. Bis zu dem Tag, an dem man mich öffnet, schläft das Versprechen still in meinem Inneren."},"ICON-0389":{"nm":"Kleines Bekenntnis-Anhänger","de":"Worte, die man kaum aussprechen konnte, werden auf einen kleinen Anhänger geschrieben und unauffällig dazugesteckt. Die Schrift zitterte, aber die Aufrichtigkeit war klar. Manchmal trägt das kleinste Papier den größten Mut in sich."},"ICON-0390":{"nm":"Anonyme Fanchant-Zettelbox","de":"Auch ohne Namen zu nennen, kommt die Zuneigung an. Jeder Zettel, der in die Box gelangt, stapelt eine weitere anonyme Unterstützung. Auch wenn man nicht weiß, wer es geschrieben hat – die Wärme ist klar: eine Sammlung namenloser Herzlichkeit."},"ICON-0391":{"nm":"Origami-Papier","de":"Das quadratische Blatt wird in Händen zum Kranich, zum Stern. Mit jeder Falte wird auch ein Wunsch eine weitere Schicht aufeinandergelegt. In der sorgfältig gefalteten Form wohnt eine Aufrichtigkeit, die länger anhält als Worte."},"ICON-0392":{"nm":"Siegelband-Wachs","de":"Wenn man Kerzenwachs tropfen lässt und den Stempel fest aufdrückt, ist der Brief erst richtig versiegelt. Ganz nach alter Sitte, um das Herz fest zu machen. Auf dem erkaltenden roten Siegelwachs schließt sich ein Geheimnis ganz still ein."},"ICON-0393":{"nm":"Geschenk-Polsterpapier","de":"Damit das Geschenk nicht beschädigt wird, umhüllt man es weich von allen Seiten. In jeder Falte ist die Bitte eingearbeitet: bloß nicht kaputtgehen. Ein unsichtbarer Gedanke an einem unsichtbaren Ort – eine behutsame, stille Fürsorge."},"ICON-0394":{"nm":"Farbige Briefkordel","de":"Auch die Kordel, die den Brief bindet, hat eine Farbe. Gelb ist Ermutigung, Blau ist Sehnsucht. Gefühle, für die Worte nicht ganz reichten, werden in Farbtönen zu Knoten gemacht. Noch vor dem Öffnen überträgt sich die Herzenstemperatur zuerst auf die Fingerspitzen."},"ICON-0395":{"nm":"Handschrift-Abdeckband","de":"Ein Band, das die Schrift bis zum letzten Moment verbirgt. Es schützt ein Bekenntnis, das man fast zu früh preisgegeben hätte, bis ganz zuletzt. Hebt man es kurz an, wird die Aufrichtigkeit sichtbar – das Gewicht dieses Zitterns kenne ich von allernahestem."},"ICON-0396":{"nm":"Fanchant-Satz-Chip","de":"In der Nacht, in der die Leuchtstäbe wogen, ist ein einzelner Satz in den Chip eingraviert, den alle gemeinsam rufen. Das Versprechen, das verstreute Herzen in einer Zeile vereint. Wenn alle ihn gemeinsam singen, erstrahlt dieser Satz am hellsten."},"ICON-0397":{"nm":"Alter Übungsraum-Schlüsselanhänger","de":"Ein Schlüsselanhänger, der die Tür des Übungsraums hundertfach geöffnet und geschlossen hat. Die Farbe hat sich abgenutzt und der Ring ist locker geworden, doch daran haftet der Handschweiß der unbeholfensten Zeit. Abgenutzt sein bedeutet, so lange dageblieben zu sein."},"ICON-0398":{"nm":"Bühnenmake-up-Kordelfragment","de":"Bühnenmake-up ist erst im Bühnenlicht vollständig. Ein Fragment dieser kräftigen Farbe. In der Spur, die selbst im Schweiß nicht verwischt wurde, steckt die Sorgfalt, Gefühle bis in die hinterste Ecke des Zuschauerraums zu übermitteln."},"ICON-0399":{"nm":"Ohrstöpsel-Etui","de":"Die kleinen Ohrstöpsel, die auf der Bühne geholfen haben, die eigene Stimme zu hören. Nach dem Konzert werden sie sorgfältig ins Etui gelegt. Je näher etwas der Musik war, desto sorgfältiger möchte man es aufbewahren."},"ICON-0400":{"nm":"Persönliches Schließfach-Etikett","de":"Am Ende des Unterkunftskorridors hängt an jedem Schließfach ein Namensschild. Die kleinen Buchstaben, die zeigen, wessen Platz es ist, verwandeln den fremden Raum in ein Zuhause. Einen eigenen Platz zu haben bedeutet: die freundliche Erlaubnis, hier zu bleiben."},"ICON-0401":{"nm":"Tragbarer Kehlen-Pflegebehälter","de":"Zwischen den Proben trinkt man langsam einen Schluck lauwarmes Wasser. Die Kehle ist das ausgeliehene Instrument des Sängers – dieser kleine Behälter, der sie auffüllt, bevor sie auskühlt, schützt den ersten Ton von morgen. Fürsorge ist immer so still."},"ICON-0402":{"nm":"Zeitplan-Hinweispin","de":"Auf einem Tag, der minutenweise vollgepackt ist, zeigt ein Pin auf das nächste Feld. Das Schönste in all diesen dichten Zeilen ist ein leeres Feld. Die kurze Zeit, in der man einfach aus dem Fenster schauen darf, versteckt sich dort, ganz klein."},"ICON-0403":{"nm":"Garderobe-Decken-Clip","de":"Als man in einem Nachmittag nach der Schminke an den Stuhl gelehnt kurz eingedöst war, legte jemand leise eine Decke über die Schultern. Dieser Clip, der verhindert, dass sie herunterrutscht, hält die Wärme jener Geste fest, bis man auf die Bühne tritt."},"ICON-0404":{"nm":"Kleines Parfüm-Sample","de":"Tippt man es leicht an die Innenseite des Handgelenks, entfaltet sich der Duft nur in einem Umkreis von einer Handbreite. Es muss sich nicht weit verbreiten. Eine Spur, die nur jemand bemerkt, der nah kommt – so diskret und doch so ich."},"ICON-0405":{"nm":"Übungskleidung-Wasch-Anhänger","de":"Egal wie oft man wäscht, der tief ins Gewebe eingezogene Schweißgeruch lässt sich nie ganz auswaschen. Beim sorgfältigen Zusammenlegen der in der Sonne getrockneten Übungskleidung denkt man: Diese Spur, die sich nicht entfernen lässt, ist eigentlich die ehrlichste Hinterlassenschaft."},"ICON-0406":{"nm":"Farbfolie für Bühnenbeleuchtung","de":"Schiebt man eine dünne Folie ein, verwandelt das weiße Licht sich in Abendrot, schiebt man noch eine dazu, senkt sich die Morgendämmerung herab. Die Hand, die der Bühne ihre Jahreszeit verleiht und dem Licht Kleidung anzieht, hält hinter dem Vorhang den Atem an."},"ICON-0407":{"nm":"Spot-Linsenkappe","de":"Auch wenn die Kamera aus ist, wischt jemand diese kleine Abdeckung ab und reinigt die Linse. Für die nächste Szene, die noch nicht aufgenommen wurde. In der Zeit, die nicht auf dem Bildschirm zu sehen ist, stellt die geschäftigste Hand schon den nächsten Fokus ein."},"ICON-0408":{"nm":"Bühnen-Reflektor","de":"Ohne selbst zu leuchten, schickt diese Tafel das empfangene Licht ins schattige Gesicht zurück. Dass die Bühnenmitte so hell ist, liegt daran, dass jemand am Rand den Winkel hält und still darauf richtet."},"ICON-0409":{"nm":"Farbfilter-Sleeve","de":"Schiebt man blaues Licht in die transparente Hülle, wird das gesamte Publikum zum Meer; tauscht man es gegen rotes aus, geht an derselben Stelle die Sonne unter. Dass dieselbe Bühne mit einer einzigen Farbe zu einer anderen Jahreszeit wird, beginnt mit dieser einen dünnen Schicht."},"ICON-0410":{"nm":"Lichtnummern-Pin","de":"An jeder Leuchte hängt eine kleine Nummer. Welche Leuchten in welcher Reihenfolge aufgehen und schlafen gehen, ist der Ablauf des heutigen Abends, schon im Voraus in dieser Ziffernfolge gewoben. Hinter dem strahlenden Vorhang liegt immer eine sorgfältige Liste ausgebreitet."},"ICON-0411":{"nm":"Lichtband-Markierung","de":"Auf dem abgedunkelten Bühnenboden leuchtet ein fluoreszierendes Band still die Stoppstelle an. Von der Zuschauerseite ist es unsichtbar, aber die Fußspitzen der Darsteller ertasten dieses schwache Licht und finden ihren Platz. Auch im Dunkeln gibt es freundliche Wegweiser."},"ICON-0412":{"nm":"Schattenabschirmtafel","de":"Eine Tafel, die einfallendes Licht abfängt und den Schatten klar abfallen lässt. Auch mit Schatten umzugehen ist letztlich, mit Licht umzugehen – was man zeigen wird, entscheidet sich zuerst darin, was man still bedeckt hält."},"ICON-0413":{"nm":"Beleuchtungsstärke-Chip","de":"Ein kleiner Chip in der Handfläche misst die Helligkeit des Raumes in Zahlen. Zu hell und zu dunkel machen die Augen gleichermaßen unwohl. Die unsichtbare ideale Schwelle, bei der man am komfortabelsten verweilt – dieser Chip schützt sie still."},"ICON-0414":{"nm":"Spot-Licht-Abschirmung","de":"Eine Abschirmung, die verhindert, dass das Spotlicht an die falsche Stelle fällt. Das Licht nur auf eine einzige Person zu richten ist eine liebevolle Konzentration. In dem Moment, in dem man in diesen Lichtkreis tritt, schaut die Welt kurz nur auf einen einzigen Menschen."},"ICON-0415":{"nm":"Ohrstöpsel-Set","de":"Ein paar Ohrstöpsel, die perfekt ins Ohr passen. Schon eine kleine Größenabweichung lässt den Klang entweichen, und sobald er entweicht, verliert man den Takt. Dass der Gesang auf der Bühne nicht einen Moment wankt, beginnt manchmal bei diesem kleinen Gummipaar."},"ICON-0416":{"nm":"Kabel-Klettverschluss","de":"Ein Klettbandstreifen, der wirre Kabel zu einem geordneten Strang bündelt. Hinter den Kulissen, wo niemand hinschaut, glänzt Ordnung am meisten. Die Sauberkeit eines gebündelten Kabels trägt still den ununterbrochenen Klang, der vorne fließt."},"ICON-0417":{"nm":"Leitungscheck-Etikett","de":"An jedem der dutzenden Kabel hängt ein handgeschriebenes Schildchen, das verrät, welches Instrument es ist. Erst wenn jedes dieser schiefen Schriftzeichen seinen Platz hält, strömen die einzeln gespielten Töne zu einem einzigen Lied zusammen."},"ICON-0418":{"nm":"Schalldämpfer-Pad","de":"Ein Geräuschdämpfer-Pad, das Schrittgeräusche und Vibrationen still schluckt. Es wird dort ausgelegt, wo tiefe Stille gebraucht wird. Der reinste Klang entsteht manchmal erst auf diesem stillen Boden, von dem kein Störgeräusch mehr entweicht."},"ICON-0419":{"nm":"Soundcheck-Token","de":"Ein Token, der sich vor dem Konzert beim Einpegeln des Klangs in der Hand erwärmt. Jedes Mal, wenn Mikrofon und Lautsprecher überprüft sind, wechselt er die Hand. Die Perfektion der Hauptbühne wird Schritt für Schritt in dieser stillen Probe geformt."},"ICON-0420":{"nm":"Mikrofonkopf-Kappe","de":"Weil so viele Stimmen diesen Ort berührt haben, reinigt man diese Kappe am Ende des Mikrofons mit besonderer Sorgfalt. Als Behälter für Gesang ist sie dem Sänger wie eine zweite Hand. Beim Reinigen stellt man sich schon die erste Silbe von morgen vor."},"ICON-0421":{"nm":"Pop-Filter-Clip","de":"Ein dünnes Netz zwischen Lippen und Mikrofon. Dank des kleinen Clips, der es hält, werden raue Atemgeräusche zu runden, weichen Tönen geformt und fließen heraus."},"ICON-0422":{"nm":"Sound-Rack-Anhänger","de":"Im dunklen Backstage-Bereich, zwischen den übereinander gestapelten Geräteregalen, hängen kleine Anhänger, damit man sich nicht verirrt. Der Ursprung des prächtigen Klangs, der das Publikum erfüllt, ist hier, in diesem schummrigen Raum, immer sorgfältig aufgereiht."},"ICON-0423":{"nm":"Lautsprecher-Gitter-Pin","de":"Ein Pin, der das Lautsprechergitter fest fixiert. Die Öffnung, durch die der Klang herausdringt, ist die Stelle, die zuerst Staub fängt – daher schützt eine dünne Maschenweite den Ton. Alles, was das Ohr berührt, hat unsichtbar eine Schutzschicht aufgetragen."},"ICON-0424":{"nm":"Schrittmarkierungs-Aufkleber","de":"Aufkleber, die für die Tanzbewegungen auf den Boden gepickt werden. Das Geheimnis, warum ein Gruppentanz wie ein einziger Schnitt aussieht, liegt eigentlich unter den Füßen. Auf den Markierungen, die dutzende Male getreten wurden, wo man sich verstreute und wieder sammelte."},"ICON-0425":{"nm":"Drehübungs-Teller","de":"Ein Drehteller für Pirouettenübungen. Um den Schwindel zu überwinden, muss man zuerst lernen, den Blick auf einen einzigen Punkt zu fixieren. Damit man sich egal wie schnell dreht diesen Punkt nie verliert, wird das Gleichgewicht langsam in den Körper eingraviert."},"ICON-0426":{"nm":"Knie-Tape-Rolle","de":"Eine Tape-Rolle, die das Knie fest einwickelt. Die Gelenke, die Tausende Male gesprungen und gelandet sind, schweigen am Ende, aber diese Schicht trägt ihr Schweigen still. Hinter dem Körper, der bis zum Ende durchhält, steckt immer jemandes Fürsorge."},"ICON-0427":{"nm":"Zehenspitzen-Ausrichtplatte","de":"Eine Platte, die den Winkel der Zehenspitzen ordentlich ausrichtet. Tanz vollendet sich an den Zehenspitzen, nicht an den Fingerspitzen, sagt man. Wenn sich dutzende in dieselbe Richtung gestreckte Zehenspitzen zusammenfinden, entsteht der Zauber, dass viele wie eine einzige Person aussehen."},"ICON-0428":{"nm":"Übungsraum-Antirutschmatte","de":"Eine Antirutschmatte auf dem Übungsraum-Boden. Um sich frei zu bewegen, muss man zuerst sicher sein. Erst auf einem Boden, auf dem man ohne Sturzangst rollen kann, blüht die mutigste und furchtloseste Bewegung auf."},"ICON-0429":{"nm":"Bewegungsanalyse-Karte","de":"Eine Karte, auf der die Choreografie taktweise klein aufgezeichnet ist. Teilt man auch die schwierigste Bewegung in einzelne Felder, folgt man ihr irgendwann. Der flüssige Bewegungsfluss auf der Bühne ist das Ergebnis dieser stückweise auswendig gelernten Bilder."},"ICON-0430":{"nm":"Spiegel-Abdeckvorhang-Pin","de":"Ein Pin, der den Vorhang hält, der den Übungsraumspiegel kurz abdeckt. Manchmal braucht man Zeit, nur mit dem Körpergefühl zu tanzen, ohne das Spiegelbild. Im Moment des Abdeckens spürt man, wie die Musik erst richtig in die Haut einzieht."},"ICON-0431":{"nm":"Takt-Zähl-Perlen","de":"Perle für Perle mit den Fingerspitzen weitergeschoben, taktet man den Rhythmus greifbar wie alte Rechenkunst. Das Grundgerüst der Musik, der Takt, muss so gelernt werden – als etwas Anfassbares –, damit er sich fest und dauerhaft in den Körper einschreibt."},"ICON-0432":{"nm":"Aufwärm-Check-Kordel","de":"Eine Check-Kordel, um festzuhalten, ob man sich ausreichend aufgewärmt hat. Vor ernsthaftem Training kommt immer erst die ruhige Vorbereitung. Lieber eine Kordel binden und den Körper langsam wecken, als später verletzt zu bereuen – letztlich hält das länger tanzen."},"ICON-0433":{"nm":"Kostüm-Nummerierungsclip","de":"Ein Clip, der jedem Kostüm eine Nummer anheftet, damit mehrere Kostüme nicht durcheinander geraten. Im atemlosen Umkleiden darf nicht eine einzige Verwechslung passieren – daher ist auf jedem Kleidungsstück seine Reihenfolge klar eingetragen. Auch Hektik braucht Ordnung, um anmutig zu sein."},"ICON-0434":{"nm":"Schneideratelier-Nadelkissen","de":"Ein Nadelkissen in der Ecke des Schneiderateliers. Hier ruht die Hand, die zerrissene Nähte und abgefallene Knöpfe schweigend wieder geflickt hat. Hinter dem makellos sitzenden Kostüm auf der Bühne stecken Stiche, die die Bühne nie zu sehen bekommen."},"ICON-0435":{"nm":"Stoffmuster-Ring","de":"Restliche Stoffstücke auf einen Ring gereiht. Denselben Stoff hält man vorsorglich zurück, für den Fall, dass das echte Kleidungsstück Schaden nimmt. Diese kleine Vorbereitung, die man hofft nie zu brauchen, rettet das Bühnenkostüm genau dann, wenn das Schlimmste passiert."},"ICON-0436":{"nm":"Schnellknopf-Pack","de":"Ein Pack Knöpfe, die man bei Bedarf sofort annähen kann. Wenn kurz vor der Vorstellung ein Knopf abspringt, bricht im ganzen Schminkraum kurz Aufregung aus. Das kleine Notfallset, das diesen kurzen, schwindelerregenden Alarm auf Anhieb beendet."},"ICON-0437":{"nm":"Bühnen-Gürtelhalter","de":"Ein Halter, der den Gürtel des Bühnenkostüms fest fixiert. Auch wenn man springt und dreht, verrutscht das Kostüm nicht. Die Freiheit, die man auf der Bühne vollkommen ausleben kann, kommt erst, wenn alles Unsichtbare darunter sorgfältig festgemacht ist."},"ICON-0438":{"nm":"Federstaubwedel","de":"Weil selbst ein kleines Flusenbällchen unter dem Bühnenlicht auffällt, streicht man mit dem Federwedel sanft über das Kostüm. Der zärtliche Handgriff, das Kleid kurz vor dem Betreten der Bühne ein letztes Mal zu glätten, gehört immer diesen weichen Federn."},"ICON-0439":{"nm":"Garderobenschuh-Anhänger","de":"Ein Namensanhänger an den Schuhen der Garderobe. In dem kleinen Schildchen, das zeigt, wem sie gehören, steckt still die Erleichterung: Wir sind ein Team. Der Raum, in dem man die Schuhe auszieht und die Beine ausstreckt, wird hinter der Bühne zum gemütlichsten Zuhause."},"ICON-0440":{"nm":"Styling-Clip-Tafel","de":"Eine Clipleiste, die während des Frisierens die Strähnen festhält. Beim Bearbeiten einer Strähne nach der anderen vertrauen die Finger die widerspenstigen Haare für einen kurzen Moment diesem Clip an. Gepflegtheit entsteht letztlich aus solchen kleinen Pausen."},"ICON-0441":{"nm":"Sicherheitsnadel-Kapsel","de":"Öffnet man in einer Nacht mit geplatzter Naht den Kapseldeckel, liegen kleine, kalte Silberstreifen ordentlich darin. Die Hand, die das Kostüm von innen am festesten hält, ohne gesehen zu werden – die Sicherheitsnadel arbeitet immer still hinter der Bühne."},"ICON-0442":{"nm":"Linsenputztuch","de":"Einmal pusten, dann einen Kreis drehen beim Reiben – und die trübe Welt wird wieder klar. Diesen kurzen Moment genießt man und wischt die Linse immer wieder ab. Ein kleines Frühlingssonnen-Blatt, das stellvertretend jemandes Sicht aufhellt."},"ICON-0443":{"nm":"Stativ-Gummifuß","de":"Zieht man Gummi auf die drei Füße, jammert der Holzboden nicht mehr. Während der kleine Punkt die Erschütterungen schluckt, wird die Szenerie im Bild lügenlos ruhig. Stabilität beginnt immer leise von unten."},"ICON-0444":{"nm":"Kamera-Regenabdeckung","de":"Selbst wenn Regentropfen hinabrinnen, bleibt die Linse trocken und nimmt die Welt auf. An einem trüben Nachmittag bei Außenaufnahmen wird ein transparenter Regenponcho sanft über die Kamera gezogen. Wer das Kostbare schätzt, schützt es, bevor es nass wird."},"ICON-0445":{"nm":"Aufnahme-Markierungsband","de":"\"Steh hier, dreh dich dorthin\" – kurze, bunte Markierungen weisen wortlos den Weg. Wenn die Vorstellung vorbei ist, zieht man das Band reulos ab, doch die Füße, die sich daran gewöhnt haben, erinnern sich noch lange an diesen Ort."},"ICON-0446":{"nm":"Schnitt-Trennungsclip","de":"Ein kleiner Clip, der verstreute Papiere auf einmal festhält. Klack – mit einem einzigen fröhlichen Geräusch werden gestern und heute ordentlich gebündelt. Ordnen ist die freundliche Angewohnheit, das zu halten, was fast verloren gegangen wäre."},"ICON-0447":{"nm":"Weißabgleich-Tafel","de":"Hält man die weiße Tafel vor den Bildschirm, finden die Farben leise ihren Platz. Weder das gelbliche Abendrot noch das blaue Morgengrauen schwindeln. Eine Tafel, die das wahre Weiß kennt, lässt alle übrigen Farben ehrlich sprechen."},"ICON-0448":{"nm":"Speicherkarten-Aufbewahrungsdose","de":"In der kleinen Blechdose schlafen Chips voller Erinnerungen. Öffnet man den Deckel, klickt es – und die Szenen vergangener Jahreszeiten fallen in die Handfläche. Erinnerungen ruhen, sorgfältig in einem festen Behälter bewahrt, so geborgen."},"ICON-0449":{"nm":"Monitor-Streulichtschutz","de":"Zieht man eine schwarze Blende um den Monitor, hören die Lichtreflexionen schlagartig auf. Auch am Fenster im Sonnenschein verliert das Bild nicht seine Farbe. Um besser sehen zu können, muss man erst das Streulicht abschirmen – das sagt die Blende ganz leise."},"ICON-0450":{"nm":"Aufnahmeraum-Schalldämmungspin","de":"Ein kleiner Pin in der Türritze filtert den Außenlärm ganz leise weg. Schritte im Flur, Lachen im Nebenzimmer – all das erreicht hier nicht mehr. Um einen reinen Klang aufzunehmen, muss man zuerst die Stille bauen."},"ICON-0451":{"nm":"Schmink-Schwammset","de":"Ein ordentliches Bündel weicher Schwämme, eng nebeneinander gelegt. Wenn man das Puder mit den Fingerspitzen sanft antupft, erstrahlt das Gesicht gleich eine Nuance heller. Hinter dem strahlenden Lächeln auf der Bühne verbirgt sich stets diese zarte, fleißige Berührung."},"ICON-0452":{"nm":"Haarnadeletui","de":"Ein aufgeräumtes Zuhause für die kleinen Nadeln, die sich so leicht verlieren. Öffnet man den Deckel, reihen sich die silbernen Helferlein ordentlich auf. Was verstreut kaum auffällt, gibt im Ensemble Halt – auch kleinen Dingen gebührt ihr fester Platz."},"ICON-0453":{"nm":"Pinsel-Sterilisationsdose","de":"Die ganztägig farbgesättigten Pinsel duschen im Inneren der Dose unter UV-Licht. Während unsichtbares Licht das Alte wegspült, erwacht die Pinselspitze von morgen frisch wie am ersten Tag. Sauberkeit ist ein weiterer Ausdruck von Sorgfalt."},"ICON-0454":{"nm":"Puderquasten-Trockennetz","de":"Die runden Quasten liegen ruhig im Netz und holen Atem. Weil die Luft durch die Maschen strömt, bleibt die Leichtigkeit lange erhalten. In einer gut getrockneten Quaste schläft bereits die Frische des nächsten Morgens."},"ICON-0455":{"nm":"Haarlack-Sprühaufsatz","de":"Ein einziger Sprühstoß – und kein Wind bringt die Frisur mehr durcheinander. Diese kleine Kappe hält die mühevoll gestaltete Haarpracht die ganze Nacht. Über dem fest fixierten Haar ergießt sich das strahlende Bühnenlicht wie in tausend Funken."},"ICON-0456":{"nm":"Lippenpinsel-Schutzkappe","de":"Ein kleines Deckelchen umhüllt behutsam die feine Pinselspitze. Selbst wenn sie in der Tasche hin- und herschaukelt, bleibt der Pinsel gerade und sauber. Wer diesen kleinen Pinsel pflegt, vollendet damit den einen Strich Farbe auf den Lippen."},"ICON-0457":{"nm":"Wartungsnummer-Spiegel","de":"Neben der Zahl, die meinen Aufruf ankündigt, hängt ein kleiner Spiegel. Kurz vor dem Betreten der Bühne richtet man ein letztes Mal das vorgewischte Pony. Schaut man seine Aufregung einmal an, wird sie ein kleines Stück leichter."},"ICON-0458":{"nm":"Handgelenk-Schweißband","de":"Ein weiches Band, das den Schweiß von der Stirn mit einem einzigen Wischen des Handgelenks abtupft. Je intensiver die Choreografie, desto häufiger greift die Hand danach. In jedem atemlosen Moment ein kleiner Trost am Handgelenk."},"ICON-0459":{"nm":"Requisitentaschen-Etikett","de":"Stehen zehn gleiche Taschen in der Garderobe, gibt es keine Verwechslung mehr. Das Namensschild an jeder Tasche weist klar auf den Besitzer hin. 'Gehört mir' zu markieren ist eine kleine, aber herzliche Geste."},"ICON-0460":{"nm":"Proberaum-Reservierungspin","de":"Wer nutzt heute diesen Proberaum? Ein kleiner Pin am Aushang am Eingang teilt die Zeit stillschweigend auf. Die Herzen derer, die auf die nächste Runde warten, reihen sich geduldig hinter diesem einen Pin auf."},"ICON-0461":{"nm":"Wanduhr-Schutzring","de":"Eine transparente Abdeckung senkt sich behutsam über die Wanduhr und hält den Staub fern. Der tickende Zeiger bleibt klar, die Zeit fließt ungetrübt. Um Wertvolles braucht es stets eine unsichtbare Schutzschicht."},"ICON-0462":{"nm":"Bodenschutzpad","de":"Ein dünnes Pad unter den Stuhlbeinen bewahrt den Parkettboden vor Kratzern. Selbst beim Schieben entstehen keine Schrammen, selbst beim Umstellen bleibt keine Spur. Den Boden unsichtbar zu schonen – das ist das Geheimnis langer Nutzung."},"ICON-0463":{"nm":"Getränke-Verbotsmarkierung","de":"Hier bitte kurz kein Getränk abstellen – darum bittet der kleine Chip freundlich. Denn Noten und Geräte sollten nicht nass werden. Selbst 'Verboten' kann sich, so behutsam ausgedrückt, in eine herzliche Rücksichtnahme verwandeln."},"ICON-0464":{"nm":"Lüftungsknopf-Etikett","de":"Wenn die Luft stickig wird, zeigt ein kleines Etikett neben dem Knopf, wo man drücken soll. Das Gefühl zu atmen beginnt überraschend oft ganz still mit einem einzigen, winzigen Hinweisschild."},"ICON-0465":{"nm":"Lautsprecher-Gummifuß","de":"Ein Gummifuß unter dem Lautsprecher schluckt dumpfe Vibrationen. Weil der Bass nicht mehr über den Boden kriecht, klingt der Ton ein gutes Stück klarer. Ein gutes Klangerlebnis entsteht erst auf einem soliden Fundament."},"ICON-0466":{"nm":"Spindnummer-Magnet","de":"Ein kleiner Zahlmagnet, der sich an die Spindtür heftet. In welchem Fach schläft heute mein Gepäck? Egal wie oft sich der Platz ändert – ein Magnet genügt, und schon hat man sein eigenes Fach. Zugehörigkeit kommt von solch leichten Markierungen."},"ICON-0467":{"nm":"Spiegel-Wischer","de":"Eine einzige Wischbewegung über den Spiegel – und der Beschlag ist weg. Im nächsten Moment taucht das eigene Gesicht wieder klar auf. Um sich selbst richtig zu sehen, muss man zuerst behutsam das Trübe wegwischen."},"ICON-0468":{"nm":"Türstopp-Puffer","de":"Ein weiches Polster in einem kräftig zuschlagenden Türspalt. Es nimmt den Knall ebenso auf wie das Einklemmen von Fingern. Ein kleines Stück Freundlichkeit im rauen Aufeinanderprallen – eine stille Sicherheitsmaßnahme."},"ICON-0469":{"nm":"Kabelkanal-Block","de":"Über den quer durch den Raum laufenden Kabeln liegt ein solider Deckel und bildet eine Brücke. Kein Stolpern mehr, kein versehentliches Darauftreten. Ein Block, der schweigend den Weg freihalten und zugleich schützen kann."},"ICON-0470":{"nm":"Rutschgefahrkegel","de":"Auf nassem Boden steht ein gelber Kegel allein und warnt leise: vorsichtig, langsam auftreten. Hinter der hellen Bühne hält dieser schweigsame kleine Wächter die Schritte sicher."},"ICON-0471":{"nm":"Notfallleuchtstab","de":"Ein Lichtstrahl, der im dunklen Korridor aufleuchtet. Damit man auch in der Dunkelheit den Weg nicht verliert, liegt dieses Notlicht in der Hand. In der dunkelsten Stunde gibt es sicher Dinge, die am hellsten strahlen."},"ICON-0472":{"nm":"Geländerschutzkappe","de":"Eine runde Kappe auf dem Ende des Treppengeländers umhüllt weich die scharfe Kante. Selbst wenn die Hand gedankenlos daran streift, gibt es keine Verletzung. Spitzes behutsam abzudecken ist auch eine Form der Fürsorge für andere."},"ICON-0473":{"nm":"Bühnenkanten-Polster","de":"Am Rand der Bühne ist ein weiches Polster angebracht. Damit die Fußspitze bei intensiver Choreografie keine blauen Flecken bekommt. Hinter jedem strahlenden Schritt tanzt unsichtbarer Schutz mit."},"ICON-0474":{"nm":"Bodenmarkierungs-Scheibe","de":"Eine runde Scheibe auf dem Boden sagt leise: 'Stell dich hierhin.' Wer Schlange steht, wer seinen Platz sucht – alle halten bei diesem einen Punkt inne. Ordnung wächst aus kleinen Markierungen."},"ICON-0475":{"nm":"Taschenlampen-Schlaufe","de":"Einmal die Schlaufe am Taschenlampenende um das Handgelenk gewickelt, verliert man das Licht auch in der Dunkelheit nicht. Kein Fallenlassen mehr, dafür freie Hände – ein kleiner, aber verlässlicher Dreher."},"ICON-0476":{"nm":"Absperrseil","de":"Bitte hier nicht eintreten – ein einziges Seil zieht sanft eine Linie. Eine herzliche Grenze, die Gefahrenbereich und sicheren Bereich still voneinander trennt. Auch das Abriegeln ist ein Weg, jemanden zu schützen."},"ICON-0477":{"nm":"Sicherheitsprüfungspin","de":"An jeder geprüften Stelle hinterlässt ein kleiner Pin das Wort 'Bestätigt'. Ein Stempel des Herzens, der zeigt: nichts wurde ausgelassen. Sicherheit ist nichts Aufwendiges – sie ist die Summe dieser sorgfältig abgehakten Spuren."},"ICON-0478":{"nm":"Mini-Filmklappe","de":"Ein schwungvolles Klack beim ersten Takt – und aller Atem am Set synchronisiert sich in einem Atemzug. So klein sie ist, jede Szene startet stets mit diesem einen Schlag. Hier öffnet sich der aufgeregte Beginn der Aufnahme."},"ICON-0479":{"nm":"Tischmikrofon-Überzug","de":"Ein flauschiger Überzug legt sich sanft über das Tischmikrofon. Selbst wenn der Atem rau aufbricht, wird er sauber und klar übertragen. Die warmste Umhüllung einer Stimme ist oft diese eine weiche Schicht."},"ICON-0480":{"nm":"Akustikplatten-Stück","de":"Ein Stück Akustikplatte an der Wand nimmt das Echo still in sich auf. Weil der Klang nicht mehr an den Wänden abprallt, sammelt sich der Gesang ein gutes Stück klarer. Gutes Klingen entsteht im Feilen an der Stille."},"ICON-0481":{"nm":"Kopfhörerhalter-Kappe","de":"Den Kopfhörer hier aufzuhängen ist eine kleine Abmachung. Damit der Nächste ihn sofort greifen kann – Kabel gelöst und ordentlich. Ein einziger Haken bringt stille Ordnung in ein geschäftiges Tonstudio."},"ICON-0482":{"nm":"Aufnahme-Signalleuchte","de":"Sobald das rote Licht aufleuchtet, hält im Aufnahmeraum jeder Atem inne. Selbst Schritte vor der Tür verstummen auf dieses Signal. Der Klang einzufangen beginnt damit, diese tiefe Stille zu bewahren."},"ICON-0483":{"nm":"Plektrum-Sortierdose","de":"Plektren nach Farbe geordnet aufgesteckt. Dicke und Gewicht formen die Gewohnheit der Fingerspitzen. Kurz vor dem Auftritt, ohne hinzusehen sofort das Richtige zu greifen – diese Präzision wächst genau hier."},"ICON-0484":{"nm":"Kabelbeschrifter","de":"Um in einem Gewirr aus Dutzenden Kabelsträngen nicht die Orientierung zu verlieren, muss man beide Enden beschriften. Nur wer aufgeschrieben hat, woher etwas kommt und wohin es geht, tappt im Dunkeln nicht mehr herum."},"ICON-0485":{"nm":"Kleinmixer-Drehregler","de":"Ein Finger, eine Fingerbreite gedreht – und die Textur der Stimme verändert sich. Zu laut klingt es rau, zu leise geht es unter; dieser eine Punkt dazwischen wird ertastet. Der feinste Handgriff bewirkt die größte Veränderung."},"ICON-0486":{"nm":"Ständer-Befestigungsscheibe","de":"Was die Bühne trägt, ist nicht das farbenfrohe Licht, sondern dieser kleine Ring. Er hält das Wackeln fest im Griff, fällt niemandem auf und hält trotzdem standhaft seinen Platz."},"ICON-0487":{"nm":"Set-Abbau-Etikett","de":"Auch alles, was aufgebaut wurde, hat beim vorsichtigen Niederlegen eine klare Reihenfolge. Ein Zettel, auf dem steht, was zuerst gelöst und wohin es gebracht werden soll. Die Hand, die abbaut, ist genauso tüchtig wie die, die aufbaut."},"ICON-0488":{"nm":"Fundsachen-Beutelchip","de":"Dinge, die jemand zurückgelassen hat, tragen jede für sich eine eigene Geschichte. Einen Gegenstand im kleinen Beutel zu verwahren und auf den Namen des Besitzers zu warten, ist eine Freundlichkeit, die auch das Herz des Verlustes kurz hütet."},"ICON-0489":{"nm":"Reinigungsweg-Markierung","de":"Folgt man dem Pfeil auf dem Boden, wird jeder Winkel lückenlos geputzt. Auch der Besen braucht eine Richtung, um nicht umsonst zu kreisen. Der strahlendste Platz wartet am Ende der am besten eingezeichneten Schritte."},"ICON-0490":{"nm":"Ausgangs-Führungsstab","de":"Wenn der letzte Applaus abklingt, öffnet dieser Stab den Weg. Eine Hand, die das noch aufgeregte Herz behutsam und unverletzt hinausleitet. Auch das Begleiten eines Endes ist erfüllt von herzlicher Fürsorge."},"ICON-0491":{"nm":"Rest-Kleberollball","de":"Wickelt man die verbleibenden Reste rund zusammen, entsteht erneut Nützlichkeit. Wie weggeworfene Enden sich zu einem festen Ball sammeln, wächst die Sparsamkeit in kleinen Händen."},"ICON-0492":{"nm":"Stuhlnummer-Kappe","de":"Erst wenn jeder Platz im Publikum eine Zahl trägt, verirrt sich niemand. Eine kleine Kappe, die den Platz zuweist, verwandelt das Herzklopfen eines Erstbesuchs in erleichterte Sicherheit."},"ICON-0493":{"nm":"Mülltrennung-Markierungspin","de":"Ein kleiner Pin, der Papier und Plastik voneinander trennt. Vermischt ist es nur Abfall, getrennt wird es wieder Ressource. Sortieren ist eine freundliche Tat, die Dingen ein zweites Leben schenkt."},"ICON-0494":{"nm":"Geräte-Rückgabeanhänger","de":"Was geliehen wurde, muss an seinen Platz zurückkehren. An jedem Handgelenk, das etwas mit einem Anhänger zurückbringt, wächst Vertrauen Schicht für Schicht. Wer gut zurückgibt, leiht sich beim nächsten Mal unbeschwerter."},"ICON-0495":{"nm":"Umkleide-Auschecklist","de":"Schminke und Kostüm sind abgelegt, zum Schluss wird dieser Schlüssel zurückgegeben. Was beim Eintritt empfangen wurde, wird beim Hinausgehen wieder abgegeben. Beginn und Ende des Tages liegen in derselben Hand."},"ICON-0496":{"nm":"Kissen-Puderquasten-Etui","de":"Wird die weiche Quaste gedrückt, verliert sie ihre Textur. Darin liegt der Grund, sie in ihrem runden Zuhause behutsam zu betten. Sanftheit lange zu bewahren beginnt damit, sanft mit ihr umzugehen."},"ICON-0497":{"nm":"Lidschatten-Chip","de":"Ein einziger Farbpunkt auf dem Augenlid verändert den Gesichtsausdruck vollständig. Die in einem kleinen Chip schlummernde Farbe erwacht erst im Bühnenlicht und verleiht dem auf die Bühne gerichteten Blick Tiefe."},"ICON-0498":{"nm":"Rouge-Pinsel-Kappe","de":"Wenn die Pinselspitze beschädigt ist, leidet auch die Farbabgabe. Die Textur durch ein kleines Käppchen zu schützen ist die stille Gewohnheit jener, die gute Werkzeuge lange bei sich behalten möchten."},"ICON-0499":{"nm":"Slim-Lippenfarbpalette","de":"Eine dicke Palette nimmt in der Tasche den ganzen Platz ein. Eine Hand, die weiß, dass eine dünne Reihe genügt. Der Moment, in dem Weglassen gleichzeitig Mitnehmen ist."},"ICON-0500":{"nm":"Mascara-Schutzschild","de":"Damit die einzeln aufgerichteten Wimpern nicht verwischen, hütet ein kleines Schild behutsam ihre Kurve. Was mit Sorgfalt aufgetragen wurde, muss mit Sorgfalt bewahrt werden – so lautet die Lehre der Zeit vor dem Spiegel."},"ICON-0501":{"nm":"Wattestäbchen-Etui","de":"Ein kleines Zuhause, das die weißen Wattestäbchen davor bewahrt, sich in alle Richtungen zu verstreuen. Stets griffbereit für die letzte Korrektur. Sorgfältige kleine Vorbereitungen füllen die Lücken einer großen Bühne."},"ICON-0502":{"nm":"Wimpernzangen-Gummipack","de":"Ist das Gummi verhärtet, zwickt das Klemmen der Wimpern unangenehm. Ersatz parat zu haben ist eine Freundlichkeit, die auch kleinen Schmerz im Voraus bedenkt."},"ICON-0503":{"nm":"Concealer-Pinsel","de":"Mit der feinen Pinselspitze werden Schatten sanft weggezaubert. Dort, wo das Licht nicht hinfiel, wird Helligkeit eingeführt. Eine Hand, die nicht bedeckt, sondern Licht hinzufügt, erzielt einen schöneren Abschluss."},"ICON-0504":{"nm":"Puder-Sieb","de":"Einmal gesiebt, legt sich das feine Pulver gleichmäßig und klumpenfrei auf. Diese eine Mühe des nochmaligen Durchsiebens. Sorgfalt zeigt sich letztlich an Fingerspitzen, die einen Schritt mehr unternehmen."},"ICON-0505":{"nm":"Pony-Rollklammer","de":"Eine Klammer, die das Pony rund aufrollt und kurz festhält. Während man wartet, setzt sich die Form in Ruhe. Ordentlichkeit erblüht dort, wo man das Warten kennt."},"ICON-0506":{"nm":"Haargel-Löffel","de":"Bevor das Wachs auf die Hand aufgetragen wird, entnimmt man es mit diesem kleinen Löffel. Nur so viel wie nötig herausschöpfen – die Zurückhaltung. Eine Hand, die maßvoll umgeht, erschafft das natürlichste Ergebnis."},"ICON-0507":{"nm":"Lockenstab-Unterlagematte","de":"Ein heiß aufgeheiztes Glätteisen darf nicht achtlos abgelegt werden. Eine Unterlagematte schützt Tisch und Hand gleichermaßen. Wer mit Hitze umgeht, braucht stets einen sicheren Platz zum Abstellen."},"ICON-0508":{"nm":"Haaröl-Probe","de":"Der Glanz, für den ein einziger Tropfen genügt, wird in einem kleinen Probefläschchen sicher aufbewahrt und unauffällig in die Tasche gesteckt. Das kleine Fläschchen kommt, anders als das große, überraschend oft zum Einsatz."},"ICON-0509":{"nm":"Bürsten-Reinigungsrechen","de":"Mit dem Rechen werden die in der Bürste verhedderten Haare langsam herausgekämmt. Die Pflege des Werkzeugs ist ein stilles Ritual nach getaner Arbeit. Eine gut gepflegte Bürste formt das Ergebnis von morgen schön."},"ICON-0510":{"nm":"Haargummi-Spule","de":"Auf die Spule gewickelt, hat man sofort den Überblick. Dieses kleine, aufgerollte Bündel ist ein herzliches Geschenk für den geschäftigen Morgen, an dem die Haargummis überallhin gerollt wären."},"ICON-0511":{"nm":"Färbe-Handschuhpack","de":"Dünne Handschuhe, die man anzieht, damit die Hände beim Auftragen der Farbe sauber bleiben. Der Wunsch, auch nach der Arbeit mit sauberen Händen in den nächsten Tag zu starten. Schutz ist ein anderer Name für genau diese Vorbereitung."},"ICON-0512":{"nm":"Haarnetz-Täschchen","de":"Ein kleines Täschchen, in das das Haarnetz sorgfältig zusammengefaltet verstaut wird. Gerade das Volumenlose verliert sich so leicht, darum dankt man dem aufmerksamen Handgriff, der ihm ein festes Zuhause gibt."},"ICON-0513":{"nm":"Flaum-Fixierstift","de":"Ein Stift, der herausstehende Haarflaum sanft andrückt und glättet. Die allerletzte Handbewegung, nachdem das große Styling abgeschlossen ist. Abschluss bedeutet stets, dem kleinsten Ort eine liebevolle Berührung zu schenken."},"ICON-0514":{"nm":"Parfüm-Testkappe","de":"Beim Auswählen eines Dufts hält man die Nase nicht direkt daran. Auf die kleine Kappe auftragen und in der Luft verstreuen – erst dann zeigt sich der echte Charakter. Auch ein Duft ist erst dann ehrlich, wenn man ihn aus einer gewissen Distanz wahrnimmt."},"ICON-0515":{"nm":"Roll-on-Duftflakon","de":"Die runde Kugel rollt sanft über das Handgelenk und hinterlässt eine Duftspur. Anders als ein Parfümflakon von früher, der getupft wurde, gleitet dieser wie ein Strich. Ein Duft hinterlässt je nach Art des Auftragens eine andere Geschichte."},"ICON-0516":{"nm":"Body-Mist-Deckel","de":"Ein kleiner Deckel, der den Duft einfängt, der sich nebelhaft ausbreitet. Bewahren, was sich öffnend verströmen würde. Wer etwas spart, lässt es länger in der Nähe bleiben."},"ICON-0517":{"nm":"Handcreme-Schlüsselring","de":"Befestigt man einen Ring an der kleinen Handcreme, ist sie überall dabei. Baumelt sie draußen an der Tasche, ist sie ein herzlicher täglicher Gruß an rissige Fingerspitzen."},"ICON-0518":{"nm":"Duschball-Halter","de":"Nach den blubbernden Schaumblasen muss der Ball gut getrocknet werden. Das Netzball, das auf einem Haken im Badezimmer hängt, schüttelt die Feuchtigkeit ab und wartet frisch auf den nächsten Morgen."},"ICON-0519":{"nm":"Massageball-Täschchen","de":"Den festen Ball, der verspannte Schultern löst, in ein kleines Täschchen stecken. In der kurzen Pause hinter der Bühne ein stilles Moment des Entspannens verspannter Muskeln. Fürsorge beginnt stets bei einem selbst."},"ICON-0520":{"nm":"Kühlpflaster-Dose","de":"Eine Dose voller Pflaster, die sich kühl anfühlen, wenn man sie aufklebt. In der Nacht nach der heißen Bühne lässt etwas den aufgewühlten Körper und Geist langsam abkühlen – die kleine Linderung darin schlummert leise."},"ICON-0521":{"nm":"Nagelöl-Stift","de":"Drücken, reiben, glänzen. Ein einziger Tropfen genügt für trockene Fingerspitzen. Kein aufwendiges Rezept nötig – ein zarter Glanz, der vom Stiftende auf die Nägel gleitet, umschmeichelt sie sanft. Fürsorge beginnt mit einem kleinen Tropfen."},"ICON-0522":{"nm":"Duftsachet-Klammer","de":"Ein kleiner Knoten, der den Duft an ein Blatt Papier bindet. Jedes Mal, wenn eine Schublade geöffnet wird, grüßt ein sanfter Hauch die Hand. Unsichtbar und trotzdem nah – diese eine Klammer trägt still den Trost eines ganzen Tages."},"ICON-0523":{"nm":"Nagelspitzen-Tablett","de":"Ein kleines Podium, auf dem die Farben für alle zehn Finger ausgebreitet werden. Welcher Ton passt zum heutigen Tag? Auf dem Tablett findet eine stille Probe statt. Dieses kurze Auswählen ist irgendwie aufregend – hier beginnt der Tag der Fingerspitzen."},"ICON-0524":{"nm":"Nagelhaut-Schieber-Kappe","de":"Auch das Schieben kann sanft sein. Mit dem runden Ende langsam und ohne Hast. Eilige Hände übersehen immer etwas – Ordnen ist eher ein Hinschauen mit Zeit."},"ICON-0525":{"nm":"Mini-Nagelfeile-Buffer","de":"Grobe und feine Seite – zwei Gesichter in einer Hand. Ecken sanft abzuschleifen und glatt zu polieren ist eine kleine Arbeit; aber Vollendung kommt stets aus solchen kleinen Handgriffen. Das letzte Wort gehört der Weichheit."},"ICON-0526":{"nm":"Nagelsticker-Bogen","de":"Sterne, Blumen, Herzen – einfach das passende für die heutige Stimmung heraussuchen und aufkleben. Auf dem Bogen reihen sich winzige Bilder auf; ein Sticker auf der Fingerspitze leuchtet wie ein herzliches kleines Zeichen."},"ICON-0527":{"nm":"Gel-Lampen-Abdeckplatte","de":"Eine dünne Schicht, die das Licht kurz einhüllt. Während der Aushärtung ruhen die Augen, nur die Fingerspitzen werden still fest. Auch das Warten braucht ein schattiges Plätzchen – in der Zeit ohne Hast werden die Nägel des Tages vollendet."},"ICON-0528":{"nm":"Nagelschmuck-Sortierbox","de":"Glitzernde Stückchen schlummern in kleinen Fächern. Kristalle, Perlen, Sternenpuder – man öffnet den Deckel mit der Aufregung einer namenlosen Schatzkiste. Der Moment des Auswählens – welches Licht auf den Nagel kommt – glänzt am schönsten."},"ICON-0529":{"nm":"Handpflege-Handschuhpack","de":"Ein kurzer Urlaub für die Hände während des Schlafs. Unter den Handschuhen wird trockene Haut die ganze Nacht über langsam weich. Fürsorge geschieht immer im Verborgenen – am Morgen kennt die Fingerspitze als erste diese Herzlichkeit."},"ICON-0530":{"nm":"Entferner-Pumpflasche","de":"Einmal drücken – genau die richtige Menge. Der kühle Duft, der in die Watte zieht, wischt das Gestern von den Nägeln rein ab. Auch das Leeren hat seinen Rhythmus: Ein Pumpstoß schafft still Platz für Neues."},"ICON-0531":{"nm":"Schmuckstein-Pinzette","de":"Manchmal braucht man feinere Finger als die eigenen. Eine Pinzette, die einen kleinen Stein zitterlos aufnimmt und platziert – Präzision ist ebenso Aufgabe des Werkzeugs wie des Herzens. Ein kleines Licht findet seinen Platz."},"ICON-0532":{"nm":"Ohrringe-Aufbewahrungsbrett","de":"Damit einzelne Ohrringe keine verlorenen Funde mehr in der Schublade werden. Paarweise auf ihren Platz gesteckt, wird das Auswählen im geschäftigen Morgen viel leichter. Aufräumen ist ein kleines Geschenk an das zukünftige Ich."},"ICON-0533":{"nm":"Ring-Größenset","de":"Ein kleines Bündel Ringe, das den Fingerumfang in Zahlen übersetzt. Einer nach dem anderen ausprobieren kommt dem langsamen Kennenlernen des eigenen Passenden gleich. Genauso wie dieses Aufatmen, wenn etwas perfekt sitzt."},"ICON-0534":{"nm":"Uhrenarmband-Stift","de":"Wenn das Armband locker wird, hält dieser kleine Stift die Zeit wieder am Handgelenk fest. Das am tiefsten verborgene Bauteil hält am längsten – das weiß eine lange getragene Uhr ohne Worte."},"ICON-0535":{"nm":"Ketten-Entwirrungsbrett","de":"Die feinen Kettchen kommen in separate Fächer, damit sie sich nicht ineinander verheddern. Ein verwirrungsfreier Morgen beginnt mit den kleinen Trennwänden vom Vorabend. Ruhe ist letztlich das Herz, das aufräumt, bevor die Hand greift."},"ICON-0536":{"nm":"Brosche-Verschlusskappen","de":"Je prunkvoller die Vorderseite, desto schweigsamer die Rückseite. Eine kleine Kappe, die die in den Stoff gesteckte Brosche fest hält – hinter dem strahlenden Licht gibt es stets Hände, die namenlos stützen. Unsichtbar und darum umso verlässlicher."},"ICON-0537":{"nm":"Sonnenbrillen-Täschchen","de":"Ein weiches Tuch umhüllt behutsam die Gläser, die das Sommerlicht ferngehalten haben. Ein kleines Täschchen schützt ein Paar Sichtfelder vor Stößen in der Tasche. Etwas zu hegen bedeutet stets, eine sanfte Schicht darüber zu legen."},"ICON-0538":{"nm":"Gürtel-Lochzange","de":"Ob der Bund enger wurde oder der Sommer weiter. Ein weiteres Loch genügt, und der Gürtel passt wieder. Ich bin es, der sich immer verändert, und es ist die Aufgabe dieses kleinen Werkzeugs, schweigend mitzuwachsen."},"ICON-0539":{"nm":"Schal-Halteklammer","de":"Eine Klammer, die den gleitenden Schal an einem Punkt zusammenfasst und festhält. Der im Wind drohend aufgehende Schwung findet endlich seinen Platz. Auch Eleganz lehnt sich gelegentlich an diese kleine Klammer, um einen beinahe aufgelösten Tag ordentlich zu schließen."},"ICON-0540":{"nm":"Charm-Ring-Set","de":"Kleine Ringe, die man auf einer Seite der Tasche befestigen kann, kamen als Set. Seine Lieblinge am Körper zu tragen – das Aufhängen eines Charms für die heutige Stimmung ist ein kleines, nur ihm bekanntes Ritual, das irgendwie Freude bereitet."},"ICON-0541":{"nm":"Fusselentferner","de":"Wenn ein Pullover über Nacht wie gealtert mit Fusseln bedeckt ist, rollt man dieses Gerät leise darüber, und es hat wieder das Gesicht des Neuen. Das leise Surren, das das Verblasste wegräumt, ist irgendwie beruhigend. Ein geliebtes Kleidungsstück lebt so noch einmal auf."},"ICON-0542":{"nm":"Textilduft-Karte","de":"Tief in den Kleiderschrank gesteckt, füllt sie tagelang still mit Duft. Ein Brief, der in Duft statt in Worten verfasst ist – eine Seite, die man liest, ohne sie zu öffnen. Jeden Morgen beim Herausnehmen breitet sich das am gestrigen Tag aufgeschriebene Herzliche zuerst aus."},"ICON-0543":{"nm":"Antistatik-Pin","de":"An einem Wintermorgen, wenn der Rock an den Beinen klebt, löst ein einziger Pin sanft dieses Haften. Ein kleiner Frieden, der sogar unsichtbare Reibung beruhigt – ist ein kleines Ärgernis erst weg, verläuft der Tag spürbar reibungsloser."},"ICON-0544":{"nm":"Taschen-Kleiderbürste","de":"Kurz vor dem Hinausgehen, ein einzelner Staubfaden auf der Schulter. Die zusammengefaltete Bürste einmal aufrollen genügt, und der erste Eindruck ist wieder tadellos. Abschluss findet immer vor der Tür statt, und Gepflegtheit vollzieht sich in diesem einen Handgriff."},"ICON-0545":{"nm":"Wäschenetz-Etikett","de":"Was sich nicht mischen darf, wird im Netz verwahrt, und das Etikett schreibt leise den Namen. Auch beim Waschen gibt es Plätze, und zu Plätzen gehören kleine Markierungen. Die Ordnung eines leicht wirr werdenden Tages wächst aus diesen kleinen Namensschildern."},"ICON-0546":{"nm":"Fleckenentferner-Stift","de":"Selbst ein Kaffeefleck auf dem Hemd verschwindet, wenn man sanft darauf tupft. Kein Überdecken, sondern behutsames Wegwischen. Jeder verdient einmal die Chance, den Tag neu und sauber zu beginnen."},"ICON-0547":{"nm":"Schuhcreme-Tuch","de":"Mit einem Wischen über das Tuch findet das Leder seinen Glanz zurück. Je länger die Schuhe getragen wurden, desto tiefer zieht das Wachs ein. Der Glanz ist der Lohn der gemeinsam gegangenen Zeit – die Schuhe tragen diese Jahre still auf dem Rist."},"ICON-0548":{"nm":"Schnürsenkel-Endkappe","de":"Eine kleine Kappe am Ende des gelösten Schnürsenkels. Damit bis zur Ziellinie kein Blick zur Seite abgelenkt wird, ist das Ende fest versiegelt. Ein sicher gebundener Schnürsenkel trägt den Schritt weiter – eine kleine Absicherung gibt den Mut, bis ans Ende zu laufen."},"ICON-0549":{"nm":"Kleiderbügel-Namenschip","de":"Inmitten ähnlicher Kleiderbügel flüstert dieser kleine Chip leise: 'Mein Platz.' Ein stiller Wegweiser, der das Durcheinander am geschäftigen Morgen reduziert – weniger Sucherei macht den Tagesbeginn ein gutes Stück leichter."},"ICON-0550":{"nm":"Linsen-Pinzetten-Dose","de":"Manchmal braucht man eine genauere Spitze als die Fingerspitze. In der Dose wartet eine Pinzette, die eine kleine Linse ohne Zittern aufnimmt. Präzision schläft immer ruhig vorbereitet und wacht sofort auf, wenn man sie ruft."},"ICON-0551":{"nm":"Wattepads-Minipack","de":"Ein kleines Bündel – genau so viel, wie man einmal braucht. Die Weichheit bleibt erhalten, auch wenn der Umfang in der Tasche schrumpft. Weniger einzupacken ist auch eine Form von Herzlichkeit – im freigelassenen Raum entsteht ein leichterer Tag."},"ICON-0552":{"nm":"Blotting-Paper-Etui","de":"Mit einem einzigen Blatt wischt man den Mittagsglanz auf der Nasenspitze behutsam ab. Im Etui schlummern ordentlich aufgereihte Blätter – beim Herausnehmen eines schaut jeder kurz, herzlich auf sich selbst im Spiegel."},"ICON-0553":{"nm":"Klappspiegel mit Kamm","de":"Zugeklappt passt er in eine Hand, aufgeklappt bietet er Spiegel und Kamm. Das kleine Allroundtalent in der Tasche, das im Notfall für Ordnung am Erscheinungsbild sorgt. Gepflegtheit ist nichts Aufwändiges – es ist die Bereitschaft, irgendwo den Kamm einmal anzusetzen."},"ICON-0554":{"nm":"Reise-Rasierer-Kappe","de":"Die scharfe Klinge im Reisegepäck wird sicher zur Ruhe gebettet. Dank dieser stumpf wirkenden, aber soliden Kappe verletzt sich auch die tastende Hand im geschäftigen Morgen nicht. Vorsorge bedeutet stets, Gefahren schon vorab abzudecken."},"ICON-0555":{"nm":"Lippenbalsam-Ring","de":"Ein kleines Schutzmittel, das an der Taschenklappe baumelt. Keine Sorge mehr, dass es in der Hosentasche rollt und zerbricht – rissige Lippen sind immer in Greifweite. Etwas dabeizuhaben bedeutet letztlich, das Nötige an den nächsten Ort zu legen."},"ICON-0556":{"nm":"Handdesinfektions-Halter","de":"Einmal drücken, eine Handvoll Sauberkeit. Vor der Tür, am Schreibtisch, überall aufgehängt rückt auch das Händewaschen näher. Gute Gewohnheiten entstehen nicht aus Großem, sondern dort, wo man die Hand hinstreckt."},"ICON-0557":{"nm":"Slim-Taschentuchtasche","de":"Schlanker Körper, ein Häppchen Taschentücher darin. Ohne dass die Tasche sich beulen muss, ist man auf plötzliche Schnupfen oder Tränen immer leise vorbereitet. Ein Stück zum Hinüberreichen – je schlanker die Vorbereitung, desto stilvoller."},"ICON-0558":{"nm":"Mini-Mundspül-Fläschchen","de":"Wenn man nach einem scharfen Ramen-Gericht jemanden treffen muss, übernimmt dieses kleine Fläschchen diskret die Mundpflege. Ein Schluck Frische kann manchmal echtes Selbstvertrauen geben und ein zögerndes Hallo leichtherzig machen."},"ICON-0559":{"nm":"Glitter-Puder-Chip","de":"Mit den Fingerspitzen sanft auf die Wange getupft, verstreuen sich Sternenpartikel wie im Bühnenlicht. Eine ganz gewöhnliche Wange leuchtet im nächsten Moment auf – die Magie dieses kleinen Chips. Licht kommt immer so, als winziger Puder auf der Fingerspitze."},"ICON-0560":{"nm":"Glitter-Abdecksticker","de":"Wo zu viel Glitzern zu auffällig wäre, drückt dieser Sticker das Licht sanft herunter. Auch das Reduzieren von Prunk ist Teil des Stylings – was im gedämpften Bereich bleibt, wird manchmal ein anderes, feines Gefühl."},"ICON-0561":{"nm":"Steinaufklebe-Stift","de":"Ein kleiner Stein, der am Fußweg liegen geblieben ist. Ein Stift, mit dem man sich die Mühe macht, sich zu bücken und ihn aufzusammeln. Das Herzliche zeigt sich immer dort, wo man anhält."},"ICON-0562":{"nm":"Wimpern-Aufbewahrungsbrett","de":"Eine kleine Platte, auf der jede einzelne Wimpern ordentlich abgelegt wird. Auch nach dem Abnehmen bleibt die feine Kurve ungestört. Selbst das, was kurz abgelegt wird, erinnert sich an seinen Platz – ein stilles, ordentliches Aufbewahrungsgefühl."},"ICON-0563":{"nm":"Doppelband-Schneidekappen","de":"Zwei Klingen greifen ineinander und schneiden einen Knoten auf einmal. Je sauberer der Schnitt, desto ordentlicher der nächste Knoten. Aus einer Hand, die gut bindet und gut schneidet, löst sich auch ein neuer Anfang leichter."},"ICON-0564":{"nm":"Gesichtslinie-Klebestreifen","de":"Einen Streifen entlang der Kinnlinie – atemlos und vorsichtig auftragen. Kontur bedeutet nicht, eine Linie neu zu zeichnen, sondern das bereits Schöne zu betonen. Eine Hand, die die von Natur aus vorhandene Textur sanft nachzeichnet."},"ICON-0565":{"nm":"Licht-Reflektor-Puder","de":"Ein Pulver, das Licht in sich aufnimmt und es fein zurückgibt. Auch ohne selbst zu leuchten, wird man durch das Verstreuen des empfangenen Lichts hell. Wie man erhaltene Freundlichkeit an andere weitergibt, wächst das Strahlen mit dem Teilen."},"ICON-0566":{"nm":"Make-up-Fixer-Fächer","de":"Ein Fächerhauch hält die aufwendige Schminke bis ans Ende des Tages. Nicht nachlassen, nicht verlaufen – sanft kühlen und festigen. Damit das sorgfältig geschminkte Gesicht bis zum Fallen des Bühnenvorhangs klar erkennbar bleibt."},"ICON-0567":{"nm":"Farbkorrektur-Palettenplättchen","de":"Kleine Plättchen, die abweichende Farbtöne Schritt für Schritt beruhigen und korrigieren. Auch eine Farbe, die allein herumgeistert, strahlt auf, sobald eine passende Nachbarfarbe dazukommt. Erst wenn Farbe und Farbe die Hand reichen, ergibt sich ein klares Bild."},"ICON-0568":{"nm":"Halsschal-Packset","de":"Um den Hals gewickelt, wird die kühle Luft des frühen Morgens im Übungsraum spürbar milder. Warm wie die Hand einer Großmutter, die dem Enkel den Schal umlegt. Kälte setzt immer an den feinsten Stellen an – darum wärmt man erst den Hals."},"ICON-0569":{"nm":"Wärme-Augenmaske-Beutel","de":"Ein Beutel, in dem die gewärmte Augenmaske aufbewahrt wird. Im Moment des Öffnens gleitet wohliges Wärme sanft über die Augenlider. Ein herzliches Ritual vor dem Einschlafen, das einen langen Tag kurz einschließt und wieder löst."},"ICON-0570":{"nm":"Mobiler Befeuchtungsfilter","de":"Ein kleiner Filter, der dem ausgetrockneten Raum Feuchtigkeit zurückgibt. Im Unsichtbaren filtert er schweigend das Trübe. Die Frische, die den Raum erfüllt, ist eine klare Güte, die von jemandes unsichtbarem Einsatz geschützt wird."},"ICON-0571":{"nm":"Vitaminsortierdose","de":"Eine Dose, in der die Tagesdosen Tabletten in Fächern aufgeteilt werden. Regelmäßig zu nehmen bedeutet, das Versprechen zu geben, auch morgen auf der Bühne zu stehen. In jedem kleinen Fach ist das Selbstfürsorge-Herz sorgfältig geordnet."},"ICON-0572":{"nm":"Schlaf-Ohrenstöpsel-Etui","de":"Das Zuhause der Ohrstöpsel, die die Welt vorübergehend abschließen. Auch Stille braucht Fürsorge, darum liegen sie ordentlich im Etui. Dass eine tief schlafende Nacht die Stimme des nächsten Tages hell aufwachen lässt – das weiß die Rast."},"ICON-0573":{"nm":"Kühltuch-Klammer","de":"Eine Klammer, die das gekühlte Handtuch fest an der Schulter hält, damit es nicht herunterfällt. An einem heißen Tag ist ein einziger kühler Streifen am Nacken das, was den langen Nachmittag durchhält. Auch kleine Kühle bleibt, wenn man sie festhält."},"ICON-0574":{"nm":"Dehnball-Täschchen","de":"Ein Täschchen, in das der Ball, der den Körper gelockert hat, wieder verstaut wird. Den Ball ganz aufzublasen und dann wieder klein einzupacken gleicht Einatmen und Ausatmen. Im Wechsel zwischen Ausdehnen und Zusammenziehen wird Körper und Geist langsam fest."},"ICON-0575":{"nm":"Stütz-Bandagerolle","de":"Ein Band, das den gestreckten Knöchel Lage für Lage sanft umhüllt. Kein Abschnüren, sondern stilles Stützen. Je überbeanspruchter die Stelle, desto mehr braucht sie eine Begleitung, die schweigend aushält – so flüstert es sich beim Aufrollen."},"ICON-0576":{"nm":"Konditions-Check-Anhänger","de":"Ein Anhänger, auf dem man die Verfassung des heutigen Tages in einem Satz notiert. Gut oder schlecht ehrlich dranzuhängen erfordert etwas Mut. Statt 'Alles okay' zu sagen, wer den heutigen Ich-Stand aufschreibt, dem schenkt jemand einen aufmerksamen Blick."},"ICON-0577":{"nm":"Schuh-Duftkapsel","de":"Eine Duftkapsel, die einfach ins Schuhinnere gesteckt wird. Eine kleine, zarte Aufmerksamkeit für die Füße, die den ganzen Tag die Bühne tragen. Die besten Düfte an die Stellen, die am meisten gearbeitet haben – Herzlichkeit lässt keinen Fußzeh aus."},"ICON-0578":{"nm":"Einlagesohlen-Größentabelle","de":"Auf jeder Einlagesohle ist die Fußgröße klar eingetragen. Das perfekt passende Paar macht den Schritt auf der Bühne leichter. Den Schritt jedes Einzelnen zu berücksichtigen – Maßanfertigung ist letztlich das Herz, das genau hinschaut."},"ICON-0579":{"nm":"Schuhanzieher-Schlüsselring","de":"Ein auf Handtellergröße verkleinerter Schuhlöffel als Schlüsselanhänger. Eine kleine Aufmerksamkeit, die den Moment des Anziehens sanft erleichtert. An den Füßen, die aufbrechen, hängt immer still jemandes herzliche Begleitung mit."},"ICON-0580":{"nm":"Taschenstaubschutz-Abdeckung","de":"Ein Tuch, das die geliebte Tasche behutsam vor Staub schützt. Selbst wenn sie nicht benutzt wird, bewahrt es die Textur und lässt sie gepflegt ruhen. Auch Dinge, zu denen man nicht oft greift, denen aber das Herz gehört, umschließt so eine stille Fürsorge."},"ICON-0581":{"nm":"Trägerstift-Einstellpin","de":"Ein Pin, der den schlüpfrigen Träger fest am Körper hält. Zu locker gleitet die Schulter herunter, zu eng schränkt das Atmen ein. Im kleinen Einstellschritt, der das Richtige findet, wird auch das Bühnenkostüm – und das Herz – endlich bequem."},"ICON-0582":{"nm":"Reißverschluss-Gleitstift","de":"Einmal über den klemmenden Reißverschluss gefahren, gleitet er wieder weich. Dieses Geräusch, wenn Festsitzendes sich wieder löst – wie erleichternd das ist. Ein Hauch Glattheit lässt das, was stockte, wieder fließen."},"ICON-0583":{"nm":"Sneaker-Reinigerspitze","de":"Die Schmutzflecken auf den Turnschuhen werden Punkt für Punkt weggeputzt. Die Spuren des Übens, die außerhalb der Bühne unsichtbar blieben, werden sorgfältig getilgt. Wenn die Schuhspitze wieder strahlend weiß ist, glaubt man, auch morgen mit frischem Mut laufen zu können."},"ICON-0584":{"nm":"Imprägnierspray-Kappe","de":"Die Kappe des wasserabweisenden Sprays lässt Tropfen rund abrollen. Eine Schutzschicht im Voraus aufzutragen ist fürsorgliches Vorausdenken. Weil man den Regen kennt, trägt man an einem klaren Heute schon eine Lage Schutz auf."},"ICON-0585":{"nm":"Leder-Schutzdeckel","de":"Ein Tuch, das behutsam über das Leder gelegt wird, damit keine Falten entstehen. Wie man früher eine Leinwand in Seidenpapier hüllte, um die Maserung zu wahren. Je länger man etwas bei sich behalten möchte, desto langsamer – denn Pflege ist ein anderer Name für die Zeit des Behütens."},"ICON-0586":{"nm":"Koffer-Namensband","de":"Ein Namensband, das das eigene Gepäck unter vielen auf einen Blick erkennbar macht. Während die Koffer sich auf dem Förderband im Kreis drehen, hebt ein einziger Buchstabe die Hand. So weit man auch reist – ein Name, und man findet sich wieder."},"ICON-0587":{"nm":"Kompressionsbeutel-Klammer","de":"Eine Klammer, die aufgequollenes Gepäck flach presst und verschließt. Nicht geleert, sondern sorgfältig gefaltet und zusammengelegt. An Fingerspitzen, die den Haushalt schmal ordnen, schrumpft auch der Wunsch nach mehr mit."},"ICON-0588":{"nm":"Reise-Waschmittelblatt","de":"Ein Blatt, das am Waschbecken zum Waschmittel wird. Ähnlich der Reiseweisheit, Kleidung unterwegs mit der Hand zu waschen. Das Gepäck bleibt leicht, aber die Ordentlichkeit kommt mit – die beständige Haltung des Reisenden."},"ICON-0589":{"nm":"Nackenkissen-Bezug","de":"Ein frisch aufgezogener Bezug für das Kissen, das den Nacken stützte. Die Anlehnung sollte stets sauber sein, damit das Herz Ruhe findet. Den Platz frisch und einladend freizuhalten für jemanden, der sich anlehnen möchte – Herzlichkeit beginnt genau dort."},"ICON-0590":{"nm":"Gepäckwaagen-Band","de":"Ein Band, mit dem man die Tasche hochhebt und das Gewicht abwägt. Vor der Abreise das Gewicht des Gepäcks einmal mit den Händen spüren. Im Abwägen zwischen mitnehmen und zurücklassen wägt man auch still das Gewicht des Herzens mit."},"ICON-0591":{"nm":"Schuhtaschen-Paar","de":"Ein Paar Täschchen, die linken und rechten Schuh nebeneinander aufnehmen. Was getrennt abgelegt leicht verloren geht, hat als Paar mehr Halt. In Dingen, die immer zusammen gehen, steckt die Kraft, einander still zu beschützen."},"ICON-0592":{"nm":"Zusatztaschen-Haken","de":"An einem Tag, an dem eine Hand nicht reicht, hängt man die Tasche kurz an diesen kleinen Haken. Eine Reservekapazität für den Tag, an dem das Gepäck einfach zu viel wird. Schon das Wissen, dass es einen Platz zum Aufhängen gibt, macht die Schulter leichter."},"ICON-0593":{"nm":"Reiseplan-Chip","de":"Auf einem Chip werden die Wege eines Tages sorgfältig vermerkt. Wo man sich trifft, wohin der Weg führt – eine vorab gezeichnete Linie für Schritte, die sich leicht verirren. Gemeinsam unterwegs zu sein heißt, Schritt für Schritt aufzuschreiben, um sich kaum zu verirren."},"ICON-0594":{"nm":"Multiadapter-Kappe","de":"Eine Kappe, die sich auch in die Steckdose eines fremden Landes passgenau einfügt. Auch wenn die Form anders ist, verbindet sie sich letztlich zu einem. Verschiedenes miteinander zu verbinden – Harmonie beginnt mit einer kleinen Anpassung."},"ICON-0595":{"nm":"Fahrkarten-Schutzhülle","de":"Ein transparenter Einschub, der die Karte bei jedem Durchschieben am Drehkreuz schützt. Jede tägliche Fahrt, sogar die abgenutzten Stempel, wird sorgfältig eingehüllt. Dass auch ein gewöhnlicher Weg zur Erinnerung wird, beweist diese dünne Schicht."},"ICON-0596":{"nm":"Fahrkarten-Klammer","de":"Eine Klammer, die das schnell zerknitterte Stück Papier ordentlich festhält. Verliert man das Ticket unterwegs, gerät alles ins Schwanken. Kleines Papier fest zu halten – die Gewissheit einer Reise kommt von genau diesem einen Fach."},"ICON-0597":{"nm":"Umstieg-Notizchip","de":"Ein kleiner Chip mit einer einzeiligen Notiz, wo man umsteigen muss. An jedem verwirrenden Abzweig öffnet ein vorab geschriebenes Wort den Weg. Eine Notiz ist ein herzlicher Hinweis, den man dem zukünftigen sich zusteckt, damit er sich nicht verirrt."},"ICON-0598":{"nm":"Durchgangs-Passiermarke","de":"Eine Marke, die beim Durchschreiten des Tores still erkannt wird. Auch ein Weg, der wie versperrt wirkte, öffnet sich einem, der seinen Ausweis mit dabei hat. Aufrecht voranzutreten bedeutet, ohne Zögern leicht in das nächste Feld einzutreten."},"ICON-0599":{"nm":"Taxibon-Halter","de":"Auf jedem kleinen Quittungszettel ist der Weg des Tages klar aufgedruckt. Quittungen, die überall herumkugelten, ordentlich eingeheftet zu sammeln – und was wie nichts wirkte, häuft sich zu einer richtigen Reiseroute auf."},"ICON-0600":{"nm":"Fahrrad-Reflektorband","de":"Ein Band, das auf dem dunklen Weg das Licht Vorbeifahrender aufnimmt und sanft aufleuchtet. Ohne selbst zu leuchten, wird man durch das Licht anderer hell. Sichtbar zu sein bedeutet eine herzliche Bitte in der Nacht: komm bitte heil nach Hause."},"ICON-0601":{"nm":"Trolleyrollen-Schutzkappe","de":"Auch nach tausend Runden auf dem Flughafenband bleiben die Ecken heil – dank dieser kleinen Kappe, die die Räder umschließt. Die rauhsten Wege werden zuerst berührt; jemanden still zu beschützen, geschieht immer dort, wo man es kaum bemerkt."},"ICON-0602":{"nm":"Sitzplatz-Kopfstützenbezug","de":"Langer Bus, ein Bezug über die Kopfstütze gelegt, Kopf ans Fenster gelehnt. Der Geruch des Vordermanns und die Erschöpfung des gestrigen Tages kommen hier nicht heran. Eine saubere Lehnstelle – auf fremden Wegen ein überraschend großer Trost."},"ICON-0603":{"nm":"Parkplatz-Markierungspin","de":"„Welche Etage, welche Reihe war das noch?“ Wer schon mal ewig in einem leeren Parkhaus gesucht hat, weiß, wie wertvoll dieser Pin ist. Statt verblassender Erinnerung ein gezielter Steckpunkt – der Rückweg ist von vornherein gesichert."},"ICON-0604":{"nm":"Zimmerschlüssel-Halteschlaufe","de":"Wie leicht verschwindet ein Zimmerschlüssel. An der Schlaufe ums Handgelenk gehängt, vergisst man das Zimmer für diese Nacht nicht mehr. Das kleine Gefühl der Geborgenheit, in einer fremden Stadt einen festen Platz zu haben, baumelt am Handgelenk."},"ICON-0605":{"nm":"Türhänge-Signalchip","de":"Wenn die Probe beginnt, hängt ein Chip an die Tür: Bitte nicht stören – hier ist gerade volle Konzentration angesagt. Die tiefe Stille hinter der Bühne wird von solchen kleinen Signalen lautlos bewacht."},"ICON-0606":{"nm":"Toilettenartikel-Täschchen","de":"Zahnbürste, Reinigungsschaum, ein handflächengroßes Handtuch. Ganz gleich wohin die Reise geht – ist dieses Täschchen dabei, beginnt und endet jeder Tag mit vertrauten Handgriffen. Ein kleiner Haushaltsvorrat, der fremde Schlafstätten rasch heimelig macht."},"ICON-0607":{"nm":"Reservehandtuch-Clip","de":"Das Reservehandtuch neben dem Waschbecken, nie einen richtigen Platz und stets feucht. Mit einem Clip angehängt, findet es endlich seinen Platz. Einem Handtuch einen Trockenplatz zu geben – Fürsorge hat oft genau diese Größe."},"ICON-0608":{"nm":"Mehrfachstecker-Täschchen","de":"Beim Öffnen der Tasche lagen die Ladekabel stets verknäult. Steckerleiste und Kabel zusammengerollt verstaut, und schon ist alles ordentlich. Wenn die Kabel sich entwirren, löst sich auch ein Zipfel der Anspannung vor dem Aufbruch."},"ICON-0609":{"nm":"Bettnummer-Etikett","de":"An jedem Etagenbett im Gemeinschaftsquartier klebt eine Nummer. Durch dieses eine Etikett – das zeigt, welcher Platz meiner ist – wird das fremde Zimmer noch in derselben Nacht ein Zuhause. Anfänge sind immer so klein."},"ICON-0610":{"nm":"Mini-Wäscheleine","de":"Zwischen zwei Fensterrahmen gespannt wird sie zur Wäscheleine. An einem sonnigen Tag tanzen handgewaschene Socken weich im Wind. Auch fern von zuhause trocknet der Alltag so auf einer Leine."},"ICON-0611":{"nm":"Hausschuh-Kennzeichnungsanhänger","de":"Wenn sich am Eingang Hausschuhe stapeln, weiß man bald nicht mehr, welche die eigenen sind. Ein kleiner Anhänger, und die Schuhe erkennen ihren Besitzer wieder. Wer zusammenlebt, braucht solche freundlichen Markierungen."},"ICON-0612":{"nm":"Frühstückscoupon-Halter","de":"Ein Halter für den Frühstücksbon. Am knurrenden frühen Morgen ist mit diesem Zettel eine dampfende Schüssel Suppe schon versprochen. Der Tag am Reiseziel beginnt langsam und warm mit einer guten Mahlzeit."},"ICON-0613":{"nm":"Fußgelenk-Reflektorband","de":"Am Knöchel befestigt, wirft es im Dunkel Licht zurück. Beim Nachtspaziergang winkt dieses kleine Band herannahenden Autos lautlos zu: „Hier ist ein Mensch.“ Sicherheit leuchtet manchmal so schlicht."},"ICON-0614":{"nm":"Feuchttücher-Verschlusskappe","de":"Eine Kappe, die genau auf die Öffnung der Feuchttücherpackung passt. Ein Tuch nach dem anderen gleitet weich heraus, der Rest trocknet nicht aus. Selbst scheinbar unwichtige Dinge, nach denen man täglich greift, haben stets einen guten Grund."},"ICON-0615":{"nm":"Kleine Picknickmatten-Schlaufe","de":"Die Picknickmatte rund zusammengerollt und mit einer Schlaufe verschnürt. Am Ufer des Han, im Schatten der Kirschblüten – kaum breitet man sie irgendwo aus, wird der Fleck zu unserem Platz. Eine Schlaufe, die ein handtellergroßes Stück Wiese als ganzes Reich mit sich führt."},"ICON-0616":{"nm":"Mückenpflaster-Etui","de":"Ein Etui für das Sommernacht-Muss: Mückenpflaster. Die Voraussicht, die darin steckt, trägt man in diesem kleinen Fach mit sich. Die Backstage-Bereiche unter freiem Himmel werden durch solche kleine Vorbereitungen sicherer."},"ICON-0617":{"nm":"Spaziergang-Trinkflaschenring","de":"Ein Ring, um die Trinkflasche beim Spaziergang an der Tasche zu befestigen. Wasser zur Hand zu haben, wenn der Durst kommt, bedeutet: Man kann noch viel weiter laufen. Eine kleine Verbindung, die Gehende nicht anhält."},"ICON-0618":{"nm":"Faltbarer Einkaufskorb","de":"Aufgeklappt ein Einkaufskorb, zusammengefaltet handtellergroß. Ideal, um beim Bummeln durch den Marktgang ein frisches Bündel Gemüse einzulegen. Die Weisheit des Haushalts wächst stets in Richtung weniger Volumen und leichterem Tragen."},"ICON-0619":{"nm":"Windschutz-Klemme","de":"An einem windigen Tag packt sie ein flatterndes Zeltende und hält es fest. Eine Klemme drückt das ständig Zitternde wieder an seinen Platz. Im Freien ist das Verlässlichste oft ein fingergroßes Ding wie dieses."},"ICON-0620":{"nm":"Sonnenschutz-Stecknadel","de":"Eine Stecknadel, die am Fenster die Sonne schräg abschirmt. Wenn das Mittagslicht zu grell ist, wirft sie sanft einen kleinen Schatten. Jemandem die Blendung zu nehmen kann ebenfalls eine zärtliche Geste sein."},"ICON-0621":{"nm":"Not-Trillerpfeifen-Schutzkappe","de":"Eine Kappe, die die Öffnung der Notfallpfeife abdeckt. Damit kein Staub eindringt und sie im entscheidenden Moment sofort ertönt. Manche Dinge beruhigen einen allein dadurch, dass sie da sind – auch wenn man hofft, sie nie zu brauchen."},"ICON-0622":{"nm":"Regenschirmspitzen-Schutzkappe","de":"Eine kleine Kappe für die Schirmspitze. Ist die scharfe Spitze gedämpft, verletzt sie weder Nachbarn noch die eigene Tasche. Anstand an Regentagen beginnt leise damit, scharfe Enden weich zu umhüllen."},"ICON-0623":{"nm":"Regenponcho-Aufbewahrungsbeutel","de":"Ein Beutel, um den getrockneten Regenponcho zusammenzurollen. Er wartet still in einer Taschenecke, bis der nächste Schauer kommt. Vorsorge ist letztlich der Herzensimpuls, auch etwas mitzunehmen, das man vielleicht nie braucht."},"ICON-0624":{"nm":"Wasserdichte Schuhüberzieher","de":"Über die Schuhe gezogen, dringt kein Regenwasser mehr ein. Selbst auf dem verregneten Schulweg in der Regenzeit bleiben die Socken trocken. Ein Tag, an dem die Füße nicht nass werden, hebt die Stimmung überraschend stark."},"ICON-0625":{"nm":"Eislauf-Antirutschpad","de":"Unter den Schuh geklebt, ist selbst Glatteis weniger beängstigend. In jenem Winter, als man mit kleinen Schritten schneebedeckte Gassen überquerte – das Pad hielt einen leise fest. Versteckter Halt unter behutsamen Schritten."},"ICON-0626":{"nm":"Kühlender Nackenring","de":"Umgelegt, zieht er sanft die Wärme ab. Mitten in der drückenden Hochsommerhitze trägt man diese eine kühle Frische um den Nacken – die sommerliche Weisheit, die Hitze zu ertragen, wird von Jahr zu Jahr feinfühliger."},"ICON-0627":{"nm":"Handventilator-Ständer","de":"Ein Ständer, auf dem der Handventilator abgestellt wird. Hat man beide Hände frei, blättert man Seiten um oder schreibt statt zu fächeln. Eine kleine Brise macht den langen Sommer am Schreibtisch gerade noch erträglich."},"ICON-0628":{"nm":"Wärmekissen-Täschchen","de":"Ein Täschchen, in dem Wärmekissen mitgetragen werden. Greift man in der Kälte in die Tasche, ist dort schon eine kleine Wärme und wartet. Mit diesem Handvoll Wärme übersteht man Winterausflüge."},"ICON-0629":{"nm":"Ohrenwärmer-Etui","de":"Ein Etui, in dem Ohrenschützer aufbewahrt werden. Ein Platz, um sie bis zur nächsten Kälte sorgfältig zu verwahren. Dinge, die man auch beim Saisonwechsel nicht wegwerfen kann, tragen einen stillen Glauben an den Winter, der wiederkommt."},"ICON-0630":{"nm":"UV-Messchip","de":"Hält man ihn kurz ins Licht, zeigt er die UV-Intensität des Tages farblich an. Was bislang unsichtbar war, wird nun sichtbar. Ein kleines Auge für das Sonnenlicht, still ums Handgelenk gebunden."},"ICON-0631":{"nm":"Gassen-Stempelkarte","de":"Eine Karte, auf der man bei jedem Geschäft in der Gasse einen Stempel sammelt. Mit jedem Abdruck zeichnet sich die Karte des Viertels klarer im Gedächtnis ab. Erinnerungen, die man zu Fuß gesammelt hat, hinterlassen so Stempelspuren."},"ICON-0632":{"nm":"Besuchsorte-Pinnwand","de":"Eine kleine Pinnwand, auf der man für jeden besuchten Ort eine Nadel einsteckt. Mit jedem Punkt wächst auch der eigene Horizont. Jede Nadel flüstert leise: „Hier war ich.“"},"ICON-0633":{"nm":"Mini-Kompassschlaufe","de":"Auch nach langem Irren zeigt Norden stets dieselbe Richtung. Der kleine Kompass auf der Brust hilft zuerst, den schwankenden Geist zu beruhigen, wenn man nicht mehr weiß, wohin man gehen soll."},"ICON-0634":{"nm":"Wegweiser-Notizenring","de":"Auf einem Ring aufgefädelt die Zettel, auf denen man sich den Weg notiert hat. „An der roten Briefkastensäule links abbiegen.“ Jemandes ungeübte Handschrift lotst einen still durch fremde Gassen. Wege auf Papier verblassen kaum."},"ICON-0635":{"nm":"Sehenswürdigkeiten-Stickerbuch","de":"Ein Buch, das man Seite für Seite mit je einem Sticker vom Reiseziel füllt. Türme, Brücken, alte Stadtmauern – sie schichten sich Seite für Seite. Besuchte Orte zu sammeln gleicht dem Berühren vergangener Zeit mit den Fingerspitzen."},"ICON-0636":{"nm":"U-Bahn-Umstiegschip","de":"An der Umstiegsstation, wo Linien sich gabeln, fest in der Hand gehalten. Dieser kurze Moment der Entscheidung, welche Linie man nimmt, kann manchmal den ganzen Tag in eine andere Richtung lenken. Bei einer kleinen Wahl zeigt die Stadt ein anderes Gesicht."},"ICON-0637":{"nm":"Viertel-Entdeckerkarte","de":"„Heute bis zur Bäckerei in diesem Viertel.“ Eine Karte gezogen, und das Tagesziel ist gesetzt. Selbst vertraute Gassen, durch die man täglich läuft, werden mit einem Auftrag zu neuen Wegen. Eine Karte, die flüstert: Das Abenteuer liegt nah."},"ICON-0638":{"nm":"Visitenkarten-Halter","de":"Ein Halter für die Visitenkarten der Stammläden. Das leckere Lokal, der freundliche Inhaber – sie sammeln sich Fach für Fach. Sich mit einer Stadt anzufreunden beginnt mit solchen kleinen Zetteln."},"ICON-0639":{"nm":"Strecken-Abzeichen-Tafel","de":"Eine Tafel, auf der nach Abschluss einer ganzen Spazierstrecke ein Abzeichen aufgesteckt wird. Die Befriedigung des Durchhaltens nimmt die Form eines runden Metallstücks an. Das Gefühl des Stolzes, den nur kennt, wer bis zum Ende gegangen ist, ist hier klar sichtbar."},"ICON-0640":{"nm":"Taschenschloss-Schlüsselring","de":"Ein kleines Schloss zugleich Schlüsselring für den Taschenreißverschluss. Es schützt das Wertvolle zuverlässig und baumelt dabei leise am Taschenende. Ein ziemlich cleverer Reisebegleiter, bei dem Sicherheit und Schmuck eins sind."},"ICON-0641":{"nm":"Verlustsicherungs-Tag","de":"Tief verborgen im dunkelsten Winkel der Tasche, blinkt er genau dann, wenn alle aufgegeben haben. „Hier bin ich.“ Das Geräusch, wie etwas, das verloren geglaubt war, wieder in die Hände zurückkehrt. Klein, und doch bleibt er bis zum Schluss beim Besitzer."},"ICON-0642":{"nm":"Reißverschluss-Sicherungsring","de":"Einmal eingehakt, kriegt ihn keine normale Hand auf. Eilige Fingernägel wie auch heimlich heranschleichende Finger werden gleichermaßen abgewiesen. Sicherheit darf manchmal etwas klemmen, sagt dieses schwere kleine Stück."},"ICON-0643":{"nm":"Diebstahlschutz-Alarmschlaufe","de":"Ein unsichtbarer Wächter, der verhindert, dass Ausstellungsstücke das Geschäft verlassen, bevor sie bezahlt sind. Berührt ihn eine ehrliche Hand, schweigt er bis zuletzt. Die Glocke, die nicht läutet, ist die friedlichste Glocke."},"ICON-0644":{"nm":"Kontaktdaten-Abdecketikett","de":"Es legt sich sanft über Namen und Nummer auf dem Paketaufkleber. Wer darin wohnt und wohin es geht, soll nur der Empfänger wissen. Auch das Verdecken ist eine Form von Fürsorge, und dieses Etikett hält still seinen Platz."},"ICON-0645":{"nm":"Reisepasshüllen-Band","de":"Früh am Morgen, wenn Dutzende gleicher Umschläge über das Band laufen. Inmitten all dieser zeigt eine nur mir bekannte Farbe: „Hier entlang.“ Ein kleiner Mantel für den Ausweis auf langer Reise. Selbst wenn der Einband abwetzt, bleibt die Reise hell."},"ICON-0646":{"nm":"Bargeld-Sortiertäschchen","de":"Scheine links, Münzen rechts, Notgroschen im Geheimfach. Die Hand nach dem Marktbesuch greift zuerst hierher. Auch ein unruhiger Tag findet hier seinen Platz – ordentlich, klingelnd, wohlsortiert."},"ICON-0647":{"nm":"Sicherheitssiegel-Aufkleber","de":"Einmal abgezogen, hinterlässt er eine Spur. „Hier wurde geöffnet“ lässt sich nicht verbergen – ein kleines, ehrliches Gewissen. Dass das Paket unversehrt ankam, verdankt sich dem stillen Schweigen dieses kleinen Freundes."},"ICON-0648":{"nm":"Notfallkontakt-Chip","de":"In der Tasche eines verlorenen Kindes, im Laptop-Innenfach, am Hundehalsband. Auch wenn man selbst nicht sprechen kann, liest er laut und deutlich die Nummer vor. In diesem kleinen Chip steckt ganz: „Bitte bring mich nach Hause.“"},"ICON-0649":{"nm":"Selfie-Fernauslöser-Schutzkappe","de":"Auf Gruppenfotos fehlte stets jemand, weil der Arm nicht lang genug war. Jetzt genügt ein Knopfdruck am Ende, um die ganze Familie ins Bild zu bringen. In jenem Augenblick, in dem alle lachen, drücke ich still auf den Auslöser und springe hinein."},"ICON-0650":{"nm":"Objektivtäschchen-Schlaufe","de":"Eine Schlaufe hält das Reserveobjektiv in der Tasche sicher, damit es sich nicht stößt. Ein Glassplitter ist gleichbedeutend mit einer verlorenen Aussicht, also wird sein Gewicht nicht leichtfertig geschwenkt. In jedem Knoten steckt die Sorgfalt des Fotografen."},"ICON-0651":{"nm":"Filteretui-Ring","de":"Ein dünnes Stück verändert denselben Himmel in ein anderes Licht. Ein runder Ring, in dem diese kleinen Wunder ordentlich verwahrt werden. Jedes Mal, wenn man das Etui öffnet, fragt sich die Fingerspitze: Welches Abendrot soll es heute sein?"},"ICON-0652":{"nm":"Stativ-Täschchen","de":"Zusammengeklappt eine Handspanne, aufgestellt drei zuverlässige Beine. Den Freund, der zitternde Hände ersetzt und die Landschaft festhält, rollt man weich hinein. Schweres Gerät verdient es, auf weichem Stoff zu ruhen."},"ICON-0653":{"nm":"Kameragurt-Schulterpolster","de":"Nach einem langen Wandertag kommt der Moment, in dem die Kamera die Schulter drückt. Dann nimmt dieses Polster einen Teil des Gewichts still auf sich. Ein kleiner, weicher Trost für die Schulter, die für eine gute Aufnahme weit gegangen ist."},"ICON-0654":{"nm":"Speicherkarten-Sortierkarte","de":"Eine Nacht, in der man nicht mehr weiß, auf welcher Karte die hunderten Erinnerungen schlummern. Farbige Markierungen zeigen den Weg. Frühjahrsreise in Blau, erste Bühne in Gelb. Ein kleiner, freundlicher Bibliothekar, der auch Erinnerungen in Fächer ordnet."},"ICON-0655":{"nm":"Ladekabel-Aufrollhalter","de":"Bevor das Kabel in der Tasche sein Knotenkunststück vorführt, rollt man es ordentlich zusammen und legt es zur Ruhe. Legt man ein Kabel ordentlich, löst sich irgendwie auch ein innerer Knoten. Im aufgerollten Zustand strahlt es eine wohltuende Ruhe aus."},"ICON-0656":{"nm":"Foto-Backup-Etikett","de":"„Habe ich diese Fotos schon gesichert?“ Ein kleiner Zettel, der die nächtliche Unruhe im Voraus beantwortet. Je wertvoller der Moment, desto wichtiger, dass er an mindestens zwei Orten lebt – das Etikett hält es deutlich fest."},"ICON-0657":{"nm":"Bildkompositions-Rahmenplatte","de":"Schaut man durch das rechteckige Fenster auf die Welt, sieht man sofort, was hineingehört und was wegfallen kann. Ein gutes Foto entsteht nicht durch Hinzufügen, sondern durch gezieltes Weglassen – das lehrt der leere Rahmen als Erstes."},"ICON-0658":{"nm":"Münzgeldbeutel-Anhänger","de":"Baumelt am Taschenende und birgt ein paar Münzen. Vor dem Automaten, vor dem dampfenden Fischkuchen-Stand – als Erstes geöffnet, dieses kleine Schatzkästchen. Das Klimpern ist der Klang kleiner alltäglicher Freuden."},"ICON-0659":{"nm":"Kassenbon-Sammelrölle","de":"Zettel, die man wegwerfen wollte, reihen sich einer nach dem anderen auf. Was man heute gegessen und gekauft hat, ist im Bon ehrlicher vermerkt als in jedem Haushaltsbuch. Sammelt man einen Monat, ergibt sich ein ordentliches Lebensprotokoll."},"ICON-0660":{"nm":"Markttaschen-Anhänger","de":"Hängt am Handgelenk beim Marktbummel und begleitet einen überall. Ein Stück Tofu, ein Bund Frühlingszwiebeln, dazu noch die Herzlichkeit des Händlers. All das Gewicht nimmt er klaglos. Er freut sich mehr beim Füllen als beim Leeren."},"ICON-0661":{"nm":"Souvenir-Magnetplatte","de":"An jedem Reiseziel einen ausgewählt und an den Kühlschrank geheftet – schon wird die Küche zur kleinen Weltkarte. Die besuchten Städte hängen nebeneinander und flüstern: „Komm wieder.“ Selbst eine gewöhnliche Eisenplatte kann Erinnerungen festhalten."},"ICON-0662":{"nm":"Regional-Stempelbuch","de":"Seite für Seite ein Stempel, und die gelaufenen Gassen leben in Tinte wieder auf. Die roten Abdrücke aus dem ganzen Land ergeben eine Karte der eigenen Fußspuren. Je weniger leere Felder, desto mehr winkt die nächste Reise."},"ICON-0663":{"nm":"Geschenkband-Rolle","de":"Eine endlos ausrollende Geduld, die sich entrollt, wenn man ein Geschenkpaket verschnüren will. Nur der, der weiß, wann er abschneiden muss, darf einen sauberen Knoten machen. Aufgerollt wartet sie still auf ihren nächsten Einsatz."},"ICON-0664":{"nm":"Geschenk-Polsterbeutel","de":"Er umhüllt Zerbrechliches weich und fürsorgend. Auch in einem schaukelnden Paketfach sagt er: „Ist gut, ich halte dagegen.“ Er beschützt sogar schon das strahlende Lächeln des Empfängers, wenn die Schachtel geöffnet wird."},"ICON-0665":{"nm":"Preisschild-Abdecksiegel","de":"Ein freundliches kleines Täuschungsmanöver, das den Preis des Geschenks behutsam verdeckt. „Wie viel es kostet, musst du nicht wissen – nur das Herz zählt“, setzt es sich sanft über das Preisschild. Es verbirgt nichts, es lässt das Herz noch mehr leuchten."},"ICON-0666":{"nm":"Mini-Einkaufswagen-Chip","de":"Mag er auch kein echtes Gefährt ziehen – dieser kleine Anhänger trägt die ganze Vorfreude eines Supermarktausflugs. Auch wenn er winzig ist, steckt die Aufregung des „Was kaufe ich heute?“ genauso schwer drin wie das Original."},"ICON-0667":{"nm":"Leuchtender Schuh-Clip","de":"Am Ende des Sportschuhs beim Nachtspaziergang blinkt er und sendet vorbeifahrenden Autos das Signal: „Hier ist ein Mensch.“ Das erste Licht, das in einer dunklen Gasse entgegenkommt. Sicherheit beginnt leise von den Füßen aus."},"ICON-0668":{"nm":"Mini-Taschenlampen-Aufsatz","de":"Aufgesetzt auf die Taschenlampe, strahlt das Licht weiter und sanfter. Ein kleiner Zauberer, der an die Zeltdecke ein Sternbild zeichnet. In Nächten, in denen einem die Dunkelheit etwas unheimlich ist, gibt es keinen besseren Freund."},"ICON-0669":{"nm":"Heimkehr-Signalknopf","de":"Einmal drücken, und „Bin sicher angekommen“ fliegt zu einer fernen Familie. Statt des Klingelns der Eingangstür spät nachts gibt dieser kleine Knopf Nachricht. Jemand wartet auf dieses Signal und schläft dann ein."},"ICON-0670":{"nm":"Reflexstreifen-Rolle","de":"Ein Stück abschneiden, an Tasche, Fahrrad oder Regenschirm kleben – schon ist der Nachtweg sicherer. Ein Schläfer, der erst im Scheinwerferlicht aufwacht und hell leuchtet. Aufgerollt wartet er auf die nächste Dunkelheit."},"ICON-0671":{"nm":"Notfall-Taxikarte","de":"In ein Kartenfach gesteckt, ist selbst eine leere Haltestelle spät nachts weniger beängstigend. Eine Nummer, eine Zeile Adresse – wie ein Versprechen: „Ich bring dich nach Hause.“ Dass das Wort „Notfall“ so beruhigen kann."},"ICON-0672":{"nm":"Nachtweg-Kartenband","de":"Man bindet es ums Handgelenk und geht durch Straßen mit spärlicher Beleuchtung. Es verrät, wo Laternen stehen und wo es dunkel ist – Abkürzungen, die nur die Nacht kennt. Ein Band, das einen auch im Dunkeln nicht die Richtung verlieren lässt."},"ICON-0673":{"nm":"Sicherheitsalarm-Täschchen","de":"Im Notfall zieht man daran, und die ganze Gasse erschrickt laut auf. Sonst liegt er still im Täschchen und spart seine Stimme für den einen entscheidenden Moment. Der lauteste Schrei, der in der kleinsten Tasche steckt."},"ICON-0674":{"nm":"Türbeleuchtungs-Schlüsselring","de":"Vorbei die Nächte, in denen man in einem dunklen Flur tappend das Schlüsselloch suchte. Er hängt an der Tür und empfängt die heimkehrende Hand mit einem runden Lichtkreis. „Du hast es geschafft, du bist angekommen“ – der Schlüsselring grüßt als Erster."},"ICON-0675":{"nm":"Unterkunft-Rückkehr-Notiz","de":"„Schirm einpacken, Licht aus beim Rausgehen.“ Ein kurzer Hinweis am Kühlschrank wacht über die leere Unterkunft. Ein kleiner Zettel für den, der zurückkommt. Die Wärme, die auf einem Blatt Papier Platz findet, begleitet einen bis zur Haustür."},"ICON-0676":{"nm":"Kabelordnungs-Kamm","de":"Verworrene Kabel werden sanft wie Haare durchgekämmt und ordentlich gerichtet. Das Kabeldschungel hinter dem Schreibtisch wird nach wenigen Kämmzügen ordentlich. Nicht nur Haare verfilzen, sagt der Kamm leise."},"ICON-0677":{"nm":"Stiftehalter-Trennsteg","de":"Bleistifte hierhin, Marker dorthin, Schere ins letzte Fach. Innerhalb eines Bechers entsteht ein kleines Dorf, das jedem Stift seinen Platz zuweist. Hat jeder seinen Platz, tastet auch die Hand nicht mehr umher. Der Beginn kleiner Ordnung auf dem Schreibtisch."},"ICON-0678":{"nm":"Monitor-Memoklammer","de":"An der Seite des Monitors hängend, hält sie „die heutigen Aufgaben“ genau auf Augenhöhe. Ein kleines Notizbrett, an dem man nicht vorbeikommt. Eine einzige Klammer hält die Hand zurück, die sich immer wieder drückt."},"ICON-0679":{"nm":"Schubladen-Sortiertablett","de":"Büroklammern und Gummibänder, Reißnägel und Radiergummis. Kleine Bewohner der Schublade bekommen je ein eigenes Zimmer. Findet die Hand einen geordneten Platz, hat man weniger Suchzeit und ein leichteres Gefühl."},"ICON-0680":{"nm":"Staubbürsten-Behälter","de":"Ein einziges Staubkorn auf der Linse wird im Foto zu einem riesigen Fleck. Deshalb wartet die Bürste im Behälter stets sauber und bereit. Fleißige Fingerspitzen, die unsichtbare Reinheit bewahren."},"ICON-0681":{"nm":"Schreibtischmatte-Eckpad","de":"Eine Handspanne Weichheit in einer Ecke des Schreibtisches. Der Stift rollt nicht herunter, und statt kaltem Glas stützt warmes Material das Handgelenk. Damit die Schrift in langen Nächten nicht zittert, bietet diese freundliche Unterlage als Erstes Platz an."},"ICON-0682":{"nm":"Mauskabel-Halter","de":"Geraten Kabel durcheinander, verknäult sich irgendwie auch die Gedanken. Ein Halter greift rechtzeitig nach dem einen Strang und legt ihn ordentlich hin. Kaum sichtbar, und doch hält er den Ton des Schreibtisches still in Ordnung."},"ICON-0683":{"nm":"Ladestation-Standfuß","de":"Das liegende Gerät leicht aufgestellt, und der Bildschirm trifft endlich den Blick. Die Wartezeit beim Laden wird dadurch ordentlich. Etwas zu stützen bedeutet auch, dem Ruhenden eine Haltung zu schenken."},"ICON-0684":{"nm":"Mini-Papierkorb-Etikett","de":"Selbst dem kleinsten Behälter wird ein Name gegeben. „Hier bitte entsorgen“ bringt mit einem Satz stille Ordnung auf einen unruhigen Schreibtisch. Ein Etikett ist im Grunde ein freundlicher Hinweis an ein Ding: Dein Platz ist hier."},"ICON-0685":{"nm":"Pinnwand-Stift","de":"Einmal in die Pinnwand gedrückt, hält er ein Blatt fest. Dem Herzen liegende Dinge werden kurz der Wand anvertraut. Die heutige Absicht, die am Stift baumelt, schaukelt sacht im Luftzug und hält einen beim Vorbeigehen fest."},"ICON-0686":{"nm":"Etikett-Rahmen-Chip","de":"Ein kleiner rechteckiger Rahmen verwandelt gewöhnliche Buchstaben in einen klaren Satz. Ein Chip, der flüchtigen Notizen ein ordentliches Format gibt. Es ist kein Einengen – es ist ein fürsorgliches Umhüllen wichtiger Worte."},"ICON-0687":{"nm":"Durchsichtiger Schubladengriff","de":"Hat man einen Griff an der durchsichtigen Schublade, sieht man zwar den Inhalt, öffnet sie aber nicht mehr so leichtfertig. Eine Handspanne Distanz – sehen, ohne zu greifen. Auch Transparenz braucht Anstand, flüstert die Schublade."},"ICON-0688":{"nm":"Deckel-Verschlussklemme","de":"Offen gelassen, entweichen Duft und Farbe still. Eine kleine Klemme hält den Deckel fest verschlossen, sodass das Gestrige bis morgen unversehrt bleibt. Zu verschließen bedeutet im Grunde, das Wertvolle zu bewahren."},"ICON-0689":{"nm":"Feuchtigkeitsschutz-Halter","de":"Ein kleiner Wächter, der Feuchtigkeit verabscheut und still seinen Posten hält. Dieser ordentliche Halter erinnert leise daran, dass Trockenheit die erste Bedingung langer Lagerung ist. So bleibt das Trockene trocken."},"ICON-0690":{"nm":"Ordnungskorb-Anhänger","de":"An jedem Korb ein kleines Namensschild. Weiß man, was in welchem Fach wohnt, wird aus Suchzeit Ruhezeit. Ordnung ist ein freundlicher Zettel, den man sich selbst für die Zukunft hinterlässt."},"ICON-0691":{"nm":"Mini-Trennwand","de":"Eine kleine Zwischenwand, die auf dem Schreibtisch im Nu ein eigenes Zimmer aufbaut. Mit dieser einen Platte entsteht eine stille Ecke, ein kleiner Rückzug von der Welt. Ein gemütliches Plätzchen ganz für sich allein."},"ICON-0692":{"nm":"Aufbewahrungsbeutel-Ständer","de":"Ein Ständer, der die immer umfallenden Tüten sanft aufrichtet. Schon das bloße Stehenlassen macht das Herausgreifen viel leichter. Aufrecht aufzustellen bedeutet, an den nächsten zugreifenden Moment zu denken."},"ICON-0693":{"nm":"Leerfeld-Markierchip","de":"Ein Chip, der bewusst auf ein leeres Feld hinweist. Einen Platz freizuhalten ist ebenfalls ein echter Plan. Ein Leerfeld ist keine Faulheit – es ist ein höflich reservierter Freiraum für das, was noch kommen wird."},"ICON-0694":{"nm":"Zahnbürsten-Schutzkappe","de":"Was den Mund berührt, verdient besondere Sorgfalt. Eine kleine Kappe, die nicht einmal Staubteilchen durchlässt. Für unsichtbare Sauberkeit zu sorgen ist die bescheidene Mühe, jeden Morgen frisch zu beginnen."},"ICON-0695":{"nm":"Seifenablage-Gitter","de":"Ein Gitternetz, das die Seife leicht schwebt und verhindert, dass sie im Wasser aufweicht. Wasser ablaufen zu lassen verlängert die Haltbarkeit – dieses Prinzip wird täglich still bewiesen, am niedrigsten und kleinsten Platz im Badezimmer."},"ICON-0696":{"nm":"Shampoo-Pumpen-Clip","de":"Er hält den Pumpkopf fest, sodass beim einmaligen Drücken genau die richtige Menge fließt. Maßvolles Verbrauchen ist das Fundament eines nachhaltigen Haushalts. Ein kleiner Clip, der sanft gegen Verschwendung ankämpft."},"ICON-0697":{"nm":"Rasierer-Aufhängekappe","de":"Für scharfe Dinge richtet man ein eigenes kleines Haus ein. Die Rasierklingenkappe aufgesteckt und aufgehängt, fließen Nässe und Gefahr gemeinsam ab. Den Umgang mit Schärfe sorgfältig zu üben bedeutet auch, sich selbst zu schätzen."},"ICON-0698":{"nm":"Duschhandtuch-Ring","de":"Das lang herabhängende Handtuch bildet eine Schlaufe und erreicht damit auch den sonst unerreichbaren Rücken. Entlang des schäumenden Striches breitet sich die warme Zärtlichkeit, den eigenen Rücken waschen zu können, wohlig durch das ganze Bad aus."},"ICON-0699":{"nm":"Abflusssieb-Beutelpack","de":"Wasser lässt es durch, Rückstände hält es zurück – ein kleines Netz. Es arbeitet unsichtbar und verhindert still Verstopfungen. Was an den niedrigsten Stellen wirkt, hält den Fluss des Hauses am Laufen, sagt der Abfluss wortlos."},"ICON-0700":{"nm":"Saugnapf-Hakenplatte","de":"Ohne einen einzigen Nagel entsteht ein neuer Platz an der Wand. Drücken, befestigen, ablösen – kein Abdruck bleibt. Die Kunst, vorübergehend zu bleiben ohne Spuren zu hinterlassen – das beherrscht die Saugnapfplatte mit leiser Würde."},"ICON-0701":{"nm":"Badezimmer-Hausschuh-Anhänger","de":"Ein ordentlich aufgestelltes Paar vor der Türschwelle. Die Sorgfalt des Hauses, in dem man die Schuhe auszieht, reicht bis vor die Badezimmertür. Der Anhänger bestimmt still diesen Platz und empfängt kalte Fußspitzen herzlich."},"ICON-0702":{"nm":"Mini-Zahnputzbecher","de":"Ein kleiner runder Becher für einen Schluck zum Ausspülen. Das kurze Ritual des Mundspülens nimmt still Anfang und Ende des Tages entgegen. Auch das Unscheinbare, das täglich da ist, ist solides Haushaltsgut."},"ICON-0703":{"nm":"Staubwedel-Schutzhülle","de":"Eine Hülle für den Federwedel, der Staub sanft wie streichelnd aufnimmt. Wie ein Vogel, der seine Schwingen ordentlich faltet, wenn er ruht – ein Gerät, das seinen Ruheplatz kennt, hält sich lange im Einsatz."},"ICON-0704":{"nm":"Fusselroller-Nachfüllpack","de":"Eine Schicht abgezogen, und darunter kommt eine frische, weiche Oberfläche zum Vorschein. Schichten voller Klebekraft, die Flusen und Haare aufsammeln. Im runden Nachfüllpack, das sich stets wieder auffüllen lässt, steckt die Tugend fleißiger Wiederholung."},"ICON-0705":{"nm":"Wischlappen-Klemme","de":"Die Klemme packt den Wischlappen anstelle der Hände fest. Sie hält einen Handspannen-Abstand zwischen kaltem Boden und Fingerspitzen. Ein Griff, der unangenehme Arbeit stellvertretend übernimmt und das lästige Putzen ein Stück leichter macht."},"ICON-0706":{"nm":"Spaltenbürsten-Schutzkappe","de":"Eine kleine Kappe schützt die zarte Spitze der Schmalbürste, die sich in enge Ritzen zwängt. Die Sorgfalt, auch schwer erreichbare Ecken zu reinigen. Wer das Unsichtbare putzt, vergrößert den Komfort des Hauses um eine Handspanne."},"ICON-0707":{"nm":"Sprühflaschen-Etikettring","de":"Ein kleines Namensschild am Hals der Sprühflasche. Ein einziger Satz verrät klar, ob klares Wasser oder Reinigungsmittel drin ist. Verwirrungen im Voraus auszuräumen ist die alte Gewohnheit eines flinken Haushaltsführers."},"ICON-0708":{"nm":"Toilettenpapier-Nachfüllband","de":"Ein Band, das eine neue Rolle an die leere Stelle befestigt und fest verschnürt. Die einfachste Geste, etwas Unterbrochenes wieder zu verbinden. Die Fürsorge jemandes, der auffüllt, bevor es leer ist, ist in diesem kleinen Ring rund eingewickelt."},"ICON-0709":{"nm":"Reinigungshandschuh-Aufhängehaken","de":"Ein Haken, an dem feuchte Gummihandschuhe nach getaner Arbeit zum Trocknen hängen. Den müden Händen ein kurzes Ausruhen gönnen. Während die Nässe langsam trocknet, eine kurze Verschnaufpause für den nächsten Einsatz."},"ICON-0710":{"nm":"Besen-Aufhängestift","de":"Den Besen umgekehrt aufgehängt, bleibt die Bürste gerade und krümmt sich nicht. Aufrecht hängend, wartet er auf den nächsten Einsatz im Hof. Ein kleiner, aber zuverlässiger Platz, der auch nach getaner Arbeit die eigene Form bewahrt."},"ICON-0711":{"nm":"Müllbeutel-Verschlussklemme","de":"Sie klemmt den Beutelmund fest zu, sodass nichts entweicht und alles sauber verschlossen bleibt. Ein einmaliges, festes Zudrücken, und der Abschluss ist sauber erledigt. Aufräumen beginnt letztlich mit dem richtigen Schließen."},"ICON-0712":{"nm":"Wäscheklammern-Behälter","de":"Ein Behälter, in dem leicht verlorene Wäscheklammern gemeinsam wohnen. Den kleinen Dingen ein gemeinsames Zuhause geben. Sind alle an einem Ort, findet man sie auf Anhieb."},"ICON-0713":{"nm":"Socken-Sortierring","de":"Socken ohne Pärchen verschwinden immer irgendwohin. Jeweils zu zweit mit einem Ring zusammengebunden, bleiben sie auch nach dem Trocknen beisammen. Sortieren ist ein kleines Versprechen gegen das Verschwinden."},"ICON-0714":{"nm":"Waschbeutel-Kugeltasche","de":"Sie rollt klappernd durch die Waschmaschine und klopft eingewachsenen Schmutz aus der Wäsche. Ein Rhythmus, mit dem sie die Wäsche sanft bearbeitet. Inmitten des Wasserstroms trägt ein Täschchen das uralte Instinkt des Waschens – das Klopfen – weiter."},"ICON-0715":{"nm":"Wollwaschmittel-Messkappe","de":"Für empfindliche Kleidung genau die empfindliche Menge. Eine Messkappe, die Wollwaschmittel auf genau einen Deckel abmisst. In einer kleinen Markierung steckt die behutsame Hand im Umgang mit Wolle. Auch Zurückhalten ist Sorgfalt."},"ICON-0716":{"nm":"Stoff-Schutzflicken","de":"Ein kleines Flickenstück, das sanft auf die abgewetzte Stelle aufgenäht wird. Eine Fingerspitze, die Getragenes nicht wegwirft, sondern liebevoll pflegt. An jeder gestopften Stelle bleibt die Textur der gemeinsam verbrachten Jahre schön erhalten."},"ICON-0717":{"nm":"Wäscheständer-Fixierstift","de":"Ein Stift, der verhindert, dass Wäsche bei Wind vom Ständer fliegt. Auch wenn die Wäsche im Sonnenschein schwankt, hilft er, die Position zu halten. Kleines, aber verlässliches Gegengewicht."},"ICON-0718":{"nm":"Unterwäsche-Wäschenetz-Anhänger","de":"Empfindliche Unterwäsche wird getrennt im Netz gewaschen. Das Netz schützt zartes Gut sicher vor starkem Wasserdruck. Ein kleines Beutelchen mit Namensanhänger zeigt, dass auch das Schützen von Empfindlichem Haushalt bedeutet."},"ICON-0719":{"nm":"Waschmittel-Löffelhalter","de":"Den Löffel zum Abmessen von Pulverwaschmittel ordentlich an der Wand aufgehängt. Keine Mühe mehr, die Hand zu beschmutzen, wenn man ihn in der Dose versenkt. Die ordentliche Gewohnheit, Gerät stets am selben Ort zu lassen, steckt in diesem kleinen Halter."},"ICON-0720":{"nm":"Wäschelinien-Stopper","de":"Er beißt sich am Wäscheleinen-Ende fest, sodass auch bei schwerer Beladung nichts herausgleitet. Der letzte Knoten, der verhindert, dass die straffe Linie nachgibt. An ihm hängt das ordentliche Finish."},"ICON-0721":{"nm":"Kissenbezug-Etikett","de":"An der Innenseite des Bezugs, der als erstes die Wange berührt, eingenäht – ein kleines Etikett. Wer liest schon die winzige Schrift mit der Waschtemperatur? Und doch ist es der nächste kleine Wegweiser an der Seite des schlafenden Gesichts."},"ICON-0722":{"nm":"Bettdecken-Klemme","de":"Steht das Fenster offen, kommt der Wind herein – aber die Decke geht nirgendwo hin. Denn die Klemme hält die Ecke fest umschlossen. Eine stille Hand, die den Zipfel festhält, während jemand schläft."},"ICON-0723":{"nm":"Schlaflampen-Abschirmplatte","de":"„Wenn Licht die Augen trifft, entflieht der Schlaf.“ Eine von jemandem leise aufgestellte Abschirmplatte lässt das Licht zurückweichen und erhellt nur sacht den Fußbereich. Eine kleine Trennwand, die ein bisschen Dunkelheit leiht."},"ICON-0724":{"nm":"Bettspalten-Tasche","de":"Der Spalt zwischen Matratze und Wand – eine Hand kommt nicht hin. Fernbedienung und Brille, die früher hineinfielen, landen jetzt hier. Eine Tasche, die das Bett still entfaltet, um fast Verlorenes aufzufangen."},"ICON-0725":{"nm":"Brillen-Ablage-Tablett","de":"Nimmt man die Linsen heraus, verschwimmt die Welt weich – diesen kurzen Moment der Schutzlosigkeit fängt ein flaches Schälchen auf. Am Morgen wartet die Brille stets an derselben Stelle, ohne dass man danach tasten muss."},"ICON-0726":{"nm":"Wecker-Standfuß","de":"Auf dem festen Sockel, von dem um sechs Uhr früh der verhassteste Klang ertönt. Er stützt die Uhr, ohne zu wanken, und läutet schließlich jemandes Tag ein. Er trägt still das starre Versprechen des Erwachens."},"ICON-0727":{"nm":"Kopfkissen-Kabelhalter","de":"Das Ladekabel, das früher am Kopfkissen hinunterglitt, fällt nicht mehr auf den Boden. Der kleine Halter hält das Kabelende sanft fest. Handreichweite Nähe – die Nacht ordentlich arrangiert."},"ICON-0728":{"nm":"Schlafanzug-Aufrollband","de":"Ein Band, das um den ordentlich gefalteten Schlafanzug gewickelt wird. Auch Weichem, das leicht zerknittert, gebührt ein gepflegtes Äußeres. Eine kleine Vorbereitung, die das heutige Ich für das Ich von morgen Nacht macht."},"ICON-0729":{"nm":"Duftkartenhalter","de":"Eine Duftkarte schräg aufgestellt, und man blättert beim Drüberstreichen der Nase durch die Jahreszeiten. Von Lavendel zu Citrus – ein Tagebuch, das in Düften den Tag festhält."},"ICON-0730":{"nm":"Schlüsselschalen-Pad","de":"Eine Ecke im Eingangsbereich, wo Schlüssel früher klirrend fielen. Ein weiches Pad im Schälchen schluckt diesen scharfen Klang. Die erste Bewegung des Heimgekehrten wird still von einem kleinen Untersetzer aufgefangen."},"ICON-0731":{"nm":"Regenschirm-Tropfenkappe","de":"Am mitgebrachten Regenschirm tropft Regenwasser herunter. Eine Kappe fängt diese Tropfen zuverlässig auf – kein kleines Pfützchen schleicht sich mehr auf den Holzboden. Als hätte jemand im Voraus daran gedacht."},"ICON-0732":{"nm":"Maskenhalter-Chip","de":"Ein kleiner Chip an der Wand neben dem Eingang. Wie ein letztes Ritual vor dem Ausgehen hängt hier die Maske. Ein kleines Gedächtnishilfe, das auf Augenhöhe vor der Tür wartet, damit man nichts vergisst."},"ICON-0733":{"nm":"Paketmesser-Schutzabdeckung","de":"Eine Schutzabdeckung für die Klinge, die Pakete öffnet. Die verborgene Gefahr des Schneidens hinter der Vorfreude wird sanft abgedeckt. Eine unsichtbare Rücksicht, die das Ende des Wartens sicher aufschließt."},"ICON-0734":{"nm":"Schuhbürsten-Untersetzer","de":"Der Platz, auf dem die Schuhbürste nach dem Bürsten abgelegt wird, noch feucht. Selbst wenn sie Nässe aufnimmt, bleibt der Boden darunter trocken. Auch das Werkzeug, das Sauberkeit schafft, braucht einen Platz zum Ausruhen."},"ICON-0735":{"nm":"Besucher-Notiztafel","de":"„Bin kurz vorbeigekommen.“ Eine kurze Zeile auf der Eingangstafel. Ein kleiner Platz, an dem sich Leute, die sich verpasst haben, über Zeiten hinweg begegnen. Auf einem Blatt stapeln sich Grüße, Bitten und ein Herzchen."},"ICON-0736":{"nm":"Türspalt-Abdichtrolle","de":"Durch den fingerlangen Spalt unter der Tür drückte sich früher Zugluft herein. Die aufgerollte Dichtung stellt sich leise in den Weg. Die Wärme, die unbemerkt entwich, wird so eine Schicht mehr im Zimmer gehalten."},"ICON-0737":{"nm":"Türstopper-Anhänger","de":"Ein kleiner Anhänger, der den Fuß der weit geöffneten Tür stützt, damit sie nicht wieder zugeht. Er hält schwer seinen Platz für vorbeiziehenden Wind und Schritte. Ein freundliches, hartnäckiges Stückchen, das Offenhalten aufrechterhält."},"ICON-0738":{"nm":"Eingang-Lichtschalter-Abdeckung","de":"Der Eingangsschalter, den man spät nachts tippend suchte. Die Leuchtabdeckung zeigt im Dunkeln sanft ihren Ort an. Damit die Hand nicht irrt – sie leuchtet, bevor das Licht angeht."},"ICON-0739":{"nm":"Tassenhalter-Unterlagspad","de":"Der Moment, in dem ein auf den Tisch gestellter Becher wegrutscht – das Pad hält ihn sanft fest. Selbst wenn Tropfen sich bilden, bleibt keine einzige Spur. Ein ruhiger Untersetzer, der still seinen Platz hält."},"ICON-0740":{"nm":"Auto-Duftclip","de":"Ein kleiner Duftclip, der im Auto hängt. Der sanfte Duft breitet sich getragen vom Lüftungswind langsam im engen Raum aus. Selbst die Langeweile beim Warten an der Ampel wird vom Duft ein wenig erwärmt – ein freundlicher Trost am Fahrersitz."},"ICON-0741":{"nm":"Sicherheitsgurt-Abdeckung","de":"Eine weiche Abdeckung für den Gurt, der quer über die Schulter läuft. Das kratzig-raue Gefühl am Nacken verschwindet sanft. Auch einem Sicherheitsgurt kann man etwas Sanftmut hinzufügen, sagt ein Handspannen Stoff."},"ICON-0742":{"nm":"Parkplatznummern-Abdeckplatte","de":"Eine Platte, die im Untergrundparkhaus die eigene Nummernschildnummer kurz verdeckt, bevor man ein Foto macht. Jeder hat Informationen, die er nicht hinterlassen möchte. Eine Schicht, die in einem Alltagsmoment behutsam ausgeblendet wird."},"ICON-0743":{"nm":"Fahrradklingel-Schutzkappe","de":"Klingeling. Der helle Gruß, den ein Fahrrad an der Gassenkurve entsendet. Die Kappe auf der Klingel schützt diesen Klang vor Regenwasser. Beim Klang eines kleinen Glöckchens lächeln Menschen und treten einen Schritt zur Seite."},"ICON-0744":{"nm":"Lenker-Griffring","de":"Ein Ring, der die Griffigkeit des Lenkers weich ummantelt. Auch nach längerem Fahren tauben die Hände nicht. Je weiter der Weg, desto mehr verringert die Bequemlichkeit des Greifpunktes die zurückgelegte Strecke."},"ICON-0745":{"nm":"Helm-Namensaufkleber","de":"Ein Namensaufkleber auf der Innenseite des Helms. Inmitten gleich aussehender Schutzhelme ruft er leise: „Das ist meins.“ Die persönlichste Markierung, eingeschrieben in die Festigkeit, die den Kopf schützt."},"ICON-0746":{"nm":"Rad-Reflexionskappe","de":"Erst wenn die Sonne untergeht, beginnt die Kappe ihren Dienst. Sie nimmt vorbeifahrendes Licht auf und spiegelt das Rad deutlich zurück. Im Dunkeln ein kleines Lichtsignal: „Hier ist ein Mensch.“"},"ICON-0747":{"nm":"Autoschlüssel-Schutztäschchen","de":"Der Autoschlüssel, der früher in der Tasche an anderen Schlüsseln schabte und Kratzer bekam. Ein weiches Täschchen umhüllt ihn nun. Je häufiger man etwas in die Hand nimmt, desto mehr wünscht man sich, es bleibe makellos – dieses Gefühl steckt darin."},"ICON-0748":{"nm":"Saugnapfregal-Stift","de":"Ein Saugnapfregal, das sich einfach an die Wand klickt, ohne einen Nagel. Auch an Wänden, an denen man keine Spuren hinterlassen möchte, entsteht ein Regalplatz. Das Handwerk, in einem geliehenen Raum Einrichtung aufzuhängen, ohne Spuren."},"ICON-0749":{"nm":"Bohrlochfreie Hakenplatte","de":"Ohne in die Wand zu bohren, kann man trotzdem etwas aufhängen. Die bohrlochfreie Hakenplatte übernimmt leichtes Gepäck. Die Rücksicht, einen geborgten Raum unversehrt zu lassen, steckt in diesem kleinen Haken."},"ICON-0750":{"nm":"Magnet-Ordnungsleiste","de":"Metallteile klacken an ihren Platz. Zieht man mit dem Magneten kleine verstreute Werkzeuge zusammen, wird die vorhin chaotische Werkbank in einer Reihe ordentlich – ein kleines Erfolgserlebnis folgt auf dem Fuße."},"ICON-0751":{"nm":"Spaltenstab für Lücken","de":"Stell dir den schmalen Spalt zwischen Kühlschrank und Wand vor, der jahrelang leer blieb. Ein schlanker Stab füllt ihn mit nützlichem Stauraum. Ein kluger Einfall, der aus nutzlosem Raum praktische Ordnung macht."},"ICON-0752":{"nm":"Haftpad-Folie","de":"Einmal aufgeklebt, hält diese Klebstofffolie sogar schwere Gegenstände mühelos an Ort und Stelle. Wenn man sie ablöst, bleibt überraschend keine Spur zurück. Eine stille, zähe Kraft, die im Verborgenen trägt."},"ICON-0753":{"nm":"Türhaken-Kappe","de":"Einfach über die Tür hängen – fertig ist der Haken für Taschen und Handtücher in griffbereiter Höhe. Ohne einen einzigen Nagel entsteht ein neuer Aufhängeplatz, der dem kleinen Zimmer ein weiteres Stückchen Luft gibt."},"ICON-0754":{"nm":"Kabel-Wandclip","de":"Ein Clip, der die an der Wand herabhängenden Kabel in einer ordentlichen Linie hält. Das wirre Kabeldurcheinander hinter dem Schreibtisch verwandelt sich in eine saubere Führung. Unsichtbare Ordnung, die sogar die Luft im Raum leichter wirken lässt."},"ICON-0755":{"nm":"Stativlampen-Unterlagspad","de":"Ein Pad, das sanft unter den Fuß einer Stehleuchte gelegt wird. Es hinterlässt keine Kratzer auf dem Schreibtisch und dämpft selbst feinste Vibrationen. Bevor man Licht aufstellt, braucht es zuerst einen sicheren, ruhigen Boden."},"ICON-0756":{"nm":"Rutschfeste Haftmatte","de":"Die Matte, die sich bisher immer weggeschoben hat, bleibt endlich an ihrem Platz – dank der Haftseite, die den Boden fest packt. Ein unsichtbares Sicherheitsnetz, das einen Sturz verhindert, bevor er passiert."},"ICON-0757":{"nm":"Präzisionsschraubendreher-Kappe","de":"„Diese winzige Schraube dreht sich einfach nicht raus.“ Die Kappe auf dem Präzisionsschraubendreher schützt die Klinge. Das feinfühligste Werkzeug der Hand, das die kleine Welt im Inneren einer Maschine öffnet."},"ICON-0758":{"nm":"Inbusschlüssel-Ring","de":"Ein Ring, der mehrere Inbusschlüssel auf einem Bund vereint. Die nach Größe sortierten Metallschlüssel lassen sich wie ein Fächer ausklappen. Ein geordneter Handgriff, der den richtigen Schlüssel auf Anhieb findet."},"ICON-0759":{"nm":"Mini-Maßband-Clip","de":"An einem kleinen Maßband, das in die Handfläche passt, hängt ein praktischer Clip. Er befestigt sich am Schlüsselbund und ist immer dabei. Ein kleiner Begleiter, der eine spontane Längenfrage direkt vor Ort beantwortet."},"ICON-0760":{"nm":"Schrauben-Sortierdose","de":"Eine Sortierdose, in der jede Schraube ihren eigenen Platz findet. Auch das kleine Durcheinander rollendes Kleinkrams bekommt endlich Ordnung. Wer etwas reparieren will, lernt dabei zuerst das Sortieren."},"ICON-0761":{"nm":"Klebstoff-Düsenkappe","de":"Geschlossen trocknet er nicht aus, offen dagegen schon – ich lebe genau dazwischen. Bei jedem einzelnen Tropfen wird irgendwo ein Bruch wieder zusammengefügt. Ein kleiner Deckel, der still die Grenze zwischen Pause und Fluss bewacht."},"ICON-0762":{"nm":"Wasserwaage-Schlüsselanhänger","de":"Eine taschengroße Ehrlichkeit, die am Schlüsselbund baumelt. Die kleine Luftblase ist immer die Erste, die ein schiefes Regal bemerkt. Ein Freund, der einen leise darauf hinweist, wenn die Welt ein klein wenig schief geraten ist."},"ICON-0763":{"nm":"Pinzetten-Schutzkappe","de":"Je spitzer etwas ist, desto mehr braucht es eine schützende Hülle. Die Spitze sanft abgedeckt – schon verletzt sich weder die Hand noch das Bauteil. Die erste Höflichkeit im Umgang mit Scharfem ist es, die Spitze einfach abzudecken."},"ICON-0764":{"nm":"Kleine Schneidmatte","de":"Eine Matte, deren Schnittstellen sich nach Tausenden von Klingendurchgängen von selbst schließen. Wo einmal geschnitten wurde, wird wieder geschnitten – und die Wunde heilt erneut. Ein stiller Alltagsheld, der sich selbst opfert, damit andere sauber schneiden können."},"ICON-0765":{"nm":"Reparaturteil-Tütchen","de":"Ein Tütchen, das seinen Mund verschließt, damit kein einzige Schraube und keine Feder für immer verloren geht. Was nach der Reparatur übrig bleibt, wartet hier geduldig auf seinen nächsten Einsatz. Das Vergessen zu verhindern – das schaffen immer solche kleinen Fächer."},"ICON-0766":{"nm":"Chipstüten-Clip","de":"Das Knusprige einer geöffneten Tüte bleibt frisch dank einem einzigen entschlossenen Griff. Ein kleines Versprechen, der Weichheit keine Chance zu lassen. Die Gewohnheit, das Ende fest zuzuklappen, rettet den Snack von morgen."},"ICON-0767":{"nm":"Geleeportion-Becher","de":"Wer eine Tüte mit mehreren teilen will, muss zunächst gerecht aufteilen. In jeden kleinen Becher kommt der gleiche Anteil – mit Bedacht abgemessen. Teilen beginnt damit, dass niemand zu kurz kommt."},"ICON-0768":{"nm":"Schokoladen-Silberfolie","de":"Das silbrige Papier, das einmal Süßes umhüllte, knittern die Finger mühelos zusammen. Glattgestrichen schimmert es kurz, gefaltet wird es zur Erinnerung. Ein Stückchen Glanz, das erst nach dem letzten Biss am schönsten ist – schau noch einmal hin, bevor du es wegwirfst."},"ICON-0769":{"nm":"Snack-Etikettenband","de":"Was drin ist, bis wann es gut ist – ich spreche, wo die stumme Tüte schweigt. Sobald ein Streifen draufklebt, bekommt der Snack einen Namen und ein Versprechen. Ordnung ist eigentlich die freundlichste Art, sich etwas zu merken."},"ICON-0770":{"nm":"Bonbon-Sortierdose","de":"Das Saure und das Süße kommen nicht in dasselbe Fach. Vorher sortieren, damit die Hand nicht zögert. Wenn kleine Dosen aufgereiht stehen, verdoppelt sich die Freude am Aussuchen ganz von allein."},"ICON-0771":{"nm":"Keks-Polsterpapier","de":"Dünnes Papier, das zwischen die Kekse gelegt wird, damit sie auf dem Weg keine Beulen bekommen. Je zerbrechlicher etwas ist, desto sanfter muss es begleitet werden. Manchmal schützt Weichheit besser als Härte."},"ICON-0772":{"nm":"Donut-Schachtelband","de":"Ein einziger Kreuzknoten trägt die Verantwortung dafür, dass der Kuchen in der Schachtel heil ankommt. Es wird zum Griff, zur Versiegelung und zum Zeichen freudiger Erwartung. Der Moment, in dem dieses Band gelöst wird, ist jemandes Geburtstag."},"ICON-0773":{"nm":"Brotbeutel-Klammer","de":"Einmal umgedreht und festgeklemmt – und die Weichheit des Brots bleibt bis zum nächsten Morgen eingeschlossen. Ein kleines, beharrliches Stück, das Luft fernhält. Weiches lange frisch zu halten, ist stets die Aufgabe von etwas Festem."},"ICON-0774":{"nm":"Snack-Tauschanhänger","de":"Dein Teil zu mir, mein Teil zu dir. Erinnerst du dich an die Aufregung, als du Snacks tauschtest und auf dem kleinen Anhänger den Namen einer Freundin lasest? Auf einem Zettel fürs Teilen steht immer ein vertrauter Name."},"ICON-0775":{"nm":"Trinkhalm-Verschlusskappe","de":"Wenn man eine Pause macht, klappt man mich zu. Damit nichts ausläuft, nichts kalt wird, damit man in Ruhe warten kann. Den Eingang zu bewachen, bis der nächste Schluck kommt – das ist meine stille Aufgabe."},"ICON-0776":{"nm":"Trinkflasche-Namensring","de":"Ein kleiner Ring, der unter vielen nebeneinander stehenden Thermoflaschen flüstert: „Diese hier gehört mir.“ Eine einzige Farbe löst alle Verwechslungen auf. Für die Markierung des Eigenen reicht dieser eine Ring vollkommen."},"ICON-0777":{"nm":"Becherhülse","de":"Eine Lage Wellpappe, die sich sanft zwischen den heißen Becher und die Handfläche schiebt. Damit man sich nicht verbrennt und der Becher nicht wegrutscht. Einen sicheren Abstand zu halten, macht erst einen unbeschwerten Kaffeegenuss möglich."},"ICON-0778":{"nm":"Eiswürfelform-Etikett","de":"Es gibt Menschen, die auf jeden Eiswürfel das Datum des Einfrierens schreiben. Mit der Überzeugung, dass auch Kälte eine Reihenfolge hat. Ein kleines Etikett lässt die Zeit im Gefrierfach ehrlich und der Reihe nach verstreichen."},"ICON-0779":{"nm":"Teebeutel-Zange","de":"Man beobachtet, wie der Tee zieht, und hebt ihn genau im richtigen Moment heraus. Eine Hand, die weiß, wann sie aufhören muss, bevor es zu stark wird. Die Stärke des Tees bestimmt weniger die Ziehzeit als der Zeitpunkt des Herausnehmens."},"ICON-0780":{"nm":"Drip-Filter-Ständer","de":"Er steht still da und hält den Filter, damit heißes Wasser langsam hindurchsickern kann. Er weiß, dass zu schnelles Brühen dem Aroma schadet. Auch das Stützen des Wartens braucht eine unerschütterliche Haltung."},"ICON-0781":{"nm":"Flaschen-Trageband","de":"Ein Band, das die Wasserflasche an Handgelenk oder Schulter hängt und einfach mitgeht. Eine Art des Zusammenseins, die sicherstellt, dass man sie nie vergisst. Manchmal ist ein leichtes Zubinden die freundlichste Lösung."},"ICON-0782":{"nm":"Dosenöffner-Abdeckung","de":"Deckt die Öffnung einer angetrunkenen Dose ab und schützt vor Staub und Kohlensäureverlust. Ein kleiner Hut, der für den nächsten Schluck für Frische sorgt. Auch etwas kurz Geöffnetes verdient, mit Sorgfalt wieder verschlossen zu werden."},"ICON-0783":{"nm":"Getränkecoupon-Hülle","de":"Eine Hülle, die die Stempelkarte für den zehnten Gratiskaffee sicher verwahrt. Damit die fleißig gesammelten Stempel nicht zerknittert werden. In dieser Hülle stecken alle treuen Besuche, die sich angesammelt haben."},"ICON-0784":{"nm":"Lunchbox-Verschlussband","de":"Ein Band, das die Lunchbox einmal fest umschlingt, damit der Deckel nicht aufgeht. Eine kleine Sicherheit, die garantiert, dass die Suppe in der Tasche nicht ausläuft. Für einen unversehrten Mittag sorgt dieser eine zuverlässige Umgang."},"ICON-0785":{"nm":"Beilagen-Bechersets","de":"Gibt jeder Beilage ihren eigenen Platz, damit sich die Geschmäcker nicht vermischen. Kimchi bleibt Kimchi, Gemüse bleibt Gemüse – klar und deutlich getrennt. Die kleinen Fächer schaffen Ordnung in der Lunchbox und zeigen die Sorgfalt der Koch-Hand."},"ICON-0786":{"nm":"Essstäbchen-Etui","de":"Ein kleines Zuhause, das die Essstäbchen nach drei Mahlzeiten sauber aufbewahrt. Ein stiller Begleiter, der im Schulranzen für Gepflegtheit sorgt. Das Mitnehmen selbst ist am Ende das, was eine ordentliche Mahlzeit ausmacht."},"ICON-0787":{"nm":"Soßenbehälter-Etikett","de":"Bringt Klarheit in Flaschen, bei denen man nicht wusste, ob es Sojasoße oder Essig ist. Sobald ein Streifen klebt, verschwindet das Zögern der Hand. Die Geschwindigkeit in der geschäftigen Küche entsteht durch solche kleinen Markierungen."},"ICON-0788":{"nm":"Kimbap-Rollmatte","de":"Ein dünnes Noriblatt, das Reis und Füllung zu einem Ganzen zusammenrollt. Fest gerollt, damit beim Schneiden nichts auseinanderfällt. Der Aufregung am Ausflugmorgen rollt sich genau hier, in dieser einen Schicht, ein."},"ICON-0789":{"nm":"Spießhalter-Dose","de":"Wenn Spieße und Zahnstocher an einem Ort stehen, greift die Hand im entscheidenden Moment nicht ins Leere. Auch spitzen Dingen ein festes Zuhause geben. Aufräumen ist letztlich eine kleine Freundlichkeit für die nächste Hand."},"ICON-0790":{"nm":"Kühlakku-Hülle","de":"Den Kühlakku noch eine Lage zusätzlich einwickeln, damit die Kälte etwas länger hält. Und damit die Tasche nicht durch Kondenswasser nass wird. Das Kühle bis zum Ende zu bewahren – das schafft diese eine dicke Schicht."},"ICON-0791":{"nm":"Lunchbox-Trennwand","de":"Eine kleine Wand, die verhindert, dass Reis und Beilagen in das Revier des jeweils anderen vordringen. Ein Frieden in einem Fach, durch den keine Brühe überschwappt. In der ordentlich aufgeteilten Lunchbox steckt die Sorgfalt dessen, der sie gepackt hat."},"ICON-0792":{"nm":"Speisereihenfolge-Karte","de":"Eine Karte, die sanft darauf hinweist, ob man mit der Suppe oder dem Reis beginnen soll. Eine freundliche Anleitung: In dieser Reihenfolge schmeckt es am besten. Sie erinnert daran, dass auch eine Mahlzeit einen Ablauf hat, ganz wie eine Geschichte."},"ICON-0793":{"nm":"Messbecher-Aufkleber","de":"Ein kleiner Aufkleber neben der Skala zeigt genau: „Bis hierhin.“ Er trifft die Menge, bei der man jedes Mal gezögert hat. Genauigkeit kommt aus einer einzigen kleinen Markierungslinie."},"ICON-0794":{"nm":"Silikondeckel-Griff","de":"Ein kleiner Griff, mit dem man heiße Topfdeckel anhebt, ohne sich die Finger zu verbrennen. Er leiht einem still den Mut, einen dampfenden Topf zu öffnen. Sicherheit kommt immer daher, dass man vorher einen Haltepunkt vorbereitet."},"ICON-0795":{"nm":"Mini-Klammerhaken","de":"Eine kleine Klemme, die Dingen, die bisher keinen Platz hatten – Küchentücher, Tüten –, einen Platz gibt. Verwandelt eine unordentliche Wandecke in eine aufgeräumte Ansicht. Eine einzige Aufhänge-Gewohnheit macht die Küche spürbar leichter."},"ICON-0796":{"nm":"Ölpinsel-Kappe","de":"Den Pinsel abdecken, und schon bleiben Staub und Verhärten fern. Ein Hütchen, das seine Weichheit bis zum nächsten Gericht bewahrt. Die kleine Fürsorge für das Werkzeug schützt am Ende den Geschmack."},"ICON-0797":{"nm":"Salzdosen-Löffel","de":"Ein kleiner Löffel, der direkt in der Salzdose wohnt. Er schöpft bei jeder Prise gewissenhaft die genaue Menge. Das Würzen mit der richtigen Hand ist das Maß an Herzlichkeit, das dieser kleine Löffel kennt."},"ICON-0798":{"nm":"Kühlschrank-Timermagnet","de":"An der Kühlschranktür zählt er drei Minuten für Nudeln und dreißig Sekunden für Sport. Dank eines Magnets bleibt die verfließende Zeit vor Augen. Ein fleißiger kleiner Kreis, der die vorbeigehende Zeit kurz an der Wand festhält."},"ICON-0799":{"nm":"Topfgriff-Schutzhülle","de":"Eine Schicht, die verhindert, dass man den erhitzten Griff mit bloßen Händen anfasst. Ein kleiner Schutzschild zwischen Hitze und Handfläche. Etwas sicher zu transportieren beginnt immer mit diesem weichen Umhüllen."},"ICON-0800":{"nm":"Schneidebrett-Gummimatte","de":"Wenn ich unten liege, rutscht das Schneidebrett nicht mehr weg. Ein Stück Gummi, das beim Schneiden von unten standhält. Stabilität ist die Kunst des festen Beißens an einer unsichtbaren Stelle."},"ICON-0801":{"nm":"Küchenhandschuh-Clip","de":"Ein Ort, an dem die unermüdlich am Herd arbeitenden Hände kurz zur Ruhe kommen. Ein Handschuh, den man an die Wand klemmt, leitet eine kurze Atempause bis zur nächsten Mahlzeit ein. Aufräumen ist ein anderes Wort für Fürsorge."},"ICON-0802":{"nm":"Kaffeepad-Halter","de":"Neben der Theke lehnen die schlanken Stäbchen Schulter an Schulter aneinander, bereit. Geordnet aufgestellt, um den Morgenkaffe einer anderen Person zu rühren – sie sehen aus wie ein Chor kurz vor dem Einsatz."},"ICON-0803":{"nm":"Untersetzer-Set-Band","de":"Ein Band, das den leisen Klang fängt, wenn ein Glas den Tisch berührt. Die runden Untersetzer zusammenzubinden bedeutet, für den Gästeempfang bereit zu sein. Gastfreundschaft beginnt immer an solchen kleinen, unscheinbaren Stellen."},"ICON-0804":{"nm":"Sirup-Etikettenclip","de":"Ein Name auf der Flasche – süß, dickflüssig. Dieses eine kurze Wort bringt Ordnung in einen geschäftigen Morgen. Ein Etikett ist ein Zettel, auf dem man kleine Versprechen vorausschreibt."},"ICON-0805":{"nm":"Dessert-Picks-Dose","de":"Eine Dose, in der die spitzen Stäbchen wohnen, die ein Stückchen Obst aufspießen. Bevor sie wie Fähnchen in den Dessertteller gesteckt werden, warten sie hier still auf ihre Reihenfolge. Auch Süßes hat seine Ordnung."},"ICON-0806":{"nm":"Rührstab-Hülse","de":"Eine Papierhülle, die einen Bündel Rührstäbchen fest umschließt. Sie saugt das Kondenswasser des kalten Getränks auf und hält die Hand trocken. Fürsorge, die nicht gesehen wird, kommt stets von den Rändern her."},"ICON-0807":{"nm":"Take-away-Carrier-Anhänger","de":"Ein kleiner Henkel, der die Becher übernimmt, wenn zwei Hände nicht reichen. Er hält die verpackte Wärme tropfenlos fest und begleitet sie bis zur Gasse vor dem Haus."},"ICON-0808":{"nm":"Café-Piepser-Hülle","de":"Eine Hülle, die das Warten umhüllt, bis der Piepser vibriert. Im Café-Eck hält sie das Wartennummer-Licht und trägt das Kribbeln: Gleich komme ich dran."},"ICON-0809":{"nm":"Stempelkarten-Ring","de":"Das Papier, aus dem nach zehn Feldern ein gratis Kaffee wird. Mit jedem Stempel wächst auch ein bisschen der Stammkunden-Status. Aufgefädelt auf einem kleinen Ring – eine schlichte, ehrliche Freude."},"ICON-0810":{"nm":"Kaffeebohnen-Probetüte","de":"Eine Tüte, die eine Handvoll Bohnen fasst und zuerst den Duft reichen lässt. Säure und Süße, die an der Nasenspitze vorbeischweben – dieser erste Eindruck entscheidet über eine Tasse. Aroma kommt schneller an als jede Beschreibung."},"ICON-0811":{"nm":"Kühlschranktür-Namensmagnet","de":"Ein kleines Namensschild, das an der Kühlschranktür klebt. Was wann hereingekommen ist, lässt sich so leicht notieren – und kein Gericht wird mehr vergessen. Wirtschaft bedeutet, die fließende Erinnerung festzuhalten."},"ICON-0812":{"nm":"Haltbarkeitsdatum-Chip","de":"Ein kleines Stückchen, das das Abfülldatum deutlich festhält. Es ist der stille Zeuge, der sagt: Das ist noch gut. Frische bewahren beginnt mit der Hand, die sich das Datum merkt."},"ICON-0813":{"nm":"Vorrats-Behälter-Band","de":"Ein Band, das die Taille des portionierten Behälters umschlingt. Es zieht den wackelnden Deckel fest und hält die kleine Ordnung im Kühlschrank aufrecht. Etwas zu binden ähnelt dem Ordnen der eigenen Gedanken."},"ICON-0814":{"nm":"Dichtungsclip-Farbband","de":"Bunte Klemmen, die den Tütenboden fest zubeißen. Rot für Scharfes, Gelb für Süßes – die Hand weiß es, bevor die Augen lesen. Die Ampel der Küche zeigt so lautlos den Weg."},"ICON-0815":{"nm":"Tiefkühl-Namensetikette","de":"Ein Etikett, das sanft auf das Gefrorene gelegt wird. Damit es auch unter Reif nicht vergisst, was es einmal war. Ein kleines Hallo an die Zutaten, die ihren Winterschlaf halten."},"ICON-0816":{"nm":"Gemüsenetz","de":"Ein weitmaschiges Netz, das erdiges Gemüse großzügig aufnimmt. Dass es Luft braucht, um lang frisch zu bleiben, wusste die Küche der Großmutter längst. Belüftung ist das freundliche Loslassen, das Gemüse braucht."},"ICON-0817":{"nm":"Flaschendeckel-Sortierkappe","de":"Eine Sortierkappe, die Deckel nach Größe einander zuordnet. Das verlorene Gegenstück wiederzufinden ist überraschend liebevoll. Ein passendes Paar einzusortieren lässt auch die Küche aufatmen."},"ICON-0818":{"nm":"Eierkarton-Etikett","de":"Ein Etikett, das jedes der zehn kleinen Nester nummeriert. Es erinnert daran, die älteren Eier zuerst zu verwenden – eine Weisheit des Haushaltens. Sogar für das Morgen-Spiegelei gibt es eine Reihenfolge, die man achten kann."},"ICON-0819":{"nm":"Reste-Aufkleber","de":"„Das ist meins!“ – ein Zettel genügt, und der Kühlschrank erlebt einen Moment des Friedens. Eine charmante Besitzanmeldung für den Spätimbiss. Familien funktionieren manchmal dank solcher kleinen Abmachungen."},"ICON-0820":{"nm":"Besteck-Unterlagsplättchen","de":"Ein kleines Stückchen, das verhindert, dass Löffel und Stäbchen direkt auf dem Tisch liegen. Diese kleine Gepflegtheit hebt das Niveau einer Mahlzeit still an. Tischmanieren wachsen an solchen ruhigen Kleinigkeiten."},"ICON-0821":{"nm":"Servietten-Fixierring","de":"Ein Ring, der flatternde Servietten sanft zusammenhält. Er fasst das weiße Papier, das darauf wartet, entfaltet zu werden, ordentlich zusammen und schreibt eine kleine Ordnung auf den Tisch."},"ICON-0822":{"nm":"Tischmatte-Eckhalter","de":"Ein Stückchen, das die aufgebogene Ecke der Matte sanft andrückt und glätttet. Erst wenn eine Ecke gehalten wird, liegt das Ganze gerade – das lehrt der Tisch jeden Tag. Auch die Ecke trägt ihren Teil der Verantwortung."},"ICON-0823":{"nm":"Kleines Gewürztablett","de":"Ein kleines Tablett, das ein Schälchen Sojasoße und eine Prise Salz nebeneinander aufnimmt. Eine Tischkultur, die auch Beilagen ihren Platz gibt. Koreanische Küche wird durch die Fürsorge für das Nebensächliche tiefer."},"ICON-0824":{"nm":"Tischnummern-Chip","de":"Die Zahl, nach der im belebten Restaurant gerufen wird. Sie gibt jedem Warten seine Reihenfolge und sorgt für faire Gleichbehandlung. In dem kleinen Chip steckt ein Versprechen – und bald eine warme Schüssel."},"ICON-0825":{"nm":"Wasserglasmarkierungsband","de":"Ein Band um das Wasserglas, das leise verrät, wessen Glas das ist. Eine kleine Flagge, die unter ähnlichen Gläsern den eigenen Platz markiert. Bei einem gemeinsamen Tisch verhindert diese Geste unnötige Missverständnisse."},"ICON-0826":{"nm":"Vorspeisenteller-Pin","de":"Ein Pin, der die Vorspeisenteller farblich voneinander trennt. Er zieht eine freundliche Grenze zwischen Meinem und Deinem und macht das gemeinsame Essen übersichtlicher. Geteilt wird herzlich – und trotzdem hygienisch."},"ICON-0827":{"nm":"Menühalter","de":"Hinter der aufgeschlagenen Speisekarte verbirgt sich kurz die Zeit des Überlegens. Auch das kurze Zögern bei der Wahl gehört schon zum Essen dazu. Was nehme ich heute – dieses kleine Kribbeln wird sanft verborgen."},"ICON-0828":{"nm":"Tischkarten-Ständer","de":"Ein kleiner Ständer, der einen Namensschildchen aufrecht hält. Ob Festtafel oder Veranstaltungssaal – er verkündet deutlich: Hier ist dein Platz. Gastfreundschaft vollendet sich in dem Moment, in dem ein Name ausgerufen wird."},"ICON-0829":{"nm":"Muffin-Papierbanderole","de":"Eine Papierhülle, die den dicken Bauch des frisch gebackenen Muffins fest umschlingt. Sie schützt die Wärme davor, der Hand zu entgleiten, und bewahrt die Wärme bis zum ersten Bissen. Auch Desserts brauchen ihre Kleidung."},"ICON-0830":{"nm":"Spritzbeutel-Verschlusskappe","de":"Ein Stopfen, der den Auslass des Spritzbeutels fest verschließt, damit beim Rasten kein Tropfen entweicht. Er hält die Creme zurück, damit daraus eine kleine Blume auf der Torte werden kann. Zurückhaltung ist der Ursprung jeder Dekoration."},"ICON-0831":{"nm":"Keksausstecher-Ring","de":"Eine Form, die Teig in Sterne und Bären verwandelt. Dasselbe Mehl erwacht unter den Händen in Dutzenden von Gesichtern. Egal was man bäckt – als Erstes berührt den Teig immer die Herzlichkeit."},"ICON-0832":{"nm":"Teigschaber","de":"Eine flache Hand, die Teig akkurat zusammenschabt und sauber teilt. Die Sorgfalt, mit der jeder Krümel aus der Schüssel geholt wird, bestimmt am Ende das Volumen des Brotes. Backen ist die Arbeit einer sparenden Hand."},"ICON-0833":{"nm":"Messlöffel-Ablagebrett","de":"Ein Brett, auf dem Messlöffel ordentlich liegen – ein Teelöffel, ein halber Esslöffel. Der genaue Löffel setzt den Maßstab für den Geschmack. Hinter dem Ausdruck „Handgeschmack“ verbirgt sich insgeheim sorgfältiges Abmessen."},"ICON-0834":{"nm":"Ofenhandschuh-Haken","de":"Ein Haken, an den der Handschuh gehängt wird, der heiße Öfen bewacht. Die schwere Hand, die vor Verbrennungen schützte, wartet in der Ruhepause griffbereit. Sicherheit beginnt damit, dass etwas immer an seinem Platz ist."},"ICON-0835":{"nm":"Abkühlgitter-Clip","de":"Eine Klemme, die das Auskühlen der frisch gebackenen Kekse ordentlich festhält. Sie hält das Gitter, bis die Knusprigkeit fertig ist, und wartet geduldig mit. Auch das Auskühlen braucht ein wenig Geduld."},"ICON-0836":{"nm":"Kuchentopper-Halter","de":"Ein Halter, der „Alles Gute zum Geburtstag“ auf der Torte aufrichtet. Kurz bevor die Kerzen erlöschen, erhellt dieses kleine Fähnchen jemandes ganzen Tag. Glückwünsche sollte man hoch aufstellen, damit sie gut zu sehen sind."},"ICON-0837":{"nm":"Puderzucker-Streudose","de":"Eine Dose für den letzten, leichten Schwung Puderzucker. Wie weißer Schnee legt er sich auf frisch gebackenes Dessert und verwandelt ein einfaches Stück in ein kleines Geschenk. Das Finishing kommt mit der leichtesten Berührung."},"ICON-0838":{"nm":"Dreieck-Onigiri-Etikett","de":"Wenn man die Folie in der Reihenfolge 1, 2, 3 abzieht, knistert das Nori wieder frisch auf. Ein Streifen, der den treuen Freund langer Nächte auf einen Blick erkennbar macht. Die Erinnerung an einen hungrigen Abend klebt direkt hier."},"ICON-0839":{"nm":"Cup-Nudel-Deckelhalter","de":"Ein Ständer, der drei Minuten lang den Deckel herunterdrückt, damit kein Dampf entweicht. Er ersetzt die Stäbchen, die man früher obendrauf legte. Diese kurze Wartezeit ist der aufregendste Moment des nächtlichen Snacks."},"ICON-0840":{"nm":"Hotdog-Spieß-Kappe","de":"Eine kleine Kappe, die das Ende des Spießes fest umschließt. Damit man gut abbeißen kann und kein Tropfen Soße an die Finger geht. Das Vergnügen am Imbiss wird durch solche kleinen Selbstverständlichkeiten erst rund."},"ICON-0841":{"nm":"Plastiktüten-Henkel","de":"Wenn man ihn über die Finger hängt, knistert die Tüte leise. Das Gewicht des Einkaufs zieht auf eine Seite, und bis nach Hause bleiben rote Male auf der Handfläche. In dem leichten Geräusch steckt der schwere Alltag eines ganzen Tages."},"ICON-0842":{"nm":"Bon-Faltclip","de":"Den langen Kassenbon halbieren und festklemmen – schon wird das Tagesgeld zu einem ordentlichen Bündel. Während die nach Druckertinte riechenden Zettel sich stapeln, ordnen sich auch die kleinen Erinnerungen des Alltags."},"ICON-0843":{"nm":"Mikrowellen-Etikett","de":"Bevor es piept, schätzt das Etikett still die nötige Zeit ab. Minuten und Sekunden, der Name dessen, was erhitzt werden soll – ein kleines Schild, das Auskunft gibt. Auch das Warten auf Wärme hat seine Skala."},"ICON-0844":{"nm":"Rabattaufkleber-Rolle","de":"Bei jedem abgezogenen Stückchen gibt es ein leises Knistern, das die Fingerkuppe kitzelt. Wenn rote Zahlen nacheinander abgerollt werden, wird der Einkaufskorb eines anderen ein bisschen leichter. Eine Rolle kleiner Freundlichkeiten, die gerollt auf ihre Runde wartet."},"ICON-0845":{"nm":"Soßenbeutel-Ring","de":"Sauer platzt hervor und der Alltag wird ein bisschen süßer. Wenn der am Ringchen hängende Beutel beim Gehen wippt, begleitet ein kleines Stückchen Süßes einen den ganzen Tag in der Tasche."},"ICON-0846":{"nm":"Convenience-Store-Körber-Chip","de":"In der Hand wippt der Kunststoff leicht. In einem Laden voller Licht am späten Abend reicht er für zwei Onigiri und ein Getränk. Eine sanfte, gerade große Schüssel – genug für eine Mahlzeit, genug um nicht allein zu sein."},"ICON-0847":{"nm":"Macaron-Box-Band","de":"Ein Band, das die Schachtel mit den bunten Macarons sanft zusammenhält, damit nichts durcheinanderkommt. Wer schon einmal ein Geschenk bekommen hat, weiß mit den Fingerspitzen: Das Kribbeln kurz vor dem Öffnen des Bandes ist am süßesten."},"ICON-0848":{"nm":"Obstnetzklemme","de":"Das Netz zugreifen und zuklemmen – und leise schleicht Apfelduft durch die Maschen. Eine kleine Hand, die verhindert, dass die Früchte herausfallen. Eine stille, freundliche Mahnung, sie zu essen, bevor sie weich werden."},"ICON-0849":{"nm":"Marmeladenglas-Stofdeckel","de":"Ein Stofdeckel über dem Deckel, mit einem Gummiband befestigt – so erinnert man sich an die Sommerküche der Großmutter. Ein kariertes Stückchen Stoff bewahrt die süße Zeit des Einmachens und die Sorgfalt, die darin steckt. Handgemachter Geschmack wird so aufbewahrt."},"ICON-0850":{"nm":"Keks-Geschenkband","de":"Selbst gebackene Kekse in Folie legen, das Bändchen drehen und verknoten – und der Butterduft zieht bis in die Bandspitzen. Die Hand, die etwas Selbstgemachtes weiterreicht, zittert immer ein bisschen. Eine Schleife, in der das Herz mit eingeknüpft ist."},"ICON-0851":{"nm":"Schokoladen-Trennwand","de":"Sie weist jeder Schokolade ihren eigenen Platz zu, damit keine die andere berührt. Damit nichts schmilzt, damit nichts zerbricht. Was die kleine Trennwand bis zuletzt schützt, ist ein heiles Stückchen Herzlichkeit für jemanden."},"ICON-0852":{"nm":"Tee-Geschenketikett","de":"Auf dem Etikett der Teetüte steht in Handschrift der Name – klar und ordentlich. Das kleine Zettelchen verrät schon vorher: Wenn du aufgießt, steigt Kräuterduft mit dem Dampf auf. Die Hände werden warm, noch bevor man trinkt."},"ICON-0853":{"nm":"Bonbon-Fläschchen-Kette","de":"Ein buntes Süßigkeitenfläschchen mit einer Kordel um den Flaschenhals – zum Tragen. Bei jedem Schritt kullert ein leises Klimpern im Inneren. Eine stolze kleine Schatztruhe aus der Kindheit, die man um den Hals trug."},"ICON-0854":{"nm":"Geschenklöffel-Anhänger","de":"Ein kleiner Anhänger am Löffelstiel macht aus einem schlichten Löffel auf einmal ein Geschenk. Bei jedem Abschöpfen erklingt ein helles Klimpern. Ein kleiner Schmuck, der dem Schenken eine besondere Note verleiht."},"ICON-0855":{"nm":"Dankeschön-Anhänger für Snacks","de":"Die Freude zurückgeben, zumindest ein bisschen. Ein kleiner Anhänger an der Snacktüte. Was man nicht in Worte fassen konnte, reicht dieser stille kleine Gruß von Hand zu Hand weiter."},"ICON-0856":{"nm":"Washi-Tape-Musterring","de":"Muster, die in kleinen Streifen aufgereiht auf Probe kleben. Während man mit den Fingern langsam wählt, welche Farbe gefällt, wird der ganze Tag durch das bloße Planen schon bunter. Eine Musterkollektion, bei der sogar das Überlegen Spaß macht."},"ICON-0857":{"nm":"Sticker-Pinzetten-Kappe","de":"Mit einer Kappe auf der Pinzettenspitze bleibt selbst ein Aufkleber in Daumennagel-Größe unversehrt. Eine präzise Hand, die Ecken erreicht, wohin kein Finger kommt. Im Umgang mit Liebgewonnenem ist immer Vorsicht geboten."},"ICON-0858":{"nm":"Tagebuch-Ecksiegel","de":"Klebt man Siegel auf alle vier Ecken des Tagebuchs, liegen die flatternden Seiten auf einmal still. Das leichte Andrücken des Papiers ist ein kleines Ritual, das den Tag ordentlich versiegelt. Aufzeichnungen beginnen in den Ecken, fest zu werden."},"ICON-0859":{"nm":"Lochführungs-Schablone","de":"Eine Schablone, die zeigt, wo das Loch hinkommt. Einfach an der Linie ausrichten – und es sitzt perfekt. Die Bereitschaft, einmal kurz innezuhalten und nachzumessen, ist der leise Ursprung aller Genauigkeit."},"ICON-0860":{"nm":"Papierschnipsel-Tablett","de":"Die Papierschnipsel vom Scherenschneiden rutschen sanft ins Tablett. Damit der Schreibtisch nicht vollkritisch wird, bekommen die kleinen Teile eine kurze Bleibe. Das Aufräumen nach dem Basteln geschieht so still und ganz von selbst."},"ICON-0861":{"nm":"Farbstempelpad","de":"Leicht andrücken und abheben – schon spreizt sich Farbe feucht auf der Fingerkuppe. Rot, Gelb, Blau – ein kleiner Regenbogen auf einem Stempel. Ein weiches Feld, in das man Tupfer für Tupfer Farbe auf weißes Papier setzt."},"ICON-0862":{"nm":"Deko-Klebeband-Rolle","de":"Das Muster rollt sich endlos ab. Einen Streifen ablösen und aufkleben – und eine kahle Stelle erblüht. Wohin die Hand auch führt, wird es schöner: eine Rolle kleiner Magie, die darauf wartet, abgewickelt zu werden."},"ICON-0863":{"nm":"Motivstempel-Kappe","de":"Ein kleines Hütchen, das die Stempeloberfläche abdeckt, damit die Tinte nicht eintrocknet. Es schützt das nächste Motiv, damit es auf dem Papier klar und deutlich erscheint. Gut aufbewahrte Farbe blüht auch auf dem nächsten Blatt Papier unverändert."},"ICON-0864":{"nm":"Dekolocher-Konfetti","de":"Was der Locher ausstanzt – Sterne, Herzen, Blütenblätter aus Buntpapier – landet in der Handfläche. Zu schön zum Wegwerfen, also klebt man sie irgendwo hin. Kleine Schätze, die aus dem Nichts entstehen."},"ICON-0865":{"nm":"Garnrollen-Etikettenring","de":"Ein kleines Etikett an jeder Fadenrolle mit dem Namen der Garnfarbe. Eine freundliche Markierung, die verhindert, dass sich alles verwirrt. Verwirrte Fäden wie verwirrte Gedanken – ein Name hilft, sie zu entwirren."},"ICON-0866":{"nm":"Nähnadelbuch-Hülle","de":"Eine weiche Hülle, die das Filz-Büchlein mit den eingesteckten Nadeln abdeckt. Aufgeklappt liegen die Näh-Utensilien ordentlich und empfangen einen. Eine kleine Herberge, in der spitze Dinge sicher schlafen."},"ICON-0867":{"nm":"Stoffmuster-Ring","de":"Rau oder weich – man tastet sich langsam durch die Beschaffenheit der Stoffe. Unter nach Farben geordneten Gewebestücken wartet das Tuch darauf, vor einem Kleid erst berührt zu werden."},"ICON-0868":{"nm":"Stickrahmen-Ring","de":"Stoff in den runden Rahmen spannen und festziehen – er wird straff wie ein Trommelkopf. Das kleine Signal, dass man bereit ist, Stich für Stich zu sticken. Was der Ring fest hält, ist nicht der Stoff, sondern die Konzentration."},"ICON-0869":{"nm":"Knopf-Sortierkapseln","de":"Die überall herumkullernden Knöpfe sortieren sich farblich in ihre Kapsel-Fächer. Damit kein einziger verloren geht, wird alles klein aufgeteilt. Auch das Sammeln des Verstreuten braucht seine Sorgfalt."},"ICON-0870":{"nm":"Schneidkreide-Halter","de":"Ein Halter, in dem die Kreide zum Markieren auf Stoff gut in der Hand liegt. Er stützt das Leicht-Zerbrechliche. Erst wenn der erste Strich gerade ist, wird auch das Kleidungsstück gerade – der ruhige erste Gedanke vor der Schere."},"ICON-0871":{"nm":"Stecknadel-Fläschchen","de":"Im klaren Fläschchen klimpern die Stecknadeln leise aneinander. Im Gegenlicht formt sich an jeder Nadelspitze ein kleines Licht. Ein zuverlässiges Gefäß, das alles, was sich verteilen und stechen könnte, sicher vereint."},"ICON-0872":{"nm":"Reparatur-Klebeband-Rolle","de":"Auflegen und bügeln – und das Rissige haftet wie von Zauberhand. Ohne einen einzigen Stich schließt sich das aufgetrennte Kleid. Das Flicken statt Wegwerfen rollt sich in dieser runden Rolle auf."},"ICON-0873":{"nm":"Applikationsschnittmuster","de":"Ein Schnittmusterbogen, auf dem die Formen vorgezeichnet sind. Gepunktete Linien führen die Schere freundlich. Zuerst den Umriss zeichnen – die Vorfreude beginnt immer mit diesem blassen Grundriss."},"ICON-0874":{"nm":"Aquarellbecher-Deckel","de":"Den Deckel auf den Wasserbecher – und selbst wenn Farbwasser schwappt, tropft nichts heraus. Er schützt auch vor dem trüben Wasserfleck auf dem Schreibtisch. Ein stiller Deckel, der den Mal-Platz unerschütterlich bewacht."},"ICON-0875":{"nm":"Pastell-Schutzband","de":"Ein Band um den pudrigen Pastellstift lässt die Finger sauber bleiben. Papier, das das Zarte schützt, damit es nicht abbricht. Je weicher die Farbe, desto sanfter muss man sie halten – dann liegt sie auch auf dem Papier weich."},"ICON-0876":{"nm":"Buntstift-Verlängerungskappe","de":"Eine Kappe auf den abgenutzten Buntstift gesteckt – und der Stift wird wieder länger. Nicht wegwerfen, weil er kurz geworden ist. Wer bis zum letzten Strich auszeichnet, vollendet das Bild in satteren Farben."},"ICON-0877":{"nm":"Pinsel-Spülbecher-Ring","de":"Den Spülbecher am Ring aufhängen, und Tropfen vom Pinsel rinnen sauber ab. Kurze, klare Stille vor der nächsten Farbe, wenn der Pinsel gespült wird. Auch im Reinwerden liegt ein stilles Gleichmaß."},"ICON-0878":{"nm":"Palettenmesser-Schutzkappe","de":"Eine kleine Kappe, die die Klinge des Palettenmessers schützt, damit sie nicht stumpf wird. Die Textur der dick aufgetragenen Farbe entsteht an einem gut gepflegten Ende."},"ICON-0879":{"nm":"Leinwand-Spannclip","de":"Eine kräftige Klemme, die die Leinwand fest am Rahmen aufspannt. Fest angeklemmt liegt die Malfläche straff. Erst ein stabiler Untergrund macht den darüber tanzenden Pinsel wirklich frei."},"ICON-0880":{"nm":"Zeichenbrett-Trageband","de":"Das Band über die Schulter werfen – und das Brett folgt auf dem Rücken. Wo immer man sich niederlässt, wird es zum eigenen Atelier. Ein kleines Malstudio, das man auf dem Rücken trägt, um die richtige Landschaft zu suchen."},"ICON-0881":{"nm":"Acrylfarben-Farbkey","de":"Ein Tropfen Wasser mehr, und es wird Morgendämmerung. Weniger, und es wird Mitternacht. Aus demselben Blau öffnet sich unter den Händen jedes Mal ein anderer Himmel. Mit einem Farb-Key beginnt die Farbe des heutigen Tages sich auf dem Papier auszubreiten."},"ICON-0882":{"nm":"Farbverlaufsmuster-Blatt","de":"Dieses Papier wusste schon vorher, dass der Sonnenuntergang nicht auf einmal rot wird. Kleine Stufen, die vom Hellen ins Dunkle führen. Die Augen gehen langsam diesen Weg und folgen der Zeit, in der die Farbe reift."},"ICON-0883":{"nm":"Häkelnadel-Schutzkappe","de":"Ein kleiner Schutz wie ein Fingerhut, bevor der Faden in die Finger schneidet. Wer lange gehäkelt hat, weiß es. Nur wer sich nicht verletzt, kann sanft bis zur letzten Masche begleiten."},"ICON-0884":{"nm":"Strick-Maschenmarkierer","de":"Eine Markierung genügt, und es wird sofort wieder klar, wie weit man schon ist. Die Erleichterung, keine Masche doppelt zu zählen. So, wie man manchmal zurückschaut und die zurückgelegte Stelle berührt, um nicht den Weg zu verlieren."},"ICON-0885":{"nm":"Reihenzähler-Anhänger","de":"In jedem Fach stapelt sich das stille Zeugnis einer fertig gestrickten Reihe. Was endlos schien, ist zur Hälfte, wenn man Stück für Stück abzählt. Kleines Zählen hält das Herz durch bis zum Schluss."},"ICON-0886":{"nm":"Fadenende-Ordnungspin","de":"Ein loses Fadenende unbeachtet lassen – und niemand weiß, wo sich der nächste Knoten bildet. Eine Hand, die auch das Unsichtbare ordnet. Fürsorge zeigt sich meistens an Stellen, die niemand sieht, die sich aber zuerst bewegen."},"ICON-0887":{"nm":"Knotenübungsschnur","de":"Überhandknoten, Schleifenknoten, Ringknoten. Dieselbe Schnur immer wieder knüpfen und lösen, bis die Hände die Form auswendig kennen. Wenn die ungeübten Finger eines Abends plötzlich fließend werden, weiß die Schnur es als Erste."},"ICON-0888":{"nm":"Wollknäuel-Etikettenband","de":"Ein kleines Band an jedem Knäuel: Stärke, Farbe, Materialangabe. Die Gewohnheit entstand aus Nächten, in denen man nach dem Aufbrauchen dieselbe Wolle nicht mehr finden konnte. Ein Notiz für das künftige Ich ist die freundlichste Art der Aufzeichnung."},"ICON-0889":{"nm":"Maschendichte-Messlineal","de":"Wie viele Maschen auf zehn Zentimeter passen – diese kleine Zahl bestimmt die Größe eines ganzen Kleidungsstücks. Dass ein handflächengroßes Stückchen das gesamte Maß hält, ist, wenn man darüber nachdenkt, recht schwerwiegend."},"ICON-0890":{"nm":"Knopfloch-Markierung","de":"Bevor der Knopf genäht wird, setzt man zuerst einen Punkt, wo das Loch kommen soll. Diese Markierung, die bald verschwinden wird, hält das Knopfleiste gerade. Sorgfalt lebt meist still an Stellen, die am Ende nicht mehr zu sehen sind."},"ICON-0891":{"nm":"Kleines Quasten-Ringlein","de":"Wie eine Quaste am Ende einer Kordel lässt ein kleines Ringlein Bewegung entstehen. Hängendes, das sanft schwankt, zieht immer die Blicke auf sich. Eine Regung, die sich still belebt, wenn der Wind vorübergeht."},"ICON-0892":{"nm":"Mini-Farblack-Fläschchen","de":"Nicht sparen, sondern präzise verwenden – so geht man richtig mit Farblack um. Eine kleine Flasche neben der Hand, die Menge abschätzen. Genügsamkeit beginnt damit, den Wunsch einmal loszulassen."},"ICON-0893":{"nm":"Kleines Schleifstäbchen","de":"Von der groben Seite zur feinen. Eine auf einmal glatte Oberfläche gibt es nirgends. Die Hand, die die Körnung Stufe für Stufe verfeinert, lässt das Raue langsam weich werden."},"ICON-0894":{"nm":"Modellbau-Klemmenhalter","de":"Ein geleimtes Bauteil mit der Hand zu halten hinterlässt Fingerabdrücke. Sanft in eine Klemme eingespannt, werden die Hände frei, und das Trocknen endet still von allein. Auch das Warten fällt leichter, wenn jemand trägt."},"ICON-0895":{"nm":"Klebstoff-Unterlagsplatte","de":"Fällt ein Tropfen Klebstoff auf den Schreibtisch, bleibt der Fleck lange. Eine Unterlagsplatte vorher hinzulegen ist eine Gewohnheit. Die Hälfte der Arbeit beginnt vielleicht mit dem Vorsatz, den Platz nicht zu beschmutzen."},"ICON-0896":{"nm":"Kleinteil-Sortierfach","de":"Wenn Dutzende gleicher Teile durcheinandergemischt sind, wird die Montage schnell zum Labyrinth. Die Hände, die vorher sortieren, sparen später Suchzeit. Ordnung ist Freundlichkeit gegenüber dem künftigen Ich."},"ICON-0897":{"nm":"Montagereihenfolge-Chip","de":"Ein kleiner Chip mit der Notiz, welches Bauteil zuerst gesteckt wird. Wer die Reihenfolge einhält, baut nichts, was leicht zusammenbricht. Modelle wie sorgfältig aufgebaute Tage – beides wird auf diesem stillen Versprechen stabil."},"ICON-0898":{"nm":"Mini-Pinselhalter","de":"Den Pinsel nach Gebrauch flach hinzulegen drückt die Borsten krumm. Verkehrt herum aufgehängt lässt das Wasser ablaufen. Wer sein Werkzeug lange bei sich behalten will, ist nach getaner Arbeit emsiger und fürsorglicher."},"ICON-0899":{"nm":"Modellbau-Restebehälter","de":"Ein Behälter, in dem die vom Rahmen abgezogenen Reste still zusammenkommen. Weggeworfen wirkend, kehren sie eines Tages als kleines Detail zurück. Auch Überbleibsel haben ihre Reihenfolge, das weiß der Behälter geduldig wartend."},"ICON-0900":{"nm":"Klarlack-Sprühkappe","de":"Die letzte Schicht aufzusprühen – zu nah, und sie läuft herunter. Eine Handbreit Abstand, leicht, ganz leicht. Glanz aufzutragen ist vielleicht auch das Üben darin, den eigenen Wunsch einmal loszulassen."},"ICON-0901":{"nm":"Druckbleistiftminenbox","de":"Dünne Minen brechen in der Tasche nur allzu gern ab. Wer sie ordentlich in einem kleinen Behälter ablegt, verschwendet keine einzige. Ordnung halten ist im Grunde eine stille Fürsorge für das zukünftige Ich."},"ICON-0902":{"nm":"Radiergummi-Hülle","de":"Ein kleines Papierkleid, das den Radiergummi umhüllt. Je schwärzer es von Gebrauchsspuren wird, desto mehr Korrekturen hat es bezeugt. Radieren bedeutet auch: die freundliche Erlaubnis, neu anzufangen."},"ICON-0903":{"nm":"Federdosenbehälter","de":"Federn reißen ein, wenn sie austrocknen, und biegen sich, wenn sie stoßen. Ein kleines Behältnis, in dem sie einzeln liegen, bewahrt die Qualität der Schrift lange. Ein gut gepflegtes Werkzeug gleitet am Ende dankbar zurück."},"ICON-0904":{"nm":"Füllertinten-Probe","de":"Tinten, die man tropfenweise ausprobiert. Was man für Petrol hielt, wird auf dem Papier zum tiefen Ozean. Farbe muss man immer selbst erleben – das im Kopf gemalte Bild liegt oft daneben."},"ICON-0905":{"nm":"Buchmarken-Behälter","de":"Ein kleines Fähnchen, das die aufgeschlagene Seite festhält. Wenn man das Buch wieder aufschlägt, winkt das gestrige Ich einem entgegen. Sogar ein Innehalten wird zum Versprechen – das ist die stille Güte dieses kleinen Zeichens."},"ICON-0906":{"nm":"Haftfähnchen-Pack","de":"Klebt man eines auf, beginnt die Geschichte genau dort von vorn. Reihen sich die Fähnchen am Buchrand auf, fügen sich verstreute Gedanken zu einer einzigen Karte zusammen."},"ICON-0907":{"nm":"Büroklammern-Magnet","de":"Ein kleiner Magnet, der verstreute Büroklammern auf einen Schlag einsammelt. Kleine Dinge gehen besonders leicht verloren – eine einzige Anziehungskraft rettet leise ein unordentliches Schreibtischleben. Auch Anziehung kann zärtlich sein."},"ICON-0908":{"nm":"Bleistiftkappenset","de":"Kleine Hütchen, die die Bleistiftspitze schützen und die Tasche bewahren. Spitzes sticht nun einmal – deshalb braucht es eine Hand, die es sanft abdeckt. Nicht stumpf werden, aber auch niemanden verletzen."},"ICON-0909":{"nm":"Schreibtisch-Namensschild-Sticker","de":"In dem Moment, in dem man seinen Namen aufschreibt und auf den Schreibtisch klebt, gehört einem dieser Platz wirklich. Selbst in einem handbreiten Raum verändert sich die Haltung, sobald er einen Besitzer hat."},"ICON-0910":{"nm":"Sprungseilgriff-Kappe","de":"Eine Kappe für das Griffende, bevor es ausfranst und reißt. Den Rhythmus des tausendmal geschwungenen Seils erinnern die Handflächen früher als der Kopf. In den Körper eingeschriebener Takt verblasst kaum."},"ICON-0911":{"nm":"Yoga-Ring-Gurt","de":"Den Ring haltend, öffnet sich der Körper langsam. Je straffer das Band, desto mehr lösen sich die verspannten Schultern Schicht für Schicht. Dehnen ist kein gewaltsames Ziehen – es kommt dem geduldigen Warten näher, bis der Körper sich öffnet."},"ICON-0912":{"nm":"Tischtennisball-Etui","de":"Der weiße Ball, der wegen seiner Leichtigkeit weit rollt und beim Drauftreten einfach einbeult. Ein kleines Etui schützt diesen empfindlichen Ball bis zum nächsten Spiel. Stärke kommt oft vom sanften Umhüllen."},"ICON-0913":{"nm":"Badminton-Griffband","de":"Legt sich sorgfältig über den vor Schweiß rutschigen Griff. Auf einem gut gewickelten Griff wird der Schläger zum Teil der Hand. Das Geheimnis, nicht mit Kraft, sondern mit Gefühl zu schlagen, verbirgt sich in dieser dünnen Lage."},"ICON-0914":{"nm":"Kleine Punktechips","de":"Ein Punkt, noch ein Punkt. Die kleinen Chips werden verschoben, Punkt für Punkt angesammelt. Wenn man die Punkte vor Augen hat, wird das Spiel klarer – und der Mut, einen Punkt aufzuholen, wächst leise."},"ICON-0915":{"nm":"Schuh-Ausrichtungsclip","de":"Die Schuhspitzen zeigen stets in dieselbe Richtung. Eine kleine Geste beim Ausziehen: einmal kurz drehen. Diese winzige Ordnung macht den Schritt am nächsten Morgen eine Spur leichter."},"ICON-0916":{"nm":"Pfeifenband","de":"Wer die Pfeife um den Hals trägt, erhält das Recht, Halt zu rufen. Ein kurzer Ton, und der ganze Platz erstarrt. Die Herzen, die diesem kleinen Laut vertrauen, formen gemeinsam ein Versprechen."},"ICON-0917":{"nm":"Pumpnadel-Behälter","de":"Selbst ein platter Ball lässt sich mit einer einzigen dünnen Nadel wieder aufpumpen. Diese fein aufbewahrte Nadel macht die ganze Pumpe wertlos, sobald sie verlorengeht. Manchmal ist das Kleinste am wichtigsten."},"ICON-0918":{"nm":"Mini-Hütchen-Markierung","de":"Von hier bis dort – kleine Kegel zeichnen Grenzen, die man sonst nicht sieht. Auch ohne Linien folgen Menschen diesen Zeichen ganz natürlich. Ordnung wächst leise aus solch kleinen Signalen."},"ICON-0919":{"nm":"Token-Beutel","de":"Ein Beutelchen, das klimpernde Tokens an einem Ort versammelt. Zieht man den Beutel zu, kann nichts mehr verstreuen. Auch kleine, unwichtige Dinge erfüllen ihren Zweck erst, wenn sie einen Platz haben – das zeigt der Beutel wortlos."},"ICON-0920":{"nm":"Karten-Mischmatte","de":"Auf einem glatten Tisch lassen sich Karten kaum greifen. Eine Unterlage macht sowohl das Mischen als auch das Aufnehmen wesentlich angenehmer. Auch zum guten Spielen gehört die freundliche Vorbereitung – zuerst den Boden ebnen."},"ICON-0921":{"nm":"Spielplan-Eckenschutz","de":"Nach einer Brettspielnacht kümmert sich jemand leise um die vier Ecken des Spielplans. Denn wer weiß: Tiefe Falten lassen das nächste Spiel schief werden. In den Händen, die die Ecken glätten, steckt die stille Bitte: Lass uns morgen wieder spielen."},"ICON-0922":{"nm":"Würfelbecher-Deckel","de":"Schütteln, rollen, gemeinsam den Atem anhalten – dieser kurze Moment. Ein kleines Dach, das verhindert, dass die Würfel herausfliegen. Unter dem Deckel hält das heutige Glück kurz inne und rollt dann klappernd heraus."},"ICON-0923":{"nm":"Kachel-Ausrichtungsplatte","de":"Je begeisterter jemand spielt, desto schiefer werden die Reihen. Kacheln, die sich schräg stellen, sanft zurechtdrücken – das ist die Aufgabe. Ausrichten bedeutet, die Aufgeregtheit des anderen freundlich aufzufangen."},"ICON-0924":{"nm":"Punktechip-Behälter","de":"Je mehr Chips in einem Behälter zusammenkommen, desto heißer wird das Spiel. Wenn die runden Punkte in der Handfläche gegeneinanderklappern, freut man sich über den Klang, noch bevor man überhaupt gewonnen oder verloren hat."},"ICON-0925":{"nm":"Zugrings-Marker","de":"Ein kleiner Ring, der anzeigt: Jetzt bist du dran. In dem Moment, in dem man ihn ein Feld weiterrückt, ruhen alle Augen ruhig auf einem. Ein Ring, der langsam zwischen Warten und Vorfreude kreist."},"ICON-0926":{"nm":"Spielfigur-Sockel","de":"Je leichter eine Figur umfällt, desto stabiler muss ihr Fuß sein. Ein Sockel hält sie auch auf einem leicht wackelnden Spielfeld an ihrem Platz. Erst wenn das Kleine standhält, kann das Große darüber aufragen."},"ICON-0927":{"nm":"Regelwerk-Clip","de":"Das Regelwerk klappt immer von selbst zu, wenn es aufgeschlagen daliegt. Eine Klammer, die eine Seite festhält, bevor der Wind sie davonträgt. Nur wenn man die Regeln festhält, hält das Spiel bis zum Ende durch."},"ICON-0928":{"nm":"Gitarrenplektrum-Etui-Schnur","de":"Das Gitarrenplektrum schlüpft einem garantiert genau in der aufregendsten Stelle aus den Fingern. Eine am Etui befestigte Schnur verhindert dieses kleine Entkommen. Nur wer Nächte erlebt hat, an denen die Musik abbrach, ist für diese Schnur dankbar."},"ICON-0929":{"nm":"Blatt-Aufbewahrungs-Dose","de":"Ein Blatt verliert seinen Klang in dem Moment, in dem es austrocknet. Ein feines Schilfrohrblatt wartet in einer feuchten Dose auf das nächste Spiel. Ein Platz, an dem man Atem bewahrt, bevor man ihn einhaucht."},"ICON-0930":{"nm":"Saiten-Aufwickler","de":"Wenn die Saite locker wird, sinkt auch der Ton sachte. Durch langsames Drehen des Knopfes kehrt die Spannung zurück – Sorgfalt kommt stets aus dem Handgelenk. Sauberer Klang beginnt mit solch alltäglicher Pflege."},"ICON-0931":{"nm":"Instrument-Reinigungstuch","de":"Nach dem Spielen bleibt auf dem Instrument ein leichter Schweißfilm. Ein weiches Tuch, das einmal darübergeführt wird, beruhigt zusammen mit dem Glanz die Töne des Tages. Zuneigung zeigt sich immer im Abschluss."},"ICON-0932":{"nm":"Stimmwirbelabdeckung","de":"Stimmstifte rosten ungeschützt irgendwann von selbst. Eine kleine Abdeckung verzögert die Jahreszeiten des Metalls um einen Takt. Wer zuerst an die verborgenen Ecken denkt, spielt am längsten."},"ICON-0933":{"nm":"Notenständer-Klemmleuchte","de":"Hinter der dunklen Bühne gibt es Momente, in denen nur die Noten hell sein müssen. Ein kleines Licht, das am Notenständer befestigt ist und seinen Schein sanft nach unten wirft. Eine Handvoll Beleuchtung, damit die Noten den Weg nicht verlieren."},"ICON-0934":{"nm":"Übungs-Dämpferkappe","de":"Nachtübungen streiten sich immer leise mit dem Schlaf des Nachbarn. Eine Kappe, und der volle Klang schrumpft zum Flüstern. Es gibt Musik, die wächst, während sie den ruhigen Schlaf anderer schützt."},"ICON-0935":{"nm":"Drumpad-Sticker","de":"Kleine Markierungen auf dem Drumpad. Bevor die Hände es lernen, lernen die Augen zuerst den Weg – welche Fläche welchen Klang erzeugt. Der Rhythmus schreibt sich so langsam in den Körper ein."},"ICON-0936":{"nm":"Melodie-Notiz-Chip","de":"Eine vor sich hin gesummte Melodie verschwindet, wenn man sie nicht festhält. Ein paar hastig auf dem Chip notierte Takte können später zu einem ganzen Lied heranwachsen. Inspiration sucht immer wieder die fleißige Hand, die schreibt."},"ICON-0937":{"nm":"Buchcover-Band","de":"Ein halbgelesenes Buch, das sich in der Tasche von selbst aufschlägt, ist lästig. Ein Band hält die Seiten still. Ein ordentliches Versprechen, das Buch für das nächste Kapitel zusammenzuhalten."},"ICON-0938":{"nm":"Seitenhalter-Ring","de":"An Tagen, an denen man ein Buch mit einer Hand aufgeschlagen halten und dabei einen warmen Kaffee trinken möchte. Ein Ring am Finger hält die Seiten stellvertretend fest. Kleine Freiräume entstehen aus solch schlichten Erfindungen."},"ICON-0939":{"nm":"Lese-Timer-Chip","de":"Nur noch ein Kapitel, sagt man – und plötzlich ist es tief in der Nacht. Stellt man mit dem Chip eine Zeit ein, bekommt auch das Lesen eine Pause. Gerade bei Dingen, die man liebt, braucht man den freundlichen Mut zu stoppen."},"ICON-0940":{"nm":"Bucheckenschutz-Kappe","de":"Je lieber einem ein Buch ist, desto leiser beginnen die Ecken zu verschleißen. Eine Kappe schützt das Buchohr sanft. Eine kleine Rüstung, die den Wunsch birgt, das Lieblingsstück lange in der Nähe zu behalten."},"ICON-0941":{"nm":"Lese-Notizband","de":"Es gibt Momente, in denen einem ein einziger Satz den Atem verschlägt. Auf den Streifen übertragene Gedanken verweilen wie Lesezeichen auf dieser Seite. Die warme Temperatur eines Unterstrichs, die nur der Lesende kennt."},"ICON-0942":{"nm":"Bibliotheks-Rückgabeetikett","de":"Der Rückgabetermin kommt immer einen Tag früher als erwartet. Das auf dem Etikett notierte Datum schiebt sanft an – und auch ausgeliehenen Büchern gebührt die Höflichkeit eines Abschlusses. Die Bibliothek wartet so auf die nächste Hand."},"ICON-0943":{"nm":"Buch-Leseleuchte-Clip","de":"Nächtliches Lesen, während die Familie schläft. Ein kleines Licht, das am Ende des Buchdeckels hängt, reicht völlig aus. Man muss die Dunkelheit nicht ganz verdrängen – eine Seite genügt für diese stille Zeit."},"ICON-0944":{"nm":"Buch-Duftkarte","de":"Alte Bücher duften nach Sonnenschein und Papier, gemischt. Eine Karte, die diesen Duft eingefangen hat – aufgeklappt, und einen Moment lang erwacht die Gasse mit dem Antiquariat an der Nasenspitze. Erinnerungen setzen auch mit Gerüchen Lesezeichen."},"ICON-0945":{"nm":"Lesemarkierung-Pin","de":"Ein kleiner Pin, der die bange Frage auflöst: Wo war ich stehen geblieben? Am letzten Satz befestigt, muss das morgige Ich nicht mehr suchen. Eine freundliche Markierung, die die Unterbrechung im Gedächtnis behält."},"ICON-0946":{"nm":"Handyband-Ring","de":"Mit einem einzigen Ring am Handyband wirkt jemand gleich ein bisschen anders. Lieblingsfarbe, Lieblingsform. Das kleine Geschmacksstück in der Hand beeinflusst sachte die Stimmung des Tages."},"ICON-0947":{"nm":"Kameraobjektiv-Schutzkappe","de":"Das Schicksal eines Reisefotos hängt an einem einzigen Linsenblatt. Den Deckel abzunehmen ist gleichzeitig eine innere Vorbereitung auf den Auslöser. Ein kleines Ritual, bei dem die Augen zuerst aufgehen, bevor man die Landschaft einfängt."},"ICON-0948":{"nm":"Ladebuchse-Stöpsel","de":"Staub in der Tasche hat es immer auf das Ladeanschluss-Loch abgesehen. Ein Stöpsel schützt die kleine Öffnung, damit der Anschluss lange sauber bleibt. Auch die verborgenen Lücken zu bedenken – das ist der Eifer, der hier wohnt."},"ICON-0949":{"nm":"Handy-Aufsteller-Popring","de":"Ein Video entspannt anzuschauen, während man das Handy schräg hinstellt. Klappt man den Popring auf der Rückseite auf, gewinnen Hand und Bildschirm Spielraum. Ein kleiner, herausragender Halter dehnt den Abend angenehm in die Länge."},"ICON-0950":{"nm":"Display-Reinigungspatch","de":"Ein vollverschmiertes Display macht irgendwie auch die Gedanken trüb. Ein Wisch mit dem Patch, und die Welt wird wieder klar. Sauberkeit kann manchmal die kurze Arbeit eines einzigen Fingers sein."},"ICON-0951":{"nm":"SIM-Nadel-Etui","de":"Die SIM-Nadel ist eine Fee, die genau dann verschwindet, wenn man sie braucht. Legt man sie in ein Etui-Fach, durchsucht man nicht mehr das ganze Haus nach einer Haarnadel. Kleine Ordnung rettet im Notfall leise."},"ICON-0952":{"nm":"Kabelloses Ladegerät-Sticker","de":"Einfach ablegen, und über Nacht füllt es sich von selbst. Der aufgeklebte Sticker markiert dezent den Platz, auf den das Handy sich legen soll. Unsichtbarer Strom füllt lautlos die Energie des Tages auf."},"ICON-0953":{"nm":"Benachrichtigungs-Abdecksticker","de":"Manche Benachrichtigungen möchte man lieber nicht sehen – dann deckt man sie ab. Ein einzelner Sticker legt das kleine Nachtlicht schlafen. Manchmal ist das Nicht-Sehen auch eine freundliche Art, sich selbst zu schützen."},"ICON-0954":{"nm":"Kameralinsen-Schutzring","de":"In dem Moment, in dem das Kameraobjektiv den Boden berührt, sinkt einem das Herz. Ein umgelegter Ring fängt diesen kleinen Sturz ab. Ein Rahmen, der zuerst die Augen schützt, die Erinnerungen einfangen."},"ICON-0955":{"nm":"Kabel-Anhänger","de":"In einem Knäuel ineinander verdrillter Kabel das eigene herauszufinden. Ein Anhänger gibt dem Ladekabel endlich einen eigenen Namen. Ein kleines Fähnchen, das in dem verwirrenden Gewirr den Weg weist."},"ICON-0956":{"nm":"Ladegerät-Etui","de":"Ladegeräte in einer Reisetasche streiten sich immer und verheddern sich. In einem Etui-Fach ordentlich verstaut, vertragen sie sich endlich. Die Kunst des Packens liegt darin, Verstreutes freundlich an einen Ort zu rufen."},"ICON-0957":{"nm":"Mehrfachstecker-Etikett","de":"Alle Steckdosen der Steckleiste sehen gleich aus und bringen einen ständig durcheinander. Klebt man Etiketten auf und legt fest, wer welchen Platz hat, wird der hektische Morgen einfacher. Kleine Namensschilder verringern die kleinen Reibungen des Alltags."},"ICON-0958":{"nm":"Kabelaufroller","de":"Abwickeln, benutzen, wieder aufwickeln – so sieht der ordentliche Tag eines Kabels aus. Auf einer Rolle sauber aufgerollt, sind Verwirrungen wie weggeblasen. Die Hand, die nach Gebrauch alles an seinen Platz zurücklegt, macht den nächsten Tag leichter."},"ICON-0959":{"nm":"Magnetische Anschlusskappe","de":"Magnetische Anschlüsse ziehen unbemerkt winzige Eisenspäne an. Mit einer Kappe abgedeckt, bleibt kein klebriger Staub haften. Geräte, um die man sich einmal mehr gesorgt hat, halten länger."},"ICON-0960":{"nm":"Powerbank-Band","de":"Powerbank und Kabel verschwinden getrennt aufbewahrt immer abwechselnd. Mit einem Band zusammengebunden, bilden sie endlich ein Paar. Kurz vor dem Ausgehen zusammengebunden – ein kleiner Knoten, der sagt: Bleibt zusammen."},"ICON-0961":{"nm":"Stecker-Staubschutzkappe","de":"In einem leeren Steckdosenloch richtet sich binnen weniger Tage leise der Staub ein. Diese kleine Kappe bewacht den Platz stellvertretend – damit das nächste Ladegerät einen sauberen ersten Atemzug nehmen kann. Ein Türsteher, der die Leere ordentlich hütet."},"ICON-0962":{"nm":"Kabel-Farbring","de":"In jenem Knäuel Kabel nach dem eigenen tastend: Wer hatte damals die Idee, Farbe draufzutun? Blau gehört dir, Gelb gehört mir. Dank einem kleinen Ring verwechseln wir uns nicht mehr. Ein zärtliches Versprechen, das in einer Ecke des Proberaums geblieben ist."},"ICON-0963":{"nm":"Adapter-Sortier-Chip","de":"Runde Stifte und flache Stifte, 110 und 220. Ein Chip, der die verschiedenen Steckdosengesichter der Welt ruhig auswendig kennt. Früher hatte diese kleine Sortierkarte immer ihren Platz in der Ecke des Koffers, wenn man erstmals auf eine Bühne jenseits des Meeres reiste."},"ICON-0964":{"nm":"Ohrstöpsel-Sortiertablett","de":"Gehörgänge sollen von Mensch zu Mensch an Tiefe und Breite verschieden sein. Große, mittlere und kleine Paare nebeneinander legen und das passende Paar für das eigene Ohr wählen. Eine freundliche Prozedur, bei der man zuerst den Körper einstellt, bevor man Klang empfängt."},"ICON-0965":{"nm":"Case-Silikonring","de":"Für Bühnenkostüme wird jede einzelne Naht sorgfältig bedacht – und doch stoßen die Case-Ecken immer ungeschützt aneinander. Legt sich dieser dünne Silikonrand sanft drum herum, übersteht das Display selbst eine Morgenstunde, in der es aus der Hand gleitet. "},"ICON-0966":{"nm":"Noise-Cancelling-Sticker","de":"Es gibt Tage, an denen man die Geräusche der Welt kurz ausschalten möchte. Dieser kleine Sticker auf dem Kopfhörer-Ohr ist das Zeichen, das die Stille einschaltet. Jubel aus dem Zuschauerraum, U-Bahn-Lärm – beides wird bis zum Ende eines Lieds in die Ferne gerückt."},"ICON-0967":{"nm":"Ohr-Haken-Set","de":"Beim Tanzen fällt ein Ohrhörer immer zuerst heraus. Legt man diesen Ring, der die Ohrmuschel sanft umfasst, an, bleibt die Musik auch in der stürmischsten Choreografie bis zum Ende im Ohr. Eine kleine Entdeckung, die im Proberaum von Hand zu Hand weiterging."},"ICON-0968":{"nm":"Reinigungsbürsten-Kappe","de":"Eine kleine Mütze, damit der Staub an den Bürstenborsten nicht wieder aufgewirbelt wird. Auch das Werkzeug, das andere reinigt, braucht selbst Reinigung – das wussten Hände, die früher nach dem Fegen den Besen umgekehrt abgestellt haben, schon lange."},"ICON-0969":{"nm":"Ladestation-Bodenpad","de":"Die Ladestation rutschte immer auf dem Schreibtisch, weil sie keine Füße hatte. Dieses eine dünne Pad auf dem Boden übernimmt die Füße-Rolle, und das Gerät bleibt still an Ort und Stelle und lädt die ganze Nacht leise auf."},"ICON-0970":{"nm":"Links-Rechts-Markierung","de":"Links L, rechts R. Damit man auch im Dunkeln tastend erkennt: noch einen Punkt dazufügen. Der Wunsch, auf der Bühne mit dem linken und rechten Fuß niemals einen Fehler zu machen, ist in dieser kleinen Markierung ganz und gar eingebrannt."},"ICON-0971":{"nm":"Audio-Verteiler-Buchsen-Kappe","de":"Die Buchse, über die ein einziger Klang mit vielen geteilt wurde – ihr Ende muss in der Ruhepause verschlossen bleiben. Damit kein Staub in die Schaltkreise dringt. Eine kleine, behutsame Geste, damit das gemeinsam gehörte Lied auch das nächste Mal klar fließt."},"ICON-0972":{"nm":"Ohrhörer-Kabelwickler","de":"Wie die alten Handbewegungen beim Aufwickeln von Garnrollen – auch das Ohrhörerkabel wird hier ordentlich aufgerollt. Der Moment, in dem die in der Tasche herumrollende Musik geordnet wird. Das Morgen des Abwickelns wird ein Stück leichter."},"ICON-0973":{"nm":"Objektivdeckel-Halteband","de":"Jedes Mal, wenn man das Objektiv öffnete, hatte der Deckel nirgendwo hin. Einmal an der Kamera festgebunden, musste man nicht mehr umsonst in den Taschen suchen. Was man nicht verlieren will, bindet man in die Nähe – das lernen zuerst die Hände."},"ICON-0974":{"nm":"Blitzschuh-Zierkappe","de":"In den leeren Blitzschuh der Kamera schiebt man einen kleinen Schmuck. Dieser eine Anhänger ohne jede Funktion lässt das schwere, unnahbare Equipment plötzlich wie ein vertrautes Ding wirken. Sich an ein Werkzeug zu gewöhnen, es gern zu haben."},"ICON-0975":{"nm":"Gurtverstell-Schnalle","de":"Jedes Mal, wenn der Taschenriemen in die Schulter schneidet, löst und zieht man diese Schnalle ein wenig. Ein Fingerzeig, der die Länge an den eigenen Körper anpasst. Auch das Tragen von Lasten ist letztlich ein Akt der Selbstfürsorge, sagt die Schnalle leise."},"ICON-0976":{"nm":"Filterstapel-Etui","de":"Ein kleines Haus, in dem Glasscheiben, die Licht spalten, ordentlich übereinanderliegen. Dunst und Klarheit, Abendrot und Nacht. Wie eine Schublade, in der das Wetter vorab ausgewählt aufbewahrt wird – darum öffnet der Fotograf vor dem Aufbruch immer zuerst dieses Etui."},"ICON-0977":{"nm":"Blasebalg-Staubschutzkappe","de":"Der Gummiball, der Staub mit Luft vertreibt, ist selbst anfällig für Staub an der Öffnung. In der Ruhepause setzt man diese Kappe auf. Das Werkzeug, das andere reinigt, das seine Öffnung still verschließt – irgendwie ist das rührend."},"ICON-0978":{"nm":"Auslöserknopf-Abdeckung","de":"Dass der Auslöser in der Tasche unbeabsichtigt gedrückt wird und nur hundert Bilder des leeren Himmels entstehen – das kennt wohl jeder. Diese kleine Abdeckung über dem Knopf verhindert diese Mühe. Ein bescheidenes Schloss für die Momente, die man wirklich festhalten will."},"ICON-0979":{"nm":"Akku-Sortier-Sticker","de":"Verbrauchte und volle Akkus in derselben Tasche zu haben, ist immer peinlich. Farbige Sticker an jedem Akku schaffen leise Ordnung. Rot ist leer, Grün ist bereit. Eine stumme Ampel am Filmset."},"ICON-0980":{"nm":"Kamera-Taschen-Trennwand","de":"Im Inneren der Tasche wird mit Trennwänden verhindert, dass Objektiv, Body und Reserveakku gegeneinanderstoßen. In einem Gepäck kleine Zimmer anlegen. Jeder Platz hat einen Besitzer – selbst beim Schütteln geht nichts verloren."},"ICON-0981":{"nm":"Foto-Handschuh-Pad","de":"Bei Outdoor-Aufnahmen im Winter darf die Hand, die den Auslöser drückt, nicht frieren. Ein dickes Pad auf der Handfläche, Gefühl an den Fingerspitzen. Den Wunsch, Wärme und Präzision gleichzeitig in einer Hand zu halten – das ist der freundliche Kompromiss aus der Praxis."},"ICON-0982":{"nm":"Tablet-Stiftspitzen-Dose","de":"Dass auch Stiftspitzen sich abnutzen wie Bleistiftminen, wissen nur Menschen, die ein Tablet lange in der Hand gehalten haben. Diese kleine Dose, in der Ersatzspitzen aufbewahrt werden, ist wie eine Notreserve an den Fingerkuppen, damit kein Strich abreißen muss."},"ICON-0983":{"nm":"Tastatur-Keycap-Tablett","de":"An dem Tag, an dem man alle Keycaps einzeln abzog und wusch und wieder aufsetzte, diente dieses Tablett als kleines Watt. Konsonanten und Vokale lagen in ihren Fächern und trockneten. Auch Sorgfalt, die erst nach dem Zerlegen sichtbar wird, existiert."},"ICON-0984":{"nm":"Maus-Gleitfüße-Pack","de":"Das Geheimnis, warum die Maus auf dem Schreibtisch wie gleitend fährt, liegt in diesen kleinen Füßen unter dem Boden. Ein Bündel zum Auswechseln, wenn sie abgenutzt sind. Der stille Einsatz der Unsichtbaren, die das Gleiten tragen."},"ICON-0985":{"nm":"Laptop-Gummi-Standfuß","de":"Sieht aus wie ein Notizbuch, ist aber eigentlich ein Gummistand für den Laptop. Hebt den Bildschirm leicht auf Augenhöhe und richtet den gebeugten Nacken auf. Eine Fürsorge, die die Haltung aufrichtet, für alle, die lange schreiben und lange hinschauen."},"ICON-0986":{"nm":"Webcam-Schiebe-Abdeckung","de":"Den Finger über die Linse schieben und schließen, wieder öffnen. Sehen zu wollen – nur dann, wenn man selbst es will. In diesem kleinen Schieber steckt das große Beruhigungsgefühl namens Privatsphäre. Das Schließgeräusch klingt irgendwie verlässlich."},"ICON-0987":{"nm":"USB-Sortier-Etikett","de":"Fünf ähnliche schwarze Stäbchen – unmöglich zu wissen, was in welchem steckt. Klebt man kleine Etiketten auf und gibt jedem einen Namen, werden sie erst wirkliche Familienmitglieder. Man findet nur leicht, wovon man den Namen kennt."},"ICON-0988":{"nm":"Schreibtischpad-Ecken-Halter","de":"Wenn die Ecken des Schreibtischpads immer wieder hochrollen, werden selbst Handschriften schief. Dieses kleine Teil, das die vier Ecken sanft niederdrückt, hütet den flachen Frieden auf dem Schreibtisch. Erst wenn der Boden ruhig ist, werden auch die Finger ruhig."},"ICON-0989":{"nm":"Hub-Ständer-Clip","de":"Eine Klammer, die den Hub, in dem viele Kabel zusammenlaufen, schräg an die Schreibtischkante stellt. Verwirrende Kabel finden in einem Punkt zusammen und werden ordentlich. Auch hier lebt das Handgefühl, Verfilztes in einen einzigen Strang zu bringen."},"ICON-0990":{"nm":"Displayreinigungsspray-Kappe","de":"Der kleine Verschluss des Sprays, das Fingerabdrücke auf dem Display wegwischt. Immer fest schließen, damit die Flüssigkeit nicht ausläuft oder eintrocknet. Die schlichte Reihenfolge der Haushaltsführung: Um klar zu sehen, muss man zuerst das Reinigungsmittel schonen."},"ICON-0991":{"nm":"Speicherkarten-Etui","de":"Die Bühnenvideos von mehreren Tagen schlafen still in einer einzigen, daumennagel-großen Karte. Geht sie verloren, verschwindet ein ganzer Tag spurlos – also bewahrt man sie sorgfältig in einem kleinen Etui auf. Ein Haus für die kleinste und größte Erinnerung zugleich."},"ICON-0992":{"nm":"Externe Festplatten-Etikett","de":"Fünf schwarze externe Festplatten schlafen mit demselben Gesicht in der Schublade. Etiketten aufkleben und sie 'Jener Sommer' oder 'Unveröffentlichte Clips' nennen. Eine Arbeit, die den unklaren Erinnerungen einen deutlichen Index gibt."},"ICON-0993":{"nm":"Backup-Check-Chip","de":"Ob man schon gesichert hat oder nicht – dieser Hauch von Unterschied macht einem das Herz schwer. Dieser kleine Chip, den man in den fertigen Platz steckt, sagt: 'Bis hierher ist es sicher.' Beruhigung kommt davon, eine Markierung zu hinterlassen."},"ICON-0994":{"nm":"Cloud-Notiz-Token","de":"Ein Token, der eine einzelne Notizzeile in ein irgendwo in der Luft schwebendes Archiv schickt. Wo immer man den Bildschirm aufklappt, kommt dieser Text einem entgegen – ein kleines Wunder. Als würde der Nachthimmel, in den man einst Drachen mit Wünschen steigen ließ, sanft auf die Handfläche heruntersinken."},"ICON-0995":{"nm":"USB-Schutzkappe-Set","de":"Wenn der Anschluss unbedeckt in der Tasche liegt, wird das Kontaktstück beschädigt. Jedes Ende bekommt ein kleines Hütchen – ein komplettes Set. Die Zeit, in der man es nicht benutzt, ordentlich wegschlafen lassen. Die stillste Vorbereitung für die nächste Verbindung."},"ICON-0996":{"nm":"Datenträger-Hüllband","de":"Ein Band, das das Gerät mit den wertvollen Daten vollständig umschlingt und zusammenhält. In der schwankenden Tasche damit es nicht aneinanderstößt – einmal herumgewickelt und fest verschnürt. Die sorgfältige Hand, die früher Bündel band, lebt auch im Digitalen weiter."},"ICON-0997":{"nm":"Datei-Sortier-Tag","de":"Wenn Hunderte von Dateien ohne Namen aufgestapelt werden, wird das Suchen zum Irren. In dem Moment, in dem man farbige Tags anhängt und Wege anlegt, öffnet sich durch das unordentliche Häufchen ein Pfad. Ordnen bedeutet letztlich, Wege zu schaffen."},"ICON-0998":{"nm":"Passwort-Hinweiskarte","de":"Das vollständige Passwort aufzuschreiben ist gefährlich, es gar nicht aufzuschreiben bedeutet Vergessen. Also notiert man nur die Hinweise, die man selbst versteht. 'Die Stadt des ersten Auftritts.' Keine Antwort, sondern einen Pfad aufzuschreiben – eine kluge und zärtliche Gedächtnistechnik."},"ICON-0999":{"nm":"Einlagerungs-Datumssticker","de":"Was man ohne eingetragenes Datum einlagert, wird bald vergessen. An jeder Schachtel angebrachte Datumssticker halten das 'Seit wann' fest. Die Gesinnung der alten Speisekammer, auf der der Einlegetag der fermentierten Paste stand, lebt auf diesem kleinen Papierstück weiter."},"ICON-1000":{"nm":"Mini-Ringlicht-Kappe","de":"Eine Kappe, die die Öffnung des kleinen runden Lichts abdeckt. Sie bewahrt das Objektiv in der Tasche vor Kratzern und legt das Licht kurz schlafen. Auch das Hüten der Dunkelheit vor dem Einschalten ist eine Art, das Helle zu schonen."},"ICON-1001":{"nm":"Halterung-Klemmschraube","de":"Noch eine halbe Umdrehung mehr. Der lockere Spalt verschwindet, und eine stabile Verlässlichkeit legt sich in die Handfläche. Hinter jeder standfesten Bühne verbirgt sich immer ein beherztes Handgelenk, das zuvor gedreht hat. Was eine kleine Schraube trägt, ist unsichtbare Stärke."},"ICON-1002":{"nm":"Auf-Sendung-Markierungs-Chip","de":"In dem Moment, in dem das rote Licht aufleuchtet, gehen die Schritte auf dem Korridor auf Zehenspitzen. 'Sendung läuft' – vor diesem einen Wort halten alle den Atem an. Dass selbst die Stille hinter der Tür eine Zuwendung an jemanden ist, das teilt dieser kleine Chip leise mit."},"ICON-1003":{"nm":"Chat-Notizpad","de":"Mit den Fingerspitzen die Fangrüße auffangen, die über den Bildschirm fliegen. Wort für Wort, die sonst vorbeirauschen würden, verweilen sorgfältig auf Papier. Aufzeichnen ist der Platz, an dem Zärtlichkeit wohnt, die auch spät noch ankommen möchte."},"ICON-1004":{"nm":"Lautlose Tastaturabdeckung","de":"Zwei Uhr morgens – und das Tippgeräusch verschwindet wie gelogen. Eine dünne Schicht, damit der tief schlafende Mitbewohner nicht aufwacht. Die leiseste Fürsorge beginnt immer dort, wo kein Laut zu hören ist."},"ICON-1005":{"nm":"Mikrofonarm-Clip","de":"Der genaue Abstand zwischen Lippen und Mikrofon, bei dem die Stimme nicht ins Wanken gerät. Dieser kleine Clip hält dieses Versprechen fest. Hinter der Bühne wartet stets diese feste, stützende Hand zuerst."},"ICON-1006":{"nm":"Hintergrundstoff-Klemme","de":"Auch wenn der Wind bläst, rührt sich der Hintergrundstoff nicht. Denn eine kleine Zange an jeder Ecke hält die gesamte Szene zusammen. Hinter jeder unerschütterlichen Kulisse steht jemand, der im Verborgenen die Zähne zusammenbeißt."},"ICON-1007":{"nm":"Stream-Deck-Etikett","de":"Auf Dutzenden von Tasten lässt sich die Hand dank kleiner Namensschildchen nicht verirren. Eine einzige Etikettzeile löscht im Voraus einen Fehler aus der Live-Sendung. Gelassenheit kommt von Buchstaben, die man aufgeschrieben hat, bevor man aufgeregt wurde."},"ICON-1008":{"nm":"Zeitstempel-Taste","de":"Drückt man sie, pflanzt sich ein kleines Fähnchen in den Fluss der Zeit. Dem Jetzt, das nie zurückkommt, einen Stempel geben. Schaut man lange danach zurück, ist diese Markierung zur Tür geworden, durch die man in die Erinnerung eintritt."},"ICON-1009":{"nm":"Tag-Leser-Schlüsselring","de":"Dranhalten, und tik – die Information erwacht. Ein kleiner Begleiter, der klappernd in der Tasche baumelt. Gewöhnliche Tage werden durch solche schlichten Signaltöne heil weitergefädelt."},"ICON-1010":{"nm":"Smart-Plug-Etikett","de":"Gibt man jeder Steckdose einen Namen, muss man nie mehr rätseln, welches Kabel wohin gehört. Dem unsichtbaren Strom selbst einen Namen zuzuweisen – das ist eine Gesinnung. Ordnung ist ein anderes Gesicht, das sich die Zärtlichkeit kurz ausleiht."},"ICON-1011":{"nm":"Temperatur- und Feuchtigkeitssensor-Ständer","de":"Ein handflächengroßer Wächter, der Temperatur und Feuchtigkeit im Zimmer wortlos beobachtet. Behaglichkeit spricht nicht, aber dieser Ständer kümmert sich in jedem Moment still um deine Verfassung. So wird Wohlbefinden leise bewacht."},"ICON-1012":{"nm":"Türöffnungssensor-Kappe","de":"Ein kleines Auge, das den flüchtigen Moment nicht verpasst, in dem eine Tür sich sachte öffnet. Lautlos teilt es mit, dass jemand zurückgekehrt ist. Leere Häuser zu hüten – das übernehmen immer diese wortlosen Dinge."},"ICON-1013":{"nm":"Fernbedienungs-Halter","de":"Die überall herumrollenden Fernbedienungen finden endlich jede ihren eigenen Platz. Ein kleiner Halt, der das Verlorenzugehen sanft verhindert – Hände, die ein Wiedersehen schon im Voraus einschreiben."},"ICON-1014":{"nm":"Schlaf-App-Token","de":"Für jede ausgeschlafene Nacht rollt ein runder Beweis sachte hinzu. Auch Schlafen wird wie eine Übung Schritt für Schritt angesammelt, sagt die App freundlich. Das kleinste Belohnungsstück der Welt, überreicht an dich, der gut geruht hat."},"ICON-1015":{"nm":"Timer-Würfel-Untersetzer","de":"Während drei Minuten genau verstreichen, zählt der Würfel unerschütterlich seine Zeit. Ein handflächengroßer Platz, der ihn dabei sanft trägt. Auch das Warten braucht einen Boden, auf dem man unbesorgt stehen kann."},"ICON-1016":{"nm":"Benachrichtigungslampen-Abdeckung","de":"Nicht zu grell – das Licht wird in einer Schicht sanft umhüllt. Damit die Benachrichtigung zwar dringlich ist, die Augen aber ruhig bleiben. Fürsorge bedeutet, auch die Stärke des Lichts still abzuwägen."},"ICON-1017":{"nm":"Akku-Wechselkarte","de":"Wenn diese Karte erscheint, ist es Zeit, das kleine Herz im Gerät auszuwechseln. Ein freundlicher Hinweis: Kümmere dich, bevor es aufhört. Das Geheimnis langen Zusammenseins liegt immer im einen Takt früheren Hinsehen."},"ICON-1018":{"nm":"Joystick-Kappen-Set","de":"Kleine Mützchen, die man aufsetzt, damit der Daumen nicht abrutscht. Das Fingerspitzengefühl wird eine Spur klarer. Diese winzige Kappe kann über Sieg und Niederlage in einer schweißnassen Runde entscheiden."},"ICON-1019":{"nm":"Switch-Dock-Abdeckung","de":"Deckt den Ruheplatz der Konsole sanft vor Staub ab. Denn auch ein schlafendes Gerät braucht eine Decke. Die Zuneigung zeigt sich am deutlichsten gerade dann, wenn man etwas nicht benutzt."},"ICON-1020":{"nm":"Portable-Konsolen-Tasche","de":"Beim Unterwegs-Sein kommt es grundsätzlich hier rein. Eine Tasche, die die tragbare Konsole weich umhüllt. Damit sie in der Reisetasche, egal wie es schüttelt, nichts abbekommt – Wertvolles wickelt man lieber einmal mehr ein."},"ICON-1021":{"nm":"Tasten-Sticker-Ring","de":"Klebt man nur ein kleines Bild auf eine schlichte Taste, gehört sie in diesem Moment einem ganz allein. Auf demselben Gerät ein eigenes Zeichen zu hinterlassen. Persönlichkeit blüht immer leise an solch unbedeutenden Plätzen auf."},"ICON-1022":{"nm":"Spielkarten-Etui","de":"Eine ganze Nacht Spielversunkenheit schläft in diesem kleinen Etui friedlich. Öffnet man den Deckel wieder, erwacht jene Nacht unversehrt. Erinnerungen passen manchmal überraschend gut in eine handflächengroße Schachtel."},"ICON-1023":{"nm":"Kühllüfter-Untersetzer","de":"Während der Wind die Hitze abkühlt, ein schräger Untersetzer, der das Gerät trägt. Er schafft eine Atempause für den überhitzten Körper. Wer weit laufen will, muss auch wissen, wann er anhält und sich abkühlt."},"ICON-1024":{"nm":"Handgelenkschlaufen-Pin","de":"Legt man ihn ums Handgelenk und verschließt den Pin, bleibt der Controller selbst bei heftigen Bewegungen nicht zurück. Diese unbequem aussehende Schnur ist in Wirklichkeit die Sicherheit, die einen unbesorgt herumtollen lässt."},"ICON-1025":{"nm":"Analog-Grip-Kappe","de":"Auf dem alt-vertrauten, blank gegriffenen Griff ein neues Kleid anlegen. Das eingeübte Gefühl bleibt, nur die Oberfläche ist neu. Ein Moment, in dem Vertrautheit und Aufregung nebeneinander in einer Hand wohnen."},"ICON-1026":{"nm":"Speicherschlitz-Etikett","de":"In jedem Speicherfeld wird sorgfältig notiert, wessen Abenteuer darin steckt. Eine Etikettzeile bewacht stumm die Reise der vergangenen Tage. Kostbare Erinnerungen verdienen einen eingravierten Namen, damit sie nicht überschrieben werden."},"ICON-1027":{"nm":"Diktiergerät-Tasche","de":"Das Gerät, das Klang aufbewahrt, ist wegen seines Inhalts umso wertvoller. Es wird sorgfältig in einer weichen Tasche untergebracht. Denn vielleicht schläft dort die Stimme von jemandem – umso behutsamer."},"ICON-1028":{"nm":"Windschutz-Kappe","de":"Windgeräusche herausfiltern und nur die Stimme behalten. Ein flaumiges Hütchen, das beim Außendreh aufs Mikrofon gesetzt wird. Ein kleines Sieb, das in einem Gewirr störender Geräusche nur das Aufrichtige herausfischt."},"ICON-1029":{"nm":"Sprachnotiz-Etikett","de":"Das hier ist ein aufgekommener Liedtext, das hier eine gesummte Melodie. Jede Sprachnotiz bekommt ein farbiges Namensschildchen. Die überall zerstreuten Inspirationsfetzen finden endlich ihren Platz und stellen sich in Reih und Glied."},"ICON-1030":{"nm":"Sampling-Tasten-Chip","de":"Drückt man ihn, springt ein vorher eingefangener Klangsplitter heraus. Regentropfen, Applaus, jemandes Lachen – Fragmente der Welt erwachen an den Fingerspitzen. Musik ist der zärtliche Chor solcher kleinen Chips."},"ICON-1031":{"nm":"Klangsammel-Beutel","de":"Klangsplitter, die man beim Gehen zufällig aufgesammelt hat, legt man sachte in diesen Beutel. Das Wesen des Winds, die Stille einer Morgendämmerungsgasse. Die Rohstoffe, die eines Tages ein Lied werden, sammeln sich immer so schlicht."},"ICON-1032":{"nm":"Mini-Stativ-Beine","de":"Drei Beine entfalten auf dem Schreibtisch eine kleine Bühne. Statt zitternder Hände stehen sie fest und halten das Bild. Ein klarer Schnappschuss wird erst von diesen drei reglos stehenden Beinen geboren."},"ICON-1033":{"nm":"Aufnahmedatei-Tag","de":"An hunderten von Aufnahmedateien wird eine nach der anderen kurz beschriftet. Damit man auf einen Blick erkennt, ob es die erste Strophe von damals war. Ein kleiner Wegweiser, der verstreute Stimmen zurückfindet."},"ICON-1034":{"nm":"Wellenform-Sticker-Band","de":"Ein Wellenlinienband, das die Form des Klangs originalgetreu nachzeichnet. Um ein Heft oder ein Etui gewickelt, wirkt es, als wäre Musik vor Augen zu sehen. Eine freundliche Täuschung, die Hörbares sichtbar macht."},"ICON-1035":{"nm":"Headset-Aufhänge-Pin","de":"Wenn die Übung endet, bereitet dieser Pin dem erschöpften Headset einen Ruheplatz. Ein kleiner Haken, der in die Schreibtischkante gesteckt wird. Ein aufgeräumter Schreibtisch ist ein Ort, an dem man die Energie für den nächsten Tag schon im Voraus aufhängt."},"ICON-1036":{"nm":"Kleines Geschenkbox-Band","de":"Die letzte Runde um die Taille der Geschenkbox. Mit diesem einen Band wird das Herzgefühl erst vollständig. Zuneigung gelangt eher über die streichelnde Hand, die das Äußere glattstreicht, als über das, was darin liegt."},"ICON-1037":{"nm":"Schleifenende-Kappe","de":"Das Schleifenende wird sanft umhüllt, damit es sich nicht löst. Ein einziges kaum sichtbares Detail verändert den ersten Eindruck des Geschenks unmerklich. Ist das Ende sauber, kommt auch das Herzgefühl sauber an."},"ICON-1038":{"nm":"Siegelwachs","de":"Einen heißen Tropfen herunterfallen lassen und das Kuvert versiegeln. Wie bei einem alten Brief – ein gewichtiges Versprechen: Bitte nicht achtlos öffnen. Förmlichkeit kann manchmal so ein warmes Gewicht tragen."},"ICON-1039":{"nm":"Dankeskarten-Halter","de":"Damit die Karte, in der man sich bedankt, sich nicht verbiegt und gerade ankommt. Damit das Herzgefühl aufrecht stehend übermittelt wird. Dankbarkeit hinterlässt sich tiefer im Gedächtnis, wenn auch ihre Form ordentlich ist."},"ICON-1040":{"nm":"Sternförmiges Füllpapier","de":"In Sternform ausgeschnittene Papierstücke füllen die Lücken in der Schachtel weich aus. Die Sorge in Watte-Form: Bitte komm unbeschadet an. Selbst in der Dunkelheit des Kartons leuchtet ein kleiner Stern."},"ICON-1041":{"nm":"Geschenklisten-Tag","de":"Vor dem Feld für den Empfänger macht der Stift eine lange Pause. Im Moment des Aufschreibens des Namens taucht ein Gesicht auf – eine gemeinsame Jahreszeit. Von dem Moment an, in dem das Bändchen gebunden ist, ist dieses kleine Stück Papier ein Geheimnis, das bis zum Öffnen niemand lesen kann."},"ICON-1042":{"nm":"Glückwunsch-Stempel-Ring","de":"Drückt man ihn, erscheint ein rundes Glückwunschmotiv klar aufgedruckt. In dem kurzen Moment, in dem man wartet, bis die Tinte trocknet, ist das Überlegen, wem man es überreicht, am wärmsten. Wenn es einen Makel gibt, dann den, dass man noch einmal stempeln möchte."},"ICON-1043":{"nm":"Verpackungsschnur-Spule","de":"Sorgfältig aufgerollt, bis sie von aufgeregten Fingerspitzen fröhlich abgerollt wird. In dem kurzen Moment des Auf- und Abrollens wird ein auf dem Faden gebundenes Herzgefühl endlich zum Geschenk."},"ICON-1044":{"nm":"Kleiner Knoten-Anhänger (keine Blume)","de":"Nicht eine Blume imitierend, sondern ein Faden, der den eigenen Körper mehrfach umarmte und von selbst erblühte. Die Geduld der Fingerkuppen, die die ganze Nacht Knoten geordnet haben, blieb als diese kleine Knospe zurück."},"ICON-1045":{"nm":"Glücksmünzen-Beutelchen","de":"Das Herzgefühl, dem Aufbrechenden heimlich ein paar Münzen in die Tasche zu stecken. Nicht das Gewicht, sondern die Zärtlichkeit füllt ihn. Mit jedem Schritt klingert der Beutel – ein Abschiedsgruß: Komm gut hin."},"ICON-1046":{"nm":"Wunschkapsel-Anhänger","de":"In der runden Kapsel schläft ein gefalteter Wunsch friedlich. Zu sagen, er erfülle sich beim Öffnen, ist eine Lüge – aber dass der Wunsch ewig lebt, solange man ihn verschlossen trägt, das ist wahr."},"ICON-1047":{"nm":"Schutzknoten-Schnur","de":"Fest geflochten aus bunten Fäden, um böse Einflüsse abzuwehren. Wie die Hand der Großmutter, die früher einen Knoten ums Handgelenk band – an jeder gebundenen Stelle ist jemandes stilles Gebet sauber eingewirkt."},"ICON-1048":{"nm":"Kleiner Papierkranich-Etui","de":"Ein kleines Haus, das den einzigen Kranich, den man nach tausend Faltungen gefaltet haben soll, damit er ein Wunsch wird, vor Beschädigung bewahrt. Denn bricht auch nur ein Flügel, löst sich die ganze Nacht Hingabe wieder auf."},"ICON-1049":{"nm":"Glitzersteinchen-Beutel","de":"Die kleinen Lichtkörnchen, die vom Bühnenkostüm abgefallen sind – zu schade zum Wegwerfen, also wischt man sie zusammen. Auch das Glitzern, das sich einmal angehaftet hat und eine Woche folgt, schläft hier ruhig wie in einer Handfläche."},"ICON-1050":{"nm":"Glückszeichen-Stempel-Chip","de":"Ein kleiner Chip, den man heimlich dazulegt, wenn man einen guten Tag aussucht. Nicht vor der Tür eines Wahrsagers, sondern auf dem eigenen Schreibtisch – für diesen einen Tag nur Gutes, sagt man leise. Ein Stückchen freundlichen Aberglaubens."},"ICON-1051":{"nm":"Wunscharmband-Karte","de":"Auf einem einzigen Blatt Papier, gedruckt in Armband-Form, ruht jemandes stilles Gebet. Auch wenn man es nicht ums Handgelenk legen kann – tief in die Brieftasche gesteckt, bleibt dieses Gefühl stets an der Seite und geht jeden Schritt mit."},"ICON-1052":{"nm":"Salztopf für den Eingang","de":"Grobes Salz, still in ein kleines Fläschchen gefüllt und vor die Tür gestellt. Ein alter Brauch, der böse Geister fernhalten und nur willkommene Gäste hereinlassen soll. Jedes einzelne Salzkorn ist ein kleiner Wächter, der das Zuhause beschützt."},"ICON-1053":{"nm":"Rubbellos-Abdeckung","de":"Kurz vor dem Rubbeln ist jeder für einen Moment Gewinner. Diese Abdeckung, die die Glückszahl sanft verbirgt, hütet die letzte Sekunde, in der die Vorfreude am größten ist. Selbst wenn die Hand dabei zittert, schaut sie diskret weg."},"ICON-1054":{"nm":"Geburtstagskerzenschutzkappe","de":"Eine pfiffige Kappe, um selbst eine bereits angezündete Kerze sicher bis zum nächsten Geburtstag aufzubewahren. Wenn der letzte Wunsch noch nicht in Erfüllung gegangen ist, kann man ihn einfach an derselben Stelle weiterwünschen – eine herzliche Lebensweisheit."},"ICON-1055":{"nm":"Jubiläums-Countdown-Ring","de":"Ein freches Ding, das den Countdown am Finger trägt. Wenn die Zahl jeden Tag um eins weiterrückt, springt das Herz genauso weit nach vorne. Am Tag der Null leuchtet er von selbst auf – zumindest behauptet er das stur von sich."},"ICON-1056":{"nm":"Partyhütchen-Schnur","de":"Die dünne Schnur, die ein Partyhütchen sanft auf dem Kopf hält. Zwar nimmt es die Hauptperson bald wieder ab, weil es drückt – doch auf dem Foto bleibt das Hütchen für immer aufgesetzt. Das war auch schon sein ganzer Auftrag."},"ICON-1057":{"nm":"Minitorte-Picker","de":"Ein kleines Schild, das in eine gerade zwei Finger große Torte gesteckt wird. Selbst auf einem Häppchen, das in einem Bissen verschwunden ist, behauptet die Feier stolz ihre Größe. Klein hin oder her – Geburtstag bleibt Geburtstag, und du bist heute der Star."},"ICON-1058":{"nm":"Konfetti-Knaller-Aufkleber","de":"Ein Papierknaller, der ohne Knall trotzdem am prächtigsten aussieht. Sobald er auf einem Umschlag klebt, verwandelt sich gewöhnliche Post in einen Brief vom Festtisch. Viele können sich nicht überwinden, ihn abzuziehen."},"ICON-1059":{"nm":"Foto-Wäschelinien-Klammer","de":"Damit keine Erinnerung von der Leine fällt, kneife ich meinen Mund stets fest zusammen. Solange ein Foto nach dem anderen darin hängt, fallen diese Momente auch im stärksten Durchzug nicht herunter."},"ICON-1060":{"nm":"Datums-Ballon-Patch","de":"Ein Aufnäher in Ballonform mit einer Zahl darauf. Wer ihn auf die Kleidung klebt, lässt die ganze Nachbarschaft wissen, wie viele besondere Tage es heute schon sind. Beim Ablösen bleibt ein Abdruck zurück – doch auch dieser blasse Fleck ist eine Erinnerung."},"ICON-1061":{"nm":"Geschenketausch-Markierung","de":"Eine schelmische Markierung, die ein kleines Durcheinander stiftet zwischen dem, der gab, und dem, der empfing. Die kleine, herzliche Regel des Schenkens lautet: Nicht wer gegeben hat ist wichtig, sondern was dabei übertragen wurde."},"ICON-1062":{"nm":"Jubiläums-Tischnummer","de":"Eine kleine Nummer, die bei jedem Festtisch aufgestellt wird. Wer vorab bestimmt, wer wo sitzt, erspart peinliches Suchen – eine herzliche Weisheit derer, die schon viele Feste ausgerichtet haben."},"ICON-1063":{"nm":"Türgriff-Geschenktasche","de":"Eine Methode, Zuneigung zu zeigen, ohne klingeln zu müssen. Wer sie still an den Türgriff hängt und dann eilig davonläuft, bekommt das überraschte Gesicht des Beschenkten als größtes Geschenk zurück."},"ICON-1064":{"nm":"Geheimversand-Etikett","de":"Auf der Außenseite steht gar nichts. Es ist der kleine Stolz dieses Etiketts, den Absender bis zuletzt zu verbergen. Je länger der Empfänger rätselt und lächelt, desto vollkommener gelingt seine geheimnisvolle Mission."},"ICON-1065":{"nm":"Türklingel-Notiz-Chip","de":"Ein kleiner Zettel, den man anbringt, wenn man nicht den Mut hat, anzuklingeln. Ein kurzer Satz wie 'War kurz vorbei' bleibt länger als ein Klingelton. Denn in schiefer Handschrift steckt ein Gesichtsausdruck."},"ICON-1066":{"nm":"Paketmesser-Schutzkappe","de":"Wenn die Klinge des Paketmessers unachtsam nach dem Finger schnappt, tritt dieser kleine Held ruhig dazwischen. Er schützt die vor Vorfreude hastige Hand bis zum allerletzten Schnitt."},"ICON-1067":{"nm":"Luftpolsterfolie-Stück","de":"Ich bin dazu da, gedrückt zu werden. Bei dem kleinen Knall löst sich merkwürdigerweise die Anspannung des Tages. Manchmal werde ich länger geliebt als der Inhalt, den ich einst geschützt habe."},"ICON-1068":{"nm":"Lieferzeitpin","de":"Ein Pin, der genau festhält, wann die Lieferung ankommt. Selbst das unbestimmte Warten wird erträglicher, sobald es eine Koordinate bekommt. Wie oft man bis zu dieser Stunde zur Haustür schaut, ist allein Sache des Empfängers."},"ICON-1069":{"nm":"Packstation-Schlüsselanhänger","de":"Ein kleiner Begleiter für alle, die den Paketfach-Code immer wieder vergessen. Am Schlüsselbund baumelnd, entlockt er im entscheidenden Moment ein erlöstes 'Ach ja' – das ist seine stille Spezialität."},"ICON-1070":{"nm":"Eingangskorb-Etikett","de":"Ein Namensschild am Korb in der Hausecke. Es trägt die stille Botschaft: 'Bitte hier ablegen.' Selbst wenn er leer steht, ist ein Platz, der auf jemandes Gedanken wartet, niemals einsam."},"ICON-1071":{"nm":"Adress-Schwärz-Aufkleber","de":"Auf dem Karton, der entsorgt wird: den Namen lassen, die Adresse einfach abdecken. Was jeder wissen darf, endet beim Namen – wo man wohnt, bleibt das eigene Geheimnis. Eine Lage draufgeklebt, und schon ist man ein kleines Stück ruhiger."},"ICON-1072":{"nm":"Snackdosen-Etikett","de":"Ein Etikett, das auf einen Blick zeigt, was in der Dose steckt. Dabei ist es seltsam tröstlich, wenn 'Snacks' draufsteht – auch ohne den Deckel zu öffnen. Das Etikett ist nicht für den Hunger zuständig."},"ICON-1073":{"nm":"Kleiner Halsketten-Anhänger","de":"Ein kleines Stück, das still die Körperwärme teilt, verborgen unter der Kleidung. Gerade weil es niemand sieht und es doch immer nah ist, wird es umso inniger. Der nächste Gefährte, der gemeinsam mit dem Herzen geht."},"ICON-1074":{"nm":"Fußabdruck-Stempelunterlage","de":"Drückt man die Pfote auf, hinterlässt sie eine Reihe kleiner Abdrücke. Ein Spaziertagebuch, das auf Papier festhält, wer wohin gegangen ist. Der erste Schritt mit Tinte ist stets der deutlichste."},"ICON-1075":{"nm":"Fellbürsten-Schutzkappe","de":"Eine kleine Kappe, die sich um das im Kamm verhedderte Fell kümmert. In der Übergangszeit, wenn eine Handvoll Fell mit jedem Kämmen kommt, würde ohne diese Kappe das ganze Haus zu einer weichen Schneelandschaft. Ein stiller, fleißiger Hausputzer."},"ICON-1076":{"nm":"Spaziergang-Beutel-Halter","de":"Ein kleines Etui, das die Tütchen für den Spaziergang ordentlich aufbewahrt. Wer vorausdenkt, geht entspannt – das beweist dieser Halter täglich aufs Neue. Die eine Tüte, die man vergessen hat, macht alles schwierig."},"ICON-1077":{"nm":"Namens-Verhüllungs-Tag","de":"Ein Etikett, das den echten Namen verbirgt und nur den Spitznamen zeigt. Manche Zärtlichkeiten möchte man nicht mit allen teilen. Die Anrede, die nur Eingeweihte kennen, schlummert hier versteckt."},"ICON-1078":{"nm":"Wassernapf-Unterlage","de":"Ich liege unter dem Wassernapf und bin stets feucht. Die umherspritzenden Wassertropfen nehme ich auf, damit der Boden trocken bleibt. Niemand lobt mich dafür – aber ich beschwere mich auch nicht."},"ICON-1079":{"nm":"Spielzeug-Reparaturfaden","de":"Ein aufgerissenes Plüschtier wirft man nicht weg – man näht es wieder zusammen. Mit jedem Stich festigt sich die gemeinsam verbrachte Zeit mit dem Kind. Reparieren heißt letztlich, den Abschied still hinauszuzögern."},"ICON-1080":{"nm":"Erinnerungsfoto-Halskette","de":"Das strahlendste Lachen trägt man als Bild um den Hals. Statt eingefroren zu sein, schwingt dieser Tag mit jedem Schritt bis heute mit. Schöne Momente hören nicht auf."},"ICON-1081":{"nm":"Stimmungs-Farbchip","de":"Wenn auch Gefühle eine Farbe hätten – welche Farbe wärst du heute? Sobald man einen Chip wählt und ihn auf den Schreibtisch legt, breitet sich still aus, was sich in Worte kaum fassen ließ. Abendrot oder Morgendämmerung – ein kleiner Spiegel, der den Tag in einem still widerspiegelt."},"ICON-1082":{"nm":"Tagesgedächtnis-Murmel","de":"Wenn der Tag zur Neige geht, kondensiert er sich rund in der Murmel. Gelungenes wie Missgeschicke kullern darin zusammen gesammelt weiter. Hält man sie in die Handfläche und spürt das sanfte Wärmen von gestern, ist das ein kleines Schulterklopfen: Heute war ein guter Tag."},"ICON-1083":{"nm":"Lobzettel-Flasche","de":"Gute Worte verflüchtigen sich zu leicht – deshalb faltet man sie einzeln zusammen und füllt diese Flasche. Wenn Lob sich wie Duft ansammelt, öffnet man den Deckel an leeren Abenden. Liest man eine fremde Freundlichkeit erneut, erwacht die Wärme jenes Tages wieder."},"ICON-1084":{"nm":"Versöhnungsband","de":"Verknäulte Gefühle gleichen einem Knoten – auch zum Lösen braucht man Sorgfalt. Wenn zwei Menschen je ein Ende des Bandes halten und es langsam ziehen, entsteht daraus eine hübsche Schleife. Versöhnung ist kein Durchtrennen, sondern ein Neuverknüpfen – das zeigt dieses Band still."},"ICON-1085":{"nm":"Dankbarkeits-Token","de":"An Tagen, an denen Danke schwer über die Lippen kommt, reicht man stattdessen still einen Token weiter. Die empfangende Hand liest das ganze Gefühl aus diesem kleinen Gewicht. Ein Dank, der vor Worten ankommt – ein herzliches Stück Aufrichtigkeit, rund und handlich."},"ICON-1086":{"nm":"Pause-Markierung","de":"Auch im Übungsraum nach einem langen Tag braucht es einen Moment zum Durchatmen. Hängt man dieses Schild an die Tür, verlangsamt sich die Zeit ein wenig. Dass Musik atmet, wenn Pausen da sind, wissen alle, die schon einmal einen hastigen Tag erlebt haben."},"ICON-1087":{"nm":"Geheime Gefühlsschublade","de":"Es gibt Tage, an denen man nicht alles zeigen kann. Dann legt man Trauer und Aufregung still in eine kleine innere Schublade und schließt sie. Es ist in Ordnung, sie vorerst dort zu lassen – irgendwann kommt der Tag, an dem man sie in Ruhe herausnimmt und ordnet."},"ICON-1088":{"nm":"Lach-Aufkleber-Rolle","de":"Zieht man einen ab, haftet ein Lächeln an der Fingerkuppe. Auf eine Notizbuchecke, auf das Schließfach eines Freundes – kleine Fröhlichkeit, still angebracht. Wenn auf Papier eine kleine Sonne aufgeht, wird der Tag desjenigen, der sie entdeckt, ein wenig heller."},"ICON-1089":{"nm":"Gruß-Glöckchen-Anhänger","de":"Der Wunsch, jemanden in der Ferne zu erreichen, hat sich in einem kleinen Glöckchen niedergeschlagen. Schüttelt man es, übermittelt sein heller Klang den Gruß. An Tagen, an denen man 'Wie geht's?' nicht über die Lippen bringt, fliegt dieses kleine Läuten zuerst im Wind davon."},"ICON-1090":{"nm":"Frühlingsregen-Schutzpin","de":"An Frühlingsregentagen wird Geliebtes besonders leicht nass. Schließt man mit diesem Pin den Einband, gleitet der Regen ab. Ein geliebtes Buch ins Herz zu schließen – ein kleiner Pin übernimmt diese Zärtlichkeit."},"ICON-1091":{"nm":"Sommer-Kühl-Aufkleber","de":"Mitten im Hochsommer einen auf den erschöpften Handrücken gelegt. Eine kühle Frische breitet sich aus wie Pfefferminze und die Hitze lässt nach. Die Frische, die man früher auf der kühlen Veranda mit einem Fächer erfahren hat, ahmt dieses handgroße Papier auf seine Weise nach."},"ICON-1092":{"nm":"Herbst-Karo-Stoffstück","de":"Ein Stück Karostoff in Herbstfeldfarben. Eine Spur, dass jemand sorgfältig einen abgewetzten Fleck geflickt hat. Der Gedanke, Dinge nicht wegzuwerfen, sondern zu flicken – kleine Stoffstücke, die Zerschlissenes wieder warm zum Leben erwecken."},"ICON-1093":{"nm":"Winterhandschuh-Clip","de":"Winterhandschuhe schaffen es irgendwie, immer einen Handschuh verschwinden zu lassen. Mit diesem Clip verbunden, verirrt sich keine frierende Hand mehr. Der Wunsch, nichts zu verlieren, hat sich in dieses kleine Metallstück eingenistet und hält beide Handschuhe nebeneinander."},"ICON-1094":{"nm":"Regenzeit-Wasserdichtes-Etikett","de":"In der Regenzeit verwischen selbst Namensschilder im Regen. Dieses wasserdichte Etikett schützt die Schrift auch im strömenden Regen. Eine Zeile, die nach dem Regen noch klar lesbar ist – damit niemand vergisst, wem das gehört."},"ICON-1095":{"nm":"Erstschnee-Aufbewahrungsflasche","de":"Der erste Schnee verschwindet in dem Moment, in dem er die Hand berührt – deshalb bewahrt man wenigstens die Aufregung in dieser Flasche. Was hinter dem Glas gefangen ist, ist nicht Schnee, sondern das aufgeregte Herz von jenem Tag. Schüttelt man sie, wirbelt ein ganzer Winter auf und trägt einen zurück in diesen Morgen."},"ICON-1096":{"nm":"Festtagsumschlag-Band","de":"Ein rotes Band um den Festtagsumschlag. Alle wissen: die Zuneigung der reichenden Hand wiegt mehr als der Inhalt. Der Wunsch, gut zu leben und Glück mitzuschicken, ist in diesem schmalen Band sorgfältig verschnürt."},"ICON-1097":{"nm":"Picknick-Besteck-Band","de":"Wenn man die Decke ausbreitet und die Lunchbox öffnet, hebt der Wind immer wieder den Deckel. Mit diesem Band das Besteck fest zusammengebunden, bleibt das Picknick in Ordnung. Der Wunsch, das mitgebrachte Essen bis zum Ende zu schützen, steckt in diesem kleinen Streifen."},"ICON-1098":{"nm":"Saison-Duft-Probenkarte","de":"Damit man die Jahreszeit auch ohne Öffnen erkennt, hat diese Karte den Duft der jeweiligen Saison aufgenommen. Frühling riecht nach Blüten, Herbst nach trockenen Blättern. In dem Moment, in dem es die Nasenspitze streift, steht die ganze Jahreszeit auf – 'Das ist die Luft des April'."},"ICON-1099":{"nm":"Preisschildklemmbrett","de":"Das Preisschild, das vom Marktstand immer wieder wegflog, hat dieses Klemmbrett ein für alle Mal zur Ruhe gebracht. Es hält die Zahl fest und zeigt sie den Kunden geradeaus. Ein ehrlicher Auftritt im Handel beginnt mit einer Zeile, die nicht davonfliegt."},"ICON-1100":{"nm":"Geöffnet/Geschlossen-Wendeschild","de":"Hängt man dieses Schild um, erwacht der Laden erst richtig. Von 'Noch geschlossen' zu 'Herzlich willkommen'. Das kleine Signal für den Tagesbeginn – die erste Stelle, die morgens von der Hand des Inhabers berührt wird."},"ICON-1101":{"nm":"Stempelkarten-Pad","de":"Wenn alle zehn Felder voll sind, passiert irgendwie etwas Gutes. Jeder Stempel ist ein Stammkundenbesuch und angesammeltes Herzblut. In jedem Abdruck auf dem Pad, bis die Tinte verblasst, lebt ein kleines Versprechen: 'Ich komme wieder'."},"ICON-1102":{"nm":"Papiertüten-Henkel-Kappe","de":"Der Henkel einer Papiertüte ist immer das erste, das dem Gewicht nachgibt. Mit dieser Kappe hält das Griff stand. Der Wunsch, den Inhalt sicher bis nach Hause zu bringen – ein kleines Teil trägt diesen Weg bis zum Ende."},"ICON-1103":{"nm":"Kassentisch-Münzteller","de":"Das Zögern beim Münzenwechseln von Hand zu Hand nimmt dieser Teller einem sanft ab. Das Klimpern der Münzen, die ihren Platz finden. Dass das Geben und Nehmen ein wenig wärmer wird, verdankt man einem solchen runden, aufmerksamen Detail."},"ICON-1104":{"nm":"Punkte-Sammel-Chip","de":"Jeder heutige Schritt sammelt sich als ein Chip an. Je mehr sich ansammelt, desto leichter wird das Herz – eine wundersame Rechnung. Die Freude am schrittweisen Füllen gleicht der Freude, zuzuschauen, wie ein leeres Glas nach und nach voll wird."},"ICON-1105":{"nm":"Regalstandort-Nummerpin","de":"An jedem Regal steckt freundlich eine kleine Nummer. Ein stiller Wegweiser, der zeigt, wo was zu finden ist. Der Gedanke, vorab alles zu schildern, damit niemand herumirrt – auch in Ordnung steckt eine solche Wärme."},"ICON-1106":{"nm":"Kostprobe-Spießbecher","de":"Ein kleiner Becher, der eine Kostprobe bereithält. Selbst der zögerlichste Gast öffnet sich bei diesem einen Häppchen. Die Einladung 'Probieren Sie doch mal' hängt am Spießende und hält den erstmaligen Besucher fest."},"ICON-1107":{"nm":"Reservierungslisten-Halter","de":"Die Namen der heutigen Gäste stehen ordentlich aufgereiht in diesem Halter. Ein herzliches Versprechen, dass auch das Warten seine Reihenfolge hat. Ein Blatt Papier aufrecht hinzustellen ist die erste Vorbereitung, um jemanden sorgfältig zu empfangen."},"ICON-1108":{"nm":"Wandfoto-Schnur-Klammer","de":"Fotos an einer Schnur an der Wand aufgehängt, eine nach der anderen eingeklemmt. Lachende Momente hängen nebeneinander wie Wäsche und trocknen. Hängt man Erinnerungen in die Sonne, flattert das Lachen jenes Tages beim Vorbeigehen wieder."},"ICON-1109":{"nm":"Mini-Teppich-Ecke","de":"Ein kleiner Teppich, der sich am Zimmerrand ausbreitet. Ein Platz, der dem kalten Boden zuerst Wärme schenkt. Einen Handbreit, auf dem die Füße als erstes landen – hier kommt man nach Hause, und die müden Zehen können endlich loslassen."},"ICON-1110":{"nm":"Türschild-Abdecktuch","de":"Ein Tuch, das das Türschild sanft verhüllt. Den eigenen Namen für eine Weile zu verbergen, ist auch eine Art Wohnkunst. Ein Stoff, der die Grenze zwischen innen und außen hübsch drapiert – ein weiches Zeichen dafür: Heute möchte ich still ausruhen."},"ICON-1111":{"nm":"Lichterketten-Kabel-Clip","de":"Dieser Clip hält das herabhängende Lampenkabel ordentlich an seinem Platz. Er sorgt dafür, dass das Licht nicht in Unordnung gerät, und glättet den Weg. Wenn man gegen Abend ein wirres Kabel in Ordnung bringt, werden das Licht im Zimmer und die Gedanken gleich ruhiger."},"ICON-1112":{"nm":"Poster-Magnet-Kappe","de":"Eine kleine Magnetkappe, die Poster an der Wand befestigt. Kein einziges Reißzweckenloch, und das Papier hält trotzdem seinen Platz. Wie man mit Lieblingsdingen umgeht – sorgsam, damit nichts beschädigt wird."},"ICON-1113":{"nm":"Vorhang-Quasten-Schnur","de":"Eine Quastenschnur, die den Vorhangstoff zur Seite bindet. Sie öffnet dem Morgenlicht einen schönen Weg herein. Zieht man einmal an der bestickten Schnur, schreitet ein heller Tag groß ins Zimmer und bleibt."},"ICON-1114":{"nm":"Kerzenhalter-Etikett","de":"Ein kleines Etikett auf dem Kerzenhalter. Was für ein Duft brennt, wann er zum ersten Mal entzündet wurde – alles sauber festgehalten. Dem Lieblingsduft einen Namen zu geben – diese Ordentlichkeit macht die Luft im Zimmer noch ein wenig herzlicher."},"ICON-1115":{"nm":"Dekorationsregal-Gummifüße","de":"Vier Gummifüße, die das Regal am Wackeln hindern. An unsichtbarer Stelle tragen sie still das Gewicht. Klein und niedrig, kaum zu sehen – doch was ganz unten standhält, hält am längsten."},"ICON-1116":{"nm":"Richtungspfeil-Anhänger","de":"Für alle, die zögern, wohin sie gehen sollen, zeigt ein Pfeil ruhig die Richtung. Eine herzliche Geste: 'Verirr dich nicht.' Dank jemandes vorausgegangener Fürsorge an jeder Weggabelung geht man auch heute ohne Umwege weiter."},"ICON-1117":{"nm":"Inseleinladungs-Schlüsselschnur","de":"Eine Schlüsselschnur, die in die Hand derer gegeben wird, die zur Insel eingeladen werden. Wer sie empfängt, ist von nun an ein Mitglied dieses Ortes. Die Herzlichkeit, einen fremden Gast in die Wärme zu bitten, ist fest in dem kleinen Versprechen am Ende der Schnur verankert."},"ICON-1118":{"nm":"Beziehungstemperatur-Chip","de":"Ein Chip, der leise die Wärme zwischen zwei Menschen anzeigt. Noch distanziertes Blau oder schon warmes Dunkelrot? Die Geschwindigkeit, mit der Zuneigung wächst, lässt sich kaum messen – aber die Handfläche spürt die Wärme stets zuerst."},"ICON-1119":{"nm":"Vorlieben-Probierbox","de":"Wenn man noch nicht weiß, was jemanden begeistert, packt man kleine Kostproben in eine Schachtel und reicht sie weiter. Im Vergnügen des Auswählens entfaltet sich der Geschmack langsam. Was davon deins wird – in der Schachtel steckt eine Fülle aufregender Möglichkeiten."},"ICON-1120":{"nm":"Pflegetermin-Pin","de":"Das Versprechen, jemanden zu versorgen, steckt klar in diesem Pin. Schreibt man Name und Uhrzeit auf, findet die Zuneigung ihren Weg. Die herzliche Nachbarschaftshilfe, bei der man gegenseitig auf die Kinder aufgepasst hat, lebt hier weiter."},"ICON-1121":{"nm":"Wachstumsrekord-Kapsel","de":"Wie Wachstumsstriche auf dem Türrahmen Zeile für Zeile aufsteigen, versiegelt diese Kapsel still das gestrige Ich. Wenn man eines fernen Tages den Deckel öffnet, wird man es wissen: wie weit die kleinen Schritte von damals wirklich getragen haben."},"ICON-1122":{"nm":"Erstes-Treffen-Bewahrungs-Band","de":"Das Zittern beim ersten Händedruck ist sanft in ein Band geknüpft. Der Knoten ist nicht zum Lösen da, sondern damit die Wärme jenes Tages am Handgelenk weiterlebt."},"ICON-1123":{"nm":"Mein-Zimmer-Requisiten-Etikett","de":"'Hier ist mein Platz.' In dem Moment, in dem ein kleines Etikett an der Schreibtischkante klebt, atmet das fremde Zimmer auf und wird zum eigenen. Ein Namensschild ist der erste Ort, an dem das Herz landet."},"ICON-1124":{"nm":"Vertrautheits-Murmelbehälter","de":"Schüttelt man ihn, kullert es leise – ein Klang, der besagt, dass die zwei sich wieder ein Stück nähergekommen sind. Wenn der Behälter sich zu füllen beginnt, wird schon ein Lächeln zur Begrüßung kommen, bevor der Name gerufen ist."},"ICON-1125":{"nm":"Debütvorbereitungs-Versiegelungssiegel","de":"Das letzte Blatt, das den Umschlag schließt. Bis hierhin war Vorbereitung – wer die nächste Seite umblättert, steht auf der Bühne. Mit der Fingerkuppe sanft aufgedrückt, hält der Trainee inne und holt Luft. Endlich – es geht los."},"ICON-1126":{"nm":"Wasser","de":"Am gewöhnlichsten und doch am kostbarsten. Im dunklen Übungsraum mitten in der Nacht richtet ein einziger Schluck einen erschöpften Menschen wieder auf. Sanft genug, um in jedes Gefäß zu fließen und sich anzupassen."},"ICON-1127":{"nm":"Klares Wasser","de":"Kristallklar bis auf die Kieselsteine am Grund. Die Bergquelle prahlt nie mit ihrer Reinheit. Ein Herz ohne Geheimnisse lässt sich genauso durchschauen – bis auf den Grund."},"ICON-1128":{"nm":"Meerwasser","de":"Berührt es die Zungenspitze, rollt eine ferne Welle heran. In einem einzigen salzigen Schluck stecken Horizont, Möwen und der zurückgelassene Hafen. Das Meer bleibt immer salzig in der Erinnerung."},"ICON-1129":{"nm":"Eis","de":"In der Handfläche wird es langsam kleiner und schwindet, so viel man auch festhält. Obwohl es so hart wirkt, findet es am Ende doch zurück zum Wasser. Eis ist ein Fluss, der kurz den Atem angehalten hat."},"ICON-1130":{"nm":"Schneeball","de":"Fest zusammengerollt fliegt er weiß durch die Gasse. Kicherndes Lachen und rot gefrorene Wangen. Das weißeste Spielzeug, das der Winter den Kindern heimlich in die Hand drückt."},"ICON-1131":{"nm":"Erde","de":"Sie birgt Samen, trinkt Regenwasser und nimmt wortlos die Fußabdrücke der Vorbeigehenden auf. Dunkle Haut, die alles umfängt. Jedes Keimende beginnt mit einer einzigen Handvoll von ihr."},"ICON-1132":{"nm":"Fruchtbare Erde","de":"Steckt man den Finger tief hinein, umschließt sie ihn weich und fettig. Das Geheimnis des ewig grünen Gemüsegartens der Großmutter lag genau hier. Gut gereife Erde flüstert mit dem Duft von Kompost von einer reichen Ernte."},"ICON-1133":{"nm":"Ton","de":"Sobald er Feuchtigkeit aufnimmt, nimmt er willig jede Form an. Unter der Hand wird er zum Vogel, zur Schale – fügsames Fleisch. Während sich die Scheibe dreht, beginnt eine Handvoll Erde zu träumen."},"ICON-1134":{"nm":"Sand","de":"Die feinen Körnchen rieseln durch die Finger, und je fester man greift, desto schneller fließen sie davon – ganz wie die Zeit. In einer Handvoll Strand schlafen unzählige gestrige Tage."},"ICON-1135":{"nm":"Kieselsteine","de":"Am Bach rundgeschliffen. Eine Spur davon, wie das Wasser sie lange, lange gestreichelt hat, bis alle Kanten verschwanden. Je weiter ein Stein gerollt ist, desto sanfter liegt er in der Hand."},"ICON-1136":{"nm":"Stein","de":"Achtlos am Wegesrand liegend. Der eine tritt ihn weg, der andere hebt ihn auf und stapelt Steine zu einem Turm. Derselbe Stein wird, je nach Gemüt, zur Last oder zum Wunsch."},"ICON-1137":{"nm":"Steinplatten","de":"Breite Steine, die den Schlosshof durchziehen. In der Mitte haben sie sich durch die Schuhe von Hunderten von Jahren sanft eingemuldet. Jeder, der darüber schreitet, legt eine weitere Schicht Zeit hinzu."},"ICON-1138":{"nm":"Kalkstein","de":"Muscheln aus Meereszeiten haben sich Schicht für Schicht zu weißem Stein verdichtet. Im Brennofen löst er sich zu Kalk und tüncht Mauern strahlend weiß. So ruhig er wirkt – er trägt eine ganze Epoche in sich."},"ICON-1139":{"nm":"Kohle","de":"Ein alter Wald, der schwarz eingeschlafen ist. Farne vor Hunderten von Millionen Jahren, die sich tief im Erdinnern hart verdichtet haben. Zündet man sie an, erwacht das lange verborgene Sonnenlicht aufleuchtend neu."},"ICON-1140":{"nm":"Holzkohle","de":"Glut aufnehmen, Rauch still schlucken. Im Brennofen zu Schwarz gehärtetes Holz, das auf dem Kohlenbecken lautlos rot aufleuchtet. Was am stillsten ist, wärmt am längsten."},"ICON-1141":{"nm":"Ast","de":"Ein Ast, der sich schweigend gebogen hat, um nicht zu brechen, kennt die Kunst des Nachgebens. An jeder Stelle, an der er einen harten Wind überstanden hat, sitzt ein Knorren – wahre Festigkeit ist am Ende das Zeichen guten Biegens."},"ICON-1142":{"nm":"Baumstamm","de":"In den Jahresringen des frischen Schnitts sind hundert Frühlings- und Winterzeiten rund übereinandergelegt. Die gelebten Jahre eines ganzen Baumes liegen nun da und warten geduldig, zur Säule eines Hauses zu werden."},"ICON-1143":{"nm":"Holz","de":"Jedes Mal, wenn der Hobel darüber fährt, kommt eine duftende Maserung zum Vorschein. Während das rohe Holz glatt wird, sammeln sich die Späne auf dem Boden wie gelber Schnee. Bearbeitende Hände wecken den Zweck."},"ICON-1144":{"nm":"Holzbrett","de":"Dielen werden verlegt, Bänke gezimmert, Zäune errichtet. Wenn sich gerade gesägte Brettchen aneinanderreihen, entsteht erst ein Ort zum Leben. Aus gewöhnlichen Dingen zusammengefügt entsteht ein Zuhause."},"ICON-1145":{"nm":"Bambus","de":"Hohl von innen und doch gerade vor dem Wind. Die Kraft, nach jedem Schnitt neu auszutreiben, wollten die alten Gelehrten sich abschauen. Gerade weil es leer ist, steht es aufrechter als alles andere."},"ICON-1146":{"nm":"Kork","de":"Drückt man ihn nieder und lässt los, schwillt er auf seine ursprüngliche Dicke zurück. Diese leichte und dennoch zähe Textur lehrt: weich sein ist keineswegs schwach sein. Vom Flaschenstöpsel bis zur Pinnwand – er trägt still von unten."},"ICON-1147":{"nm":"Gras","de":"Selbst wenn es niedergetreten wird, richtet es sich nach dem nächsten Regen wieder auf. Grüne Beharrlichkeit, die namenlos eine ganze Wiese überzieht. Klein genug, um übersehen zu werden – doch den Frühling kündigt stets als Erster dieser niedrige Platz an."},"ICON-1148":{"nm":"Stroh","de":"Was nach der Herbsternte gelb auf den Feldern zurückblieb. Geflochten wurde es zum Dach, ausgebreitet zum warmen Schlafplatz. Alles Korn weggegeben und dennoch bis zum letzten Halm für den Menschen da."},"ICON-1149":{"nm":"Schilf","de":"Wenn der Wind darüber streicht, raschelt das ganze Flussufer. Hohle Stängel, die umso weiter klingen, weil sie innen leer sind. Dass das Schwingen sein eigenes Lied ist, schämt sich das Schilf kein bisschen."},"ICON-1150":{"nm":"Baumwolle","de":"Wenn die reife Kapsel aufspringt, blüht eine kleine Wolke. Diese leichte, weiche Watte wird zu Garn und Kleidung und wärmt in kalten Winternächten sanft jemandes Schulter."},"ICON-1151":{"nm":"Schafwolle","de":"Anfassen hinterlässt Fett auf den Händen und ein stilles Wärmen. Ein Mantel, den das Schaf sich selbst gegen die Kälte des Berges zugelegt hatte. Diese Wärme, einmal geschoren, kommt nun dem menschlichen Winter zugute."},"ICON-1152":{"nm":"Faden","de":"Kaum sichtbar, so dünn er ist – und doch stets derjenige, der zwei getrennte Enden wieder zusammenfügt. Als einzelner Faden schwach, geflochten zu einem Stück Stoff. Für das Verbinden spielt die Stärke keine Rolle."},"ICON-1153":{"nm":"Stoff","de":"Schuss- und Kettfäden kreuzen sich unzählige Male zu einer einzigen Bahn. Das Ergebnis von Fäden, die sich gegenseitig fest halten, obwohl sie allein auseinanderfallen würden. Je enger das Gewebe, desto wärmer – das gilt für Stoff wie für Menschen."},"ICON-1154":{"nm":"Leder","de":"Je mehr man es benutzt, desto mehr nimmt es die Patina seines Besitzers an. Während die anfängliche Steifheit nachlässt, vertieft sich die Farbe und die Oberfläche wird weich. Den Glanz, den die Zeit eingraviert, kann nichts nachahmen."},"ICON-1155":{"nm":"Feder","de":"So leicht, dass man in der Handfläche kein Gewicht spürt. Eine einzige Feder, die noch die Erinnerung ans Fliegen trägt. Was am leichtesten ist, ist am höchsten gestiegen – das soll man nie vergessen."},"ICON-1156":{"nm":"Muschelschale","de":"Die Worte der Großmutter fallen einem ein: 'Halt sie ans Ohr.' Im schimmernden Inneren ist das Meer, das zurückgelassen wurde, ganz eingeritzt. Aus einer leeren Schale hört man noch das Wogen einer vergangenen Zeit."},"ICON-1157":{"nm":"Koralle","de":"Steinhart, und doch war sie einmal eine atmende Gemeinschaft. In der langsamen Tiefsee breitet sie über Jahrhunderte ihre Äste aus. Der festeste Ast ist der, der am längsten gewartet hat."},"ICON-1158":{"nm":"Perle","de":"Weil ein Sandkorn zu sehr störte, hat die Auster es still im Licht eingehüllt. Schmerzen rund zu bewahren macht einen so strahlend – eine kleine Aufmunterung, die das Meer reicht."},"ICON-1159":{"nm":"Meeresalge","de":"Auf den Felsen nach der Ebbe schlüpfrig herabgebreitet. Greift man hinein, riecht es sofort fischig und scharf nach Meer. Ohne Wurzeln, dem Wellengang überlassen, pflegt das Meer seinen Garten still."},"ICON-1160":{"nm":"Nori","de":"Ein schwarzes Blatt kurz über der Flamme gehalten, es wird grün und ein nussiger Duft verbreitet sich. Jener Morgen, an dem man frisch gekochten Reis darin gerollt hat. Noch so dünn, umhüllt es das Glück einer ganzen Mahlzeit."},"ICON-1161":{"nm":"Salz","de":"Weiße Kristalle, die das Meer in der Sonne zurückließ. Eine Prise vertieft den dünnsten Sud, zu viel überdeckt jeden Geschmack. Nur eine Hand, die das richtige Maß kennt, führt mich richtig."},"ICON-1162":{"nm":"Glasscherbe","de":"Erst am Bruch bricht es das Licht und lässt einen Regenbogen entstehen. Eine Fähigkeit, die im Ganzen nie zu sehen war. Auch in Zerbrochenen steckt noch ein Anteil, den Sonnenschein zu teilen – ein Splitter auf dem Fensterbrett zeigt das still."},"ICON-1163":{"nm":"Glas","de":"Transparent zu sein bedeutet nicht nur, nichts zu verbergen. Es hat sein eigenes Bild ausgelöscht, damit das Licht ungehindert hindurchfließen kann. Auch im unsichtbaren Dasein, von dem man die kühle Ordentlichkeit spürt, wenn man es berührt."},"ICON-1164":{"nm":"Glasflasche","de":"Leer sein heißt, bereit zum Befüllen sein. Ob Marmelade, ein Feldblumenstrauß oder ein gefalteter Brief – je nachdem, was hineinkommt, ändert sie den Namen. Ein Gefäß, das die Leere nicht fürchtet, ist am großzügigsten."},"ICON-1165":{"nm":"Leere Flasche","de":"Die Stille, die nach dem letzten Schluck einkehrt, ist schön. Jemand wirft mich weg, jemand spült mich aus und stellt mich auf die Fensterbank voll Sonnenschein. Nach dem Ende wieder nützlich werden – das ist das zweite Leben der Leeren."},"ICON-1166":{"nm":"Papier","de":"Ausgebreitet und bereit, alles aufzunehmen. Wer am längsten in ein leeres Blatt schaut, ist stets ich, während jemand zögert, die erste Zeile zu schreiben. Die Geduld des weißen Papiers reicht einen Fingerbreit tiefer als die Tinte."},"ICON-1167":{"nm":"Altes Papier","de":"Vergilben ist nicht Altern, sondern Standhalten. In jedem Knick steckt die Wärme der Hände, die es aufgeschlagen und gelesen haben. Altes Papier schreibt die vergangene Zeit in seiner eigenen Farbe fest, damit es nicht in Vergessenheit gerät."},"ICON-1168":{"nm":"Tinte","de":"Aus einem einzigen Tropfen wird ein Satz, und getrocknet bleibt er wie ein Versprechen. Verwischt ist der Verwisch selbst die Spur jenes Tages. Weil ich Dinge unumkehrbar mache, tupft man mich einmal mit mehr Bedacht auf."},"ICON-1169":{"nm":"Eisenerz","de":"Ein Stein, der tief unter der Erde in rotem Schlummer lag. Erst wenn er das Feuer durchschreitet, gibt er das Eisen in seinem Innern frei. Härte heißt nicht von Anfang an hart sein, sondern ein Name, den man erst nach der Hitze empfängt."},"ICON-1170":{"nm":"Eisenbarren","de":"Das Erz hat das Feuer überstanden und ist zu einem Stück erkaltet. Diese kalte, schwere Form wird zur Brücke, zum Schwert, zur Hacke. Weil der Zweck noch nicht feststeht, kann ich alles werden."},"ICON-1171":{"nm":"Kupfererz","de":"Mit grünem Belag bedeckt aus der Erde gekommen. Geschmolzen läuten Glocken, stehen Standbilder, fließen Leitungen. Auch im Dunkel der Erde wartete ich stets auf mein nächstes Dasein."},"ICON-1172":{"nm":"Kupferbarren","de":"Lange an der Seite, kleidet er sich selbst in blaues Gewand. Mancher nennt das Makel, ein anderer streicht es als Muster der Zeit. Das Metall, das sich für seine wechselnde Farbe nicht schämt, wird am längsten geliebt."},"ICON-1173":{"nm":"Golderz","de":"Gefunden nach vielem Sieben und nochmaligem Sieben des Flusssandes. Nicht selten, daher wertvoll – sondern unveränderlich, daher wertvoll. Den Alten war es als Zeichen für ein Herz, das nicht rostet, in die Hand gegeben."},"ICON-1174":{"nm":"Goldbarren","de":"Weder getrübt noch verrostet, liegt er als ein Stück da. Er hat die stärkste Gier der Menschen gehört, begehrt selbst jedoch gar nichts. Schweigsames Gewicht, das einzig darin treu ist, zu strahlen."},"ICON-1175":{"nm":"Altmetall","de":"Nicht am Ende seiner Nützlichkeit – wartend auf den nächsten Zweck. Verbogene Nägel und zerbeulte Dosen kommen zusammen und treffen wieder auf heißes Feuer. Weggeworfen bedeutet für mich nur: kurze Ruhepause."},"ICON-1176":{"nm":"Schraube","de":"Allein kann ich gar nichts. Erst eingedreht, zwei Platten fest ineinander verzahnt, tue ich meinen Teil. Großes festzuhalten mit kleinem Körper – auch in der Kraft des Anziehens steckt Sorgfalt."},"ICON-1177":{"nm":"Nagel","de":"Einmal eingeschlagen, weiche ich kaum zurück. Was der Hammer niederschlägt, vertieft kein Schmerz, sondern ein Versprechen. Für das Fest-Verbinden von Dingen biete ich gerne meinen Kopf an."},"ICON-1178":{"nm":"Zahnrad","de":"Es schiebt den Zahn des Nachbarn und dreht gemeinsam mit ihm. Es kennt die Kunst, nicht allein voranzueilen, sondern das Tempo des Nebenmanns anzupassen. Wie in einer Uhr, die Zeit vergeht, wenn Räder ineinandergreifen – Einklang ist Bewegung."},"ICON-1179":{"nm":"Feder","de":"Je stärker man drückt, desto mehr sammelt sie die Rückkehrkraft nach innen. Sich biegen ist kein Aufgeben, sondern die Vorbereitung zum Aufrichten. Die kleine Spirale, in der Flexibilität Festigkeit bedeutet."},"ICON-1180":{"nm":"Kabel","de":"Außen eine ruhige Ummantelung, innen ein ununterbrochen fließender Weg. Unsichtbar trägt es Licht und Klang. Wie eine Hand, die still hinter der Bühne alles verknüpft – ein Kanal, dem man gerade weil er nicht sichtbar ist, noch mehr vertraut."},"ICON-1181":{"nm":"Batterie","de":"Das Licht eines halben Tages sorgfältig in einem kleinen Körper gespeichert. Wenn sie leer ist, einfach wieder aufladen – sie betrachtet das Leersein nie als Ende. Sie birgt eine kleine Abenddämmerung, die jemandes lange Nacht erhellen wird."},"ICON-1182":{"nm":"Glühbirne","de":"Ein einziger dünner Faden glüht rot auf und verdrängt die Dunkelheit. Nicht der Raum wird erhitzt, sondern erleuchtet. Ein kleines Sonnenzeichen, das in dem Moment am heißesten ist, in dem es am hellsten strahlt."},"ICON-1183":{"nm":"Linse","de":"Sie bündelt das zerstreute Licht und stellt es an einem Punkt scharf. Ferne Sterne wie auch kleine Schrift in der Handfläche ruft sie heran. Ein klarer, runder Vermittler, der sein eigenes Bild verbirgt, um anderen beim Sehen zu helfen."},"ICON-1184":{"nm":"Gummi","de":"Drücken, dehnen – und kehrt doch immer an seinen Platz zurück. Wer es als weich belächelte, greift an Regentagen als Erster danach. Harte Stöße weich aufzufangen – in dieser Weichheit lebt zähe Ausdauer."},"ICON-1185":{"nm":"Plastiksplitter","de":"Ein kleines Stück, das vom Hauptkörper abgebrochen ist. Fast weggeworfen – doch wenn viele zusammenkommen, werden sie wieder zu etwas Neuem. Nicht leicht, weil klein, sondern leicht genug, um als Teil von etwas Weiterem weit zu tragen."},"ICON-1186":{"nm":"Seil","de":"Erst viele Stränge zusammengedreht ergeben ein einziges Seil. Allein zerfällt es leicht, geflochten zieht es Boote und bündelt Fracht. Wie zäh es wird, liegt daran, wie fest sie ineinandergewunden sind – das rissige Seil der Zusammenarbeit."},"ICON-1187":{"nm":"Segelstoff","de":"Statt den Wind zu hassen, nimmt er ihn volles Herz auf. Prall gebläht schickt er das Schiff in die Ferne – selbst Gegenwind ist für ihn Kraft. Die Kunst, Heftiges nicht zu widerstehen, sondern zu umarmen und voranzukommen, hat er auf dem Meer gelernt."},"ICON-1188":{"nm":"Ankerstück","de":"Nur ein Teil des Ankers, und doch erinnert sein Gewicht noch ganz an damals. An die Zeit, als er den tiefen Grund hielt und das Schiff stoppte. Auch jetzt, abgetrennt, ist er ein schweres Stück, das das Gewicht des Verweilens kennt."},"ICON-1189":{"nm":"Schiffsnagel","de":"Ein Nagel, der das im Wellengang schwankende Deck Punkt für Punkt festhielt. Selbst vom Salzwasser rot verrostet, ließ er seinen Platz nie los. Auch das Festhalten von Treibendem braucht Sturheit."},"ICON-1190":{"nm":"Wasserdichter Stoff","de":"Den Regen abzuhalten ist sein stilles Handwerk. Was von oben herabströmt, nimmt er wortlos auf und hält das Darunter trocken. Nicht prächtig, aber das Gepäck jemandes unbenetzt zu decken – verlässliche Schutzschicht."},"ICON-1191":{"nm":"Farbstoff","de":"Wenn er sich still in das ungefärbte Tuch einschreibt, wird er zur Farbe. Ob Indigoblau oder Krapp – die alten Mütter haben sich die Fingerkuppen gefärbt, während sie dem Stoff Farbe gaben. Auch im Einsinken und Einziehen steckt eine Tiefe, die kaum verblasst."},"ICON-1192":{"nm":"Duftöl","de":"Ein einziger Tropfen, und schon breitet sich ein weites Feld im ganzen Zimmer aus. Unsichtbar und doch der erste Gast, der ankommt. Es zupft sanft am Ärmel schlafender Erinnerungen – die Landschaft, die zuerst die Nasenspitze erreicht."},"ICON-1193":{"nm":"Wachs","de":"Erhitzt fließt es, abgekühlt härtet es und behält die Form. Zwischen Weich und Hart pendelnd, nimmt es alles still ab. Schließen, versiegeln, polieren – ein herzliches Material, das sein Gesicht je nach Temperatur wechselt."},"ICON-1194":{"nm":"Kerze","de":"Sie schmilzt langsam ihren eigenen Körper und erhellt eine Ecke der Dunkelheit. Wenn sie abgebrannt ist, bleibt nur ein verkleinerter Stumpf – doch die Zeit, in der sie jemandes Nacht wärmte, verschwindet nicht. Ein gerader Docht, der weiß, wie man kleiner wird und dabei leuchtet."},"ICON-1195":{"nm":"Kompost","de":"Verrottende Dinge kommen zusammen und werden zur fettesten Erde. Weggeworfene Schalen und trockene Blätter werden zur Nahrung neuer Frühlingssprosse. An dem Ort, den man für beendet hielt, holt das nächste Leben still seinen ersten Atemzug."},"ICON-1196":{"nm":"Reis","de":"Bis zu einem einzigen Korn reichen achtundachtzig Hände. Von der Reispflanzung bis zum Dreschen steckt das ganze Jahr des Bauern in diesem kleinen Korn. Eine dampfende Schüssel Reis ist die vier Jahreszeiten von jemandem."},"ICON-1197":{"nm":"Brauner Reis","de":"Nur die äußerste Hülle abgestreift und die ursprüngliche Farbe bewahrt. Der nussige Geschmack beim Kauen ist der Geschmack von Ehrlichkeit, die nicht gehastet hat. Das eigensinnige Beharren des Korns, das sich das Schleifen verweigert und seine raue Maserung behält."},"ICON-1198":{"nm":"Weizen","de":"Er erinnert an die goldenen Felder, auf denen sich alle gleichzeitig im Wind verbeugten. Er wird zu Brot, zu Nudeln, zu Teigflecken und wärmt Tische auf der ganzen Welt. So alltäglich, dass er umso tiefer in das Leben der Menschen eingedrungen ist."},"ICON-1199":{"nm":"Mehl","de":"Erst wenn es zum feinen weißen Pulver geworden ist, macht es sich für alles bereit. Wasser trifft es, es bläht sich auf, Feuer trifft es, es gart. Ohne feste Form gewinnt es seine Gestalt durch die formenden Hände – ruhiger Rohstoff."},"ICON-1200":{"nm":"Teig","de":"Mehl und Wasser verbinden sich unter der Handfläche zu einem Stück. Je mehr man ihn knetet, desto zäher wird er, je länger er wartet, desto fluffiger bläht er sich auf. Weil Eilen ihn zäh macht, sagt die alte Bäckerei: Die Zeit des Gehens kann man nicht antreiben."},"ICON-1201":{"nm":"Paniermehl","de":"Die weißen Krümel bleiben an den Fingerspitzen hängen und landen schon bald auch auf dem Ärmel. Als Panade wird es knusprig, aufgehäuft erinnert es an den ersten Schnee. Was nach dem Backen eines Laibs übrig bleibt, ist das leichteste Zeichen seiner Existenz – doch auch das Kleinste findet seine Verwendung."},"ICON-1202":{"nm":"Nudeln","de":"Wer eine Handvoll wie einen Fächer ins kochende Wasser gleiten lässt, holt sich für einen Moment fernes Sonnenlicht in die Küche. Lange Nudeln sind Handgelenksarbeit, und al dente sein heißt, noch ein wenig unfertig warten zu können. Sieh, wie sie sich glänzend um die Gabel wickeln."},"ICON-1203":{"nm":"Instant-Nudeln","de":"Tief in der Nacht, wenn die Bühnenmaske abgewaschen ist, öffnet man heimlich eine Tüte. Die drei Minuten, in denen die Nudeln aufquellen, sind die privateste Zeit des Tages. Das Pusten kühlt die Anspannung mit, und hinter beschlagenen Brillengläsern verabschiedet sich der Tag leise."},"ICON-1204":{"nm":"Reiskuchen","de":"Erst wenn der Reis die Schläge des Mörsers übersteht, wird er zum Reiskuchen. Als Meo, als Injeolmi, als Songpyeon – dasselbe Getreide bekommt durch Handarbeit hundert Namen. Auf dem Festtisch spricht das Herz schneller an als der Magen: Das hier ist ein Essen, das man teilen muss."},"ICON-1205":{"nm":"Reiskuchen-Scheiben","de":"Schräg geschnittener Garaetteok sieht aus wie kleine Münzen. Was im weißen Brühsud schwimmt – sind es Reisscheiben oder runde Wünsche? Eine Schüssel am ersten Neujahrsmorgen zu leeren bedeutet, ein weiteres Jahr älter zu werden. Eine herzliche Rechenart, wie sie nur dieses Land kennt."},"ICON-1206":{"nm":"Kartoffel","de":"Wenn man die Erde abschüttelt, kommt ein rundes Gesicht zum Vorschein. In den Hanglagen Gangwons vom Wind geschüttelt, wächst diese Knolle still und unerschütterlich. Gedämpft ist sie mehlig, gebraten nussig. Eine ehrliche Wurzel, die auch an knappen Tagen die ganze Familie satt macht."},"ICON-1207":{"nm":"Süßkartoffel","de":"Sobald an der Straßenecke der Ofen für gebackene Süßkartoffeln auftaucht, beginnt der Winter. Die Folie aufzufalten lässt gelben Dampf aufsteigen, der die Finger zuerst wärmt. Diese Süße ist die Antwort der Wurzel auf die Kälte, die sie ausgehalten hat. Am schönsten, wenn man sie heiß pustend mit jemandem teilt."},"ICON-1208":{"nm":"Karotte","de":"Ein orangefarbener Stab, der geradewegs in die Erde reicht. Nur Hasen mögen sie, dachte man – doch gebraten erwacht eine versteckte Süße, und in der Suppe sorgt sie auch für Farbe. Die alten Leute, die sagten, sie tue den Augen gut, hatten meistens recht."},"ICON-1209":{"nm":"Rettich","de":"Eine einzige dieser weißen, schweren Wurzeln reicht für einen vollwertigen Wintertisch. Als Dongchimi scharf und klar, als Suppe erfrischend, als Kkakdugi knackig. Da nicht einmal das grüne Rettichgrün weggeworfen wird – man hängt es zum Trocknen unter das Vordach und bewahrt es als Sirae-gi – ist das ein wirklich sparsames Gemüse."},"ICON-1210":{"nm":"Zwiebel","de":"Beim Schälen rinnt eine Träne die Wange hinab. Doch das scharfe, beißende Innere wird durch heißes Öl wie von Zauberhand süß. Ihr Name steht in fast allen koreanischen Gerichten ganz oben – sie ist die stille Heldin, die behutsam den Duftgrund legt."},"ICON-1211":{"nm":"Lauchzwiebel","de":"Erst wenn der weiße Strunk und die grünen Blätter fein gehackt über die Suppe gestreut werden, wirkt die Schüssel wirklich fertig. Den übrig gebliebenen Strunk in ein Wasserglas stellen – schon wächst er wieder munter nach, ein kleines Fenstergärtchen für sparsame Haushalte."},"ICON-1212":{"nm":"Knoblauch","de":"Sechs Zehen schmiegen sich zu einem Kopf zusammen. Diese scharfe Wurzel soll den Bären zur Frau gemacht haben. Mit dem Messerrücken klopfen, und der Duft bricht schlagartig auf – ohne eine Handvoll davon ergeben weder Kimchi noch Eintopf überhaupt einen Sinn."},"ICON-1213":{"nm":"Ingwer","de":"Eine kleine, knorrige Wurzel, die aussieht wie ein Knoten. Schon ein Stück beruhigt Fischgeruch und wärmt den erkälteten Körper von innen. In einer kalten, schmerzhaften Nacht begann das mit Honig aufgebrühte, heiße Tässchen in dieser würzigen Schärfe."},"ICON-1214":{"nm":"Chinakohl","de":"Erst wenn die festen Blätter in Salz eingelegt werden, beginnt das erste Kapitel des Kimchis. Im späten Herbst türmte er sich in jedem Hof wie ein Berg. Das Einlegen eines ganzen Vorrats, während die Familie beisammen saß, war das Versprechen, den langen Winter gemeinsam zu überstehen."},"ICON-1215":{"nm":"Weißkohl","de":"Blatt für Blatt von den sich überlagernden Lagen zu lösen scheint kein Ende zu nehmen – und irgendwann wird man ganz gelassen dabei. Geblanchiert zart und weich, gebraten leicht süßlich. Hinter dem unscheinbaren Äußeren verbirgt sich eine unerwartete Freundlichkeit."},"ICON-1216":{"nm":"Eisbergsalat","de":"Ein Stück Fleisch auf das gewölbte Blatt legen, Ssamjang darüber – und dann den Mund so richtig voll nehmen. Wer im Kreis sitzt und einwickelt, legt unweigerlich die Etikette ab. Das ist nichts anderes als grüne Gastfreundschaft."},"ICON-1217":{"nm":"Blattsalat","de":"Das erste, was in einem Hausgarten aus der Erde schießt. Zupft man ihn ab, wächst er nach und füllt den Tisch den ganzen Sommer. Der frische, grüne Duft vom Abspülen mit kaltem Wasser und Einwickeln mit der Hand ist für manche der vollständige Geschmack der Heimat."},"ICON-1218":{"nm":"Spinat","de":"Das Grün, das dem Cartoon-Helden nach dem Öffnen der Dose Kraft verlieh. Blanchiert schrumpft er zur Handvoll, doch Duft und Kraft bleiben erhalten. Ob zart gewürzt oder in die Doenjang-Suppe gegeben – man sollte dieses alltägliche Gemüse niemals unterschätzen."},"ICON-1219":{"nm":"Farnsprossen","de":"Die zarten Triebe, die der Frühlingswald schenkt, werden gebrochen, dann gekocht und getrocknet. Erst nach dieser langen Mühe finden sie ihren Platz auf dem Gedenkopfertisch oder im Bibimbap. Ein kostbares Kraut, das der Berg eine Jahreszeit lang aufgezogen hat, in das sich Schicht für Schicht Sorgfalt eingewoben hat."},"ICON-1220":{"nm":"Wildkräuter","de":"Scheinbar namenlos, aber jedes mit eigenem Duft – ein Geschenk des Frühlings. Großmutters Hände erkannten auf dem Bergpfad sofort, welches Blatt essbar ist. In einem Korb voller Kräuter ist die ganze Jahreszeit mit ihrem Duft eingeschlossen."},"ICON-1221":{"nm":"Beifuß","de":"Das erste Kraut, das durch den gefrorenen Boden bricht – herb und zugleich aromatisch. Zu Reiskuchen verarbeitet, trägt es den Frühlingsglanz direkt in den Mund. Zu Neujahr kochte man daraus eine Suppe, um das Unglück des neuen Jahres abzuwehren. Der Frühling kam stets mit diesem Duft."},"ICON-1222":{"nm":"Perilla-Blätter","de":"Schon ein einziges Blatt hinterlässt einen intensiven Duft im Mund. Zu goldenem Samgyeopsal gereicht oder in Sojasoße eingelegt, ist eine Schüssel Reis im Handumdrehen leer. Dieses besondere Aroma ist nur am Tisch dieses Landes wirklich zuhause."},"ICON-1223":{"nm":"Grüner Paprika","de":"Eine grüne Frucht, die hohl und knackig zerbricht. Der leichte Bitterton weckt den müden Gaumen, beim Braten in Öl wird die Farbe noch lebhafter. Fein gehackt und darüber gestreut macht er jedes Gericht sofort frisch und lebendig."},"ICON-1224":{"nm":"Paprika","de":"Rot, gelb, orange – wie eine Ampelfarbenauswahl in einem Korb. Roh reinbeißen und es läuft ein süßer Saft heraus; allein die Farben erhellen den Tisch. Der Satz, dass gut aussehendes Gemüse auch besser schmeckt, trifft hier genau zu."},"ICON-1225":{"nm":"Tomate","de":"Das runde Rote, über das sich Obst und Gemüse immer stritten. Lang gekocht wird der Geschmack tiefer, roh gegessen ist es herrlich frisch. Wer in dieses Fruchtfleisch, das am ehrlichsten die Sommersonne speichert, hineinbeißt, dem platzt der Mittag im Mund."},"ICON-1226":{"nm":"Gurke","de":"Das kühlste Grün gegen die Sommerhitze. In kalter Suppe treibend macht sie den Mund erfrischend kühl; als Sobaegi-Kimchi eingelegt, bleibt sie knackig. An heißen Tagen tut sie auch dünn aufgeschnitten auf den Augen gut – ein Gemüse, das innen wie außen erfrischt."},"ICON-1227":{"nm":"Kürbis","de":"Er hängt rund an der Ranke und füllt sich bis in den Spätherbst langsam mit Süße. Lang geschmort wird er zum gelben Brei, der den Bauch beruhigt; gebraten wird er zum goldbraunen Pfannkuchen. Unters Vordach gehängt, hält er den ganzen Winter als Vorratskammer durch."},"ICON-1228":{"nm":"Zucchini","de":"Tagtäglich dicker werdend im Sommergarten – ein helles Hellgrün. In den Doenjang-Eintopf grob geschnitten, als Pfannkuchen goldgelb gebraten – weich genug selbst für kleine Kindermünder. Alltäglich und deshalb umso willkommener: ein treuer Stammgast auf dem Sommertisch."},"ICON-1229":{"nm":"Aubergine","de":"Eine längliche Frucht mit purpurviolettem Glanz. Im Öl wird sie unendlich weich, gedämpft hat sie eine Textur wie Seide. Unauffällig und doch zu allem passend – die freundliche Nebenrolle auf dem Esstisch."},"ICON-1230":{"nm":"Mais","de":"Gelbe Körner, sauber in Reih und Glied. Im Topf gedämpft und pustend abgebissen – ein Sommersnack und zugleich das erfreuliche Zeichen, dass das Feld reif ist. Im flauschigen Bart verbirgt sich jede Menge Süße."},"ICON-1231":{"nm":"Sojabohnen","de":"Die kleinen, harten Körner saugen über Nacht Wasser auf und werden prall. Fein gemahlen wird es Sojamilch, lange fermentiert wird es zu Paste – das Protein auf dem Tisch dieses Landes hatte seinen Ursprung meistens hier. Eine in die Erde gesäte Bohne kehrt als ganze Pflanze zurück."},"ICON-1232":{"nm":"Tofu","de":"Wenn Sojabohnen Wasser aufnehmen, gemahlen und geformt werden, entsteht ein weißer Block mit glatten Kanten. Er ist weich und unkompliziert und beharrt in keiner Suppe auf seiner eigenen Farbe. Er zerfällt beim Löffelstich sanft – ein Essen, dessen Schlichtheit seine Tugend ist."},"ICON-1233":{"nm":"Rote Bohnen","de":"Gart man die kleinen roten Körner lang, entfaltet sich ein tiefes, dunkles Süßaroma. In der längsten Nacht wärmt eine Schüssel heißer Patjuk und vertreibt Kälte und böse Geister zugleich. In den Lagen des Sirutteok war dieses Rote schlicht und einfach Hingabe."},"ICON-1234":{"nm":"Bohnenpaste (Anko)","de":"Aus gekochten roten Bohnen wird eine weiche Füllung gerührt, eingekocht und nochmals eingekocht. Zwischen Brotscheiben, in Reiskuchen, löffelweise auf Bingsu – ein Hauch Süße wärmt auch alte Erinnerungen mit auf. Die lange Zeit des Abseihen und Einkochen wird selbst zur Süße."},"ICON-1235":{"nm":"Pilze","de":"Nach dem Regen tauchen sie still im dunklen Waldschatten auf und strecken die Köpfe heraus. Sie entfalten ihren Duft ganz ohne Sonnenlicht – das Geschick der Erde. Nur eine Handvoll in die Suppe, und schon entsteht eine tiefe Umami-Note ganz ohne Fleisch. Das Geheimnis, das der Wald hütet."},"ICON-1236":{"nm":"Shiitake-Pilze","de":"Ein brauner Schirm mit weit geöffnetem Hut. An der Sonne getrocknet wird der Duft um ein Vielfaches intensiver, und ein einziger getrockneter Pilz reicht für einen ganzen Suppentopf. Ein verlässlicher Pfeiler der vegetarischen Küche und ein treuer Begleiter für alle, die tiefen Geschmack schätzen."},"ICON-1237":{"nm":"Matsutake-Pilze","de":"Tief im Herbstkiefernwald taucht er nur neben Kiefern versteckt auf. Weil man ihn nicht anbauen kann und nur durch eigene Schrittzählung findet, ist er umso kostbarer. Kurz gegrillt und mit einem Hauch Salz getupft – und schon hält ein Stück Wald Einzug in den Mund."},"ICON-1238":{"nm":"Kräuterseitlinge","de":"Den dicken Stiel der Faser entlang zu zupfen gibt einem das Gefühl des Bissfesten direkt in die Hand. Er wächst das ganze Jahr über verlässlich und findet immer einen Platz auf dem Tisch. Gegrillt oder gebraten – sein üppiges Fleisch ist erfüllend ohne zu belasten."},"ICON-1239":{"nm":"Erdbeere","de":"Am Ende eines Foliengewächshauses, das den Winter überstand, reift sie als Erstes rot. Ein Bissen und es schmeckt süß-sauer – wie das erste Begrüßen des frühen Frühlings. Eine einzige Beere auf dem Kuchen lässt selbst einen gewöhnlichen Tag zum kleinen Festtag werden."},"ICON-1240":{"nm":"Heidelbeere","de":"Beim Zerplatzen breitet sich eine helle Säure im Mund aus. Die kleinen violetten Kügelchen einzeln zu pflücken, und schon ist das Schälchen leer; auf weiße Milch gestreut entsteht ein kleiner Nachthimmel. Ihre Farbe macht selbst den Alltag ein wenig festlich."},"ICON-1241":{"nm":"Apfel","de":"Beim Hineinbeißen kracht der Herbst knackig auseinander. Das Rot, das die Obstbauernoma mit einem Tuch abrieb und reichte, hat Stunden Sonnenlicht gespeichert. Je fester, desto länger bleibt er süß – das weiß er selbst."},"ICON-1242":{"nm":"Birne","de":"Schält man die Schale ab, kühlt zuerst die Fingerspitze. Auf dem Jahreszeitenopfertisch in der ersten Reihe – wenn der kühle, süße Saft den Mund füllt, setzt sich eine Brise des Herbstabends leise daneben."},"ICON-1243":{"nm":"Pfirsich","de":"Wo die Pfirsichblüten abfallen, reift ein flaumiger Sommer heran. Leicht drücken und der Duft breitet sich zuerst aus; beim ersten Bissen strömt die ganze Jahreszeit in den Mund."},"ICON-1244":{"nm":"Weintrauben","de":"Violette Beeren hängen als eine Traube zusammen, jede an der anderen Schulter lehnend. Beim Zerplatzen kommt zuerst die Säure und die Süße folgt einen halben Takt später – wie ein ruhiges Chorgesang am Ende des Sommers."},"ICON-1245":{"nm":"Grüne Weintrauben","de":"Das helle Grün lässt Sonnenlicht direkt durchscheinen, sodass jede Beere wie eine Laterne leuchtet. Ohne Kerne und klar erfrischend – eine Süße ohne jedes Zuviel, wie der erste Ton eines Liedes."},"ICON-1246":{"nm":"Zitrone","de":"Mit dem Fingernagel über die gelbe Schale ritzen und der Duft springt einem an die Nase. Schon ein Tropfen zieht die Mundwinkel zusammen – doch nach der Säure hellt sich der Tag auf merkwürdige Weise wieder auf."},"ICON-1247":{"nm":"Limette","de":"Kleiner und dunkler als eine Zitrone, begrüßt diese Frucht mit einem prickelnden Duft. Schon ein Stück weckt selbst lauwarmes Wasser sofort auf – ein kleines, aber kraftvolles Stück Frische."},"ICON-1248":{"nm":"Orange","de":"Die Schale abzupfen lässt an den Fingern den Duft von Sonnenlicht entstehen. Eine nach der anderen in den Mund – und kleine süße Wasserblasen platzen nacheinander auf. Rundes macht auch die Stimmung runder."},"ICON-1249":{"nm":"Mandarine","de":"Weißt du noch – unter der Bettdecke auf dem Fußbodenheizungsabteil, mit den Füßen drin, Mandarinen pellen? Der Duft, der sich zwischen den Fingernägeln ausbreitete, färbte das ganze Zimmer gelb. Eine Tüte reicht, um die Familie zusammenzurufen."},"ICON-1250":{"nm":"Banane","de":"An einem hungrigen Morgen im Übungsraum rollte sie aus der Tasche – dieses eine Gelbe, das eine Mahlzeit war. Weich, süß und sättigend – der herzlichste Notbehelf."},"ICON-1251":{"nm":"Ananas","de":"Erst wenn man die stachelige Außenseite überwindet, kommt das gelbe Innere zum Vorschein. Ein Stück in den Mund und Süß-Sauer prickelt auf der Zunge; schon schwirrt der Geruch des Südmeeres um die Lippen."},"ICON-1252":{"nm":"Mango","de":"Das reife Fruchtfleisch mit den Händen teilen und der klebrige Süßduft benetzt die Finger. Wenn das satte Gelb im Mund schmilzt, streift einen ein süßer Traum – wie ein kurzes Mittagsschläfchen im Sommer."},"ICON-1253":{"nm":"Kokosnuss","de":"Die harte Schale schütteln und es plätschert innen. Aufbrechen und man findet weißes Fruchtfleisch und kühlen Saft – ein kleines Gefäß, in dem das ferne Meer in seiner Gänze schwappt."},"ICON-1254":{"nm":"Drachenfrucht","de":"Beim ersten Anblick der rosa Schuppen zögert man, doch aufgeschnitten zeigt sich weißes Inneres voller kleiner Punkte. Vom Geschmack schlicht, von der Erscheinung prächtig – eine Frucht, bei der Inneres und Äußeres genau entgegengesetzt sind."},"ICON-1255":{"nm":"Kiwi","de":"Die braune, flauschige Außenseite halbieren und es kommt grünes Juwel zum Vorschein. Das Querschnittsbild mit den sternförmig eingebetteten schwarzen Kernen einen Löffel nehmen – und die saure Kostprobe reißt einen aus dem Schlaf."},"ICON-1256":{"nm":"Hähnchenfleisch","de":"In der geölten Pfanne zischt es laut – und das goldbraune Geräusch ist das Erste, was gart. Mild und zart, es passt auf jeden Tisch ohne anzuecken – der vertraute Gast bei einer schlichten Mahlzeit."},"ICON-1257":{"nm":"Schweinefleisch","de":"Auf dem Grillrost brutzelt und spritzt das Fett und es bräunt sich langsam golden. Auf ein Salatblatt legen, Ssamjang drauf und den Mund voll nehmen – der nussige Duft wärmt die ganze Runde beim Feierabendessen."},"ICON-1258":{"nm":"Rindfleisch","de":"In jedem roten Faserbündel glänzt fein eingebettetes Fett. Auf die heiße Steinplatte gelegt nimmt der Duft zuerst den Platz ein, und mit dem ersten Bissen löst sich die Müdigkeit des Tages ganz still auf."},"ICON-1259":{"nm":"Speck","de":"Morgens in der Pfanne knistert das Fett und tanzt. Allein dieser salzige Duft bringt selbst den Langschläfer gähnendes Auges in die Küche – eine Mahlzeit, zu der der Geruch schon vorher ruft."},"ICON-1260":{"nm":"Würstchen","de":"Wo der Einschnitt aufgeht, platzt der Fleischsaft heraus. Das rote Tintenfischform-Würstchen, das ein Lunchbox-Fach bewachte – ein kleiner Luxus, den die Mittagspause der Kindheit genoss."},"ICON-1261":{"nm":"Peperoni (Belag)","de":"Die kleine, würzige Scheibe wölbt sich auf dem heißen Käse von den Rändern her ein. Wenn sich Öl leicht sammelt, ist das der Höhepunkt auf einer Pizza – klein, aber mit rundem, intensivem Auftreten."},"ICON-1262":{"nm":"Burger-Patty","de":"Dick geformt und auf die Grillplatte gelegt, bräunt es sich von den Rändern her. Zwischen zwei Brotscheiben mit Gemüse drin – eine Handvoll Sättigung, fertig gepackt."},"ICON-1263":{"nm":"Ei","de":"Aufschlagen, und das Eigelb gleitet wie eine runde Sonne hinein. Auf frisch gekochtem Reis umgerührt genauso gut, als gelber Streifen im Gimbap auch – das alltäglichste und herzlichste Protein."},"ICON-1264":{"nm":"Milch","de":"Eine kühle Flasche vor der Tür am frühen Morgen – das Gefühl dieser Kälte in der Handfläche öffnete einst den Tag. Erwärmt steigt Dampf auf, gekühlt duftet sie nussig – ein immer präsentes Weiß."},"ICON-1265":{"nm":"Käse","de":"Eine gelbe Scheibe zerfällt langsam auf warmem Brot. Auf diesen einen Moment des langen Ziehens zu warten – je mehr er schmilzt, desto tiefer und nussiger wird der Geschmack."},"ICON-1266":{"nm":"Cheddar-Käse","de":"Das kräftige Orange kündigt schon auf den ersten Blick einen salzigen Geschmack an. Dünn geschnitten auf Toast gelegt verbreitet sich Umami im ganzen Mund – so klar die Farbe, so klar der Charakter."},"ICON-1267":{"nm":"Butter","de":"Ein Stück in die heiße Pfanne fallen lassen, und es schmilzt zischend weg, während nussiger Dampf aufsteigt. Aufs Brot streichen, in den Reis rühren – sie macht alles, was sie berührt, eine Spur zarter. Das gelbe Wunder."},"ICON-1268":{"nm":"Schlagsahne","de":"Je länger man rührt, desto fester werden die weichen weißen Flocken zu einer stabilen Wolke. Einen Löffel auf dem Kuchen – und ein gewöhnlicher Nachmittag wird hell wie ein kleiner Geburtstag."},"ICON-1269":{"nm":"Joghurt","de":"Der Löffel gleitet glatt durch das säuerlich-weiße, weiche Innere. Mit einem Stück Obst drin wird der Morgen leichter, eine Tasse davon beruhigt den Bauch sanft – der Geschmack eines sanften Anfangs."},"ICON-1270":{"nm":"Makrele","de":"Auf dem Rost spritzt Öl und steigt ein Rauch auf, halb fischig, halb nussig, und füllt die Küche. Die Gräten herauspicken und auf den Reis legen – in dieser einfachen, alltäglichen Geste steckt tiefste Fürsorge."},"ICON-1271":{"nm":"Lachs","de":"Rosa Fasern liegen ordentlich gefaltet übereinander. Kalt geschöpft löst er sich weich im Mund auf, gebraten ist er nussig vom Fett – ein entschiedener Geschmack, der aus einem fernen Meer geschwommen kam."},"ICON-1272":{"nm":"Thunfisch","de":"Den Deckel der Dose aufzureißen lässt einen salzigen Duft aufsteigen. In den Reis mischen, in Meeresalgen wickeln und essen – in einer Studentenbude wurde eine Dose zur vollständigen Mahlzeit. Es gab diese Zeit."},"ICON-1273":{"nm":"Kabeljau","de":"Das helle, milde Fleisch ergibt beim Kochen eine klare, erfrischende Brühe. Weißer Fisch, der den schneidenden Wind des Winterhafens überstanden hat – eine heiße Eintopfschüssel lässt langsam auch frostige Hände auftauen."},"ICON-1274":{"nm":"Garnelen","de":"Beim Garen rollen sie sich zusammen und das Grau rötet sich zartrosa. Der knackige Biss und der nussige Duft – wenn man sie eine nach der anderen pult, ist der Teller unversehens leer."},"ICON-1275":{"nm":"Krabbe","de":"Das weiße Fleisch aus dem harten Panzer zu lösen ist ein kleines Geduldsspiel. Der Bissen am Ende dieser Mühe ist köstlich süß – und für einen Augenblick hält der ganze Herbst am Meer Einzug in den Mund."},"ICON-1276":{"nm":"Tintenfisch","de":"Auf dem Grillrost rollt er sich zusammen und steigt ein nussig duftender Rauch auf. Ein Stück zäh kauen, in Gochujang tauchen und in den Mund stecken – und das salzige Meer kommt gleich mit."},"ICON-1277":{"nm":"Muscheln","de":"In der klaren Brühe öffnen sie sich und geben ihren Duft sanft preis. Das Blubbern und der Meeresgeruch breiten sich aus, und ein Schlürfen wärmt das Innerste."},"ICON-1278":{"nm":"Fischkuchen","de":"Am Spieß in heiße Brühe getaucht steigt Dampf auf. Vor dem Imbisswagen an einem kalten Tag, Brühe in einen Papierbecher nehmen und pusten – der kleine Trost, den eine Gasse reicht."},"ICON-1279":{"nm":"Kimchi","de":"Im Krug langsam reifend wächst ein saures, tiefes Aroma heran. Mit den Händen in Stücke reißen und auf frischen Reis legen – und schon verrät der Geschmack, welche Familie dahintersteht. Jedes Haus hat seinen eigenen Kimchi."},"ICON-1280":{"nm":"Eingelegter Rettich (Takuwan)","de":"Eine gelbe Scheibe zerbricht knackig und lebhaft im Mund. Der treue Begleiter neben dem Gimbap und einem Teller Snacks – das Säuerlich-Süße spült den fettigen Gaumen frisch aus."},"ICON-1281":{"nm":"Pickles","de":"Die Gurke kurz im Salz atmen lassen, dann im Essig die Augen aufmachen. In dem Moment, wenn die Knackigkeit zurückkehrt, verlässt das Einmachglas nicht das sonnige Fensterbrett. Das langsam Einlegen bringt den Geschmack."},"ICON-1282":{"nm":"Gochujang","de":"Das Rot, das ein Jahr lang im Krug ausgeharrt hat. Hinter der Schärfe verbirgt sich sachte eine Süße der Sojabohne, und ein Löffel davon macht aus dem Eintopf das Gesicht des eigenen Hauses. Das ist die Tiefe, die der Sonnenschein auf dem Krugständer im Hof heranzog."},"ICON-1283":{"nm":"Doenjang","de":"Der Meju hielt mit dem Schimmel zusammen einen ganzen Winter durch. Das Herzhafte ist ein heikler Balanceakt zwischen Reife und Überreife – Großmutter erkannte diesen Übergang allein am Geruch an den Fingerspitzen. Der Geschmack wächst mit der Wartezeit."},"ICON-1284":{"nm":"Sojasoße","de":"Je schwärzer die Bohne wird, desto tiefer ihr Inneres. Ein Tropfen davon belebt das Gemüse und verleiht dem Schmorgericht Glanz – alle Farben in der Küche gehen letztlich von diesem warmen Braun aus. Umami jenseits des Salzigen."},"ICON-1285":{"nm":"Schwarze Bohnenpaste","de":"Auch wenn beide schwarz sind, ist die Textur unterschiedlich. Das Karamellisieren gibt eine süß-salzige Endnote, und in Nudeln gerührt belebt der schwarze Glanz den Gaumen. Der erste Knopf, an dem das Wok-Feuer beginnt."},"ICON-1286":{"nm":"Currypulver","de":"Verschiedene Gewürze schmiegen sich freundlich in einem Löffel zusammen – ein gelbes Pulver. In Wasser gelöst blubbert es und wärmt das ganze Haus; es ist das Vorspiel zur wärmsten Schüssel an einem verregneten Abend."},"ICON-1287":{"nm":"Schwarzer Pfeffer","de":"Erst frisch gemahlen lebt das Aroma auf – vorher mahlen und es flüchtet leise. Deshalb die letzte Drehung immer kurz vor dem Ausschalten des Herdes. Das kleine Ausrufezeichen, das die kochende Hand aufhebt."},"ICON-1288":{"nm":"Chilipulver","de":"Unter dem Herbstsonnenlicht getrocknete Taeyang-Chilis vollenden das Rot. Ob fein oder grob gemahlen – davon hängt der Charakter des Kimchis ab. Handarbeit bedeutet letztlich, die Körnung dieses Pulvers zu wählen."},"ICON-1289":{"nm":"Salz","de":"Die Würze abzustimmen heißt, sich Prise für Prise dem Fehlenden zu nähern. Einmal drin, lässt sich das Salzige nicht mehr zurücknehmen, also legt die geübte Hand immer am Ende ein wenig weniger rein und kostet. Was zurückgehalten wird, ist der Spielraum."},"ICON-1290":{"nm":"Zucker","de":"Er beruhigt Bitteres und rundet die Ecken der Säure ab. Doch Süße darf sich nicht verraten – je besser ein Gewürz, desto stiller verschwindet der Zucker im Hintergrund. Eine Süße, die zu schweigen weiß."},"ICON-1291":{"nm":"Honig","de":"Ein Glas, für das Bienen das Blumenfeld tausende Male überquert haben. Wenn er kristallisiert, im Warmwasserbad wieder verflüssigen; in Tee eingerührt legt er sich sanft um die Kehle. Ein goldener Löffel, in dem eine ganze Saison eingekocht ist."},"ICON-1292":{"nm":"Speiseöl","de":"Eine Runde in die heiße Pfanne und die Zutaten vergessen das Ankleben. Zu früh eingefüllt verbrennt es, zu spät klebt alles – genau der Moment, wenn der Rauch aufsteigt, ist die Kunst des Pfannkuchenbackens. Die Zeit hört man an den Geräuschen."},"ICON-1293":{"nm":"Olivenöl","de":"Im erstgepressten Grün leben Kräuterduft und ein leichtes Brennen nebeneinander. Es sollte erst am Schluss drüber geträufelt werden, damit das Aroma erhalten bleibt – unerhitzt ist die ehrlichste Verwendung."},"ICON-1294":{"nm":"Sesamöl","de":"Ein letzter Tropfen am Ende und das Gemüse erklärt sich für fertig. Da Nussigkeit bei Hitze schnell entweicht, kommt es stets nach dem Ende aller Kochvorgänge als stiller Schlusspunkt dazu."},"ICON-1295":{"nm":"Vanilleschote","de":"Eine Schote aufschneiden und die schwarzen Samen herausschaben – und das Dessert wechselt das Duftkostüm. Die verbrauchte Hülle nicht wegwerfen, sondern im Zuckertopf aufbewahren – die altüberlieferte Sparsamkeit der Patisserie."},"ICON-1296":{"nm":"Kakao","de":"Im Fruchtinneren weißes Fruchtfleisch und bittere Samen. Fermentation und Sonnenwärmtrocknung sind nötig, bevor sich das Ganze in die Süße übersetzt, die wir kennen. Vor dem Schokolade-Werden hat er das wildeste, ursprünglichste Gesicht."},"ICON-1297":{"nm":"Schokolade","de":"So empfindlich, dass sie in der Wärme der Handfläche allein schon schmilzt. Um bei knapp 28 Grad den matten Knackglanz zu erhalten, muss sie richtig temperiert werden – hinter der Süße verbirgt sich überraschend eine penible Temperaturregelung."},"ICON-1298":{"nm":"Kaffeebohnen","de":"Ein noch unverarbeitetes Korn gleicht fast einem stillen Schweigen. Doch begegnet es heißem Wasser, bläht es sich auf und gibt seinen Duft frei – das erste Signal, den Morgen zu wecken, kommt stets von diesem kleinen Korn."},"ICON-1299":{"nm":"Teeblätter","de":"Zu lang im heißen Wasser und es wird herb, zu kurz und es bleibt schal. Die Zeit ruhig abzuwägen, in der die Blätter sich langsam entfalten – Tee aufzubrühen ist das Messen der Geduld mit den Fingerspitzen."},"ICON-1300":{"nm":"Minze","de":"Quetscht man sie, dringt Bitteres heraus – also immer behutsam anfassen. Leicht antippen, um den schlafenden Duft zu wecken, und an heißen Tagen in ein Glas geben; dann sinkt der Hochsommer um einen Ton kühl ab."},"ICON-1301":{"nm":"Kräuter","de":"Den Stiel mitverwenden macht das Aroma tief, nur die Blätter verwenden macht es klar. Getrocknet intensiviert es sich, frisch verwendet bleibt es frisch – je nach dem Duftspektrum eines einzigen Bunds öffnet sich auch die Küche weiter."},"ICON-1302":{"nm":"Kastanie","de":"Im stacheligen Mantel verbirgt sich das glänzende Fruchtfleisch. Einritzen und rösten, dann platzt sie auf und duftet süßlich – als greife man gerade nach dem warmen Beutel mit Maroni aus einer Herbstgasse."},"ICON-1303":{"nm":"Erdnüsse","de":"Das Nussige entsteht im Röstfeuer. Eine nach der anderen aufpuhlen und man verliert das Zeitgefühl – auf dem Dielenboden im Kreis sitzen und teilen, dann plaudern die Geschichten gleich mit."},"ICON-1304":{"nm":"Mandeln","de":"Kurz blanchieren und die Haut abziehen, dann wird das Innere noch weißer und weicher. Gemahlen wie Milch, ganz geröstet knusprig – eine einzige Mandel birgt so viele Verwandlungen, dass die Fantasie des Konditors weit reicht."},"ICON-1305":{"nm":"Sesam","de":"Bei schwacher Hitze sachte schwenken, und irgendwann hüpfen die Körner los. Kurz bevor das Geräusch aufhört, ist der nussigste Moment – Sesam rösten wird am Ende zur Aufgabe für die Ohren."},"ICON-1306":{"nm":"Zuckerrohr","de":"Einen Stängelabschnitt kauen, und zusammen mit einem Kräuterduft dringt Süßsaft heraus. Einkochen und nochmals einkochen, bis die Süße entsteht, die wir kennen – der Anfang des Zuckers ist überraschend grün und hoch gewachsen."},"ICON-1307":{"nm":"Rohrzucker","de":"Eine grobe Süße, die weniger raffiniert ist und ihre eigene Farbe bewahrt. Ein leises Erdiges klingt noch nach, und wer die Ehrlichkeit des Unpolierten schätzt, sucht ihn gezielt auf."},"ICON-1308":{"nm":"Kakaobohnen","de":"Die frisch aus der Schote geholten Samen sind bitter und herb. Erst wenn sie die Tage der Fermentation still überstehen, entfaltet sich das Aroma – Süße ist die kleine Belohnung, die diese Bohne nach langem Warten empfängt."},"ICON-1309":{"nm":"Kakaonibs","de":"Die gerösteten und zerbrochenen Bohnen enthalten keinen einzigen Körnchen Zucker. Im Mund kommt zuerst das Herbe und das Nussige folgt später – so begegnet man dem Kakao am ehrlichsten, vor aller Süße."},"ICON-1310":{"nm":"Grüne Kaffeebohnen","de":"Noch grasig riechende, grüne Körner. In diesem Zustand schläft das Aroma tief, und bis sie das Feuer empfangen haben, ruhen sie still als Möglichkeit – ohne zu wissen, was sie noch werden."},"ICON-1311":{"nm":"Geröstete Kaffeebohnen","de":"Auf der braunen Oberfläche, aus der leicht Öl tritt, hat sich das Aroma angesammelt. Vor dem Abkühlen mahlen, damit es erhalten bleibt – das Schicksal einer Tasse wird nach dem Rösten still in wenigen Tagen entschieden."},"ICON-1312":{"nm":"Vanilleschote","de":"Ein einziger Streifen Duft durchdringt einen ganzen Topf Milch. Selbst die verbrauchten Hülsen in den Zuckertopf stecken – nach einigen Tagen duftet der ganze Zucker; ein Luxus, bei dem nichts weggeworfen werden muss."},"ICON-1313":{"nm":"Schwarzer Pfeffer","de":"Das Aroma eines ganzen Pfefferkorns nimmt ab dem Moment des Mahlens ab. Deshalb hält man ihn ganz auf dem Tisch und mahlt ihn jedes Mal frisch – Frische kommt aus dem Mut, nicht aufzuschieben."},"ICON-1314":{"nm":"Weißer Pfeffer","de":"Die enthüllten, glatteren Körner sind milder als ihr schwarzes Gegenstück. Aus dem Wunsch, in heller Soße keinen schwarzen Punkt zu hinterlassen, geboren – eine Feinheit, die an unsichtbarer Stelle wirkt."},"ICON-1315":{"nm":"Zimt","de":"Eine Stange aufgebrüht bringt langsam ein warmes Brennen in den Tee. Im Stück zu verwenden hält das Aroma länger als als Pulver, und die Tiefe eines Wintergetränks kommt aus der Ausdauer dieser getrockneten Rinde."},"ICON-1316":{"nm":"Gewürznelken","de":"In einer kleinen nagelförmigen Knospe ist Duft in Hülle und Fülle konzentriert. Zu viele und das Gericht wird überdeckt – eine einzige Nelke in Maßen hält das Gleichgewicht des Aromas still aufrecht."},"ICON-1317":{"nm":"Muskatnuss","de":"Den ganzen Samen erst kurz vor Gebrauch leicht abreiben. Da das Aroma bei vorgeriebener Variante schnell verfliegt, macht der letzte kurze Abrieb die Milchnote um eine Nuance tiefer."},"ICON-1318":{"nm":"Kardamom","de":"Die grüne Kapsel aufplatzen und ein frischer Duft strömt heraus. Zwei Kapseln im Tee aufgebrochen, und ein gewöhnliches Glas erhält auf einmal den Duft eines fernen Landes."},"ICON-1319":{"nm":"Safran","de":"Aus einer einzigen Blüte werden nur drei rote Fäden geerntet. In warmem Wasser aufgelöst breitet sich Gelb langsam aus – Kostbarkeit ist auch das Gewicht der Zeit, die jemand in der Ernte Hand für Hand aufgewendet hat."},"ICON-1320":{"nm":"Kurkuma","de":"Die Wurzel aus der Erde mahlen und sogar die Fingerspitzen färben sich gelb. In Öl leicht angeröstet erwacht das Aroma – das goldene Leuchten des Currys ist die Farbe, die diese kleine Wurzel über dem Feuer entfacht hat."},"ICON-1321":{"nm":"Lorbeerblatt","de":"Das Blatt, das man einst dem Sieger auf die Stirn legte. Eines ins kochende Wasser geben und zwischen dem Dampf taucht kurz das Rauschen alter Arenen auf. Auch wenn man verloren hat – seinen Duft einzuatmen ist ein stilles grünes Trost, das den heutigen Tag leise umarmt."},"ICON-1322":{"nm":"Kokosmilch","de":"Der weiße Saft, der erst nach dem Aufbrechen der harten Schale fließt. An einer Marktecke eines heißen Landes einen Strohhalm reinstecken und einen Schluck nehmen – und der Durst der Mittagshitze erlischt. Der kühle Süßduft, der sich im Mund ausbreitet, bringt den Schatten der Tropen mit."},"ICON-1323":{"nm":"Kokosöl","de":"Fest ist es weiß wie frischer Schnee, in der Handfläche gewärmt breitet sich der Duft sanft aus. Eine Dose reicht von Kopf bis Fuß, hieß es – die herzliche Haushaltsweisheit der Inselin, kompakt in einer runden Dose aufbewahrt."},"ICON-1324":{"nm":"Getrocknete Bananen","de":"Unter Sonnenstrahlen ein paar Tage hingelegt, wird das gelbe Fruchtfleisch zäh und weich. Stückchen für Stückchen genüsslich abbeißen, und der klebrige Süßduft der verregneten Erntezeit lebt im Mund langsam wieder auf. So trägt langsam gereifte Süße die Jahreszeit in sich."},"ICON-1325":{"nm":"Getrocknete Mango","de":"Das weiche Fruchtfleisch hat sich unter der Sonne zu bernsteinfarbenem Fruchtgummi verdichtet. In einem Stück stecken sauer, süß und zäh zugleich, und wer sie langsam im Mund rollt, dem wird der Nachmittag beim Verzehr einer ganzen Tüte lang."},"ICON-1326":{"nm":"Getrocknete Ananas","de":"Anders als das stachelige Äußere ist das Fruchtfleisch innen leuchtend gelb und einladend. Getrocknet konzentriert sich die Säure, sodass schon ein Stück die Mundwinkel unweigerlich hebt. Das frische Nachklingen am Ende eines Stücks bleibt lange."},"ICON-1327":{"nm":"Tropenfrüchtekorb","de":"Frisch geerntete Farben liegen zusammen in einem Korb. Das Orange der Mango, das Gelb der Banane, das Gold der Ananas – noch bevor man die Hand ausstreckt, strömt der Sommer zuerst in die Nase. Ein Arm voll Früchte, der allein beim Anblick das Herz aufhellt."},"ICON-1328":{"nm":"Meeresalgenbündel","de":"Das Haar des Meeres, geerntet vom Felsenstrand bei Ebbe. Im salzigen Meeresduft ist das Wellenrauschen verflochten; in klarem Wasser eingeweicht dringt der Meeresgeruch langsam bis in die Küche. Eine Handvoll breitet auf dem Tisch ein kleines Wattenmeer aus."},"ICON-1329":{"nm":"Getrockneter Fisch","de":"Eine Handvoll zäh getrocknetes Meer. Mit den Händen entlang der Faser reißen und mit dem Salzgehalt weht ein alter Hafenwind heraus. Wer einen Schluck Makgeolli dazu vermisst, hat einen herzlichen, alten Freund am Tisch."},"ICON-1330":{"nm":"Getrockneter Tintenfisch","de":"Alle zehn Tentakel ordentlich ausgebreitet und an der Sonne getrocknet. Kurz über der Flamme geröstet bis ein nussiger Duft aufsteigt, dann entlang der Faser ziehen. Das zähe Kauen hebt den Anspruch eines Spätabend-Snacks um eine Stufe."},"ICON-1331":{"nm":"Salzfisch","de":"In grobem Salz vergraben lernt der Fisch, der Zeit standzuhalten. Ein Stück seines tief salzigen Fleisches und eine Schüssel Reis ist im Handumdrehen leer – das herzliche Geheimrezept, das die Großmutter am Meer mit ihren Fingerspitzen weitergab."},"ICON-1332":{"nm":"Garnelenpaste","de":"Kleine Garnelen reifen langsam im Salz zu purer Umami. Ein Löffel davon in den Kimchi-Kohl – und im ganzen Hof breitete sich der salzige Duft des Kimjang-Tages aus. Dieser eine Löffel entscheidet über den Geschmack des Jahres-Kimchis."},"ICON-1333":{"nm":"Sardellen","de":"Ein fingerlanger Körper trägt die Tiefe eines ganzen Suppentopfs. Die Köpfe und Eingeweide entfernen und dabei in der alten Familienküche plaudern – klein, aber stets mittendrin im Herz des Haushalts. Ein dankbarer Fisch."},"ICON-1334":{"nm":"Kombu","de":"Ein langer, schwarzer Streifen, der tief im Meer gewachsen ist. In kaltes Wasser geben und kurz vor dem Aufkochen behutsam herausnehmen – das ist der Pakt, den alle Suppenköche durch die Generationen gehalten haben. Tiefer Umami kennt keine Eile."},"ICON-1335":{"nm":"Hijiki","de":"Die knubbelige Textur platzt im Mund immer wieder auf. Im Frühling färbt diese Meeresalge das Felsenufer grün, zart gewürzt entfaltet sie auf einer Ecke des Tisches ein kleines, frisches Meer. Es schmeckt wie Frühling kauen."},"ICON-1336":{"nm":"Perlmuschel","de":"Zwischen zwei harten Schalen über lange Zeit gehütet – ein rundes Leuchten. Das Unbehagen eines einzigen Sandkorns in einen Edelstein zu verwandeln, darin hat das Meer nie gezögert. In der Handfläche liegt das ganze Gewicht dieser langen Geduld."},"ICON-1337":{"nm":"Korallendeko","de":"Ein Meeresast, den Wellen hunderte von Jahren geformt haben. Im Sonnenlicht breitet er sich in Rosa und Orange aus und macht allein durch Dastehen ein ganzes Zimmer zur warmen Insel. Selbst die raue Oberfläche an den Fingerspitzen fühlt sich vertraut an."},"ICON-1338":{"nm":"Muschelknöpfe","de":"Aus der schimmernden Innenseite einer Muschel wurde ein Kreis ausgestanzt. Jedesmal zuzuknöpfen lässt an den Fingerspitzen einen kleinen Regenbogen aufblitzen. Das letzte herzliche Geschenk, das das Meer hinterließ, bevor es die Muschel verließ."},"ICON-1339":{"nm":"Glasmurmeln","de":"In der Handfläche rollen und das darin gefangene Licht rollt gleich mit. In der Gasse hockend, im Sonnenschein vergessen – wer damals beim Murmelspielen eine mehr ergatterte, hatte eine besonders schwere und stolze Tasche."},"ICON-1340":{"nm":"Zedernholzstück","de":"Aus jedem geritzten Faserbündel dringt ein feines Aroma hervor. Die Alten brannten dieses Holz, um unruhige Gedanken zu ordnen. Ein Stück still in der Hand halten, und von den Fingerspitzen aus steigt langsam Gelassenheit auf."},"ICON-1341":{"nm":"Räucherstäbchen","de":"Ein dünner Faden brennt langsam und bahnt sich nach oben einen Weg. Den Kurven des Rauchs mit den Augen folgen – und das ganze Getriebe des Tages verlangsamt unwillkürlich seinen Schritt und bleibt einen Moment lang still."},"ICON-1342":{"nm":"Färberblüten","de":"Die in den Blütenblättern verborgene Farbe im kochenden Topf aufzulösen lässt ein helles Tuch sich langsam damit tönen. Ein aus der Natur geborgtes Licht auf Zeit – Färben war von jeher ein herzlicher Gruß an die Blume."},"ICON-1343":{"nm":"Indigoblauer Farbstoff","de":"Aus dem Indigostrauch durch wiederholtes Fermentieren gewonnenes tiefes, stilles Blau. Jedes Mal eingetaucht und herausgezogen wandelt sich das Tuch langsam vom Himmelblau zum Meeresblau. Eine Farbe, die erst nach dem Ablegen aller Ungeduld aufblüht – die Farbe des Wartens."},"ICON-1344":{"nm":"Roter Farbstoff","de":"Die Krappwurzel aufzubrühen lässt das im Boden schlafende Abendrot im Topf erwachen. Die Farbe, mit der man einst das Brautkleid bei Festlichkeiten im Dorf schön tönte – das freudigste und hellste Licht im Dorf."},"ICON-1345":{"nm":"Goldfaden","de":"Gold zu einem Faden feiner als ein Haar zu ziehen und Faden für Faden sorgfältig zu spinnen. Wo die Stickerei sitzt, saugt es Licht auf, und selbst in einem dunklen Zimmer ohne Lampenlicht leuchtet das Muster still und warm von allein."},"ICON-1346":{"nm":"Seide","de":"Das Gespinst der Seidenraupe weben und nochmals weben, bis gerade eine Bahn entsteht. An den Handrücken streifend gleitet sie wie Frühlingsfluss dahin – ein glattgewebtes Tuch, das die Alten langsam durch eine ganze Jahreszeit großgezogen haben."},"ICON-1347":{"nm":"Perlmuttknöpfe","de":"Nur das innere Schimmern der Perle, rund geschliffen. Jedes Zuknöpfen am Jeogori lässt die Fingerspitze für einen Moment elegant innehalten. Klein und doch stillt er still die Klasse des Outfits – ein ordentliches Körnchen."},"ICON-1348":{"nm":"Kartenreste (Seekarte)","de":"Hinter dem zerrissenen Rand bricht die unbekannte Küstenlinie ab. Nur wer alle Fetzen zusammenfindet, soll dem Schatz nahekommen – doch vielleicht war die Reise selbst, auf der man den Wind begleitete und suchte, schon längst der Schatz."},"ICON-1349":{"nm":"Alte Seekarte","de":"Vom Meerwasser verwischte Seerouten und verblasste Kompasszeichnungen. Den Strich, den ein Seemann einst in stockdunkler Nacht nur nach Sternen zog, mit dem Finger nachfahren – und eine längst verschwundene Insel taucht auf dem alten Papier langsam wieder auf."},"ICON-1350":{"nm":"Flaschenpost","de":"Von Wellen getrieben kommt ein Glasfläschchen mit einem aufgerollten Zettelchen darin. Ein Gruß, von dem niemand weiß, wer ihn wann abgeschickt hat, hat endlich jemandes Hände erreicht. Auch das Meer kann, wenn es nur den Willen hat, zum langsamen Postboten werden."},"ICON-1351":{"nm":"Treibkiste","de":"Das Abenteuer steckt im Moment, bevor man den salzverkrusteten Deckel aufbricht. Ob Schatz oder leerer Sand — eine weit gereiste Kiste trägt stets die unbekannte Geschichte irgendjemandes mit sich."},"ICON-1352":{"nm":"Kleiner Schlüssel","de":"Ein abgenutztes Stück Eisen, das bequem in die Handfläche passt. Welches Schloss er öffnet, ist längst vergessen — doch sein vertrautes Gewicht lässt einen zuerst ans Aufschließen denken, nicht ans Verschließen."},"ICON-1353":{"nm":"Silbermünze","de":"Rundes Silber, dessen Muster von vielen Händen glattgerieben wurde. Einst bezahlte man damit Fährplätze und karge Nächte. Streicht man mit dem Finger über die kühle Oberfläche, erwacht die Wärme eines längst vergangenen Handels wieder."},"ICON-1354":{"nm":"Goldmünze","de":"Schon das Gewicht auf der Handfläche lässt das Herz höherschlagen. Eine einzige Münze, die im Sonnenlicht golden aufleuchtet — und doch glänzt am hellsten das Kribbeln kurz vor dem Griff danach."},"ICON-1355":{"nm":"Kapitänssiegel","de":"Das Versprechen des Kapitäns, tief in rotes Wachs gedrückt. Ein einziges Muster gab Befehlen Geltung und legte raue Kurse fest. Autorität war letztlich nichts anderes als ein kleiner, fester Stempel — dem alle an Bord gemeinsam vertrauten."},"ICON-1356":{"nm":"Handmikrofon","de":"Sobald man es umschließt, liegt ein merkwürdig beruhigendes Gewicht in der Hand. Beim zitternden ersten Gruß wie beim finalen Hochton — dieser kleine Stab verleiht der Stimme ganz leise Flügel."},"ICON-1357":{"nm":"Funkmikrofon","de":"Mit dem Kabel verschwand auch die Grenze der Bühne. Selbst am letzten Sitz der Zuhörer reißt die Stimme nicht ab — als würde einem jemand sanft den Rücken anstoßen: Lauf, tanz, sing nach Herzenslust."},"ICON-1358":{"nm":"Standmikrofon","de":"Fest auf dem Boden, wartet es still auf den Sänger. Sind die Hände frei, strömt der Gesang nicht mehr aus den Fingerspitzen, sondern aus dem ganzen Körper. Auch darin, an einem Ort bis zum Schluss zu bleiben, steckt eine eigene Würde."},"ICON-1359":{"nm":"Popschutz","de":"Eine einzelne runde Lage Stoff vor dem Mikrofon. Harte Atemgeräusche werden weich gefiltert, nur die klare Stimme darf hindurch. Gut verständlich zu machen bedeutet manchmal, unsichtbar an seinem Posten zu bleiben und zu schützen."},"ICON-1360":{"nm":"In-Ear-Monitor","de":"Tief im Ohr taucht die eigene Stimme mitten im Lärm von Tausenden wieder auf. Inmitten von Licht und Schall ist das der kleinste und diskreteste Begleiter, der dafür sorgt, den Takt nicht zu verlieren."},"ICON-1361":{"nm":"Kopfhörer","de":"Sobald sie die Ohren umschließen, schrumpft die Welt um eine Handbreit — und nur die Musik bleibt groß. Ein rundes Zimmer für sich allein. Im Kopfhörer ist man seltsamerweise alles andere als allein."},"ICON-1362":{"nm":"Notenblatt","de":"Wenn schwarze Punkte auf den Linien zur Ruhe kommen, nimmt das schweigende Papier Klang in sich auf. Buchstaben, die man nicht liest, sondern hört. Im Aufschlagen beginnt der Gesang erneut zu atmen."},"ICON-1363":{"nm":"Vokalpartitur","de":"An jedem Atemzug ein kleiner Kreis. Hier einatmen, dort sanft loslassen. Eine freundliche Karte, die der Stimme den Weg weist, damit sie nicht verletzt wird."},"ICON-1364":{"nm":"Klavierpartitur","de":"Eine Seite, auf der zehn Finger gleichzeitig den Weg erfragen. Die linke Hand verankert die Wurzel, die rechte zeichnet den Gesang. Zwei Hände, die verschiedenes erzählten, finden sich im letzten Takt schließlich zusammen."},"ICON-1365":{"nm":"Gitakkordraster","de":"Die erste Fremdsprache der Finger, und ihr erstes Wort steht hier geschrieben. Wenn sechs Punkte zu einem Kreis werden, erklingt endlich ein Ton. Jede Übungsnacht hinterlässt eine Schwiele mehr."},"ICON-1366":{"nm":"Metronom","de":"Tick, tick — ein unerschütterlicher Schritt schlägt nebenan. Wenn das Herz vorauseilt, hält es von hinten sanft zurück: langsam, langsam. Der Takt ist letztlich ein Versprechen, gemeinsam zu gehen."},"ICON-1367":{"nm":"Stimmgerät","de":"Wenn die Nadel in die Mitte gleitet, findet der Ton seinen Platz. Weder zu hoch noch zu tief — dieser eine Punkt. Richtig liegen bedeutet: aufhören zu zittern und still werden."},"ICON-1368":{"nm":"Klaviertastenkarte","de":"Mit jeder umgeblätterten Seite schreiten die Tasten in die Handfläche. Von Do bis Si — ein kleines Universum aus sieben Feldern. Auch ohne echtes Klavier wächst hier in der Stille ein Lied."},"ICON-1369":{"nm":"Gitarrenpick","de":"Ein kleines, hartes Stückchen zwischen Daumen und Zeigefinger geklemmt. Lässt man es fallen, verschwindet es für immer unter dem Stuhl — doch hält man es fest, erklingen alle sechs Saiten auf einmal."},"ICON-1370":{"nm":"Drumsticks","de":"Treffen zwei Stäbe in der Luft aufeinander, fällt das Startsignal. Eins, zwei, drei, vier. Alle verstreuten Herzen beginnen in diesem Viertakt im selben Rhythmus zu schlagen."},"ICON-1371":{"nm":"Tamburin","de":"Ein Schlag, und der helle Klang splittert wie Sonnenlicht in alle Richtungen. So leicht es wirkt — wenn der Schwung nachlässt, greift man zuerst nach ihm. Klein, aber unantastbar."},"ICON-1372":{"nm":"Tanzschuhe","de":"Für Füße, die über den Boden gleiten, ist Reibung die stärkste Waffe. Jede abgenutzte Sohle trägt die Drehungen all der Male in sich. Die schönste Bewegung beginnt immer mit einem soliden Paar Schuhe."},"ICON-1373":{"nm":"Knieschützer","de":"Nur wer unzählige Male auf die Knie gegangen und wieder aufgestanden ist, weiß, wie wertvoll diese dünne Schicht Stoff ist. Wenn der Boden keine Angst mehr macht — manchmal sitzt Mut einfach ums Knie gebunden."},"ICON-1374":{"nm":"Handgelenkschützer","de":"Wenn man die empfindliche Stelle schon im Voraus umhüllt, werden auch übertriebene Bewegungen etwas nachsichtiger aufgenommen. Das Handgelenk schweigt und erträgt die Last allein, bis der Schmerz es verrät. Eine einzige Schicht hält dieses lange Schweigen auf."},"ICON-1375":{"nm":"Knöchelschützer","de":"Auf jeden hohen Sprung folgt eine Landung, und auf jede Landung folgt der Knöchel. Er trägt das gesamte Körpergewicht an der untersten Stelle auf. Dieses schmale Band schützt still das Training von morgen."},"ICON-1376":{"nm":"Dehnband","de":"Zieht man daran, stemmt es sich dagegen und will zurück. Indem man diesem Widerstand standhält, wird der Körper unmerklich ein Stück dehnbarer. Dehnung ist letztlich die Spur, die das Ausharren hinterlässt."},"ICON-1377":{"nm":"Yogamatte","de":"Sobald sie ausgerollt ist, entsteht auf dem Boden ein eigenes kleines Stück Erde. Ein kleines Territorium zum Strecken, Liegen und Atemholen. Hier findet der Tag seinen stillen Anfang und sein ruhiges Ende."},"ICON-1378":{"nm":"Schaumstoffrolle","de":"Drückt man auf die verspannte Stelle, tut es zuerst weh — dann wird es wohltuend. Etwas Verkrampftes zu lösen, kostet immer ein wenig Schmerz. Denn ob Körper oder Seele: Loslassen braucht immer erst ein bisschen Druck."},"ICON-1379":{"nm":"Hantel","de":"Dasselbe Gewicht heben, wieder und wieder. Einmal mehr als gestern — das ist alles. In dieser schlichten Wiederholung wird der Arm schweigend stärker. Ein ehrliches Stück Eisen."},"ICON-1380":{"nm":"Kettlebell","de":"Einem einzigen Griff folgt der ganze Körper. Wenn das runde Gewicht einen Bogen zieht, wird das Gleichgewicht desjenigen, der standhält, auf die Probe gestellt. Um nicht zu schwanken, muss man zuerst seinen eigenen Mittelpunkt kennen."},"ICON-1381":{"nm":"Sprungseil","de":"Wieder und wieder springt man über das Seil, das unter den Füßen durchflitzt. Wie früher das Zählen mit Freunden auf dem Hof: Je mehr Wiederholungen sich ansammeln, desto voller wird der Atem — und desto breiter das Lächeln."},"ICON-1382":{"nm":"Laufschuhe","de":"Ihren wahren Wert kennt man erst, wenn man auf der Strecke läuft. Läuft man morgens wieder dieselbe Runde, ist die Kurve, die gestern noch weit schien, plötzlich zum Greifen nah. Die Beine erinnern sich an die Distanz."},"ICON-1383":{"nm":"Sporthandtuch","de":"Wischt man sich den Schweiß von der Stirn, ist darin der Einsatz des heutigen Tages eingeschrieben. Beim Waschen verschwinden die Spuren — doch das Geschaffte lagert sich irgendwo ab. Die ehrlichste Ermutigung trocknet stets in der Nähe."},"ICON-1384":{"nm":"Trinkflasche","de":"Leer — nachfüllen. Trocken — einen Schluck trinken. Diese einfache Hin-und-Her-Bewegung trägt den ganzen Tag. Wie ein Schöpfeimer am Brunnen: Jeder neue Schöpfzug ist ein neuer Beginn des Tages."},"ICON-1385":{"nm":"Proteinshake","de":"Ein Schluck, und die heute beanspruchten Muskeln füllen sich morgen wieder auf. Kein besonderer Geschmack, aber der Körper weiß: Das ist die Sprache der Erholung. Wachstum wird immer still getrunken."},"ICON-1386":{"nm":"Energieriegel","de":"Ein flach zerdrückter Riegel tief in der Tasche. Notration für die Lücke zwischen zwei Mahlzeiten. Auch ohne Aufhebens — dieser eine Bissen lässt einen die Bewegung der nächsten Nachmittagsstunde durchhalten."},"ICON-1387":{"nm":"Halsbonbon","de":"Rollt man es im Mund, streicht kühle Minze sanft über den ramponierten Hals. An Tagen mit vielen Worten und Nächten mit viel Gesang beruhigt ein kleines Bonbon den rauen Weg. Süßigkeit hat auch ihre praktische Seite."},"ICON-1388":{"nm":"Stimmtee","de":"Warmer Dampf wärmt den Hals, und mit einem Schluck löst sich die Anspannung in den Schultern. Ein altes Hausmittel, wie Ingwertee von der Großmutter. Vor dem Singen ein herzlicher Gruß an die Stimme."},"ICON-1389":{"nm":"Honigwasser","de":"Einen Löffel Honig langsam in lauwarmem Wasser auflösen. Das Getränk, das Erwachsene bei einem rauen Hals stets einschenken. Kein Medikament, kein Softdrink — einfach eine sanfte Wärme, die von innen streichelt."},"ICON-1390":{"nm":"Luftbefeuchter-Tank","de":"Ein Behälter, der im Zimmer leisen Nebel verbreitet. In Winternächten, wenn trockene Luft am Hals kratzt, gibt er still Feuchtigkeit ab. Fürsorge für andere läuft meistens so: geräuschlos und unsichtbar."},"ICON-1391":{"nm":"Ruhegutschein","de":"Ein Zettel, auf dem steht: Du darfst pausieren. Sobald man ihn in die Hände bekommt, wird das Herz eine Spur leichter. Auch Innehalten ist Übung — dieser kleine Schein erteilt die Erlaubnis dazu."},"ICON-1392":{"nm":"Trainingsplan","de":"Auf jedem ausgefüllten Kästchen landet ein Stück des Tages. Morgens Stimmübungen, nachmittags Choreografie, abends Erholung. Selbst der dunkle nächste Tag wird begehbar, sobald man ihn in Abschnitte teilt."},"ICON-1393":{"nm":"Anwesenheitsstempel","de":"Mit einem festen Druck bestätigt man: Heute war ich da. Je mehr gestempelte Kreise das Heft füllen, desto mehr wird aus stiller Beständigkeit ein Weg. Der kleine Beweis für jeden einzelnen Tag."},"ICON-1394":{"nm":"Lobsticker","de":"Statt eines Worts klebt man einfach einen Stern. So winzig er auch ist — auf der Ecke des Notizbuchs lässt er den ganzen Tag erstrahlen. Lob mag klein sein, aber es leuchtet auf merkwürdige Weise lange."},"ICON-1395":{"nm":"Mental-Notizbuch","de":"Seiten, auf denen man die aufgeregte Unruhe hinter der Bühne in Worte fasst. Auch schlechte Tage ehrlich aufzuschreiben macht sie irgendwie leichter. Ein Herz wird stark in dem Maß, in dem man es anschaut."},"ICON-1396":{"nm":"Mentaltrainingskarte","de":"Schließt man die Augen und hält sie fest, entfaltet sich im Kopf leise eine Bühne. Ein Spaziergang durch den Platz, den man noch nie betreten hat. Der im Geiste gezeichnete Weg kommt einen Schritt früher an als die echten Füße."},"ICON-1397":{"nm":"Mimik-Übungsspiegel","de":"Vor dem Spiegel lächeln, streng schauen, wieder lächeln — dasselbe Gesicht hundert Mal formen. Hier lernt man: Auch Freude und Traurigkeit brauchen Übung. Denn ein Gesichtsausdruck ist nichts anderes als ein nach außen geschriebenes Gefühl."},"ICON-1398":{"nm":"Choreografie-Notizbuch","de":"Seiten, auf denen der Weg von Füßen und Armen in Skizzen festgehalten ist. Pfeile flüstern, wohin sich der Körper bei jedem 8-Takt wenden soll. Auch hartnäckig schwer zu merkende Bewegungen werden hier langsam vertraut."},"ICON-1399":{"nm":"Choreografie-Chip","de":"Hunderte von Bewegungen passen auf einen winzigen Chip. Schaut man ihn sich kurz vor dem Schlafengehen noch einmal an, folgen die Fingerspitzen ganz von selbst dem Weg. Wiederholung ist eine weitere Form der Aufzeichnung — die im Körper."},"ICON-1400":{"nm":"Bühnenplan","de":"Eine Karte der Bühne aus der Vogelperspektive. Wer wen wo trifft und wohin alle auseinandergehen — mit Linien und Punkten im Voraus vereinbart. Wer gemeinsam ein Bild zeichnen will, muss zuerst die Wege aufteilen."},"ICON-1401":{"nm":"Probe-Ausweis","de":"Das Publikum fehlt noch, das Licht schläft noch. Dieser Ausweis lässt einen in diese Stille eintreten. Die Bühne, bevor sie jemand sieht — hier beginnt die Zeit, in der man dem ehrlichsten Teil von sich begegnet."},"ICON-1402":{"nm":"Stilbuch","de":"Mit welchem Gefühl zieht man sich heute an? Selbst ein einfaches Hemd hat seine passende Stimmung, so erklärt dieses Buch ganz behutsam. Mit jeder umgeblätterten Seite wächst ein kleines Gespür für Stil in den Händen, die vor dem Spiegel zögerten."},"ICON-1403":{"nm":"Haarspray","de":"Ein kurzes Zischen, und kein Wind kann mehr etwas durcheinanderbringen. Der kleine Ehrgeiz, ein paar Minuten auf der Bühne makellos zu halten. Perfekte Momente gelingen immer auf dem Fundament solcher unscheinbaren Eigensinnigkeiten."},"ICON-1404":{"nm":"Make-up-Palette","de":"Zwölf Felder, zwölf Stimmungen. Welche Rolle trägt man heute auf der Bühne — die Hand wählt zuerst, das Herz folgt. In jedem leergenutzten Feld steckt still ein Tag, der auf der Bühne zurückgelassen wurde."},"ICON-1405":{"nm":"Kostümnadel","de":"Im glanzvollsten Moment hält an unsichtbarer Stelle eine kleine Nadel den Stoff zusammen. Damit nichts verrutscht, nichts verreißt. Der Glanz auf der Bühne steht immer auf der Standhaftigkeit von jemandem im Verborgenen."},"ICON-1406":{"nm":"Namenstafel","de":"Sobald ein Name die leere Tafel füllt, wird aus einem vagen Versprechen ein klares. Wer an diesem Platz stehen wird — ein einziger Satz entscheidet es. Ein Name ist die kürzeste und festeste Form eines Versprechens."},"ICON-1407":{"nm":"Fan-Service-Karte","de":"Die Empfängerin ist nur eine — doch für diese eine bedeutet die Karte die ganze Welt. In wenige Zeilen Dankbarkeit für viele Nächte hineinpressen. Das Herz läuft auch auf einem handflächengroßen Stück Papier über."},"ICON-1408":{"nm":"Autogrammübungsblatt","de":"Am Anfang wirkt selbst der eigene Name fremd auf dem Papier. In nächtlichem Ziehen und Feilen, hundert-, tausendmal, bis die Hand den Fluss auswendig kennt. So wird aus einem Namen schließlich ein Autogramm."},"ICON-1409":{"nm":"Interviewfragebogen","de":"\"Was antworte ich darauf?\" Die Hand, die das Papier hält, zittert ein wenig. Keine Antworten auswendig lernen — sondern aufrichtige Gedanken der Reihe nach ordnen. Denn ein Vorstellungsgespräch wie ein Geständnis fragt letztlich nach der Reihenfolge der Gefühle."},"ICON-1410":{"nm":"Fremdsprachenvokabelheft","de":"Die abgenutzten Ecken zeigen, welches Wort am häufigsten nachgeschlagen wurde. Mit jeder fremden Aussprache, die sich auf der Zunge festsetzt, rückt eine Welt, die man noch nie besucht hat, ein Stückchen näher."},"ICON-1411":{"nm":"Aussprache-Lernkarte","de":"Das rollende R, das entweichende S. Karte für Karte zähmt man in einer frühen Morgenstunde die Zunge. Je deutlicher die Sprache wird, desto klarer erscheint auch das Gesicht derjenigen, die man mit ihr erreichen möchte."},"ICON-1412":{"nm":"Live-Checkliste","de":"Mikrofon an, In-Ears gecheckt, Bewegungsabläufe kontrolliert. Mit jedem abgehakten Kästchen verschwindet eine Portion Nervosität. Bevor man auf die Bühne tritt, ist Sorgfalt der leiseste Mut."},"ICON-1413":{"nm":"Konditions-Patch","de":"Kaum aufgeklebt, breitet sich wohltuende Wärme aus. Überbeanspruchte Schulter, verspannter Wadenmuskel — ein handflächengroßer Trost, der auf die kleinen Signale des Körpers sanft antwortet. Sich gut auszuruhen ist auch ein Teil des Trainings."},"ICON-1414":{"nm":"Eispack","de":"Vorsichtig auf den geschwollenen Knöchel legen. Während die Kühle langsam einsickert, merkt man erst, wie weit man heute gelaufen ist. Erholung hinter der Bühne kommt immer so: leise und ohne Ankündigung."},"ICON-1415":{"nm":"Notfalltasche","de":"Pflaster, Schmerzmittel, Taschenspiegel. Diese kleine Tasche mit ihrem unscheinbaren Inhalt erweist sich im entscheidenden Moment als unverzichtbar. Vorausschauende Fürsorge leuchtet hell auf, wenn das Unerwartete eintritt."},"ICON-1416":{"nm":"Cue-Karte","de":"Hinter der Kamera hebt jemand sie verstohlen hoch. Das Wort, das man fast vergessen hätte, steht dort deutlich geschrieben. Hinter einem reibungslosen Ablauf verbirgt sich immer eine Hand, die im Bild unsichtbar bleibt."},"ICON-1417":{"nm":"Missionsumschlag","de":"Der aufregendste Moment ist kurz vor dem Aufreißen. Was auch immer darin steckt — das prickelnde Unwissen dieses kurzen Augenblicks macht den Charme einer Spielshow aus."},"ICON-1418":{"nm":"Namensschild","de":"Ein kleiner Name auf der Brust übernimmt die erste Begrüßung. Unter Fremden bricht ein einziges Namensschild das Eis. In dem Moment, in dem man den Namen ausspricht, beginnt eine Beziehung."},"ICON-1419":{"nm":"Strafe-Sticker","de":"Ein Aufkleber, der dem Verlierer auf die Stirn getippt wird, und alle lachen schallend. Als Strafe zu freundlich, sodass selbst die Niederlage zu einer unvergesslichen Erinnerung wird. Ein kleines, herzliches Zeichen, das gemeinsames Lachen bezweckt."},"ICON-1420":{"nm":"Zufalls-Strafkarte","de":"Vor dem Ziehen weiß niemand, was drinsteht. Zehn Runden mit Elefantenrüssel oder eine süße Geste? In dem Moment, in dem man sein Schicksal dem Papier übergibt, ist es das Lachen, das zuerst losbricht."},"ICON-1421":{"nm":"Hinweiskarte","de":"Eine helfende Hand, die in einer Sackgasse sanft ausgestreckt wird. Sie verrät nicht die Lösung, zeigt aber den Weg. Ein guter Hinweis gibt nicht die Antwort — er reicht still den Mut, noch einmal nachzudenken."},"ICON-1422":{"nm":"Joker-Karte","de":"Die einzige Chance, ein kippendes Spiel in einem Zug zu wenden. Wann man sie einsetzt, entscheidet die Partie. Sorgfältig aufgespartes Glück erweist erst im entscheidendsten Moment seinen wahren Wert."},"ICON-1423":{"nm":"Auszeit-Karte","de":"Diese Karte sagt stellvertretend: Es ist okay, kurz zu pausieren. In einem Moment, wo man Luft holen muss, selbstbewusst die Hand zu heben — auch eine Pause ist eine vollgültige Taktik, und gut auszuruhen ist ebenfalls Können."},"ICON-1424":{"nm":"Lach-Knopf","de":"Drückt man ihn, sprudelt helles, fröhliches Lachen heraus. Bei wirklich witzigen Szenen darf gern ein bisschen Nachhilfe geleistet werden. Die Wärme eines Raums entsteht manchmal aus einem einzigen kleinen Scherz."},"ICON-1425":{"nm":"Soundeffekt-Fernbedienung","de":"Ein Knopf für Applaus, ein anderer für Buhrufe. An einem ruhigen Platz in der Regie sitzt ein Zauberer, der per Fingerkuppe die Stimmung formt. Was auf dem Bildschirm lebendig wirkt, atmet durch unsichtbare Regie."},"ICON-1426":{"nm":"Filmklappe","de":"Klack — und mit einem fröhlichen Geräusch beginnt eine neue Einstellung. Zwischen unzähligen Fehlversuchen und dem einen gelungenen Take zählt diese schwarze Tafel jeden einzelnen Moment gewissenhaft mit. Sie ist der erste Takt der Aufzeichnung."},"ICON-1427":{"nm":"Markierungsband","de":"Sobald die Fußspitze die Linie berührt, senkt sich das Licht wie erwartet herab. Das eine Feld, auswendig gelernt bis es abgenutzt ist — die Bühne ist erst mit diesem kleinen farbigen Streifen auf dem Boden vollendet."},"ICON-1428":{"nm":"Lichtfilter","de":"Dasselbe Gesicht sieht unter jeder Lichtfarbe anders aus. Im blauen Filter wohnt die Morgendämmerung, im roten das Abendrot. Atmosphäre ist nie weit entfernt — sie liegt still gefaltet in einem dünnen Farbblatt."},"ICON-1429":{"nm":"Kamera-Akku","de":"Wenn das rote Licht zu blinken beginnt, wird man sofort unruhig. Ausgerechnet die besten Szenen erscheinen immer bei einem Prozent Restladung. Ein Reserveakku in der Tasche bedeutet schlicht: durchatmen."},"ICON-1430":{"nm":"Speicherkarte","de":"Ein ganzer Tag voller Lachen und Schweiß ist dicht auf einem daumennagel-großen Chip verpackt. So klein, dass man sie leicht verliert — und gerade deshalb so kostbar. Das Gewicht der gespeicherten Erinnerungen lässt sich nie an der Größe ablesen."},"ICON-1431":{"nm":"Polaroidfilm","de":"Klick, und dann ein stilles Warten. Auf der zuerst weißen Fläche taucht langsam ein Gesicht auf — diese wenigen Sekunden sind auf merkwürdige Weise aufregend. Auch in einem Sofortbild steckt immer ein Löffelchen Geduld."},"ICON-1432":{"nm":"Fotokarten-Film","de":"Welcher Ausdruck auf diesem Blatt entwickelt wird, bleibt bis kurz vor dem Druck ein Geheimnis. Das Gesicht, das zum Lieblingsmotiv von jemandem wird, entsteht genau hier. Ein kleines Stück Papier trägt ein so großes Herz."},"ICON-1433":{"nm":"Fotokartenhülle","de":"Eine Fotokarte fasst man nicht mit bloßen Händen an. Ein einziger Druckpunkt auf der Ecke, und das Lächeln des Tages bekommt eine Falte. Das geliebte Foto sorgfältig in durchsichtige Folie hüllen — Schätzen braucht diese Art von Hingabe."},"ICON-1434":{"nm":"Toploader","de":"Zwischen zwei steife Lagen geschoben, kann selbst die Zeit es nicht mehr knicken. Damit es sich nicht biegt, nicht faltet. Etwas wirklich zu schützen bedeutet immer, sich eine Lage Festigkeit zu leihen."},"ICON-1435":{"nm":"Sticker-Pack","de":"Blatt für Blatt abziehen und in die Ecke des Tagebuchs, auf den Laptop-Deckel tippen. Ein kleines Bild lässt einen bis dahin farblosen Tag aufblühen. Der Wunsch, das Umfeld zu verschönern, kennt kein Alter."},"ICON-1436":{"nm":"Signiermarker","de":"Während die Tinte mit leisem Kratzen über das Papier gleitet, wird die Zeile länger. Im Album, das mit zitternden Händen dargeboten wurde, bleibt eine Begegnung von wenigen Sekunden lange erhalten. Über die Stiftspitze reist das Herz hinüber."},"ICON-1437":{"nm":"Signieralbum","de":"Öffnet man den Umschlag, grüßt als Erstes eine vertraute geschwungene Unterschrift. Was durch Musik verbunden war, rückt auf dem Papier eine Handbreit näher. Bewahren heißt: diesen Moment still anhalten."},"ICON-1438":{"nm":"Lightstick-Akku","de":"\"Bitte geh an, bitte.\" Kurz vor dem Einlass wechselt man hastig die Batterien. Damit das eine Licht inmitten von Zehntausenden nicht erlischt — ein kleiner Akku erhellt diese große Nacht."},"ICON-1439":{"nm":"Lightstick-Tasche","de":"Ohne eine einzige Schramme, heil für die nächste Nacht voller Jubel. Auch wenn die heiße Aufregung längst abgeklungen ist, trägt man den Stick behutsam nach Hause. Auch Zubehör für Zuneigung hat seinen Platz — und ein Herz, das ihn hütet."},"ICON-1440":{"nm":"Slogan-Banner","de":"Ein Satz auf langem Tuch entfaltet sich quer durch die Ränge. Was man mit Worten nicht sagen konnte, öffnet sich in diesem Moment — und aus dem Herzen einer Person wird der Ruf aller. Das Tuch selbst wird zur Stimme."},"ICON-1441":{"nm":"Mini-Banner","de":"Kleine Unterstützung, die in eine Handfläche passt. Das große hängende Transparent gehört allen — doch dieses weht nur am Ende deines Schreibtisches. Kleines Format bedeutet nicht kleines Herz, das beweist es still und wippend."},"ICON-1442":{"nm":"Fanbrief","de":"Den Namen des Empfängers dreimal neu geschrieben, den ersten Satz sieben Mal gestrichen. Die zitternden Finger kurz vorm Verschließen — das Herz ist einfach zu ehrlich. Schwerer als eine Briefmarke ist die aufrichtige Zuneigung, die darin gefaltet liegt."},"ICON-1443":{"nm":"Geschenkpapier","de":"Der eine Augenblick kurz vor dem Aufreißen ist der aufregendste, das weiß das Papier besser als alle. Obwohl es zum Zerreißen bestimmt ist, schmiegt es sich in den schönsten Falten — dem Herz der schenkenden Person gleich."},"ICON-1444":{"nm":"Schleife","de":"Zu fest gebunden klemmt sie, zu locker geht sie auf — und genau den richtigen Punkt zu treffen ist die eigentliche Sorgfalt. In dem Knoten, den die Fingerspitzen formen, liegt die Form des Herzens. Die letzte Zeile eines Geschenks schreibt immer die Schleife."},"ICON-1445":{"nm":"Dankeskarte","de":"Ein mündliches Dankeschön verweht im Wind, doch handgeschrieben bleibt es. Empfangene Herzlichkeit ein wenig verzinst zurückzuschicken. Beim langsamen Hinschreiben Buchstabe für Buchstabe wird das Herz doppelt so tief."},"ICON-1446":{"nm":"Lunchbox-Gutschein","de":"Mit diesem Zettel löst sich die Sorge ums Mittagessen in Luft auf. Frisch gekochter Reis mit aufsteigendem Dampf, ein vollständiges Menü mit gefüllten Fächern — bereits versprochen. Ein kleines Amulett für einen nährenden Nachmittag."},"ICON-1447":{"nm":"Snack-Gutschein","de":"Einlösbar, wenn um drei Uhr nachmittags der kleine Hunger klopft. Das Wissen, dass eine Kleinigkeit die Stimmung um eine halbe Handbreit hebt. Keine große Belohnung — aber eine, die genau dann sanft auftaucht, wenn man sie am meisten braucht."},"ICON-1448":{"nm":"Café-Gutschein","de":"Eine warme Tasse und ein Fensterplatz — das ist alles, was dieser Gutschein verspricht. Für manche wird daraus die kleine Belohnung, die den Tag durchgehalten hat. Eine herzliche Einladung, bei der das Aroma schon einen Schritt vorauseilt."},"ICON-1449":{"nm":"Zimmer-Reinigungsbon","de":"Fenster weit auf, Bettdecke ausschütteln, bis nicht ein Staubkorn mehr bleibt. Wie luxuriös es doch ist, wenn man das nicht selbst erledigen muss. Wenn das Zimmer glänzt, ordnet sich auch der Geist auf einmal still mit."},"ICON-1450":{"nm":"Reparatur-Kit","de":"Schraubenzieher, Klebeband, ein paar rätselhafte Einzelteile. Zusammen wirkt es, als könnte man alles reparieren — öffnet man es, fehlt immer irgendwas. Und doch verleiht es in der Hand ein seltsames Gefühl von Sicherheit."},"ICON-1451":{"nm":"Glücksticket","de":"Ein leeres Ticket ohne Sitznummer und Uhrzeit. Genau das ist der Kern: Was heute Gutes passieren wird, steht nicht drauf. Das Ausfüllen dieser Leerstelle liegt bei dem, der es in der Tasche trägt."},"ICON-1452":{"nm":"Würfel","de":"Der fairste aller Freunde. Er bevorzugt keine Seite und liebt alle sechs gleich. In dem Moment, in dem er die Hand verlässt und rollt, tritt Können und Beziehung kurz zurück — und überlässt dem Schicksal seinen Platz."},"ICON-1453":{"nm":"Reisebon","de":"Von hier nach dort — ein einziger Schritt genügt, so das Versprechen. Ein Stück Papier, das weite Wege klein faltet und in die Tasche steckt. An Tagen, an denen das Aufbrechen schwerfällt, gibt es keinen besseren Grund."},"ICON-1454":{"nm":"Zweiter-Versuch-Bon","de":"Statt jemandem, der gefallen ist, die Hand zu reichen, stößt dieser Bon ihn sanft an: Versuch es noch einmal. Er sagt auf die leiseste Art, dass ein Scheitern kein Ende, sondern ein kurzes Komma ist. Neuer Mut wächst hier."},"ICON-1455":{"nm":"Sofortfertig-Bon","de":"Ein freundliches Cheat-Ticket, das das Warten ein bisschen überspringt. Wer mag schon drei Minuten nicht abwarten? Das Vergnügen, den Sand der Sanduhr mit dem Finger anzustoßen — ein kleiner, fast verbotener Spaß."},"ICON-1456":{"nm":"Produktivitäts-Booster","de":"Gleiche Hände, gleiche Zeit — doppeltes Ergebnis. Das Geheimnis will nicht verraten werden; auf dem Arbeitstisch dreht er sich einfach munter. Ein kleines Gerät, das den fleißigen Händen leise Flügel verleiht."},"ICON-1457":{"nm":"Vertrauens-Bonbon","de":"Peinliche Stille taut vor Süßem wie von selbst auf. Ein gemeinsam geknabbertes Bonbon, und man ist sich plötzlich um eine Handbreit nähergekommen. Süße als Geschwindigkeit der Annäherung — eine liebenswürdige Entdeckung."},"ICON-1458":{"nm":"Stimmungs-Gummibär","de":"An trüben Tagen helfen Kühles und Weiches am schnellsten. Einen Bissen, und der bewölkte Gesichtsausdruck löst sich sachte auf. Das Herz zu reparieren ist von Natur aus kostbar — darum ist die seltene Verfügbarkeit kein Zufall."},"ICON-1459":{"nm":"Funkelpulver","de":"Darüber gestreut verwandelt sich das Gewöhnlichste in etwas Besonderes. Im Grunde nur glitzerndes Puder — doch kaum haftet es, wirkt die Welt ein bisschen festlicher. Wie ein Gewürz, das dem Alltag Glück hinzufügt."},"ICON-1460":{"nm":"Bühnenmarkierungsband","de":"Auf der Bühne suchen Scheinwerfer als Erstes die markierte Stelle. Das kleine X auf dem Boden zeigt ihr lautlos den Weg. Was im Verborgenen am genauesten ist, trägt letztlich die größte Bühne."},"ICON-1461":{"nm":"Kabelbinder","de":"Ein kleiner Held, der verworrene Kabel in einem Zug bändigt. Einmal zugezogen, gibt es kein Zurück mehr — das ist zugleich Nachteil und Reiz. Ein unverzichtbares Werkzeug für alle, die Ordnung wirklich ernst nehmen."},"ICON-1462":{"nm":"Ersatzkabel","de":"Solange vorhanden, völlig unauffällig — fehlt es, wird es schmerzlich vermisst. Tief in der Tasche hinter der Bühne schlummert es, bis es im entscheidenden Moment aufwacht. Es beweist durch sein Dasein, was Vorbereitung bedeutet."},"ICON-1463":{"nm":"Probenlauf-Checkliste","de":"Wege, Cues, Kostümwechsel — alles dicht auf dem Papier. Bleibt auch nur ein Kästchen leer, sinkt irgendjemandem das Herz in die Hose. Eine perfekte Vorstellung beginnt erst, wenn diese Liste vollständig ist."},"ICON-1464":{"nm":"Set-Wegweiser","de":"Hier ein Café, dort eine Gasse — folgt man dem Pfeil, betritt man eine völlig andere Welt. Auf Sperrholz gemalte Unwahrheit, die vor der Kamera zur Wahrheit wird. Ein ehrlicher Wegweiser, dem es nie an Einsatz mangelt."},"ICON-1465":{"nm":"Mini-Trophäe","de":"Schon beim Entgegennehmen fühlt man sich einen Schritt gewachsen, dieses kleine goldene Stück. Auch ohne ersten Platz glänzt sie vom Schreibtisch herab: Ich weiß, wie viel du heute gegeben hast. Kleiner Lohn, große Güte."},"ICON-1466":{"nm":"Rucksack","de":"Sobald er auf den Schultern sitzt, scheint jedes Ziel erreichbar. Drinnen mag nicht viel stecken — doch Möglichkeiten sind reichlich. Ein Abenteuer beginnt immer damit, die Schulterriemen fest zu ziehen."},"ICON-1467":{"nm":"Kompass","de":"Auch wenn man sich verläuft, gerät man nicht in Panik, denn die Nadel zeigt immer nach Norden. Das Hin- und Herschwingen, das schließlich zur Ruhe kommt, gleicht dem Menschenherzen. Auch Irren ist erlaubt, sagt die zitternde Spitze leise."},"ICON-1468":{"nm":"Notizbuch","de":"Die erste Seite ist stets leer. Nur wer den Stift hält, weiß, was hineinkommt. Ich warte einfach darauf, dass der heutige Gedanke zu Buchstaben wird und sich still auf mir niederlässt."},"ICON-1469":{"nm":"Bleistift","de":"Dass Fehler erlaubt sind, ist das freundlichste Merkmal dieses Werkzeugs. Solange der Radiergummi daneben liegt, kann man so oft neu beginnen wie nötig. Kürzer mit jedem Anspitzen — aber umso länger geliebt."},"ICON-1470":{"nm":"Film","de":"In dem Moment, in dem Licht hindurchfällt, brennen sich die Farben dieses Tages ein. Ein ausgelöster Verschluss lässt sich nicht zurücknehmen — das macht Spannung wie Reiz aus. Die Wahl derer, die sich in einer schnellen Zeit bewusst ein Tempo langsamer erinnern."},"ICON-1471":{"nm":"Sofortbildkamera","de":"Klick, und dann ein kurzes Warten. Während man das Bild sanft in der Hand hält, wird ein verschwommener Moment nach und nach scharf. Eine kleine, fast magische Maschine, die diesen Augenblick auf einem Blatt Papier festhält."},"ICON-1472":{"nm":"Altes Foto","de":"Je ausgeblichener die Farbe, desto mehr Zeit ist vergangen. An jeder abgenutzten Ecke ruht jemandes Berührung. Dass das älteste Foto die klarste Erinnerung trägt, liegt wohl an all diesen Berührungen."},"ICON-1473":{"nm":"Scrapbook","de":"Zu schade zum Wegwerfen — Stück für Stück entsteht daraus ein ganzes Buch. Verblasste Kinokarten, getrocknete Blütenblätter, ein kurzer Notizzettel. Für andere nur Krempel, für den, der es aufschlägt, eine vollständige Lebensepoche."},"ICON-1474":{"nm":"Bordbuch","de":"Wind und Wellen des heutigen Tages — und eine Zeile übers eigene Befinden. Auch stille Tage werden pflichtgetreu eingetragen. Der Beweis der glücklichen Ankunft liegt irgendwo in dieser dicken Aufzeichnung."},"ICON-1475":{"nm":"Kartenfragment","de":"Nur ein Eckchen des Ganzen — doch ohne es findet man den Weg nicht. Das Aufeinandertreffen einer gerissenen Kante mit dem passenden Gegenstück ist ein solcher Genuss. Dieses Stück ist wie das letzte fehlende Puzzleteil — mit einem Gewicht, das man spürt."},"ICON-1476":{"nm":"Flaschenpost","de":"Ohne zu wissen, wer liest, vertraut man sich den Wellen an. Auf eine Antwort hofft man nicht — man wünscht sich nur, dass das Geschriebene irgendwo ankommt. Die langsamste, aber romantischste Art, Post zu schicken."},"ICON-1477":{"nm":"Würfel","de":"Alle sechs Seiten grüßen mit einem runden Lächeln. Gleiche Form, doch jedes Rollen bringt eine andere Antwort — die unveränderliche Launenhaftigkeit dieses kleinen Freundes. In dem Moment, da er die Hand verlässt, übergibt man die Entscheidung kurz dem Schicksal."},"ICON-1478":{"nm":"Windrad","de":"Erst wenn Wind weht, erwacht es. Stillgehalten sind es nur Papierflügel, aber sobald jemand pustet, dreht es sich vergnügt. Sich helfen zu lassen und das nicht zu schämen — das ist die Weisheit dieser kleinen Blume."},"ICON-1479":{"nm":"Picknickkorb","de":"Öffnet man den Deckel, grüßt als Erstes der Duft von Reisröllchen. Grüner Rasen, ausgelegte Decke und teilende Hände rundum. An Tagen, an denen dieser Korb voll war, war der Himmel seltsamerweise stets blau."},"ICON-1480":{"nm":"Blumenvase","de":"Schon eine einzige Blume verändert die Luft im ganzen Raum. Leer zu sein und still zu warten, ist ihre eigentliche Bestimmung. Um die Blume strahlen zu lassen, hält sie selbst sich bescheiden zurück — die demütigste Bühne des Zimmers."},"ICON-1481":{"nm":"Blütenblatt","de":"Trägt der Wind eines fort, wird der Frühling um genau das leichter. Der alte Baum im Hof grüßt Jahr für Jahr gleich: Fallen gehört zum Blühen dazu. Das Verwehen ist kein Ende — es ist ein Brief, der schon für den nächsten Frühling aufgegeben wurde."},"ICON-1482":{"nm":"Rose","de":"Die Dornen zuerst aufzustellen bedeutet: Fass mich nicht achtlos an. Dahinter verbirgt sich das röteste aller Herzen. Jemand hat einst eine einzige Blüte leise zu Füßen gelegt — und statt eines Namens nur eine Farbe hinterlassen."},"ICON-1483":{"nm":"Lilie","de":"Neben weißem Porzellan stand stets diese weiße Blume. Ihr Duft reist weit, doch ihr Anblick bleibt makelloser. Statt Pracht wählte sie Reinheit — und hütet von ihrem Platz aus still eine Würde, die kein Wort braucht."},"ICON-1484":{"nm":"Tulpe","de":"In Reih und Glied, den Kopf ein wenig gesenkt — das wirkt irgendwie ordentlich. Die erste Reihe des Frühlingsbeetes gehört ihr. Dass sie zusammen aufblüht und zusammen verblüht, macht die kurze Saison am tiefsten leuchtend."},"ICON-1485":{"nm":"Hyazinthe","de":"An einem einzigen Stiel hängen dicht gedrängt kleine Glocken. Sie klingeln nicht — doch ihr Duft bringt den ganzen Raum zum Schwingen. Ein duftendes Privileg, das die Luft eines Zimmers zu Frühlingsbeginn mit einer einzigen Vase völlig verwandelt."},"ICON-1486":{"nm":"Frosch-Präparat","de":"In einem Glaskasten hält die Zeit inne. Das Etikett vermerkt: Reisfeld und Stausee, am aktivsten nach Regen. Erst nach dem Stillstand bleibt die Temperatur des Gewässers, in dem einst Leben war, als Aufzeichnung erhalten."},"ICON-1487":{"nm":"Eidechsen-Präparat","de":"Selbst als Präparat verblasst die Klugheit nicht, mit der sie Schwanz und Flucht meisterte. Kleiner Gast, der warme Steinmauern liebte. Die Notiz daneben vermerkt penibel die Himmelsrichtung der Sonnenseite, die sie am liebsten erklomm."},"ICON-1488":{"nm":"Maulwurfs-Aufzeichnung","de":"Das Tagebuch eines Bewohners unter der Erde wird in der Maserung des Tons geschrieben. Wo er grub und wo er anhielt — die Karte eines unsichtbaren Weges. Auch eine in Dunkel verbrachte Zeit kann für jemanden eine gewissenhafte Aufzeichnung sein."},"ICON-1489":{"nm":"Muschel-Präparat","de":"Ein hartes Muster, von Tausenden Wellen poliert. Wattenmeer-Bewohner erkannten einst nur am Muschelschalenmuster, aus welchem Meer sie stammten. Die Form des Meeres, in dem einst Leben atmete, ist in diesem handflächengroßen Präparat vollständig bewahrt."},"ICON-1490":{"nm":"Korallen-Präparat","de":"Tief im Meer wächst es in Jahrhunderten kaum eine Handbreit. Wie Äste aussehend, ist es in Wirklichkeit das gemeinsam errichtete Zuhause vieler kleiner Leben. Dass Langsames länger bleibt, beweist die Koralle schweigend."},"ICON-1491":{"nm":"Aidong-Hinweis","de":"Ein Fragment einer Geschichte, die über die Insel verstreut liegt. Ein kleines Stückchen Papier zeigt leise den nächsten Schritt. Jedes Abenteuer beginnt damit, solche unscheinbaren Spuren aufzulesen, sagt der alte Wegweiser."},"ICON-1492":{"nm":"Signatur-Fragment","de":"Wenn das verstreute Muster seinen Platz findet, wird ein vollständiges Zeichen daraus. Ein Stück mit dem einzigartigen Muster von jemandem. Bis es zusammengefügt ist, hält es seine Bedeutung verborgen — und wird erst im Zusammenfügen zu einem Namen."},"ICON-1493":{"nm":"Bühnenerinnerungs-Fragment","de":"Auch wenn ein Lied endet, bleibt die Nachwärme im Saal. Wird diese Wärme herausgelöst und festgemacht, entsteht so ein kleines Stück. Splitter von Applaus und Jubel — gesammelt, erwacht die ganze Nacht wieder zum Leben."},"ICON-1494":{"nm":"Debütstempel","de":"Der Tintenabdruck auf dem Handrücken am Tag, an dem der eigene Name zum ersten Mal gerufen wurde. Das Herz, das damals sorgfältig darauf achtete, er möge nicht verwischen — das war der Startschuss. Ein kleiner Stempel, der einen einzigen Tag für immer unauslöschlich macht."},"ICON-1495":{"nm":"Top-Idol-Medaille","de":"Eine Schwere, die nur dem höchsten Platz vorbehalten ist. Doch schwer ist diese Medaille nicht wegen des Metalls. Sondern weil das Gewicht der unzähligen Hände, die die Bühne gemeinsam füllten, sich in ihr vereint."},"ICON-1496":{"nm":"Kleiner Schlüssel","de":"Der erste Schlüssel im Wohnheim war stets der zum innersten Zimmer. Der Ort, an dem man das Öffnen vor dem Schließen lernte. Am Abreisetag verweilt auf dem kühlen Metall noch lange die Wärme der Handinnenfläche."},"ICON-1497":{"nm":"Schatztruhe","de":"Bevor man sie öffnet, weiß niemand, was drinnen liegt. Genau dieses Nichtwissen ist der eigentliche Schatz einer Schatztruhe. In dem kurzen Augenblick, in dem man den Deckel hebt, kehrt jeder kurz in das Kribbeln seiner Kindheit zurück."},"ICON-1498":{"nm":"Bauplan","de":"Auf den sorgfältig gezogenen Linien wohnt ein Gebäude, das noch nicht existiert. Den Plan aufzurollen bedeutet, den morgigen Tag schon einmal zu Fuß abzugehen. Eine gut gezogene Linie trägt das Morgen, das nicht einstürzt."},"ICON-1499":{"nm":"Rezeptkarte","de":"Auf einer abgegriffenen Karte stehen Omas Handgriffe als Mengenangaben geschrieben. \"Eine Prise Salz\" — das scheinbar Ungenaue ist das genaueste Geheimnis. Je blasser die Schrift wird, desto klarer erscheint die Küche, in der dieses Gericht köchelte."},"ICON-1500":{"nm":"Nutzungsgenehmigung","de":"Ein einzelnes Blatt Papier verwandelt einen leeren Platz in einen nutzbaren Ort. Ein neues Gebäude brauchte stets zuerst den Stempel des Dorfes. Erlaubnis ist letztlich ein herzliches Siegel: Hier darf etwas beginnen."},"ICON-1501":{"nm":"Hafenerlaubnis","de":"Bevor ein Schiff den Anker warf, musste dieses eine Blatt vorliegen. Das verblasste Siegel des Hafens war der erste Gruß für jene, die von weither kamen. Zwischen Aufbruch und Ankunft öffnet der Hafen sein Herz stets mit einem einzigen Stück Papier."},"ICON-1502":{"nm":"Inselzugehörigkeitsnachweis","de":"Ein kleines Dokument, das bezeugt: Du gehörst nun zur Familie dieser Insel. Frühere Dörfer reichten warme Reiskuchen herum, wenn ein neuer Nachbar einzog und fügten seinen Namen zur Gemeinschaft hinzu. Nur ein Blatt Papier – doch darauf steht in hellen Lettern: ‚Du bist jetzt einer von uns'."},"ICON-1503":{"nm":"Unterkunftsschild","de":"Erst wenn ein Name neben der Tür hängt, wird ein leeres Zimmer wirklich jemandes Zuhause. Auch an alten Gästehäusern wurde zuerst das Namensschild des Besitzers aufgehängt. Klein wie es ist – in diesem Schild steckt die Wärme von: ‚Hier wohnt ein Mensch'."},"ICON-1504":{"nm":"Fandom-Briefmarke","de":"Einst gehörte die Sorgfalt des Anleckens und festen Aufdrückens noch zum vollständigen Brief dazu. Ein kleines Stück Papier, auf das man seine Zuneigung heftet und weit fortschickt. Auch im digitalen Zeitalter nimmt sich manch einer die Mühe, Gefühle eigenhändig zu versenden."},"ICON-1505":{"nm":"Glitzerinsel-Abzeichen","de":"Trägt man es am Revers, folgt ein kleines Leuchten auf jedem Schritt. Begegnet man unterwegs jemandem mit dem gleichen Abzeichen, versteht man sich ohne Worte. Das Glitzern ist keine Prahlerei, sondern ein stilles Signal: ‚Wir lieben dieselbe Insel'."},"ICON-1506":{"nm":"Werkbank","de":"Die zerkratzte Oberfläche bezeugt die Hände, die hier am meisten geschaffen haben. Ein Ort des Reparierens, Verbindens und Verfeinerns. Ein unordentlicher Werktisch erzählt in Wirklichkeit mehr Geschichten als ein makelloser Schreibtisch."},"ICON-1507":{"nm":"Aufbewahrungsbox","de":"Je wertvoller etwas ist, desto früher sucht man ihm einen festen Platz. Auch früher bewahrten die Menschen kostbare Dokumente gesondert in Paulownia-Holzkästchen auf. Gut aufbewahren bedeutet letztlich, den heutigen Tag ordentlich für jemanden in der Zukunft zu falten."},"ICON-1508":{"nm":"Ressourcenbox","de":"In üppigen Zeiten sammeln, in knappen Zeiten entnehmen. Die Weisheit jener Tage, als volle Vorratskammern auch das Gemüt füllten, steckt hier drin. Ein Vorrat ist eine freundliche Mahlzeit, die man seinem künftigen Ich schon heute bereitlegt."},"ICON-1509":{"nm":"Kühlbox","de":"Eine mit Eis gefüllte Truhe hielt selbst im Hochsommer die Kühle fest. Die alte Weisheit des Eishauses ist hier auf Handflächengröße geschrumpft. Kälte zu bewahren heißt, den frischesten Augenblick so lange wie möglich festzuhalten."},"ICON-1510":{"nm":"Wasserpumpe","de":"Schwingt man den Griff auf und ab, steigt tiefes Grundwasser empor. Eine ehrliche Maschine: Erst mit einer Handvoll Anlaufwasser sprudelt sie richtig los. Was man zuerst hineingießen muss, um etwas zu empfangen – das wusste der Brunnenrand schon lange."},"ICON-1511":{"nm":"Wasserfilter","de":"Ein kleines Wunder: Trübes Wasser läutert sich Schicht für Schicht. Früher schichteten die Menschen Sand und Kohle in Tongefäße, um Wasser zu klären. Reinheit ist kein Geschenk, das man umsonst bekommt, sondern Sorgfalt, die langsam filtert."},"ICON-1512":{"nm":"Gießkannenhalter","de":"Sobald die Gießkanne ihren Ruheplatz hat, ist der Tag im Blumenbeet ordentlich. Für sein Werkzeug einen festen Ort zu bestimmen ist die Gewohnheit jener, die ihre Arbeit lieben. Ist ein Platz erst einmal festgelegt, wird auch der ganze Garten ein Stück gefasster."},"ICON-1513":{"nm":"Angelrutenständer","de":"Bis der Biss kommt, mag der Mensch weggehen – die Angelrute bleibt auf ihrem Posten. Die geduldige Haltung jener, die am Fluss die Zeit angelten, hat sich hier eingeschrieben. Ein Ständer ist im Grunde eine Halterung, auf der man die Ungeduld für eine Weile ablegt."},"ICON-1514":{"nm":"Sammelkorb","de":"Das Handgepäck der Mutter, wenn sie eine Handvoll Wildkräuter oder eine Wiesenblume heimbrachte. Durch die geflochtenen Spalten schleicht sich leise Erdgeruch heraus. Was man hineintut, entscheidet: Ein leerer Korb kann Frühling oder Herbst sein."},"ICON-1515":{"nm":"Mörser","de":"Wumm, wumm – im gleichmäßigen Takt des Kornstampfens erwachte das Dorf in den Morgen. Zu Festen erfüllte das Stampfergeräusch die Gassen. Um Hartes weich zu machen, braucht es den beständigen Rhythmus geduldiger Hände."},"ICON-1516":{"nm":"Schneidebrett","de":"In jeder Messerspur ist die Geschichte einer Mahlzeit eingekerbt. Das zerkerbte Holzbrett ist die Auszeichnung der fleißigsten Hände in der Küche. Das Schneiden beginnt immer im Wunsch, jemandem etwas Liebevolles zu servieren."},"ICON-1517":{"nm":"Kochtopf","de":"Das Blubbern und Brodeln ist inniger als jede Musik. Drei Minuten warten, bis die Nudeln gar sind – in der hungrigen Nacht der persönlichste Trost. Im runden Bauch wärmt sich die Wärme auf, die man für jemanden bereitet."},"ICON-1518":{"nm":"Bratpfanne","de":"Ob ein Gericht in einem einzigen Moment gelingt, hängt an dieser einen Pfanne. Je besser die Oberfläche eingebraten ist, desto glatter und glänzender das Ergebnis. Eine lang benutzte Eisenpfanne ist selbst ein Beweis dafür, wie viele Jahre die Küche erlebt hat."},"ICON-1519":{"nm":"Backofen","de":"Während man die Tür schließt und wartet, vollzieht sich drinnen still ein Wunder. Der Teig geht auf, die Farbe bräunt sich langsam durch. Glaubt man und wartet geduldig, öffnet sich die Tür und gibt ein warmes Ergebnis preis."},"ICON-1520":{"nm":"Mixer","de":"Was auch immer man hineinsteckt, wird in einem Augenblick zu einem weichen Getränk. Ein kleiner Strudel, in dem verschiedene Zutaten sich mischen und ein neuer Geschmack entsteht. Harmonie ist letztlich die Kunst, ein wenig von seinen eigenen Ecken abzugeben."},"ICON-1521":{"nm":"Schneebesen","de":"Mit einem Schwung des Handgelenks schließt sich Luft ein, und je schneller man rührt, desto fester wird das Weiche. Während sich der Schaum zu Gipfeln türmt, bläht sich nicht nur der Teig auf. Auch das Herz, das heute jemanden bekochen möchte, wächst mit."},"ICON-1522":{"nm":"Kaffeemühle","de":"Dreht man den Griff an einer Handvoll Bohnen, bricht zuerst der Duft im Mahlwerk. Wenn die Arme schmerzen, ist das Mehl endlich fein – und der erste Schluck so tief wie die aufgewandte Mühe. Sorgfalt beginnt immer im Handgelenk."},"ICON-1523":{"nm":"Getreidemühle","de":"Körner gleiten zwischen den Steinen hindurch und kommen als weißes Mehl heraus. Wenn es beim ersten Mal nicht fein genug ist – kein Problem, noch zweimal mahlen. Auch für das Verfeinern des Groben gibt es eine Reihenfolge, die die Mühle schweigend lehrt."},"ICON-1524":{"nm":"Sägetisch","de":"Wenn ein Baumstamm aufliegt, liest die Säge zuerst die Maserung. Äste umgehen, nur geraden Linien folgen – sonst wird das Brett schief. Ein Baum zu sägen heißt letztlich, die Zeit, die er gelebt hat, ordentlich zu entfalten."},"ICON-1525":{"nm":"Nähmaschine","de":"Das Rattern der Nadel, die durch den Stoff läuft, füllt manche späte Nacht. Eine Naht verbindet zwei Bahnen zu einem Ganzen; in den unsichtbaren Stichen an der Innenseite von Bühnenkostümen stecken schlaflose Stunden."},"ICON-1526":{"nm":"Färbetisch","de":"Taucht man weißen Stoff ein und hebt ihn heraus, ist er zunächst hellgrün – erst die Luft lässt ihn blau werden. Diese Farbe soll dreimal aus dem Indigo gebrüht werden. Dass Warten selbst zur Farbe wird, habe ich zum ersten Mal vor diesem Färbetisch begriffen."},"ICON-1527":{"nm":"Kamerastativ","de":"Sobald die drei Beine sich entfalten und den Boden berühren, hält die schwankende Welt inne. Eine Aufnahme, die in der Hand gezittert hätte, wird auf dem Versprechen dieser drei Punkte gestochen scharf. Wer etwas lange betrachten will, muss zuerst lernen stillzustehen."},"ICON-1528":{"nm":"Lichtstativ","de":"Setzt man Licht auf eine einzige Säule, wird jede Ecke des Raums zu einer kleinen Bühne. Ein leichtes Drehen des Winkels – die Schatten werden länger, der Ausdruck lebt. Kein Werkzeug zum Löschen von Dunkel, sondern eines, das selbst das Dunkel freundlich in Szene setzt."},"ICON-1529":{"nm":"Mikrofonständer","de":"In dem Moment, in dem man die Höhe einstellt, ist der Abstand zwischen Mund und Lied festgelegt. Auch wenn man loslässt, bleibt die Stimme an ihrem Platz. Erst wenn auf der Bühne die Hände frei sind, beginnt der Gesang mit dem ganzen Körper."},"ICON-1530":{"nm":"Notenständer","de":"Wenn das aufgeschlagene Blatt sich schräg anlehnt, stellen sich die Noten in Augenhöhe des Musikers auf. Eine Geste – und die nächste Zeile kommt, ohne dass der Ständer wackelt. Hinter jedem Spiel gibt es stets einen stillen, tragenden Platz."},"ICON-1531":{"nm":"Gemüsebeet","de":"Pflügt man die Erde und zieht Furchen, entstehen auf dem Land kleine Reihen aus Versprechen. Die ersten Tage nach der Aussaat scheinen ereignislos – doch eines Morgens schiebt sich ein zartes Keimblatt durch die Erde. Eine Aussicht, die nur der Geduldige zu sehen bekommt."},"ICON-1532":{"nm":"Fruchtbares Gemüsebeet","de":"Dasselbe Saatgut, und doch wachsen die Blätter hier doppelt so groß. Steckt man den Finger hinein, haftet die schwarze, weiche Erde bis unters Nagelbett. Dass etwas gut gedeiht, war am Ende die stille Leistung des unsichtbaren Untergrunds."},"ICON-1533":{"nm":"Gewächshaus","de":"Unter dem Glasdach verläuft der Wechsel der Jahreszeiten einen Takt langsamer. Draußen mag Reif fallen – drinnen ist die Luft feucht wie im Hochsommer. Für all jene, die die Kälte nicht vertragen, hat jemand das Sonnenlicht sanft im Dach eingeschlossen."},"ICON-1534":{"nm":"Kräuterbeet","de":"Streift man mit den Fingerkuppen über die Blätter, grüßt der Duft als Erstes. Basilikum, Rosmarin, Minze – bei jedem Namen bleibt ein anderer Geruch an den Fingern haften. Ein kleines Beet verwandelt die ganze Küche auf die denkbar herzlichste Weise."},"ICON-1535":{"nm":"Obstgarten","de":"Im Frühling biegen sich die Äste unter Blütenschatten, im Herbst unter dem Gewicht der Früchte. Klettert man die Leiter hinauf, pflückt eine Frucht und beißt hinein, explodiert im Mund die Süße von einem ganzen Jahr Sonnenlicht. Wie ein Brief, den der Baum an den Menschen schreibt."},"ICON-1536":{"nm":"Pilzbaumstamm","de":"Bohrt man Löcher in einen gefällten Stamm und impft ihn mit Pilzbrut, beginnt das tote Holz wieder etwas zu nähren. Wenn eines Morgens Hüte in Trauben sprießen, beginnt an einem Ort, den man schon für beendet hielt, still ein neues Leben."},"ICON-1537":{"nm":"Bienenstock","de":"Hält man das Ohr nah, hört man darin ein tiefes, fleißiges Summen. Tausende Flügelschläge ergeben gerade mal einen Löffel Süße. Ein ganzer Tag des Hin- und Herflugens zwischen Blumenwiesen liegt golden und klebrig hier versammelt."},"ICON-1538":{"nm":"Hühnerstall","de":"Noch vor der Morgendämmerung raschelt es auf der Stange. Greift man die Hand in das warme Stroh, findet man ein noch warmes Ei. Der Platz, der den Tag zuerst ankündigt, bereitet auch als Erster das Frühstück."},"ICON-1539":{"nm":"Weide","de":"Weite Felder, wo Grasduft und Sonnenwärme sich vermischen. Über den gemächlich wiederkäuenden Rücken hinter dem Zaun gleiten Wolkenschatten vorbei. An einem Ort, wo es keinen Grund zur Eile gibt, verläuft sogar die Zeit so langsam wie grasende Kühe."},"ICON-1540":{"nm":"Käserei","de":"Frisch gemolkene Milch wird langsam fest, indem sie gerinnt und reift. Auf kühlen Regalen wie in Höhlen wartet sie Monate – bis ein tiefer, runder Geschmack in die weiße Masse eingezogen ist. Käse ist der Name, der nur der Milch gehört, die nicht in Eile war."},"ICON-1541":{"nm":"Tofumanufaktur","de":"Weicht man Bohnen ein, mahlt sie und kocht sie, wandelt sich das strenge Bohnenaroma in Nussiges. Ein Tropfen Gerinnungsmittel fügt das Zerstreute zu weichem Tofu – und lässt man ihn pressen, nimmt er Form an. Hier sind Hände, die wandernde Gedanken beruhigen und formen."},"ICON-1542":{"nm":"Sojasaucenregale","de":"An einem sonnenreichen Platz im Hof stehen kleine Krüge dicht an dicht und sonnen sich. Hebt man den Deckel, steigt der Geruch alter Zeit auf. Den Geschmack der Sojapaste, die Großmutter einst einlegte, zu kosten bedeutet eigentlich, in einem Löffel die Jahre zu schlürfen."},"ICON-1543":{"nm":"Getreidemühle (Dorf)","de":"Wenn Steine drehen und rumpeln, löst sich das Korn zu Mehl auf. Weißer Staub treibt im Sonnenlicht, und die Menschen warten der Reihe nach, um einen Bottich voll Reiskuchen zu formen. Der Festtag des Dorfes begann stets an dieser Schwelle."},"ICON-1544":{"nm":"Bäckerei","de":"Durch den Türspalt strömen Butter- und Zuckerduft heraus. Wenn die Laibe goldbraun werden, verlangsamen sich die Schritte der Passanten ganz von selbst. In einem frisch gebackenen Brot steckt eine Herzlichkeit, der niemand widerstehen kann."},"ICON-1545":{"nm":"Imbisswagen","de":"Die Plastikplane flattert im Wind, und die scharfe Reiskuchenbrühe köchelt und blubbert. Ein Abend mit einem Fischkuchenspieß und einem Pappbecher Brühe – der Ort, der Kälte und Hunger auf einmal vertreibt. Ein kleiner Trost am Ende der Gasse."},"ICON-1546":{"nm":"Westküche","de":"Die Pfanne heizt sich auf, Olivenöl zischt. Ein Grad zu viel, und die Soße verbrennt; ein Grad zu wenig, und sie zieht nicht an. In einer Küche, wo sogar das Farbenspiel auf dem Teller bedacht wird, ist eine Mahlzeit eine sorgfältig inszenierte Aufführung."},"ICON-1547":{"nm":"Chinesische Küche","de":"Über starker Flamme dreht sich der Wok wie tanzend im Kreis. In einem kurzen Moment lodernder Hitze wird das Aroma der Zutaten vollständig eingeschlossen. Schnell und heiß – im Zögern liegt das Verpassen dieses einen Atemzugs, in dem das Geheimnis der chinesischen Küche wohnt."},"ICON-1548":{"nm":"Café","de":"Öffnet man die Tür, empfängt einen zuerst Kaffeegeruch und sanfte Musik. Ein Fensterplatz, ein langsam abkühlender Latte, ein aufgeschlagenes Notizbuch. Damit man im geschäftigen Alltag kurz durchatmen kann, hat die Stadt solche kleinen Zimmer überall versteckt."},"ICON-1549":{"nm":"Dessertladen","de":"In der Glasvitrine stehen bunte Torten Schlange und warten auf Gäste. In dem Moment, in dem die Gabel die Sahne teilt, hebt sich unweigerlich der Mundwinkel. Selbst an traurigen Tagen macht ein Stück das Leben erträglicher – ein kleines, süßes Rezept."},"ICON-1550":{"nm":"Metzgerei","de":"Unter rotem Licht liegt das Fleisch ordentlich in der Maserung. ‚Das hier ist heute besonders gut' – und schon gleitet das Messer in der richtigen Stärke hindurch. Die Fülle auf dem Abendbrottisch beginnt still mit diesen Händen, die jeden Tag an derselben Stelle stehen."},"ICON-1551":{"nm":"Fischarbeitsplatz","de":"Ein Arbeitsplatz, an dem Fischgeruch in der Früh und die Kälte von Eis sich mischen. Schuppen spritzen, Hände frieren – und doch hören die Augen, die das Frischeste heraussuchen, nicht auf. Was gerade eben noch im Meer war, findet hier seinen Weg auf den Esstisch."},"ICON-1552":{"nm":"Saline","de":"Hält man Meerwasser zurück, erledigen Sonne und Wind den Rest. Wartet man ein paar Tage, bis das Wasser verdunstet, entstehen auf dem Grund weiße Kristalle wie Sterne. Eine Prise Salzgeschmack ist in Wahrheit ein langsames Gemeinschaftswerk von Meer und Himmel."},"ICON-1553":{"nm":"Meeresalgentrockner","de":"An langen Schnüren hängen Wakame und Kombu nebeneinander und schaukeln im Wind. Was das Meerwasser getränkt hat, dunkelt beim Trocknen tief ins Grüne nach. Der schlichteste Geschmack des Meeres, gemeinsam von Sonnenlicht und Seewind erschaffen, hängt hier."},"ICON-1554":{"nm":"Kleiner Anlegesteg","de":"Holzplanken, halb ins Wasser getaucht, schwingen leicht unter den Füßen. Genau der richtige Platz, um ein kleines Boot festzumachen. Das Aufbrechen in die Ferne wie das sichere Zurückkehren – beides beginnt und endet an diesem einen Fleck."},"ICON-1555":{"nm":"Hafenlagerhalle","de":"Öffnet man die vom Seewind gebeizte Holztür, türmen sich Netze, Fässer und Taue bis zur Decke. Reisegepäck für ferne Fahrten und gerade eingetroffenes Gepäck verweilen kurz unter demselben Dach. Ein Umsteigebahnhof, an dem Aufbruch und Rückkehr sich für einen Moment streifen."},"ICON-1556":{"nm":"Leuchtturm","de":"Wenn das Meer am finstersten ist, beginnt er erst seine Arbeit. Das rotierende Licht durchschneidet den Nebel und sagt: ‚Hier ist der Weg.' Damit jemand sicher heimkehrt, schläft er nie – ein hochgewachsener Wächter, der bis zuletzt wacht."},"ICON-1557":{"nm":"Schiffsbauwerkstatt","de":"Stellt man den Kiel auf und befestigt die Spanten, nimmt ein Schiffsrumpf Form an. Auf einem Hof, auf dem den ganzen Tag Hammerschläge hallen, träumt ein Schiff, das das Wasser noch nicht kennt, von seiner ersten Fahrt. Ein Ort, an dem man zuerst standhaft werden muss, um aufbrechen zu können."},"ICON-1558":{"nm":"Aufnahmekabine","de":"Schließt sich die Tür, verstummt mit einem Schlag jedes Geräusch von draußen. Was durch den Kopfhörer zu hören ist, sind nur Atemzüge und Takt. In der Stille dieses kleinen Raums wird endlich eine Stimme geboren, die zittern darf, so viel sie will."},"ICON-1559":{"nm":"Musikraum","de":"Durch den Türspalt schleichen sich Harmonien in den Flur und füllen ihn. Jemand übt Tonleitern, jemand anderes zählt den Takt. Ein Ort, an dem unsichere und geübte Klänge sich vermischen dürfen – ein herzliches Klassenzimmer, in dem alle Lieder ihre ersten Schritte wagen."},"ICON-1560":{"nm":"Klavierzimmer","de":"Hebt man den Tastendeckel, liegt ein leichter Staubschleier auf den weißen Tasten. Berühren die Finger sie, breitet sich ein klarer Klang durch den ganzen Raum aus. Wenn ein Abend nicht einsam ist, liegt es wohl an diesem einen Klavier."},"ICON-1561":{"nm":"Tanzraum","de":"Drückt man die Zehenspitzen auf den Boden, federt er zurück. Während die vier Wände voll Spiegel dieselbe Bewegung viermal spiegeln, lernt der Körper die Choreographie einen halben Takt vor dem Rhythmus. Der Raum, in dem Schweiß und Atem am längsten verweilen – hier tanzt, was auf die Bühne gehen will."},"ICON-1562":{"nm":"Fitnessraum","de":"Gewichte lügen nicht. Weil man genau so viel gewinnt, wie man hebt, lieben die Menschen diese ehrliche Erfahrung und kommen früh morgens. Was sich langsam im Spiegel abzeichnet, sind keine Muskeln – sondern die Zeit des Durchhaltens."},"ICON-1563":{"nm":"Yogaraum","de":"Atmet man tief ein, hat man das Gefühl, der Holzboden schwinge mit. Ein Raum, um den schnellen Tag langsam zu falten; auf einer einzigen Matte kehrt jeder zum eigenen Atemrhythmus zurück. Auch ein gehetztes Herz legt sich hier für eine Weile nieder."},"ICON-1564":{"nm":"Schminkraum","de":"Kurz bevor man auf die Bühne tritt, wird man hier für einen Moment zu jemand anderem. Wenn die Glühbirnen rund um den Spiegel das Gesicht gleichmäßig ausleuchten, schleicht sich das Zittern am Quastenpinsel entlang in den Kragen und versteckt sich. Der Ort, an dem Verwandlung beginnt und endet."},"ICON-1565":{"nm":"Kostümraum","de":"Bis ein Bühnenkleid fertig ist, werden die hier hängenden Kostüme dutzende Male an- und abgezogen. Eine Schaufensterpuppe mit Stecknadeln, eine Kreidenaht. Auf der Rückseite des Glanzes bleiben stets jemandes Nadelstiche."},"ICON-1566":{"nm":"Studiodekorationsset","de":"Nur die eine Seite, auf die die Kamera zeigt, muss echt aussehen, lernte ich früh. Dreht man sich um, findet man hinter der Spanplatte nur ein leeres Gerüst. Das Fundament, das die Pracht der Vorderseite schweigend trägt, sind stets die unsichtbaren Latten."},"ICON-1567":{"nm":"Fotostudio","de":"Das erste Geheimnis: Licht aus drei Richtungen werfen, um Schatten zu tilgen. Das Hauptlicht fürs Gesicht, das Fülllicht für den Schatten, das Hinterlicht für die Haarspitzen. In dem Augenblick, in dem der Verschluss fällt, fängt ein weißer Hintergrund das schönste Lächeln des Tages ein."},"ICON-1568":{"nm":"Aufführungsort","de":"In der hohen Dunkelheit trage ich stets dasselbe Versprechen: Wenn der Vorhang sich hebt, hält selbst das leere Parkett den Atem an. Für jenen einen Moment des ersten Taktes stehe ich das ganze Jahr über still und leer bereit."},"ICON-1569":{"nm":"Fanmeetingstand","de":"Der Abstand zwischen den Händen beträgt genau eine Tischbreite. Kurze Begrüßung, zitterndes Autogramm, das eine Wort, das man nicht über die Lippen brachte – alles zieht vorbei. In dieser kleinen Kabine begegnet ein lang gepflegtes Gefühl zum ersten Mal einem Gesicht."},"ICON-1570":{"nm":"Bett","de":"Das Erste, das das Ende eines Tages auffängt, war immer ich. Wenn schwere Beine vom Training und das Zittern hinter der Bühne sich ganz gesetzt haben, beginnt der Morgen wieder mit leichten Zehenspitzen. Schlaf gut – ich halte dich schweigend."},"ICON-1571":{"nm":"Etagenbett","de":"Zwischen Ober- und Unterstock verbinden fünf Leitersprosse zwei Menschen. Leise Stimmen im Dunkeln, Leuchtsterne an der Decke. Die enge Unterkunft wird am weitesten, wenn jede Nacht Geschichten die Leiter hinauf- und hinunterklettern."},"ICON-1572":{"nm":"Regal","de":"Was man darauf stellt, verrät den Menschen dahinter. Empfangene Briefe, die erste Trophäe, eine verblasste Eintrittskarte stehen Schulter an Schulter. Ich bin kein Möbelstück zum Prahlen – sondern ein Ort, der Erinnerungen aufbewahrt, die man nicht wegwerfen konnte."},"ICON-1573":{"nm":"Schreibtisch","de":"Ein Liedtext-Notizbuch liegt aufgeschlagen; über ausradierten Spuren zieht sich eine neue Zeile. Leere Pappbecher über Nacht angesammelt, eine Melodie, die gerade noch gerettet wurde. Die langsame Arbeit, Gefühle in Wörter zu übersetzen, geschieht stets still auf dieser flachen Fläche."},"ICON-1574":{"nm":"Stuhl","de":"‚Setz dich kurz' ist überraschend herzlich gesagt. Auch wenn Sitzungen lang werden und Proben sich ziehen, nimmt die Rückenlehne schweigend das Gewicht des Menschen auf. Wer lange gestanden hat, schätzt mich besonders – das weiß ich."},"ICON-1575":{"nm":"Sofa","de":"Um ein Unterkunftszimmer zum Wohnzimmer zu machen, genüge ich allein. Sitzt man dicht zusammengedrängt und schaut eine Unterhaltungsshow, schläft irgendwann einer an der Armlehne ein. Der eingedellte Mittelteil beweist die Wärme dieses Hauses."},"ICON-1576":{"nm":"Tisch","de":"Wenn man sich herumschart, ist niemand am Ehrenplatz. Frisch gekochter Eintopf, klappernde Löffel, alles was heute passiert ist – strömt in die Mitte. Breitet man diese runde Fläche aus, setzt sich auch der zerstreute Tag wieder an einen Tisch."},"ICON-1577":{"nm":"Kleiderschrank","de":"Mit jedem Jahreszeitenwechsel quillt aus dem Inneren eine alte Geschichte hervor. Bühnenkostüme und Alltagskleidung stehen Schulter an Schulter; hinter der geschlossenen Tür warten die Kleider auf ihren nächsten Einsatz. Erst wenn man die Tür öffnet, steht fest, welcher Tag heute beginnt."},"ICON-1578":{"nm":"Spiegel","de":"Lob und Makel gibt er mit derselben ehrlichen Sachlichkeit zurück. Der Ort der letzten Kontrolle vor dem Auftritt – hier wählen die Menschen ihren Ausdruck und richten die Haltung. Der aufrichtigste Freund sagt nie ein Wort."},"ICON-1579":{"nm":"Schminktisch","de":"In jedem kleinen Schubfach schläft ein anderes Gesicht. Ein Töpfchen für die Bühne, eines für den Alltag, ein limitiertes aufgespartes. Wer sich vor den Spiegel setzt, entscheidet zuerst langsam, als wer er heute die Tür öffnen wird."},"ICON-1580":{"nm":"Teppich","de":"Die Temperatur des Raumes legt sich fest in dem Moment, in dem nackte Füße ihn berühren. Spuren des gemeinsamen Kuschelns und Knabberns bleiben als Fusseln zurück. Das tiefste Möbelstück – es wärmt den kalten Boden einen Handbreit mehr."},"ICON-1581":{"nm":"Vorhang","de":"Wie viel Morgen hereinkommt, bestimme ich. Rafft man mich leicht, fällt langes Sonnenlicht herein; zieht man mich fest zu, verzeiht sich sogar der Langschläfer. Zwischen Fenster und Zimmer stehe ich und dosiere das Licht – das ist meine Aufgabe."},"ICON-1582":{"nm":"Beleuchtung","de":"Dasselbe Zimmer wird je nach Lichtfarbe zu einem völlig anderen Moment. Gelbes Licht zieht den Abend in die Länge, weißes Licht weckt den frühen Morgen scharf. Mit einem einzigen Schalter die Stimmung des Tages sanft wenden – der handtellergroße Zauberer."},"ICON-1583":{"nm":"Wanduhr","de":"Das Ticken des Sekundenzeigers ist nur im stillen Zimmer zu hören. Taucht man tief in die Probe ein und vergisst mich – schaut man irgendwann hoch und sieht, dass es draußen schon Morgengrauen ist. Keine Klage über die vergangene Zeit; nur schweigend auf das nächste Kästchen zeigen."},"ICON-1584":{"nm":"Vase","de":"Auch wenn die Blumen welken, lasse ich den Platz nicht leer. Ich bin das Gefäß, das empfangene Zuneigung für eine Weile bewahrt; solange eine Hand das Wasser wechselt, bleibt der Tisch hell. Selbst wenn ich leer bin, stehe ich in der Haltung der Erwartung."},"ICON-1585":{"nm":"Posterrahmen","de":"Auch das Aufhängen eines geliebten Gesichts an der Wand ist ein Akt der Fürsorge. Ein Platz, den kein direktes Sonnenlicht trifft; ein einziger Nagel, der genau waagerecht sitzt. Das sorgfältig hinter Glas gebettete Blatt begrüßt mich jeden Morgen als Allererstes, wenn ich ins Zimmer trete."},"ICON-1586":{"nm":"Fotokarten-Board","de":"Ob man alphabetisch oder nach Erscheinungsdatum sortiert – schon diese glückliche Überlegung ist der Beginn des Fan-Seins. Ein leeres Fach ist der Platz für den Lieblings-Charakter, dem man noch nicht begegnet ist. Je mehr Fächer gefüllt werden, desto mehr wird das Board zur eigenen kleinen Chronik."},"ICON-1587":{"nm":"Lightstick-Ständer","de":"Batterie heraus, Griff nach oben. Auch der Winkel, in dem man ihn schräg hinstellt, hat seinen eigenen Kniff. Im Warten auf den nächsten Jubel legt der Stick das Licht aus und bettet sich ordentlich hier zur Ruhe. Wer gut ausruht, leuchtet heller."},"ICON-1588":{"nm":"Trophäenregal","de":"In die vorderste Reihe kommt das Älteste. Von der kleinen Bronze eines Wettbewerbs bis zum Pokal der großen Bühne – aufgereiht nicht nach Größe, sondern nach der Reihenfolge des Herzens. Beim Abstauben spürt man jedes Mal das Zittern jenes Tages auf der Bühne wieder an den Fingerkuppen."},"ICON-1589":{"nm":"Picknickkorb","de":"Öffnet man den Deckel, strömt zuerst der Duft von Frühlingssonne heraus. Gimbap, Thermosflasche und eine gefaltete Decke – alles dicht gestapelt und bereit fürs Feld. Wer mich trägt, schreitet irgendwie mit einem Fußbreit leichterem Schritt als sonst."},"ICON-1590":{"nm":"Kleiner Blumentopf","de":"Eine Fensterbank breit genügt mir. Auch wenn man das Gießen oft vergisst, halte ich geduldig durch – das kleine Grün. In einer Ecke des Schreibtischs eines Vielbeschäftigten entfalte ich jeden Tag noch ein Blatt und grüße still mit dem Befinden des heutigen Tages."},"ICON-1591":{"nm":"Großer Blumentopf","de":"Während ich wachse, wächst der Mensch mit. Wenn die breiten Blätter, die eine Zimmerecke füllen, das Sonnenlicht empfangen und Schatten werfen, zieht auch im Raum eine Jahreszeit ein. Der Lohn, den nur kennt, wer das Gießen nicht vergisst."},"ICON-1592":{"nm":"Duftkerzen-Set","de":"In dem Moment, in dem man den Docht anzündet, legt sich die Luft im Zimmer eine Stufe tiefer. Der Duft breitet sich langsam aus und schmilzt die Müdigkeit des gestrigen Tages weg. Mit einer kleinen Flamme das Ende eines geschäftigen Tages wie ein stilles Ritual abschließen."},"ICON-1593":{"nm":"Mini-Kühlschrank","de":"Öffnet man die Tür spät nachts, grüßt einen eine kühle Dose. Das leise Summen macht die leere Unterkunft ein wenig weniger einsam. Für einen großen Haushalt tauge ich vielleicht nicht – aber für hungrige Nächte bin ich unschlagbar."},"ICON-1594":{"nm":"Libellen-Kopfschmuck","de":"Setzt man ihn auf, folgt auf der Stelle eine Sommerwiese auf den Schultern. Das runde Netz filtert das Sonnenlicht sanft, und mit jedem Schritt weht Grasduft herein. Ein Hut, in den man den ganzen Sommer gesteckt hat – auch ohne eine einzige Libelle zu fangen."},"ICON-1595":{"nm":"Sammelnetz-Beutel","de":"Er hängt am Gürtel und wird zum Begleiter beim Sammeln. Zieht man den Eingang ein wenig zu, entkommt das Gefangene nicht wieder – der erste Trick, den man auf der Wiese lernte. Ein leichter Stoffbeutel umschließt fest die ganze Tagesausbeute."},"ICON-1596":{"nm":"Insektenbeobachtungsbehälter","de":"Für einen kurzen Gast ist die Belüftungsöffnung das Wichtigste – das weiß ich. Ein kleines Atemloch im Deckel, ein Blatt Gras auf dem Boden. Zum Behälter gehört auch, den Gast ins Gebüsch zurückzugeben, wenn die Beobachtung endet."},"ICON-1597":{"nm":"Präpariernadeldose","de":"Im Winkel, in dem man die Nadel schräg einsticht, steckt das Können. Zu tief, und es zerbricht; zu flach, und es wackelt – die Kraft der Fingerspitzen muss feinfühlig dosiert werden. Eine Dose, in der sich die Sorgfalt eines Menschen niederlegt, der ein kleines Leben lange betrachten möchte."},"ICON-1598":{"nm":"Terrarium-Deckel","de":"Die Grenze zwischen innen und außen zu verantworten ist meine Aufgabe. Zu fest geschlossen, und die Luft stockt; zu locker, und das Tier findet den Ausweg nicht – deshalb lasse ich stets einen haarschmalen Spalt. Beschützen und Einsperren sind eindeutig zweierlei."},"ICON-1599":{"nm":"Schmetterlings-Futterteller","de":"Legt man in die Mitte ein mit Zuckerwasser getränktes Wattepad, scharen sich die Flügel heran. Flach und weit, gerade tief genug, dass kleine Beine nicht versinken – das ist das Geheimnis. Ein Teller lockt im sonnigen Garten sanft all jene herbei, die nur kurz zu Besuch bleiben wollen."},"ICON-1600":{"nm":"Insektenfalle (Licht)","de":"Lässt man sie im Dunkeln leise leuchten, strömen kleine Flügel dem Licht nach. Sanft hell, weit weg von den Menschen. Der liebenswürdigste Anlocker, der eine laute Sommernacht ein wenig ruhiger werden lässt."},"ICON-1601":{"nm":"Insekten-Sticker-Label","de":"Sechs Beine, ein Paar Fühler – auf einem Stück Papier von Nagelgröße schlummert ein kleines Leben. Klebt man es an eine Notizbuchecke, breitet sich zwischen den Buchseiten leise ein Fleck Wiese aus."},"ICON-1602":{"nm":"Sammelgenehmigungs-Anhänger","de":"Bevor man den Kescher schwingt, fragt der Erwachsene zuerst. Wie viele, bis wohin. Dieser kleine Anhänger zieht eine sanfte Grenzlinie zwischen ausgelassener Neugier und dem, was man einhalten muss."},"ICON-1603":{"nm":"Köderbox","de":"Öffnet man den Deckel, steigt ein fischiger, frischer Morgengeruch auf. Vielleicht lockt Fische nicht der Köder, sondern das Herz, das ruhig abwarten kann, bis die Pose zuckt."},"ICON-1604":{"nm":"Schwimmerbox","de":"Ein kleines Schränkchen, in dem bunte Posen Fach für Fach schlafen. Manche passen zu einem stillen Morgen am See, andere zum reißenden Strom am Mittag. Für jeden Ausdruck des Wassers liegt hier ordentlich der passende Partner bereit."},"ICON-1605":{"nm":"Angelschnurroller","de":"Schling die abgewickelte Schnur nicht um die Finger. Wickelt man sie ordentlich auf dieses runde Gerät auf, löst sich auch das Verknäueln. Eine Bewegung, die dem Wiederordnen eines langen Tages ähnelt."},"ICON-1606":{"nm":"Hakenentferner","de":"Nur wer sich schon einmal beim Versuch, einen Haken mit bloßen Händen zu entfernen, gestochen hat, erkennt dieses Werkzeug sofort. Ein weniger schmerzhafter Weg für das kleine Lebewesen wie für die eigenen Fingerspitzen. Rücksichtnahme beginnt stets an solch kleinen Enden."},"ICON-1607":{"nm":"Muschelschaufel-Abdeckung","de":"Eine Lage, die das soeben aus dem Wattenmeer ausgegrabene Schaufelblatt umhüllt. Damit Schlamm und Salzwasser das Blatt nicht zerfressen, wird zwischen Meer und Werkzeug eine dünne, sanfte Ruhepause eingeschoben."},"ICON-1608":{"nm":"Gezeitentafel-Karte","de":"Wann das Wasser kommt und wann es sich zurückzieht – eine handflächengroße Karte sagt es leise. Ein kleiner Kalender, auf den Menschen den alten Pakt zwischen Mond und Meer abgeschrieben haben."},"ICON-1609":{"nm":"Aquarium-Reinigungsbürste","de":"Wischt man den grünen Algenfilm sacht von der Glaswand, fällt wieder Licht in die kleine Unterwasserwelt. Jemandes Tag heller zu machen verläuft meist so – still und fließend."},"ICON-1610":{"nm":"Aquarium-Temperatur-Chip","de":"Eine Zahl blinkt auf, hält bei der richtigen Gradzahl inne – und die Fische beruhigen sich. Nicht zu kalt, nicht zu warm: eine Wärme, die genau in eine Spalte passt. Fürsorge reicht bis dorthin, wo man sie nicht sieht."},"ICON-1611":{"nm":"Meereswesen-Beobachtungsbehälter","de":"Ein kleiner Gast, der kurz im durchsichtigen Behälter verweilt. Man zählt sorgfältig die Rückenflossen und gibt ihn dann ans Meer zurück. Beobachten heißt nicht besitzen, sondern für eine Weile ausleihen."},"ICON-1612":{"nm":"Fossilienbürste","de":"Der Jahrmillionen schläft im Stein – und der Hammer weckt ihn nicht auf, sondern das weiche Bürstenende. Angesichts einer Zeit, die zerbricht, wenn man sich übereilt, ist Behutsam-Sein die tiefste Form des Respekts."},"ICON-1613":{"nm":"Ausgrabungspinsel-Kappe","de":"Trocknet die Pinselspitze aus, fällt die Erde nicht mehr sauber ab. Ein kleines Käppchen hält die Feuchtigkeit des Pinsels. Die Hand, die ihr Werkzeug pflegt, tut den ersten Schritt zur Ausgrabung."},"ICON-1614":{"nm":"Bodenschicht-Probetafel","de":"In einer Handbreit Erde liegen Jahrhunderte übereinandergeschichtet. Schöpft man davon sanft auf diese Tafel, tauchen langsam die unsichtbaren Muster der Zeit auf und ziehen ihre Linien."},"ICON-1615":{"nm":"Knochenfragment-Tablett","de":"Legt man die verstreuten Teile ordentlich in die Fächer, beginnt ein ganzes Leben langsam seinen Platz zu finden. Restaurierung ist das freundliche Wiederbefragen der verlorenen Reihenfolge."},"ICON-1616":{"nm":"Restaurierungsklebeband","de":"Ein dünner Faden, der die gebrochene Stelle verbindet. Narben werden nicht verborgen, sondern herzlich gehalten und zusammengehalten. Auch was zerbrochen war, kann wieder ganz werden – das beweist es leise."},"ICON-1617":{"nm":"Vitrinenschild-Abdeckung","de":"Eine einzelne Lage, die verhindert, dass das Namensschild hinter Glas verblasst. Der Wunsch, dass dieser kurze Satz darüber, wer hier lebte und woher er kam, noch in ferner Zukunft klar zu lesen ist, steckt darin."},"ICON-1618":{"nm":"Magazin-Tag","de":"Ein tiefer Raum, in dem Schätze schlafen, die nicht im Licht stehen. Allem darin hängt ein kleines Namensschild. Damit selbst jene, die keinen hellen Platz haben, niemals vergessen werden."},"ICON-1619":{"nm":"Museums-Schenkungsumschlag","de":"Jemand übergibt schweigend, was er ein Leben lang gesammelt hat. Was in diesem Umschlag steckt, ist kein Gegenstand, sondern ein lang gehütetes Gefühl. Das Teilen wird zur längsten Ausstellung und erleuchtet jemanden."},"ICON-1620":{"nm":"Probennummer-Chip","de":"An der Fundstelle wird dem Gesammelten leise eine kleine Zahl gegeben. Wann und wo man es zuerst traf. Eine Entdeckung, die man nicht aufschreibt, zerstreut sich rasch wie Morgennebel."},"ICON-1621":{"nm":"Sternschnuppen-Splitterflasche","de":"Ein Splitter, der den Nachthimmel durchschnitten hat und herabfiel, ist in der Glasflasche gefangen. Ein Lichtstrahl, der verglühte, noch ehe man einen Wunsch aussprechen konnte, funkelt nun still und leise wieder in der Hand."},"ICON-1622":{"nm":"Muschel-Windspielschnur","de":"Am Strand Muschel für Muschel aufgelesen, auf eine Schnur gefädelt und unters Dach gehängt. Bei jedem Windzug ein klimperndes Klirren – und das Meer jenes Sommers zieht leise bis ins Haus hinein."},"ICON-1623":{"nm":"Regenbogentropfen","de":"Ein Tropfen, der nach dem Regen an der Blattspitze hängt. In seiner runden Wölbung fasst sich der ganze Himmel mit seinen sieben Farben. Manchmal birgt das Kleinste die weiteste Landschaft."},"ICON-1624":{"nm":"Nebelfänger-Flasche","de":"Eine ganze Flasche voll Morgennebel vom Fuß des Berges heimgebracht. In der Hand fühlt sie sich kühl an und trübt sich milchig ein. Ein kleiner, liebevoller Wunsch, das Unfassbare für einen Moment bei sich zu behalten."},"ICON-1625":{"nm":"Tautropfen-Becher","de":"Ein kleiner Becher, der den Tau auffängt, den ein Grashalm die Nacht über Tropfen für Tropfen gesammelt hat. Kaum ein Schluck – und doch ruht darin der klarste, reinste Teil des Morgens ganz still."},"ICON-1626":{"nm":"Windhauch-Schleifenspange","de":"Eine Schleife, gebunden nach dem Muster, das der Wind hinterlässt. Steckt man sie ins Haar, folgt bei jedem Schritt ein sanftes Lüftchen. Die Leichtigkeit eines Frühlingstags, in einer einzigen Spange still festgebunden."},"ICON-1627":{"nm":"Wellenrauschen-Kapsel","de":"Hält man sie ans Ohr, rollen die Wellen des fernen Meeres heran. Als hätte jemand jenen Klang, den man einst in einer Muschelschale bewahrte, behutsam in einer kleinen Kapsel versiegelt."},"ICON-1628":{"nm":"Sandstern-Splitter","de":"Greift man am nächtlichen Strand eine Handvoll Sand, blitzt darin Sternenstaub auf. Ob er vom Himmel fiel oder von den Wellen fein gemahlen wurde – danach fragt niemand ernstlich."},"ICON-1629":{"nm":"Inselwetter-Aufzeichnungschip","de":"Der Himmel der Insel ändert mehrmals am Tag seine Laune. Trägt man Sonne, Nebel und Schauer sorgsam auf einem kleinen Chip ein, lässt sich der Himmel von gestern heute wieder aufschlagen."},"ICON-1630":{"nm":"Klippentreppen-Bausatz","de":"Eine Stufe, noch eine Stufe, um den steilen Hang auf und ab zu gehen. Setzt man die verstreuten Teile zusammen, wird selbst die Klippe zu einem gemächlichen Spazierweg. Einen Weg anzulegen heißt, den nächsten Schritt eines anderen schon vorauszulegen."},"ICON-1631":{"nm":"Feldweg-Musterrolle","de":"Eine Rolle, die die Maserung eines weichen Feldwegs originalgetreu abgeformt hat. Rollt man sie aus, breitet sich still ein ländlicher Pfad zu Füßen aus, den man am liebsten barfuß entlanggehen möchte."},"ICON-1632":{"nm":"Steinweg-Musterchip","de":"Das Muster des Kopfsteinpflasters, das einst die alten Gassen füllte, ist unversehrt in einem kleinen Chip bewahrt. Bei jedem Tritt ein klappernder Klang – und die Schritte eines alten Dorfes leben unter den Füßen wieder auf."},"ICON-1633":{"nm":"Strandzaun-Segment","de":"Ein niedriger Zaun, in den Sand gesetzt, damit die Wellen nicht herüberschwappen – ein Stück davon. Ein kleiner, schweigsamer Grenzhüter, der zwischen Meer und Sand eine freundliche Linie zieht."},"ICON-1634":{"nm":"Rasenausbesserungs-Flicken","de":"Ein Stück Grün, das man sacht über eine kahlgetretene Stelle legt. In wenigen Tagen fassen sich die Gräser an den Händen und füllen die Lücke. Die Natur weiß stets, wie sie von selbst wieder heilt."},"ICON-1635":{"nm":"Wasserlauf-Markierungspflock","de":"Ein Pflock, der dem Wasser im Voraus den Weg weist. Damit das Regenwasser nicht ratlos umherirrt, wohin es fließen soll, steht dieser kleine Wegweiser fest in der Erde – auch an Regentagen unbeirrt."},"ICON-1636":{"nm":"Kleine-Brücke-Bauteil","de":"Ein Teilstück einer winzigen Brücke, die beide Ufer eines Bachs verbindet. Zwischen dieser und jener Seite beginnt in diesem einen kleinen Bauteil still das Versprechen, jederzeit hinübergehen zu können."},"ICON-1637":{"nm":"Aussichtsplattform-Geländerkappe","de":"Der höchste Ort der Insel – ein Abschlussstück, das das Ende jenes Geländers umschließt. Die Stelle, die die Hände der Menschen, die zum Fernblick zusammenkommen, am häufigsten berühren, stützt und beschützt es still."},"ICON-1638":{"nm":"Lagerfeuer-Untersatz","de":"Bevor man das Brennholz auflegt, ein Platz, der die Funken davon abhält, sich zu verstreuen. Darüber die Nächte, in denen man zu den Sternen aufblickte und plauderte, brennen noch lange warm nach."},"ICON-1639":{"nm":"Tapeten-Musterrolle","de":"Die Stimmung eines Zimmers beginnt an einer einzigen Wand. Eine kleine Rolle auszubreiten und die Farbe zu wählen heißt, im Voraus still zu entwerfen, was für Tage man künftig leben möchte."},"ICON-1640":{"nm":"Bodenbelag-Musterchip","de":"Man tastet mit den Fingerspitzen vorab, wie sich der Boden anfühlen wird, den nackte Füße berühren. Ob warm oder kühl – an diesem kleinen Chip hängt still die Behaglichkeit der kommenden Tage."},"ICON-1641":{"nm":"Deckenhaken-Set","de":"In dem Moment, in dem man einen Haken am Balken anbringt, wird die leere Decke zu einem Platz, der auf jemanden wartet. Ein Windspiel oder einen Blumentopf? Das Gewicht trägt dieser kleine Eisenhaken – was man daran hängt, bestimmt das Herz des Bewohners."},"ICON-1642":{"nm":"Fensterabschirmfolie","de":"Weil das Licht des Mittags allzu schonungslos ist, legt man dem Fenster eine dünne Schicht an. Die Sonne fällt herein wie zuvor, doch die Kanten lösen sich sanft, und alles im Zimmer wird aprikosenfarben und milde. Kein Verdunkeln, sondern ein freundliches Verstreuen des Lichts."},"ICON-1643":{"nm":"Türklingel-Abdeckung","de":"Auch die Klingel, die ein Gast drückt, brauche ein Kleid, dachte jemand und setzte ihr eine runde Abdeckung auf. Sie hält Regen und Staub ab und ist vor allem ein kleiner, runder Mund, der als Erster grüßt: ‚Hier wohnt ein Mensch'."},"ICON-1644":{"nm":"Gästebuch-Ständer","de":"Ein Ständer, der aufgestellt wurde, damit jeder Ankommende seinen Namen einträgt. Noch bevor die Tinte trocknet, fließt vom Federende eine Zeile mit Grüßen. Reiht sich ein Besuch nach dem anderen, wird das leere Heft alsbald zum dicksten Album dieses Hauses."},"ICON-1645":{"nm":"Möbelplatzierungs-Pin","de":"Den Schreibtischplatz, bei dem man zögerte, ob man ihn verrücken soll, nagelt ein einziger Pin am Boden fest und entscheidet ihn. Ein kleiner Nagel, der die Füße der Möbel sacht festhält. Ein Platz, einmal bestimmt, wird einem ans Herz wachsen, nickt der Dielenboden still."},"ICON-1646":{"nm":"Aufbewahrungs-Etikettrahmen","de":"Was worin steckt, kann die Schublade am Ende nicht sagen. Also steckt man in einen eckigen Rahmen ein Namensschild und lässt es an ihrer statt sprechen. Sobald ein Etikett seinen Platz findet, gewinnt jedes unordentliche Fach seinen Namen zurück und wird still."},"ICON-1647":{"nm":"Raumduft-Diffusorstäbchen","de":"Der Duft, mit dem die Stäbchenenden getränkt sind, steigt langsam empor. Mal Lavendel, mal eine Wiese nach dem Regen. Wenn dieser fadenfeine, unsichtbare Geruch die Luft des Zimmers austauscht, löst sich von den Schultern des Heimkehrers die Müdigkeit eines ganzen Tages."},"ICON-1648":{"nm":"Samentütchen-Klammer","de":"Die im Frühjahr gekauften und nicht ausgesäten Samen klemmt man samt Tütchen fest mit einer Klammer zusammen. Entweicht auch nur ein Korn, wird das nächste Jahr um eine Reihe ärmer. In diesem kleinen Verschluss schlummert das ganze Gemüsebeet des kommenden Jahres."},"ICON-1649":{"nm":"Setzling-Tablett","de":"Fach für Fach mit Erde gefüllt, entsteht das erste Zimmer der jungen Keime. In jedem Loch ein Leben, in Reih und Glied heranwachsende Neulinge. Blickt man hinein, beginnt jeden Morgen aufs Neue ein Appell, bei dem das Grün dicht gedrängt Anwesenheit meldet."},"ICON-1650":{"nm":"Gieß-Markierungspin","de":"‚Ich habe Durst.' Weil der Blumentopf nicht sprechen kann, steckt ein kleines Schildchen in der Erde und sendet an seiner statt das Signal. Ändert sich die Farbe, ist es Zeit zu gießen. Die kleinste Übersetzung zwischen Pflanze und Mensch steckt ganz in diesem handbreiten Stäbchen."},"ICON-1651":{"nm":"Pflanzenstützband","de":"Damit schwankende Stängel nicht unter ihrem eigenen Gewicht nachgeben, bindet man sie sachte mit einem weichen Band an die Stütze. Zu fest geschnürt erstickt die Pflanze, zu locker fällt sie um – die Hand, die bindet, braucht das richtige Maß an Zartheit. Auch beim Wachsen braucht man manchmal Begleitung."},"ICON-1652":{"nm":"Insektenschutznetz","de":"Ein fein gewebtes Netz hält still die kleinen Mäuler fern, die es auf zarte Blätter abgesehen haben. Wind und Sonnenlicht lässt es passieren, nur das Schädliche hält es ab – ein unsichtbarer Wächter. Dass es im Gemüsebeet so friedlich ist, verdankt man dieser sorgfältigen Maschenarbeit."},"ICON-1653":{"nm":"Sonnenmesserkarte","de":"Wie viel Sonne fällt hier eigentlich? Man stellt eine Karte ins Beet und fragt nach. Je dunkler die Farbe, desto mehr Licht hat die Stelle heute empfangen. Dieses kleine Stück Papier weist dem Sonnenliebhaber und dem Schattenpflänzchen ihren richtigen Platz zu."},"ICON-1654":{"nm":"pH-Teststreifen für Erde","de":"Hält man den Streifen in die Erde, verrät sie ihre Stimmung in Farben von Rosa bis Blau. Weder zu sauer noch zu bitter – in der goldenen Mitte atmen Wurzeln am tiefsten. Das verborgene Innenleben des Bodens lässt sich Feld für Feld ablesen."},"ICON-1655":{"nm":"Erntekorbschild","de":"Ob Salat oder Kirschtomaten – jeder Korb bekommt ein Namensschildchen. An diesem Erntevormittag, der nach Erde und frischem Grün duftet, wird der Korb mit dem Schild zum ersten Wegweiser auf dem Weg zum Esstisch."},"ICON-1656":{"nm":"Saatgutaufbewahrungsglas","de":"Die diesjährigen Samen kommen ins Glas und werden dem nächsten Frühling geschickt. Mit dem Verschließen hält die Zeit kurz inne, und die kleinen Körnchen warten im Dunkeln auf ihren Auftritt. Dieses Glas ist wie ein Brief, der eine Jahreszeit überspringt."},"ICON-1657":{"nm":"Veredelungsband","de":"Abgeschnittenes und neues Reis werden zusammengefügt und mit dem Band umwickelt – langsam werden die beiden eins. Der Saft fließt wieder durch die verletzte Stelle, die Wunde heilt. Zusammenfügen heißt letztlich, die Struktur des anderen anzunehmen."},"ICON-1658":{"nm":"Schutzklappe für Gartenschere","de":"Auf die scharfe Klinge der Gartenschere setzt man ein kleines Schutzköpfchen. Solange die Hände ruhen, bleibt die Schneide scharf und die Hand unversehrt. Auch ein Werkzeug, das seinen Dienst getan hat, braucht sein Schlafanzügchen – der Gemüsegarten legt seine Geräte sorgsam schlafen."},"ICON-1659":{"nm":"Blumensamen-Sortierdose","de":"Balsamine, Portulakröschen, Wunderblume – Samen mit verschiedenen Namen und Farben bekommen jeder ihr eigenes Fach. Sind sie durcheinandergeraten, weiß man im Frühling nicht mehr, wer wer ist. Die kleinen Trennwände zeichnen schon jetzt den Plan des Gartens vor, der noch nicht erblüht ist."},"ICON-1660":{"nm":"Blumentopf-Rolluntersetzer","de":"Selbst ein schwerer Topf rollt auf vier Rädern dem Sonnenlicht entgegen. Morgens ans Ostfenster, mittags in den Schatten. Das einstige Schwergewicht düst jetzt munter durch die Wohnung und sucht den ganzen Tag über den besten Platz im Licht."},"ICON-1661":{"nm":"Rankführungsschnur","de":"Ranken, die ziellos in der Luft tasten, leitet die Schnur behutsam auf den richtigen Weg. Aufwärts, immer höher. Hat man ihnen einen Halt gegeben, greifen Pflanzen auf wundersame Weise danach. Auch beim Wachsen braucht man manchmal eine Richtung."},"ICON-1662":{"nm":"Blumensprache-Kartenhalter","de":"Auf der Karte neben der Blume steht, was sie uns sagen möchte. Hortensie: Aufrichtigkeit, Gänseblümchen: Reinheit. Damit ein Spaziergang durchs Beet zum Lesen von Briefen wird, leiht der kleine Halter der stummen Blume leise seine Stimme."},"ICON-1663":{"nm":"Gartenpfahl-Schutzklappe","de":"Damit der Regen die Aufschrift nicht verwischt, setzt man dem Gartenpfahl eine klare Kappe auf. „Hier Tomaten“, „hier Basilikum“. Die Namensschilder bleiben deutlich erhalten – der Gemüsegarten vergisst auch nach einem Jahr keines seiner Mitglieder."},"ICON-1664":{"nm":"Düngerlöffel","de":"Gibt man der Erde zu viel Nährstoffe, verbrennen die Wurzeln. Also genau ein Löffel, nicht mehr. Der kleine Löffel schöpft die richtige Menge und erinnert daran: Eine gute Pflegegeste kommt stets aus Händen, die das rechte Maß kennen."},"ICON-1665":{"nm":"Wassertropfen-Brausekopf","de":"Dreht man den Brausekopf, verteilt sich der Wasserstrahl wie feiner Nebel. Zarte Blätter, die von einem starken Strahl niedergedrückt wurden, richten sich unter den taugleichen Tröpfchen sanft auf. Auch das gleiche Wasser kann eine ganz andere Begrüßung sein, je nachdem, wie man es spendet."},"ICON-1666":{"nm":"Futtermessbecher","de":"Ein Becher, zwei Becher. Die Mahlzeit des Freundes nicht nach Augenmaß, sondern mit Bedacht abmessen. Zu viel bleibt übrig, zu wenig lässt ihn hungrig – die richtige Menge zu finden ist Fürsorge. Manchmal kommt Liebe in Gestalt eines Messbechers."},"ICON-1667":{"nm":"Fellbürsten-Schutzkappe","de":"In der Fellwechselzeit hüllt die Kappe die weichen Haare, die sich in der Bürste verfangen haben, sorgsam ein. Nach dem Bürsten ein Käppchen drüber – dann startet der nächste Tag frisch und sauber. Die Pflege des glänzenden Fells unserer Mitbewohner wächst in solch kleinen Ordnungsmomenten still heran."},"ICON-1668":{"nm":"Krallenschneider-Schutzkappe","de":"Auf die scharfe Spitze des Krallenschneiders kommt ein kleines Schutzkäppchen. So kratzt das Werkzeug nach getaner Arbeit nichts anderes in der Schublade an. Die Pflegerunde ist erst vollständig, wenn man auch das Werkzeug sorgsam zur Ruhe bringt."},"ICON-1669":{"nm":"Halsband-Schmuckchip","de":"Hängt ein glitzernder Chip am Halsband, wird der gewohnte Spaziergang ein kleines bisschen besonderer. Das winzige Schmuckstück funkelt im Sonnenlicht. Nicht pompös, aber ein deutliches Zeichen: Dieses Tier ist jemandem sehr am Herzen."},"ICON-1670":{"nm":"Tiergesundheitskarte","de":"Hat er heute gut gefressen? Tut ihm etwas weh? Den Tag des Mitbewohners Zeile für Zeile auf einer Karte festhalten. Wenn das Befinden des stummen Gefährten schriftlich dokumentiert ist, wird auch das Herz des Pflegenden ruhiger und umsichtiger."},"ICON-1671":{"nm":"Schlafkissen-Schonbezug","de":"Das Lieblingsküssen bekommt ein frisches, weiches Kleid. Zieht man den alten, zerknautschten Bezug ab, strömt der Duft sonnengetrockneter Watte heraus. Den am häufigsten genutzten Platz am saubersten zu halten ist die tägliche Sorgfalt für unseren Mitbewohner."},"ICON-1672":{"nm":"Kleiner Zaun-Steckstab","de":"Am Rand des Blumenbeets steckt man kleine Stäbchen ein und zieht so einen niedrigen Zaun. Kein Verbot – sondern eine freundliche Grenze, die sagt: bis hierher ist Blumenraum. Wer eine klare Linie hat, kann dahinter unbesorgt wachsen."},"ICON-1673":{"nm":"Vertrauens-Leckerlibüchse","de":"Selbst das schüchternste Tier spitzt die Ohren, wenn man diese Büchse rasselt. Darin wartet eine Handvoll Leckerlis, die das Herz öffnen. Nähe entsteht schneller durch kleine Versprechen als durch Worte – und das Klappern kommt als erstes entgegen."},"ICON-1674":{"nm":"Gassi-Aufzeichnungs-Tag","de":"Welchen Weg sind wir heute wie weit gegangen? Die Aufzeichnung knüpft sich wie ein Knoten um den Tag. Aus Fußspuren wird eine Karte, aus Karten werden Erinnerungen. Alle gemeinsamen Tage stapeln sich sorgfältig in diesem kleinen Anhänger."},"ICON-1675":{"nm":"Vogelfutterschälchen","de":"Stellt man eine Schale auf die Fensterbank und legt ein paar Hirsekörner hinein, landen bald unbekannte Gäste einer nach dem anderen. Leises Picken, flatterndes Gefieder. Eine kleine Aufmerksamkeit, die jeden Morgen ein kleines Konzert bringt."},"ICON-1676":{"nm":"Eichhörnchen-Beobachtungsdose","de":"Durch die transparente Dose trifft man auf die runden Augen eines Eichhörnchens. Mit vollen Backentaschen voller Eicheln schaut es verwundert. Mit dem Versprechen, es gleich wieder freizulassen, tauscht man einen kurzen Gruß mit der kleinen Wildnis."},"ICON-1677":{"nm":"Gipsabdruck-Form für Tierpfoten","de":"Weichen Gips eingießen und einen kleinen Abdruck nehmen. Während er aushärtet, hält auch die Zeit im Garten kurz inne. Den kleinen Pfotenabdruck, der mit dem Wachsen verschwinden wird, hebt die weiße Form wie für die Ewigkeit auf und legt ihn behutsam in die Hände."},"ICON-1678":{"nm":"Nachtsicht-Objektivkappe","de":"Auf das Objektiv, das in die Nacht geblickt hat, kommt ein kleines Käppchen. So wartet das Glas, das Sterne und Nester geschaut hat, staubfrei auf die nächste Nacht. Auch ein Auge, das die Dunkelheit scharf sieht, braucht tagsüber eine Pause."},"ICON-1679":{"nm":"Nistschutz-Markierung","de":"Entdeckt man ein Nest zwischen den Ästen, stellt man statt näherzugehen eine Markierung auf. „Hier lebt eine Vogelfamilie, bitte leise.“ Der respektvolle Abstand – nicht zu nahe, aber nah genug zum Beobachten – schützt das Nest am besten."},"ICON-1680":{"nm":"Tierstimmen-Aufnahmechip","de":"Das Zwitschern im Gebüsch, das Singen unter dem Dachvorsprung, das Zirpen der Nachtinsekten – nicht einsperren, sondern kurz borgen. Spielt man die Aufnahme ab, erwacht auch die Luft jenes Augenblicks wieder. Damit kein Klang, der einmal war, verloren geht."},"ICON-1681":{"nm":"Beobachtungsfernglas-Abdeckung","de":"Kurz bevor ein Vogel aufsteigt, hält der Wald den Atem an. Ein Stück Stoff, das in diesem Moment der Stille das Objektiv schützt, bewahrt die Schärfe für ferne Dinge, ohne dass ein einziger Fingerabdruck bleibt."},"ICON-1682":{"nm":"Waldweg-Kameragurt","de":"Beim Erklimmen steiler Waldpfade berührt die Kamera immer wieder die Brust. Herzpochen und Verschlussgeräusch schwingen im gleichen Rhythmus, und dieser eine Riemen hält all diese Momente fest ans Herz gedrückt."},"ICON-1683":{"nm":"Naturerklärungskarte","de":"Auch ein einzelnes Kraut hat einen Namen, erklärt die Karte leise. Wenn das Unbemerkte einen Namen bekommt, füllt sich der Waldweg plötzlich mit vertrauten Gesichtern."},"ICON-1684":{"nm":"Mast-Reparaturflicken","de":"Auch das Segel, das den Wind mit ganzem Körper aufnimmt, trägt Narben davon. Ein kleines Stück Stoff, das die gerissene Stelle still abdichtet, gibt dem Segel wieder das Recht, die hohe See zu suchen."},"ICON-1685":{"nm":"Tauknotenbrett","de":"Rauf, runter, noch einmal umschlingen – die Hände kennen diese Reihenfolge auswendig und machen daraus einen Knoten. In einer Nacht, in der der Sturm das Deck peitscht, hält genau dieser Ablauf Mensch und Schiff zusammen."},"ICON-1686":{"nm":"Ankerketten-Schutzklappe","de":"Unterschätze diese kleine Kappe am Ende der Eisenkette nicht. Weil Rost im Verborgenen wächst, verlängert eine Kappe, die dem Seewind trotzt, still die Lebensdauer des Ankers."},"ICON-1687":{"nm":"Kursmarkierungs-Wimpel","de":"An Tagen, an denen dichter Nebel alles auslöscht, spricht ein einziger Wimpel für den Weg. Ein farbiger Fleck, der im Wind weht, löst endlich die versteiften Schultern des irrenden Steuermanns."},"ICON-1688":{"nm":"Kajüten-Schlüsselring","de":"Auf dem schwankenden Meer hängt ein kleiner Ring an der Tür der engen Kajüte. Solange der Schlüssel an seinem Platz ist, wartet eine Kammer immer auf dich – unverschlossen nur für dich."},"ICON-1689":{"nm":"Wasserdichtes Kartencase","de":"Im Regen löscht die Papierkarte den Weg vor der Reise. Während eine einzige Karte im transparenten Case trocken durchhält, verliert auch die nasse Fahrt am Ende nicht die Richtung."},"ICON-1690":{"nm":"Schiffslampen-Docht","de":"Das Öl, das der Docht langsam aufsaugt, entfacht sich schließlich zur Flamme. Ein einziger Lichtpunkt auf dem Deck – und in seinem kleinen Flackern rückt die weite Dunkelheit des Nachtmeers ein Stück näher."},"ICON-1691":{"nm":"Notsignaltuch","de":"Dort, wo die Stimme nicht mehr hinreicht, trägt eine hoch geschwungene rote Flagge die Botschaft weiter. Dieses eine Tuch schneidet durch den Wind und ruft für einen: Hier lebt noch jemand."},"ICON-1692":{"nm":"Seewind-Richtungsnadel","de":"Wer weiß, woher der Wind weht, bestimmt den Kurs. Die Richtung, auf die eine kleine Nadel still zeigt, trägt das Schicksal der heutigen Fahrt ein Stück weit mit."},"ICON-1693":{"nm":"Klappschaufel-Schutzhülle","de":"Klappt man die Klinge ein und deckt sie ab, darf auch die fleißige Schaufel kurz verschnaufen. Die letzte Handlung nach dem Ausschaufeln ist, die Schneide für morgen zu schonen – das ist Fürsorge für das Werkzeug."},"ICON-1694":{"nm":"Kompass-Etui","de":"Die Nadel zeigt immer ohne Zögern nach Norden, doch was sie schützt, ist das robuste Etui. Wer sich einmal verlaufen hat, hütet seine Richtung umso sorgsamer."},"ICON-1695":{"nm":"Campinggeschirr-Trockennetz","de":"Das gespülte Geschirr hängt man ins Netz und trocknet es im Morgensonnenschein. Der Tag am Lagerplatz beginnt mit dem Geräusch abtropfenden Wassers – und genau diese Kleinigkeit füllt das Innere des Zelts mit Geborgenheit."},"ICON-1696":{"nm":"Campingerlaubnis-Karte","de":"Die Erlaubnis, eine Nacht in diesem Wald zu verbringen. In dem Augenblick, in dem das Blatt Papier in die Hand gleitet, wird auch der fremde Wald kurz zum eigenen – und nimmt das kleine Zelt still auf."},"ICON-1697":{"nm":"Erkundungspfad-Wimpelschnur","de":"Bindet man an jeder Abzweigung einen Wimpel, verliert der Rückweg sich auch in der Dunkelheit nicht. Das kleine Zeichen des Vorausgehenden schiebt den nachfolgenden Schritten sacht den Rücken."},"ICON-1698":{"nm":"Wasserdichte Streichholzdose","de":"Ein einziger Tropfen genügt, und das Streichholz schweigt für immer. In einer hermetisch versiegelten Dose wartet das Feuer trocken auf die kälteste Nacht. Wärme hält sich still bereit."},"ICON-1699":{"nm":"Tragbarer Wasserfilter","de":"Auch trübes Wasser wird nach dem Durchlaufen dieses Filters klar. Ein kleines Gerät, das den Zweifel vor dem Durst beiseiteschiebt – denn der Glaube, trinken zu können, ist selbst schon eine Erquickung."},"ICON-1700":{"nm":"Notfalldecken-Pack","de":"Zusammengefaltet handtellergroß, aufgefaltet Wärme für einen Menschen. Damit das Wort Notfall etwas leichter wiegt, wartet die Decke in einer Ecke des Rucksacks jederzeit darauf, zu wärmen."},"ICON-1701":{"nm":"Nachtmarkierungs-Armband","de":"Wenn Dunkelheit über den Bergpfad fällt, leuchtet ein Handgelenk still. Das schmale Band, das die Standorte der anderen anzeigt, verbindet die Gehenden unsichtbar und freundlich miteinander."},"ICON-1702":{"nm":"Berghelm-Sticker","de":"Der Sticker auf dem Helm ist das zweite Namensschild des Bergmanns. Tief im Stollen, wo selbst das Licht knapp ist, erkennt man den Kameraden freudig an dem kleinen Bild im Lampenschein."},"ICON-1703":{"nm":"Erzader-Markierungsnadel","de":"An der Stelle, wo die Erzader gefunden wurde, steckt man leise eine Nadel. Ein einziger Punkt, der in der Dunkelheit glänzt, sagt dem Nächsten: Hier anfangen zu graben."},"ICON-1704":{"nm":"Rissbreitenmesser","de":"Den Riss in der Wand zu messen ist langsame, geduldige Arbeit. Hat er sich seit gestern um einen Spalt verbreitert? Die kleine Zahl, die das Lineal angibt, greift dem Einsturz vor, bevor er geschieht."},"ICON-1705":{"nm":"Reliefmuster-Abklatschpapier","de":"Man legt das Papier auf das in Stein gemeißelte Muster und tupft behutsam Tusche darauf. In dem Moment, in dem die Handschrift vor tausend Jahren auftaucht, setzt sich die vergangene Zeit kurz gegenüber."},"ICON-1706":{"nm":"Antike Münzen-Etui","de":"Dieses kleine Metallstück, das sorgfältig vor Rost bewahrt schlummert, trägt die letzte Stimme eines verschwundenen Landes in sich. In einer ganzen Münze steckt eine Epoche – und altert langsam im transparenten Etui."},"ICON-1707":{"nm":"Kristall-Aufsteller","de":"Auch ein Kristall, der Licht in sich birgt, braucht einen Halt. Sobald er auf den kleinen Ständer gesetzt wird, entfaltet das zerbrechliche Stück endlich sein ganzes Leuchten."},"ICON-1708":{"nm":"Höhlenkarten-Fragment","de":"Eine zerrissene Karte zeigt nur die Hälfte eines Geheimnisses. Bis das andere Stück gefunden ist, verbirgt dieses eine Blatt irgendwo in der Höhle den Rest des Weges halbverdeckt."},"ICON-1709":{"nm":"Abseilring","de":"Wer den Körper über den Abgrund hinuntergibt, muss zuerst diesem Ring vollständig vertrauen. Sein ganzes Gewicht auf kaltes Eisen legen – Vertrauen ist von Natur aus etwas so Schweres."},"ICON-1710":{"nm":"Ausgrabungsgenehmigung","de":"Ein Blatt mit dem deutlichen Stempel, dass man graben darf. Bevor man das Vergrabene weckt, hole man sich zuerst die Erlaubnis – Ausgrabungen beginnen mit einer Lektion in Höflichkeit."},"ICON-1711":{"nm":"Windschutz-Pack","de":"Entfaltet man ihn mit dem Rücken zum Wind, entsteht mitten auf dem stürmischen Feld ein Fleck Stille. Diese eine Schicht schützt eine kleine Flamme und lässt einen erschöpften Menschen kurz ausruhen."},"ICON-1712":{"nm":"Sandsturm-Brillenabdeckung","de":"Auch wenn Sand heftig wirbelt, muss das Sichtfeld bis zuletzt gehalten werden. Eine dünne Schutzfolie über der Brille gibt den Mut, auch mitten im Sturm die Augen offen zu halten und weiterzugehen."},"ICON-1713":{"nm":"Regenbesuchs-Abtropfschale","de":"An den Schuhspitzen des angereisten Gastes tropft Regenwasser. Eine Schale, die still vor der Tür steht, nimmt die nassen, kalt gewordenen Füße wortlos und wärmend auf."},"ICON-1714":{"nm":"Hitzewellen-Kühlanhänger","de":"Ein kleiner Anhänger, der die Mittagshitze sanft dämpft. Am Rucksack befestigt bewahrt er Kühle, und wenn sich Schweißperlen bilden, reicht er einen Hauch Schatten weiter."},"ICON-1715":{"nm":"Kälteschutz-Wärmegürtel","de":"Ein warmer Gürtel, einmal um die Taille gelegt. Wenn die Wärme der Handwärmer über Rücken und Lenden streicht, wird auch das schneidende Winterfeld ein wenig erträglicher."},"ICON-1716":{"nm":"Feuchtigkeitssaugbeutel","de":"Feuchtigkeit zernagt Dinge lautlos. Während ein kleiner Beutel in der Schachtel schweigend Nässe aufsaugt, bleiben all die Lieblingsstücke trocken und in Form."},"ICON-1717":{"nm":"Schuhüberzug für Schlamm","de":"Manchmal muss man durch den Matsch, ohne dass die Schuhe schmutzig werden. Diese dünne Hülle, die den Dreck abhält, macht den Schritt über die Türschwelle nach Hause ein Stück leichter."},"ICON-1718":{"nm":"Seesucht-Lampenabdeckung","de":"Wenn Meeresnebel versucht, das Lampenlicht zu verschlucken, sammelt diese Abdeckung die verschwimmenden Strahlen behutsam. Selbst im grauen Morgengrauen bleibt das Licht des Hafens am Ende brennen."},"ICON-1719":{"nm":"Blitzwarnnadel","de":"Ziehen dunkle Wolken tief heran, gibt eine Nadel als erste die Warnung. Den Körper tief zu halten, bevor der Blitz schlägt – Demut vor der Natur lernt man am besten im Voraus."},"ICON-1720":{"nm":"Rezeptbuch-Lesezeichen","de":"Ein kleines Lesezeichen, das man zwischen die aufgeschlagene Seite des Kochbuchs schiebt. Wenn man mitten im Kochen am Herd eine Zeile sucht, erwacht auch der Handgeschmack der Mutter auf genau dieser Seite mit."},"ICON-1721":{"nm":"Gewürz-Portionierstab","de":"Mama sagte immer nur „eine Prise“. Unmöglich, das genau zu treffen – und doch hat ihr Handgeschmack nie geschwankt. Misst man mit diesem Stäbchen das Salz ab, merkt man: Was länger als jedes Maß gereift ist, war keine Schätzung, sondern Liebe."},"ICON-1722":{"nm":"Fermentationsdeckel-Band","de":"Weißt du, dass auch ein Tonkrug atmet? Schmiegt sich dieses Band um den Deckel, beginnen Innen und Außen langsam miteinander zu sprechen. Erst nach ein paar ungeeilten Tagen bekommt das Warten schließlich den Namen Geschmack."},"ICON-1723":{"nm":"Reifungs-Etikettierschip","de":"Ein kleiner Chip, auf dem das Einlegedatum sorgfältig notiert ist. Die Schrift verblasst, doch der Inhalt wird tiefer. Irgendwann unerwartet wieder herausholen – Reifung ist ein solches Versprechen, das man hält."},"ICON-1724":{"nm":"Brüheseiher","de":"Klare Brühe entsteht erst nach wiederholtem Durchseihen. Das Netz, das das Feste zurückhält und nur das Reine durchlässt, flüstert eine alte Küchenweisheit in die Fingerspitzen: Im Weglassen sammelt sich Tiefe."},"ICON-1725":{"nm":"Teig-Gärtuch","de":"Ein Tuch wird behutsam über den Teig gelegt. In der Dunkelheit darunter arbeitet die Hefe fleißig und lässt den Teig aufgehen – und man lernt zum ersten Mal die Güte jener Dinge kennen, die unsichtbar wachsen."},"ICON-1726":{"nm":"Zutaten-Vorbereitungsnadel","de":"Eine kleine Nadel, die die Struktur des Frühlingszwiebels teilt und den Knoblauch fest hält. Vorbereiten ist wie eine erste Begrüßung an die Zutaten – so sorgfältig zugerichtet leuchtet der Abendtisch eine Spur heller."},"ICON-1727":{"nm":"Anrichte-Pinzette","de":"Wo das letzte Stück auf dem Teller landet, entscheidet am Ende diese Pinzette. In dem kurzen Zögern, in dem die geübte Hand in der Luft innehält, wird aus einer Mahlzeit leise ein kleines Bild."},"ICON-1728":{"nm":"Warmhaltebox-Abdeckung","de":"Die an der Schultür überreichte Brotdose musste bis zur Mittagsglocke warm bleiben. Die Wärme, die in dieser Hülle eingeschlossen ist, kühlt so wenig aus wie das Herz desjenigen, der seit dem frühen Morgen am Herd stand."},"ICON-1729":{"nm":"Essenseinladungskarte","de":"„Komm doch mal zu uns zum Essen.“ Gibt es etwas Herzlicheres? Ganz ohne große Verabredungen einfach am selben Tisch sitzen – diese älteste Einladung der koreanischen Sprache steckt in dieser einen Karte."},"ICON-1730":{"nm":"Tischreservierungs-Chip","de":"Namen aufschreiben, Platz reservieren. Während ein kleiner Chip den leeren Tisch für eine Weile für jemanden festhält, nähert sich die vereinbarte Stunde leise wie ein Fußschritt."},"ICON-1731":{"nm":"Degustationskarte","de":"Einen Bissen nehmen und dann mit ernstem Gesicht die Sterne vergeben. Die ehrliche Zeile, die auf dieser Karte sorgfältig notiert wird, ist der wärmste Nörgel, der den nächsten Teller noch besser macht."},"ICON-1732":{"nm":"Brotdosen-Dankesband","de":"Um die sauber geleerte Brotdose wird ein Band gebunden und sie zurückgeschickt. Auch wer nie ein Dankeschön in Worte fassen konnte – dieser Knoten überbringt das ungesagte Gefühl stellvertretend."},"ICON-1733":{"nm":"Allergen-Kennzeichnungs-Tag","de":"Dieser kleine Anhänger schützt still den Tisch von jemandem. Was alles enthalten ist, deutlich anzugeben ist ein anderer Name für jene Gastfreundschaft, die auch an unsichtbare Bedürfnisse denkt."},"ICON-1734":{"nm":"Geschmackserinnerungs-Löffel","de":"Was lange auf der Zunge bleibt, war eigentlich die Stimmung jenes Tages. Weil ein einziger Löffel auf Anhieb in die Küche der Kindheit zurückführt, scheint es, als ob Erinnerungen nicht im Magen, sondern im Herzen aufbewahrt werden."},"ICON-1735":{"nm":"Tagesmenü-Token","de":"Was esse ich heute bloß – die schwerste Frage der Welt, gegen die wir jedes Mal verlieren. Wirft man diesen Token um und überlässt dem Schicksal die Menüwahl, ist man danach überraschenderweise erleichtert und gut gelaunt."},"ICON-1736":{"nm":"Gemeinschaftstisch-Glocke","de":"Klingelt die Glocke einmal, strömen die Familienmitglieder aus ihren Zimmern an einen Tisch. Dieses Glockensignal über dem runden Tisch ist die herzlichste Übersetzung von: „Es ist fertig, kommt alle her.“"},"ICON-1737":{"nm":"Dessert-Reihenfolge-Karte","de":"Das Süße kommt immer ganz zuletzt – wer das beschlossen hat, weiß niemand, doch diese Karte hält das Versprechen. Sie ist die kleine, freundliche Moderatorin des Tisches, die den Höhepunkt des Gaumens bis zum letzten Happen aufhebt."},"ICON-1738":{"nm":"Preisverhandlungs-Token","de":"Mitten auf dem Markt prallen „Geben Sie mir etwas nach“ und „Ich mache schon Verlust“ freundschaftlich aufeinander. Dieser Token ist die Quittung eines alten Stammkunden, der den Handel am Ende immer mit einem Lachen abschließt."},"ICON-1739":{"nm":"Bestandsprüfungs-Nadel","de":"Die Lagerregale stillschreitend nach leeren Stellen absuchen und eine Nadel hineinstecken. Zu wissen, was noch da ist und was ausging – das große Werk des Haushaltens beginnt immer mit dieser kleinen Bestandsaufnahme."},"ICON-1740":{"nm":"Ladentheken-Reinigungsbürste","de":"Nach Marktschluss legt sich das Geräusch, die leere Theke abzubürsten, tief in den Laden. In den Händen, die den Platz für morgen schon heute sauber machen, steckt der Fleiß, der einen Tag sorgfältig zu Ende bringt."},"ICON-1741":{"nm":"Tagesempfehlungskarte","de":"„Das hier ist heute gut.“ Eine Karte, die der Inhaber lässig hinreicht. In dieser Empfehlung, die die zögernde Hand des Kunden sachte anschubst, steckt ein ganzer Tag voll Stolz auf das eigene Angebot."},"ICON-1742":{"nm":"Stammkunden-Stempelhalter","de":"Zehn Stempel voll, und einmal ist es umsonst. Dieser Halter, in dem die Stempel sich Reihe für Reihe füllen, ist das andere Gesicht des Wortes Stammkunde – wer öfter kommt, mag es eben einfach."},"ICON-1743":{"nm":"Tauschbuch-Klammer","de":"Eine Klammer, die die Aufzeichnungen aller ausgetauschten und zurückgegebenen Dinge bündelt. Je mehr hin- und hergegangen ist, desto dicker das Heft – und so dick wie das Heft ist auch das Vertrauen, das mit den Nachbarn aufgebaut wurde."},"ICON-1744":{"nm":"Verkauft-Schild","de":"In dem Moment, in dem das letzte Stück dieses Schild bekommt, erfüllt sich das Herz seltsam. Ein kurzes „Auf Wiedersehen“ an eine Ware, die zum Esstisch von jemandem und in eine Zimmerecke irgendwo aufbricht."},"ICON-1745":{"nm":"Reservierungskorb","de":"Mit deinem Namensschild hütet ein Korb ein Regalfach. Dieser eine reservierte Platz sagt dem Eintretenden leise: „Ich habe die ganze Zeit auf dich gewartet.“"},"ICON-1746":{"nm":"Verpackungstisch-Matte","de":"Die Matte auf dem Packtisch ist die Bühne geschäftiger Hände. Während Papier gefaltet und Schnur ordentlich gebunden wird, verwandelt sich eine gewöhnliche Sache in der kurzen Zeit stillschweigend in das Geschenk von jemandem."},"ICON-1747":{"nm":"Besuchsversprechen-Zettel","de":"„Ich komme morgen vorbei.“ Ein kurzer Satz, in den Türspalt geschoben. Auch wenn man sich nicht persönlich sehen konnte, reist das Versprechen auf einem Blatt Papier voraus und wartet geduldig."},"ICON-1748":{"nm":"Nachbarschafts-Geschenkkorb","de":"In den Korb, der über den Zaun gereicht wird, legt man immer die Erklärung „Ich hatte so viel davon.“ Koreas Herzenswärme kommt genau so – großzügig und unschuldig tuend – leise herübergeschwappt."},"ICON-1749":{"nm":"Dorfnachrichtenkasten","de":"Große und kleine Neuigkeiten des Dorfes stapeln sich in diesem Kasten. Wer neu eingezogen ist, wer ein Fest gibt – ein paar Blätter zusammen übermitteln den ruhigen Herzschlag der Nachbarschaft."},"ICON-1750":{"nm":"Dankesbesuchs-Stempel","de":"Die Dankbarkeit, dass jemand vorbeigeschaut hat, drückt man mit einem kräftigen Stempelabdruck aus. Die Tintenspur, die sich ins Papier frisst, bleibt länger als das Wort „Ich werde es nicht vergessen.“"},"ICON-1751":{"nm":"Freundlichkeits-Dankeskarte","de":"Eine Karte, auf der man die Freundlichkeit, die jemand einem erwiesen hat, niederschreibt und sie zurückgibt. In einem Dorf, das kleine Herzlichkeiten der Mühe des Aufschreibens für wert hält, kommt Gutes immer wieder und wieder zurück."},"ICON-1752":{"nm":"Entschuldigungsbrief-Siegel","de":"Wie ein Apfel, der gut gereift ist, lässt sich auch ein Entschuldigungswort erst nach ausreichendem Reifen übergeben. Dieses Siegel, fest auf den Umschlag gedrückt, ist der Abdruck des Muts, der das lange ungesagte Entschuldigung am Ende durchgehalten hat."},"ICON-1753":{"nm":"Gemeinschaftsarbeits-Tabelle","de":"Eine Tabelle, in der aufgeschrieben steht, wer was übernimmt. Selbst die schwerste Arbeit wird leichter, wenn die Namen geteilt werden – das weiß, wer einmal Schulter an Schulter gearbeitet hat."},"ICON-1754":{"nm":"Nachbarschaftsvorlieben-Band","de":"Was dem Nachbarn gefällt, wird still mit farbigen Bändern markiert. Sich die Vorlieben von jemandem zu merken ist das leiseste Geständnis, dass man diese Person mag."},"ICON-1755":{"nm":"Einladungs-Türhakenring","de":"Ein Ring am Türschild kündigt an: „Heute empfange ich Gäste.“ Obwohl das Zeichen handflächengroß ist, hängt darin ein weit geöffnetes Herz, das bereit ist, jemanden zu empfangen."},"ICON-1756":{"nm":"Festival-Einlassarmband","de":"Ein verblasstes Band, das man tagelang nicht abnehmen mochte. Das Fest begann erst wirklich in dem Moment, als es ums Handgelenk geschlossen wurde. Darin schläft ein Tag, der vergangen ist und doch nie ganz aufgehört hat."},"ICON-1757":{"nm":"Feuerwerk-Tickethalter","de":"Kurz bevor der Nachthimmel aufbricht, hält dieser Halter das Ticket und mit ihm das Herzklopfen fest umschlossen. Das Versprechen, das man schweißnass in der Handfläche hält, wartet auf den ersten Knall, das erste aufblühende Licht."},"ICON-1758":{"nm":"Mondbetrachtungs-Schälchen","de":"Es gab Nächte, in denen man den Vollmond scheinbar in eine Schüssel schöpfte. Legt man frische Früchte und Reiskuchen hübsch auf dieses Schälchen und verbeugt sich vor dem Mond, reicht ein rundes Herz bis ans Ende des Himmels."},"ICON-1759":{"nm":"Winterfest-Handschuhnadel","de":"Selbst wenn die Hände im Schnee steif werden, rutschen die Handschuhe ständig über das Handgelenk. Erst wenn diese Nadel fest am Ärmelaufschlag sitzt, kann man auf dem Winterfest endlich nach Herzenslust umhertollen."},"ICON-1760":{"nm":"Frühlingsgrußkarte mit Samen","de":"Ein paar Samenkörner schlummern in der Karte und warten auf ihren Frühling. Wenn man sie in die Erde bettet und sie wie versprochen keimen sieht, scheint es, als käme jeder Anfang von einem kleinen, festen Punkt."},"ICON-1761":{"nm":"Sommerstrand-Stempel","de":"Die Welle drückt ihren Stempel in den Sand und zieht sich wieder zurück. Ein kleines Zeichen, das hinterlassen wird, obwohl man weiß, dass es bald verwischt: Hier war jemand. Der Sommer prägt sich jedes Mal deutlich ein und fließt dann mit dem Salzgeruch davon."},"ICON-1762":{"nm":"Herbsternte-Band","de":"Die Hände, die die Körner gebunden haben, knüpfen am Ende ein schönes Band. Ein Knoten, der die Mühe eines ganzen Jahres sorgsam einschließt. Auch wenn das Feld leer wird, verabschiedet sich der Herbst noch einmal in den schönsten Farben wie ein Abendrot."},"ICON-1763":{"nm":"Erinnerungsfoto-Sprechblase","de":"„Danke, dass du so weit zu mir gekommen bist.“ Der Gruß, den man nicht laut sagen konnte, bläht sich rund auf dem Papier auf. Ein rundes Herzstück, das dem eingefrorenen Schweigen im Foto sanft eine Stimme leiht."},"ICON-1764":{"nm":"Festivalgelände-Kartennadel","de":"Jemand hat diese Markierung gesteckt, damit man sich auf dem weitläufigen Platz nicht verläuft. Auch wenn die Klänge des Festumzugs die Füße vorausrennen lassen – diese Nadel bringt das Verirrte still an den vereinbarten Ort."},"ICON-1765":{"nm":"Album-Generalschlüssel","de":"Was hinter dem Schloss ist, ist kein Tonträger – es ist die darin versiegelte Zeit. Das Zittern der ersten Aufnahme, die Nacht des letzten Abmischens. Dreht man den Schlüssel langsam, öffnet sich knarrend die Tür zu dem Raum, den nur der Schöpfer kennt."},"ICON-1766":{"nm":"Tracklist-Karte","de":"Die Reihenfolge der Lieder auf einer Karte ist eigentlich die Reihenfolge der Gefühle. Wo man aufwühlen, wo man den Atem anhalten wird – das Papier weiß es schon längst. Die Aufregung, die sich vor dem ersten Ton aufbaut."},"ICON-1767":{"nm":"Audioproof-Tag","de":"Nur wer dieselbe Stelle an die hundert Mal zurückgespult hat, bringt diesen Tag an. „Noch einmal, nur noch ein einziges Mal.“ Neben dem Freigabestempel verbirgt sich die Nacht von jemandem, der bis in den Morgen hinein seinen eigenen Ohren nicht traute."},"ICON-1768":{"nm":"Vorbestellungs-Etikett","de":"Das Versprechen, auf etwas zu warten, das noch gar nicht auf der Welt ist. Im Moment, in dem das Etikett aufgeklebt wird, wird ein leerer Platz still auf jemandes Namen reserviert. Auch sehnlichem Warten gibt es eine Wartenummer."},"ICON-1769":{"nm":"Erstauflage-Siegelsticker","de":"Er ähnelt der alten Geste, Hanfpapier über einen Krug zu legen und mit Kleister zu versiegeln. Ein Blatt, das verspricht, das Original so zu bewahren, wie es war. Weil man weiß, dass es beim Ablösen verschwinden wird, schaut man immer länger auf die ordentliche Naht."},"ICON-1770":{"nm":"Comeback-Kalenderchip","de":"Wenn im Kalender ein weiterer Kreis erscheint, wird die Zahl der verbleibenden Nächte bis zu jenem Tag um eins kürzer. Auf dem kleinen Chip in der Hand steht das Rückkehrdatum deutlich. Für wartende Menschen ist Zeit etwas, das man mit den Händen abzählt."},"ICON-1771":{"nm":"Konzeptfoto-Schutzhülle","de":"Bevor die Farben eines Konzepts von einem neuen verdrängt werden, schiebt man die Stimmung schützend in eine transparente Hülle. Damit die Farben vergangener Tage auch nach dem Jahreswechsel nicht vergessen gehen, werden sie mitsamt den Ecken sanft bewahrt."},"ICON-1772":{"nm":"Teaser-Enthüllungstoken","de":"Kurz bevor der Schleier gelüftet wird, ein kleines Münzchen in der Handfläche. Reicht man es hin, öffnet sich die erste verschlossene Szene der Welt gegenüber um einen Spalt. Enthüllen ist letztlich eine Frage, wer zuerst die Hand ausstreckt."},"ICON-1773":{"nm":"Plattenhalter","de":"Sobald ein niedriger Ständer das Album leicht anhebt, wird aus einer gewöhnlichen Scheibe der Star des Regals. Ein stiller Mitarbeiter im Hintergrund, der sicherstellt, dass das Licht aus dem schönsten Winkel fällt."},"ICON-1774":{"nm":"Debüt-Showcase-Pass","de":"Ein Ausweis, auf dem steht: „Wir zeigen es Ihnen zum ersten Mal.“ Den langen Korridor hinter der Bühne bis zum ersten Applaus des Saals – dieser Pass lässt die zitternde Schwelle des Debüts übertreten."},"ICON-1775":{"nm":"Erste-Bühne-Positions-Chip","de":"Mit der Zehenspitze ertastet man den Chip auf dem Boden. Ein Feld, das der Körper kennt, ohne hinzuschauen. In dem Moment, in dem man genau an der eingelernten Stelle landet, wird das Zittern in den Fingern zu einer klaren Bewegung."},"ICON-1776":{"nm":"Dankesrede-Karte","de":"„Das alles verdanke ich Ihnen“ – auch diese vertraute Phrase ist nicht mehr gewöhnlich, wenn sie in zitternder Handschrift steht. Ein paar Zeilen, die man aufschrieb, damit man in der Aufregung nicht vergisst. Aufrichtigkeit lehnt sich manchmal an eine Karte."},"ICON-1777":{"nm":"Profilaufnahme-Terminzettel","de":"Ein Blatt, auf dem der Tag, an dem man vor das Objektiv tritt, sorgfältig notiert ist. Ein Zeitplan, den besten Ausdruck in Ruhe vorzubereiten. Je mehr der Leere ausgefüllt wird, desto länger werden auch die Nächte vor dem Spiegel."},"ICON-1778":{"nm":"Fanclub-Beitrittsformular","de":"Ein Blatt, auf das man schüchtern Namen und Herz schreibt und es überreicht. „Ich mag dich“ ist immer schwer zu sagen, aber dieses Formular schreibt es stellvertretend klar und deutlich. Die erste Unterschrift für das Dabeisein."},"ICON-1779":{"nm":"Debütgeschenk-Prüfliste","de":"Jedes Teil einzeln abtasten, während man an die Person denkt, die es empfangen wird. Ist eine Ecke beschädigt? Fehlt ein Stück Herzlichkeit? Das Geschenk wird schon einmal geliebt, bevor es überreicht wird."},"ICON-1780":{"nm":"Bühnenfinale-Markierung","de":"Kurz bevor sich der Vorhang schließt, steht die Markierung an dem Ort, wo die letzte Pose verweilt. Sie kündigt kein Ende an, sondern schließt das Ende schön ab – ein kleiner Punkt. Nur ein gut beschlossener Vorhang öffnet das nächste Mal."},"ICON-1781":{"nm":"Interview-Wartestift","de":"Ein Stift, der die Stille hütet, kurz bevor die Fragen beginnen. In dem kurzen Schweigen, in dem man im Kopf nach der Antwort greift, sagt dieser kleine Anhänger stellvertretend freundlich: „Noch nicht, gleich.“"},"ICON-1782":{"nm":"Debüt-Erinnerungsumschlag","de":"Wie der alte Brauch, einem Aufbrechenden einen wertvollen Brief im Umschlag in die Hand zu drücken, bewahrt eine Lage die Aufzeichnungen des ersten Auftritts. Öffnet man ihn eines fernen Tages, strömt auch das Zittern von damals auf einmal heraus."},"ICON-1783":{"nm":"Gesangsstimm-Atemstrohhalm","de":"Durch das dünne Röhrchen den Atem lang und in einem Strahl ausstoßen üben. Singen ist am Ende wohldosierter Atem – das erinnert dieser kleine Strohhalm jeden Morgen leise. Erst der Wind, dann der Ton."},"ICON-1784":{"nm":"Rhythmustraining-Klickchip","de":"Tock, tock, tock – der ehrlichste Freund der Welt. Wird es zu schnell, bremst er; wird es zu langsam, schiebt er an. Den Rhythmus in den Körper einzuschreiben ist wie ein langes Gespräch mit diesem beharrlichen Chip."},"ICON-1785":{"nm":"Tanzlinie-Prüfband","de":"Mit einem Band erspürt man, wo die Finger halten und wo die Schultern aufgehen. Eine gut gezeichnete Tanzlinie ist gerade und ordentlich bis dorthin, wo kein Auge aus dem Zuschauerraum mehr hinschaut."},"ICON-1786":{"nm":"Mimik-Feedbackkarte","de":"Dass man auch das Lächeln lernen muss – dieser Satz hatte seine Richtigkeit. Auf einem Blatt sorgsam festgehalten: Winkel um die Augen, Höhe der Mundwinkel. Was der Spiegel nicht vermitteln konnte, erklärt diese Karte freundlich."},"ICON-1787":{"nm":"Rap-Flow-Notiz","de":"„Hier kurz pausieren, dort alles rauslassen“ – eine Notiz, die den Weg des Wortes vorauszeichnet. Je schneller der Abschnitt, desto klarer muss der Atemweg sein. In den hingeworfenen Pfeilen atmet der Rhythmus einer ganzen Strophe."},"ICON-1788":{"nm":"Stimmtemperatur-Sticker","de":"Auch die Stimme hat warme und kühle Tage. Ein kleiner Sticker, der die heutige Beschaffenheit in Farbe festhält. Wärmen und wieder abkühlen – jeden Morgen erwacht der Klang in einer etwas anderen Temperatur."},"ICON-1789":{"nm":"Ruheprogramm-Token","de":"Eine Münze, die man in die Hand bekommt mit dem Wort: Gut erholen ist auch Können. Zeigt man sie vor, darf man ohne schlechtes Gewissen kurz innehalten. Für jemanden, der ununterbrochen gelaufen ist, ist Stoppen die mutigste Wahl."},"ICON-1790":{"nm":"Wachstumsziel-Nadel","de":"Eine kleine Nadel, die gesetzt wird mit dem Satz: „Da wollen wir einmal hin.“ Auch wenn es weit weg scheint – man wächst jeden Tag einen Schritt in diese Richtung. Ein Ziel ist ein freundliches Versprechen, das von weit draußen winkt."},"ICON-1791":{"nm":"Wochenauswertungs-Umschlag","de":"Schweiß und Tränen einer Woche werden sorgsam in einen Umschlag gefüllt und übergeben. Darin stecken das Geglückte und das Bedauerte nebeneinander. Ihn zu öffnen ist eine kleine Aufgabe, die man dem nächsten Ich von sich stellt."},"ICON-1792":{"nm":"Bühnendeko-Ersatzteildose","de":"Hinter der glitzernden Bühne leben namenlose Teile. Eine Schraube, ein Ring – zusammen lassen sie die Sterne an der Decke schweben. Öffnet man die Dose, quillt der stille Fleiß hervor, der das Strahlende trägt."},"ICON-1793":{"nm":"Kostümkonzept-Board","de":"Stoff für Stoff, Farbe für Farbe aufkleben und ein Kleid anprobieren, das es noch nicht gibt. Das Bühnenkostüm, das sich auf dem Board zuerst vervollständigt. Die Fantasie geht dem Nähen immer einen Schritt voraus."},"ICON-1794":{"nm":"Farbanprobe-Chip","de":"Dasselbe Kleidungsstück zeigt je nach Licht ein völlig anderes Gesicht. Welche Farbe mit dieser Person am hellsten lächelt, findet man, indem man die Chips einen nach dem anderen vorhält. Stimmigkeit ist eine Entdeckung am Ende langen Vergleichens."},"ICON-1795":{"nm":"Schnürsenkel-Musterbrett","de":"Was jeden festen Schritt auf der Bühne trägt, ist überraschenderweise ein kleines Band. Nicht lösen, aber auch nicht beengen. Verschiedene Qualitäten nebeneinander auslegen und wählen – die fürsorglich-nachdenklichste Überlegung vom untersten Punkt aus."},"ICON-1796":{"nm":"Accessoire-Prüfumschlag","de":"Je glitzernder etwas ist, desto größer fällt ein einziger Kratzer ins Auge. Den Schmuck im Umschlag ins Licht halten und ihn aufmerksam begutachten. Das Herz, das die kleinen Dinge bis zuletzt unter die Lupe nimmt, hütet die Bühne."},"ICON-1797":{"nm":"Haarfarbe-Teststrähne","de":"Ein kleines Muster, das dem Haar eine neue Jahreszeit anprobiert. Die Farbe, die an einer Strähne sanft schimmert, gibt dem nächsten Konzept leise seinen ersten Eindruck. Veränderung beginnt immer auf einer handtellergroßen Fläche."},"ICON-1798":{"nm":"Nageldesign-Konzeptkarte","de":"Auf einem Blatt wird festgehalten, welches kleine Bild auf zehn Fingerspitzen gemalt werden soll. Damit sogar in einer Geste das Konzept dezent mitschwingt, wird bis ins kleinste Detail sorgfältig eine Geschichte aufgetragen."},"ICON-1799":{"nm":"Styling-Wechselkarte","de":"„Heute werde ich ein bisschen anders sein als gestern“ – eine Karte, die diesen einen Satz möglich macht. Ob Frisur, Kleidung oder Ausstrahlung – diese Karte öffnet die aufregende Tür zu einem neuen Ich."},"ICON-1800":{"nm":"Größenanpassungs-Tag","de":"Ein Tag, auf dem sorgfältig notiert ist, wo enger und wo weiter gemacht werden muss. Wie die alte Hand, die Kinderkleider Stich für Stich angepasst hat, macht diese kleine Korrektur die Bühne einen Spalt bequemer."},"ICON-1801":{"nm":"Thumbnail-Rohkarte","de":"Ein Blatt, das die Farbe noch nicht kennt. Über den groben Bleistiftlinien fragt man sich leise, wohin die nächste Szene führen wird. Das Aufregendste ist nie das Fertige, sondern immer diese unfertige erste Linie – so flüstert das stille Schnittzimmer."},"ICON-1802":{"nm":"Fotoerlaubnis-Aufkleber","de":"\"Darf ich dich festhalten?\" Statt Worten klebt man ein rundes Zeichen auf die Brust. Ein kleiner Aufkleber schließt ein herzliches Versprechen zwischen Kamera und Herz."},"ICON-1803":{"nm":"Fotowall-Positionsnadel","de":"Eine kleine Nadel, fest in eine Ecke der Wand gesteckt. Sie markiert im Voraus, wer wo stehen soll. Überall, wo eine Nadel steckt, hält ein Lächeln inne und wird zu einem einzigen Foto."},"ICON-1804":{"nm":"Bildauswahl-Chip","de":"Ein Finger, der aus Hunderten von Aufnahmen genau eine herausgreift. In dem Moment, wo dieser Chip fällt, haben alle beiseitegelassenen Ausdrücke für genau dieses eine Bild gelebt. Auswählen gleicht immer einem stillen Abschied."},"ICON-1805":{"nm":"Hinter-den-Kulissen-Umschlag","de":"Was hinter der Kamera geschah, ruht hier drin. Faltet man die Öffnung zu, schlafen Lachen, Versprecher und müdes Gähnen beieinander. Was man oft mehr schätzt als den fertigen Film, ist häufig das hier drinnen."},"ICON-1806":{"nm":"Schnittanfrage-Notiz","de":"\"Hier noch eine Sekunde mehr, die Musik etwas leiser.\" Ein Zettel voller roter Schrift. Die Sorgfalt von jemandem bringt den Atem des Videos um einen halben Takt ins Lot. Perfektion wächst auf solchen kleinen Handgriffen."},"ICON-1807":{"nm":"Upload-Planungszettel","de":"Ein kleines Etikett für das Video, das morgen früh um sieben Uhr von selbst in die Welt tritt. Selbst während alle schlafen, hält das Versprechen die Augen offen. Eine im Voraus aufgezogene Zeit versteht sich nicht auf Verspätung."},"ICON-1808":{"nm":"Thumbnail-Rahmencover","de":"Eine Hülle, die die schönste erste Szene umschließt. Die Kanten werden ordentlich geschlossen, damit kein Fingerabdruck, kein Staub sie berühren kann. Bis zum großen Moment wird der erste Eindruck so hübsch gehütet."},"ICON-1809":{"nm":"Videolänge-Chip","de":"Ein kleiner Chip, der abschätzt, wie viele Minuten das heutige Filmmaterial ausmacht. Länger bedeutet nicht besser, kürzer nicht leichter. Das Gespür für die richtige Länge ist der erste Knopf beim Schnitt."},"ICON-1810":{"nm":"Anfeuerungs-Prüfblatt","de":"Ein Blatt, das man nochmals durchsieht, bevor man aus voller Kehle ruft. Verschiebt sich auch nur ein Buchstabe, zerstieben tausende Stimmen. Hinter dem Jubel ist zuerst eine unsichtbare korrigierende Hand hindurchgegangen."},"ICON-1811":{"nm":"Fanart-Schutzfolie","de":"Ein Bild, das jemand die ganze Nacht gezeichnet hat. Man gibt ihm ein durchsichtiges Zuhause, damit es nicht knittern kann. Als wollte es sagen: Was aus dem Herzen gemalt ist, muss mit dem Herzen bewahrt werden – die Hülle hält es schweigend in den Armen."},"ICON-1812":{"nm":"Fanbriefe-Sortierschnur","de":"Eine Schnur, die den Stapel Briefe nach Absender ordentlich bündelt. In einem Knoten verbirgt sich ein Tag voller Sehnsucht. Die Hand, die keinen einzigen Brief verlieren möchte, auch wenn sie nicht antworten kann, ist hier."},"ICON-1813":{"nm":"Merchandise-Tauschzettel","de":"\"Hat jemand Lust zu tauschen?\" Ein Zettel, auf den man sein zitterndes Herz schreibt. Allein weil man dasselbe liebt, werden zwei Fremde für einen kurzen Moment zu Freunden."},"ICON-1814":{"nm":"Gemeinschafts-Sitzchip","de":"Ein Chip, der die Plätze für Menschen bestimmt, die alle dieselbe Farbe tragen. Wenn sich verstreute Herzen in einem Bereich versammeln, beginnt das Publikum wie ein riesiger Mensch zu singen."},"ICON-1815":{"nm":"Geburtstagsanzeigen-Quittung","de":"Ein Kassenbon, den man in der Hand hält, nachdem man Liebe auf eine Leuchttafel gebracht hat. Was neben dem Betrag nicht steht, ist der Einsatz einer schlaflosen Nacht. Dieser Zettel bleibt als einziger Beweis für Glückwünsche, die einem einzigen Menschen gelten."},"ICON-1816":{"nm":"Grußbuch-Cover","de":"Ein Einband, der ein Buch voller Handschriften verschiedener Menschen umschließt. Klappt man es auf, legen sich unterschiedlichste Schriftzüge mit einem gemeinsamen Herz übereinander. Außen schlicht, innen erfüllt von warmem Durcheinander."},"ICON-1817":{"nm":"Fanclub-Mitgliederpin","de":"Ein kleiner Pin, der nur an jene weitergegeben wird, die denselben Namen rufen. Im Moment des Ansteckens wird ein einzelnes Mögen zu einem Versprechen von vielen. Zugehörigkeit hat diese runde Form."},"ICON-1818":{"nm":"Online-Anfeuerungs-Token","de":"Ein Lichtpunkt, den weit entfernte Hände jenseits des Bildschirms schwingen. Der Abstand ist unermesslich, doch der Takt ist derselbe. Es ist das Zeugnis dafür, dass Unterstützung auch von einem unsichtbaren Platz aus zuverlässig ankommt."},"ICON-1819":{"nm":"Altes Schlüsselstück","de":"Ein Metallbruchstück mit ausgebrochenem Zahn. An welche Tür es einst gepasst hat, erinnert sich niemand mehr. Was länger überlebt als das Schloss selbst, ist immer die Hälfte eines solchen nutzlos gewordenen Schlüssels."},"ICON-1820":{"nm":"Geheimgang-Karte","de":"Ein vergilbtes Blatt, das einen hinter Efeu verborgenen Weg zeigt. Die Abkürzung kennt nur, wer weiß. Faltet man sie auf, verwandelt sich die vertraute Insel still in eine Bühne des Abenteuers."},"ICON-1821":{"nm":"Code-Entschlüsselungskarte","de":"Eine Karte, die durcheinandergewürfelte Buchstaben wieder an ihren Platz bringt. Passt eine Zeile zusammen, winkt das nächste Geheimnis. Auch das unlösbarste Knäuel fängt beim ersten Buchstaben an."},"ICON-1822":{"nm":"Versiegelungsbox-Schnur","de":"Eine Schnur, die alles fest zusammenhält, als solle nichts geöffnet werden. Nur wer sie geknüpft hat, weiß, was darin schläft. Der Wunsch aufzumachen und der Wunsch zu bewahren liegen in dieser einen Schnur nebeneinander gebunden."},"ICON-1823":{"nm":"Ruinen-Puzzle-Chip","de":"Ein kleines Bruchstück, das von einer alten Steinmauer gefallen ist. Setzt man es an die richtige Stelle, erwacht das Können von jemandem vor tausend Jahren unter den Fingern wieder. Zerstreutes zusammenzufügen bedeutet, die Zeit neu zu verbinden."},"ICON-1824":{"nm":"Insel-Sagen-Ausschnitt","de":"Ein Blatt, auf das jemand alte Geschichten, die auf der Insel umherwandern, von Hand abgeschrieben hat. Ob sie wahr sind oder nicht, ist nicht so wichtig. Was von Mund zu Mund gewandert ist, wird selbst zum Jahresring der Insel."},"ICON-1825":{"nm":"Versteckter Markierungsstein","de":"Ein Stein, der am Wegrand beiläufig zu liegen scheint. Nur dem kundigen Auge zeigt er leise die Richtung. Je tiefer ein Geheimnis vergraben sein soll, desto gewöhnlicher ist das Gesicht, das es trägt."},"ICON-1826":{"nm":"Rätsel-Umschlag","de":"Auf dem Umschlag steht kein einziges Wort. Dieser kurze Augenblick, kurz bevor man das Siegel bricht, ist der aufregendste. Bis die Antwort in der Hand liegt, lebt jede Möglichkeit noch im Umschlag."},"ICON-1827":{"nm":"Detektiv-Lupenkappe","de":"Eine kleine Kappe, die man ruhig über das Lupenglas stülpt. Wenn man gerade nicht hindurchschaut, lässt sie die Linse in Ruhe ausruhen. Dass man gut sehen muss, um gut zu hüten – das lernt ein Detektiv früh."},"ICON-1828":{"nm":"Insel-Rundbus-Ticket","de":"Ein Ticket für den Bus, der einmal rund um die Insel fährt. Die Endstation ist wieder der Ausgangspunkt. Auf einem Weg, der sich dreht und wieder zum Anfang kommt, sieht die Landschaft jedes Mal ein wenig anders aus."},"ICON-1829":{"nm":"Fahrradverleih-Tag","de":"Ein Schild, das am Lenker des geliehenen Fahrrads baumelt. Bis zur Rückgabe ist ein kleines Stück Freiheit erlaubt. Wenn die Zeit des Winddurchfahrens endet, nimmt dieses Schild das Versprechen still zurück."},"ICON-1830":{"nm":"Kleinfähren-Ticket","de":"Ein Ticket für eine kleine Fährüberfahrt. Auf einem schwankenden Deck rücken Insel und Insel näher zusammen. Das Überqueren des Wasserwegs bringt immer ein bisschen Vorfreude und ein bisschen Seekrankheit zugleich mit."},"ICON-1831":{"nm":"Karrenspeichen-Pin","de":"Ein Pin, der das Rad eines Karrens fest hält. Dieses kleine Stück Metall lässt eine schwere Last rollen. Oft ist es das unauffälligste Bauteil, das am meisten Gewicht still erträgt."},"ICON-1832":{"nm":"Seilbahn-Token","de":"Ein runder Token für die Seilbahn, die durch die Luft gleitet. Im Moment, wo die Füße den Boden verlassen, liegt die ganze Insel auf einmal im Blick. Je höher man aufsteigt, desto weiter wird die Aussicht."},"ICON-1833":{"nm":"Heißluftballon-Armband","de":"Ein Band, das man sich vor dem Einsteigen in den Korb ums Handgelenk legt. Wenn die Flamme sich bläht und der Boden weiter wird, wird auch das Herz leichter. Aufsteigen bedeutet, für einen Moment das Gewicht loszulassen."},"ICON-1834":{"nm":"Wassertaxi-Chip","de":"Ein kleiner Chip, um ein Taxi auf dem Wasser zu rufen. Streckt man die Hand aus, nähert sich ein Boot, das die Wellen teilt. Auch dort, wo kein Weg ist, einen zu bahnen – das ist am Ende der Mut dessen, der zuerst ruft."},"ICON-1835":{"nm":"Wanderweg-Eingangspass","de":"Ein Pass, den man am ersten Tor zum Berg überreicht bekommt. Von hier an bestimmen die Fußspitzen den Weg. Der Gipfel mag weit sein – doch nur wer das Eingangstor passiert hat, dem ist jene Aussicht versprochen."},"ICON-1836":{"nm":"Hafenschließfach-Schlüssel","de":"Ein kleiner Schlüssel für ein Schließfach am Kai. Man gibt das Gepäck ab und blickt mit leichten Händen aufs Meer. Einen Ort zu haben, wo man kurz loslassen kann, ist wie ein geliehener Mut, weit aufzubrechen."},"ICON-1837":{"nm":"Einmachglas-Deckel","de":"Ein Deckel, der die Säuerlichkeiten einsperrt. Fest verschlossen hält er die Sommergurke bis in den Winter knackig. Das Geheimnis, die Zeit zu überlisten, beginnt, wenn man genau weiß, wie man schließt."},"ICON-1838":{"nm":"Dörrgestell-Etikett","de":"Ein Namensschild für alles, was auf dem Gitter zum Trocknen ausgelegt wird. Notiert man, was wann aufgelegt wurde, bleibt das Warten geordnet. Auch für Sonne und Wind gilt: eine Reihenfolge ist nötig."},"ICON-1839":{"nm":"Räucherspan-Beutel","de":"Ein Beutel, in dem Holzspäne zum Räuchern aufbewahrt werden. Öffnet man ihn, begrüßt einen zuerst ein Geruch wie von einem Lagerfeuer. Der Geschmack, der durch Rauch tief wird, entfaltet sich nur langsam für denjenigen, der auf das Warten versteht."},"ICON-1840":{"nm":"Vorrats-Aufkleber","de":"Ein Aufkleber, den man auf den Krug klebt und ihm wünscht, das Jahr gut zu überstehen. Das Einlegedatum und die Sorgfalt stehen darauf geschrieben. An lange haltbaren Speisen hängt immer ein kleiner Zettel, der den Handgeschmack jenes Tages festhalten will."},"ICON-1841":{"nm":"Gärungs-Zeit-Tag","de":"Gärung vertraut keiner Uhr. Die Zeit wird nicht nach Minuten, sondern nach Duft gemessen. Wenn der säuerliche Geruch die Nasenspitze erreicht, nickt das Schildchen leise: \"Jetzt ist es so weit.\" Auch das Warten hat seine eigene Skala."},"ICON-1842":{"nm":"Kühlschrank-Ordnungspin","de":"Ein kleiner Ordnungshüter für das Kühlschrankfach. Gemüse nach oben, Beilagen nach unten, Gestriges in die Vorderreihe. Steckt man einen Pin, findet die Hand beim nächsten Öffnen der Tür von selbst den Weg."},"ICON-1843":{"nm":"Lunchbox-Wärmeband","de":"Mama wickelte ein Band um die Lunchbox. Damit die Wärme nicht flüchtet bis zur Mittagspause. Löst man das Band, liegt unter dem beschlagenen Deckel noch immer die morgendliche Sorgfalt warm und auf einen wartend."},"ICON-1844":{"nm":"Soßenreife-Flasche","de":"Eine gute Würze eilt nie. Es geht darum, Sojasoße und Knoblauch still Zeit zu geben, ineinander einzuziehen. Im Dunkel der Flasche wird der Geschmack langsam tiefer, und die geduldige Weisheit des Gärtopfes zieht in das kleine Glas ein."},"ICON-1845":{"nm":"Saisonales Marmeladen-Etikett","de":"Im Frühling Erdbeere, im Sommer Aprikose, im Herbst Feige. Ein Etikett schreibt die Jahreszeit sorgfältig auf das Glas. Öffnet man den Deckel mitten im Winter, schmilzt das vergangene Sonnenlicht löffelweise langsam heraus."},"ICON-1846":{"nm":"Sammelquoten-Abzeichentafel","de":"Man muss nicht mühsam zählen, wie viele man gesammelt hat. Die Abzeichentafel prahlt an Stelle von einem. Jedes Mal, wenn eine Leerstelle gefüllt wird, reckt sich die Schulter – das sind keine Zahlen, sondern Spuren, mit den Fußspitzen hinterlassen."},"ICON-1847":{"nm":"Unentdeckter Slot-Karte","de":"Ein Platz, dem man noch nicht begegnet ist. Die Silhouette in der Karte macht nur verschwommen ein Versprechen. Leer zu sein bedeutet gleich gefüllt zu werden – und Vorfreude wartet immer in der Form eines Fragezeichens auf dich."},"ICON-1848":{"nm":"Sammelalbum-Abschlussstempel","de":"Das Geräusch, wenn der Stempel auf dem letzten Feld \"bum\" niederfällt. Klappt man das Album zu und streckt die Handfläche aus, klebt ein roter Tintenfleck darauf wie ein Orden der Vollständigkeit. Diese tiefe Befriedigung kennt nur, wer bis zum Schluss gesammelt hat."},"ICON-1849":{"nm":"Seltenheitsfarb-Chip","de":"Auch bei gleicher Form ändert sich die Geschichte, wenn die Farbe anders ist. Ein Chip zieht leise eine Linie zwischen dem Gewöhnlichen und dem Kostbaren. Das Auge eines Sammlers verweilt immer lange vor diesem feinen Farbunterschied."},"ICON-1850":{"nm":"Doppeltes-Sammelstück-Tauschgutschein","de":"Schon wieder dasselbe, zum dritten Mal. An dem Tag, als man es zum dritten Mal aufhob, streckte dieser Gutschein leise die Hand aus. Wie ein sanfter Trost, der sagt: Auch Doppeltes aufzuheben zahlt sich irgendwann aus."},"ICON-1851":{"nm":"Sammelbox-Nummernschildchen","de":"Versieht man jede Box mit einer Nummer, wird ein Lager zur kleinen Bibliothek. In Box 17 das im Frühling Gesammelte, in Box 23 das am Strand Gefundene. Ich bin ein stilles Inhaltsverzeichnis, das verstreute Erinnerungen Zeile für Zeile ordnet."},"ICON-1852":{"nm":"Ausstellungsplatzierungs-Guide","de":"Eine Ausstellung wird zur Hälfte durch den Platz gemacht. Großes nach hinten, Glänzendes in die Mitte. Folgt man dem Guide mit den Händen, hält das unordentliche Regal plötzlich inne und atmet ruhig wie ein kleines Museum."},"ICON-1853":{"nm":"Sammlerstück-Staubpinsel","de":"Je mehr man etwas schätzt, desto leichter setzt sich Staub darauf. Mit sanfter Pinselspitze wischt man auch das schlechte Gewissen, zu selten hingeschaut zu haben, mit fort. Während man putzt, glänzen auch die eingeschlafenen Erinnerungen kurz wieder auf."},"ICON-1854":{"nm":"Aufbewahrungskapazitäts-Erweiterungsgutschein","de":"Wenn das Sammeln zu eng wird, ist auch das eine glückliche Sorge. Das Regal um eine Etage zu erweitern und sich dabei ruhig zu erleichtern – das ist kein Geiz, sondern der Beweis, dass man so vieles liebt."},"ICON-1855":{"nm":"Freundeseinladungs-Codekarte","de":"Diesen Code weiterzugeben ist die herzlichste Einladung zum Mitspielen. Einige Ziffern, in denen ein Herz steckt – sobald der Freund seinen ersten Schritt auf die Insel setzt, beginnt die gemeinsame Geschichte."},"ICON-1856":{"nm":"Gemeinschaftslager-Schlüssel","de":"Das Lagertor öffnet sich nie allein. Erst wenn zwei Hände zusammenkommen, dreht sich das Schloss. In einem gemeinsam genutzten Raum hängt immer ein gemeinsam gehütetes Versprechen – in der Form eines Schlüssels."},"ICON-1857":{"nm":"Fundsachen-Melde-Tag","de":"Auch ein verlorener Gegenstand ist jemandem wichtig. \"Hier liegt es\" in eine Zeile zu schreiben und anzuhängen – das Schild verbindet ein kurz verirrtes Herz und seinen Besitzer wieder sanft miteinander."},"ICON-1858":{"nm":"Hilferuf-Fähnchen","de":"Um Hilfe zu bitten ist keine Schwäche, sondern Mut. Wenn die Fahne steigt, eilt von irgendwo jemand herbei. Was sich auf dieser Insel am schnellsten verbreitet, ist keine Nachricht, sondern eine ausgestreckte Hand."},"ICON-1859":{"nm":"Notfallkontakt-Armband","de":"Ein kleines Gefühl von Sicherheit am Handgelenk. Was auch immer passiert – die Nummer hier kommt schneller als jeder andere. Ein stiller Begleiter, den man im Alltag vergisst und ausgerechnet im entscheidenden Moment am stärksten spürt."},"ICON-1860":{"nm":"Aufgabenteilungs-Chip","de":"Wer einkauft und wer kocht – teilt man die Chips auf, gibt es keinen Streit. Der erste Schritt, gemeinsam etwas herzustellen, beginnt damit, jedem seinen Anteil herzlich zuzuweisen."},"ICON-1861":{"nm":"Gemeinschaftsprojekt-Bogen","de":"Was man allein nie gewagt hätte, wird zu mehreren wie durch Zauberhand möglich. Je mehr Namen den Bogen füllen, desto weniger Lücken bleiben und desto mehr Lachen wächst. Zusammenarbeit gedeiht still zwischen den Feldern."},"ICON-1862":{"nm":"Besuchsbenimmkarte","de":"Betritt man das Haus eines anderen, werden die Fußspitzen vorsichtiger. Auf der Karte stehen keine großen Regeln, nur kleine, warme Versprechen wie: \"Schuhe ordentlich, zuerst grüßen\"."},"ICON-1863":{"nm":"Partyauflösungs-Glocke","de":"Auch Freude braucht ein Ende, damit das nächste Mal erwartet werden kann. Wenn die Glocke \"bimm\" tönt, packen alle mit bedauernden Gesichtern ihre Sachen zusammen. Eine Party, die gut Abschied nehmen kann, bleibt am längsten im Herzen."},"ICON-1864":{"nm":"Matratzenkanten-Band","de":"Egal wie glatt man das Laken streckt, die Ecken lösen sich unweigerlich. Dank des Bands, das alle vier Ecken fest hält, wacht man jeden Morgen in einem Bett auf, das so ordentlich ist wie ein Hotelzimmer."},"ICON-1865":{"nm":"Bettdecken-Knopfschnur","de":"Ich bin die Knopfschnur, die den Deckenrand der Bettdecke hält. Auch wenn man die ganze Nacht wälzt, lasse ich den Rand nicht entwischen. Eine Bettdecke ohne eine einzige Falte nach dem Aufwachen – das ist der Lohn meiner nächtlichen Schicht."},"ICON-1866":{"nm":"Topper-Fixierclip","de":"Der Topper schleicht sich bei jeder Gelegenheit weg. Jedes Mal klemmt der Clip die Ecke fest und hält die Stellung. Ein stiller Dickschädel, der an unsichtbarer Stelle die Schlafunterlage an ihrem Platz bewacht."},"ICON-1867":{"nm":"Laken-Glätter","de":"Die feinen Falten im Laken, die über Nacht entstehen, ähneln seltsam den Knitterfalten im Herzen. Streicht man einmal mit dem Glätter darüber, glättet sich der Stoff – wenn sich auch der verknitterte Tag so schön bügeln ließe."},"ICON-1868":{"nm":"Matratzenlüftungs-Unterlage","de":"Auch eine Matratze braucht Raum zum Atmen. Öffnet die Unterlage von unten einen Luftkanal, entweicht die Feuchtigkeit und Frische zieht ein. Guter Schlaf beginnt still in der Luft, die den Rücken trägt."},"ICON-1869":{"nm":"Bettdeckenbezug-Reißverschluss-Abdeckung","de":"Der nächtliche Kampf, wenn das Inlett beim Wechsel des Bezugs immer wieder herausquillt. Deckt man den Reißverschluss mit einer Abdeckung zu, wacht man nicht mehr auf, weil man nachts dagegen getreten ist. Ein kleines Stückchen Stoff bringt großen Frieden."},"ICON-1870":{"nm":"Füllungs-Anti-Klumpen-Pad","de":"Kissenfüllung sammelt sich irgendwann auf einer Seite und bildet einen kleinen Hügel. Stemmt sich das Pad dazwischen und hält dagegen, bleibt die Gleichmäßigkeit bis zum Schluss. Jeden Abend kehrt so das fluffige Neue unfehlbar zurück."},"ICON-1871":{"nm":"Bettlaken-Spannring","de":"Das Laken hat die Tendenz, sich langsam von einer Seite zu lösen. Befestigt man die Ecken mit dem Ring straff, hält es die ganze Nacht durch Wälzen stand. Straffe Spannung wird so still zur Grundlage für erholsamen Schlaf."},"ICON-1872":{"nm":"Kissenbezugwechsel-Tag","de":"Hat man heute den Kissenbezug gewaschen oder nicht – wenn man sich plötzlich unsicher ist, gibt das Schildchen eine klare Antwort. Was man beim Schlafen immer wieder vergisst, hält dieses kleine Zeichen gewissenhaft fest."},"ICON-1873":{"nm":"Traumtagebuch-Lesezeichen","de":"Den Traum, der beim Aufwachen zwischen den Fingern zerrinnt, hält das Lesezeichen auf der aufgeschlagenen Seite fest. Schlägt man es auf, ist das Meer von gestern Nacht noch da, der Himmel auch – eine kleine Brücke, sanft zwischen Schlaf und Text gelegt."},"ICON-1874":{"nm":"Weißes-Rauschen-Kieselstein","de":"Eine zu stille Nacht weckt manchmal eher auf. Lässt der Kieselstein ein sanftes Geräusch wie Regen los, sinkt das Herz langsam mit diesem Klang in sich. Ein kleiner Stein, der die Stille sachte beruhigt."},"ICON-1875":{"nm":"Temperatur-Schlaf-Chip","de":"Ob die Stirn im Schlaf heiß ist oder die Fußspitzen kalt – der Chip beobachtet es still nebenan. Dank des nächtlichen Wächters, der leise die passende Temperatur sucht, fließt der Schlaf bis zum frühen Morgen ungestört."},"ICON-1876":{"nm":"Verdunkelungsvorhang-Klemme","de":"Der Morgensonnenstrahl ist so fleißig, dass er sich immer durch den Vorhangspalt drängt. Klemmt man beide Enden zu, wird das Zimmer wieder mitternächtlich schwarz. Ein treuer Komplize für einen langen Ausschlafmorgen."},"ICON-1877":{"nm":"Mondlicht-Projektor-Stehlampe","de":"Schaltet man das Licht aus, geht am Himmel über einem der Mond auf. Das sanfte Licht des Strahlers verwandelt das Zimmer in einen kleinen Nachthimmel. Den Moment, in dem man einst unter dem Mond einschlief, stellt man so ans Kopfende."},"ICON-1878":{"nm":"Schlafduft-Säckchen-Haken","de":"Ein Säckchen voller Lavendel und Wiesenduft schaukelt leise am Kopfende hin und her. Mit dem Duft, der durch die Nase zieht, entspannen sich die Schultern, und das Duftsäckchen bittet noch vor dem Kissen um Einschlafen."},"ICON-1879":{"nm":"Schlaflieder-Spieluhr-Pin","de":"Dreht man das Uhrwerk behutsam auf, entfaltet sich eine kleine Melodie. Das Schlaflied, das an der Pinspitze herausdreht, ähnelt haargenau dem Takt, in dem die Großmutter einst den Rücken klopfte. Note für Note macht es die Augenlider langsam schwer."},"ICON-1880":{"nm":"Luftfeuchtigkeits-Pflanzentasse","de":"Ich bin eine Tasse, in der Pflanzen statt in Erde in klarem Wasser großgezogen werden. Schaut man auf die winzigen Wurzeln, die im Wasser treiben, wird sogar die Zimmerluft ein wenig feuchter. Ein kleiner grüner Brunnen auf dem Schreibtisch."},"ICON-1881":{"nm":"Traumfragment-Sammelfläschchen","de":"Der Traum, der im Halbschlaf entweicht, hat keine Form und fließt beim Aufwachen zwischen den Fingern hindurch. Den versinkenden Splitter mit einem Flaschenverschluss abzufangen und bis zum Morgen zu bewahren – das Verlangen zu erinnern beginnt an solch kleinen Orten."},"ICON-1882":{"nm":"Nachttisch-Brillentablett","de":"In dem Moment, wo man die Brille ablegt, gleitet merkwürdigerweise auch die ganze Tageserschöpfung mit hinunter. Dieser kleine Platz am Kopfende ist genau dafür da, diese eine Geste aufzunehmen. Das Tablett, das die Welt vor dem Schlafengehen leise unscharf werden lässt."},"ICON-1883":{"nm":"Nachttisch-Untersetzerring","de":"Der runde Rand, den ein Wasserglas hinterlässt, sieht winzig aus, wird aber zur Macke in der Holzmaserung des Nachttisches. Der kleine Ring, der das verhindert. Fürsorge wirkt immer still an diesen unsichtbaren Stellen."},"ICON-1884":{"nm":"Bettdecken-Falthilfe","de":"Auch ein ordentlich gefaltetes Bett hat sein Muster. Richtet man die Ecken mit diesem Werkzeug aus, glätten sich dabei auch die Gedanken ein wenig. Ein aufgeräumter Platz ist die schlichteste Begrüßung für einen neuen Tag."},"ICON-1885":{"nm":"Ladekabel-Kopfenden-Haken","de":"Weil es lästig war, dass das Ladekabel jede Nacht zu Boden glitt, hängt es jetzt am Haken am Kopfende. Während man schläft, sammelt es still Energie, und morgens wartet es vollgeladen in der Hand."},"ICON-1886":{"nm":"Kopfenden-Snackkörbchen","de":"Ein Körbchen mit Lieblingssnacks in greifbarer Nähe. Eine herzliche Vorkehrung für den abendlichen kleinen Hunger, der kommen wird. Das Rascheln einer Tüte, die man im Dunkeln greift, hat etwas wohltuend Vertrautes."},"ICON-1887":{"nm":"Einschlaf-Bücherregal-Flügel","de":"Ein Flügel, der die aufgeschlagene Buchseite hält, damit man nicht die Zeile verliert, wenn die Schläfrigkeit kommt. Die letzte Seite, kurz vor dem Schließen der Augen aufgeschlagen, wartet morgen Nacht an derselben Stelle auf dich."},"ICON-1888":{"nm":"Nachttisch-Wecker-Steinuntersatz","de":"Auch der Wecker, der den Morgen ruft, braucht einen sicheren Stand. Der runde Steinuntersatz nimmt sein Gewicht schwer auf, damit er selbst im frühen Morgengrauen nicht verrutscht – wie ein Versprechen, das bleibt."},"ICON-1889":{"nm":"Schlafmaske-Wandhaken","de":"Ein Haken, an dem die Schlafmaske, die die ganze Nacht das Licht abgehalten hat, tagsüber Luft schöpft. Dem Tuch, das seinen Dienst getan hat, einen trockenen Platz zu geben – kleine Fürsorge schleicht sich so unbemerkt ein."},"ICON-1890":{"nm":"Kopfenden-Taschenlampen-Clip","de":"Ein Clip, der das kleine Licht, das man mitten in der Nacht braucht, in die gewünschte Richtung hält. Hängt man die Taschenlampe an den Bettrand, entspannt sich die Hand, die sonst im Dunkeln tastete. Ein Clip, der die Richtung des Lichts bestimmt."},"ICON-1891":{"nm":"Trennvorhang-Ringkette","de":"Eine Ringkette, die den Vorhang hält, der einen Gemeinschaftsraum abtrennt. Auch wenn es nur ein dünnes Stück Stoff ist – dahinter liegt jemandes private Nacht. Eine herzliche Grenzlinie, die in einem gemeinsam bewohnten Zimmer den Schlaf des anderen schützt."},"ICON-1892":{"nm":"Gemeinschaftssteckdosen-Verteiler-Brett","de":"Ein Holzbrett, das die einzige Steckdose für viele nutzbar macht. Es teilt den Strom gleichmäßig auf, damit niemandes Nacht dunkel wird. Zusammen zu leben beginnt letztendlich damit, so Kleines wie das zu teilen."},"ICON-1893":{"nm":"Lichthelligkeits-Rücksichtsstein","de":"Wenn das Licht zu hell ist, reicht man statt Worten leise diesen Stein herüber. \"Kannst du ein bisschen dimmen?\" – das sagt dieses kleine Ding stellvertretend. Die sanfteste Bitte in einem gemeinsam bewohnten Zimmer."},"ICON-1894":{"nm":"Aufstehzeit-Rücksichts-Token","de":"Ein kleines Zeichen, das man demjenigen übergibt, der als Erster aufsteht. Ohne Streit regelt dieser Token, wer früh wacht und wer noch kurz weiterschläft. Ein Herz, das die Reihenfolge des Nachgebens mit den Fingerspitzen festlegt."},"ICON-1895":{"nm":"Gemeinschaftskleiderhaken-Nummernring","de":"Nummerierte Ringe an den gemeinsam genutzten Kleiderhaken. Eine kleine Zahl sagt leise, wessen Platz welcher ist, damit es keine Verwechslung gibt. Eine herzliche Linie, die im leicht durcheinander geratenden Alltag Ordnung schafft."},"ICON-1896":{"nm":"Etagenbett-Leitersprossen-Kappe","de":"Eine Kappe, die auf die Sprossen der Leiter zum Oberbett gestülpt wird. Damit selbst bloße Füße nicht frieren und nicht ausrutschen, schützt sie eine Stufe. Diese kleine Fürsorge am Ende der Leiter trägt den Traum im Oberstock sicher."},"ICON-1897":{"nm":"Gemeinschafts-Toilettenpapierhalter-Arm","de":"Ein armförmiger Halter für das Toilettenpapier im gemeinsamen Bad. So aufgehängt, kann jeder mit einer Hand bequem eine Lage abreißen. Auch wenn es banal klingt – er verbindet die Morgen von vielen fließend miteinander."},"ICON-1898":{"nm":"Lufterfrischer-Turnus-Chip","de":"Ein Chip, auf dem der Turnus steht, wer den Lufterfrischer auffüllt. Ein Versprechen, auch für einen Hauch Duft gemeinsam Verantwortung zu tragen. Angenehmer Geruch entsteht nicht von selbst – er blüht an der Reihe von jemandem."},"ICON-1899":{"nm":"Gemeinschafts-Schlaflicht-Griff","de":"Der Griff der Schlaflampe, die alle gemeinsam ein- und ausschalten. Die Hand, die am längsten wach blieb, löscht zuletzt das Licht. Ein stilles Versprechen der Menschen, die das sanfte Leuchten teilen."},"ICON-1900":{"nm":"Sofa-Armlehnen-Getränkehalter","de":"Eine runde Mulde in der Sofa-Armlehne, die das Glas aufnimmt. Auch wenn man das Glas kurz loslässt, muss man keine Angst vor dem Verschütten haben. Erst wenn ein Ruheplatz auch Platz für ein Glas hat, kann das Herz sich wirklich entspannen."},"ICON-1901":{"nm":"Kissen-Reißverschluss-Griff","de":"Ein kleiner Griff am Reißverschluss, mit dem man das Kisseninnere öffnet und schließt. Diese eine Schlaufe erspart das mühsame Wechseln des Inletts. Auch in die unsichtbare Innenseite fürsorglich hineinzudenken – in diesem Handgriff verbirgt sich die Herzlichkeit des Haushaltens."},"ICON-1902":{"nm":"Sofa-Rückenlehnen-Einlegekissen","de":"Ein Kissen, das den Spalt in der Rückenlehne füllt und den Rücken stützt. Auch bei längerem Sitzen tut der Rücken nicht weh, weil die Lücke gefüllt ist. Im Moment des Anlehnens erkennt der Körper sofort: \"Genau das war es.\""},"ICON-1903":{"nm":"Sitzkissen-Eckband","de":"Ein Band, das das Sitzkissen, das beim Hinsetzen immer wieder wegrutscht, an der Ecke festhält. Es fixiert es an einem Fleck, damit es nicht gleitet. Ordentlichkeit beginnt mit solch kleinem, hartnäckigem Festhalten."},"ICON-1904":{"nm":"Kissen-Naht-Schutzband","de":"An einem Kissen verschleißen immer zuerst die Ecknähte. Ein Schutzband, das diese Stellen im Voraus umhüllt und ein Aufplatzen verhindert. Der Wunsch, es lange bei sich zu behalten, ist so fest wie eine Naht."},"ICON-1905":{"nm":"Sofaspalt-Fernbedienungs-Tasche","de":"Die Fernbedienung, die immer wieder zwischen den Kissen verschwand, hat endlich ein eigenes Zuhause bekommen. Eine kleine Tasche, die man in den Sofaspalt steckt. Dass das, was man für verloren hielt, immer dort ist, ist beruhigender als man denkt."},"ICON-1906":{"nm":"Kniedecken-Rollschnur","de":"Eine Schnur, mit der man die Kniedecke aufrollt und zusammenbindet. Die Wärme, die sich beim Ausbreiten verflüchtigt, wird ordentlich für die nächste Nacht aufbewahrt. Wärme, so versorgt, lässt sich morgen wieder hervorholen und überdecken."},"ICON-1907":{"nm":"Fußablage-Abdeckknopf","de":"Ein Knopf, mit dem man den Bezug der am stärksten verschleißenden Fußablage leicht auswechseln kann. Dieser eine Handgriff verlängert das Leben des Stoffs. Der Wunsch, länger zu nutzen, hat an kleinen Stellen solche Zähigkeit."},"ICON-1908":{"nm":"Sofa-Bein-Rutschkappe","de":"Auch ein schweres Sofa darf den Boden nicht zerkratzen. Weiche Kappen, die über alle vier Beine gestülpt werden, schonen das Parkett behutsam. Ein Möbel, das bis in die Fußspitzen vorsichtig ist, hat irgendwie mehr Charme."},"ICON-1909":{"nm":"Fernbedienungs-Organizer","de":"Ein Ständer, der die Fernbedienungen, die überall herumkugelten, ordentlich nebeneinander aufstellt. Wenn lange und kurze Stäbe sich in einer Reihe aufgestellt haben, beruhigt sich allein schon dadurch die Stimmung im Zimmer um eine Note."},"ICON-1910":{"nm":"Gamepad-Ladehaken","de":"Ein Haken, an den man das Gamepad nach einer ausgelassenen Spielrunde zum Laden hängt. Während es hängend still Energie sammelt, ruhen auch die Hände kurz. Diese kleine Atempause bereitet die nächste Runde gründlich vor."},"ICON-1911":{"nm":"Brettspielfiguren-Beutel","de":"Ein kleiner Beutel, in dem die bunten Spielfiguren auf die nächste Runde warten. Die Stücke, die in einem Beutel aufeinandertreffen, klappern beim Schütteln. Bei diesem Geräusch erwacht das Verlangen nach \"noch einer Runde\" als Erstes."},"ICON-1912":{"nm":"Würfelwurf-Schale","de":"Eine eigene Schale nur zum Würfeln. Den Würfel, der gerne vom Tisch hüpfte und verschwand, hält der Rand darin gefangen. In dem kurzen Augenblick, wo er rollt und stoppt, halten alle gemeinsam den Atem an."},"ICON-1913":{"nm":"Kartendeck-Band","de":"Ein Band, das ein Kartenspiel zusammenhält, damit es nicht auseinanderfällt. Bis zum Mischen ist die Reihenfolge das Versprechen. Die Geste, das Band zu lösen und die Karten zu entfalten, gibt einer ganzen Runde erst den Anfang."},"ICON-1914":{"nm":"Konsolenkabel-Klemme","de":"Eine Klemme, die die hinter der Konsole verknäulten Kabel fasst und ordentlich nach unten kämmt. Sie räumt still das Durcheinander auf, das man kaum sieht. Ordentlichkeit vollendet sich immer so, leise hinter einem."},"ICON-1915":{"nm":"Punktestand-Drehscheibe","de":"Eine kleine Drehscheibe, auf der man den Punktestand anzeigt. Klick – wenn die Zahl eine Stelle weiterrückt, kommt der Jubel hinterher. Auch ohne im Kopf zu rechnen, merkt sich die Hand den heutigen Spielstand."},"ICON-1916":{"nm":"Spielbrett-Aufstellhalter","de":"Ein Halter, der das Spielbrett schräg aufstellt, damit alle Sitzenden auf einen Blick das Feld sehen. Niemand muss den Kopf recken; der Halter öffnet still eine faire Sicht für alle."},"ICON-1917":{"nm":"Spielreihenfolge-Zuglosbehälter","de":"Ein Behälter, in den man die Hand steckt und einen Stab zieht, um die Spielreihenfolge zu bestimmen. Der gezogene Stab entscheidet, wer anfängt. In diesem kurzen Moment des tastenden Greifens zittern alle gemeinsam im runden Behälter."},"ICON-1918":{"nm":"Snack-Teilungsteller mit Fächern","de":"Ein Fächerteller, auf dem Snacks nach Sorte aufgeteilt werden. Hat jeder sein Fach, stoßen keine Hände zusammen, und man kann seinen Lieblingssnack herausgreifen. In jedem Fach steckt die Fürsorge für denjenigen, mit dem man isst."},"ICON-1919":{"nm":"Teekannenwärmer","de":"Ein Wärmer, der die Schultern der Teekanne umhüllt und die Wärme bewahrt. Während der Tee langsam zieht, schützt er ihn vor dem Erkalten. Die Hand am Ende, die eine warme Tasse reicht, ist hier zu spüren."},"ICON-1920":{"nm":"Teebeutel-Ablage","de":"Ein Untersetzer, auf den man den ausgelaugten Teebeutel hebt und kurz rasten lässt. Bis zum letzten Tropfen auffangen, ohne zu kleckern. Auch dem Teeblatt, das seinen Dienst getan hat, einen ordentlichen Abschluss zu geben."},"ICON-1921":{"nm":"Gemeinschaftsbecher-Kennring","de":"Sechs identische Becher im Teepausenregal. Statt zu fragen, wessen welcher ist, steckt man bunte Ringe drauf. Ein kleines Zeichen verbindet sechs Menschen mit verschiedenem Geschmack still an demselben Tisch."},"ICON-1922":{"nm":"Popcorn-Teilungskörbchen","de":"Beim Herumreichen begrüßt einen der nussige Dampf als Erstes. Komischerweise wird umso mehr von etwas, je öfter man es weitergibt – und das ist das Herz des Abends, an dem man zusammensitzt und teilt."},"ICON-1923":{"nm":"Würfelzucker-Zangenbehälter","de":"Ein Würfelzucker, mit der Zange gepickt und sanft in die Teetasse fallen gelassen. Zuzuschauen, wie die weiße Ecke sich langsam auflöst und verschwindet – die Etikette des langsamen Süßens, die man einst am Teetisch der Großmutter gelernt hat."},"ICON-1924":{"nm":"Tablett-Antirutsch-Matte","de":"Auch wenn das Tablett sich neigt, bleibt das Glas an seinem Platz. Wie es immer bei denen ist, die schweigend festhalten – die Matte erträgt allein die Momente, in denen etwas fast gekippt wäre, und behält es für sich."},"ICON-1925":{"nm":"Getränkehalm-Aufstellbecher","de":"Hält man den Halm aufrecht, geraten weder Getränk noch Gedanken durcheinander. An einem Nachmittag, an dem schon diese schlichte Vertikalität den Schreibtisch ordentlich wirken lässt, trägt der Becher still die träge Zeit."},"ICON-1926":{"nm":"Kekskrümel-Auffangschale","de":"Knack – in dem Moment, in dem ein Keks abbricht, landen die Krümel hier. Auch die Spuren des allerbesten Bisses noch aufzunehmen – das ist das stille Finale am Tisch, herzlich bis zum letzten Brösel."},"ICON-1927":{"nm":"Fotoclip-Hängeschnur","de":"Polaroids, mit Clips auf eine quer gespannte Schnur geheftet wie Wäsche. Während die heutigen Lächeln im Wind leicht flattern und trocknen, wird eine Wandecke zum kleinen, hellen Ausstellungsraum der Erinnerungen."},"ICON-1928":{"nm":"Erinnerungs-Garnwickler","de":"Ein Garn, das entwirrt und ordentlich aufgewickelt wurde. An jedem Reißpunkt hat man einen Knoten gemacht und weitergeführt. Auch Erinnerungen, Runde für Runde langsam zurückgespult, entfalten eine Länge, die kürzer schien als sie war."},"ICON-1929":{"nm":"Wanddeko-Hakenabdeckung","de":"Eine kleine, runde Abdeckung, die den Nageleindruck verbirgt. Die kleine Narbe, die nach dem Abnehmen eines Gehängten zurückbleibt, wird ruhig überdeckt, und die Wand kehrt mit glattem Gesicht zurück, als wäre nichts gewesen."},"ICON-1930":{"nm":"Gruppenfoto-Einschubrahmen","de":"Ein Gruppenfoto, auf dem sechs Schultern dicht aneinandergedrückt sind. Im Moment des Einführens in den Rahmen werden das Lachen und die Wärme jenes Tages mit versiegelt. Ein Rahmen ist die stillste Hand, die einen flüchtigen Tag anhält."},"ICON-1931":{"nm":"Notizhalter-Korkplatte","de":"Eine braune Platte, dicht gespickt mit Reißzweckenlöchern. Termine, die nicht vergessen werden dürfen, Anfeuerungszettelchen von jemandem, heutige To-dos – alles steckt übereinander. Der zuverlässige Kamerad am Schreibtisch, der statt des Kopfes erinnert."},"ICON-1932":{"nm":"Kranz-Aufhänge-Knoten","de":"Auch an einem Türkranz hängt der Geschmack der Hände. Damit er in windigen Jahreszeiten nicht fällt, muss der Knoten fest sein. Die Herzlichkeit, die jemanden willkommen heißt, beginnt an unsichtbarer Stelle und wird fest."},"ICON-1933":{"nm":"Wanduhr-Pendelabdeckung","de":"Eine Stoffabdeckung, die das tickende Pendel schützt und Staub fernhält. Sogar das Zeitmessen wird so behütet. Bewahrt man es sachte, bleibt die Wanduhr noch ein bisschen länger an unserer Seite."},"ICON-1934":{"nm":"Sticker-Sammel-Steckplatte","de":"Die Sticker, die in jeder Schublade verstreut lagen, stehen jetzt in einer Reihe auf der Platte. Lieblingscharaktere, glitzernde Sterne, handgeschriebene Blätter. Wenn kleine Sammelfreuden ordentlich aufgereiht sind, wird auch das Herz gerade."},"ICON-1935":{"nm":"Dekorwimpel-Verbindungsschnur","de":"Eine Schnur, die bunte Wimpel in einer Reihe verbindet. Ob Geburtstag oder Willkommensfeier – in dem Moment, wo die Schnur die Decke quert, verwandelt sich das gewöhnliche Zimmer in ein Festhaus. Feiern bedeutet, gebrochene Herzen wieder zusammenzubinden."},"ICON-1936":{"nm":"Wasserkocher-Korkunterlage","de":"Ein Korkuntersetzer, der den heißen Boden des Wasserkochers aufnimmt. Er umfängt die Hitze allein, damit der Tisch sich nicht verbrennt. Eine stille Fürsorge, die das Zeichen von jemandes Wärme nicht zum Makel werden lässt."},"ICON-1937":{"nm":"Toaster-Krümelschublade","de":"Die Krümel, die das goldbraun geröstete Brot fallen lässt, kullern in die Schublade. Rausziehen, ausschütteln, fertig. Sie nimmt den turbulenten Morgen wortlos auf und bereitet die nächste Mahlzeit frisch vor."},"ICON-1938":{"nm":"Mikrowellen-Drehteller-Ring","de":"Auf dem sich drehenden Ring beschreibt der Teller langsam einen vollen Kreis. Diese Umdrehung, die gleichmäßiges Erhitzen gewährleistet, erweckt den erkalteten gestrigen Reis wieder als dampfende Mahlzeit."},"ICON-1939":{"nm":"Mini-Induktionskochfeld-Abdeckung","de":"Selbst wenn Öl nach allen Seiten spritzt, bleibt das Kochfeld immer sauber. Eine Abdeckung, die zwischen wilder Hitze und der Hand trennt. Was unsichtbar dagegenhält, bewahrt die Küche als einen Platz, an dem man sich nicht verbrennt."},"ICON-1940":{"nm":"Reiskocher-Dampfventilkappe","de":"Zisch – der Dampf entweicht. Dank der kleinen Kappe, die den Druck sanft ablässt, öffnet frisch gekochter Reis den Deckel mit dem weichsten Gesicht. Beim Ziehenlassen gibt es kein Drängen."},"ICON-1941":{"nm":"Kochkellen-Aufstellhalter","de":"Die Kochkelle nach dem Rühren senkrecht aufstellen. Ein kleines Herz, das keinen Flecken auf die Arbeitsfläche tropfen lassen möchte. Ordentlichkeit in der Küche beginnt immer an solch unscheinbarer, kleiner Stelle."},"ICON-1942":{"nm":"Topfgriff-Silikonaufsatz","de":"Stülpt man Silikon über den glühend heißen Topfgriff, verbrennt sich die Hand nicht. Eine einzige Schicht, die zwischen Hitze und Handfläche tritt. Sie schützt aus nächster Nähe denjenigen, der warmes Essen kocht."},"ICON-1943":{"nm":"Wasserkocher-Kalkfilter","de":"Auch im täglich aufgekochten Wasser sammeln sich langsam helle Rückstände. Ein feines Netz filtert den Kalk still heraus und lässt nur einen klaren Schluck durch. Eine fleißige Hand, die den ersten Schluck Tee von unsichtbarem Ort her schützt."},"ICON-1944":{"nm":"Kochtimer-Klemmfüßchen","de":"Ein Timer mit Klemmfüßchen, der sich fest an die Tischkante gebissen hat und nur noch drei Minuten wartet. Während die Nudeln kochen, hält er auf kleinen Beinen durch und zählt tick-tack den aufregendsten Moment des Tages mit."},"ICON-1945":{"nm":"Besteck-Abtropfbecher","de":"Vom gerade gespülten Besteck rinnen Wassertropfen herunter. Fängt der Becher die Feuchtigkeit ruhig auf, ist die Tischfläche im Nu trocken. Sauberkeit ist diese herzliche Fleißigkeit, die auch den letzten Tropfen beachtet."},"ICON-1946":{"nm":"Teller-Aufstelltrennsteg","de":"Teller werden senkrecht gestellt und durch Stege in Fächern getrennt. Schüsseln, die aufeinandergestapelt sich gegenseitig zerkratzten, bekommen nun jede ihr eigenes Fach. Ordnung bedeutet letztendlich, allen einen Platz zu geben, an dem sie nicht anstoßen."},"ICON-1947":{"nm":"Essstäbchen-Paar-Ring","de":"Ein Essstäbchen, das sein Paar verloren hat, wird mit einem Ring zusammengefädelt und wieder zu zweien gemacht. Ein einsames Stück verliert schnell seinen Sinn, also hält dieser kleine Ring die Ordnung in der Schublade."},"ICON-1948":{"nm":"Becherhalter-Astständer","de":"Ein Ständer, der sich wie Äste in viele Richtungen verzweigt, an dem man Becher einzeln aufhängt. Während die umgestülpten Gläser abtropfen, steht eine Ecke der Küche still wie ein kleiner, ordentlicher Baum da."},"ICON-1949":{"nm":"Besteckkorb-Traygriff","de":"Ein Tablett, in dem Löffel, Essstäbchen und Gabeln ordentlich nebeneinander liegen, mit einem Griff zum Herausheben. Greift man ihn und hebt alles auf einmal heraus, wird das Tischdecken leichter. Auch in der Schublade wohnt die Ästhetik der Ordnung."},"ICON-1950":{"nm":"Becher-Abtropfplatte","de":"Stellt man gespülte Becher umgestülpt darauf, tropft das Wasser tröpfelnd herunter. Während sie langsam in der Sonne am Fenster trocknen, gewinnt das Glas ruhig seine ursprüngliche Transparenz für den nächsten Schluck zurück."},"ICON-1951":{"nm":"Gabelzinken-Reinigungskamm","de":"Ein feiner Kamm, der Speisereste aus den Zinken der Gabel herausbürstet. Dank dieser sorgfältigen Pflege beginnt die nächste Mahlzeit stets mit einem makellos sauberen ersten Bissen."},"ICON-1952":{"nm":"Stapelschutz-Filz für Schüsseln","de":"Wenn Schüsseln aufeinandergestapelt werden, erzeugt Keramik auf Keramik ein scharfes Schleifen. Ein einziger Filzzwischenleger bannt dieses Reiben. Das Geheimnis langen gemeinsamen Gebrauchs liegt darin, einander ein wenig sanfter zu begegnen."},"ICON-1953":{"nm":"Teelöffel-Aufhängeschnur","de":"Das zierliche Teelöffelchen wird an einem Haken aufgehängt und an der Wand befestigt. Statt im Schubladenchaos zu versinken, glänzt es stets griffbereit an seinem Platz. Auch im Haushalt hat jedes Ding seinen richtigen Ort."},"ICON-1954":{"nm":"Kühlschrank-Facheinteilungs-Tablett","de":"Wer das Kühlschrankfach in Bereiche unterteilt, gibt jedem Lebensmittel ein kleines Zuhause. Was früher durcheinandergeriet und vergessen wurde, findet seinen Platz — und beim Öffnen der Tür ist auf einen Blick klar, was wo ist."},"ICON-1955":{"nm":"Gefrierklemmhalter für Zip-Beutel","de":"Einen halb vollen Gefrier-Zip-Beutel mit der Klemme aufrecht stellen: kein Umkippen, kein Verschütten, leichtes Wiederfinden. In der kalten Tiefkühltruhe steckt ein Funken kluger Haushaltsweisheit."},"ICON-1956":{"nm":"Flaschen-Festverschlusskappe","de":"Eine nicht richtig geschlossene Flasche verliert still und leise ihr Aroma. Ein einziger fester Dreh am Handgelenk hält Duft und Kohlensäure bis zum nächsten Morgen frisch. Tüchtigkeit zeigt sich im Kleinen."},"ICON-1957":{"nm":"Eierhalter-Rutschschutz","de":"Eine Einlage, die runde Eier davon abhält, zu rollen und zu zerbrechen, indem sie jedes in einem eigenen Fach hält. Die Fürsorge für das Zerbrechlichste findet still und herzlich an der Kühlschranktür ihren Platz."},"ICON-1958":{"nm":"Kühlschranktür-Facherweiterungsband","de":"Das Kühlschranktürfach lässt sich mit diesem Band seitlich ein wenig vergrößern, um ein weiteres Abteil zu schaffen. Wächst der Haushalt, muss der Platz mitwachsen. Im Geschick, Enges weit zu machen, spiegelt sich der kluge Sinn einer erfahrenen Haushaltshand."},"ICON-1959":{"nm":"Restessen-Andrückdeckel","de":"Ein Deckel, der sanft auf übrig gebliebene Beilagen gedrückt wird. Er hält sie feucht und schützt sie vor fremden Gerüchen. Wer fürsorglich wirtschaftet, bewahrt auch den letzten Rest einer Mahlzeit mit Bedacht."},"ICON-1960":{"nm":"Kaltluft-Lenkungsflügel","de":"Ein kleiner Flügel bestimmt leise, in welche Richtung die Kaltluft strömt. Wird der unsichtbare Luftweg mit einem Fingertipp leicht umgelenkt, reicht die Kühle bis in den hintersten Winkel."},"ICON-1961":{"nm":"Gemüsefach-Feuchtigkeitspad","de":"In der dunkelsten Ecke des Gemüsefachs nehme ich still Feuchtigkeit auf. Das kleine Wunder: welke Blätter vom gestrigen Tag sind morgens wieder knackig frisch. Auch wenn es niemand bemerkt — die Frische liegt stets in meiner Hand."},"ICON-1962":{"nm":"Getränkedosen-Rollstopper","de":"Unauffällig am Tischrand befestigt, hält er wegrollende Dosen auf. Beinahe verschüttetes Getränk, beinahe abgewischter Tisch. Sicherheit im Haushalt beginnt mit so einem unscheinbaren kleinen Stopper."},"ICON-1963":{"nm":"Schichtdienst-Drehscheibe","de":"Heute Abwaschen, heute Mülltrennen — ein Dreh am Pfeil, und der Streit löst sich im Kreis. In einem Haus, in dem fünf Menschen zusammenleben, ist eine geregelte Reihenfolge der freundlichste Friede."},"ICON-1964":{"nm":"Tassen-Trennband für Mitbewohner","de":"Fünf ähnliche Tassen, und am Morgen weiß niemand, welche seine ist. Ein farbiges Band am Rand macht aus 'Wessen ist das?' ein klares 'Das ist meins' — und bringt freundliche Ordnung auf den Frühstückstisch."},"ICON-1965":{"nm":"Portionsring für den Teller","de":"An geschäftigen Tagen ist die Markierung im Teller ein zuverlässiger Helfer. Eine Seite für Reis, eine für Beilagen. Weder zu wenig noch zu viel — eine stille, freundliche Linie, die sagt, wie viel man heute essen soll."},"ICON-1966":{"nm":"Snack-Teilungszange und -box","de":"Wer die ganze Tüte hinstellt, hinterlässt Fingerabdrücke und Verlegenheit. Wer mit einer Zange Stück für Stück herausreicht, gibt jedem den gleichen Anteil. Beim Teilen passt ein gutes Händchen besser als ein bloßes Zugreifen."},"ICON-1967":{"nm":"Wasserkessel-Diensthalter","de":"Das Wasserkochen lag immer bei denselben Händen. Seit die Namen abwechselnd am Halter neben dem Kessel hängen, ist eine warme Tasse Tee zur Zuneigung geworden, die reihum gereicht wird."},"ICON-1968":{"nm":"Lass-nichts-übrig-Wender-Chip","de":"Ein kleines Schildchen am Pfannenwender erinnert mit feiner Stimme: 'Bitte nichts liegenlassen.' Es klingt streng, aber es steckt kein Tadel darin — nur der alte Respekt vor einer Mahlzeit, der von früher an den Tisch geträufelt ist."},"ICON-1969":{"nm":"Persönliche Besteck-Beutelhalterung","de":"Das Besteck liegt nicht mehr kreuz und quer in der Schublade. Jedes Stück hat seinen eigenen Beutel und hängt an der Wand — fünf Haushaltsplätze stehen Seite an Seite in einer Reihe. Kleine Ordnung trägt den täglichen Frieden."},"ICON-1970":{"nm":"Sitzplatz-Korkchip für den Tisch","de":"Ein Korkstück auf dem Tisch zeigt, wer wo sitzt. Der vertraute Platz, das vertraute Gesicht daneben. Ein fester Sitzplatz ist der stillste Beweis dafür, dass man gemeinsam lebt."},"ICON-1971":{"nm":"Dienstschürzen-Rollhaken","de":"Die Schürze nach dem Abwaschen nicht einfach hinwerfen. Aufgerollt und am Haken befestigt, ist sie am nächsten Morgen frisch und griffbereit. In diesem kleinen Knoten lebt die Rücksicht auf den Nächsten."},"ICON-1972":{"nm":"Einweg-Hausschuhe Faltbeutel","de":"Wenn Gäste kommen, wird der Beutel aufgefaltet. Ordentlich verpackte Einwegpantoffeln begrüßen jeden neuen Fuß weich und herzlich. Gastfreundschaft beginnt immer still und leise an der Eingangstür."},"ICON-1973":{"nm":"Wattestäbchen-Papierschwänzchen-Tasche","de":"Wenn das Wattestäbchen verbraucht ist und nur noch das Papierröhrchen übrig bleibt, bewahre ich es sorgfältig auf. Auch dem Wegzuwerfenden einen Platz geben — das saubere Schreibtischgeheimnis liegt in solcher beiläufigen Achtsamkeit."},"ICON-1974":{"nm":"Nähkasten-Garnspulenbündel","de":"Die Garnspulen werden zusammengebunden, damit sich die Fäden nicht lösen und verwickeln. Ein gerissener Knopf, ein lockerer Ärmelabschluss — dieses eine Bündel macht alles im Nu wieder ganz. Stille Handnäherei, die entscheidende Abende rettet."},"ICON-1975":{"nm":"Einzelverpackte Seifenstücke","de":"Sorgfältig einzeln verpackte Seifenstücke liegen in jedem Gästezimmer bereit. Ein handflächengroßes Stück wäscht mit einer Handvoll Schaum den Staub des Tages fort. Sauberkeit beginnt immer im Kleinen."},"ICON-1976":{"nm":"Faltbare Duschhaube","de":"Zusammengefaltet passt sie in eine Handfläche, aufgeklappt schützt sie das ganze Haar. Damit die frisch frisierte Frisur unter der Dusche nicht in sich zusammenfällt. Diese eine dünne Schicht bewahrt die Ordentlichkeit des nächsten Morgens."},"ICON-1977":{"nm":"Zahnbürstenschutzkappen-Hülse","de":"Zahnbürstenborsten sind empfindlicher als man denkt. Eine Hülle, die ihre Spitze bedeckt, hält selbst im Tascheninneren den Staub fern. Das Unsichtbare schützen — das ist die eigentliche Aufgabe der Reisehygiene."},"ICON-1978":{"nm":"Wattepads-Einzeln-Zange","de":"Wattepads lassen sich am besten einzeln herausnehmen. Wer sie schüttet, verschwendet mehr als nötig. 'Eines nach dem anderen, mit Sorgfalt' — das ist die stille Regel auf dem Schminktisch."},"ICON-1979":{"nm":"Mini-Faltschuhlöffel","de":"Zusammengeklappt passt er in die Tasche, aufgeklappt schont er die Ferse. Er leistet mit kleinem Körper recht Großes. Auch am Morgen nach dem Verschlafen erlaubt er, Schuhe anzuziehen, ohne sie zu ruinieren — das war immer mein Verdienst."},"ICON-1980":{"nm":"Einzelportions-Zahnseidewickler","de":"Eine sorgfältig aufgewickelte Portion Zahnseide lässt sich bei Bedarf genau abzwacken. Der Wickler ist daumennagelgroß, aber bei der Pflege eines strahlenden Lächelns unverzichtbar. Auch ein Lächeln hat seine unsichtbare Vorbereitung."},"ICON-1981":{"nm":"Wasserkocher-Deckelgriff","de":"Damit man sich beim heißen Dampf des kochenden Wassers nicht die Hand verbrennt, steckt man mich auf den Deckel. Eine Handbreit zwischen Hitze und Handfläche. Diese kleine Distanz wärmt den Morgen eines geschäftigen Menschen sicher."},"ICON-1982":{"nm":"Bügeleisenständer aus Silikon","de":"Der gefährlichste Moment beim Bügeln ist die kurze Pause, in der man die Hand wegnimmt. Stellt man das Bügeleisen auf die Silikonplatte, verbrennt weder Tisch noch Kleidung. Erst auf der Unterlage ist das Faltenlätten wirklich abgeschlossen."},"ICON-1983":{"nm":"Diebstahlschutz-Kleiderbügelhaken","de":"Der Haken hält fest, was hängt, und lässt die Kleidung nicht einfach abrutschen. Ein kleiner Wächter neben dem geliebten Kleidungsstück im Schrank. Bewachen ist eine stille, bescheidene Angelegenheit."},"ICON-1984":{"nm":"Wasserkocher-Kalkfiltersieb","de":"Meine Aufgabe ist es, Kalkablagerungen, die im kochenden Wasser schweben, still herauszufiltern. Erst wenn selbst unsichtbare Rückstände gefiltert sind, wird eine Tasse Tee wirklich klar. Sorgfalt entsteht immer dort, wo niemand hinsieht."},"ICON-1985":{"nm":"Rutschfestes Kleiderbügel-Band","de":"Ein Kleiderbügel mit rutschfestem Band lässt selbst leichten Seidenstoff nicht abrutschen. Wer einmal ein zerknittertes Kleidungsstück vom Boden aufgehoben hat, weiß, wie wertvoll dieser dünne Streifen ist."},"ICON-1986":{"nm":"Bügelschnur-Ordnungsclip","de":"Ein locker liegendes Kabel kann jemanden zum Stolpern bringen. Ein einziger Handgriff mit dem Clip hält es ordentlich zusammen. Unfälle zu verhindern beginnt immer mit dieser kleinen, unauffälligen Ordnung."},"ICON-1987":{"nm":"Wasserkocher-Standfuß mit Topfschutznut","de":"Der Kessel wird sicher in die passende Nut des Standfußes gesetzt. An seinem Platz stehen bedeutet Sicherheit. Es hat seinen Grund, dass das warme Wasser jeden Morgen an derselben Stelle erhitzt wird."},"ICON-1988":{"nm":"Hosenbügel-Klemmbeine","de":"Wenn die Klemmbacken den Hosensaum fest greifen, entsteht keine einzige Bügelfalte. Eine gut gebügelte Hose wird von dem Moment an gepflegt, in dem sie am Bügel hängt. Der perfekte Sitz beginnt im Kleiderschrank."},"ICON-1989":{"nm":"Haartrockner-Wandhaken","de":"Lässt man den Fön irgendwo liegen, verwickelt das Kabel sich im Nu. Hängt man ihn am Haken auf, wird das Waschbecken großzügiger und der nächste Morgen leichter. Ein ordentlicher Platz lockert den geschäftigen Alltag ein wenig."},"ICON-1990":{"nm":"Minibar-Getränkeuntersetzer","de":"Stellt man den Untersetzer ruhig unter das Glas, läuft kein Wassertropfen auf den Tisch. Die Fürsorge eines einzigen Untersetzers hinterlässt keine Wasserränder. Sauberkeit ist Freundlichkeit, die keine Spuren hinterlässt."},"ICON-1991":{"nm":"Bitte-nicht-stören-Türhänger","de":"Ein Schild am Türknauf flüstert leise: 'Im Moment wird geruht.' Es wacht über einen wohlverdienten Mittagsschlaf nach einem langen Tag. Auch eine Ruhepause muss von jemandem sorgsam gehütet werden."},"ICON-1992":{"nm":"Zimmerservice-Knopfabdeckung","de":"Dank der Abdeckkappe wird der Knopf nicht versehentlich gedrückt, wenn ein Kleidungsstück dagegen streift. Er soll nur im echten Bedarfsfall klar und deutlich gerufen werden. Eine kleine Abdeckung macht das geschäftige Zimmer ein gutes Stück ordentlicher."},"ICON-1993":{"nm":"Minibar-Eiszange","de":"Eis mit bloßer Hand zu greifen ist kalt und rutschig. Die Zange übernimmt diese Arbeit tüchtig. In dem Moment, in dem ein kühles Getränk seinen Anfang nimmt, verbirgt sich eine unsichtbare helfende Hand."},"ICON-1994":{"nm":"Zimmer-Schlüsselkarten-Einschubschlitz","de":"Steckt man die Karte in den Schlitz, geht im Zimmer das Licht an. Ich bin nur ein kleiner Spalt — und doch bin ich die erste Geste, die einen Raum öffnet, in dem man die Erschöpfung eines ganzen Tages ablegen kann. Wo man hinkommt, geht das Licht wieder an."},"ICON-1995":{"nm":"Flaschenhals-Sicherheitsring","de":"Ist der Sicherheitsring am Flaschenhals noch intakt, bedeutet das: noch hat niemand diese Flasche berührt. Ein kleines Versprechen, das den ursprünglichen Zustand bezeugt. Vertrauen beginnt mit einem ungebrochenen Siegel."},"ICON-1996":{"nm":"Prospektständer-Aufsteller","de":"Stellt man den Prospekt leicht geneigt auf, bleibt jeder vorbeikommende Blick einen Moment daran hängen. Die bescheidene Haltung von Informationen, die darauf warten, aufgeschlagen zu werden. Wer sie gut sichtbar aufstellt, macht den Weg des anderen ein wenig leichter."},"ICON-1997":{"nm":"Minibar-Flaschenöffner-Chip","de":"In einer Ecke des flachen Chips versteckt sich unscheinbar eine Rille zum Öffnen von Kronkorken. Auch wenn er klein ist, erledigt er seine Aufgabe tadellos. Der erfrischende erste Schluck aus einer Flasche beginnt mit diesem kleinen Chip."},"ICON-1998":{"nm":"Beleuchtungsregler-Knaufabdeckung","de":"Dreht man langsam den umhüllten Knauf, verändert sich die Zimmerhelligkeit behutsam. Heller, dann gedämpfter. Das Licht für den Schlaf zu wählen ist ein Ritual, das den Tag liebevoll ausklingen lässt."},"ICON-1999":{"nm":"Koffer-Radstopper-Keil","de":"Schiebt man den Keil unter das Rad, rollt der Koffer nicht mehr unkontrolliert weg. Auch auf einer schrägen Bahnsteigplattform bleibt das Gepäck an Ort und Stelle. Das Sicherheitsgefühl auf Reisen wird durch diesen kleinen Keil gefestigt."},"ICON-2000":{"nm":"Reisegepäck-Faltpackbrett","de":"Legt man Kleidungsstücke auf das aufgeklappte Brett, werden Hemden wie Hosen sauber und knitterfrei gefaltet. Damit der Koffer nicht kollabiert und man im Zielort frisch und ordentlich auftreten kann. Gut gepacktes Gepäck erleichtert die Reise schon vor der Abfahrt."},"ICON-2001":{"nm":"Zimmersafe-Verschlussgriff","de":"Dreht man den Griff, gleitet der kleine Riegel ins Innere. Wertgegenstände anzuvertrauen bedeutet, für eine Nacht die Sorgen loszulassen. Das Schloss ist nicht Ausdruck von Angst, sondern ein anderer Name für Sicherheit und Geborgenheit."},"ICON-2002":{"nm":"Koffer-Griffhülle","de":"Auf jeder abgegriffenen Stelle ist ein Aufbruch eingraviert. Hält man diese abgenutzte Hülle in der Hand — die Strecke, die man gezogen hat — begreift man leise, dass Weggehen und Wiederkehren ein und dasselbe meinen."},"ICON-2003":{"nm":"Reise-Beutelklemme","de":"Hängt man den Beutel an der Waschbeckenkante auf, gewinnt das enge Hotelzimmer eine Handbreit mehr Platz. Was eine kleine Klemme mit der Ordnung im Koffer anstellt, wissen Hände, die schon weit gereist sind."},"ICON-2004":{"nm":"Ladekabel-Multi-Steckclip","de":"Mehrere Kabel an eine einzige Steckdose — eine kleine Hand, die die verstreuten Leitungen in der Nacht, während alles lädt, freundlich beieinanderhält."},"ICON-2005":{"nm":"Koffer-Namenschildschnur","de":"Ein einzelner Faden, der inmitten lauter gleich aussehender schwarzer Koffer zeigt, welcher der eigene ist. Seinen Namen daran zu befestigen ist ein freundliches Zeichen: Dieses Gepäck hat ein Ziel, zu dem es zurückfindet."},"ICON-2006":{"nm":"Zimmer-Wandladekabelhalter","de":"Eine kleine Wandplatte am Kopfende des Bettes hält das Ladekabel ordentlich bereit. In der ersten Nacht in einem fremden Zimmer lässt ein vertrautes Lämpchen, das aufleuchtet, den Ort für eine Weile zur Heimat werden."},"ICON-2007":{"nm":"Kofferbock-Klappstelzen","de":"Klappt man die Beine aus, hebt sich der Koffer eine Handbreit vom Boden ab, weg vom Schmutz. Ein noch nicht ausgepackter Koffer, der so aufgestellt wartet, hält die unvollendete Reise still in sich und wartet auf den nächsten Morgen."},"ICON-2008":{"nm":"Schlüsselkarten-Einschubschlot","de":"Erst wenn die Karte steckt, geht das Licht im Zimmer an. Das Licht, das nur brennt, solange man hier ist — der Tag des Reisenden wird durch genau so viel Helligkeit erwärmt, wie dieser kleine Schlot erlaubt."},"ICON-2009":{"nm":"Schlüsselkarten-Trageschnur-Öse","de":"Hängt man die Karte um den Hals, werden beide Hände frei. Das kleine Geschick, die Sorge vor dem Verlieren an eine Schnur zu knüpfen, ist eine Weisheit, die gepäckbeladene Reisende seit Langem weitergeben."},"ICON-2010":{"nm":"Rezeptionsruf-Klingelknopf","de":"Drückt man ihn, ertönt irgendwo an der Rezeption ein heller Klingelton. Damit man ohne Hemmung um Hilfe bitten kann, liegt die Klingel immer an einem Ort, den eine Handbewegung erreicht."},"ICON-2011":{"nm":"Check-in-Nummernclip","de":"Den am Ende der Schlange erhaltenen Nummernzettel klemmt man fest. Auch das Warten hat seine Reihenfolge — Ordnung wächst aus dem stillen Versprechen, die Zeit des anderen zu achten."},"ICON-2012":{"nm":"Zimmerschlüssel-Quaste","de":"Die am Schlüsselende befestigte Quaste schwingt bei jedem Schritt leicht. Dem Nützlichen ein wenig Eleganz hinzuzufügen ist eine Freude, die nur kennt, wer die kleinen Genüsse der Fingerspitzen zu schätzen weiß."},"ICON-2013":{"nm":"Rezeptionsklingel-Abdeckung","de":"Bedeckt man die Klingel, bleibt die Stille des hellen Mittags ungestört. Eine kleine Rücksicht, um jemandem seinen ruhigen Schlaf zu bewahren — auch Stille ist etwas, das jemand liebevoll bereitet."},"ICON-2014":{"nm":"Zimmernummer-Türhänge-Zettel","de":"Auf dem am Türknauf hängenden Zettel steht die Zimmernummer deutlich geschrieben. Einige Ziffern bestimmen den Ort, an den man heute Nacht zurückfindet — im fremden Flur werden sie zu einem kleinen Leuchtturm."},"ICON-2015":{"nm":"Schlüsselkarten-Magnetstreifen","de":"Hält man den schwarzen Streifen an den Türspalt, öffnet sich das Schloss lautlos. Ein unsichtbares Signal öffnet die Tür — was einst wie Magie wirkte, ist heute alltägliche Handgeste auf der Handfläche."},"ICON-2016":{"nm":"Check-in-Stempelunterlage","de":"Bei jedem Stempelabdruck nimmt die Unterlage die Tinte gleichmäßig auf. Damit der Abdruck der Bestätigung klar und deutlich bleibt, gibt es eine Hand, die still und unsichtbar darunter stützt."},"ICON-2017":{"nm":"Gepäckwagen-Hängestange","de":"Die an den Gepäckwagen gehängte Stange trägt Kleidertaschen faltenfrei. Wer die schweren Tage stellvertretend trägt, den möchte man manchmal gerne mit einem herzlichen Dankeschön bedenken."},"ICON-2018":{"nm":"Koffer-Griff-Anhänger","de":"Am Koffergriff hängt ein kleiner Anhänger. Solange das Namensfeld noch leer ist, bleibt das Reiseziel dieses Koffers offen — und die Vorfreude auf das Unbekannte ist noch ganz da."},"ICON-2019":{"nm":"Gepäckwagen-Rad-Bremskeile","de":"Damit der Wagen am Hang nicht wegrollt, schiebt man einen Keil unter das Rad. Das Stillstehen zu bewahren ist manchmal das verlässlichste Sicherheitsnetz überhaupt."},"ICON-2020":{"nm":"Reisegurt-Schnalle","de":"Damit die prall gefüllte Reisetasche nicht platzt, schnallt man das Band fest. Weil die Erinnerungen, die man mitnimmt, an Volumen nicht abnehmen, hält die Schnalle dieses Gewicht bis zum Ende fest."},"ICON-2021":{"nm":"Gepäckwagen-Haken-Schutzabdeckung","de":"Die Abdeckung am Wagenhaken hinterlässt keine Kratzer an der Kleidung. Selbst unsichtbare Schäden im Voraus zu bedenken — gute Gastfreundschaft vollendet sich in solchen Kleinigkeiten."},"ICON-2022":{"nm":"Koffer-Namensschildtäschchen","de":"Das kleine Täschchen an der Kofferseite bewahrt das Namensschild. Seine Besitzerin oder seinen Besitzer einzutragen bedeutet, dem Gepäck schon im Voraus das Recht zu geben, selbst nach einem Verlust zurückzufinden."},"ICON-2023":{"nm":"Gepäckhandschuh-Klemme","de":"Damit die Handschuhe beim Tragen schwerer Lasten nicht verrutschen, hält die Klemme sie tüchtig fest. Die Hand zu schützen und die Arbeit gut zu erledigen kommt aus ein und demselben Herzen."},"ICON-2024":{"nm":"Gepäck-Netz-Abdeckplane","de":"Bedeckt man das Gepäck mit einer Netzplane, zerstreuen sich die kleinen Sachen nicht in alle Richtungen. Jede einzelne Masche hält im emsigen Hin und Her der Reise die kleinen Dinge fest, damit nichts verloren geht."},"ICON-2025":{"nm":"Gepäckwagen-Memo-Steckhalter","de":"In den am Wagengriff steckenden Zettel ist die Zimmernummer geschrieben. Die Gewohnheit, das Ziel zu notieren — gerade geschäftige Hände verlassen sich auf eine einzige Zeile."},"ICON-2026":{"nm":"Servierplatten-Kloche","de":"Hebt man die silberne Haube ab, steigt der Dampf auf einen Schlag empor. Das Herz, das nicht zulässt, dass das Essen kalt wird, ist Hingabe pur — die Wärme so weiterzugeben, wie sie ist."},"ICON-2027":{"nm":"Bitte-nicht-stören-Türschild","de":"Hängt man dieses Schild an den Türknauf, werden selbst Schritte im Flur vorsichtiger. 'Bitte nicht wecken' — auch Ruhe wird erst vollständig, wenn jemand sie bewacht."},"ICON-2028":{"nm":"Zimmerservice-Papierserviettenring","de":"Eine Papierserviette in den runden Ring stecken und ordentlich formen. Die Förmlichkeit einer Mahlzeit beginnt an diesem kleinen Ring — Sorgfalt zeigt sich am deutlichsten in der Nebensache."},"ICON-2029":{"nm":"Tablett-Rutschfeste Unterlage","de":"Legt man die Unterlage auf das Tablett, verrutscht das Geschirr nicht. Was auch im Schwanken an seinem Platz bleibt — auch ruhiger Stabilität liegt ein durchdachtes Design zugrunde."},"ICON-2030":{"nm":"Frühstücks-Türhänge-Bestellkarte","de":"Hängt man die Frühstücks-Bestellkarte an die Türklinke, ist der nächste Morgen schon versprochen. Den ersten Bissen des Tages noch am Abend aufzuschreiben ist ein weiteres freundliches Gesicht des Wartens."},"ICON-2031":{"nm":"Tablett-Beinständer","de":"Klappt man die Beine des Tabletts aus, entsteht selbst auf dem Bett ein richtiger Esstisch. Ein Frühstück, das man liegend entgegennimmt — ein kleiner Ständer verwandelt ein gewöhnliches Zimmer in eine üppige Szene."},"ICON-2032":{"nm":"Kannenwärmer-Haube","de":"Stülpt man die Wärmhaube über die Kanne, hält das Wasser seine Wärme länger. Wie einst um den Herd versammelt — der Wunsch, Wärme zu bewahren, kennt keine Zeit."},"ICON-2033":{"nm":"Reinigungswunsch-Türhänger","de":"Ein Reinigungswunsch-Anhänger am Türknauf hinterlässt ein schweigendes Signal. Eine Bitte, die ohne Worte ankommt — hinter einem sauberen Zimmer steckt das Versprechen unsichtbarer Hände."},"ICON-2034":{"nm":"Tablett-Gewürzhalter","de":"Damit die Gewürzflaschen nicht umkippen, hält der Halter sie sicher fest. Selbst auf einem schwankenden Tablett die Balance der Aromen zu bewahren ist die stille, verlässliche Aufgabe dieses kleinen Fixierers."},"ICON-2035":{"nm":"Reservierungs-Memo-Aufsteller","de":"Steckt man den Reservierungszettel in den Aufsteller, liest man die Reihenfolge auf einen Blick. Damit selbst geschäftige Hände nicht durcheinandergeraten, ist dieses kleine Ordnungsmittel ein klarer Helfer."},"ICON-2036":{"nm":"Sehenswürdigkeits-Pinnwand-Karte","de":"Auf der Karte einen Pin einstechen und den nächsten Wunschort markieren. Jeder Pin ist eine Vorfreude auf ein noch unbesuchtes Ziel — eine Reise beginnt in dem Moment, in dem die Karte aufgefaltet wird."},"ICON-2037":{"nm":"Taxi-Ruf-Fähnchen-Klemme","de":"Damit das Fähnchen beim Rufen eines Taxis aufrecht steht, hält die Klemme es gerade. Statt eine Hand zu heben, ruft das Fähnchen stellvertretend — ein Signal muss klar und deutlich sein, damit es auf der Straße ankommt."},"ICON-2038":{"nm":"Concierge-Klingelgriff","de":"Drückt man den Griff, ertönt am Concierge-Pult ein heller Ton. Das Signal der Gastfreundschaft, das sagt: Fragen sind willkommen — der verlässlichste Ruf in einer fremden Stadt."},"ICON-2039":{"nm":"Reservierungsnummer-Klemmtafel","de":"Den Reservierungsnummernzettel in die Klemmtafel spannen und gut sichtbar aufstellen. Damit der vereinbarte Platz nicht durcheinanderkommt, hält diese kleine Gewissenhaftigkeit die Zahl sauber fest."},"ICON-2040":{"nm":"Tour-Prospekt-Einschubrahmen","de":"Steckt man Tourprospekte hinein, bleibt der Blick der Reisenden unwillkürlich hängen. In jedem herausgezogenen und aufgefalteten Blatt liegt die Landschaft eines Weges, den man noch nicht gegangen ist."},"ICON-2041":{"nm":"Lagekarten-Stempelständer","de":"Für den Fuß, der zum ersten Mal die Türschwelle übertritt, hält der Ständer das Lageplan-Stempelfeld ruhig. Läuft die Tinte nicht aus, verirrt man sich auch nicht — der Ständer hält die kleine Wegweisung aufrecht, schweigend und verlässlich."},"ICON-2042":{"nm":"Regenschirm-Anhänger","de":"An einem regnerischen Nachmittag, Tropfen um Tropfen, bekommt jeder Schirm eine Nummer. Wenn der Regen aufhört und die Menschen zurückkehren, ruft der Anhänger die nasse Erinnerung klar beim Namen."},"ICON-2043":{"nm":"Infotheke-Hängeglocke","de":"Kling, eine kurze Berührung, und von drüben kommt jemand strahlend herbei. Die kleine Glocke an der Ecke des Infopults übermittelt auch das, was man nicht über die Lippen bringt — der freundlichste Dolmetscher überhaupt."},"ICON-2044":{"nm":"Shampoo-Spenderpumpe","de":"Hält man die Handfläche hin und drückt leicht, quillt der Schaum hervor. Der Duft breitet sich im ganzen Badezimmer aus — ein einziger Pumpzug. Das Signal, das einen verschlafenen Morgen am sanftesten weckt, beginnt genau hier."},"ICON-2045":{"nm":"Seifenhalter mit Wasserablauf","de":"Ein Ablagefach, das das unter der Seife stehende Wasser still abfließen lässt. Damit sie nicht aufweicht und matschig wird. Etwas, das täglich ein wenig abnimmt, noch ein Stückchen länger an seiner Seite zu halten — eine kleine, herzliche Fürsorge."},"ICON-2046":{"nm":"Badezusatz-Schaufel","de":"Schöpft man einen Löffel Pulver und gibt ihn ins warme Wasser, breiten sich Farbe und Duft langsam aus. Während man mit dem Handgelenk umrührt, wird die Wanne zu einem kleinen See, und die Erschöpfung eines ganzen Tages versinkt darin."},"ICON-2047":{"nm":"Schaumseifenbeutel","de":"Sperrt man ein Seifenstück ins Netz und reibt es, füllt sich die Handfläche mit weichem Schaum. Was rau war, wird sanft — der stille Alchemist einer Badezimmerecke."},"ICON-2048":{"nm":"Zahnbürsten-Sterilisierkappe","de":"Der Wunsch, dass das, was in den Mund kommt, immer sauber ist. Eine kleine Kappe, die sanft die Borstenspitze umhüllt, kümmert sich auch um das Unsichtbare. Sauberkeit entsteht, wenn sich solche Kleinigkeiten summieren."},"ICON-2049":{"nm":"Wattestäbchendosen-Deckel","de":"Eine Dose, in der weiße Stäbchen ordentlich liegen, und ein runder Deckel darüber. Auf geht's, zu. Mit einem kleinen Geräusch die Ordnung abzuschließen ist das freundliche Schlusspunkt-Ritual des Badezimmers."},"ICON-2050":{"nm":"Badeöl-Tropfflasche","de":"Neigt man sie leicht, fällt Tropfen für Tropfen das duftende Öl. Glanz und ein zarter Duft verbreiten sich im Wasser. Zu luxuriös für Alltag, zu vertraut für Sonderfall — dieser eine Tropfen."},"ICON-2051":{"nm":"Amenity-Tablett-Trennsteg","de":"Auf dem in Fächer unterteilten Tablett findet jedes kleine Fläschchen seinen Platz. Was verstreut unordentlich wirkt, wird gesammelt zu etwas Gepflegtem. Ein Trennsteg wahrt die Ordnung des geschäftigen Morgens."},"ICON-2052":{"nm":"Sauna-Sanduhr-Ständer","de":"So lange, wie der Sand hindurchrieselt, die Wärme in den Rücken eindringen lassen — ein freundliches Versprechen. Während die Uhr auf dem Ständer leise die Zeit zählt, lässt der Mensch im dampfenden Nebel alles los und ruht für einen Moment."},"ICON-2053":{"nm":"Dampfbad-Schafsohr-Handtuch","de":"Rollt man die Handtuchenden auf und stellt sie wie Ohren auf, entspannt sich das Gesicht im Spiegel. Im heißen Dampf kehrt jeder für einen Augenblick in die Unbeschwertheit zurück — ein kleines Ritual des Dampfbades."},"ICON-2054":{"nm":"Sauna-Wasserschöpfkelle","de":"Schöpft man Wasser in die Kelle und schüttet es auf die glühenden Steine, zischt es — und Dampf schießt bis zur Decke. In diesem Moment taucht der ganze Körper in einen warmen Nebel, und tief sitzende Erschöpfung löst sich langsam in Schweißtropfen auf."},"ICON-2055":{"nm":"Fußbad-Thermometerstab","de":"Taucht man den Stab ins Wasser, spricht die Skala leise. Nicht zu heiß, nicht zu kalt — genau die richtige Temperatur. Bevor man die Füße hineintaucht, ist es der erste Finger, der das Wasser begrüßt."},"ICON-2056":{"nm":"Dampfbad-Steinzange","de":"Frisch erhitzte Steine mit bloßen Händen anfassen ist keine Option. Die Zange greift sie tüchtig und trägt die Hitze auf sicherer Distanz. Vorsicht ist auch eine Kunstfertigkeit, sagt das Dampfbad leise."},"ICON-2057":{"nm":"Sauna-Sitzmatte","de":"Legt man eine Matte auf den heißen Boden, wird die Stelle, wo der Rücken aufliegt, ein wenig weicher. Die Matte, die schweigend einen schweißnassen Tag auffängt. Erholung kommt letztlich aus dem richtigen Abstand zum Boden."},"ICON-2058":{"nm":"Fußbad-Salzbeutel","de":"Eine Handvoll grobes Salz in warmes Wasser aufgelöst — von den Zehen her schmilzt die Müdigkeit sanft dahin. Wenn salziger Dampf die Waden umhüllt, kommt der Tag, der so viel Gehen verlangt hat, endlich zum Stehen."},"ICON-2059":{"nm":"Sauna-Duftstein-Schale","de":"Einige Tropfen Parfüm auf den erhitzten Stein geträufelt, breitet sich der erwärmte Duft langsam in der Sauna aus. Die Augen schließen — ob man im Wald oder auf einer Blumenwiese ist. Die kürzeste Reise, die die Nase unternimmt."},"ICON-2060":{"nm":"Wärmepack-Isolierhülle","de":"Eine Hülle, die das erwärmte Pack umhüllt und die Wärme lang festhält. Genau in dem Geist, es fest zu umarmen, damit es nicht auskühlt, bewacht die auf dem Bauch liegende Wärme die ganze Nacht hindurch."},"ICON-2061":{"nm":"Aroma-Diffusor-Stäbchen","de":"Dünne Stäbchen saugen den Duft auf und geben ihn langsam ans Zimmer ab. Bei jedem Einatmen schleicht er sich zart ein. So nimmt der Raum, in dem man wohnt, nach und nach den Duft seines Bewohners an."},"ICON-2062":{"nm":"Liegestuhl-Neigungsgriff","de":"Dreht man den Griff langsam, neigt sich die Rückenlehne sachte. Ein wenig zur Sonne, ein wenig in den Schatten. Den angenehmsten Winkel ertasten — das ist eine Rechenaufgabe, die nur man selbst lösen kann."},"ICON-2063":{"nm":"Pool-Randstreifen gegen Ausrutschen","de":"Ein Antirutschstreifen, der ringsherum den Poolrand fasst. Damit kleine Füße, die begeistert herbeigerannt kommen, sicher zum Stehen kommen — die unsichtbar verlegte Ziellinie der Sicherheit."},"ICON-2064":{"nm":"Schwimmreifen-Ventilhaken","de":"An dem kleinen Ventil, das die Luft festhält, hängt sorgsam ein Haken. Damit das Ventil nicht ins Wasser treibt, wenn es aus dem Reifen rutscht. Ein kluger Griff, der einen lästigen Verlust an einem Sommermittag verhindert."},"ICON-2065":{"nm":"Pool-Einstiegsleiter-Schutzkappe","de":"Die Enden der Leiter ins Wasser werden weich ummantelt. Damit nackte Fußsohlen nicht aufgeschürft werden und der erste Schritt ins Wasser sanft aufgenommen wird. Denn jeder Anfang soll behutsam sein."},"ICON-2066":{"nm":"Liegestuhl-Kissen-Befestigungsöse","de":"Damit das Kissen nicht hinunterrutscht, hält eine Schnuröse es fest. Ein kleines Versprechen, seinen Platz auch im Wind zu halten. Ein einziges Geflecht hält die nachmittägliche Trägheit an Ort und Stelle."},"ICON-2067":{"nm":"Pool-Villa-Getränkehalter-Brett","de":"Ein Brett am Poolrand, in das man das Glas steckt. Ein sicherer Platz, der auch wildem Planschen standhält. Eine kühle Erfrischung in Reichweite zu halten verlängert den Sommermittag."},"ICON-2068":{"nm":"Nasse-Badekleider-Wäscheklemme","de":"Den triefenden Badeanzug klemmen und dem Wind überlassen. In der Sonne trocknend hält die Klemme ihn still und schweigend. Eine stille, herzliche Wartezeit auf das nächste Planschen."},"ICON-2069":{"nm":"Sonnenschirm-Standfußgewicht","de":"Ein schweres Gewicht, das am Fuß des Schirmmasts liegt, damit der Schirm im Wind nicht schwankt. Dass der Schatten so lange an einer Stelle bleibt, verdankt sich diesem Gewicht. Das Verlässliche versteckt sich oft an der niedrigsten Stelle."},"ICON-2070":{"nm":"Pool-Temperatur-Schwimmchip","de":"Ein kleiner Chip, der auf dem Wasser treibt und still die Temperatur anzeigt. Zu kalt leuchtet er rötlich, genau richtig weich und sanft. Der niedliche Wahrsager, der die Stimmung des Wassers an seiner Farbe abliest."},"ICON-2071":{"nm":"Zelt-Reißverschluss-Zugquaste","de":"Zieht man die kleine Quaste am Reißverschlussende nach oben, gleitet die Zelttür auf. Ein Griff, den man auch im Dunkeln sofort findet. Er führt freundlich durch das Kommen und Gehen in der tiefen Nacht."},"ICON-2072":{"nm":"Zeltschnur-Schmetterlingsklammer","de":"Eine Klammer in Schmetterlingsform, die die Schnur fasst und fest hält. Das flatternde Zelttuch findet endlich Ruhe. Campingnächte werden von solchen kleinen, tüchtigen Knoten still bewacht."},"ICON-2073":{"nm":"Glamping-Matratzen-Luftventil","de":"Ins Ventil pusten, puh, puh — die Matratze füllt sich langsam. Schließt man das Ventil fest, wird der Boden weich, und unter dem Sternenhimmel ist endlich ein Lager zum Hinlegen bereit."},"ICON-2074":{"nm":"Zelthimmel-Aufhängeöse","de":"Eine Öse an der Zeltdecke, um Laternen oder Handtücher aufzuhängen. Die kluge Nutzung des kleinen Raums über dem Kopf. Man hängt gleichsam einen Stern an die Decke, statt an den Himmel."},"ICON-2075":{"nm":"Schlafsack-Rollbefestigungsband","de":"Ein Band, das um den aufgerollten Schlafsack gespannt wird, damit er sich nicht entrollt. Jeden Morgen schrumpft das Nachtlager wieder zusammen. Aufbruchsbereitschaft ist das sorgfältige Falten der Wärme von gestern Nacht."},"ICON-2076":{"nm":"Zeltzugang-Schuhablage","de":"Eine Ablage am Zelteingang, auf die man Schuhe ordentlich stellt. Schmutz bleibt draußen, das Innere bleibt sauber. Die freundliche Trennung von innen und außen durch eine einzige Schwelle — das kleine Benehmen des Campinglebens."},"ICON-2077":{"nm":"Glamping-Laternen-Hängekralle","de":"Ein gebogener Haken zum Aufhängen der Laterne. Hängt sie hier, breitet sich das Licht rund im Zelt aus. Der Platz, an dem man in der Dunkelheit ein Licht aufhängt, wird zum Wohnzimmer der heutigen Nacht."},"ICON-2078":{"nm":"Zeltlüftungsfenster-Rollklemme","de":"Eine Klemme, die das aufgerollte Lüftungsfenster festhält. Lässt man etwas Luft herein, wird es im Zelt frischer. Eine kleine Öffnung schafft still den Raum zum Atmen für die ganze Nacht."},"ICON-2079":{"nm":"Zeltboden-Schutzmatte","de":"Eine Matte, die auf dem Zeltboden ausgebreitet Erde und Feuchtigkeit abhält. Eine Schicht, die auch auf dem Rasen ein trockenes Lager bereitet. In der Natur zu übernachten, ohne von ihr durchnässt zu werden — eine stille Begleitung."},"ICON-2080":{"nm":"Hantelstangen-Sicherungsring","de":"Ein Ring, der an beiden Enden der Hantelstange verhindert, dass die Scheiben herausfallen. Das kleine Schloss, das dem Gewicht desjenigen vertraut, der hebt. Wenn die Sicherheit fest stützt, kann man eine Grenze nach der anderen überwinden."},"ICON-2081":{"nm":"Kettlebell-Griffkappe","de":"Beim letzten Satz, wenn der Stahl die Handfläche wund reibt, macht diese kleine Kappe den Schmerz verschwinden. Dass es schwerer ist, bis zum Ende zu halten als anzuheben, spüren die Hände zuerst am letzten Drückpunkt."},"ICON-2082":{"nm":"Gewichtsscheiben-Ausgleichskeil","de":"Wackelt die Scheibe minimal, bricht die Haltung noch vor dem Heben zusammen. Der dünne Keil, der lautlos in den Spalt getrieben wird, hält die Mitte fest. Stabilität beginnt immer still an der unsichtbaren Stelle."},"ICON-2083":{"nm":"Hantelstangen-Verschlussklemme","de":"Beim Befestigen der Klemme darf es kein Zögern geben. Dieses eine kleine Klicken trägt alle folgenden Bewegungen. Der Körper lernt, in einer Klemme Vertrauen zu stecken."},"ICON-2084":{"nm":"Gewichtsscheiben-Farbchip","de":"Für jedes Gewicht gibt es eine andere Farbe — so erkennt die Hand das Richtige, bevor der Kopf die Zahl liest. Rot ist schwer, blau ist leicht: Gewichte durch Farben zu erinnern ist eine Methode des Körpers, Kraft mit den Augen abzuschätzen."},"ICON-2085":{"nm":"Kettlebell-Bodenunterlage","de":"Eine Unterlage, die die Auflagefläche vergrößert, damit der Holzboden nicht eingedrückt wird. Trainingsspuren sollen in Schweiß und Muskeln bleiben. Damit unten kein Schaden entsteht, liegt dieses kleine Herz darunter."},"ICON-2086":{"nm":"Hantelstangen-Mittelpunktsmarkierung","de":"Die Markierung in der Mitte der Stange ist der Referenzpunkt für die Balance von links und rechts. Wer die Mitte genau trifft, halbiert das Wanken. In dem Moment, in dem man weiß, wo die Mitte liegt, kann man sicher anheben."},"ICON-2087":{"nm":"Gewichtsscheiben-Lagerhalter","de":"Wer die Scheiben nach dem Gebrauch wieder an ihren Platz hängt, zeigt stille Rücksicht auf den nächsten. Das geordnete Bild der nach Gewicht aufgehängten Scheiben ist die verlässlichste Sicherheitsvorrichtung, die jemand kennt."},"ICON-2088":{"nm":"Rollstopperleiste für Gewichtsscheiben","de":"Eine Scheibe, die auf dem Boden liegt und leise wegrollt und den Fuß trifft — das Unglück kommt immer in einem Moment der Unachtsamkeit. Der Rollstopper stellt sich still diesem Augenblick entgegen. Großes Unheil rollt aus kleinen Lücken heran."},"ICON-2089":{"nm":"Bank-Rückenlehnen-Polster","de":"Ist das Rückenlehnenpolster zu hart, wird schon der Atem flacher. Der Punkt, der weder zu hart noch zu weich ist, ist eine Balance, die nur jemand ertasten kann, der lange darauf gesessen hat."},"ICON-2090":{"nm":"Rackstangen-Höhensteckpin","de":"Ein einziger Pin stellt die Höhe so ein, dass die Stange für jede Schulter passt. Menschen unterschiedlicher Größe teilen dasselbe Gerät einträchtig — ein einziges kleines Loch schafft diese freundliche Gleichheit."},"ICON-2091":{"nm":"Maschinen-Seilscheiben-Abdeckung","de":"In der Abdeckung um die Riemenscheibe dreht und dreht sich das Kabel lautlos. Die Reibung nach innen verbergen und nur Geschmeidigkeit nach außen geben — ein gutes Gerät zeigt die Mühe, die es auf sich nimmt, bis zum Ende nicht."},"ICON-2092":{"nm":"Bank-Standfüße mit Rutschschutz","de":"Die Rutschfüße an den vier Beinen halten die Bank fest am Boden. Erst wenn sie nicht wackelt, kann man mit ganzer Kraft drücken. Stabilität beginnt letztlich mit der kleinen Reibung an den Zehenspitzen."},"ICON-2093":{"nm":"Rack-Stangenhaken","de":"Der Haken zum Ablegen der Stange muss immer in Griffhöhe sein. Der Ort, an dem der müde Arm die Stange am Ende sanft ablegt — diese eine Handbreit entscheidet, ob das Training sicher endet."},"ICON-2094":{"nm":"Maschinen-Gewichtswechsel-Pingriff","de":"Der Griff zum Einsetzen des Pins für die Gewichtsauswahl muss glatt sein, damit die Fingernägel nicht leiden. Selbst in dem flüchtigen Augenblick, in dem man das Gewicht wechselt, steckt eine Verarbeitung, die an die Fingerkuppen des Menschen denkt."},"ICON-2095":{"nm":"Bank-Winkelverriegelungshebel","de":"Ist der Hebel, der den Winkel der Rückenlehne arretiert, locker, sackt die Haltung unbemerkt zusammen. Klick — und in diesem Moment der Gewissheit: Jeden Morgen beim Öffnen der Tür prüft der Betreiber zuerst diesen Ton."},"ICON-2096":{"nm":"Rack-Sicherheitsauffangstangen","de":"Im schlimmsten Moment, wenn die Hantel die Hände verlässt, fangen die Sicherheitsstangen das Gewicht auf. Da sie immer unsichtbar darunter warten, kann der Mensch sich bis an seine Grenzen herantasten."},"ICON-2097":{"nm":"Maschinen-Kabelendkappe","de":"Die kleine Kappe, die das Kabelende zusammenhält, ist die letzte Sicherung gegen Aufdröseln. Dafür zu sorgen, dass die Fasern nicht auseinanderfallen — die Würde des Abschlusses wohnt immer an diesem unsichtbaren Endpunkt."},"ICON-2098":{"nm":"Magnesiakreide-Beutel","de":"Eine Handvoll weißes Pulver, in die Hände gerieben, löscht das Abrutschen aus. Wie Schminke hinter der Bühne — unsichtbar, und doch beginnt die Stabilität aller heutigen Bewegungen mit dieser einen Handvoll. Vorbereitung fängt immer an den Fingerspitzen an."},"ICON-2099":{"nm":"Griffkraft-Übungsklemme","de":"Eine kleine Klemme, die man stumm und beharrlich auf- und zukneift, stärkt den Griff. Griffkraft wächst langsamer als große Muskeln — das hier ist auch eine Übung darin, die Ungeduld sanft loszulassen."},"ICON-2100":{"nm":"Fingerspreizendes Widerstandsband","de":"Ein Band, das man zwischen die Finger schiebt und nach außen dehnt. Die Hand, die nur Kraft im Greifen kannte, gewinnt auch die Kraft im Öffnen zurück. Auch das ruhige Loslassen braucht Übung, sagen die Hände."},"ICON-2101":{"nm":"Kreidedosendeckel","de":"Sitzt der Deckel der Kreidedose nur ein wenig locker, färbt sich die ganze Tasche weiß. Ein kleiner Deckel, der wirklich fest schließt, verhindert dieses kleine Missgeschick von vornherein. Ob die Sicherung gelingt, entscheidet sich immer am Verschluss."},"ICON-2102":{"nm":"Knieschutzbinde","de":"Die Binde, die das Knie umschließt und stützt, muss genau beim richtigen Druck innehalten. Zu fest gewickelt, staut sich das Blut, zu locker nützt sie nichts – und genau dieses feine Maß dazwischen ermisst eine geübte Hand still aus der Erinnerung."},"ICON-2103":{"nm":"Widerstandsschlaufe","de":"Das elastische Band, das sich dehnt und wieder zusammenzieht, weckt schlafende Muskeln auch ganz ohne Eisen. Widerstand muss nicht schwer sein. Selbst einer sanften Zugkraft antwortet der Körper stets ehrlich."},"ICON-2104":{"nm":"Fußgelenk-Sandgewicht","de":"Der Sandsack, den man sich ums Fußgelenk schnallt, zieht jeden einzelnen Schritt schwer nach unten. Ein wenig zusätzliches Gewicht macht aus gewöhnlichem Gehen ein echtes Training. Eine kleine Weisheit, dem Alltag heimlich etwas Last hinzuzufügen."},"ICON-2105":{"nm":"Handgelenk-Kraftroller","de":"Ein Rollstab, an dessen Schnur ein Gewicht hängt, das man langsam mit dem Handgelenk aufwickelt. Das Handgelenk ist das kleinste und am häufigsten vergessene Gelenk – dieses schlichte Gerät weckt still die Kraft, die darin in Vergessenheit geraten war."},"ICON-2106":{"nm":"Griffkraftball","de":"Der Gummiball, den man in der Hand mal zusammendrückt, mal loslässt, führt das Training heimlich sogar am Schreibtisch fort. Kraft, die man in kleinen Momenten sammelt, hält länger als jene, die man auf einmal aufwendet. Beständigkeit wächst immer aus solchen kleinen Dingen."},"ICON-2107":{"nm":"Herzfrequenzgurt-Schnalle","de":"Sitzt die Schnalle des Brustgurts nur ein wenig schief, springen die Zahlen wild umher. Selbst wenn man dem eigenen Herzschlag lauschen will, kommt zuerst der feste Sitz. Jede Messung beginnt letztlich mit einer lückenlosen Anlage."},"ICON-2108":{"nm":"Pulsclip","de":"Die Klammer, die sanft in die Fingerspitze beißt, zählt still den Puls. Steckt man sie auf und atmet ruhig, erscheint der Herzschlag klar auf dem kleinen Display. Der Körper teilt seinen Zustand immer ohne Lüge mit."},"ICON-2109":{"nm":"Pulsuhr-Etui","de":"Das Etui, das den Handgelenk-Messer verwahrt, erkennt seinen Schützling, so klein es auch ist. Je leichter ein kleines Gerät verloren geht, desto mehr braucht es ein Zuhause, zu dem es zurückkehren kann. Auch gutes Verwahren ist eine Form von Zärtlichkeit."},"ICON-2110":{"nm":"Streckenfähnchen-Pin","de":"Eine kleine Fähnchen-Nadel, die dem Läufer genau sein Ziel markiert. Ein Punkt, den man sich im Voraus gesetzt hat – bis hierhin, nicht weiter – trägt die schweren Füße bis zum Schluss. Die Ziellinie im eigenen Herzen steckt man sich immer selbst."},"ICON-2111":{"nm":"Herzschlaglämpchen","de":"Ein kleines Lämpchen, das leise im Takt des Herzschlags blinkt. Betrachtet man still diesen Rhythmus aus Aufleuchten und Verlöschen, rührt es einen unerwartet: Lebendig zu sein – war das schon immer so regelmäßig?"},"ICON-2112":{"nm":"Rundenzähl-Perlenschnur","de":"Mit Perlen, die man eine nach der anderen weiterschiebt, zählt man die Wiederholungen. Man muss sich die Zahl nicht im Kopf merken – die Finger erinnern sich stellvertretend. Überlässt man das Zählen der Hand, kann der Geist ganz bei der Bewegung bleiben."},"ICON-2113":{"nm":"Sättigungsmess-Clip","de":"Die Clip-Klammer, die man auf die Fingerspitze steckt, liest still den Sauerstoffgehalt im Blut. Wenn die unsichtbare Tiefe des Atems als Zahl erscheint, erkennt man von Neuem: Sich um den Körper zu kümmern heißt am Ende, ihn genau anzusehen."},"ICON-2114":{"nm":"Pulszonenband","de":"Ein Band, das die Trainingsintensität in Farben unterteilt, zeigt auf einen Blick, wie sehr man sich gerade anstrengt. Blau bedeutet Gelassenheit, Rot die Grenze. Die Farbe wird so zu einer stillen, liebevollen Sprache, zu einem leisen Versprechen."},"ICON-2115":{"nm":"Messgelee-Kapsel","de":"Die kleine Gelee-Kapsel, die den Körperzustand misst, bewahrt in einem einzigen Korn die Information eines ganzen Tages. Was auch immer sich hinter der durchsichtigen Hülle verbirgt – darin steckt immer auch der Wunsch, sich selbst ein wenig besser zu kennen."},"ICON-2116":{"nm":"Schweißtuchhaken","de":"Die kleine Angewohnheit, das Handtuch nicht achtlos irgendwohin zu werfen, sondern stets an seinen eigenen Haken zu hängen, hält den ganzen Raum ordentlich. So, wie dieser Haken dem Handtuch im Voraus einen Platz zum Zurückkehren gibt, zeigt sich Ordnung immer in den kleinen Dingen."},"ICON-2117":{"nm":"Flaschendeckelband","de":"Das kurze Band am Flaschendeckel verhindert, dass der Deckel davonrollt. Die Weisheit, leicht Verlierbares still am Körper festzubinden – ein einziges kleines Band nimmt einem den Ärger eines ganzen Tages ab."},"ICON-2118":{"nm":"Fächerblatt","de":"Ein Fächerblatt, das, weit aufgespannt, einen Windhauch erzeugt. Wie der alte Fächer, der einst an heißen Tagen den Schweiß kühlte, schenkt das einfachste Werkzeug oft den kühlsten Trost. Ein Windhauch entspringt immer den Fingerspitzen."},"ICON-2119":{"nm":"Kühltuch-Beutel","de":"Ein kleiner Beutel, der ein Tuch verwahrt, das kühl wird, sobald man es befeuchtet. Das Stück Stoff, das Hitze lindert, schlummert dort sanft, bis es leicht auf einen erschöpften Nacken sinkt und die Mittagshitze still davonträgt."},"ICON-2120":{"nm":"Tropfschale","de":"Eine Schale, die schon im Voraus einen Platz für herabfallende Tropfen bereithält. Statt das Herabtropfen zu tadeln, schafft sie zuerst einen Ort, es aufzufangen. Die Zärtlichkeit der Küche verweilt immer so, lautlos."},"ICON-2121":{"nm":"Luftleitflügel","de":"In dem Moment, in dem der frontal einströmende Wind entlang des kleinen Flügels leicht abgelenkt wird, atmet die stickige Luft des Übungsraums endlich auf. Was den Luftstrom verändert, war immer schon so ein kleiner Winkel."},"ICON-2122":{"nm":"Stirnband","de":"Wird beim Waschen der Pony nass, gerät der ganze Tag durcheinander. Dieses Band, das die Haare sanft von der Stirn hochhält, schenkt der Person vor dem Spiegel fünf trockene Minuten. Man merkt es erst, wenn es fehlt."},"ICON-2123":{"nm":"Becherklammer","de":"Wackelt der Becher bedrohlich am Rand des Schreibtisches, hält diese Klammer still eine Seite fest. Dass der Tag ohne Verschütten vergeht, verdankt sich – so verrät ein Schluck Wasser – einer Kante, die jemand stellvertretend festgehalten hat."},"ICON-2124":{"nm":"Kippfenstergriff","de":"Ein fest verschlossenes Fenster beengt, ein weit geöffnetes lässt frösteln. Genau den richtigen Spalt dazwischen merkt sich dieser Griffhaken. Lüften ist am Ende eine Sache des Herzens, das genau richtig offenzulassen versteht."},"ICON-2125":{"nm":"Korkeckenkappe","de":"Verletzt wird man immer an der spitzen Kante. Darum schneidet man ein Stück Kork zurecht und stülpt es über jede Ecke. Der sanft umhüllte Ort tut nun niemandes Knie mehr weh."},"ICON-2126":{"nm":"Bolstergriff","de":"Eine lange Nackenrolle zu tragen ist lästiger, als man denkt. Bringt man einen Griff an, passt sie mühelos in eine Hand. Wie man Schweres leicht trägt, hängt immer davon ab, wo man den Griff anbringt."},"ICON-2127":{"nm":"Gürtelschnalle","de":"Es gibt Tage, an denen man den Gürtel ein Loch enger schnallt, und Tage, an denen man ihn ein Loch lockert. Diese kleine Schnalle kennt die Verfassung des Tages am ehrlichsten. Ein Stück Metall, das die Aufrichtigkeit des Körpers stumm zu Protokoll bringt."},"ICON-2128":{"nm":"Viertelblock-Stütze","de":"Ein in vier Teile geschnittener Block stützt den Boden fest ab. Weder zu hoch noch zu niedrig, genau im richtigen Gleichgewicht. Stützen bedeutet, sich selbst zu senken, damit oben etwas emporgehoben wird – das zeigt er still und wortlos."},"ICON-2129":{"nm":"Bolsterbezug","de":"Dem eiförmig runden Kissen wird ein passgenaues Gewand angezogen. Zieht Schweiß ein, nimmt man es einfach ab und wäscht es. Je täglicher etwas die Haut berührt, desto mehr braucht es ein Wechselstück – das weiß jede gute Haushaltsführung."},"ICON-2130":{"nm":"Höhenausgleichskeil","de":"Neigt sich der Boden nur ein wenig, gerät alles mühsam Aufgeschichtete ins Wanken. Schiebt man einen dünnen Keil in den Spalt, findet die Welt ihre Waage wieder. Um etwas geradezurücken, braucht es nichts Großartiges."},"ICON-2131":{"nm":"Riemenendknoten","de":"Damit das Ende des Riemens nicht ausfranst und aufgeht, knüpft man eine feste Knotenperle. Ein Band, dessen Ende ordentlich verschlossen ist, hält lange. Dass der Abschluss schwerer fällt als der Anfang, lehrt ein einziger kleiner Knoten."},"ICON-2132":{"nm":"Knie-Faltpolster","de":"Dieser stechende Schmerz, jedes Mal, wenn das Knie auf harten Boden trifft. Ein zusammenklappbares Polster schiebt sich sacht zwischen Knie und Boden. Eine Zärtlichkeit, die stellvertretend jemandes Knie stützt."},"ICON-2133":{"nm":"Rutschfestes Unterteil","de":"Der stabilste Block nützt nichts, wenn er wegrutscht. Die feinen Rillen in der Unterlage beißen sich fest im Boden. Das Geheimnis von etwas Unerschütterlichem verbirgt sich immer auf der unsichtbaren Unterseite."},"ICON-2134":{"nm":"Ausrichtungsklammer","de":"Man richtet die Stäbe gerade aus und fixiert sie mit einer Klammer. Wer es gewohnt ist, Dinge in Reihe zu bringen, kennt sie: jene seltsame, kleine Zufriedenheit, die aufsteigt, wenn Schiefes plötzlich gleichauf liegt."},"ICON-2135":{"nm":"Dehngurtschlaufe","de":"Wenn die Rückseite des Oberschenkels zieht, dass es fast schmerzhaft ist, zieht diese Schlaufe stellvertretend die Zehenspitzen heran, die die Hand allein nicht erreicht. Dorthin, wo man allein nicht gelangt, schlägt ein einzelner Riemen eine Brücke."},"ICON-2136":{"nm":"Zehenspreizer","de":"Auch die Zehen, den ganzen Tag im Schuh gefangen, brauchen eine Verschnaufpause. Auf dem Polster, das sie sacht auseinanderspreizt, streckt sich der Fuß nach langer Zeit endlich wieder. Ein Abend, der von den entferntesten Stellen aus zu lösen beginnt."},"ICON-2137":{"nm":"Haltungswinkelmesser","de":"Mit bloßem Auge lässt sich unmöglich abschätzen, um wie viele Grad die eigene Haltung schief steht. Zeigt der Winkelmesser still den Winkel an, richtet sich der Körper endlich gerade auf. Eine Skala, die die unsichtbare Neigung sichtbar macht."},"ICON-2138":{"nm":"Beckenausrichtungskeil","de":"Ein träger Nachmittag, an dem das Becken einseitig verzogen erstarrt ist. Man stützt es mit einem Keil und findet langsam die Mitte wieder. Kein gewaltsames Geraderücken, sondern das Wiederfinden des richtigen Platzes."},"ICON-2139":{"nm":"Schulteröffnungsband","de":"Ein Band, das eingezogene Schultern sanft öffnet. Zieht man die Schnalle fest, öffnet sich der gebeugte Rücken langsam. Erst wenn man mit weit geöffneten Schultern tief einatmet, entsteht die richtige Haltung für die Verbeugung auf der Bühne."},"ICON-2140":{"nm":"Wirbelsäulen-Stützkeil","de":"Legt man sich auf den Rücken, zeichnet die Wirbelsäule ihre natürliche Kurve. Ein Keil, der diese Krümmung nicht zwingt, sondern sie still stützt. Gut auszuruhen beginnt damit, die dem Körper eigene Kurve anzuerkennen."},"ICON-2141":{"nm":"Fußrückendehnkeil","de":"Das Dehnen des Fußrückens blieb immer irgendwie unvollständig. Stützt man den passenden Keil darunter, streckt sich der Fuß erfrischend bis in Tiefen, die vorher unerreichbar waren. Eine kleine Schräge, die hilft, ein Stück weiter zu reichen."},"ICON-2142":{"nm":"Handgelenkauflage","de":"Wenn das vor der Tastatur abgeknickte Handgelenk zu kribbeln beginnt, schiebt sich die Auflage sacht darunter. Es sind gerade solche bescheidenen, niedrigen Dinge, die sich als Erstes um die lange arbeitende Hand kümmern."},"ICON-2143":{"nm":"Handgelenkbandage","de":"Bevor man etwas Schweres hebt, wickelt man die Bandage einmal ums Handgelenk. So sicher, wie sie sitzt, so beruhigt fühlt sich das Gemüt. Die Gewohnheit, sich schon vor der Verletzung zu schützen, ist das stille Geheimnis derer, die lange trainieren."},"ICON-2144":{"nm":"Armband-Handytasche","de":"Wohin mit dem Handy beim Laufen – das war immer ein Rätsel. Diese Tasche, die man sich um den Unterarm schnallt, nimmt einem diese Sorge ab. Läuft man mit dem Lieblingslied am Arm, fühlt sich der Weg gleich viel kürzer an."},"ICON-2145":{"nm":"Handtrainer-Federkappe","de":"Eine Kappe, die verhindert, dass das Federende des Handtrainers in die Handfläche sticht. Während man immer wieder zudrückt und loslässt, bewahrt dieser kleine Verschluss den Frieden zwischen Hand und Metall. Eine Rücksicht an einem Ort, den niemand sieht."},"ICON-2146":{"nm":"Handschuh-Fingerhut","de":"An den nähgewohnten Fingern der Großmutter saß immer ein Fingerhut. Dieser Fingerhut an der Handschuhspitze schützt nun die Fingerkuppe. Die Fürsorge für eine lange arbeitende Hand gleicht sich, Generation um Generation, aufs Haar."},"ICON-2147":{"nm":"Schwielenpolster","de":"Die Schwiele in der Handfläche ist der Fingerabdruck, den harte Arbeit hinterlassen hat. Das Polster, das man darüberlegt, macht den nächsten Versuch erst möglich. Indem man die hart gewordene Stelle wieder umhüllt, hängt sich der Mensch von Neuem ins Seil."},"ICON-2148":{"nm":"Anti-Rutsch-Griffband","de":"Rutscht die Handfläche immer wieder ab, verliert man, was man sich mühsam gegriffen hat. Wickelt man das raue Band darum, werden Hand und Gerät zu einem einzigen Körper. Die Kraft, nichts loszulassen, kommt überraschenderweise aus der Reibung."},"ICON-2149":{"nm":"Unterarm-Schweißband","de":"Bevor der beim Training herabrinnende Schweiß das Handgelenk erreicht, saugt ihn dieses Band am Unterarm zuerst auf. Dass Schweiß nichts ist, wofür man sich schämen müsste, bezeugt der durchnässte Stoff ganz ohne Worte."},"ICON-2150":{"nm":"Handschuhtrockner","de":"Wirft man sie achtlos irgendwohin, wird der nächste Morgen zur Qual – hängt man sie ordentlich auf, trocknet der Nachtwind sie von selbst schön flauschig. Der saubere Duft gut getrockneter Handschuhe eröffnet den morgigen Tag frisch und klar."},"ICON-2151":{"nm":"Reißverschlussgriff","de":"Mit klatschnassen Händen bekommt man den winzigen Reißverschluss einfach nicht zu fassen. Bringt man einen kleinen Griff an, geht es mit einem Zug. Ein unscheinbarer Ring rettet eine ganze verzweifelte Minute."},"ICON-2152":{"nm":"Ventilationspatch","de":"An der heißesten Stelle des Körpers bringt man einen Belüftungspatch an. Die eingeschlossene Hitze entweicht heimlich durch seine Poren. Mitten im Ersticken schenkt er ein kleines Luftloch zum Atmen."},"ICON-2153":{"nm":"Einlegesohlenflicken","de":"Aus der abgenutzten Einlegesohle schneidet man nur die verschlissene Stelle heraus und setzt ein neues Stück ein. Eine Hand, die nicht das Ganze wegwirft, sondern nur die schmerzende Stelle erneuert. Diese kleine Ausbesserung unter dem Fuß macht den Gang des Tages leichter."},"ICON-2154":{"nm":"Bügelnummer","de":"Man drückt die Rückennummer mit dem Bügeleisen fest ins Kleidungsstück. Während die Hitze abkühlt, setzt sich die Ziffer fest auf dem Stoff. Das Siegel, mit dem alle, die dieselbe Nummer tragen, zu einem Team werden."},"ICON-2155":{"nm":"Zehenschutzkappe","de":"Dem Schicksal des Schuhs, dessen Spitze ständig anstößt, stellt sich still die Verstärkungskappe an der Nase entgegen. Die Stelle, die zuerst verschleißt, wird am festesten gemacht. Je länger ein Schuh halten soll, desto solider muss er an der Spitze sein."},"ICON-2156":{"nm":"Kordelzugknoten","de":"In dem Moment, in dem man den Kordelzug der Trainingshose einmal zieht und verknotet, schmiegt sich das locker sitzende Kleidungsstück eng an den Körper. Dieser feste, nicht aufgehende Knoten hält während der wildesten Bewegungen alles an seinem Platz."},"ICON-2157":{"nm":"Söckchen-Rutschband","de":"Diese Misslichkeit, wenn sich die Söckchen immer wieder im Schuh nach unten verkriechen. Ein einziges Band hält dieses Verrutschen auf. Erst so bleibt die kleine, oft übersehene Socke an ihrem Platz."},"ICON-2158":{"nm":"Achsel-Schweißpad","de":"Ein Pad, das man im Voraus an der Stelle anbringt, an der der meiste Schweiß entsteht. Selbst wenn es völlig durchnässt ist, ist von außen nichts zu sehen. Es sind die Dinge, die still und unsichtbar arbeiten, die die Bühne makellos halten."},"ICON-2159":{"nm":"Fersenschlaufe","de":"Zieht man nach dem Anziehen kurz an der Fersenschlaufe, gleitet der Fuß mühelos hinein. Diese kleine Bequemlichkeit, sich dafür nicht hinhocken zu müssen. An hektischen Morgen erweist sich so eine Schlaufe als wahrer Lebensretter."},"ICON-2160":{"nm":"Massagekopfaufsatz","de":"Je nachdem, welche Stelle geklopft wird, wechselt man den Aufsatz. Für jeden verspannten Muskel gibt es die passende Form. Ein Abend, an dem man der Schulter, die den Tag durchgehalten hat, genau die richtige Dosis Trost auswählt."},"ICON-2161":{"nm":"Massagepistolen-Ladestation","de":"Auch die Hand, die den ganzen Tag lang Verspannungen lösen soll, erwacht erst, wenn das Laden vorbei ist. Solange das rote Licht zu Grün wechselt, darf sie kurz ruhen. Erlischt das Blinken, naht leise wieder die Stunde, verspannte Schultern zu streicheln."},"ICON-2162":{"nm":"Massagepistolen-Intensitätsregler","de":"Schwächer, noch ein wenig mehr, bis genau hierhin. Beim Drehen des Reglers verhandelt die Fingerspitze still mit dem eigenen Körper. Das heutige Versprechen, nur so fest zu werden, wie es schmerzt, steht säuberlich zwischen den kleinen Strichen geschrieben."},"ICON-2163":{"nm":"Vibrationsball-Ständerring","de":"Auch ein Ball, der gut rollt, braucht einen Ort, um kurz innezuhalten. Diese runde Halterung nimmt sanft das Verlangen auf, forttrudeln zu wollen, und bewahrt seinen Platz, bis die nächste Runde kommt. Auch Ruhe gehört zur Bewegung."},"ICON-2164":{"nm":"Akupressurstab-Griffkappe","de":"Schon eine kleine Kappe an der Spitze lässt den Schmerz in der Handfläche leise verschwinden. Zwischen Härte und Haut braucht es immer eine weiche Schicht. Diese zärtliche Handbreit rundet zuerst die Stelle ab, die berührt wird."},"ICON-2165":{"nm":"Erdnussrollen-Tasche","de":"Ein kleiner Beutel, der die erdnussförmige Rolle verwahrt. Rollt sie aus einer Ecke der Tasche hervor, kommt gleich der gestrige Vorsatz mit, sich heute doch endlich um den Körper zu kümmern. Ein kleines Täschchen, das ein Versprechen erinnert."},"ICON-2166":{"nm":"Fußroller-Ständer","de":"Wackelt der Platz, dem die Füße sich anvertrauen, wackelt auch die Entspannung. Dieser Ständer, der die Rolle aufrecht hält, verankert den Boden fest und schafft den müden Füßen einen Ort, an den sie sich beruhigt lehnen können. Geborgenheit entsteht dort, wo nichts wankt."},"ICON-2167":{"nm":"Rollenkern-Stopfen","de":"Ein kleiner Stopfen, der das hohle Innere verschließt. Nur wenn das unsichtbare Innere gefüllt ist, bleibt die Außenseite in Form. Diesen Ort, den beim Rollen niemand sieht, trägt das stille Bauteil geduldig mit."},"ICON-2168":{"nm":"Massagestab-Endkappe","de":"Eine rund aufgesetzte Kappe am Ende des Stabes. Damit nichts sich abnutzt, nichts zerkratzt – die Spitze zu schützen ist der Weg, sie lange zu behalten. Die Stelle, die als Erste auf Widerstand trifft, wird hier am zärtlichsten umhüllt."},"ICON-2169":{"nm":"Tape-Abroller mit Klinge","de":"Ein Zug mit einer Hand, und das Tape reißt sauber ab. Auch das Verknoten und Abschließen verlangt einen kleinen Kniff, und diese Klinge kennt das Gefühl für einen ordentlichen Abschluss. Ein sauberes Ende macht das Nächste leichter."},"ICON-2170":{"nm":"Klebekappe fürs Tapeende","de":"Eine Kappe, die das Ende ruhig festhält, damit es sich nicht löst. Anzufangen kann jeder, doch bis zum Schluss haften zu bleiben ist immer schwer. Diese kleine Hand, die die letzte Handbreit hält, trägt still die Verantwortung für den heutigen Abschluss."},"ICON-2171":{"nm":"Handgelenk-Kompressionsbandage","de":"Legt man dem überlasteten Handgelenk eine Schicht darum, kommt der Schmerz einen Takt später an. Wie eine Hand, die einen still festhält, wird Druck manchmal zur zärtlichsten Beschützung. Nicht Einengen, sondern Stützen ist es, was hier geschieht."},"ICON-2172":{"nm":"Schnalle der Knöchelbandage","de":"Das kurze Klicken der schließenden Schnalle beruhigt das Gemüt. Umschließt sie den Knöchel fest, keimt leise der Mut, doch noch einen Schritt weiterzugehen. Ein kleines Geräusch wird zum verlässlichen Aufbruch."},"ICON-2173":{"nm":"Spannschnalle der Kniebandage","de":"So fest man das Band zieht, so verlässlich wird das Knie. Nicht locker, doch auch nicht schmerzhaft – irgendwo dazwischen liegt genau die richtige Kerbe. Die Schnalle vergisst diesen Platz nie und findet ihn jedes Mal wieder."},"ICON-2174":{"nm":"Schere fürs Finger-Tape","de":"Eine kleine Schere, die das um das Gelenk gewickelte Tape geschickt durchtrennt. Ihre Spitze ist rund, damit sie die Haut nicht verletzt. Je pflegender ein Werkzeug ist, desto zärtlicher wird seine Klinge geschliffen – das zeigt diese Schere still."},"ICON-2175":{"nm":"Aufrollrahmen für Kompressionsbinden","de":"Ein Rahmen, der die abgewickelte Kompressionsbinde wieder ordentlich zusammenrollt. Eine Hand, die Gebrauchtes sorgsam einrollt, hält auch beim nächsten Abwickeln alles in Form. In jeder sauber gewickelten Schicht steckt die Ordentlichkeit dieses Tages."},"ICON-2176":{"nm":"Band für das Schienbeinpolster","de":"Ein Band, das das Polster vor dem Schienbein festbindet. Die Stelle zu bedenken, an der es zum Zusammenstoß kommen könnte, ist bereits Vorsorge. Betritt man mit fest verschnürten Beinen das Spielfeld, schwindet die Angst im Herzen um die Hälfte."},"ICON-2177":{"nm":"Clip der Ellbogenbandage","de":"Ein kleiner Clip, der fest verhindert, dass die Bandage herabrutscht. So unscheinbar wie das Greifen nach einem Blatt Papier – doch löst er sich, wird alles locker. Eine kleine Verankerung hält die Beruhigung eines ganzen Tages fest."},"ICON-2178":{"nm":"Griffschlaufe fürs Stretchband","de":"Hält man die Schlaufe und streckt den Körper lang, zeigt sich eine Fingerspitze, die eine Handbreit weiter reicht als gestern. Was sich beim Ziehen dehnt, ist nicht nur der Muskel. Auch das verhärtete Gemüt entfaltet sich dabei ein wenig."},"ICON-2179":{"nm":"Zehenspreizer","de":"Spreizt man die Zehen, die den ganzen Tag im Schuh gefangen waren, zieht Wind in den engen Zwischenraum. Es gibt Dinge auf der Welt, die erst behaglich werden, wenn sie kurz Abstand voneinander nehmen. Auch die Zehenspitzen brauchen etwas Luft zum Atmen."},"ICON-2180":{"nm":"Entspannungskeil für die Wade","de":"Schiebt man ihn wie einen Keil unter die Wade, löst sich das Bein wie von selbst. Ein einziger schräger Winkel lässt das Gewicht eines ganzen Tages leise abfließen. Sich ein wenig anzulehnen und zu liegen – das ist manchmal die bequemste Haltung."},"ICON-2181":{"nm":"Nackenauflage zum Einhängen","de":"Den Nacken hineinlegen und kurz die Augen schließen. Diese kleine Auflage flüstert der Schulter immer vom selben Platz aus zu, dass der schwere Kopf auch einmal abgelegt werden darf. Auch zum Sich-Anlehnen braucht es Mut."},"ICON-2182":{"nm":"Endkappe für den Stretchstab","de":"Eine Kappe, die das Ende des lang ausgestreckten Stabes bedeckt. Ist die Spitze weich, ist man beruhigt, wohin sie auch reicht. Zuerst die Kanten abzurunden, egal wem man sich zuwendet – so beginnt Rücksicht immer lautlos."},"ICON-2183":{"nm":"Noppenkissen für Akupressur","de":"Legt man den Körper auf die höckerig gewölbten Noppen, entweicht mit jedem Druckpunkt ein Stück des Tages. An dieser Grenze zwischen Schmerz und Wohlgefühl gibt die ganztags verhärtete Schulter langsam nach, wie im Ergeben."},"ICON-2184":{"nm":"Atem-Sanduhr zur Entspannung","de":"Bis das letzte Sandkorn gefallen ist, gilt das stille Versprechen, den Atem lang und ruhig zu ziehen. Der feine Sandstrahl zählt leise den Takt von Einatmen und Ausatmen. Auch das hastige Gemüt kommt währenddessen kurz zur Ruhe."},"ICON-2185":{"nm":"Fußballenauflage mit Massageball","de":"Man legt den Ball mitten unter die Fußsohle und drückt sanft. Dem Fuß, der den ganzen Tag den ganzen Körper getragen hat, überlässt diese kleine Auflage nun still ihren Platz, damit er endlich getragen wird. Auch das Tragende darf einmal ruhen."},"ICON-2186":{"nm":"Zugband zur Schulterentspannung","de":"Ein Band mit Schlaufe, das man über die Schulter hängt und zieht. Dehnt man das Band zur verhärteten Stelle hin, löst sich der verspannte Knoten Stück für Stück. Auch Freiwerden braucht manchmal etwas, das die Hand hält."},"ICON-2187":{"nm":"Bahnleinenscheibe","de":"Ein einzelnes rundes Glied der Leine, die das Wasser in Bahnen teilt. Eine freundliche Grenze, gezogen, damit man nicht mit dem Nachbarn zusammenstößt. Kleine Trennwände, die jedem seinen eigenen Weg bewahren, lassen alle bis zum Ende nebeneinander weiterschwimmen."},"ICON-2188":{"nm":"Spannhaken der Bahnleine","de":"Ein Haken, an dem die Bahnleine straff gespannt wird. Zu locker, und sie schwankt in der Welle, zu straff, und sie reißt. Die richtige Spannung zu finden gleicht dem Sich-Zusammennehmen des Gemüts – man tastet sich immer irgendwo dazwischen voran."},"ICON-2189":{"nm":"Farbkappe der Bahnleine","de":"Ein kleiner Verschluss, der jede Bahn in ihrer eigenen Farbe zeigt. Ein Zeichen, damit man den eigenen Weg auch von Weitem sofort erkennt. Mit einer einzigen Farbe niemanden in die Irre gehen zu lassen – so beginnt Orientierung stets bei dieser kleinen Freundlichkeit."},"ICON-2190":{"nm":"Aufhängebrett für Bahnleinen","de":"Ein Brett, an dem die Bahnleine ordentlich aufgehängt wird, solange sie nicht gebraucht wird. In der Hand, die die Leine sauber für den nächsten Start ordnet, ruht still die gelassene Absicht, den heutigen Tag gut abzuschließen."},"ICON-2191":{"nm":"Kurbelgriff der Leinenwinde","de":"Man dreht den Griff im Kreis und rollt die lang ausgelegte Leine wieder ein. Zusammenzutragen, was ausgebreitet wurde, verlangt stets Geduld. Umdrehung um Umdrehung – so vollendet sich der Abschluss, ohne Eile, ganz langsam."},"ICON-2192":{"nm":"Klemme für den Leinenknoten","de":"Eine Klemme, die den Knoten am Ende der Leine fest verbeißt, damit er sich nicht löst. Nicht einmal ein übrig gebliebenes Stück lässt sie achtlos entgleiten. Nur eine Hand, die bis zum Schluss wacht, bewahrt einer langen Leine ihre saubere Form."},"ICON-2193":{"nm":"Schwimmperle der Bahnleine","de":"Eine Schwimmperle der Bahnleine, die auf dem Wasser dümpelt. Um nicht zu sinken, hat sie sich innen voller Luft gefüllt. Manche Leichtigkeit kommt aus einem mühevoll gefüllten, hohlen Herzen – das zeigt die schaukelnde Welle jedes Mal aufs Neue."},"ICON-2194":{"nm":"Bahnnummer-Flagge","de":"Eine kleine Flagge, die die Bahnnummer anzeigt. Ein im Wind flatterndes Stück Stoff sagt klar: 'Hier ist dein Platz.' Ein kleiner, aber deutlicher Wegweiser, der einen ohne Umherirren geradewegs zum eigenen Weg führt."},"ICON-2195":{"nm":"Verbindungshaken der Bahnleine","de":"Ein Haken, der Leine an Leine reiht. Erst mit diesem einen Haken, der den unterbrochenen Weg wieder zusammenfügt, wird die Wasserbahn vollständig. Verbinden heißt am Ende, einem Getrennten leise die Hand zu reichen – die Arbeit eines kleinen Metallstücks."},"ICON-2196":{"nm":"Trittplatte des Startblocks","de":"Die Trittplatte auf der Startlinie fängt das ganze Gewicht des ersten Sprungs auf. In der einen Zehntelsekunde des kraftvollen Abstoßens ist es diese Festigkeit unter der Fußspitze, die den Beginn eines ganzen Rennens anschiebt. Jeder Aufschwung beginnt an einem Ort, an dem man fest auftreten kann."},"ICON-2197":{"nm":"Startgriffstange","de":"Kurz vor dem Startsignal umklammert die Hand fest diese Stange. Nur wenn das zitternde Herz sich irgendwo festhalten kann, gerät der Start nicht ins Wanken. Allein zu wissen, dass es etwas zum Festhalten gibt, macht die nächste Bewegung klarer und fester."},"ICON-2198":{"nm":"Flaggenleine für Rückenschwimmer","de":"Eine Flaggenleine, die dem zur Decke blickenden Schwimmer verrät, dass die Wand sich nähert. Eine Zärtlichkeit, die im Voraus von dem erzählt, was man nicht sehen kann. Mit einem Signal, das sich sorgsam um den Rücken kümmert, wird der letzte Zug sicher."},"ICON-2199":{"nm":"Wendewand-Polster","de":"Ein weiches Polster an der Wand, an der man die Richtung wechselt. Selbst ein harter Aufprall soll nicht wehtun, darum umhüllt es die Stelle des Abstoßens weich. Auf dem Weg der Umkehr liegt immer schon jemandes stille Rücksicht bereit."},"ICON-2200":{"nm":"Anschlagplatte am Ziel","de":"In dem Moment, in dem die Fingerspitze sie berührt, ist alles vorbei. Das Ende eines langen, atemlosen Weges ist am Ende nur dieses eine leichte Klopfen. Ankommen sei nichts Großes, antwortet die Platte still, sondern nur, genau den richtigen Platz zu treffen."},"ICON-2201":{"nm":"Startstreifen der Rutschbahn","de":"Wer am Ende der Schräge steht, hält für einen Moment unweigerlich den Atem an. Überwindet man diese kurze Furcht und gleitet hinab, platzt es mit einem Platsch aus Gischt und Lachen zugleich. Jeder Start beginnt jenseits einer kleinen Angst."},"ICON-2202":{"nm":"Wendemarkierungskegel","de":"Zögert man an einer Abzweigung, spricht dieser kleine Punkt als Erster zu einem. Hier kannst du umkehren, verirr dich nicht. Manch einer findet dank dieser einen Farbe seine Richtung wieder und geht weiter."},"ICON-2203":{"nm":"Winkelkeil des Startblocks","de":"Der halbe Takt kurz vor dem Sprung, in dem sich der Körper am tiefsten duckt. Damit die Fußspitze nicht abrutscht, liegt dort ein kleiner Tritt, der den Winkel stützt. Aus dieser Neigung wird jeder hohe Sprung geboren."},"ICON-2204":{"nm":"Eckenschutzkappe für Wände","de":"Damit ein Stoß beim Herumtoben nicht wehtut, hat die Ecke ihre Schärfe sanft abgegeben. Der Wunsch, niemanden sich verletzen zu lassen, wurde Stück für Stück abgeschliffen und haftet nun an der Wand. Der zärtlichste Schutz ist meist gerade so still."},"ICON-2205":{"nm":"Aufhängehaken für den Rettungsring","de":"Für gewöhnlich hängt er dort nur, ganz beiläufig. Doch in dem Moment, in dem jemand ins Wasser fällt, ist genau dieser Ort der erste, nach dem die Hand greift. Auch diese Art von Verlässlichkeit gibt es auf der Welt – am liebsten ungenutzt."},"ICON-2206":{"nm":"Rettungshakenstange","de":"Ein langer Arm, der eine unerreichbare Entfernung mit einem Mal verkürzt. Reicht die Hand nicht aus, wird dieser Haken an ihrer Stelle zur Hand. Retten heißt am Ende, jemandem in der Ferne die eigene Fingerspitze zu reichen."},"ICON-2207":{"nm":"Duschkopf am Beckenrand","de":"\"Vor dem Reingehen bitte kurz abspülen.\" Wie die vertraute Ansage der Aufsicht ergießt sich das Wasser über den Kopf. Mit einem kalten Schwall löst sich der Staub des Tages und rinnt einfach fort."},"ICON-2208":{"nm":"Rutschfeste Bodenfliese","de":"Feine, aufgeraute Rillen, damit der bloße Fuß nicht ausrutscht. An einem Ort, den niemand beachtet, halten sie die Fußsohle still fest. Die verlässlichste Sicherheit verbirgt sich meist an einem unscheinbaren Platz."},"ICON-2209":{"nm":"Wassertiefe-Schild","de":"Bevor der Fuß hineingeht, verrät die Zahl zuerst die Tiefe. Was einen ahnungslos erschrecken könnte, lässt sich nach einem Blick ruhig einschätzen. Dieses Schild tut nur eines: eine kleine Vorbereitung zu ermöglichen."},"ICON-2210":{"nm":"Bojenleine der Sicherheitslinie","de":"Eine bunte Leine, die auf dem Wasser treibt und Bereiche voneinander trennt. Bis hierher ist es sicher, versprechen sich die Bojen, Hand in Hand. Erst weil es eine Grenze gibt, kann man beruhigt und nach Herzenslust schwimmen."},"ICON-2211":{"nm":"Fußdesinfektionsbecken","de":"Bevor man ins Wasser steigt, verweilt der bloße Fuß kurz in diesem kleinen Becken. Ein knappes Ritual, bei dem die Reinheit schon bei der Fußspitze beginnt. Sauberkeit entsteht immer aus solch einer kleinen Sorgfalt für den ersten Schritt."},"ICON-2212":{"nm":"Warnkegel für nassen Boden","de":"Ein gelber Kegel verlangsamt den Schritt ganz sanft. 'Hier ist es nass, Vorsicht' – eine Rücksicht, die statt mit Worten in Farbe spricht. Diese kleine Warnung bewahrt still den Tag von jemandem, der beinahe gestürzt wäre."},"ICON-2213":{"nm":"Erste-Hilfe-Wandkasten","de":"Der weiße Kasten an der Wand öffnet sich nur selten. Doch in genau dem Moment, in dem er sich öffnet, wird er zur Erleichterung für jemanden. Ein Notfall wartet immer still am allernächsten Ort."},"ICON-2214":{"nm":"Kescher für die Wasseroberfläche","de":"Blätter und Staub, die auf der Oberfläche treiben, werden sanft aufgefangen. Klarheit kommt nicht von selbst – jeden Tag muss eine Hand sie einmal herausfischen. Hinter ruhigem Wasser steht immer ein fleißiger Kescher."},"ICON-2215":{"nm":"Schlauch des Bodenreinigungsroboters","de":"Auch in der Nacht, wenn alle schlafen, tastet er sich langsam über den Boden. Der fleißigste Arbeiter zu einer Stunde, die niemand sieht. Die Klarheit des Morgens ist die Spur, die dieser Schlauch die ganze Nacht gezogen hat."},"ICON-2216":{"nm":"Chlordosierbehälter","de":"Auch das Bewahren klaren Wassers braucht genau die richtige Menge. Zu viel, und es wird beißend, zu wenig, und es trübt sich – ein Gleichgewicht dazwischen. Eine unsichtbare Hand stellt jeden Tag still diese Skala nach."},"ICON-2217":{"nm":"Wasserprobenflasche","de":"In einer kleinen Flasche wird ein Schluck Wasser gesammelt und nach dem heutigen Befinden gefragt. Für das Auge sieht alles gleich aus, doch die Zahlen lügen nicht. Beruhigung ist etwas, das so jeden Tag einmal überprüft wird."},"ICON-2218":{"nm":"Rechen zum Einholen von Schwimmbrettern","de":"Ein langer Rechen, der treibende Bretter und Schwimmkörper zusammenzieht. Eine Hand, die Verstreutes einsammelt, gleicht auf seltsame Weise dem Herzen. Auch Unordnung wird ordentlich, wenn man sie einmal zusammenkehrt."},"ICON-2219":{"nm":"Abflussabdeckung","de":"Ein engmaschiges Netz, das den Weg bewacht, auf dem das Wasser abfließt. Es entscheidet still, was hindurchgelassen und was zurückgehalten wird. Auch das Loslassen braucht einen Filter, sagt dieses kleine Netz wortlos."},"ICON-2220":{"nm":"Thermometerboje","de":"Eine kleine Vorhut, die auf dem Wasser treibt und die Temperatur abliest. Ob es kalt oder angenehm ist, verrät sie zärtlich, bevor der Körper es berührt. Die erste Beruhigung beim Einstieg ins Wasser beginnt immer bei dieser Boje."},"ICON-2221":{"nm":"Poolabdeckroller","de":"Ein Griff, der die breite Abdeckung sorgfältig aufrollt und an ihren Platz bringt. Ein Werkzeug, das weiß, wann man ausbreitet und wann man einholt, wirkt irgendwie verlässlich. In der Ruhezeit deckt es sogar das Wasser wie mit einer Decke zu."},"ICON-2222":{"nm":"Skimmerkorb","de":"Ein Korb, in dem sich alles Treibgut, das an der Oberfläche umherirrte, zuletzt sammelt. Weil an einer unsichtbaren Stelle ein Gefäß den Unrat auffängt, bleibt das Wasser darüber immer klar. Hinter aller Sauberkeit häuft sich stille Mühe an."},"ICON-2223":{"nm":"Bademützen-Trockenhaken","de":"Die feuchte Bademütze hängt hier verkehrt herum zum Trocknen. Während Tropfen für Tropfen leise herabfällt, kommt die Mütze langsam wieder zu Atem. Trocknen ist am Ende nur ein anderes Wort für Geduld."},"ICON-2224":{"nm":"Schulterträger-Clip","de":"Ein kleiner Ring, der den Träger festhält, damit er nicht von der Schulter rutscht. An einer unsichtbaren Stelle wacht er still über den gepflegten Sitz. Ordentlichkeit vollendet sich immer über solch unscheinbaren Stützen."},"ICON-2225":{"nm":"Bademützen-Aufbewahrungsbeutel","de":"Ein Beutel, in dem die nassen Bademützen eine nach der anderen ihren Platz finden. Eine kleine Bleibe, die alles Streuende in eine Umarmung nimmt. Ordnung ist die liebevolle Gewohnheit, nichts verlieren zu wollen."},"ICON-2226":{"nm":"Brustpolster für Badeanzug","de":"Ein Polster, das sich sanft im Inneren des Anzugs verbirgt. Von außen unsichtbar, richtet es doch leise die Schultern der Trägerin auf. Manche Zuversicht füllt sich nicht von außen, sondern still von innen."},"ICON-2227":{"nm":"Bademützen-Namensklammer","de":"Eine kleine Klammer, die am Rand der Bademütze ein Namensschild festhält. Zwischen lauter gleich aussehenden Dingen sagt sie klar: „Das hier gehört mir.“ Eine einzige Markierung beendet jede Verwechslung auf der Stelle."},"ICON-2228":{"nm":"Reißverschlusshilfe für Badeanzug","de":"„Kannst du mir bitte den Reißverschluss am Rücken hochziehen?“ Diese kleine Öse greift anstelle einer Hand genau dorthin, wo man allein nicht hinkommt. Sie ist die freundliche Distanz, die beim letzten Stück noch mit anpackt."},"ICON-2229":{"nm":"Bademützen-Spannbrett","de":"Es stützt die Bademütze, die sich sonst gern einrollt, gerade aufgestellt ab. Eine Stütze, die still dabei hilft, dass Verbogenes wieder seine Form findet. Erst eine ausgleichende Hand lässt irgendetwas wieder gerade werden."},"ICON-2230":{"nm":"Taillenzug-Schnalle für Badeanzug","de":"Ein Verschluss, der die Taille passend umfasst, damit nichts verrutscht. Nicht zu eng, nicht zu locker – genau das rechte Maß. Behaglichkeit wohnt immer irgendwo dazwischen."},"ICON-2231":{"nm":"Wendeklammer für Bademützen","de":"Eine Klammer, die die auf links gedrehte Bademütze packt und mit einem Ruck zurechtrückt. Verkehrtes richtig herumzudrehen, hat einen ordentlich erfrischenden Griff. Die kleine Freude der Ordnung kommt aus genau solch beiläufigen Dingen."},"ICON-2232":{"nm":"Kickboard-Griffschlaufe","de":"Eine Schlaufe, die sich um die Hand legt, damit das Schwimmbrett nicht entgleitet. Selbst wenn die Strömung zerrt, gibt es etwas zum Festhalten – das beruhigt ungemein. Das Zittern des allerersten Beinschlags haftet noch immer an diesem Band."},"ICON-2233":{"nm":"Pull-Buoy-Schnürband","de":"Ein Band, das die Boje fest zwischen den Beinen hält. Erst wenn nichts verrutscht, kann man sich ganz auf die Haltung konzentrieren. Auf gut Gehaltenem wächst die Übung des Tages Spanne um Spanne."},"ICON-2234":{"nm":"Flossen-Wandhalterung","de":"Hängen Flossen ordentlich nebeneinander an der Wand, sehen sie aus wie eine Schar rastender Enten am Ufer. Füße, die eben noch geschwommen sind, schütteln das Wasser ab und warten auf morgen. Selbst die Pause hat hier etwas rundlich Niedliches."},"ICON-2235":{"nm":"Kickboard-Kantenschutz","de":"Eine kleine Kappe, sanft über die Ecke des Schwimmbretts gestülpt. Sie sorgt dafür, dass Stöße nicht schmerzen und Abnutzung nicht schadet. Wer etwas lange behalten will, beginnt damit, die Kanten zu schonen."},"ICON-2236":{"nm":"Flossen-Aufbewahrungsnetz","de":"Flossen, die Schwimmhäuten ähneln, sonnen sich im Netz. Wie Enten, die frisch aus dem Wasser ihr Gefieder trocknen, trocknen sie hier ganz allmählich. Ein gemächliches Nickerchen vor dem nächsten Schwimmzug."},"ICON-2237":{"nm":"Namensanhänger für Pull Buoy","de":"An jeder Boje hängt ein Namensschild, das den Besitzer klar benennt. Je mehr Menschen sich etwas teilen, desto beruhigender ist ein deutliches „das gehört wem“. Ein kleines Etikett schafft schon Ordnung."},"ICON-2238":{"nm":"Abtropfständer für Kickboard","de":"Eine schräge Ablage, auf der das im Schwimmbrett gesammelte Wasser leise abfließt. Erst wer loslässt, was er in sich trug, wird wieder leicht, sagt die Ablage still. Der erste Schritt zum Trocknen ist, gut abgestützt zu sein."},"ICON-2239":{"nm":"Schnallenverschluss für Flossen","de":"Ein kleines Teil, das den Flossenriemen passend am Fuß festzieht. Zu locker, und sie rutschen ab; zu fest, und es tut weh – ein feines Zwischenmaß. Wie eine Ente mit Schwimmhäuten mühelos vorankommt, braucht es genau dieses eine Stück."},"ICON-2240":{"nm":"Beinschlag-Rhythmuschip","de":"Ein kleiner Chip, der bei jedem Beinschlag den Takt vorgibt. Eins, zwei, drei – sitzt der Rhythmus erst im Körper, wird selbst das Wasser zum Lied. Dass auch das Schwimmen einen Takt hat, lehrt dieser Chip ganz leise."},"ICON-2241":{"nm":"Nassbadeanzug-Beutel","de":"In der Tasche, die das Schwimmbad verlässt, sichere ich mir immer als Erstes meinen Platz. Mögen die anderen Sachen auch schief schauen, was soll's – Nasses muss eben getrennt verwahrt werden, damit am Ende alle zusammen trocken bleiben. Die Quarantänestation der Feuchtigkeit, das ist das liebevolle Amt, das mir zufällt."},"ICON-2242":{"nm":"Wasserausdrückplatte","de":"Feuchtigkeit hat die Eigenart, bei Druck heimlich zu entwischen. Einmal fest gedrückt, zweimal fest gedrückt – erst wenn man sie auf die Platte legt und ihr Gewicht aufbürdet, gibt sie endlich auf. Für jemanden, der sonst selten seine Handgelenkskraft braucht, ist solch eine Bühne eine Seltenheit."},"ICON-2243":{"nm":"Trennwand für Schwimmtasche","de":"Steckt man alles in einen Beutel, vermischen sich Nasses und Trockenes miteinander. Dazwischen schiebt sie sich leise und zieht eine Grenze. Wenn schon ein einziges Fach Frieden bringt, ist Versöhnung vielleicht überraschend einfach."},"ICON-2244":{"nm":"Wasserdichter Schuhbeutel","de":"Er schluckt die sandigen Schuhe ganz und verzieht dabei keine Miene. Was drinnen auch geschehen mag, draußen bleibt es trocken – das ist der Anstand, den Wasserdichtheit wahrt. Ein Beutel mit dichtem Mund ist überall willkommen."},"ICON-2245":{"nm":"Ablasskappe für Schwimmtasche","de":"Dreht man die Kappe, rinnt der Tag, der sich am Boden der Tasche gesammelt hat, in einem Zug hinaus. Das Aufräumen nach vergnügtem Spiel hängt immer an diesem einen kleinen Loch. Auch Loslassen will gut durchdacht sein."},"ICON-2246":{"nm":"Saugmatte für die Tür","de":"Sie liegt still vor der Haustür und fängt bei jedem eintretenden Schritt die Nässe auf. Niemand bemerkt es, aber der Fußboden weiß es genau: Heute ist niemand ausgerutscht. In einem stillen Platz wohnt ein stiller Lohn."},"ICON-2247":{"nm":"Auffangschale für nasse Bademützen","de":"Findet die abgestreifte Bademütze keinen Ort, nehme ich sie auf. Schale genannt, trage ich statt Speisen doch nur Wassertropfen – aber wer jemandem einen Platz bereitet, darf sich getrost eine würdige Ablage nennen."},"ICON-2248":{"nm":"Handtuchklammer","de":"Auf der Wäscheleine ein Handtuch fest im Griff halten. Mag der Wind noch so necken, mein Stolz ist, niemals loszulassen. Bis es in der Sonne wieder flauschig wird, lässt eine einmal ergriffene Hand niemals zuerst los."},"ICON-2249":{"nm":"Aufhänger für wasserdichte Beutel","de":"Kaum am Haken eingehängt, bekommt die zuvor umherirrende Tasche endlich eine Adresse. Auch wenn sie nur ein Wandstück leiht, um daran zu hängen – gibt es etwas Verlässlicheres als einen Platz ohne Angst vor Verlust?"},"ICON-2250":{"nm":"Einlassarmband für die Wasserrutsche","de":"Die Vorfreude, die geduldig auf ihre Reihe wartete, ist ganz in diesem kleinen Band gebunden. Erst wenn es ums Handgelenk geschnallt ist, beginnt die Schlange vor der Rutsche zu wogen – Einlass bedeutet vielleicht, ein Versprechen ums Handgelenk zu legen."},"ICON-2251":{"nm":"Wasserrutschmatten-Bruchstück","de":"Wer läuft, merkt gar nicht, dass die Matte darunter gebrochen ist. Das Stück, das verhindern soll, dass jemand ausrutscht, macht sich erst bemerkbar, wenn es fehlt. Manches wird in dieser Welt nur durch seine Abwesenheit sichtbar."},"ICON-2252":{"nm":"Schlüssel-Wasserschutzband für Spind","de":"Mein ganzes Leben widme ich dem Schutz des Spindschlüssels vor dem Wasser. Selbst wenn ich mit ums Planschen komme, halte ich den Schlüssel trocken. Ohne ihn kommt man nicht an seine Klamotten – das ist schon eine ganz schöne Verantwortung."},"ICON-2253":{"nm":"Startampel für die Wasserrutsche","de":"In dem kurzen Moment, in dem es von Rot auf Grün springt, schlägt oben auf der Rutsche jedes Herz im Gleichtakt. Dass eine so kleine Anzeigetafel so viel Vorfreude in sich trägt – das hätte man vorher kaum gedacht."},"ICON-2254":{"nm":"Schnalle der Schwimmweste im Wildwasserpool","de":"Diese Schnalle hält die Menschen fest, die im Wildwasserpool dahintreiben. Erst wenn es klick macht, überlässt man sich beruhigt der Strömung. Manchmal beginnt das Gefühl der Sicherheit mit einem ganz kleinen Verschluss."},"ICON-2255":{"nm":"Signalflagge am Wellenbad","de":"Sie kündigt an, wann die Wellen kommen. Geht die Flagge hoch, jubeln alle; geht sie runter, verschnauft man kurz. Am Beckenrand gibt eine einzige Stoffbahn den Takt vor."},"ICON-2256":{"nm":"Rutschennummern-Anhänger","de":"Wenn man die Nummer der eigenen Schlange am Hals trägt, gibt es kein Durcheinander mehr. Ein einziges Nummernschild regelt die Reihenfolge – Ordnung kann so klein anfangen."},"ICON-2257":{"nm":"Auflade-Token für das Armband","de":"Einfach ans Armband halten, fertig aufgeladen. Im Zeitalter, in dem man auch im Wasser ohne Bargeld auskommt, übernimmt dieser kleine Token die Arbeit der Geldbörse. Leichte Handgelenke, leichtes Gemüt."},"ICON-2258":{"nm":"Griffkappe der Wasserkanone","de":"Den Griff der Wasserkanone muss man fest packen, um richtig zu zielen. Fehlt die Kappe, dreht sich alles in der Hand – und der Ausgang der sommerlichen Wasserschlacht hängt an genau diesem kleinen Abschluss."},"ICON-2259":{"nm":"Sandburg-Turmform-Becher","de":"Feuchten Sand fest hineindrücken, umkehren – und schon erhebt sich ein kleines Türmchen. Diesen Becher versteht am besten, wer immer wieder aufbaut, obwohl er weiß, dass alles zerfallen wird. Für Sandarchitekten ist die Form der Bauplan."},"ICON-2260":{"nm":"Sandharkenzinken","de":"Zieht man die Harke durch den Sand, bleiben ordentliche Rillen zurück. Auch wenn die Wellen das Muster gleich wieder auslöschen werden, zieht die Harke fleißig ihre Furchen. Etwas Vergängliches mit Sorgfalt zu erschaffen hat seinen ganz eigenen Reiz."},"ICON-2261":{"nm":"Sonnenschirm-Erdanker","de":"Damit der Sonnenschirm nicht im Wind davonfliegt, hält dieser Anker stumm und geduldig dagegen. Das Schattenspenden übernimmt nicht der bunte Stoff, sondern das schwere Gewicht, das unten steckt. Unsichtbare Schwere ist oft die verlässlichste."},"ICON-2262":{"nm":"Griff des Sandreuters","de":"Schüttelt man den Sand durch das Sieb, bleiben Muschelschalen und kleine Schätze in der Hand. Mit dem Griff hin und her – die Hälfte der Schatzsuche am Strand wird durch dieses Netz entschieden."},"ICON-2263":{"nm":"Muschelförmige Sandform","de":"Feuchten Sand hineindrücken, klopfen, umstülpen – und schon reihen sich handtellergroße Muscheln am Strand auf. Echte Muscheln kann nicht jeder finden, aber diese Form kann jeder nachbauen. Ein kleines Sommerversprechen."},"ICON-2264":{"nm":"Neigungsstellpin für den Sonnenschirm","de":"Wenn die Sonne weiterwandert, muss der Schirm mitdrehen. Einen Pin ziehen, neu einstecken – und der Schatten schleicht sich ein Stück zur Seite. Der Trick, dem Licht auszuweichen, steckt in diesem kleinen Winkel."},"ICON-2265":{"nm":"Schutzkappe für die Schaufelspitze","de":"Aufgesteckt auf die scharfe Spitze, ist die Tasche wieder sicher. Der mutige Graber von vorhin wird durch eine einzige Kappe zum harmlosen Spielzeug. Wer die Spitze verbergen kann, zeigt damit Rücksicht."},"ICON-2266":{"nm":"Eckklemme für die Strandmatte","de":"Versucht der Wind, die Mattenecke hochzuheben, beiße ich fest zu. Vier störrische Klemmen halten einen Platz am Sandstrand. Ein windstiller Nachmittag ist das gemeinsame Werk dieser kleinen Helfer."},"ICON-2267":{"nm":"Kleiderhaken am Sonnenschirm","de":"Einfach am Schirmmast einhaken, und nasse Sachen trocknen im Schatten. Das Sonnenlicht wird gemieden, der Wind genutzt – ein einziger Haken richtet die improvisierte Wäscheleine ein. Auch am Strand steckt Haushaltsweisheit drin."},"ICON-2268":{"nm":"Wasserdichte Handy-Umhängetasche","de":"Wenn das Handy darin hängt, hat man auch im Wasser den Mut zum Fotografieren. Die Tasche schützt die Lust, jeden Moment festzuhalten. Als Leibwächter der Erinnerungen ist sie ziemlich tüchtig."},"ICON-2269":{"nm":"Wasserdichter Beutel für nasse Kleidung","de":"Sie nimmt nasse Sachen ohne ein Wort des Widerspruchs auf. Dass kein Tropfen nach außen kommt, ist ihr Ehrgeiz – deshalb hält sie den Mund fest geschlossen und bewacht ihren Platz in der Tasche. Sauberer Abschluss kommt von ihr."},"ICON-2270":{"nm":"Fußriemen der Wassersandale","de":"Damit die Sandale nicht vom Fuß rutscht, schmiegt sich der Riemen sacht ums Ristgelenk. Selbst wenn man über den Sandstrand trippelt, hält ein einziger Riemen den Halt. Ein verlässlicher Begleiter jeden Schritts, der nie im Rampenlicht steht."},"ICON-2271":{"nm":"Wasserdichtes Kartenhalter-Etui zum Umhängen","de":"Es trägt Eintrittskarte und EC-Karte um den Hals und macht überall mit beim Plantschen. Damit man sorglos springen kann, stellt es sich schützend vor die Karte. Das ist die Haltung eines verlässlichen Bodyguards."},"ICON-2272":{"nm":"Putztuch-Etui gegen beschlagene Taucherbrille","de":"Einmal mit dem Tuch über die beschlagene Innenseite der Taucherbrille wischen, und die Unterwasserwelt erscheint wieder klar. Ein kleines Putzetui ist der Schlüssel, der den trüben Blick wieder öffnet."},"ICON-2273":{"nm":"Bürste zum Abklopfen von feuchtem Sand","de":"Sie streicht auch den Sand zwischen den Zehen sanft heraus. Die letzte Hand, die den Spuren eines aufregenden Tages am Meer vor der Haustür ein Ende bereitet. Nach einem einzigen Bürsten verabschiedet sich auch der letzte Sand des Tages."},"ICON-2274":{"nm":"Wasserdichte Münz-Reißverschlusstasche","de":"Sie schließt ein paar Münzen fest im Reißverschluss ein. Auch wenn alles nass wird, klingen die Münzen noch – das Notgeld für den Kiosk ist bis zum Schluss gerettet. Klein, aber eine tüchtige Haushaltsführerin."},"ICON-2275":{"nm":"Handtuchrollband für Wasserausflüge","de":"Das gerollte Handtuch einmal mit dem Band schnüren, und es hängt am Rucksackgurt. Freie Hände, Handtuch an der Schulter – das Geheimnis eines leichten Badetags steckt in diesem kleinen Bündel."},"ICON-2276":{"nm":"Abschlusskappe des wasserfesten Schlüsselbands","de":"Die Schlussschnalle des Bandes, das den Schlüssel vor Wasser schützt. Erst wenn die Kappe einrastet, springt man beruhigt ins Becken. Sie verantwortet das letzte Einschnappen – ein kleines, lückenloses Schlusszeichen."},"ICON-2277":{"nm":"Schnorchel-Einlassstopfen","de":"Nimmt man ihn in den Mund, öffnet sich der Atemweg, und die Unterwasserwelt rückt nah heran. Dieser kleine Stopfen ermöglicht das Atmen unter Wasser. Dass man so jemandem Atem leihen kann, macht doch Freude."},"ICON-2278":{"nm":"Anti-Beschlag-Pad für die Tauchermaske","de":"Beschlägt die Maske, ist der Ausflug in die Unterwasserwelt getrübt. Eine einzige Lage dieses Pads hält das Beschlagen fern – die klare Sicht ist das stille Verdienst dieser unsichtbaren Schicht."},"ICON-2279":{"nm":"Zehenklemme der Flossen","de":"Sie klemmt das Ende der Flosse fest ans Bein, damit beim Treten kein Spiel entsteht. Damit die Kraft jedes Beinschlags nicht verloren geht, zieht die Klemme am Zehenende in aller Stille einen festen Knoten."},"ICON-2280":{"nm":"Maskenband-Abdeckung","de":"Die Abdeckung verhindert, dass das Maskenband beim Abziehen an den Haaren zieht. Sie nimmt das Zwicken bei jedem Abnehmen weg – eine Lage voller Fürsorge. Was ein kleines Stück Stoff alles an Freundlichkeit birgt."},"ICON-2281":{"nm":"Schnorchel-Ablassventil-Kappe","de":"Auch beim Atmen gibt es kleine Lecks. Ein winziges Ventil leitet das eindringende Wasser still ab und hält die Atemöffnung frei. Das Meer vergisst diese unscheinbare Arbeit nicht."},"ICON-2282":{"nm":"Flossenaufhängehaken","de":"Hängt man die Flossen ordentlich an den Wandhaken, kehrt auch in den unordentlichsten Geräteraum ein ruhiges Gefühl ein. Die Dinge an ihren Platz zu hängen ist das leiseste Versprechen an den nächsten Tauchgang."},"ICON-2283":{"nm":"Nasenpolster der Tauchermaske","de":"Dieses kleine Pad drückt sanft gegen die Nase. Dank dieser kleinen Fürsorge, die verhindert, dass Wasser eindringt, verliert das Gesicht auch im kalten Meer nicht seine Fassung."},"ICON-2284":{"nm":"Schnorchel-Oberschutz","de":"Der Schutz, der das Ende des Schnorchels umschließt, drängt beim Einbrechen einer Welle das Wasser sanft zur Seite. Je unauffälliger ein Bauteil arbeitet, desto tiefer trägt es die Sicherheit jedes Atemzugs."},"ICON-2285":{"nm":"Gleitstreifen auf der Flossenunterseite","de":"Ein schmaler Streifen auf der Flossenunterseite. Er ist die Reibung, die den Fuß auf nassem Deck festhält. Sicherheit beginnt immer in solchen kleinen Rillen – und zwar leise."},"ICON-2286":{"nm":"Ventilabdeckung der Sauerstoffflasche","de":"Eine Kappe, die das Ventil der mit Luft gefüllten Flasche bedeckt. Damit kein Staub hineinkommt, damit die Atemwege sauber bleiben. Abdecken heißt, schon jetzt für den ersten Atemzug des nächsten Menschen zu sorgen."},"ICON-2287":{"nm":"Reglatormund-Schutzkappe","de":"Die Stelle, die den Mund berührt, muss stets die sauberste sein. Diese eine Kappe auf dem Mundstück schützt das Atemtor wortlos vor Salzwind und Sand."},"ICON-2288":{"nm":"Reißverschluss-Zuglaschen-Ring des Tauchanzugs","de":"Ein kurzer Zugring am Reißverschluss des Tauchanzugs. Er ist angebracht, damit man ihn auch mit von der Kälte steifen Fingern auf Anhieb greifen kann. In jeden Handgriff am Anzug ist das Nachdenken von jemandem eingewoben."},"ICON-2289":{"nm":"Schutzkappe für das Luftdruckmessgerät","de":"Eine Schutzkappe über dem Glas des Messgeräts, das die verbleibende Luft anzeigt. Die Anzeige darf nicht trüb werden. Je wichtiger die Skala für das Leben ist, desto sorgfältiger wischt man sie ab und deckt sie zu."},"ICON-2290":{"nm":"Bleigewichtsgurt-Schnalle","de":"Menschen, die mit Gewichten um die Hüfte in die Tiefe hinabsteigen. Im Bruchteil einer Sekunde, in der die Schnalle auf- und zugeht, sammelt sich die Entscheidung zwischen Auftauchen und Abtauchen still in der Fingerkuppe."},"ICON-2291":{"nm":"Handgelenksband der Taucherleuchte","de":"Im pechschwarzen Wasser hält ein am Handgelenk gebundenes Band die Lampe fest. Selbst wenn man die Hand öffnet, folgt das Licht. Mitten in der Dunkelheit das kleine Licht nicht zu verlieren – das gibt Halt."},"ICON-2292":{"nm":"Schlauchordnungsclip","de":"Ein kleiner Clip, der den Schlauch bündelt. Wer Verhedderungen vorher verhindert, tastet auch in der Eile nicht umher. Ordnung ist die stille Freundlichkeit, die man seinem künftigen Selbst erweist."},"ICON-2293":{"nm":"Fingerverstärkung des Taucherhandschuhs","de":"An jede Fingerkuppe ist ein Verstärkungsstück genäht. Da Stellen, an denen man Leinen zieht und Felsen greift, als erstes verschleißen, wurde eine Lage hinzugefügt, um diesen Verschleiß schon im Voraus abzufangen."},"ICON-2294":{"nm":"Standfußring der Sauerstoffflasche","de":"Ein Standfußring, der die schwere Flasche aufrecht hält. Er umschließt das kippgefährdete Gewicht rund und schenkt ihm Balance. Stützen heißt: dem anderen das Platzangebot geben, um nicht zu fallen."},"ICON-2295":{"nm":"Schutzkappe für die Surfboard-Finne","de":"Eine Kappe, die die scharfe Spitze der Finne unter dem Board abdeckt. Damit man beim Laufen durch den Sand nicht verletzt wird, lässt man die Schneide, die sonst Wellen zerschneidet, für eine Weile schlafen. In der Ruhe darf auch die schärfste Klinge stumpf sein."},"ICON-2296":{"nm":"Schutzkappe für das Paddel-Blattende","de":"Eine Schutzkappe, die das Ende des Paddelblatts schützt. Sie hält Kratzer durch Felsen davon ab, die Wasserführung zu stören. Wer das Ende schont, kommt mit jedem Schlag ein Stück weiter."},"ICON-2297":{"nm":"Kajak-Paddel-Handgriff","de":"Ein Griff, der dort umwickelt ist, wo Hand und Paddel aufeinandertreffen. Er stützt die Stelle, an der sonst Blasen entstehen, damit die Hand das Paddel auch beim Stromauffahren nicht verflucht. Ein vertrauter Griff lässt das Halten leichter werden."},"ICON-2298":{"nm":"Surfwachs-Aufbewahrungsdose","de":"Eine kleine Blechdose, die ein Stück Wachs verwahrt. Der Zauber, der den Fuß auf dem Board hält, wird immer aus dieser handgroßen Dose geholt. Aus einer ordentlichen Dose beginnt die Vorbereitung auf den Tag."},"ICON-2299":{"nm":"Fußschlaufen-Spannring des Leash","de":"Ein Ring, der den Leash an der Fußschlaufe festzieht. Auch wenn eine große Welle mitreißt, lässt er das Board nicht los – eine Schlaufe, die sagt: Ich verliere dich nicht. Verbindung ist das Versprechen, nicht davonzutreiben."},"ICON-2300":{"nm":"Luftventilstopfen des aufblasbaren Paddle-Boards","de":"Der Stopfen, der die Luft im Board hält, das sich durch Aufblasen verhärtet. Geöffnet legt es sich flach zusammen, geschlossen steht man darauf auf dem Wasser. In einem kleinen Stopfen steckt ein ganzer Tag – aufgepumpt und wieder zusammengeklappt."},"ICON-2301":{"nm":"Sitzpolster-Befestigungsband für das Kajak","de":"Ein Band, das das Kissen am Sitz festzurrt. Damit das Weiche nicht wegrutscht, während man lange sitzt und paddelt, wird es fest an seinen Platz gebunden. Auch Bequemlichkeit braucht manchmal einen festen Knoten."},"ICON-2302":{"nm":"Surfboard-Nasen-Bumper","de":"Der Bumper, der den Bug des Boards umhüllt. Je mehr Stöße die Nase einsteckt, desto früher braucht sie eine weiche Polsterung. Vorne das Sanfte hinzuzufügen bedeutet: Ich habe vor, dich lange zu benutzen."},"ICON-2303":{"nm":"Rollverschluss-Schnalle der Wasserdichttasche","de":"Eine Schnalle, bei der man zwei- oder dreimal faltet und zumacht, damit kein einziger Tropfen eindringt. Kostbares trocken zu halten kostet eine Handbewegung mehr. Dieses eine feste Zuziehen wird zur Gewissheit."},"ICON-2304":{"nm":"Futsalnetz-Fragment","de":"Ein Stückchen von dem Netz, das einst das Tor in Schwingung versetzte. Es erinnert in jedem Faden an das Jubeln des Einschussmoments. In jedem Knoten steckt ein Tor, und an jeder zerschlissenen Stelle lebt das Spiel noch."},"ICON-2305":{"nm":"Pumpen-Nadel für Fußball","de":"Die Pumpennadel, die einem schlaffen Ball wieder Luft gibt. Das läppische Leder, das lustlos herumlag, federt wieder. Auffüllen heißt: ein stockendes Spiel wieder zum Leben erwecken."},"ICON-2306":{"nm":"Ecksfahnen-Standfuß","de":"Der Standfuß, der die Fahne an der Spielfeldecke aufrecht hält. Als kleine Markierung, die eine Grenze anzeigt, gibt er dem Erdboden erst die Form eines Spielfelds."},"ICON-2307":{"nm":"Schienbeinschoner-Befestigungsband","de":"Das Band, das den Schienbeinschoner am Bein festzurrt. Es hält die schutzwürdige Stelle sicher umschlungen, damit jeder Schritt auch im harten Zweikampf nicht zögert."},"ICON-2308":{"nm":"Stollen-Ersatzpin","de":"Ein Pin zum Auswechseln abgenutzter Stollen gegen neue. Die kleinen Zähne, mit denen der Fuß den Rasen greift. Wer nicht ausrutschen will, muss seinen Untergrund manchmal von Grund auf erneuern."},"ICON-2309":{"nm":"Ventilkappe des Fußballs","de":"Die kleine Ventilkappe, die das Luftloch des Balls verschließt. Sie sorgt dafür, dass die eingepumpte Luft nicht entweicht. Die Spannung zu erhalten ähnelt dem Nichtaufgeben der Anspannung bis zum nächsten Spiel."},"ICON-2310":{"nm":"Markierungshütchen für Linien","de":"Ein Hütchen, das auf dem Boden eine Linie zieht und den Weg aufteilt. Bis hierher wir, ab dort ihr. Ein kleines Hütchen verwandelt einen unordentlichen Freiplatz in einen Spielort mit Regeln."},"ICON-2311":{"nm":"Schuhbürste für Futsalschuhe","de":"Eine Bürste, die den in den Fugen der Futsalschuhe steckenden Staub herausfegt. Nach dem Spiel hat sich am Schuh ein ganzer Tagesdreck angesammelt. Das Abkehren ist die stille Verneigung vor dem Fuß, der so viel gerannt ist."},"ICON-2312":{"nm":"Torwarthandschuh-Halter","de":"Ein Halter, an dem die Torwarthandschuhe zum Trocknen hängen. Der Platz, an dem die nach so vielen abgewehrten Schüssen vor Schweiß triefenden Hände kurz ausruhen. Für das nächste Spiel darf Nasses trocknen und Angespanntes langsam lockerlassen."},"ICON-2313":{"nm":"Ringhaken für das Basketballkorbnetz","de":"Die kleinen Haken, an denen das Netz am Ring befestigt wird. Durch sie entsteht das Raschelgeräusch, wenn der Ball hindurchfällt. Der kühle Klang eines Korberfolgs beginnt tatsächlich bei diesen Haken."},"ICON-2314":{"nm":"Luftablassnadel für Basketbälle","de":"Ein Werkzeug, das den zu harten Ball ein wenig Luft lässt. Wenn die Spannung zu groß ist, springt er zu wild. Das richtige Maß herauszulassen – ein griffiger Ball wird immer aus dieser feinen Abstimmung geboren."},"ICON-2315":{"nm":"Sensor-Pad des Backboards","de":"Ein Sensor-Pad, das auf der Rückseite des Backboards angebracht ist. Es liest den Augenblick, in dem der Ball auftrifft, als klare Zahl aus. Selbst Momente, die das Auge verfehlt, sind in diesem kleinen Sensor gespeichert – und die Entscheidung wird fairer."},"ICON-2316":{"nm":"Dribbling-Hindernishütchen","de":"Hütchen, die in einer Reihe auf dem Dribbelweg stehen. In dem Zickzack, das man um sie herum fährt, wächst die Fußarbeit. Sich jemandem in den Weg zu stellen ist manchmal die freundlichste Art, beizubringen, wie man besser herauskommt."},"ICON-2317":{"nm":"Ventilreinigungsbürste für Basketbälle","de":"Eine kleine Bürste zum Säubern des Ventillochs am Ball. Wenn Staub das Loch verstopft, kommt die Nadel nicht hinein – daher wird erst der unsichtbare Eingang sauber gemacht. Vor dem Füllen immer erst leeren und reinigen."},"ICON-2318":{"nm":"Fingerband-Rolle","de":"Eine Rolle Tape zum Umwickeln der Finger. Sie umschließt den verstauchten Knöchel fest und gibt einem den Mut, den Ball erneut zu greifen. Eine verletzte Stelle zu verbinden ist die kleine Ansage: Ich mache weiter."},"ICON-2319":{"nm":"Rückennummern-Klemme","de":"Eine Klemme, die die Rückennummer am Trikot befestigt. Statt deines Namens durchstreift eine Zahl das Spielfeld. Im festen Einklemmen steht klar geschrieben, wer heute spielt."},"ICON-2320":{"nm":"Schuss-Übungsring","de":"Ein Zielring, der in den Korb gesteckt wird und die Öffnung verkleinert. Je enger die Öffnung, desto mehr lernt man, Fehlschüsse auszuhalten. Wer immer auf ein enges Tor wirft, eignet sich irgendwann eine genaue Fingerfertigkeit an."},"ICON-2321":{"nm":"Schuh-Wischpad für Basketballschuhe","de":"Bevor man das Spielfeld betritt, kniet man nieder und wischt erst die Schuhsohle ab. Kein einziges Ausrutschen soll dem Hallenboden entstammen. Tritt man mit sauberen Sohlen den ersten Schritt, ist man heute ein kleines bisschen belastbarer als gestern."},"ICON-2322":{"nm":"Netzspannungshaken für Volleyball","de":"Spannung ist unsichtbar. Doch in dem Moment, in dem der Haken die Schnur bis ans äußerste zieht und hält, teilt das Netz mit einer Handbreit Anspannung das Spielfeld in zwei Hälften. Das Gleichgewicht, das eine unsichtbare Hand hält, weckt das Spiel."},"ICON-2323":{"nm":"Antennen-Befestigungsclip","de":"Vom Wind immer wieder ins Wackeln gebrachte Antennen stehen durch einen einzigen Clip wieder gerade. Ein kleines Ding hält ein großes Wackeln fest. Auch im Hintergrund eine Kabelverbindung stillschweigend zu fixieren kostet genau dieses Maß an Einsatz."},"ICON-2324":{"nm":"Libero-Weste-Aufhänger","de":"Das andersfarbige Trikot der Abwehrspezialistin hängt an der Wand und wartet auf das nächste Spiel. Libero – ein Name, der kein Rampenlicht braucht und doch das ganze Spielfeld trägt. Das Auge, das von der tiefsten Stelle am weitesten schaut, ist genau dort."},"ICON-2325":{"nm":"Knieschoner-Tasche","de":"Je öfter man sich auf den Boden wirft, desto häufiger stößt man sich die Knie an. Diese kleine Tasche, in die man die Knieschoner ordentlich legt, weiß es: Wer erst gelernt hat, richtig zu fallen, wird am Ende am weitesten fliegen."},"ICON-2326":{"nm":"Druckmessgerät für Volleybälle","de":"Mit einer Berührung der Fingerspitze lässt es sich nicht ermitteln. Die Zeigernadel vibriert fein und zeigt einen einzigen Skalenstrich an. Den Atemzug eines Balls zu messen ist der erste Schritt ins Spiel. Aus ehrlichem Druck entsteht eine ehrliche Flugkurve."},"ICON-2327":{"nm":"Völkerball-Linienband","de":"Ein auf dem Erdboden des Schulhofs aufgeklebter Kreis aus Klebeband. Das Drinnen und Draußen teilt für einen halben Tag das Fangspiel-Universum. Die Hand, die die Linie gezogen hat, weiß: Regeln sind der Anfang des Spiels."},"ICON-2328":{"nm":"Schiedsrichterpfeifen-Ablage","de":"Wenn der schrillen Pfeife die Stille folgt, legt sie sich wieder ruhig auf ihre Ablage zurück. Der Platz, der dem Atem des Schiedsrichters am nächsten ist. Fairness beginnt immer damit, die kleinen Dinge an ihren Platz zurückzulegen."},"ICON-2329":{"nm":"Zielscheibe für die Zuspiel-Übung","de":"In der Morgendämmerung, wenn niemand zuspielt, schickt man Tausende Male die Fingerspitzen auf die an der Wand befestigte Scheibe zu. Die Wand ist der großzügigste Mitspieler. Der zurückkommende Ball richtet den erschöpften einen wieder auf."},"ICON-2330":{"nm":"Netzhöhen-Messtab","de":"Ist das Netz nur eine Handbreite zu niedrig, ändert sich das Spiel. Wer dem Augenmaß am Ende nie traut, greift zu mir. Fairness kommt dort her, wo jede Höhe penibel und gewissenhaft nachgemessen wird."},"ICON-2331":{"nm":"Winkelpin des Startblocks","de":"Der Winkel, in dem die Fußspitzen beim Startblock aufliegen – dieser eine Grad entscheidet den Start. Während man mit dem Pin den Block fixiert und den Atem anhält, folgt die Startposition still bis zur Ziellinie."},"ICON-2332":{"nm":"Bahnnummern-Fähnchen auf der Laufbahn","de":"Die kleinen Fähnchen mit der Bahnnummer flattern im Wind. Alle laufen in die gleiche Richtung, aber jeder hat seinen eigenen Weg. Die Laufbahn umschließt Nebeneinander und Unterschied zugleich."},"ICON-2333":{"nm":"Staffelstab-Endkappe","de":"Damit der Stab beim Übergeben an den letzten Läufer nicht schmerzt, umschließt die Kappe die Kante weich. Im Staffellauf ist das Wichtigste nicht das Tempo, sondern die Hand, die an den Nächsten weitergibt."},"ICON-2334":{"nm":"Halter für das Messband zur Leistungsaufzeichnung","de":"Das Maßband, mit dem Rekorde gemessen wurden, wird aufgehängt, damit es sich nicht verknotet. Ein Platz, an dem der Abstand von gestern und der Abstand von heute nebeneinander hängen. Wachstum kommt immer zuerst als kleiner Zahlenunterschied."},"ICON-2335":{"nm":"Kurvenmarkierungshütchen auf der Laufbahn","de":"Ein kleines Hütchen am Kurveninneren teilt dem Lauf sein Herz mit. Nicht zu weit nach innen, nicht zu weit nach außen treiben. Wer die Kurve gut nimmt, kommt am Ende vorne an."},"ICON-2336":{"nm":"Zielband-Klemmclip","de":"Das Band, das als erstes die Brust berühren soll, hält der Clip straff und wartet. Ein Streifen, der dafür existiert, zerrissen zu werden. Für jemandes einzige Sekunde hält er den ganzen Tag lang den Wind aus."},"ICON-2337":{"nm":"Abdeckung der Startpistole","de":"Bis das Startsignal kracht, schläft der Lauf unter der Abdeckung. Das Gefäß, das den Startschuss aufbewahrt. Je tiefer die Stille, desto weiter hallt der erste Knall."},"ICON-2338":{"nm":"Höhen-Einstellpin für Hürden","de":"Mit jedem Anheben der Absprungshöhe um eine Stufe rückt auch der Pin einen Platz weiter. Die Angst wächst genauso. Und dennoch peilt der Fuß mit jedem Anlauf eine Stelle höher an und läuft weiter."},"ICON-2339":{"nm":"Rundenanzahl-Drehscheibe","de":"Wenn man beim Laufen nicht mehr weiß, wie viele Runden noch kommen, dreht man die Scheibe einen Klick weiter. Das kleine Geräusch der schwindenden Zahl gibt dem Bein neue Kraft. Die Hand, die die restliche Distanz zählt, schützt das Tempo."},"ICON-2340":{"nm":"Stab-Aufbewahrungsständer","de":"Ein langer, schwankender Stab braucht einen eigenen Platz zum Anlehnen. Weil er sich biegen muss, um sich zu schnellen, stellt man ihn besonders behutsam auf. Gut aufbewahrte Geschmeidigkeit birgt den höchsten Sprung."},"ICON-2341":{"nm":"Sandgruben-Egge","de":"Mit der Egge glättet man langsam die Fußabdrücke, die der vorangegangene Athlet hinterlassen hat. Die Sandgrube wird jedes Mal wieder eben wie am Anfang. Die Hand, die Spuren tilgt, damit jemand anderes abspringen kann, steht dort – unermüdlich und still."},"ICON-2342":{"nm":"Anlauf-Distanzmarkierungsband","de":"Ein Schritt zu wenig, ein Schritt zu viel – beides passt nicht. Das auf dem Boden befestigte Band zeigt ehrlich, wo der Fuß abstößt. Ein guter Anlauf ist kein blindes Drauflos, sondern kommt aus nüchterner Kalkulation."},"ICON-2343":{"nm":"Diskus-Griffauflage","de":"Rutscht der Finger ab, ist der Diskus schon losgeflogen, bevor man ihn geworfen hat. Die raue Oberfläche der Griffauflage, die den Diskus umschließt, hält die Rotation fest. Der Moment des Loslassens beginnt immer mit der Empfindung des Festhaltens."},"ICON-2344":{"nm":"Kugelstoß-Standfußring","de":"Ein Standfußring, der verhindert, dass die schwere Eisenkugel wegrollt. Das kleine Nest, das die Stille vor dem Stoß bewahrt. Je explosiver die Kraft ist, die wartet, desto fester muss der Platz sein, an dem sie ruht."},"ICON-2345":{"nm":"Schutzkappe der Speerspitze","de":"Die auf die scharfe Speerspitze aufgesteckte Kappe hüllt sie in ein weiches Schweigen. Wenn das Gerät, das weit fliegen soll, ruhig liegt, wird das Risiko mit Fürsorge gebändigt. Auch in der Aufbewahrung lebt Sicherheit."},"ICON-2346":{"nm":"Hochsprunglatten-Auflagehaken","de":"Damit die Querlatte auch bei leichter Berührung nicht fällt, trägt der Haken sie in feinem Gleichgewicht. Die Verantwortung für die Grenze zwischen Überspringen und Reißen liegt hier. Fairness wohnt in kleinen Details."},"ICON-2347":{"nm":"Eckklammer der Landematte","de":"Hebt sich die Ecke der Landmatte, passiert leicht ein Unfall. Die Klammer drückt alle vier Ecken fest nieder. Damit der Körper, der am höchsten geflogen ist, am sichersten landet – unsichtbar, aber tragend."},"ICON-2348":{"nm":"Wurfkreis-Begrenzungsband","de":"Die Grenze des Wurfkreises wird mit einem einzigen Streifen Band gezogen. Ob man auf der Linie landet oder sie übertritt, entscheidet, ob die Weite gilt oder nicht. Ein hauchdünnes Versprechen, wo Freiheit und Regel aufeinandertreffen."},"ICON-2349":{"nm":"Gummi-Standfuß des Schwebebalkens","de":"Damit der schmale Balken nicht wackelt, beißt sich der Gummistandfuß in den Boden. Die makellose Balance, die darauf zur Schau gestellt wird, ist in Wirklichkeit aus der Festigkeit des unsichtbaren Unterteils gemacht."},"ICON-2350":{"nm":"Reckstangen-Griffwickel","de":"Man wickelt den Griff um die Reckstange, damit die Handfläche nicht abrutscht. Das Geheimnis einer Rotation ist nicht das Glänzende, sondern der feste Griff. Der auf der Matte gefallene Schweiß weiß das."},"ICON-2351":{"nm":"Reck-Höhenfixierklammer","de":"Selbst wenn die zwei Seile nur um eine Handbreit verschieden sind, bricht die Bewegung zusammen. Die Klammer hält dieses Gleichgewicht unerschütterlich. Erst auf der exakt richtigen Höhe beginnt der freie Flug."},"ICON-2352":{"nm":"Pferdrücken-Griffabdeckung","de":"Die Abdeckung über dem Griff verhindert Blasen an der Handfläche. Hinter der kreisenden Bewegung verbergen sich Hände, die unzählige Male aufgegangen und wieder verheilt sind. Schutz ist das freundliche Versprechen an die nächste Übung."},"ICON-2353":{"nm":"Stufenbarren-Breiteneinstellpin","de":"Mit einem Pin wird der Abstand der zwei Holme genau eingestellt. Der Leerraum, durch den der Körper schwingt, wird zur Bühne. Auf der exakten Distanz entsteht der kühnste Abflug – das spüren die Fingerspitzen zuerst."},"ICON-2354":{"nm":"Sprungbrett-Federkappe","de":"Im Moment des Abstoßens katapultiert die Feder den Körper in den Himmel. Die Kappe umschließt diese Schnellkraft fest. Der kürzeste Anlauf macht den längsten Flug."},"ICON-2355":{"nm":"Magnesiumbeutel","de":"Das weiße Pulver, das man sich auf die Hände reibt, ist ein kleines Amulett gegen das Ausrutschen. Das kurze Ritual, in den Beutel zu greifen und wieder herauszuziehen, beruhigt die Nerven. Auch Anspannung wird am Ende in den Fingerspitzen bezähmt."},"ICON-2356":{"nm":"Turn-Bandage für das Handgelenk","de":"Während man das Band um das Handgelenk wickelt, zieht man auch die innere Schnur fest. Das wackelnde Gelenk wird vorsorglich eingefangen. Ein gut gebundenes Handgelenk gibt der kühnsten Rotation stillschweigend grünes Licht."},"ICON-2357":{"nm":"Sicherungsring für das Flugdreieck","de":"Kurz bevor man sich in die Luft wirft, wird die Sicherung zu einer unsichtbaren Hand. Erst wenn die Angst zu fallen verschwindet, kann man am weitesten fliegen. Vertrauen vollendet den Flug."},"ICON-2358":{"nm":"Schutzkappe der Tennisballdose","de":"Unter der Kappe schlafen neue Bälle, prall mit Druck. Das leise Plopp beim Öffnen einer Dose weckt die Vorfreude auf das Spiel. Versiegelung ist das Versprechen frischer Güte."},"ICON-2359":{"nm":"Saitenspannungs-Klemme","de":"Die Klemme hält die Saitenspannung fest und lässt nicht los bis zum Schluss. Weil die Saitenspannung die Ballabwehr bestimmt, beginnt das unsichtbare Ballgefühl bei dieser kleinen Klemme."},"ICON-2360":{"nm":"Linienkehrer für Tennisplätze","de":"Nach dem Spiel kehrt man langsam entlang der weißen Linien des Platzes. Wischt man den Erdstaub weg, treten die Linien wieder klar hervor. Den Platz für das nächste Spiel zu pflegen – dieser letzte Sorgfaltsakt belebt den Court."},"ICON-2361":{"nm":"Schutzband für den Schlägerrahmen","de":"Einmal um den Schlägerkopf gewickelt, werden auch harte Zusammenstöße rund abgefedert. Ich weiß, dass die Kante zuerst und am stärksten verschleißt. Da ich den Verschleiß an ihrer Stelle auf mich nehme, stehe ich heute – wie immer – ganz außen."},"ICON-2362":{"nm":"Lufttemperatur-Chip für Hallen","de":"Den kalten Frühlungsmorgenwind, der durch die Tür hereinbricht, liest ein handflächengroßer Chip früher als jeder Mensch. Noch bevor die Nasenspitze friert, ist er bereits da – die stillste Begrüßung am Morgen in einer leeren Sporthalle."},"ICON-2363":{"nm":"Grundlinien-Fußsohlenstütze","de":"Einem Spieler, der nicht weiß, wohin mit den Füßen, genügt eine einzige Linie auf dem Boden. Die Linie, die man nicht überschreiten soll, ist zugleich die Startlinie für den weitesten Sprung, sagt der Unterbau stillschweigend."},"ICON-2364":{"nm":"Tennisball-Korbhalter","de":"Er schluckt Dutzende Bälle und lässt keinen einzigen fallen. Alles, was auf dem Court verstreut liegt, einzusammeln und für die nächste Übung zu reichen – die fleißigen Hände, die abseits der Bühne unermüdlich tätig sind, hängen auch heute hier."},"ICON-2365":{"nm":"Schlägergriff-Endkappe","de":"Steckt man sie auf das Ende des Griffs, schmiegt sich der Schläger endlich in die Handfläche. Eine einzige kleine Kappe trennt Ausrutschen und Sicherheit. Wer das Ende fest verschließt, macht den ersten Swing belastbar."},"ICON-2366":{"nm":"Handtuch-Klemme am Spielfeldrand","de":"Auch wenn der Wind heftig bläst, hält sie das mühsam zurechtgelegte Handtuch am Platzrand fest und stemmt sich dagegen. Auch kurze Erholungspausen zu schützen hat mit dem tüchtigen Griff von jemandem zu tun."},"ICON-2367":{"nm":"Gefieder-Streckzange für Federbälle","de":"Ist auch nur eine Feder aus der Form geraten, gerät der Flug ins Wanken. Knickt man die gekrümmten Flügel vorsichtig gerade, macht sich der Federball wieder reisefertig. Weit zu fliegen beginnt immer mit solch einem kleinen Ordnen."},"ICON-2368":{"nm":"Federball-Röhrenstopfen","de":"Der Stopfen verschließt das Röhrenende fest, damit die aufgereiht aufbewahrten Federbälle nicht weich werden. Wer lange genug beobachtet hat, weiß: Schon ein Hauch Feuchtigkeit lässt die Federn einsacken. Auch ordentliches Verwahren gehört bereits zum Spiel."},"ICON-2369":{"nm":"Tischtennisball-Rollständer","de":"Ein rollender kleiner Ball hält bei mir für einen Moment inne. Damit er nicht wegrollt und fällt, stütze ich ihn sanft – die rundeste Form der Fürsorge am Tischtennistisch."},"ICON-2370":{"nm":"Gummiflächenroller für Tischtennisschläger","de":"Rollt man den Roller sachte über die Gummifläche, löst sich alter Staub und die Klebrigkeit erwacht wieder. Die Rotation muss leben, damit der Ball dreht. Der heutige Zustand des Schlägers erwacht in diesem einen sanften Streicheln."},"ICON-2371":{"nm":"Netzhöhen-Messtab für Tischtennis","de":"Schon wenn das Netz nur eine Handbreit höher ist, ändert sich der Spielfluss. Wer dem Augenmaß nie ganz traut, legt mich an. Fairness kommt erst dann, wenn die Höhe Strich für Strich nachgemessen ist."},"ICON-2372":{"nm":"Federball-Geschwindigkeitschip","de":"Die Geschwindigkeit, mit der der Federball die Luft durchschneidet, ermittele ich still. Wenn das Unsichtbare als klare Zahl niedergeht, wird das nächste Wort des Trainers viel deutlicher. Das ist die Arbeit: aus einem Gefühl eine Tatsache zu machen."},"ICON-2373":{"nm":"Tischtennisball-Aufbewahrungskapsel","de":"Legt man einen runden Ball behutsam in die Kapsel, rücken Kratzer und Staub in weite Ferne. Damit er bis zum nächsten Spiel unversehrt bleibt, überlässt man ihm ganz einfach ein kleines Zimmer. Das ist das Herzstück dieser Fürsorge."},"ICON-2374":{"nm":"Badminton-Schläger-Saitenhalter","de":"Hängt man die gelockerten Saiten geordnet auf, tastet die nächste Hand nicht umher. Ordnung ist letztlich ein freundlicher Zettel, den man sich selbst für morgen hinterlässt. Heute macht es morgen leichter."},"ICON-2375":{"nm":"Kantenband für den Tischtennisschläger","de":"Den Rand, an dem sich der Belag leicht ablöst, umschließe ich mit einem einzigen Streifen sanft. Weil sich am Ablösen auch das Ballgefühl auflöst. Den Rand zu halten bedeutet am Ende, einen Punkt zu halten."},"ICON-2376":{"nm":"Aufwärmbeutel für Squashbälle","de":"Ein kalter Ball springt kaum. Vor dem Spiel wärmt man ihn handwarm ein und lässt ihn in diesem Beutel ruhen. Die kleine Wärme, die auf die Hand übergeht, legt schon im Voraus den Rhythmus für eine Runde fest."},"ICON-2377":{"nm":"Lacrosse-Netzklemme","de":"Wenn sich eine Masche des Netzes leise zu lösen droht, beiße ich sie stillschweigend fest. Das Netz muss halten, damit der Ball bleibt. Die Hand, die das ganze Spiel von einem unsichtbaren Platz aus zusammenhält, ist genau hier."},"ICON-2378":{"nm":"Schutzband für das Squashschläger-Ende","de":"Je stärker man gegen die Wand schlägt, desto früher weint der Schläger am Ende. Schützt man das weinende Ende, spielt man noch eine Saison länger damit. Wer das Ende zu schätzen weiß, hält den Schläger am längsten in der Hand."},"ICON-2379":{"nm":"Abdeckung für das Hockeyschläger-Blatt","de":"Steckt man die Abdeckung auf das scharfe Blatt, ist sowohl die Tasche als auch die Fingerspitze beruhigt. Gefährliches still zu besänftigen – das ist beim Packen des Schlägers die erste und älteste Höflichkeit."},"ICON-2380":{"nm":"Poliertuch für den Cricket-Ball","de":"Reibt man den roten Ball am Tuch, saugt eine Seite das Licht wie ein Spiegel auf. Dass der Ball sich dreht, wenn er glänzt, spürt der Werfer in der Fingerkuppe. Auch im sorgfältigen Polieren steckt eine stille Strategie."},"ICON-2381":{"nm":"Dosen-Verschlusskappe für Lacrossebälle","de":"Damit die harten Bälle nicht beliebig herausrollen, verschließt man den Doseneingang fest. Leicht Zerstreutes einzusammeln und an einem Ort zu ordnen – der Grundstein guten Betriebs ist immer so simpel."},"ICON-2382":{"nm":"Squash-Wandzielscheiben-Stück","de":"Eine kleine Scheibe an der Wand bündelt das umherirrende Auge des Spielers auf einen einzigen Punkt. Ein einziger Punkt, der anzeigt, wohin man zielen soll – auch die breiteste Wand wird vor diesem Stück zur klaren Zielscheibe."},"ICON-2383":{"nm":"Hockeystab-Griff-Einziehschlauch","de":"Schiebt man den vertrauten Griff auf einen fremden neuen Stab, gehört das Gerät in diesem Moment auf Anhieb einem. Eine kleine Hülse, die das Vertraute neu einkleidet – das ist der kürzeste Weg zur Anpassung."},"ICON-2384":{"nm":"Feldtor-Netzhalter","de":"Erst wenn das Netz am Tor hängt, ist ein Tor wirklich ein Tor. Den kurzen Augenblick festzuhalten, in dem der Ball einschlägt, war schon immer Sache des Netzes. Den Platz, der den Jubel auffängt, halte ich besetzt."},"ICON-2385":{"nm":"Kufenschutz für Schlittschuhe","de":"Mit geschliffenen Kufen kann man außerhalb des Eises keinen einzigen Schritt getrost tun. Verlässt man das Eis, bitte diese Abdeckung aufziehen. Schärfe still zu bändigen ist ein altes Gebot der Eisläufer."},"ICON-2386":{"nm":"Schnürsenkelhaken für Eiskunstlaufschuhe","de":"Die langen Schnürsenkel der ausgezogenen Stiefel hängt man Stück für Stück ordentlich auf. Ordentlich aufgerollte Schnürsenkel öffnen das nächste Eis glatt. Der heutige Abschluss wird zur Vorbereitung für morgen."},"ICON-2387":{"nm":"Kufentrocknungstuch","de":"Kaum hat man das Eis verlassen, beschlagen die Kufen mit feinen Tröpfchen. Tupft man die Feuchtigkeit sorgfältig ab, zieht der Rost vorbei. Das stille Beseitigen der Spuren, die die Kälte hinterlässt – das ist mein Tag."},"ICON-2388":{"nm":"Knöchelpolster für Schlittschuhe","de":"Wackelt der Knöchel einmal, bricht die gesamte Gleitbahn zusammen. Das Polster, das ihn fest umschließt und den Tritt hält. Die anmutige Balance auf dem Eis beginnt immer an dem unsichtbaren Ort, der als Erstes trägt."},"ICON-2389":{"nm":"Kufenschutz-Aufbewahrungstasche","de":"Eine kleine Tasche in der Ecke des Rucksacks verwahrt die Kufenschutzabdeckungen. Die Gewohnheit, nichts zu übersehen, was eingepackt werden muss, hält die Ausrüstung auf Dauer am Leben. Eine geordnete Tasche ist die erste Szene einer guten Gleitfahrt."},"ICON-2390":{"nm":"Einlegesohlen-Klemme für Schlittschuhe","de":"Damit die Einlegesohle im Stiefel nicht leise verrutscht, hält sie die Klemme am Boden fest. Verrutscht der Untergrund, geht auch der Sprung daneben. Die Hand, die die unterste Stelle festhält, hilft am Ende beim höchsten Absprung."},"ICON-2391":{"nm":"Kufenabdeckungs-Verschlusshaken","de":"Damit die Abdeckung nicht heruntergleitet, hakt man sie mit dem Haken sicher fest. Ein loser Schutz ist am Ende kein Schutz, das ist bekannt. Ein gut eingehakter Haken schützt die Kufe bis zuletzt."},"ICON-2392":{"nm":"Schnürsenkel-Klemm-Endkappe für Schlittschuhe","de":"Schnürt man die Schnürsenkel kräftig fest und rastet die Kappe ein, kann sich nichts mehr lösen. Von der Fußspitze an lückenlos und fest zuzuziehen – die sicherste Schlaufe, die man bindet, bevor man den ersten Schritt aufs Eis setzt."},"ICON-2393":{"nm":"Kufenwischer-Tuch","de":"Nach einer ausgiebigen Gleitfahrt nimmt man die auf der Kufe perlende Feuchtigkeit sanft ab. Im Nassen gelassen wird die Kufe traurig, das weiß man. Nur eine trocken gewischte Kufe zieht auch die nächste Kurve scharf aufs Eis."},"ICON-2394":{"nm":"Griff-Endkappe für Skistöcke","de":"Wird das Ende des Stockgriffs weich umschlossen, liegt die Hand gleich viel bequemer. Die Kraft, die durch die verschneite Piste fährt, kommt letztlich von diesem sicher umfassten Ort. Eine kleine Kappe stützt die gesamte Abfahrt bis zum Ende."},"ICON-2395":{"nm":"Bindungspin für Snowboards","de":"Springt der kleine Pin heraus, der Bindung und Schuh verbindet, bleibt der Berg vor einem stehen. Kaum zu sehen, und dennoch das Erste, auf das man achten muss – dieses feste Verbindungsstück ist die Freiheit auf der Piste."},"ICON-2396":{"nm":"Skikanten-Schutzklammer","de":"Damit die scharfe Kante die Tasche nicht aufkratzt, beißt sie die Klammer sanft fest. Schärfe nach einem Berglauf zu besänftigen – das ist der freundliche Abschluss."},"ICON-2397":{"nm":"Snowboard-Nasen-Schutzkappe","de":"Deckt man die Nasenspitze des Boards ab, werden auch direkte Stöße sanft zerstreut. Die Stelle, die am häufigsten zuerst trifft, still zu schützen – der Mut für steile Abfahrten beginnt genau hier."},"ICON-2398":{"nm":"Schnallenschutz für Skistiefel","de":"Damit die Schnalle durch Schnee und Eis nicht beschädigt wird, deckt man sie sanft zu. Den Verschluss durch einen weiteren Verschluss zu schützen – diese kleine Abdeckung verlängert den Stiefeln eine ganze Saison."},"ICON-2399":{"nm":"Leash-Haken für Snowboards","de":"Damit das Board, wenn es den Händen entgleitet, nicht weit davonläuft, verbinde ich Knöchel und Board mit einem Seil. Selbst wenn man es loslässt, wird man es nicht endgültig verlieren – der stille Beruhigungshaken am Ende eines langen Seils."},"ICON-2400":{"nm":"Skiwachs-Schaberspitze","de":"Das alte, auf dem Boden festgekrustete Wachs streift man glatt heraus. Das Altbackene muss vollständig weg, damit das neue Gleiten lebt. Ein mit Sorgfalt gepflegter Unterboden öffnet die nächste Piste ein deutliches Stück schneller."},"ICON-2401":{"nm":"Snowboard-Stoßschutz","de":"Bevor das Brett den Schnee durchschneidet, berührt zuerst die Spitze die Welt. Jeden Zusammenstoß fängt zuerst dieser kleine Gummi ab. Vorn nutzt er sich am meisten ab, ohne je Aufhebens zu machen – auf dieser stumpfen Hingabe gleitet jede Abfahrt dahin."},"ICON-2402":{"nm":"Skistockteller","de":"Kurz bevor der Stock im tiefen Schnee versinken will, tastet dieser runde Reif an seiner Stelle den Boden ab. Ein Ring, der einen fast fehlgehenden Schritt still auffängt. Auch unsichtbar bleibt er wie eine Hand, die dafür sorgt, dass man nicht ausrutscht."},"ICON-2403":{"nm":"Wachsbürsten-Schutzkappe","de":"Ist die Pflege vorbei, bedeckt sie den Staub sanft, bevor er trocknet. Sie versiegelt die Geschmeidigkeit des Tages, ohne dass sich auch nur eine Faser verschiebt. Öffnet man sie das nächste Mal, wartet die Sorgfalt von gestern noch unverändert."},"ICON-2404":{"nm":"Aufhänger für Ohrenschützer","de":"Erinnerst du dich? Kommt der Frühling, werden die Ohrenschützer neben der Tasche eine Weile vergessen. Doch sobald die Nachricht vom ersten Schnee die Nacht erreicht, ruft man sie als Erstes wieder herbei – es gibt einen eigenen Platz, an dem man die Jahreszeit aufhängt, und dieser Haken vergisst dieses Versprechen nie."},"ICON-2405":{"nm":"Schleifstein-Etui","de":"Um eine Klinge zu schärfen, muss man zuerst den Stein benetzen – eine Reihenfolge, eingeprägt wie der Handgriff der Großmutter. Auch ein Werkzeug, das Stumpfheit bezähmt, braucht einen eigenen Ruheort. So hütet dieses kleine Etui den Schleifstein bis zur nächsten Pflege."},"ICON-2406":{"nm":"Beutel für Wachsblock","de":"Der Stoff, aus dem glänzende Abfahrten entstehen, schläft in sich selbst fest zu einem Klumpen geballt. Eine Schwere, die einen erstarrten Klotz in sich birgt. Aus genau dieser stillen Last löst sich das Gleiten und breitet sich über das Schneefeld aus."},"ICON-2407":{"nm":"Handwärmer-Beutelclip","de":"Auf dem winterlichen Spaziergang ist dies der erste Ort, den die Finger in der Tasche ertasten. Der kleinen Wärme, die kalte Hände erwärmt, wird ein fester Platz gegeben. Je kälter der Tag, desto liebevoller wird dieser kleine Haken."},"ICON-2408":{"nm":"Schleifstein-Halterung","de":"Wackelt sie, gerät die Klinge schief, also fixiert sie zuerst sich selbst ganz fest. Eine Halterung, die für die Genauigkeit anderer sorgt, ohne sich je selbst zu rühren. Auf dieser Stille steht die gerade Schneide von jemandem."},"ICON-2409":{"nm":"Schlauchschal-Klammer","de":"Auf dem kalten Schulweg, gerade als der Schlauchschal verrutschen will, macht es am Kragen Klick. Auch Wärme muss ihren Platz halten, um wirklich warm zu sein. Ein einziges kleines Geräusch bewahrt die Wärme des Morgens."},"ICON-2410":{"nm":"Schutzhülle für Wachsbügeleisen","de":"Während die heiß gearbeitete Fläche langsam erkaltet, hält ein Tuch sie sanft vor Staub geschützt. Ein Werkzeug pflegt hier ein anderes, das die Abfahrt vorbereitet hat. So setzt sich Fürsorge still fort."},"ICON-2411":{"nm":"Kappe für Kantenölstift","de":"Öffnet man ihn einmal und lässt ihn eintrocknen, lässt sich keine nächste Linie mehr ziehen. Verschließen bedeutet daher, das Nächste zu öffnen – diese kleine Kappe versiegelt die Feuchte der Spitze und verspricht damit im Voraus den nächsten Strich von morgen."},"ICON-2412":{"nm":"Fanquasten-Knauf","de":"Hunderte Fransen nehmen von diesem einen Punkt ihren Ausgang und flattern im Takt alle zugleich. Die Pracht des Schwingens beginnt immer an einer fest verknoteten Stelle. Unterhalb der Bühne ist es der erste Knoten, der die Tribüne zum Wogen bringt."},"ICON-2413":{"nm":"Leuchtstab-Handschlaufe","de":"Als der Jubel zwei Stunden dauerte und der Leuchtstab beinahe entglitt, holte dieses Band ihn zurück in die Hand. Der Wunsch, nichts fallen zu lassen und nichts zu verlieren. Diese liebevolle Ungeduld hat auf dem Handgelenk eine Schlaufe geformt."},"ICON-2414":{"nm":"Klappbeschlag für Stadionkissen","de":"Beim Anfeuern springt man ein paarmal auf und setzt sich wieder hin. Dazwischen faltet ein kleines Metallteil geschickt das Kissen und bewahrt den Platz. Auch in der aufgeregten Tribüne steckt eine Hand, die auf jemandes Sitzplatz achtgibt."},"ICON-2415":{"nm":"Fan-Bandana-Öse","de":"An dem Tag, an dem sich dasselbe Muster über die ganze Tribüne ausbreitet, bindet ein einziges Stück Stoff zehntausend Herzen zu einer Farbe zusammen. Der erste Punkt, an dem diese Welle beginnt, ist diese kleine Öse – der Ort, an dem einsames Anfeuern zu einem gemeinsamen Wir wird."},"ICON-2416":{"nm":"Klatschpaddel-Hälfte","de":"Allein geschlagen ist es nur ein kleiner Laut, in der Menge vereint wird es zur Welle. Die ehrlichste Hälfte, die weiß, dass Klang erst im Zusammentreffen entsteht. Im Moment, in dem dein Klatschen auf meines trifft, wächst der Jubel."},"ICON-2417":{"nm":"Eckenschutz für Fanplakat","de":"Sie umhüllt die spitze Ecke rundlich, damit die Nachbarin im Publikum sich nicht verletzt. Selbst in glühender Begeisterung steckt Rücksicht aufeinander. Anfeuern wird gerade an diesen abgerundeten Stellen noch wärmer."},"ICON-2418":{"nm":"Fahnenstangenhülle für Bandfahne","de":"Selbst wenn das Wehen einen Moment lang ruht, steht die Fahnenstange aufrecht und wartet auf den nächsten Jubelschrei. Ein kurzer, stiller Verweil, bevor sie wieder flattert. Zwischen zwei Rufen holt das Band einen kurzen, ruhigen Atemzug."},"ICON-2419":{"nm":"Anfeuerungsfächer","de":"Damit der Ruf eines Einzelnen bis zum Bühnenrand reicht, verengt die Fächerform den Weg des Klangs. Ein Mund, der sich stets mehr über den Weg der Übermittlung als über die Größe des Gefühls Gedanken macht. Diese Form ist aus der Sehnsucht entstanden, noch weiter zu reichen."},"ICON-2420":{"nm":"Nadelschutz für Fan-Anstecker","de":"Bevor sie an der Brust befestigt wird und nachdem man sie abgenommen hat, beginnt und endet die Ruhe des Abzeichens genau hier. Ein kleines Etui, das die scharfe Rückseite sicher schlafen legt. Auch ein glänzender Punkt braucht manchmal einen Ort zum Ausruhen."},"ICON-2421":{"nm":"Wendezifferplatte für Anzeigetafel","de":"In jeder eingewechselten Ziffer steckt die Sorgfalt jener Zeit, als man sie noch von Hand auswechselte. Vor der Digitaltechnik wurde der Wettkampf Strich für Strich mit den Fingern eingeprägt. Ein Plättchen, in dem selbst eine einzelne Zahl jemandes Herzklopfen trug."},"ICON-2422":{"nm":"Taktikboard-Magnetfigur","de":"Den Fingerspitzen des Trainers folgend tauschen Abwehr und Angriff die Plätze. Jedes Bild, das vor dem Spiel im Kopf entsteht, zeichnet sich zuerst in der Bewegung dieser kleinen Punkte. Der Wettkampf wird einmal im Voraus auf dem Brett durchgespielt."},"ICON-2423":{"nm":"Blendschutz für Anzeigetafel","de":"Damit die grellen Ziffern den Blick der Spieler nicht trüben, schneidet der Schirm das Licht ab. Auch Helligkeit muss manchmal passend verschattet werden, um ihre Aufgabe zu erfüllen. Am hellsten Ort arbeitet er am leisesten – ein Schatten."},"ICON-2424":{"nm":"Scoreboard-Wendering","de":"Bei jedem umgeblätterten Blatt ändert sich die Zahl, und der Jubel steigt mit ihr. Eine Spur der analogen Zeit, als der Spielstand noch von Hand erneuert wurde. Damals hüpfte mit dem Klang des umschlagenden Punktes auch das Herz mit."},"ICON-2425":{"nm":"Stiftetui für Taktiktafel","de":"Jede Laufbahn, die auf dem Whiteboard der Umkleidekabine gezeichnet wird, entspringt diesem Stift. Ein kleines, festes Behältnis, das den Entwurf des Wettkampfs in sich trägt. In der Stille vor der Entscheidung ist es der Ort, der die meisten Worte in sich birgt."},"ICON-2426":{"nm":"Punktezähl-Klicker","de":"Bei jedem Drücken steigt der Zählstand um einen Schritt, begleitet von einem klaren Klicken. Überlässt man das Zählen den Fingern, kann sich der Geist ganz dem Spiel widmen. Ein kleiner Rhythmus, der die Last des Zählens abnimmt."},"ICON-2427":{"nm":"Kabelabdeckung für Anzeigetafel","de":"Hinter jedem prächtigen Licht liegt immer ein Gewirr ungeordneter Kabel. Diese Unordnung sanft zuzudecken, ist ihre Aufgabe. Erst wenn das Unsichtbare in Ordnung gebracht ist, kann das Sichtbare wirklich erstrahlen."},"ICON-2428":{"nm":"Taktiktafel-Radierbürste","de":"Ist eine Runde vorbei, wird die Fläche für das nächste Bild sauber freigewischt. Eine neue Strategie kann immer nur auf ganz leerer Fläche beginnen. Die wischende Bürste ist im Grunde der erste Pinselstrich des nächsten Plans."},"ICON-2429":{"nm":"Fahnenklammer für Punkteanzeige","de":"Sie hält die im Wind flatternde Fahne fest im Griff und lässt sie nicht los, damit das wehende Tuch an seinem Platz bleibt. Auch um ein Ergebnis der Welt zu verkünden, braucht es zuerst eine Hand, die verlässlich festhält."},"ICON-2430":{"nm":"Kordelklammer für Schiedsrichterpfeife","de":"Mit einem einzigen Pfiff hält das Spiel inne und fließt dann wieder weiter. Ein kleiner Knoten, der diese Autorität fest um den Hals bindet. Bis die Pfeife ertönt, ist es auch die Aufgabe dieser Klammer, die Stille ordentlich zusammengebunden zu halten."},"ICON-2431":{"nm":"Maßband-Aufroller","de":"Was er ausgerollt und gemessen hat, zieht er wieder in sich zurück. Messen ist am Ende nichts als das stete Wiederholen von Ausrollen und Einrollen. Der Griff, der dieses schlichte Hin und Her klaglos begleitet, dreht sich unermüdlich im Hintergrund der Genauigkeit."},"ICON-2432":{"nm":"Linienrichterfahnen-Etui","de":"Die Fahne, die entschlossen zwischen Drinnen und Draußen der Linie schied, liegt nach dem Spiel ordentlich gefaltet und ruht. Auch das klare Signal holt kurz Atem für das nächste Mal. Selbst hinter aller Entschlossenheit wartet eine stille Rast."},"ICON-2433":{"nm":"Stoppuhr-Haken","de":"Er hängt die verrinnende Zeit nicht ans Handgelenk, sondern an einen festen Ort. Ein Bahnhof der Zeit, der stillsteht, bevor gemessen wird, und auf Zuruf sofort lossprintet. Ein kleines Zuhause der Sekunden, das mit angehaltenem Atem auf das Startsignal wartet."},"ICON-2434":{"nm":"Linienmarkierungsrad","de":"Wo es entlangrollt, bleibt jedes Mal ein klarer weißer Streifen zurück. So wird die Grenze der Regeln Runde um Runde sorgfältig in den Boden eingeprägt. Das Rad, das schon vor Spielbeginn als Erstes seine Spur auf dem Feld hinterlässt."},"ICON-2435":{"nm":"Schiedsrichter-Kartentasche","de":"Hier schlummert die eine Karte, die im entscheidenden Moment aus der Brusttasche gezogen wird. Ein Warteraum des Urteils, der bis zum letzten Augenblick beharrlich schweigt. Eine Tasche, die stets bereitliegt und insgeheim hofft, niemals gebraucht zu werden."},"ICON-2436":{"nm":"Waagegewicht-Sockel","de":"Wiegen ist nur auf einem Untergrund ehrlich, der keinen Wackler kennt. Der Sockel trägt das Gewicht und hält seine Fläche dafür ganz eben bereit. Der erste Schritt jeder genauen Messung beginnt stets an einem ruhigen Ort."},"ICON-2437":{"nm":"Startsignal-Klicker","de":"Bei einem einzigen Klick stoßen sich alle Füße im selben Augenblick vom Boden ab. Der Start dauert kaum einen Wimpernschlag, doch die Hand, die diese Kürze schafft, bleibt gelassener als jede andere. Eine Hand, die das Zittern der Startlinie mit einem einzigen Klick löst."},"ICON-2438":{"nm":"Kegel-Standfuß","de":"Sein Name mag fremd klingen, doch seine Aufgabe ist klar: Er trägt schwer und stumm die Mitte des Spielfelds, das wie eine Bühne wirkt. Im Zentrum, wo alle erstrahlen, hält immer ein unsichtbares Bein still und beharrlich die Stellung."},"ICON-2439":{"nm":"Bauchatemgürtel-Schnalle","de":"Dass ein guter Klang nicht aus der Kehle, sondern aus tiefem Atem kommt, weiß die Taille als Erste. Die Schnalle lässt die Handfläche spüren, wie sich der Bauch hebt und senkt. Der Ausgangspunkt jedes Liedes liegt stets unter diesem einen Atemzug."},"ICON-2440":{"nm":"Atemübungs-Federbrett","de":"Wenn der Atemhauch die Feder sanft zum Zittern bringt, ist das ein Zeichen für gleichmäßigen Atem. Er verleiht dem unsichtbaren Atem behutsam eine Form und lehrt so die Grundlage des Singens. Eine Übung, die den Atem vor dem ersten Ton mit den Augen erlernen lässt."},"ICON-2441":{"nm":"Einatem-Sanduhr","de":"Im Glas rinnt der Sand wie ein Atemzug herab. Die Körnchen zählen stellvertretend den Takt: einatmen, kurz innehalten, langsam ausatmen. Wer dem lautlos fallenden Sand ruhig zusieht, findet, ohne es zu merken, zu einem geordneten Atem zurück."},"ICON-2442":{"nm":"Kerzenübungs-Ständer","de":"Entzündet man den Docht, zittert die Stimme im Gleichtakt mit der flackernden Flamme. Ein Platz, den jemand sorgfältig geschnitzt hat, damit dieses kleine Zittern kurz aufgefangen wird. In der Dicke des erstarrten Wachses stecken all die Nächte, in denen hier allein gesungen wurde."},"ICON-2443":{"nm":"Bauchdruck-Kissengurt","de":"Statt die Hand auf den Bauch zu legen, drückt ein Gurt sanft an genau dieser Stelle. Füllt sich der Atem, spannt er sich straff, entweicht er, wird er leise locker. Ein stiller kleiner Begleiter, der dem Körper hilft, den Takt schon vor dem Kopf zu verinnerlichen."},"ICON-2444":{"nm":"Atemausdauer-Ballonkappe","de":"Blas den Ballon nicht auf einmal auf. Schieb den Atem lang, langsam, bis zum letzten Rest hinaus. Während die Luft durch die Kappe entweicht, dringt sie bis in den tiefsten Winkel der Lunge. Am Ende trägt dich das Lied genau so weit, wie lange du den Atem ausgehalten hast."},"ICON-2445":{"nm":"Atemberuhigungs-Griff","de":"Je mehr das Herz bebt, desto mehr will die Hand etwas fest umfassen. Greift man diesen Griff, sinken die Schultern von selbst, und der Atemzug wird um ein Stück länger. Dass Zugreifen-Lernen zugleich das Lernen ist, sich selbst zu sammeln, weiß die Handfläche als Erste."},"ICON-2446":{"nm":"Bauchmuskel-Vibrationsbandring","de":"Hängt man das Band in den Ring, breitet sich ein sanftes Vibrieren in der Mitte des Bauchs aus. Genau dort, wo es beim herzhaften Lachen zittert, sammelt sich still die Kraft. Eine starke Körpermitte wächst stets so, langsam, an einem Ort, den niemand sieht."},"ICON-2447":{"nm":"Einatemzähler-Drehscheibe","de":"Eins, zwei, drei – bei jedem Klick der Drehscheibe wird die Tiefe des eingeatmeten Atems festgehalten. Steigt die Zahl um eine Stufe, hält auch das Lied eine Phrase länger durch. Auf diesem kleinen Zifferblatt steht still geschrieben, wie viel Lungenvolumen heute dazugewonnen wurde."},"ICON-2448":{"nm":"Zungenübungs-Löffelbrett","de":"Auf dem Brett ist genau eingezeichnet, wo die Zungenspitze hin muss. Rollen, schnalzen, kurz innehalten – so lernt man es. Hinter jeder mühelos fließenden Aussprache stecken all die frühen Morgenstunden, in denen sich die Zunge diesen Weg eingeprägt hat."},"ICON-2449":{"nm":"Mundform-Spiegelklammer","de":"Die Klammer hält sanft die Mundform fest, die sich im Spiegel zeigt. Ein 'A' rund geformt, ein 'I' lang zu beiden Seiten gezogen. Eine stille Zweisamkeit aus Spiegel und mir, in der ich meinem eigenen Gesicht gegenübertrete und die Form der Klänge feile."},"ICON-2450":{"nm":"Aussprache-Korkrobbe","de":"Eine kleine, aus Kork geschnitzte Robbe sitzt in der Ecke des Schreibtisches und lauscht der Aussprache. In den Nächten, in denen das 'L' immer wieder abrutscht und der Mut sinkt, sagen die runden Augen der Robbe still: Schon gut, versuch es einfach noch ein Mal."},"ICON-2451":{"nm":"Liedtext-Atempin","de":"Wo im Text geatmet werden soll, verrät zuerst diese Nadel. Steckt man sie ans Ende einer Zeile, wird die Stelle zu einem liebevollen Komma des Liedes. Um aus vollem Herzen zu singen, braucht auch der Satz eine Atempause, ein kleines Leerzeichen."},"ICON-2452":{"nm":"Diktionsübungs-Kinnstütze","de":"Schon eine leichte Stütze am Kinn genügt, damit die auseinanderfallende Aussprache wieder ihren Platz findet. Deutliches Sprechen ist nicht allein Sache des Mundes, sondern ein Zusammenspiel von Kinn, Kehle und Atem. Diese kleine Stütze hilft still bei diesem heiklen Gleichgewicht."},"ICON-2453":{"nm":"Vokal-Mundformständer","de":"A, E, I, O, U – ein Gestell, das genau den Weg nachbildet, auf dem die fünf Vokale den Mund verlassen. Man stellt es still neben den Spiegel und übt jeden Tag am Gerüst der Klänge. Das Grundgerüst jedes Liedes beginnt am Ende immer bei diesen fünf Vokalen."},"ICON-2454":{"nm":"Zungenbrecher-Karte","de":"Fischers Fritz fischt frische Fische – eine Karte, bei der sich die Zunge verheddert und man am Ende doch lachen muss. Auch wenn man sich verspricht, ist das ganz und gar in Ordnung, denn genau das Verspechen ist die Übung. Mit jedem gemeisterten dieser tückischen Sätze erwacht eine Aussprache klarer als zuvor."},"ICON-2455":{"nm":"Lippenlockerungs-Mundstück","de":"Ein Warm-up, das die verspannten Mundwinkel weckt, indem die Lippen brummend flattern. Beißt man auf das Mundstück und lässt den Atem lang entweichen, lockern sich die schlafenden Lippen weich. Die kleinste und liebevollste Übung, um die erste Phrase sanft zu eröffnen."},"ICON-2456":{"nm":"Textabschnitt-Gummiband","de":"Um die Stelle, an der man immer wieder stockt, wird ein Gummiband gebunden. Jedes Mal, wenn man es am Handgelenk sieht, fällt einem der Berg ein, den man heute noch bezwingen muss. Je schwieriger der Takt, desto öfter schaut man hin, desto länger bleibt er im Herzen."},"ICON-2457":{"nm":"Halswärmer-Schalhaken","de":"Damit die Kehle in der kühlen Morgenluft des Jahreszeitenwechsels nicht heiser wird, hängt der Schal fest am Haken bereit. Erst ein warm umhüllter Hals lässt einen klaren Klang frei. Die Stimme zu schützen beginnt immer damit, zuerst die Kehle zu hüten."},"ICON-2458":{"nm":"Stimmband-Rollerspitze","de":"Rollt die Spitze langsam über die Seite des Halses, erwachen die Stimmbänder, die die ganze Nacht geschlafen haben, sanft auf. Die leichte Vibration löst die verhärtete Anspannung, und der zögernde erste Ton klingt gleich weicher. Eine Berührung, die den Körper wärmt, bevor gesungen wird."},"ICON-2459":{"nm":"Summwärme-Untersetzer","de":"Mit geschlossenen Lippen leise summend, umschließen beide Hände die dampfende, warme Tasse, und mit ihr wärmt sich auch die Kehle. Über dem Untersetzer breitet sich das tiefe Summen rund und sacht aus. So beginnt ein Lied mit einem einzigen Schluck lauwarmer Wärme."},"ICON-2460":{"nm":"Halsbonbon-Kapsel","de":"Für die Tage, an denen die Kehle rau und kratzig wird, sammeln sich in der Kapsel still ein paar Bonbons. Rollt man kurz vor dem Auftritt eines auf der Zunge, öffnet die kühle Minze die verschlossene Kehle mit frischem Prickeln. Ein persönlicher Trost für den Notfall, geborgen in einer kleinen Dose."},"ICON-2461":{"nm":"Dampf-Halswärmekissen","de":"Legt man das Kissen, das vom warmen Dampf sanft durchzogen ist, um den Hals, schmilzt die von langem Üben verhärtete Stelle langsam dahin. Genau wie die Wärme eines frisch erhitzten Handtuchs schenkt es den erschöpften, ermatteten Stimmbändern still einen Takt der Ruhe."},"ICON-2462":{"nm":"Stimmruhe-Sanduhr","de":"Das stille Versprechen, heute nicht zu sprechen, wird leise von den feinen Sandkörnern mitgezählt. Der Mund bleibt eine Weile geschlossen, während die Stimme geschont wird. Hier verrinnt langsam jene stille Zeit, die zugleich die beste Fürsorge ist."},"ICON-2463":{"nm":"Lip-Trill-Warmup-Mundstück","de":"Der Lip-Trill lässt die Lippen leicht flattern, während die Stimme auf und ab gleitet. Beißt man leicht auf das Mundstück, wird das zuvor willkürlich schwankende Flattern gleichmäßiger. Ein handtellergroßes kleines Hilfsmittel, das den ersten Knopf der Stimmbildung sanft schließt."},"ICON-2464":{"nm":"Halsbefeuchtungs-Sprühkappe","de":"Damit die Kehle auf der trockenen Bühne nicht austrocknet, drückt man die Kappe und versprüht einen feinen Wasserschleier. Atmet man die befeuchtete Luft tief ein, gewinnt die ausgetrocknete Stimme ihren klaren Glanz zurück."},"ICON-2465":{"nm":"Stimmlockerungs-Vibrationsball","de":"Hält man den fein vibrierenden Ball ruhig in der Handfläche, wandert das Zittern sanft den Arm hinauf bis zum Hals. Ein runder, freundlicher Warm-up-Gefährte, der die vor Anspannung verhärteten Stimmorgane behutsam wachrüttelt."},"ICON-2466":{"nm":"Formations-Bodenmarkierung","de":"Ein kleines Zeichen, fest in den Bühnenboden gesetzt. Hier ist dein Platz, dort drüben meiner. Wenn viele gemeinsam ein Bild formen, ist es das unsichtbare Versprechen, das leise dafür sorgt, dass niemand sich verirrt."},"ICON-2467":{"nm":"Laufweg-Pfeilchip","de":"Ein pfeilspitzenförmiger Chip zeigt klar die Richtung des nächsten Schritts. Wo man sich dreht und wo man stehen bleibt, verrät der Boden schon vorher, damit niemand den Weg verliert. Bewegungslinien sind eine Landkarte, die sich die Fußspitzen durch unzähliges Betreten eingeprägt haben."},"ICON-2468":{"nm":"Formations-Mittelpunktpin","de":"Ein einziger Punkt, der still zum Maßstab wird, wenn viele zusammenkommen. Um diesen Pin herum zieht sich ein runder Kreis, und die Formation entfaltet sich weit. Selbst die verstreutesten Bewegungen finden, sobald ein Mittelpunkt da ist, unversehens zu ihrer eigenen Ordnung."},"ICON-2469":{"nm":"Kreuzungspunkt-Keil","de":"Dort, wo sich zwei Wege an einem Punkt treffen, wird ein Keil fest hineingetrieben. Damit niemand zusammenstößt, damit niemand aneinander vorbeigerät. Selbst in dem kurzen, atemlosen Augenblick des Vorbeihuschens soll niemand den Weg verlieren."},"ICON-2470":{"nm":"Abgangsflagge","de":"Verklingt der Nachhall des letzten Tons, zieht man sich still in die Richtung zurück, die die Fahne weist. Denn beim Verlassen darf man ebenso wenig aus der Form geraten wie beim Betreten. Auch für den Schluss einer Bühnenshow gibt es eine vorher verabredete Richtung."},"ICON-2471":{"nm":"Abstandsmess-Maßbandklammer","de":"Klemmt die Klammer das Ende des Maßbands fest, wird Spanne um Spanne unfehlbar genau. Selbst der Abstand zwischen zwei Menschen wird so exakt wie mit dem Lineal ausgerichtet. Ein schönes Bild entsteht immer aus solch sorgfältigen Fingerspitzen."},"ICON-2472":{"nm":"Richtschnur-Haken","de":"Hängt man die Schnur in den Haken und spannt sie straff zu einer Linie, wird dieser feine Faden zum Maßstab, an dem sich alle ausrichten. Dass eine aufgereihte Formation so ordentlich wirkt, verdankt sie einzig dieser unsichtbaren, geraden Linie."},"ICON-2473":{"nm":"Laufweg-Punktmarker","de":"Kleine Stücke, die still einen gepunkteten Weg auf den Boden zeichnen. Folgt man dieser blassen Spur, verirrt man sich selbst im Dunkeln nicht. Während Punkt für Punkt sorgfältig verbunden wird, fügen sich zerstreute Schritte zu einem einzigen Fluss zusammen."},"ICON-2474":{"nm":"Positions-Bodenpin","de":"Eine Reißzwecke, fest in den Boden gedrückt, damit niemand seinen Platz vergisst. Selbst im tiefsten Dunkel ertastet die Fußspitze diese kleine Erhebung und findet sie unweigerlich. Erst wenn man genau an diesem einen Punkt zum Stehen kommt, ergießt sich das Licht über dem Kopf."},"ICON-2475":{"nm":"Halsisolations-Fokusband","de":"Wackelt das Kinn mit, gerät auch die Stimme zitternd aus der Fassung. Das Band wird angelegt, um zu lernen, den Kopf ruhig zu halten und allein den Hals zu bewegen. Hinter einer scheinbar völlig freien Bewegung steckt immer diese stille Übung der Trennung."},"ICON-2476":{"nm":"Schulterfixierungs-Kissenklammer","de":"Damit die Schulter nicht willkürlich hochzuckt, hält die Klammer das Kissen still fest. So lernt der Körper klar zu unterscheiden, wo bewegt und wo stillgehalten werden soll. Eine kontrollierte Linie entsteht immer erst aus solch kleiner, disziplinierender Fixierung."},"ICON-2477":{"nm":"Rippenwahrnehmungs-Gürtelschnalle","de":"Der Gürtel liest still das feine Muster, mit dem sich die Rippen weiten und wieder schließen. Schließt man die Schnalle, überträgt sich die Bewegung des Atems klar bis in die Fingerspitzen. Eine tiefe, feste Stimmbildung entspringt stets dieser unsichtbaren Bewegung der Knochen."},"ICON-2478":{"nm":"Beckenschwing-Pendel","de":"Während das Pendel langsam nach links und rechts schwingt, zeigt es still den Rhythmus, den das Becken zeichnet. Ein handtellergroßes Gewicht lehrt wortlos, wie die Körpermitte ihr Gewicht verlagert – dass selbst im Schwingen eine Struktur liegt."},"ICON-2479":{"nm":"Handgelenk-Drehring","de":"Legt man den Ring ums Handgelenk und dreht ihn langsam nach innen und außen, lockert sich das über Nacht verhärtete Gelenk sanft. Damit die Bewegung bis in die Fingerspitzen lebendig ankommt, muss zuerst das Handgelenk geschmeidig werden. Diese kleine Drehung öffnet den Weg zu einem größeren Ausdruck."},"ICON-2480":{"nm":"Fußgelenk-Widerstandsring-Band","de":"Steckt man den Ring ums Fußgelenk und zieht das Band, spürt jeder gesetzte Schritt einen sanften Widerstand an der Fußspitze. Je schwerer der Tritt, desto stiller wächst die Kraft im Bein. Ein federleichter Sprung steht immer auf dem Fundament solch schwerer Übung."},"ICON-2481":{"nm":"Core-Fokus-Sandsack","de":"Erst wenn man ihn um den Bauch legt, erkennt man, wo die Mitte des eigenen Körpers eigentlich liegt. Während das Gewicht an den Schultern zieht, findet der schwankende Kern langsam seinen Platz, und dort, wo man ihn schließlich ablegt, bleibt eine aufrechte Haltung zurück."},"ICON-2482":{"nm":"Wirbelsäulen-Ausrichtungsstab-Kappe","de":"Berührt die kleine Kappe den Rücken, der den ganzen Tag gebeugt war, ist es, als würde jemand still die Schultern zurechtrücken. Man kann auch gebückt weiterleben, doch aufrecht zu stehen ist eine liebevolle Fertigkeit, die man langsam wieder erlernen muss."},"ICON-2483":{"nm":"Muskelentspannungs-Akupressurkugel","de":"Drückt man fest auf die verspannte Stelle, sticht es zuerst, wird dann aber wohltuend gelöst. Wie die Wärme von Großmutters Handrücken, die einst über den Rücken strich, bedeutet Lösen, kurz mehr Schmerz auszuhalten und dabei an der Seite zu bleiben."},"ICON-2484":{"nm":"Spiegelwinkel-Justierschraube","de":"Dreht man ihn nur um Handbreite, zeigt der Spiegel ein völlig anderes Gesicht. Mit einer Drehung der Schraube neigt sich die Welt und richtet sich wieder auf – auch dem eigenen Spiegelbild zu begegnen, braucht offenbar ein stilles Zielen."},"ICON-2485":{"nm":"Spiegel-Beschlagwischer","de":"Vor dem Spiegel, den heißer Dampf trübt, verliert man für einen Moment das eigene Gesicht. Ein Wischen genügt, und das Gesicht kehrt zurück. Dank dieser Hand, die den Nebel fortstreicht, begegnet man sich selbst jeden Morgen aufs Neue."},"ICON-2486":{"nm":"Stativfuß-Gummikappe","de":"An der Fußspitze des Stativs entscheidet ein fingernagelgroßes Stück Gummi über das Schicksal des Bildes. Der feste Griff auf dem Boden bändigt jedes Wackeln – ein zitterfreies Bild beginnt stets still bei dieser unsichtbaren Reibung."},"ICON-2487":{"nm":"Winkelraster-Referenzfolie","de":"Die feinen Gitterlinien auf der Folie sind wie Stützräder für das Auge. Je vertrauter die Bildkomposition wird, desto stiller verschwinden die Linien, und nur das Gespür bleibt zurück. Je besser man etwas beherrscht, desto unsichtbarer werden die Spuren des Lernens."},"ICON-2488":{"nm":"Aufnahmestart-Fußpedal","de":"Für Hände, die voller Last sind, wird die Fußspitze zum letzten verbliebenen Finger. Ein leichtes Antippen genügt, und die Aufnahme beginnt – so leistet die Arbeit hinter der Bühne ihren Beitrag bis in die Fußspitzen hinein zuverlässig."},"ICON-2489":{"nm":"Beleuchtungsrichtungs-Klipp","de":"Wohin das Licht fällt, hängt an den Fingerspitzen dieses fingernagelgroßen Clips. Den Schatten um eine Handbreite zu verschieben und die Kontur zum Leben zu erwecken – über diesen kleinen Unterschied grübelt jemand oft lange und sorgenvoll."},"ICON-2490":{"nm":"Video-Vergleichsblende","de":"Legt man Gestern und Heute nebeneinander, beginnt die Veränderung erst zu sprechen. In dem Moment, in dem die Blende leise herabgleitet, zeigt sich ehrlich auf dem Bildschirm, welche Zeitspanne dazwischen überbrückt wurde."},"ICON-2491":{"nm":"Fernbedienungsschlaufe","de":"Ein einziges Band um das Handgelenk, und die Sorge, es könnte hinfallen, löst sich. Die kleine Sicherung macht die Hand gerade dadurch freier – ein zärtliches Paradox, bei dem das Gebundensein das Herz erst loslässt."},"ICON-2492":{"nm":"Objektivdeckel","de":"Während die Kamera ruht, schließt auch das Objektiv still die Augen. In einer Welt, in der ein einziges Staubkorn zur Narbe auf dem Bild wird, ist sanftes Zudecken schon der Wunsch, etwas lange zu bewahren."},"ICON-2493":{"nm":"Lächelzugband","de":"Zieht man die Mundwinkel sacht nach oben, löst sich der erstarrte Ausdruck ganz von selbst. Auch Lächeln ist am Ende nur ein Muskel – anfangs leiht man sich die Kraft des Werkzeugs, bis man eines Morgens aus eigener Kraft strahlend lächelt."},"ICON-2494":{"nm":"Wangenmassageroller","de":"Rollt man ihn langsam über die Wangeninnenseite, fließen die Worte gleich geschmeidiger. Vor dem Singen ein stilles Aufwecken des Gesichts. Auch der Ausdruck wird wärmer, wenn man ihn erst ein wenig erwärmt hat."},"ICON-2495":{"nm":"Lächelwinkellehre","de":"Die Kamera weiß, dass auch ein Lächeln seinen richtigen Winkel hat. Man misst hin und her mit der Lehre, bis man schließlich begreift: Das schönste Lächeln erblüht aus einer Aufrichtigkeit, die sich nie wirklich messen lässt."},"ICON-2496":{"nm":"Augenbrauenklammer","de":"Bewegt sich die Braue auch nur einen Millimeter, ändert sich die ganze Gemütslage. Die Klammer hält still das kleinste Bauteil des Ausdrucks fest – Schauspiel ist die Kunst, solche Feinheiten mit den Fingerspitzen zu meistern."},"ICON-2497":{"nm":"Wangenlifting-Sticker","de":"Klebt man ihn, die Wangenknochen sacht anhebend, auf, entsteht im Gesicht eine Stelle, an der das Licht verweilt. Ein fingernagelgroßer Aufkleber schafft diese Räumlichkeit – im Bühnen-Make-up steckt so ein unsichtbares Geheimnis."},"ICON-2498":{"nm":"Zwinkeraugenklappe","de":"Bedeckt man ein Auge, sammelt sich das Herz ganz im verbleibenden. Zwinkern zu üben heißt am Ende, zu lernen, eine Hälfte anmutig zu verbergen. Manche Ausdrücke werden gerade dadurch klarer, dass man sie verdeckt."},"ICON-2499":{"nm":"Mundformklammer","de":"Ga, gya, geo … passt man die Mundform der Schablone an, wird die verschwommene Aussprache klar. Dass jeder einzelne Vokal eine Haltung des Gesichts ist, prägt man sich vor dem Spiegel langsam ein."},"ICON-2500":{"nm":"Ausdrucks-Wärmesäckchen","de":"Kurz bevor man die Bühne betritt, ein warmes Säckchen, das das Gesicht sanft erwärmt. Wie kalte Hände das Spiel erstarren lassen, so auch ein kalter Ausdruck. Dass selbst ein Lächeln vorgewärmt werden muss – eine kleine Wahrheit hinter der Bühne."},"ICON-2501":{"nm":"Stirnglättband","de":"Legt man das Band um die Stirn, glättet sich die tief eingegrabene Falte des Stirnrunzelns ganz sacht. Ein Ding, das die von Sorgen gegrabenen Furchen für eine Weile ruhen lässt. Unter der geglätteten Stirn wird ein Mensch ein wenig jünger."},"ICON-2502":{"nm":"Drehbuch-Fingerhut","de":"Ein kleiner Fingerhut, den man beim Umblättern über die Fingerspitze streift. Der Rhythmus, mit dem man ein dickes Drehbuch Seite für Seite wendet, wird unversehens zum Takt der Geschichte. Auch im Lesen wohnt eine liebevolle kleine Gewohnheit der Hand."},"ICON-2503":{"nm":"Gefühlsfarbflagge","de":"Freude ist Gelb, Trauer ist Blau. Kleidet man das Herz in Farbe und hisst die Fahne, gewinnt das unsichtbare Gefühl im Wind flatternd Gestalt. So lässt sich auch ein Empfinden mit der Hand zeichnen."},"ICON-2504":{"nm":"Betonungsklammer","de":"Betone dieses Wort, flüstert die Klammer ganz still. Derselbe Satz kann durch eine einzige Betonung seinen ganzen Sinn wechseln – ein kleines Zeichen also, das den Schwerpunkt der Rede festhält."},"ICON-2505":{"nm":"Lesepausenblock","de":"Ein Klotz, hingelegt mit der Botschaft: Halte hier einen Takt inne. Das Komma im Text ist kein Stillstand, sondern der Atemzug für das nächste Wort. Wer gut zu pausieren weiß, spricht am Ende auch gut."},"ICON-2506":{"nm":"Atemanzeigeband","de":"Das Band steigt und sinkt entlang der Klammer und zeichnet die Länge des Atems vor Augen. Man sieht den Takt von Einatmen und Ausatmen und folgt ihm nach – jedes Lied beginnt damit, den Atem zu beherrschen."},"ICON-2507":{"nm":"Gefühlswürfelbeutel","de":"Der Würfel, der klappernd aus dem Beutel rollt, bestimmt das Gefühl des Tages. Zeigt er Freude, freut man sich, zeigt er Wut, wird man wütend. Schauspielübung wird zu einem Spiel, das das Herz dem Zufall überlässt."},"ICON-2508":{"nm":"Drehbuchschrägständer","de":"Legt man das Drehbuch auf den schräg geneigten Ständer, muss man den Kopf nicht mehr senken. Diese kleine Neigung, die die Augenhöhe bewahrt, kümmert sich still um den vom langen Üben verspannten Nacken."},"ICON-2509":{"nm":"Flüsterschirm","de":"Ein Zeichen, dass man ab hier flüstert. Senkt man hinter dem Schirm die Stimme, hält das Publikum erst recht den Atem an und lauscht. Je leiser man spricht, desto weiter trägt es – das zärtliche Paradox der Bühne."},"ICON-2510":{"nm":"Rollentausch-Token-Box","de":"Dreht man den Token sacht um, wechselt die zugeteilte Rolle. Heute die Hauptfigur, morgen die treue Freundin an ihrer Seite. Auf der Insel, wo man gemeinsam wächst, kommt für jeden einmal die Reihe, mitten auf der Bühne zu stehen."},"ICON-2511":{"nm":"Blickpunktsticker","de":"Man lässt den Blick still auf einem kleinen Punkt neben der Kamera ruhen. In dem Moment, in dem der unstete Blick einen Ort findet, erwacht der Augenausdruck im Bild klar zum Leben. Ein Blick beginnt am Ende damit, dass man ihn anhält."},"ICON-2512":{"nm":"Bildwinkel-Dreieckslineal","de":"Wirkt eine Bildecke irgendwie schief, hält man das Dreieckslineal daran, und die Antwort zeigt sich. Es geht darum, das Schiefe gerade zu rücken. Bevor man den Augen traut, vertraut man kurz lieber dem Lineal."},"ICON-2513":{"nm":"Objektiv-Augenhöhenständer","de":"Bringt man das Objektiv auf Augenhöhe des Menschen, lügt das Bild weniger. Weder von oben noch von unten, sondern erst im Blick auf gleicher Höhe fängt es den ungeschminkten, echten Ausdruck ein."},"ICON-2514":{"nm":"Blickführungspfeil","de":"Der Blick gleitet sanft dorthin, wohin die Fahne weist. Ein kleiner Pfeil, der den Blick des Betrachters unmerklich lenkt. Ein gutes Bild winkt freundlich dahin, wohin man schauen soll."},"ICON-2515":{"nm":"Laufweg-Bodenchip","de":"Tritt man still auf einen Punkt der bis zur Erschöpfung eingeübten Laufbahn, liegt der nächste Platz sofort greifbar da. Die Schritte, die über die Bühne führen, sind ein unsichtbarer Weg, geknüpft aus solchen kleinen, in den Boden gesetzten Markierungen."},"ICON-2516":{"nm":"Kameraabstandsband","de":"Mit dem Band misst man den Abstand zwischen Motiv und Kamera. In einer Welt, in der eine Handbreit über Nähe und Ferne entscheidet, wird das Maßband zum stillen Wächter der Grenze zwischen Unschärfe und Klarheit."},"ICON-2517":{"nm":"Kopfneigungsguide","de":"Wie sehr muss man den Kopf neigen, um am liebevollsten zu wirken? Folgt man dem Guide, begreift man ganz sacht: Der Neigungswinkel gleicht am Ende genau dem Maß, in dem sich ein Herz öffnet."},"ICON-2518":{"nm":"Blickkontaktspiegelklammer","de":"Klemmt man den Handspiegel neben die Kamera, blickt man in die eigenen Augen und trifft doch deinen Blick. Ein kleines Gerät, das zwischen dem Ich im Spiegel und dem Du im Bild sacht eine Brücke aus Blicken schlägt."},"ICON-2519":{"nm":"Aufnahmesignallampe","de":"Geht das Licht an, ist das Zeichen: Jetzt wird gedreht. Eine kleine Lampe bündelt die aufgeregte Spannung des Sets. Vom Moment, in dem sie leuchtet, ordnet sich der Atem aller in einem Takt."},"ICON-2520":{"nm":"Reaktionsglocke","de":"Drückt man den Knopf, erklingt hell und klar eine Glocke. Wie der Applaus, der nach einer gelungenen Szene aufbraust, steckt in dieser kleinen Glocke jemandes warmes Wort: Gut gemacht."},"ICON-2521":{"nm":"Losbecher","de":"Schüttelt man ihn, klappern zuerst die Holzstäbchen und wecken die Stimmung. Wer die Bühne eröffnet, entscheidet ein einziger Schwung des Handgelenks – der Gezogene lächelt verlegen, die Übrigen atmen erleichtert auf. Auch im Teilen des Glücks steckt eine liebevolle Regel."},"ICON-2522":{"nm":"Effektglöckchen","de":"Kippt man das Handgelenk nur leicht, klingelt sogleich ein kleiner Kommentar dazwischen. Bevor die Stille peinlich werden kann, füllt dieses kleine Glöckchen die Lücke zuerst. Beim Zählen des Lachtakts ist es stets einen Schritt schneller."},"ICON-2523":{"nm":"Überraschungsdeckel","de":"Bis er sich öffnet, kann niemand erahnen, was darin steckt. Das ist die einzige Aufgabe dieses Deckels. Damit im Augenblick, in dem er kurz aufspringt, Schrei und Lachen zugleich losbrechen, hängt an einem einzigen Scharnier die ganze Vorfreude."},"ICON-2524":{"nm":"Reaktionsfächer","de":"Das Klack, mit dem er aufgeht, wird selbst zur Antwort. Die Fächerspeichen fächeln die Bewunderung, für die die Worte nicht reichten. Zwischen den Handbewegungen des Auf- und Zuklappens geht die Freude hin und her, und ein Zipfel des Herzens weht mit dem Wind."},"ICON-2525":{"nm":"Straf-Drehscheibe","de":"Niemand weiß im Voraus, auf welchem Feld die Nadel stehen bleibt. Je langsamer sich die Scheibe dreht, desto schneller schlägt umgekehrt das Herz – klick, und auf dem Feld, wo sie hält, steht das lustige Schicksal des Tages geschrieben. Ein paar Sekunden, in denen selbst das Zittern Freude macht."},"ICON-2526":{"nm":"Ausrufeschild","de":"Hebt man es blitzschnell über den Kopf, taucht ein 'Wow' als Schriftzug auf. Ein einziges Blatt Papier ruft das Gefühl aus, dem der Mund nicht schnell genug folgen konnte. Denn auch eine Reaktion braucht ihre Bühnenregie."},"ICON-2527":{"nm":"Stopp-Fähnchen","de":"In dem Moment, in dem die Fahne hochgeht, erstarrt alles genau dort. Ein Zeichen, das selbst den Atem im Standbild gefangen hält. Sinkt sie wieder, bricht das angehaltene Lachen auf einmal wie eine Welle hervor."},"ICON-2528":{"nm":"Fehlantwort-Klammerhalter","de":"Je schräger die Antwort, desto fester wird sie festgeklammert und aufgehängt. Wenn die falschen Antworten an der Wäscheleine im Wind schaukeln, wird die Bühne mehr geliebt für ihre Abwege als für die richtige Lösung. Das Bild eines Tages, an dem auch Irren erlaubt ist."},"ICON-2529":{"nm":"Haltungskeil","de":"Lehnt man sich an, tastet sich die gekrümmte Wirbelsäule sacht auf ihren rechten Weg zurück. Ein kleiner Keil, der wortlos stützt. Erst wenn jemand einen trägt, wird gute Haltung bequem – das flüstert er still im Rücken."},"ICON-2530":{"nm":"Beckenausrichtungsblock","de":"Eine kleine, feste Stütze, die man unterlegt, wenn der Schwerpunkt ins Wanken gerät. Das Gleichgewicht des Körpers steigt am Ende langsam vom Boden auf. An unsichtbarer Stelle trägt sie die Haltung – eine namenlose Nebendarstellerin."},"ICON-2531":{"nm":"Bauchbalanceball","de":"Klemmt man ihn an den Bauch und spannt ihn still, sammelt sich die zerstreute Mitte in einem Punkt. Je tiefer man atmet, desto fester wird der Ball, und der Körper findet Atemzug für Atemzug seine vergessene Achse wieder."},"ICON-2532":{"nm":"Wirbelsäulenlineal","de":"Legt man das Lineal am Rücken entlang, tritt die unsichtbare Krümmung auf der Skala hervor. Gerade zu stehen heißt nicht, die Kurve zu tilgen, sondern selbst diese kleine Biegung liebevoll zu lesen."},"ICON-2533":{"nm":"Schulteröffnerring","de":"Legt man ihn um die Schultern und zieht langsam, öffnet sich die eingezogene Brust weit. Die Elastizität flüstert immerfort, zurückzukehren an den eigenen Platz, und der Rücken, tagsüber gebeugt, streckt sich diesem sanften Ruf folgend Stück für Stück."},"ICON-2534":{"nm":"Core-Sandsack","de":"Legt man es um die Hüfte, wecken die schweren Sandkörner die schlafende Körpermitte. Vor diesem Gewicht wird selbst eine leichte Bewegung im Nu ernst gemeint. Dass man umso fester wird, je länger man durchhält, flüstert jedes einzelne Korn ganz still."},"ICON-2535":{"nm":"Steißbeinkissen-Anhänger","de":"Ein Kissen, das das Steißbein sanft von unten stützt, mit einem kleinen Anhänger am Ende. Ein Werkzeug wie ein liebevoller Zettel, der dem vom langen Sitzen müden Tag zuflüstert: Hier darfst du dich kurz anlehnen."},"ICON-2536":{"nm":"Rückenstütz-Dreibein","de":"Auf drei Beinen stehend hält es still den Winkel, in dem sich die Hüfte anlehnen kann. Eine Stütze, die sich unmerklich in eine einstürzende Haltung schiebt. Um das Wankende festzuhalten, genügen überraschenderweise drei Punkte."},"ICON-2537":{"nm":"Kinnhaltungsklammer","de":"Zieht man das Kinn sacht ein und stützt es, findet die verrutschte Halslinie zurück an ihren Platz. Das Nörgeln dieser fingergroßen Klammer klingt irgendwie liebevoll. Wie man den Kopf richtig hebt, lehrt dieses kleine Werkzeug."},"ICON-2538":{"nm":"Schrittleiterband","de":"Das am Boden ausgebreitete Band zeichnet Feld für Feld vor, wo der Fuß hintreten soll. Tritt man Feld für Feld ehrlich auf, prägt sich unversehens der Schritt in den Körper ein. Ein Weg wird eben klarer, je öfter man ihn betritt."},"ICON-2539":{"nm":"Richtungswechselhütchen","de":"Aufgestellt zeigt es mit einem stillen 'Hier abbiegen' die Richtung an. Es schenkt dem Fuß, der nur geradeaus lief, eine Ecke. Auch im Weg, der um die Kurve führt, verbirgt sich sein eigener Rhythmus."},"ICON-2540":{"nm":"Einbeinwackelbrett","de":"Stellt man sich mit einem Fuß darauf, kippt das Brett sacht zur Seite. Die paar Sekunden, in denen man sich mit aller Kraft gegen das Wanken stemmt, sind die ehrlichste Lektion im Gleichgewicht. Die Fußspitze, die nicht fallen will, sagt alles."},"ICON-2541":{"nm":"Reaktionsblinklicht","de":"Im Augenblick, in dem das Signal aufleuchtet, wetteifern Hand und Auge, wer zuerst ist. Das blinkende Licht lässt keine Zeit zum Zögern. Die schnelle Hand bewegt sich stets einen halben Takt vor dem Gedanken."},"ICON-2542":{"nm":"Zickzackfußmarker","de":"Kleine, schräg am Boden klebende Punkte, die den Fuß im Zickzack tanzen lassen. Schwieriger als die Gerade ist immer das Kreuzen. Folgt man tastend den Punkten, reifen die kleinen Schritte zu Kraft."},"ICON-2543":{"nm":"Balancebalken","de":"Setzt man den Fuß auf den schmalen Balken, verengt sich die Welt wie ein Hochseil. Wie ein Seiltänzer über der Leere trägt man die Konzentration des ganzen Körpers auf eine Handbreit. Das Gleichgewicht wird umso klarer, je schmaler es wird."},"ICON-2544":{"nm":"Reaktionsball-Armband","de":"Trägt man es am Handgelenk, springt der kleine Ball mit einem Schnalzen zurück. Im Augenblick von Werfen und Fangen prägt sich die Schnelligkeit der Reaktion in die Fingerspitzen ein. Schnelligkeit heißt am Ende, das Zurückkommende nie zu verpassen."},"ICON-2545":{"nm":"Fußhula-Reifen","de":"Hängt man ihn an den Fuß und lässt ihn kreisen, stachelt der Hula-Reifen unablässig die Wade an. Hält man an, fällt er herunter, also zappelt der Fuß ohne Pause. Beim spielerischen Bewegen reift die Fußarbeit rasch heran."},"ICON-2546":{"nm":"Zehenbalance-Kreisel","de":"Der Kreisel, der auf der Handfläche dreht, bleibt in dem Moment, in dem er die Mitte verliert, sofort stehen. Wie in den Kindertagen, als man im Hof Kreisel schlug: Gleichgewicht ist etwas, das erst durch endloses Drehen bestehen kann."},"ICON-2547":{"nm":"Knöchelschnürband","de":"Umschließt und schnürt es den Knöchel, wird der wackelige Tritt gleich fester. Je verletzlicher eine Stelle ist, desto liebevoller muss man sie halten. Ein einziges Band wird zur Beruhigung für jeden Schritt."},"ICON-2548":{"nm":"Kniewärmeband","de":"Wickelt man es um das kalte Knie, dringt Wärme zwischen die Gelenke. Ein steifes Gelenk wird erst weich, wenn man es erwärmt. Bevor man sich bewegt, der wärmste Morgengruß an den eigenen Körper."},"ICON-2549":{"nm":"Massageball","de":"Drückt man ihn fest auf die verspannte Stelle, streichelt die Kugel den Knoten ganz sacht. Ein seltsamer Trost: Je mehr es schmerzt, desto mehr löst es sich. Selbst die Verspannung, die keine Hand erreichte, tröstet dieser kleine Ball stellvertretend."},"ICON-2550":{"nm":"Aufwärm-Drehscheibe","de":"Man weckt den Körper von dem Feld an, auf dem die Scheibe stehen bleibt. Hals, Schultern, Knöchel – die Reihenfolge überlässt man dem Zufall und hält das Gemüt leicht. Mischt sich ins Aufwärmen ein Spiel, lächelt der erstarrte Körper als Erstes ganz sacht."},"ICON-2551":{"nm":"Gelenkwärmepackung","de":"Legt man das heiße Wärmekissen auf ein Gelenk, breitet sich eine Geborgenheit aus wie am warmen Ofenplatz im Winter. Die Zeit, in der die verhärteten Gelenke sich müde und wohlig lösen. Erst der erwärmte Körper macht sich langsam bereit, sich wieder zu bewegen."},"ICON-2552":{"nm":"Dehnzugring","de":"Zieht man am Ring, dehnt sich der verspannte Muskel in die Länge. Zwischen der haltenden Hand und dem sich streckenden Körper entspinnt sich ein gespanntes Gespräch. So weit er sich heute dehnt, so viel leichter wird morgen jede Bewegung."},"ICON-2553":{"nm":"Fußsohlen-Noppenplatte","de":"Stellt man sich barfuß auf die Noppen, schreckt die eingeschlafene Fußsohle jäh auf. Wie der stechende Reiz eines barfüßigen Gangs über Kieselsteine steigt das Gefühl, den Boden zu berühren, von den Zehenspitzen aufwärts."},"ICON-2554":{"nm":"Verletzungsmerk-Magnetpin","de":"\"Nicht übertreiben\" steht darauf geschrieben, mit einem Klick an die Metalltafel geheftet. Weil schmerzhafte Erinnerungen so leicht verblassen, hängt man sie sich als Magnet vor Augen. Auch die Sorge um den eigenen Körper beginnt am Ende mit einer einzigen Notiz."},"ICON-2555":{"nm":"Faszien-Lösestab","de":"Rollt man den geknoteten Stab langsam entlang, löst sich die verklebte Faszie Stück für Stück. Eine Hand, die sanft die Verknotungen hinausdrängt. Auch ein verspannter Tag wird leichter, wenn man ihn so Glied für Glied entfaltet."},"ICON-2556":{"nm":"Gehlinienband","de":"Legt man es gerade auf den Boden, entsteht eine Linie, der die Füße folgen können. Selbst ein unsicherer Schritt findet auf dieser Linie unversehens seine Geradheit wieder. Zeichnet man den Weg vor, verirrt sich der Fuß nicht mehr."},"ICON-2557":{"nm":"Schulterwaagestab","de":"Legt man ihn quer über die Schultern, zeigt sich leise die Schräglage, in die man geraten ist. Waagerecht zu sein heißt immer, die eine Seite zu senken und die andere zu heben. Ein einzelner Stab weist still auf die schief gewordene Gewohnheit hin."},"ICON-2558":{"nm":"Scheitelausgleichsgewicht","de":"Um das Gewicht auf dem Scheitel nicht fallen zu lassen, muss der ganze Körper sich zu einer einzigen geraden Linie aufrichten. Wie einst die Frauen, die einen Wasserkrug balancierend auf dem Kopf trugen, findet die Mitte ihren Halt von ganz oben herab."},"ICON-2559":{"nm":"Kinnwinkelstütze","de":"Stützt sie sanft das Kinn, findet der immer wieder gesenkte Kopf zu seinem rechten Winkel zurück. Eine kurze Rast, angelehnt an eine einzige Stütze. Eine gerade Haltung vollendet sich erst, wenn jemand von unten trägt."},"ICON-2560":{"nm":"Schrittweitenpflock","de":"Der in den Boden geschlagene Pflock misst im Voraus den Abstand, den der Fuß nehmen soll. Ein Schritt, weder zu weit noch zu eng, diese ehrliche Distanz. Das Gleichgewicht des Gehens beginnt still an dieser kleinen Markierung."},"ICON-2561":{"nm":"Fußspitzen-Richtkeil","de":"Der zögerliche erste Schritt – die Zehenspitzen zaudern zuerst, wohin es gehen soll. Legt dieser kleine Keil die Richtung fest, neigt sich auch das Herz leise dorthin. Den Weg zu bestimmen ist keine große Entscheidung, sondern die eine Handspanne, auf die die Zehenspitze zeigt."},"ICON-2562":{"nm":"Rückenaufrichtegurt","de":"Als lebte in diesem Gurt noch die Stimme, die immer wieder mahnte: \"Zieh den Rücken gerade, gerade!\" Richtet er einen gekrümmten Tag still auf, wird seltsamerweise auch die Last auf den Schultern ein wenig leichter. Eine einzige Haltung richtet auch das Herz mit auf."},"ICON-2563":{"nm":"Gewichtsverteilungs-Trittplatte","de":"Sieben auf den linken Fuß, drei auf den rechten. Wohin man das Gewicht mehr verlagert, entscheidet über das Gleichgewicht. Die Trittplatte fragt still: Auf welche Seite neigst du dich gerade mehr? Aufrecht zu stehen ist in Wahrheit ein ständiges Nachjustieren."},"ICON-2564":{"nm":"Blickhöhen-Zielstab","de":"Der Blick fällt immer wieder zu den Zehenspitzen hinab. In solchen Momenten zieht ein Stab, weit entfernt aufgestellt, den Blick langsam nach oben. Weit zu blicken ist Übung darin, weit zu gehen – und sobald sich der Kopf hebt, rückt selbst das unerreichbar Scheinende näher."},"ICON-2565":{"nm":"Verbeugungswinkel-Kartenklammer","de":"Fünfzehn Grad, dreißig Grad, fünfundvierzig Grad. So tief sich der Rücken beugt, so tief neigt sich auch das Herz. Der Winkel auf der Karte ist keine bloße Zahl, sondern eine kleine Skala, die die Aufrichtigkeit gegenüber dem anderen misst."},"ICON-2566":{"nm":"Handfaltungsring","de":"Legt man die beiden Hände ordentlich zusammen, kommt auch das aufgeregte Herz ruhig an einem Ort zur Ruhe. Diese kleine Schlaufe hält liebevoll die unruhigen, ratlosen Fingerspitzen fest und formt still die erste Haltung der Begrüßung."},"ICON-2567":{"nm":"Laufweg-Pfeilmagnet","de":"Was ein verirrter Fuß als Erstes suchend erblickt, ist ein Pfeil. Eine einzige, am Magneten haftende Richtung durchbricht das Zögern und zieht die Schritte sacht dorthin, wohin sie gehen sollen. Auch das umherirrende Herz findet endlich eine Richtung."},"ICON-2568":{"nm":"Ausgangsmarkierungspin","de":"Der Weg hinaus ist immer schwerer als der Weg herein. Selbst in der Dunkelheit nach dem Erlöschen der Lichter leuchtet dieser Pin klar und weist still den letzten Weg. Erst am Ende begreift man, dass auch das gute Abgehen noch zur Bühne gehört."},"ICON-2569":{"nm":"Verbeugungsreihenfolge-Band","de":"Es gab Zeiten, in denen klar feststand, wer zuerst und wer danach sich verneigte. Senkt man den Körper in der auf dem Band vermerkten Reihenfolge, bekommt selbst die Höflichkeit eine Struktur und der Anstand einen Fluss. Es ist die Wahrung der inneren Rangfolge des Herzens."},"ICON-2570":{"nm":"Gleichschrittchip","de":"Gerät eine einzige Person aus der Reihe, gerät die ganze Linie ins Wanken. Wie ein Chip, der mit einem Klick an der Zehenspitze einrastet, heißt gemeinsam zu stehen, dem Nebenmenschen leise die eigene Schrittweite abzutreten. Am verlässlichsten klingen die Schritte, die im selben Takt fallen."},"ICON-2571":{"nm":"Bühnenverbeugungsmarke","de":"Selbst für eine einzige Verbeugung auf der Bühne gibt es einen festen Platz. Stellt man den Fuß auf die hufeisenförmig ausgebreitete Markierung, findet die vor Nervosität immer wieder misslungene erste Verbeugung endlich ihre Form. Kennt man seinen Platz, legt sich auch das Zittern ein wenig."},"ICON-2572":{"nm":"Dankesgestenkarte","de":"Was in Worten nicht ganz gesagt werden kann, fließt aus den Fingerspitzen. Ein Herz formen, die Hand auf die Brust legen – jede einzelne Geste auf der Karte wird zur Übersetzung des Herzens. Aufrichtigkeit, die ankommen will, hat immer eine Form."},"ICON-2573":{"nm":"Warteabstandspflock","de":"Auch das Anstellen in einer Reihe hat seine freundliche Etikette. Wie ein Pflock, der genau eine Handspanne Abstand zur Person davor bewahrt, beginnt das Warten mit der kleinen Rücksicht, einander nicht zu drängen. Ein wenig Abstand zu halten ist ebenfalls eine Form der Fürsorge."},"ICON-2574":{"nm":"Stichwortkartenring","de":"Wenn die nächste Ansage immer wieder auf den Lippen kreist, blättert der Finger unauffällig ein Blatt weiter. Die am Ring aufgereihten kleinen Zettel dämpfen still das Herzklopfen und breiten ruhig das Feld der nächsten Worte aus. Auch mit zitternden Händen reißt der Fluss nicht ab."},"ICON-2575":{"nm":"Ablaufsanduhr","de":"Betrachtet man still die rieselnden Sandkörner, ordnet sich der nächste Programmpunkt ruhig im Kopf. Bis das letzte Korn gefallen ist, lehrt einen diese kleine Uhr, die Zeit mit den Augen zu lesen, ohne sich zu hetzen."},"ICON-2576":{"nm":"Mikrofonhaltestab","de":"Bevor die Hand sich daran gewöhnt hat, wiegt ein leerer Stab schwer wie tausend Pfund. Der Winkel des Griffs, der Abstand zum Mund, die Kraft im Handgelenk – unzählige Male gegriffen und wieder losgelassen, blüht die Übung eines Tages unversehens zu einer ganz natürlichen Bewegung auf."},"ICON-2577":{"nm":"Ausspracheübungsstab","de":"Ga, na, da, ra. Man beißt auf den Stab und formt die Laute, bis die Zungenspitze klar und deutlich wird. Ein Wort, das endlich deutlich herüberkommt, ist wie eine Blume, die still über Hunderten von stockenden, verwaschenen Stunden aufblüht."},"ICON-2578":{"nm":"Signalfähnchen","de":"Start, Stopp, einen Takt Pause. Ein einziges Fähnchen, ganz ohne Worte, dirigiert den Atem der Bühne. Von einem Platz, den das Publikum nicht sieht, hält eine still winkende Hand jeden einzelnen Takt lückenlos fest."},"ICON-2579":{"nm":"Übergangsglöckchen","de":"Klingelt es hell und klar, wechselt die Szene. Wie der Glockenklang, der sich einst in der Abenddämmerung über den Marktplatz ausbreitete, trägt dieser eine kleine Klang das zögernde Herz sanft in die nächste Szene hinüber. Übergänge beginnen immer mit einem Klang."},"ICON-2580":{"nm":"Atemtaktpendel","de":"Einatmen – eins, zwei – langsam ausatmen. Folgt man mit dem Atem dem hin und her schwingenden Pendel, findet auch das hastig hervorgestoßene Wort unversehens seinen eigenen Takt zurück. Das Tempo der Worte war am Ende immer das Tempo des Atems."},"ICON-2581":{"nm":"Ablaufplan-Klapptafel","de":"In der einen Bewegung des Auf- und Zuklappens ist die gesamte heutige Reihenfolge enthalten. In dem Moment, in dem sich die von Handspuren geprägte Tafel öffnet, reiht sich das wirr durcheinandergehende Herz ruhig in eine Ordnung. Ein einziges Aufklappen bringt den ganzen Tag in Ordnung."},"ICON-2582":{"nm":"Atemtaktsanduhr","de":"Drei Zählzeiten einatmen, vier halten, sechs ausatmen. Während der Sand rieselt, fließt auch mein Atem still mit. Den Atem Zug für Zug zu zählen ist die älteste und liebevollste Art, sich selbst inmitten der Hast langsam zu umsorgen."},"ICON-2583":{"nm":"Meditationskissenquaste","de":"Die am Rand des Kissens befestigte Quaste schwingt still, auch ohne einen Windhauch. Setzt man sich im Schneidersitz nieder, kehrt jene Stille, in der einst die Alten auf der Veranda saßen und ihr Herz besänftigten, leise ein und verweilt eine Weile an der Seite."},"ICON-2584":{"nm":"Atemwindspiel","de":"Streift ein Windhauch vorbei, weint ein klarer Klang still auf. Wie ein Windspiel an der Dachtraufe hängend, lässt es einen kühlen, klaren Tropfen auf das aufgewühlt brodelnde Herz fallen. Auch ein Klang besitzt die Kraft, zu kühlen."},"ICON-2585":{"nm":"Räucherschale","de":"Der Rauch des verglühenden Räucherstäbchens sinkt langsam auf den Teller herab. Wie der Duft, der einst am Feiertagsmorgen vor dem Ahnentisch aufstieg, legt eine einzige Rauchschwade die unruhige Luft sacht zur Ruhe und füllt den Raum mit Stille."},"ICON-2586":{"nm":"Atempendel","de":"Auf ein Pendel, das langsam steigt und wieder sinkt, legt sich mein Atem. Beim Einatmen hebt es sich, beim Ausatmen sinkt es – an Tagen, an denen der Körper verlernt hat zu atmen, lehrt diese kleine Uhr es von Neuem, ganz von vorn."},"ICON-2587":{"nm":"Meditationsglockenschlägel","de":"Schlägt man die Glocke einmal sanft an, breitet sich der Nachklang lange aus. Wie der Klang der Windspiele, der einst durch einen Bergtempel hallte, wird ein Teil des Herzens klar reingespült, allein indem man still zuhört, bis der Klang gänzlich in der Luft verklungen ist."},"ICON-2588":{"nm":"Atemführungsfeder","de":"Hält man die Feder still vor die Nase, wird der unsichtbare Atemweg endlich sichtbar. Wiegt sie sich sacht, atmet man gut; bleibt sie still, hat man den Atem zu lange angehalten. Das Leichteste wird manchmal zum ehrlichsten Wegweiser."},"ICON-2589":{"nm":"Beruhigungskiesel","de":"Der in der Handfläche gehaltene Kiesel ist kühl und glatt. Wie ein Stein, der am Flussufer lange gerollt ist und all seine Kanten hergegeben hat, schleifen sich beim wiederholten Reiben mit den Fingerspitzen auch die scharfen Kanten des aufgewühlten Herzens nach und nach rund."},"ICON-2590":{"nm":"Atemtemperaturclip","de":"Die Temperatur an der Nasenspitze verrät still die Tiefe des Atems. Die Luft, die kalt hinein- und warm hinausströmt, liest der Clip leise ab und macht den Atem, den man sonst kaum spürt, deutlich vor Augen sichtbar. Auch der Atem hat seinen eigenen Ausdruck."},"ICON-2591":{"nm":"Stimmungswettertafel","de":"Ist mein Herz heute sonnig oder bewölkt? In dem Moment, in dem man einen kleinen Sticker wählt und auf die Tafel klebt, nimmt selbst ein Gefühl, das sich in Worten kaum fassen lässt, als eine Art Wetter eine klare Gestalt an. Auch das Herz braucht seinen Wetterbericht."},"ICON-2592":{"nm":"Gefühlsfarbstempel","de":"Freude ist Gelb, Trauer ist Blau. Wählt man eine Farbe und drückt sie fest aufs Papier, bleibt die Farbe des Herzens als Abdruck zurück. Selbst ein Gefühl, dem man ratlos keinen Namen geben konnte, wird von der Farbe zuerst still erkannt."},"ICON-2593":{"nm":"Stimmungsblütenchip","de":"Auf ein einzelnes Blütenblatt legt man sacht die Stimmung des heutigen Tages. Ein Chip, leicht und zart wie die im Frühling verwehten Azaleenblüten, fragt am Ende des vergehenden Tages leise, ob es einem gut ergangen sei."},"ICON-2594":{"nm":"Ermutigungs-Sprechblasenmagnet","de":"Das Wort, das man sagen möchte, kreist immer wieder auf den Lippen. In dem Moment, in dem man den Sprechblasenmagneten daran heftet, erreicht ein Ermutigungswort, das man nicht laut aussprechen konnte, sacht den erschöpften Tag eines anderen. So werden Gefühle weitergegeben."},"ICON-2595":{"nm":"Herzensbriefsiegel","de":"Worte, die man noch nicht aussprechen konnte, werden fein in einen Umschlag gelegt und versiegelt. Wie die Alten, die mit den Fingerspitzen Kleister auftrugen, um ihre Briefe zu verschließen, bewahrt ein einziges Siegel die innersten Gedanken sicher auf. Und wartet still auf den Tag, an dem man sie eines Tages wieder hervorholt und entfaltet."},"ICON-2596":{"nm":"Gefühlsknospe","de":"Die geschlossene Knospe berührt Wärme und öffnet sich Blatt für Blatt behutsam. Sie blüht mit, wenn die Temperatur des Herzens steigt – wie sehr ich mich heute erwärmt habe, weiß diese Blume noch vor jedem Wort. Auch ins Herz zieht der Frühling ein."},"ICON-2597":{"nm":"Selbstlob-Handspiegelband","de":"Man hebt den Spiegel und begegnet still den eigenen Augen, die darin erscheinen. Was die kleine, am Band hängende Fläche spiegelt, ist nicht das Gesicht, sondern das gestrige Ich, dem man ein Wort schulden sollte – dass es gut durchgehalten hat. Trost war nie weit entfernt."},"ICON-2598":{"nm":"Gefühlsausdrucksstempel-Set","de":"Ein strahlendes Lachen, tränenverhangene Augen, schmollend gespitzte Lippen. Man drückt die Gesichtsausdruck-Stempel fest aufs Papier und schreibt so ein Tagebuch des Herzens. An Tagen, die zu überwältigend sind, um sie in Worte zu fassen, erzählt ein kleines Gesicht still an meiner Stelle von der Stimmung dieses Tages."},"ICON-2599":{"nm":"Gefühlsknäuelring","de":"Selbst das verworrenste Knäuel Garn löst sich, Faden für Faden in aller Ruhe entwirrt, am Ende zu einem einzigen Strang zurück. Hängt man die vermischten, beklemmenden Gefühle nacheinander an den Ring, findet sich auch im undurchschaubaren eigenen Herzen ein feiner Faden, an dem man ansetzen kann."},"ICON-2600":{"nm":"Einschlafduftsäckchen","de":"Aus dem am Kopfende hängenden Duftsäckchen breitet sich still ein zarter Kräuterduft aus. Wie der Geruch, den Großmutter tief im Schrank verwahrte, löst sich, während die Finger die Schnur berühren, die den ganzen Tag über angespannte Nervosität leise in Schlaf."},"ICON-2601":{"nm":"Schlafwendeplatte","de":"Eine Nacht, in der man sich hin und her wälzte und erst im Morgengrauen kaum einschlief. Dreht man die liegende Haltung sanft um, geht das gestrige Wälzen leise in die Frische des heutigen Morgens über. Auch Ruhen ist eine Übung, hilft diese kleine Platte wortlos mit."},"ICON-2602":{"nm":"Mondlicht-Kissenhänger","de":"Das durch den Vorhangspalt hereinfallende Licht hängt man als ein Stück am Kopfende auf. Über das schlafende Gesicht fließt still ein sanfter Fluss, und erst dann wurde auch die Nacht des Trainees, der sich vor der Dunkelheit fürchtete, weich. Es war der erste kleine Trost, der ihm zuteilwurde."},"ICON-2603":{"nm":"Verfassungsknospenchip","de":"Die heutige Verfassung ist geschlossen wie eine Knospe. Drückt man auf den Chip, öffnet er sich langsam – ob man gut oder schlecht geschlafen hat, weiß der Körper zuerst. Selbst das Zögern vor dem vollen Aufblühen ist auf stille Weise liebenswert."},"ICON-2604":{"nm":"Nachtlicht-Dochtkappe","de":"\"Bitte das Licht nicht ausmachen.\" Für den Jüngsten, der sich vor der Dunkelheit fürchtete, hat jemand sacht eine Abdeckung über den Docht gelegt. Weder zu hell noch zu dunkel – ein kleines, liebevolles Versprechen, das nur bis zum Einschlafen an seiner Seite wacht."},"ICON-2605":{"nm":"Sonnenblumen-Weckpin","de":"Steckt man sie ans Kopfende, wendet sie sich sanft dem ersten Sonnenstrahl zu, wie eine Sonnenblume. Selbst an Tagen, an denen man nicht aufstehen möchte, hat der Ruf des Lichts seinen Grund, und sie führt den Morgen in eine einzige Richtung."},"ICON-2606":{"nm":"Schlafkräuterkissenbürste","de":"Man taucht die Bürstenspitze in Lavendel und Kamille und streicht damit einmal über das Kissen. Während der Duft in den Kissenbezug einzieht, löst sich die Anspannung des Tages langsam von den Schultern. Guter Schlaf beginnt mit diesem kleinen Duft."},"ICON-2607":{"nm":"Bettdeckenklammer","de":"Gegen Morgen entkommen die Zehenspitzen immer wieder unter der Decke hervor. Klemmt man die Ecke fest mit der Klammer, kann die Wärme die ganze Nacht nicht entweichen. Es ist eine kleine Vorsorge, die man anstelle eines Gutenachtgrußes trifft."},"ICON-2608":{"nm":"Wohlbefindenskieselkorb","de":"Eine gute Sache am Tag, ein Kiesel von der Größe einer Handfläche. Je schwerer die im Korb gesammelten Steine werden, desto sicherer fühlt sich auch das Herz. Unscheinbare Momente in der Hand zu halten und zu sammeln – Glück wird eigentlich genau so gezählt."},"ICON-2609":{"nm":"Vorsatzsterneglas","de":"Jede Nacht formt man den heutigen Vorsatz zu einem Stern und lässt ihn in das Glas fallen. Ist es einmal voll, wird das Glas zu einem kleinen Nachthimmel. Die einst leere Öffnung weiß es: Versprechen leuchten erst, wenn man sie sammelt."},"ICON-2610":{"nm":"Belohnungsbonbonhalter","de":"Am Ende eines mühsamen Tages ein Bonbon, das man sich selbst schenkt. Nimmt man eines vom Halter und steckt es in den Mund, wird es auf einmal in Ordnung, dass niemand einen bemerkt hat. Denn eine kleine Belohnung ist die ehrlichste Form der Ermutigung."},"ICON-2611":{"nm":"Geschafft-Stempel","de":"Tinte aufs Pad, dann ein fester Druck ins Heft: „Heute geschafft.“ Ob ein guter Tag oder nur ein durchgehaltener – beide füllen genau ein Feld. Nicht jeder Tag muss vollkommen sein, man muss nur weiter stempeln."},"ICON-2612":{"nm":"Jubelflaggen-Ständer","de":"Fest in den Boden gesteckt, flattert die Flagge umso kräftiger, je stärker der Wind bläst. Auch das Schwankende braucht eine stützende Hand. So hält die Anfeuerung von unten durch."},"ICON-2613":{"nm":"Zielsamen-Topf","de":"Ein Ziel spricht man nicht nur aus, man vergräbt es in der Erde. Während man ein Samenkorn einpflanzt und gießend wartet, verwandelt sich Ungeduld langsam in Wurzeln. Im Topf wächst nicht nur ein Keimling."},"ICON-2614":{"nm":"Lobsticker-Tafel","de":"Für jede gute Tat ein Sticker mehr. Je bunter die Tafel sich füllt, desto lebendiger kehren die achtlos vergangenen Tage in Farbe zurück. Schon als Kinder wussten wir: Lob wird klarer, je mehr man davon aufklebt."},"ICON-2615":{"nm":"Versprechensschleifen-Ring","de":"Die Hand fädelt das Band durch den Ring und schürzt den Knoten. Fest genug, damit er sich nicht löst, doch nicht zu stramm. Ein Vorsatz gleicht genau diesem Knoten: zu fest gezogen reißt er, zu locker gleitet er heimlich auf."},"ICON-2616":{"nm":"Erfolgs-Muschelchip","de":"Am Strand aufgelesen, trägt die Muschelschale nun einen kleinen Erfolg. Wie ein Stück, das die Wellen lange geschliffen und geglättet haben, bis es hierher fand, glänzt auch dein Tag, lange gerollt und blank poliert. Was die Zeit übersteht, beginnt irgendwann zu leuchten."},"ICON-2617":{"nm":"Medaillenhaken","de":"Eine hart erkämpfte Medaille gehört nicht in die Schublade, sondern auf Augenhöhe. Am Haken hängend richtet ihr Gewicht jeden Morgen die Schultern auf. Belohnung will nicht versteckt werden – sie wird aufgehängt, damit man sie ansieht."},"ICON-2618":{"nm":"Tropfschale für Regenschirme","de":"Der Regen der Regenzeit rinnt in kleinen Tropfen die Schirmspitze hinab. Steht eine Schale bereit, bleibt der Flur trocken. Den Regenguss selbst kann man nicht aufhalten, doch man kann bestimmen, wo er landet."},"ICON-2619":{"nm":"Kühlpack","de":"Hinter der Bühne im Hochsommer, ein kühles Päckchen kurz an den Nacken gehalten. Die aufgestaute Hitze sinkt für einen Takt herab. „Verschnauf mal.“ Eine Hand, die vor der Hitze zuerst an mich denkt, gibt Halt."},"ICON-2620":{"nm":"Ventilatorflügel-Klemme","de":"Auch der wild rotierende Flügel kommt mit einem einzigen Clip ruhig zum Stillstand. Je stürmischer der Wind, desto nötiger etwas, das ihn fest im Griff hält. Was sich schnell dreht, wird letztlich sicher durch die Hand, die es hält."},"ICON-2621":{"nm":"Schuhtrockner-Stab","de":"Nasse Schuhe machen über Nacht auch das Gemüt feucht und schwer. Steckt man den Stab hinein, lassen sie sich morgens wieder trocken anziehen. Nasses wirft man nicht weg – man trocknet es behutsam."},"ICON-2622":{"nm":"Stiefel-Abstreifmatte","de":"Gummistiefel, voller Erde vom Reisfeldrain. Erst nachdem man sie auf der Matte tüchtig abgestreift hat, betritt man die Diele. Den Matsch von draußen vor der Tür zu lassen, ist eine alte Höflichkeit gegenüber dem eigenen Zuhause."},"ICON-2623":{"nm":"Sommer-Kühlfliese","de":"Die nackten Füße wissen es zuerst. Berührt die Sohle das Fliesenstück auf dem Sommerboden, weicht die Hitze des Tages einer Handvoll Kühle. Schon eine kleine Kälte macht eine lange Jahreszeit erträglich."},"ICON-2624":{"nm":"Türschwellen-Regenleiste","de":"Nur ein Band um die Schwelle gelegt, und schon kommt kein Regenwasser mehr herein. Eine schmale Linie, die drinnen und draußen trennt. Für das, was es zu schützen gilt, taugt eine sorgfältige Grenze mehr als eine gewaltige Mauer."},"ICON-2625":{"nm":"Moskitospiralen-Teller","de":"An Sommerabenden steigt vom Teller unter der Moskitospirale beißender und doch vertrauter Rauch auf. Wie die Spirale sich rund verglimmt, vertieft sich langsam auch die Nacht. Das ist der Geruch jener Zeit, als man auf der Liege lag und Sterne zählte."},"ICON-2626":{"nm":"Kühlärmel-Clip","de":"Vor der stechenden Sonne schützt der Ärmling den Unterarm. Mit dem Clip fest am Ärmelsaum befestigt, lässt sich auch die Mittagsarbeit ertragen. Kühle ist die kleine Fürsorge, die eine Handbreit Haut beschattet."},"ICON-2627":{"nm":"Laubbesen","de":"Mit dem Handbesen kehrt man das Laub zusammen, das den ganzen Hof bedeckt. Eine Jahreszeit raschelt unter den Füßen. Etwas aufzuräumen heißt manchmal auch, das, was geht, behutsam zu verabschieden."},"ICON-2628":{"nm":"Lüftungsfenster-Stütze","de":"In der stickigen Stube hält ein Stab das Fenster einen Spalt offen. Leise weht der Herbstwind herein und trägt die abgestandene Luft davon. Lüften ist der kleine Atemzug, der drinnen Gestautes still gegen draußen tauscht."},"ICON-2629":{"nm":"Eichel-Beutelverschluss","de":"Wie ein Eichhörnchen den Beutel randvoll mit Eicheln füllt und den Verschluss fest zudrückt. Damit nichts herausrollt. Das Gesammelte zu bewahren – das ist der alte Instinkt kleiner Wesen, die den Winter überstehen müssen."},"ICON-2630":{"nm":"Deckenklopfer","de":"Die sommerüber genutzte Decke wird im Hof aufgehängt und mit dem Klopfer tüchtig ausgeklopft. Zwischen dem Staub verbreitet sich der Geruch von Sonnenlicht. Dass man die alte Jahreszeit ausklopfen muss, um die neue darunterzulegen, weiß zuerst das Handgelenk."},"ICON-2631":{"nm":"Fensterspalt-Dichtschnur","de":"Mit nur einer Schnur wird die kalte Luft, die durch den Fensterspalt kriecht, sorgfältig aufgehalten. Ein einziger dünner Strang bewahrt die Wärme des Zimmers bis zum letzten Winkel. Große Kälte beginnt immer in einer kleinen Ritze – das weiß die Wintervorbereitung."},"ICON-2632":{"nm":"Laubfangnetz-Abdeckung","de":"Ein Sieb bedeckt die Regenrinne. Laub wird fein herausgefiltert, nur das Wasser fließt weiter. Um ungehindert zu fließen, muss man entscheiden, was hindurchgelassen und was festgehalten wird – so spricht die herbstliche Dachtraufe."},"ICON-2633":{"nm":"Heubündel-Klammer","de":"Ein knochentrockenes Grasbündel wird von der Klammer fest zusammengehalten. Eine Hand, die zusammenbindet, was auseinanderstreben will. Selbst dort, wo alles Sommergrün längst gewichen ist, bleibt der Nutzen erhalten, solange man sammelt."},"ICON-2634":{"nm":"Herbstwind-Windspiel","de":"Weht der Wind, schaukelt der kleine Anhänger sacht. An der Weite seines Schwingens misst man, wie tief der Herbst heute schon ist. Temperatur erreicht die Hand nicht als Zahl, sondern zuerst als sanftes Schaukeln."},"ICON-2635":{"nm":"Handwärmer-Etui","de":"„Deine Hände sind bestimmt kalt.“ Das Handwärmer-Etui in der Jackentasche wärmt die klammen Finger ganz leise auf. Die Sorge um die Kälte eines anderen liegt immer schon still in einer Tasche bereit."},"ICON-2636":{"nm":"Tauwasser-Fensterleiste","de":"Was das Winterfenster die ganze Nacht geweint hat, fängt die Leiste still auf. Ein kleiner Wasserlauf, geschaffen vom Temperaturunterschied zwischen drinnen und draußen. Je größer der Unterschied, desto mehr fließt – das zeigt das Morgenfenster jeden Tag aufs Neue."},"ICON-2637":{"nm":"Ofenschutzgitter","de":"Vor dem lodernden Ofen steht das Schutzgitter. Die Wärme darf nah sein, die Gefahr bleibt genau eine Handbreit fern. Das Feuer neben sich zu haben, ohne sich zu verbrennen – das ist der einfachste Abstand der Fürsorge."},"ICON-2638":{"nm":"Bettdecken-Klammer","de":"Rutscht die dicke Winterdecke immer wieder weg, drückt die Klammer sie still an ihren Platz zurück. Schwere Wärme muss man fest halten, damit sie ihren Wert behält. So wird die Geborgenheit der Winternacht sorgfältig bewahrt."},"ICON-2639":{"nm":"Eiskratzer","de":"In der Morgendämmerung kratzt der Eiskratzer den weißen Raureif von der Windschutzscheibe. Zeile für Zeile öffnet sich die trübe Sicht. Auch das Erstarrte lässt sich am Ende abkratzen – das lehren die Fingerspitzen eines Winterfrühs."},"ICON-2640":{"nm":"Wärmflaschen-Hülle","de":"Über den Deckel des Warmwasserbehälters zieht man eine Isolierhülle. Damit die Wärme die Nacht über nicht erlischt, umhüllt sie die Glut noch einmal zusätzlich. Wärme lange zu bewahren heißt am Ende, sie sorgfältig in etwas zu betten."},"ICON-2641":{"nm":"Türfugen-Andrückleiste","de":"Der eisige Wind, der sich durch den Türspalt zwängt, stockt, sobald er auf dich trifft. Ein einziger Stab, der den Saum des Fensterpapiers fest andrückt. Erst dann schützt die Wärme des Zimmers ihre eigenen Leute – der Winter wird mit solch kleiner Beharrlichkeit warm überstanden."},"ICON-2642":{"nm":"Fußwärmer-Unterteller","de":"Der runde Teller unter dem Fußwärmer. Er nimmt die ganze Hitze allein auf und hinterlässt doch keinen einzigen Rußfleck auf dem Boden. Wenn irgendwo Zehen sich behaglich wärmen, endet mein Tagwerk still und unbemerkt."},"ICON-2643":{"nm":"Wischtuch-Aufhänger","de":"Damit das Tuch, das die Tropfen vom Morgenfenster gewischt hat, nirgendwo herrenlos herumliegt, wartet ein Haken an der Wand. Nicht das satte Vollsaugen macht das Wesen des Aufsaugens aus, sondern getrocknet den nächsten Morgen zu erwarten."},"ICON-2644":{"nm":"Handschuhtrockner","de":"Nach einer Schneeballschlacht spreizt der Handschuh neben dem Heizkörper seine Finger weit. Am Haken hängend steigt ihm sanft der Dampf empor. Nach einem Nachmittag mit roter Nasenspitze ist das die friedlichste Wäsche des Winters."},"ICON-2645":{"nm":"Staubwedel-Ersatzfedern","de":"Sind die Federn abgenutzt, tauscht man sie gegen neue aus. Der Moment, in dem die staubjagende Spitze wieder flauschig wird. Dass auch ein Putzgerät seinen Jahreszeitenwechsel hat, verrät dieser kleine Austausch leise in der Handfläche."},"ICON-2646":{"nm":"Mopp-Wringgriff","de":"Ein Griff, der dem Handgelenk etwas Kraft ersparen soll. Einmal gedreht, gibt der Lappen sein Wasser von selbst her. Vorbei die Zeit, in der man sich über dem Waschbrett abmühte. In der Hausarbeit wird eine Prise Geschick zu Zärtlichkeit."},"ICON-2647":{"nm":"Bodenbürsten-Ersatzkopf","de":"Ist die Bodenbürste abgenutzt, wechselt man nur den Kopf aus. Der Stiel bleibt, das vertraute Gewicht in der Hand bleibt. In langlebigen Dingen wohnt eine kleine, feste Zärtlichkeit, die nichts im Ganzen wegwerfen will."},"ICON-2648":{"nm":"Fusselrollen-Nachfüller","de":"Reißt man das letzte Blatt der Fusselrolle ab, fühlt sich das seltsam leer an. Dann kommt die neue Nachfüllrolle. Auch dem letzten Flusen-Fussel auf dem Pullover noch die Treue zu halten – das ist das beharrliche, zärtliche Versprechen des Nachfüllens."},"ICON-2649":{"nm":"Ecken-Staubkratzer","de":"Selbst in der Ecke, die der Besen nicht erreicht, richtet sich der Staub still häuslich ein. Mit der dünnen Spitze kratzt man ihn gezielt heraus. Auch das Unsichtbare mitzudenken, das ist der eigentliche Stolz der Hausarbeit."},"ICON-2650":{"nm":"Besenkamm","de":"Auch der Besen, der gerade gekehrt hat, braucht eine ausruhende Hand. Kämmt man mit diesem Kamm die Haare aus den Borsten, ist der Besen nach getaner Arbeit endlich bereit für den nächsten Kehrgang."},"ICON-2651":{"nm":"Parkettwachs-Pad","de":"Zieht man dem Maserverlauf entlang eine Schicht Wachs auf, erinnert sich das Holz langsam an einen Glanz, den es lange vergessen hatte. Die Fußsohle gleitet fast ein wenig – das ganze Haus lächelt an diesem Nachmittag blank und zufrieden."},"ICON-2652":{"nm":"Türspalt-Staubfeger","de":"Ich habe es auf den Staub abgesehen, der im Türspalt haust. Was sich bei jedem Öffnen und Schließen der Tür heimlich ansammelt, kehre ich mit meinem schmalen Körper zusammen. Je schmaler und tiefer der Spalt, desto sicherer kommt mein Einsatz."},"ICON-2653":{"nm":"Fußmatten-Netzkappe","de":"Damit der Staub, den die Fußmatte am Eingang verschluckt hat, nicht wieder nach draußen entweicht, steht eine Netzkappe als letzter Türwächter. Der Staub, den schmutzige Schuhe aus der Außenwelt mitbringen, soll genau hier seine Grenze finden."},"ICON-2654":{"nm":"Wasserhahn-Kalkbürste","de":"Am Hals des Wasserhahns hat sich still Kalk angesetzt – eine kleine Bürste dreht sich rundherum und trägt ihn ab. Gerade die Stellen, die die Hand täglich berührt, sollen am meisten glänzen. Das ist die Höflichkeit im Bad, für die diese kleine Bürste sorgt."},"ICON-2655":{"nm":"Abflusssieb","de":"Das Haar, das den Abfluss hinuntertreiben wollte, halte ich still fest. Eine kleine Katastrophe namens Verstopfung mit nur einer Kappe abzuwenden. Der Alltag dieses runden, zuverlässigen Helden fließt still unter deinen Füßen dahin."},"ICON-2656":{"nm":"Fugenkratzer","de":"Zwischen den weißen Fliesen breitet sich dunkel der Schmutz vieler Jahre in den Fugen aus – ein letztes Mal wird er sanft herausgekratzt. Werden die schmalen Zwischenräume wieder makellos, atmet das ganze Bad auf, als wäre es neu."},"ICON-2657":{"nm":"Duschkopf-Reinigungsnadel","de":"Sticht man mit der Nadelspitze die verstopften Löcher des Duschkopfs frei, ergießt sich das Wasser, das nur noch tröpfelte, wieder erfrischend kräftig. Das befreiende Rauschen eines Morgens, an dem sich eine kleine Verstopfung endlich löst."},"ICON-2658":{"nm":"Toilettenbürsten-Halter","de":"Auch eine Klobürste ist erst an einem trockenen Platz wirklich hygienisch. Ordentlich steckt sie im kleinen Becher, der die Tropfen auffängt, und wartet auf ihren nächsten Einsatz. Die Würde eines Werkzeugs zeigt sich nicht im Gebrauch, sondern in seiner Aufbewahrung."},"ICON-2659":{"nm":"Schimmelschwamm","de":"An der Fliesenecke hat sich schwarz und hartnäckig Schimmel breitgemacht – der Schwamm bittet diesen zähen Gast höflich zum Abschied. Ein einziger Wisch, und das Bad kehrt strahlend zu seinem ursprünglichen Weiß zurück."},"ICON-2660":{"nm":"Spiegelwischer","de":"Nach der Dusche, vor dem trüb beschlagenen Spiegel, zieht der Wischer eine einzige Linie – und schon kehrt das klare eigene Gesicht zurück. Der Moment, in dem man dem Ausdruck des heutigen Tages wieder begegnet, der sich kurz hinter dem Dampf versteckt hatte."},"ICON-2661":{"nm":"Badeschuh-Aufhänger","de":"Hängt man die nassen Schlappen kopfüber auf, rinnt das Wasser leise ab und die Innenseite trocknet weich. Damit der nächste Fuß nicht in die Kälte tritt. Die Fürsorge eines kleinen Aufhängers eilt immer einen Schritt voraus."},"ICON-2662":{"nm":"Nagelbürsten-Etui","de":"Auch die kleine Bürste, die den Schmutz unter den Nägeln herausschrubbt, hat ein eigenes Zuhause. Im Etui verwahrt trocknet sie fusselfrei und wartet auf das nächste Waschbecken. Ordentlichkeit beginnt immer leise beim Aufräumen."},"ICON-2663":{"nm":"Zahnbürsten-Hygienedeckel","de":"Auch die Zahnbürste, die zweimal täglich den Mund berührt, braucht einen kleinen Zufluchtsort. Sobald der Hygienedeckel sich sanft schließt, wird ein Fleckchen Reinheit vor der Feuchtigkeit des Bades bewahrt."},"ICON-2664":{"nm":"Wattestäbchen-Reisekapsel","de":"Damit die Wattestäbchen im Reisegepäck nicht abbrechen oder sich verstreuen, hält eine Kapsel sie behutsam zusammen. Je kleiner ein Ding ist, desto mehr muss man es vorher versorgen, um auf fremden Wegen nicht ratlos dazustehen."},"ICON-2665":{"nm":"Hauch-Prüfplättchen","de":"Haucht man in die hohle Hand und hält sie kurz an die Mini-Platte, beschlägt sie zart von deinem Atem. Den niedlichsten Beweis dafür, dass ich an einem kalten Tag hier lebendig bin, hält dieses kleine Plättchen wortlos fest."},"ICON-2666":{"nm":"Ohrlöffel-Etui","de":"Reist das Ohrlöffelchen in der Tasche mit, stumpft seine Spitze leicht ab. Deshalb gibt es dieses kleine Zuhause. Darin, mitgenommen und doch unversehrt, schläft das feine Werkzeug sanft."},"ICON-2667":{"nm":"Taschentuchklammer","de":"Ein ordentlich in vier Ecken gefaltetes Taschentuch hält die Klammer sacht zusammen und bewahrt es vor dem Zerknittern in der Tasche. Ein sauber gefaltetes Stück verleiht jedem Moment, in dem man es hervorholt, eine stille Würde."},"ICON-2668":{"nm":"Pflasterdose","de":"An dem Tag, an dem das Knie aufgeschürft ist, reihen sich in der geöffneten Dose allerlei Pflaster und warten schon auf dich. Eine Zärtlichkeit, die auch bei einer kleinen Wunde nicht zögert. Der Erste-Hilfe-Kasten gehört immer griffbereit in die Nähe."},"ICON-2669":{"nm":"Fingerabdruck-Wischer","de":"Wischt man den Fingerabdruck vom Glas, verschwindet die Spur einer zögernden Hand. An jeder berührten Stelle wird die trüb gewordene Welt hinter dem Fenster wieder durchsichtig – eine kleine Magie, so groß wie eine Handfläche."},"ICON-2670":{"nm":"Mülltrenn-Steg","de":"Papier hierhin, Dosen dorthin. Ein einziger Steg entscheidet über ein Schicksal, das sich sonst vermischt hätte. Mülltrennung ist am Ende ein Herz, das sorgfältig sondert, und diesen ersten Strich zieht dieser gewissenhafte Steg klar und deutlich."},"ICON-2671":{"nm":"Aufkleberschaber","de":"Selbst hartnäckig festgeklebte Sticker ergeben sich sanft vor mir. Schiebt man die flache Klinge behutsam in die Ecke, löst er sich makellos ab, ohne eine Spur zu hinterlassen — ein befriedigender Abschied."},"ICON-2672":{"nm":"Masking-Tape-Abreißzahn","de":"Wer Washi-Tape benutzen will, muss nicht erst hektisch nach der Schere suchen. Zieht man das Band an den Zähnchen entlang, reißt es sauber der Faser nach ab. Der kleine, flinke beste Freund, den bastelnde Fingerspitzen am meisten schätzen."},"ICON-2673":{"nm":"Eckverstärkungsblech","de":"Ein kleines Metallstück, das eine sich lösende Ecke von innen fest zusammenhält. An unsichtbarer Stelle bewahrt es stumm den rechten Winkel. Hinter allem, was nach außen gerade wirkt, steckt meist so eine verborgene Stütze."},"ICON-2674":{"nm":"Stickerbogen-Schutzhülle","de":"Damit der kostbare Stickerbogen nicht zerknittert oder feucht wird, schlummert er zusammen mit einer Schutzfolie in der Hülle. Neben der Freude am Sammeln steht immer auch die Sorgfalt, die ihn sanft zu bewahren sucht."},"ICON-2675":{"nm":"Stempelreinigungsbürste","de":"Die Borsten fahren sanft der Struktur nach durch die tintendurchtränkten Rillen des Stempels und lösen die alte Farbe. Eine kleine, fleißige Hand, die vorab reinigt, damit der nächste Abdruck klar und deutlich wird."},"ICON-2676":{"nm":"Klarsichteinlagen-Halter","de":"Damit die Klarsichteinlagen im Ordner nicht herausrutschen, halten die Flügel sie fest an beiden Seiten. Weil jedes Blatt an seinem Platz bleibt, geraten die Fingerspitzen beim Umblättern nie durcheinander."},"ICON-2677":{"nm":"Deko-Teilchen-Schaufel","de":"Mit der kleinen Schaufel schöpft man die verstreuten Deko-Teilchen mit einem Zug zusammen. Verschwindet die Mühe, sie einzeln mit den Fingern aufzusammeln, wird die Zeit des liebevollen Gestaltens gleich viel schöner."},"ICON-2678":{"nm":"Lesezeichen-Quastenklemme","de":"Damit die Quaste am Ende des Lesezeichens nicht locker wird, bindet die kleine Klemme sie fest zusammen. Auch ein Wegweiser zurück zur unterbrochenen Seite beruhigt das Herz erst, wenn er selbst ordentlich aussieht."},"ICON-2679":{"nm":"Deko-Stift-Kappenklammer","de":"Eine Klammer, die die Kappe fest auf die Spitze des Deko-Stifts drückt, damit sie nicht austrocknet. Sie bewahrt vor dem Missgeschick, dass ein vergessen offen gelassener Stift eintrocknet, sodass die Farbe stets so feucht fließt wie am ersten Tag."},"ICON-2680":{"nm":"Schraubendreher-Wechselbit","de":"Der Griff des Schraubendrehers bleibt derselbe, nur die Spitze am Ende wird flink ausgetauscht. Ob Kreuz oder Schlitz, beides gelingt mühelos. Die Cleverness, mit einem Werkzeug vieles zu schaffen, steckt fest in dieser kleinen Spitze."},"ICON-2681":{"nm":"Schleifpapier-Wickelgriff","de":"Wickelt man die raue Fläche rund um die Hand, wird die Handfläche selbst zum Werkzeug. Mit jedem Zug der Faser nach rundet sich die einst kratzige Kante ab, und die letzte Glätte erkennen stets die Fingerspitzen zuerst."},"ICON-2682":{"nm":"Schrauben-Sortiertrichter","de":"Verstreute Schrauben rollen durch den engen Hals und sammeln sich klappernd an einem Ort. Das Geräusch, mit dem die kleinen Dinge, die über den Schreibtisch rollten, ihren Platz finden, lässt sogar den unruhigen Sinn wieder Ordnung finden."},"ICON-2683":{"nm":"Maßband-Endhaken","de":"Der Haken am Ende des Maßbands ist die zweite Hand dessen, der allein arbeitet. Hängt man ihn an eine Kante, zittert das Band nicht mehr, und Hand wie Herz werden so ehrlich wie die gemessene Länge."},"ICON-2684":{"nm":"Schraubenschlüssel-Griffüberzug","de":"Eine zusätzliche Schicht über dem kalten Metallgriff. Im Moment des Zugreifens berührt statt Kühle eine sanfte Wärme die Hand. Ein Werkzeug bleibt länger an unserer Seite, wenn es zuerst an die Hand denkt, die es hält."},"ICON-2685":{"nm":"Ahlenspitzen-Schutzkegel","de":"Über jede spitze Klinge stülpt sich ein kleiner Kegel. Selbst wer im Schubfach tastet, muss sich nicht stechen — je schärfer etwas ist, desto sorgsamer umhüllt, verletzt es niemanden."},"ICON-2686":{"nm":"Abisolierklinge","de":"Sie schält nur die dünne Isolierung ab, ohne den Draht darunter zu verletzen. Löst sie behutsam die eine Schicht, bis die kupferfarbenen Fasern aufblitzen — eine gute Klinge weiß genau, wo sie innehalten muss."},"ICON-2687":{"nm":"Libellenglas-Putzer","de":"Erst wenn die eine Luftblase genau in der Mitte stehen bleibt, ist es wirklich waagerecht. Das kleine Fenster klar zu putzen gleicht der stillen Vorbereitung, den Atem zu ordnen, bevor man eine Linie zieht."},"ICON-2688":{"nm":"Nagel-Fingerschutzhülle","de":"Eine kleine Hülle, die den Nagel haltenden Finger ganz umschließt. Sie sagt: Auch wenn der Hammer daneben trifft, ist es in Ordnung, schlag ohne Angst zu — sie hat sich fest bereitgemacht, an Stelle des Fingers den Schlag abzubekommen."},"ICON-2689":{"nm":"Napf-Antirutschmatte","de":"Eine Gummischicht, die dafür sorgt, dass der Napf nicht über den Boden rutscht. Beim eifrigen Fressen läuft die Schale nie davon — die Ruhe einer Mahlzeit beginnt an einem Platz, der nicht wackelt."},"ICON-2690":{"nm":"Futterschaufel-Haken","de":"Die Schaufel zum Füttern hängt an der Wand und trocknet leicht ab. Eine kleine Ordnung, die zu jeder Mahlzeit an derselben Stelle die Hand empfängt — für ein Mündchen zu sorgen, das gefüttert werden will, ist eben so eine liebevolle Sache."},"ICON-2691":{"nm":"Wassernapf-Überlaufschale","de":"Sie fängt still den Schluck auf, der über den Rand des Wassernapfs schwappt. Dank des weiten Tellers, der ihn vorsorglich auffängt, damit der Boden nicht nass wird, bleibt es unter den Pfoten immer trocken."},"ICON-2692":{"nm":"Leckerli-Verteilzange","de":"Eine Zange, die ein Stück Leckerli genau greift und reicht. Selbst vor der kleinen Schnauze, die schnuppernd wartet, bleiben die teilenden Fingerspitzen ruhig und liebevoll."},"ICON-2693":{"nm":"Futterbeutel-Verschlussklip","de":"Eine kleine Klammer, die die geöffnete Futtertüte einrollt und festhält. Mit einem Klick verschlossen, wird die Feuchtigkeit ferngehalten, und die knusprige Handvoll für morgen früh bleibt unversehrt bewahrt."},"ICON-2694":{"nm":"Tränkeflaschen-Ventilstopfen","de":"Ein Stopfen, der genau in den Zapfen der Tränke passt. Der tropfende Wassertropfen hört auf, und die Umgebung trocknet. Was gut verschlossen ist, leckt nicht, sondern bleibt lange klar und still stehen."},"ICON-2695":{"nm":"Fütterungs-Messbecher","de":"Der Markierung entlang schöpft man genau einen Becher ab. Nicht zu viel und nicht zu wenig — in der Hand, die die heutige Mahlzeit gerecht bemisst, liegt der Tag des kleinen Familienmitglieds genau richtig bemessen."},"ICON-2696":{"nm":"Futtermatten-Spritzschutzrand","de":"Der Rand verhindert, dass verschüttetes Futter über die Matte hinausrutscht. Eine leicht aufgestellte Kante sammelt zuverlässig die Krümel ein, die sonst überall verstreut wären."},"ICON-2697":{"nm":"Doppelnapf-Trennring","de":"Ein kleiner Ring, der zwei ineinandergestapelte Schalen sanft voneinander löst. Die Hand, die sich sonst mühsam abmühte, weil sie fest aneinanderklebten, wird leicht. Etwas gut voneinander zu lösen, ist, genau betrachtet, auch eine liebevolle Fürsorge."},"ICON-2698":{"nm":"Garten-Ballsammeltrichter","de":"Ein Trichter, der den in den Hof gerollten Ball an einem Ort sammelt. An einem Abend nach ausgelassenem Toben denkt man unwillkürlich an die Hand, die alles verstreut Liegende wieder einsammelt."},"ICON-2699":{"nm":"Zaunpfahl-Kappe","de":"Über jeden Zaunpfahl stülpt sich eine runde Kappe. Damit die Enden nicht durch Wind und Regen aufplatzen, hat sich die Fürsorge, selbst das Kleinste zu bedecken, im ganzen Hof verbreitet."},"ICON-2700":{"nm":"Spieltunnel-Klapphaken","de":"Ein Haken, an dem der ausgiebig bespielte Spieltunnel sauber gefaltet aufgehängt wird. Verwahrt man den erdverschmutzten Tag gut und hängt ihn auf, verspricht ein ordentlich verstautes Spiel unweigerlich ein Morgen."},"ICON-2701":{"nm":"Zuggriff-Polsterung","de":"Eine weiche Polsterung, die den Zuggriff sanft umhüllt. Selbst kräftiges Ziehen hinterlässt keine Scheuerstellen an der Handfläche. Je länger man ihn festhält, desto angenehmer liegt er in der Hand – das verdankt man einer kleinen, stillen Fürsorge."},"ICON-2702":{"nm":"Haken für Hof-Schattentuch","de":"Ein Haken, der das über den Hof gespannte Schattentuch fest an seinem Platz hält. Nur was man festhält, bleibt kühl. Im Schatten, den dieser Haken behauptet, ruht ein langer, träger Nachmittag."},"ICON-2703":{"nm":"Schutzkappe für Spatenblatt","de":"Eine Kappe, die man nach getaner Arbeit behutsam über das Spatenblatt schiebt. Wer das Blatt ausruhen lässt, bevor es stumpf wird, trifft im nächsten Frühling wieder auf frische Erde."},"ICON-2704":{"nm":"Kugelrollbahn","de":"Eine geneigte Bahn, auf der eine Kugel fröhlich hinunterrollt. Dem leichten Gefälle folgend, saust sie vergnügt davon. Ein kleiner Winkel genügt, um den ganzen Tag mit Freude zu füllen."},"ICON-2705":{"nm":"Riegel-Haken für Zauntor","de":"Ein Riegel-Haken, der das Zauntor verschließt. Das leise Klicken beim Einrasten lässt das Herz aufatmen. Ein einziges, fest geschlossenes Tor macht aus einem kleinen Hof eine heile, eigene Welt."},"ICON-2706":{"nm":"Spielschnur mit Glöckchen","de":"Schüttelt man die Schnur mit dem angehängten Glöckchen sanft, breitet sich ein klarer Klang aus. Kling, kling – ein stiller Raum erwacht, und bei dem kleinen Widerhall spitzen sich alle Ohren neugierig auf."},"ICON-2707":{"nm":"Blumentopf-Untersetzer","de":"Ein Teller, der das Wasser auffängt, das durch den Blumentopf sickert. So bleibt die Fensterbank trocken. Wenn die Fürsorge überfließt, braucht es einen Platz, der sie auffängt."},"ICON-2708":{"nm":"Pflanzschaufel","de":"Eine kleine Schaufel, mit der zarte Setzlinge behutsam in die Erde gesetzt werden. Hand für Hand, Pflänzchen für Pflänzchen – selbst im handflächengroßen Gemüsebeet reckt sich der grüne Frühling empor."},"ICON-2709":{"nm":"Beetmarkierstift","de":"Ein Stift, den man mit der Aufschrift des Gesäten ins Beet steckt. Über noch keimloser Erde hält ein kleines Namensschild still fest, was hier einmal wachsen wird."},"ICON-2710":{"nm":"Gießkannenvorsatz-Sieb","de":"Ein feines Sieb, das man auf den Ausguss der Gießkanne steckt. Was als einziger Strahl zu fließen drohte, verteilt sich nun sanft wie ein leichter Regen. Nur ein weicher Wasserstrahl schützt zarte Blätter vor Schaden."},"ICON-2711":{"nm":"Stützstab-Klammer","de":"Eine Klammer, die einen schwankenden Stängel behutsam am Stützstab festhält. Eine geliehene Stütze für die Zeit, bis das noch Zarte gerade steht – beim Wachsen braucht man genau solch einen Halt."},"ICON-2712":{"nm":"Saattüten-Verschlussklip","de":"Ein Klip, der die restliche Saattüte fest verschließt. Einmal zugedrückt, geht kein einziges Korn verloren. Ein kleines Versprechen auf den nächsten Frühling steckt in diesem einen Kniff."},"ICON-2713":{"nm":"Düngemittel-Dosierlöffel","de":"Ein kleiner Löffel, mit dem Erde und Dünger in der richtigen Menge abgemessen werden. Weder zu viel noch zu wenig – erst auf der genau abgewogenen Menge kann die Erde ihr Bestes geben."},"ICON-2714":{"nm":"Blumentopf-Hängehaken","de":"Ein Haken, an dem ein Blumentopf leicht in der Luft schwebt. In die Höhe gehoben, kommt das Grün Sonnenlicht und Brise einen Span näher. Am Fenster entsteht ein kleiner schwebender Garten."},"ICON-2715":{"nm":"Schutznetz für Jungpflanzen","de":"Ein zartes Netz, das frisch gekeimte Pflänzchen behutsam abschirmt. Bis die noch weichen Blätter erste Kälte und grelles Sonnenlicht überstehen – das Zarteste verdient als erstes Fürsorge."},"ICON-2716":{"nm":"Fellbürsten-Halterung","de":"Ein Platz, um die Bürste auszuschütteln und ordentlich aufzuhängen. Die leere, frisch gereinigte Bürste wartet auf den nächsten Einsatz. Gepflegtheit beginnt immer mit der kleinen Gewohnheit, sein Werkzeug zu hegen."},"ICON-2717":{"nm":"Anti-Rutsch-Ring für Waschbottich","de":"Ein Ring, der verhindert, dass der Waschbottich beim Pfötewaschen verrutscht. So bleibt die Wanne unter den kleinen platschenden Pfoten fest – weder die waschenden Hände noch das Herz werden dabei ins Wanken gebracht."},"ICON-2718":{"nm":"Leinen-Aufhängehaken","de":"Ein Haken, an dem die Leine im Flur ihren Platz hat. Stets bereit neben der Tür, wartet alles auf den Aufbruch. Im Moment, da man die Leine abnimmt, macht sich auch schon ein freudiger Schritt auf den Weg."},"ICON-2719":{"nm":"Krallenschutz-Aufsatz","de":"Ein Schutzaufsatz, der beim Krallenschneiden das zarte Fleisch bewahrt. Erst wenn eine sichere Grenze gesetzt ist bis hierher und nicht weiter, bleibt auch die Hand ruhig und sicher."},"ICON-2720":{"nm":"Badewasser-Temperaturstreifen","de":"Ein Streifen, der auf dem Badewasser treibt und die Temperatur anzeigt. Was man früher mit dem Handrücken erspürte, liest sich nun in einer klaren Farblinie ab."},"ICON-2721":{"nm":"Fusselroller","de":"Ein einzelnes weißes Haar auf dem schwarzen Outfit kurz vor dem Auftritt – das fällt sofort ins Auge. Beim Abrollen bleibt ein ganzer Tag voller Krümel und Fasern ordentlich auf dem Klebeband haften. Sauberkeit vollzieht sich so, Streifen für Streifen, abgerollt und fertig."},"ICON-2722":{"nm":"Gassigeh-Beutelzange","de":"Am Ende des Spaziergangs gibt es diesen einen zärtlichen Moment, wo man sich bückt. Mit dem Beutel an der Zange bleiben die Hände sauber und das Gewissen leicht. Wer gemeinsam läuft, weiß: Dazu gehört auch die kleine Höflichkeit, den Weg hinter sich aufzuräumen."},"ICON-2723":{"nm":"Fußmatten-Abschlussband","de":"Das Abschlussband der Türmatte ist der erste Gruß, den der Fuß berührt. Bleiben nasse Sohlen hier einen Moment stehen, bleibt der Boden drinnen trocken. Die tiefste Stelle, die jeden Ankommenden lautlos abtrocknet und willkommen heißt."},"ICON-2724":{"nm":"Schmuckschnur mit Glöckchen","de":"Auch das Befestigen eines einzelnen Glöckchens hat seine Reihenfolge. Die Schnur zweimal umwickeln, einmal durchfädeln – und bei jedem Schritt folgt ein helles Klingeln. Pflege bedeutet letztlich, diesen kleinen Abschluss nicht zu vergessen."},"ICON-2725":{"nm":"Schirmtasche für unterwegs","de":"In der Lobby nach dem Regen tropft das zusammengeklappte Schirmende Punkte auf den Boden. Eine einzige Tasche fängt das still auf, und niemandes Füße gleiten mehr aus. Fürsorge hält so meist wortlos Wache."},"ICON-2726":{"nm":"Taschenhaken-Klammer","de":"Die am Stuhl hängende Tasche rutschte ständig herunter. Mit der Hakenklemme befestigt, hat man beide Hände frei und keine Sorge. Die Leichtigkeit des Ausgehens beginnt in dem Moment, in dem man das Gepäck kurz vergessen darf."},"ICON-2727":{"nm":"Handwärmer-Stoffbeutel","de":"In einer zugigen Gasse gleitet die Wärme des Stoffbeutels in der Tasche sachte in die Handfläche. Das Heiße ist in eine weiche Lage gehüllt und gibt die Wärme angenehm dosiert ab. Die Herzlichkeit des Winters gelangt stets durch eine einzige Lage Stoff."},"ICON-2728":{"nm":"Klappständer für Taschenspiegel","de":"Aufgeklappt findet der kleine Spiegel seinen Winkel ganz von selbst. Man muss ihn nicht in der Hand halten, um sich anzuschauen – der Ständer tritt an seine Stelle. Auch in dem kurzen Moment der Selbstkontrolle steht ein zuverlässiger Helfer bereit."},"ICON-2729":{"nm":"Feuchttücher-Verschlusskappe für unterwegs","de":"Das erste Tuch im Pack war immer schon halb ausgetrocknet. Klappt man die Kappe zu, bleibt auch das letzte Tuch feucht. Das, was bis zum Schluss schützt – im Geheimnis sparsamer Haushaltsführung stecken solche Kleinigkeiten."},"ICON-2730":{"nm":"Münzfach-Trennsteg im Portemonnaie","de":"Wenn Münzen zwischen die Scheine geraten, wird es an der Kasse hektisch. Ein einziger Trennsteg hält das Runde auf einer Seite – die Finger suchen dann nicht mehr. Ordnung ist die Kunst, jedem Ding seinen eigenen Namen zu geben."},"ICON-2731":{"nm":"Masken-Faltbox für unterwegs","de":"Eingefaltet knickt die Maske selbst in der Tasche nicht. Die Box bewahrt ein kurz abgenommenes Stück sauber auf. Dinge, die man wieder benutzen will, ordentlich aufzubewahren – das ist eine freundliche Gewohnheit."},"ICON-2732":{"nm":"Kammschutz-Abdeckung für unterwegs","de":"Die Kammzinken in der Tasche haben andere Dinge immer wieder zerkratzt. Mit der Schutzabdeckung ist der Kamm sicher und alles daneben unbeschädigt. Wer es einmal ausprobiert hat, weiß: eine dünne Schutzschicht kann beide Seiten bewahren."},"ICON-2733":{"nm":"Schubladentrennklammer","de":"Jedes Mal, wenn man die Schublade öffnete, quoll ein Durcheinander heraus wie ein Seufzer. Eine einzige Klammer teilt den Raum – und kleine Dinge finden endlich ihr Revier. Eine aufgeräumte Schublade verändert die Stimmung jeden Morgen auf leise Art."},"ICON-2734":{"nm":"Münzaufstell-Ständer","de":"Eine alte Münze aufrecht hingestellt – das ist schon für sich eine kleine Ausstellung. Der Ständer hält sie leicht schräg und zeigt das Muster der Vorderseite deutlich. Erinnerungen auf Augenhöhe zu stellen – darin liegt die tiefere Freude des Sammelns."},"ICON-2735":{"nm":"Kabelaufroll-Ring für Kopfhörer","de":"Wer kennt es nicht: die Hälfte des Morgens damit verbracht, verknotete Kopfhörerkabel zu entwirren. Ordentlich auf den Rollring gewickelt, gleitet das Kabel beim nächsten Herausnehmen sauber ab. Eine kleine Ordnung ist ein stilles Geschenk an das morgige Ich."},"ICON-2736":{"nm":"Ladekabel-Wandhaken","de":"Das auf dem Boden liegende Ladekabel wurde ständig mit dem Fuß angestoßen. Ein einziger Haken an der Wand, und der Schreibtisch wirkt gleich viel größer. Unordnung zu bändigen braucht nichts Aufwendiges – nur einen kleinen Platz, so groß wie ein Nagel."},"ICON-2737":{"nm":"Fernbedienungs-Aufstellhalter","de":"Die Fernbedienung, die im Sofaspalt verschwand, hat endlich ein Zuhause, zu dem sie zurückkehren kann. Im Halter aufgestellt, muss man nie mehr suchen und sich nie mehr versehentlich draufsetzen. Einen festen Platz zu haben ist auch für Dinge eine kleine Erholung."},"ICON-2738":{"nm":"Brillenbügel-Aufhänge-Klammer","de":"Die abgelegte Brille ist immer irgendwo leise weggerutscht. Klemmt man den Bügel in die Klammer, kommt das Glas nicht mehr auf dem Boden zu liegen. Die Sorge, den nächsten Tag ohne Kratzer zu beginnen, steckt in diesem kleinen Halter."},"ICON-2739":{"nm":"Schlüsselbund-Sortierklammer","de":"Je schwerer der Schlüsselbund wurde, desto mehr verschwamm, welcher Schlüssel zu welcher Tür gehört. Mit der Sortierklammer erkennt man das richtige Stück allein durch die Fingerkuppe. Ein stiller Ordner für die Türen, die man täglich öffnet und schließt."},"ICON-2740":{"nm":"Notizzettel-Aufstellklammer","de":"Notierte Zettel lagen auf dem Schreibtisch immer wieder umgekippt. Hält die Klammer das Papier aufrecht, schaut der Text einem geradewegs ins Gesicht. So wohnt eine wichtige Zeile stets an einem Platz, wo sie nicht vergessen werden kann."},"ICON-2741":{"nm":"Stifthalter-Auflage","de":"Wie oft hat man sich gebückt, um einen heruntergerollten Stift aufzuheben? Die Stiftspitze in die Halteauflage gesteckt, und die nächste Zeile liegt nur eine Handbreit näher. Ein kleiner Warteplatz, der stets wach neben dem Schreibenden steht."},"ICON-2742":{"nm":"Sockel für Sanduhr","de":"Eine Sanduhr lebt erst wieder, wenn jemand sie nach dem letzten Korn umdreht. Der Sockel nimmt diesen letzten Moment auf und dreht sie gleichmäßig zurück. Eine Hand, die die Zeit zum Anfang zurückbewegt, verweilt hier auf einem kleinen Stück Holz."},"ICON-2743":{"nm":"Ofenkartoffel mit Butter","de":"Über einer in der Schale gebackenen Kartoffel schmilzt die Butter langsam dahin. Wenn das gelbe Fett dem Dampf folgend einsickert, nimmt das mehlige Innere die Nussigkeit sanft in sich auf. Genau in diesem Moment wird das erdegetränkte Wurzelgemüse am wärmsten."},"ICON-2744":{"nm":"Gegrillter Maiskolben mit Butter","de":"Die gelben Körner knacken auf dem Grill mit leisen Tönen. Gleitet ein Stück Butter darüber, steigt ein süßer Duft auf. Die Süße eines Sommerfeldes landet genauso in einem einzigen Bissen."},"ICON-2745":{"nm":"Waffel","de":"In jedem der quadratischen Felder wartet man geduldig, bis sich der Sirup gesammelt hat. Außen knusprig, innen fluffig – beim ersten Hineinbeißen entweicht ein warmer Dunst. Die kleinen Vierecke sind wie Schälchen, die Glück in Portionen aufbewahren."},"ICON-2746":{"nm":"Pfannkuchen","de":"Den Duft von goldbraun aufgehendem Teig in der Pfanne kennt man noch gut. Auf die geschichteten runden Fladen legt sich Butter und schmilzt sachte. Ein weicher Teller, der sich nur in einem gemächlichen Morgen erlauben lässt."},"ICON-2747":{"nm":"Schokolade","de":"Hält man ein Stück im Mund, löst es sich langsam an der Körperwärme. Die Süße, die sich hinter dem leichten Bitterton ausbreitet, lässt die Anspannung des Herzens still nachlassen. An einem schweren Tag – das braune Stück Trost, das man aus der Tasche zieht."},"ICON-2748":{"nm":"Erdbeertorte","de":"Rote Erdbeeren thronen auf weißer Sahne und kündigen den Frühling an. Wenn die Gabel durch den weichen Querschnitt gleitet, steigt ein säuerlicher Duft auf. An einem Tag, der Feiern verdient, steht sie als herzliches Mittelstück auf dem Tisch."},"ICON-2749":{"nm":"Käsekuchen","de":"Ein schweres Stück zerfällt auf der Zunge dicht und gehaltvoll. Der leicht salzige Nachgeschmack hält die Hand der Süße fest und ruft immer wieder nach einem weiteren Bissen. Ein Dessert, das seine Liebhaber genießerisch und still vernaschen."},"ICON-2750":{"nm":"Bananenkeks","de":"Der Duft von zerdrückter Banane reift gelb im Backofen. Ein Bissen – und eine weiche Süße breitet sich im ganzen Mund aus. Der Moment, in dem eine reife Frucht als Keks neu zur Welt kommt."},"ICON-2751":{"nm":"Schokokeks","de":"Die Schokoladenstückchen im Teig lösen sich beim Backen weich und zähflüssig. Bricht man den noch warmen Keks, schimmert ein sattes Braun an den Fingern. Mit einem Glas Milch wird der Nachmittag um einiges herzlicher."},"ICON-2752":{"nm":"Kakaonibs-Keks","de":"Fein zerstoßene Kakaostückchen knacken zwischendurch im Teig. Der tiefe, nicht allzu süße Bittergeschmack beruhigt den Gaumen eines Erwachsenen. Ein etwas ernsthafter Keks, der das Aroma der Kakaobohne ganz unverfälscht in sich trägt."},"ICON-2753":{"nm":"Käsetoast","de":"Auf dem goldbraun gerösteten Brot zieht der Käse lange Fäden. Die äußere Knusprigkeit und der innere Nussgeschmack verschmelzen in einem Bissen. Ein herzliches Mahl, das einen späten Morgen solide und liebevoll füllt."},"ICON-2754":{"nm":"Sandwich","de":"Zwischen zwei Brotscheiben steckt ein ganzer Tag voll Sorgfalt. Beißt man hinein, melden sich alle geschichteten Aromen auf einmal. Ein kleiner Tisch in der Handfläche, den man überall mit hinnehmen kann."},"ICON-2755":{"nm":"French Toast","de":"In Ei getränktes Brot bräunt sich goldgelb in der Pfanne. Die Ecken, die sich mit Butterduft aufgewölbt haben, werden als Erste knusprig. Ein Strich Sirup genügt, und selbst gewöhnliches Brot wird zum Luxus eines freien Tages."},"ICON-2756":{"nm":"Pilz-Ramen","de":"Über der kochenden Brühe steigt das tiefe Aroma der Pilze als Dampf auf. Hebt man ein elastisches Hütchen heraus, breitet sich eine erdige Süße im Mund aus. Eine ganz besondere Schüssel, die den Bauch schon mit dem Duft füllt, bevor die Nudeln kommen."},"ICON-2757":{"nm":"Gebratene Ramen","de":"Die ohne Brühe geschwenkten Nudeln sind mit würziger Sauce glänzend überzogen. Hebt man sie mit Stäbchen hoch, zieht durch den Dampf ein nussiger Grillduft. Wenn man sich nach einem schnellen, kräftigen Mahl sehnt – der verlässlichste Freund."},"ICON-2758":{"nm":"Käse-Ramen","de":"Legt man eine Scheibe Käse auf die heißen Nudeln, schmilzt sie langsam hinein. Scharfe Brühe und weiche Nussigkeit treffen aufeinander und runden die Schärfe ab. Eine Schüssel, die genau zum Abend passt, wenn man die Schärfe ein wenig mildern möchte."},"ICON-2759":{"nm":"Curry-Ramen","de":"Das kräftige Currya roma umhüllt die Nudeln und lässt gelben Dampf aufsteigen. Schlürft man einen Bissen, wärmt eine angenehme Schärfe den Magen von innen. Nudeln, die dem vertrauten Sud ein leicht fremdes Aroma hinzufügen – eine fröhliche Variation."},"ICON-2760":{"nm":"Meeresfrüchte-Ramen","de":"Auf der meeresfrischen Brühe tauchen pralle Garnelen und Muscheln auf. Ein erfrischender und gleichzeitig tiefer Umami-Geschmack zieht sich durch die Nudeln. Kleiner Zauber: ohne weit zu reisen, bringt diese Schüssel den Meeresduft nach Hause."},"ICON-2761":{"nm":"Rettich-Gimbap","de":"Wenn der gelbe Rettich in der Mitte liegt und der Reis ihn rund umschließt, bündelt ein Noriblatt das alles herzlich in einer Rolle. Das ehrlichste Mahl, das in den frühen Morgenstunden vor dem Schulausflug auf dem Schneidebrett entsteht."},"ICON-2762":{"nm":"Thunfisch-Gimbap","de":"Sobald ein Löffel Thunfisch mit Mayonnaise in den Reis einzieht, wird selbst unter der spätnächtlichen Leuchtreklame eines Kiosks eine Mahlzeit warm genug. Der Trost, den die beschäftigte Hand am häufigsten greift."},"ICON-2763":{"nm":"Obstsalat","de":"Früchte der Saison treffen sich zum ersten Mal in einer Schüssel. Wie Rot, Grün und Gelb sich vertragen, ohne zu streiten, zeigen Früchte erst, wenn sie geschnitten nebeneinanderliegen."},"ICON-2764":{"nm":"Hähnchensalat","de":"Schlicht gegrillte Hähnchenbrust wird ordentlich auf grüne Salatblätter gelegt. Auf dem Tisch desjenigen, der für das nächste Auftritt bereit ist, steht immer ein solch gepflegter Teller."},"ICON-2765":{"nm":"Tomaten-Gurken-Salat","de":"Reife Tomaten und knackige Gurken werden säuerlich angemacht. Mitten im Hochsommer, wenn die Zikaden schrillen, kühlt ein Bissen diesen Salat den Sommer für einen kurzen Herzschlag ab."},"ICON-2766":{"nm":"Blattsalat","de":"Frisch vom Beet gepflückte Blätter werden im kalten Wasser gewaschen – die Fingerspitzen erwachen kühl. Der Moment, in dem das gewöhnlichste Gemüse auf dem Tisch den grünsten und frischesten Platz einnimmt."},"ICON-2767":{"nm":"Maissalat","de":"Jedes Mal, wenn ein süßes Körnchen aufplatzt, entfaltet sich ein sommerliches Feld voller Sonnenschein vor dem inneren Auge. Selbst in einer Salatschüssel vergisst der gelbe Mais sein Sonnenlicht nicht."},"ICON-2768":{"nm":"Krautsalat (Coleslaw)","de":"Wenn der geriebene Kohl die süßsaure Sauce aufsaugt, wird das Knackige ein wenig weicher und milder. Die Tugend der Beilage, die neben jedem Hauptgericht glänzt, ohne ihm den Rang streitig zu machen."},"ICON-2769":{"nm":"Limetten-Garnelensalat","de":"Drückt man ein wenig Limette hinein, erwacht die Süße der Garnelen noch klarer. Ein einziger säuerlicher Tropfen belebt den ganzen Teller – ein kleiner, aber entscheidender letzter Handgriff."},"ICON-2770":{"nm":"Hacksteak (Hamburger Steak)","de":"Ein dick geformter Hackfleischball bräunt sich auf der heißen Eisenplatte. Der Moment, in dem das Messer ansetzt und der Fleischsaft herausläuft – die Mahlzeit, die zwischen Hausmannskost und Restaurantküche am meisten geliebt wird."},"ICON-2771":{"nm":"Pizza","de":"Den Bissen mit dem lang ziehenden Käse reicht man von Hand zu Hand in der Runde. Wenn man gemeinsam eine runde Pizza in Stücke teilt, wird das Treffen erst zum wirklichen Treffen."},"ICON-2772":{"nm":"Pilz-Sahne-Pasta","de":"Das tiefe Erdaroma der Pilze und die Samtigkeit der Sahne hüllen jeden einzelnen Nudelfaden ein. An einem Abend mit leisem Regengeräusch breitet sich das kräftige Aroma langsam bis auf den Tellerboden aus."},"ICON-2773":{"nm":"Garnelen-Pasta","de":"Pralle Garnelen werden kurz in Olivenöl gebraten und mit den Nudeln vermischt. Wenn die Salzigkeit des Meeres auf die Schlichtheit der Nudeln trifft, wird selbst ein ereignisloser Abend ein wenig besonderer."},"ICON-2774":{"nm":"Öl-Pasta (Aglio e Olio)","de":"Nur Knoblauch, Öl und Nudeln – mehr nicht. Es gibt Geschmäcker, die durch Weglassen umso klarer werden. Aglio e Olio beweist das still und ohne jeden Umschweif."},"ICON-2775":{"nm":"Muschel-Pasta","de":"Die Brühe, die die Muscheln beim Öffnen abgeben, zieht tief in jeden Nudelfaden ein. Das Aroma eines Schlucks Weißwein verflüchtigt sich auf dem Teller wie ein langer Frühlingstag."},"ICON-2776":{"nm":"Sahne-Pasta","de":"Wenn die reichhaltige Sahne die Nudeln sanft umhüllt, wird beim ersten Bissen eine stille Ecke des Herzens warm. Eine Tröstung durch Weichheit – die sich an windigen Tagen noch tiefer einprägt."},"ICON-2777":{"nm":"Tomaten-Pasta","de":"Lange gekochte Tomatensauce breitet sich rot über die Nudeln aus. Wenn Süße und Säure langsam eingekocht wurden und endlich ihre Balance finden, ist der schlichteste Teller der verlässlichste."},"ICON-2778":{"nm":"Omurice","de":"Ein weiches Ei legt sich wie eine Bettdecke behutsam über den warmen Reis. Schreibt man mit Ketchup noch einen Namen hinein, wird das Essen an diesem Tag zu einem kleinen Brief von jemandem."},"ICON-2779":{"nm":"Gegrillter Lachs","de":"Man wartet geduldig vor dem Feuer, bis die Haut knusprig braun wird. Das rosafarbene Fleisch reißt entlang seiner Fasern auf, und ein Strich Dampf steigt auf – das Warten wird vom Lachs stets ehrlich belohnt."},"ICON-2780":{"nm":"Bruschetta","de":"Auf knusprig geröstetem Brot werden gewürfelte Tomaten und Basilikum großzügig gehäuft. Die Leichtigkeit, mit der man das mit den Fingern in einem Bissen verspeist, eröffnet das erste Gespräch einer Zusammenkunft herzlich."},"ICON-2781":{"nm":"Mango-Smoothie","de":"Eine reife Mango wird fein püriert und kalt mit Eis vermischt. Wenn sich an dem gelben Glas Tröpfchen bilden, füllt sich ein träger Sommernachmittag bis zum Trinkhalm."},"ICON-2782":{"nm":"Limonade","de":"Frisch gepresste Zitrone, Zucker und kaltes Wasser – im Glas kräftig geschüttelt. Wenn die gelbe Säure kühl die Kehle hinunterläuft, ergibt sich auch die hartnäckigste Hitze für einen Moment."},"ICON-2783":{"nm":"Erdbeer-Milch","de":"Verrührt man zerdrückte Erdbeeren in Milch, sinkt eine rosafarbene Wolke langsam im Glas. Die Aufregung, mit der man als Kind die Kühlschranktür aufriss, steckt in einem einzigen Glas unvermindert drin."},"ICON-2784":{"nm":"Bananen-Milch","de":"Allein durch die runde Flaschenform ist das schon die Erinnerung an eine ganze Epoche. Das gelbe Bild vom Strohhalm im Badezimmerbrunnen kommt mit jedem Schluck herzlich zurück."},"ICON-2785":{"nm":"Blaubeer-Milch","de":"Drückt man die violetten Beeren hinein, färbt sich die weiße Milch in ein zartes Himmelblau. Eine einzige Handvoll kleiner Früchte verwandelt ein ganzes Glas in eine neue Farbe."},"ICON-2786":{"nm":"Fruchtsaft","de":"Presst man verschiedene Früchte zusammen, entsteht ein Geschmack, der sich mit keinem einzigen Namen benennen lässt. Unterschiedliche Süßen, die sich mischen und noch voller aufblühen – ein kleiner Chor der Früchte."},"ICON-2787":{"nm":"Kakao","de":"Am verschneiten Fenster hält man einen warmen Becher mit beiden Händen. Ein dampfendes braunes Glas – und von den Fingerspitzen bis ins Herz taut es langsam auf."},"ICON-2788":{"nm":"Kaffee","de":"Das Licht im Probenraum im Morgengrauen schaltet immer zuerst diese eine Tasse ein. Wenn das bittere Aroma die Schläfrigkeit sachte wegschiebt, beginnt ein neuer Tag auf der Bühne still auf diese Weise."},"ICON-2789":{"nm":"Lachs-Sushi","de":"Man presst den Reis in die Hand und erspürt das genaue Maß zwischen Festigkeit und Weichheit. Im Moment, da eine dünn aufgeschnittene Lachsscheibe sich sanft darauflegt, ist ein Bissen kleines gelebtes Handwerk."},"ICON-2790":{"nm":"Butternusskürbis-Brei","de":"Gelber Kürbis wird weich gekocht und fein passiert. Mit jedem Löffel löst sich Herbstsonnenschein warm im Mund. Der Brei, an den man als Erstes denkt, wenn man krank ist."},"ICON-2791":{"nm":"Fischcurry","de":"In Gewürzen leicht geschmortes Fischfleisch zerfällt zart im Curry. Fügt man dem vertrauten Gericht die Textur des Meeres hinzu, begibt sich ein gewöhnlicher Abend auf eine kleine Reise."},"ICON-2792":{"nm":"Garnelen-Tempura","de":"Den Schwanz haltend, Teig anziehen, in heißes Öl geben – dieser kurze Moment entscheidet alles. Die Garnele in ihrem goldenen Mantel leuchtet am hellsten, wenn man sie isst, bevor die Knusprigkeit nachlässt."},"ICON-2793":{"nm":"Tintenfischringe","de":"Die runden Ringe blähen sich im heißen Öl prall auf. Diesen einen Bissen, in dem Bissfestes von Knusprigem umhüllt ist, genießt man am schönsten unter dem gelben Licht eines Imbissstandes."},"ICON-2794":{"nm":"Gebratenes Hähnchen","de":"Wenn man das marinierte Fleisch langsam grillt, beginnt die Haut glänzend zu schimmern. Der einfachste Geschmack, der am ehrlichsten ist, weil er allein von der Hitzeführung abhängt."},"ICON-2795":{"nm":"Schweinefleisch mit Kimchi gebraten","de":"Brät man gut eingelegtes Kimchi zusammen mit Schweinefleisch, wandelt sich der saure Geschmack in Süße. Das verlässlichste Gespann auf dem koreanischen Tisch – das den weißen Reistopf von selbst herbeiruft."},"ICON-2796":{"nm":"Gebratenes Schweinefleisch","de":"Bei starker Hitze schnell gebraten und von außen scharf angebraten. Wenn der nussige Bratgeruch die Küche füllt, ist das Abendmenü schon beschlossen, ohne dass man noch fragen müsste."},"ICON-2797":{"nm":"Rind mit Pilzen gebraten","de":"Wenn man duftende Pilze und Rindfleisch zusammen brät, vertiefen sie gegenseitig ihren Geschmack. Erde und Weide reichen sich auf einem Teller still die Hand – eine ordentliche Herbstmahlzeit."},"ICON-2798":{"nm":"Käse-Dak-Galbi","de":"Über dem würzig-scharfen Hähnchen wird reichlich Käse geschmolzen und lang gezogen. Wenn man zu mehreren rund um eine heiße Eisenplatte sitzt, löst sich selbst die brennende Schärfe in Lachen auf."},"ICON-2799":{"nm":"Kimchi-Eintopf","de":"Je länger das Kimchi gereift ist, desto tiefer und kräftiger wird seine Brühe. Sitzt man sich gegenüber vor dem sprudelnden Tontopf, wärmt sich das Wort Familie erneut auf."},"ICON-2800":{"nm":"Doenjang-Jjigae","de":"Würzige Sojabohnenpaste wird aufgelöst, Tofu und Zucchini dazugegeben und behutsam gekocht. Das Brodeln des Tontopfs bis zum letzten Schluck ist das verlässlichste Zeichen dafür, dass man nach Hause gekommen ist."},"ICON-2801":{"nm":"Rindfleisch-Rettich-Suppe","de":"Einen halben Tag vor dem Herd gewartet, bis der Rettich durchsichtig wird. Ein Löffel klare Brühe auf der Zunge, und der schlichte Tisch vergangener Zeiten taucht auf. Was bescheiden ist, bleibt am längsten."},"ICON-2802":{"nm":"Muscheleintopf","de":"In dem Moment, da die Muscheln sich öffnen, vertieft sich im Topf der Frühling. Steigt eine Prise Meeresduft als Dampf auf, zeichnet sich die Küche eines Küstendorfes im Morgengrauen ab. In jedem geöffneten Spalt sammelt sich das salzige Meer."},"ICON-2803":{"nm":"Karamelisierte Süßkartoffeln","de":"Nach der Schule, im Pappbecher wie eine Wärmflasche gehalten – das gelbe Stück. Beißt man durch die bräunliche Hülle, schlägt einem der Dampf entgegen. Der Geschmack, nach dem der Winter am herzlichsten war: süßlich karamellisiert außen, heiß innen."},"ICON-2804":{"nm":"Gebratene Auberginen","de":"Der Augenblick, in dem das Violett im Öl sich sachte auflöst. Das Gemüse, das man weich gescholten hat, nimmt die Würze in Wirklichkeit besser auf als jedes andere. Beißt man hinein, kommt der eingezogene Handgeschmack zuerst durch."},"ICON-2805":{"nm":"Geschmorte Kartoffeln","de":"Der Abend, an dem beim Einköcheln der Sojasauce die Küche von einem süßen Duft erfüllt war. Die Hand, die die glänzend braunen Würfel in das Lunchbox-Fach schichtete. Nicht im Rezept notierten Sorgfalt steckt in jedem dieser kleinen Stücke."},"ICON-2806":{"nm":"Perilla-Blatt-Einleger","de":"Den Sommerduft einzulegen und bis auf den Wintertisch mitzunehmen. Legt man ein Blatt auf Reis, erblüht die vergangene Jahreszeit erneut im Mund. Zwischen den übereinandergefalteten Blättern schläft das Sonnenlicht jenes Jahres."},"ICON-2807":{"nm":"Frischer Chinakohl-Salat","de":"Die Hand, die nicht bis zur Kimchi-Fermentation warten konnte, würzt ihn gleich. Nur der Moment, in dem die Würze gerade erst einzuziehen beginnt, ermöglicht diese frische Lebendigkeit. Die Unverbrauchtheit vor der Fermentation ist der Luxus des heutigen Tages."},"ICON-2808":{"nm":"Gebratene Pilze","de":"Dinge, die nach dem Regen still aus dem Waldschatten hervortreten. Beim Braten in Perillaöl verwandelt sich der Erdgeruch in Nussigkeit. Je verborgener etwas wächst, desto tiefer und intensiver sein Duft."},"ICON-2809":{"nm":"Spinat-Namul","de":"Das blanchierte Blattgemüse, das sich zu einer kleinen Handvoll zusammenzieht, wird mit den Fingerspitzen angemacht. Das ist die Tugend eines Frühlingskrauts: seine bescheidene Größe. Ein grüner Teller bringt dem Tisch ein Stück Frühlingssonne mehr."},"ICON-2810":{"nm":"Meeresalgen-Namul","de":"Frisch aus dem Meer geholte, glitschige Stränge treffen auf säuerliche Würzsauce. Bei jedem Bissen platzt eine salzige Note. Ein Teller, der das Gefühl von wogenden Wellen genau so ins Gericht überträgt."},"ICON-2811":{"nm":"Gebratene Zucchini","de":"Es gibt Gemüse, das süßer wird, je mehr es reift. Dünn geschnitten und in Garnelenpaste gebraten, gibt die bescheidene Zucchini ihren Süßgehalt schließlich preis. Bis zuletzt weich und sanft schmelzend im Mund – das Gelbe."},"ICON-2812":{"nm":"Kimchi-Gebratener Reis","de":"Wenn das überreife Kimchi seinen Höhepunkt erreicht hat, trifft es in einer Pfanne auf kalten Reis. Aus zwei Resten entsteht die sättigendste Schüssel. Spät nachts unter dem Licht einer kleinen Wohnung – der herzlichste Retter."},"ICON-2813":{"nm":"Hähnchen-Curry","de":"Wenn die gelbe Brühe den weißen Reis überdeckt, hellt sich der Tisch auf. Der Geschmack der großen Welt, mit dem man sich in einer Zeit anfreundete, als Gewürze noch fremd waren. Ein Sonntagsmittagessen, an dem das Hähnchenfleisch weich zerfiel."},"ICON-2814":{"nm":"Gebratener Reis","de":"Alle Reste aus den letzten Ecken des Kühlschranks finden in einer Pfanne zueinander. Die Großzügigkeit, die alles bereitwillig aufnimmt. Verstreutes zusammenzufügen – das ist der Anfang guter Haushaltsführung."},"ICON-2815":{"nm":"Bulgogi-Reisschale","de":"In süßlicher Marinade eingelegtes Fleisch gleitet über dampfenden Reis. Wenn ein Festtagsgericht zum schlichten Alltagsgericht wird, gewinnt das Besondere noch mehr Herzlichkeit."},"ICON-2816":{"nm":"Bibimbap","de":"Fünf farbige Gemüsebeilagen reihen sich rund auf dem Reis. In der Hand, die sie farblich anordnete, lebte noch ein altes Schönheitsgefühl feiner Achtsamkeit. Ein Geschmack der Harmonie, der erst durch gemeinsames Vermischen vollendet wird."},"ICON-2817":{"nm":"Garnelen-Gebratener Reis","de":"Pralle Garnelen treten rosa zwischen den Reiskörnern hervor. Bringt man eine Handvoll Meer ins Gericht, ahmt selbst ein gewöhnliches Mahl ein Festessen nach. Die Süße, die beim Durchbeißen aufgeht, ist wie eine freudige Begrüßung."},"ICON-2818":{"nm":"Jeyuk-Reisschale","de":"Würzig mariniertes Schweinefleisch trifft auf dampfenden Reis. Die Schüssel, die zur Mittagszeit als Erste leer war. Ein Mahl, das einen hektischen Tag sanft aufmuntert."},"ICON-2819":{"nm":"Thunfisch-Mayo-Reis","de":"Eine Dose Thunfisch, ein Strich Mayonnaise und eine warme Schüssel Reis. Die Zutaten sind schlicht, der Trost ist reichlich. In einer Schulnacht heimlich am Schreibtisch gerührt – der Geschmack jener Nacht."},"ICON-2820":{"nm":"Curry mit Reis","de":"Die sämige Goldfarbe füllt den ganzen Teller. Die Sorgfalt, die Kartoffeln und Karotten so lange rührt, bis sie weich zerfallen. Die Gemütlichkeit des Abends, an dem die ganze Familie in denselben Topf schaute."},"ICON-2821":{"nm":"Meeresalgen-Bibimbap","de":"Meeresduftende Stränge treffen auf Gochujang und werden kräftig durchgemischt. Wenn die glitschige, säuerliche Textur den Reis umhüllt, entfaltet sich das Meer, das eine Taucherin mit angehaltenem Atem geborgen hat, in einer Schüssel."},"ICON-2822":{"nm":"Gegrillte Makrele","de":"Der silberne Rücken bräunt sich auf dem Grill. Die Hand, die die Gräten herausgelöst und das Fleisch auf Reis gelegt hat. In einem Stück Blaufisch steckt die stille Liebe dessen, der so jemanden großgezogen und genährt hat."},"ICON-2823":{"nm":"Kartoffelpuffer","de":"An Regentagen in der Bergküche Kärntens gerieben und ausgebacken. Zähe Ränder und knusprige Enden leben in einem einzigen Puffer nebeneinander. Der Teig, der am besten zum Trommeln des Regens ans Fenster passt."},"ICON-2824":{"nm":"Kimchi-Pfannkuchen","de":"In dem Moment, in dem sauer gewordenes Kimchi das geölte Pfanne berührt, füllt sich das ganze Haus mit dem knisternden Geräusch. Ein bräunlicher Kreis, der unweigerlich nach einem Becher Makgeolli ruft. Das Stammgericht, das sich mit dem Regengeräusch unter dem Dachvorsprung zusammentut."},"ICON-2825":{"nm":"Zwiebelkuchen (Pajeon)","de":"Frühlingszwiebeln werden nebeneinandergelegt und mit Teig übergossen, der langsam aushärtet. Eine einzige Platte, die zwischen Knusprigkeit und Weichheit pendelt. Genau das anheimelnd vertraute Bild vom Marktplatz, wo der Dampf aufsteigt."},"ICON-2826":{"nm":"Zucchini-Jeon","de":"Dünn geschnittene Zucchini wird paniert und goldbraun gebraten. Das zartgrüne Rondell, das seinen schlichten Platz auf dem Gedenktischschmuck hielt. Die feierliche Förmlichkeit, die erst durch viel Handarbeit entsteht."},"ICON-2827":{"nm":"Würziger Tintenfisch gebraten","de":"Die roten Würzbeine glänzen satt. Selbst wenn einem die Schärfe auf die Stirn drückt, hören die Stäbchen nicht auf. Ein Teller, auf dem Schweiß und Vergnügen sich mischen."},"ICON-2828":{"nm":"Tteokbokki","de":"Reiskuchen und Fischkuchen versinken in knallroten Gochujang-Sauce. In sich die gesamte Erinnerung an den Imbiss-Nachmittag zu zweit, Münzen zusammengekratzt und geteilt. Der Geschmack der Erinnerung, bei dem allein der Name schon das Wasser im Mund zusammenlaufen lässt."},"ICON-2829":{"nm":"Fischkuchen-Eintopf (Odeng-Tang)","de":"Am Imbissstand schlägt der Dampf der Fischkuchen die Glasscheibe weiß. Hält man einen Spieß in der Hand und nimmt Brühe im Pappbecher – ein Schluck, und die frostige Winternacht wird um einiges wärmer."},"ICON-2830":{"nm":"Tofu-Kimchi","de":"Neben weichem Tofu sitzt würzig gebratenes Kimchi. Kälte und Wärme, Sanftheit und Stärke finden sich auf einem Teller zusammen. Das Begleitpaar, das die Abende der Erwachsenen lange begleitet hat."},"ICON-2831":{"nm":"Würstchen-Gemüsepfanne","de":"Rote Würstchen und Gemüse brutzeln ketchupfarben zusammen. Das Fach, das beim Öffnen der Sportfest-Lunchbox als Erstes leer war. Die Farbe jenes Tages ist geblieben, auch wenn die Zeit längst verflossen ist."},"ICON-2832":{"nm":"Süßkartoffel-Latte","de":"Fein pürierte Süßkartoffel löst sich weich in warmer Milch auf. Die hausgemachte Süße, die auf Koreanisch auf der Karte steht. An Tagen, wenn die Fingerspitzen frieren, hält man das Glas mit beiden Händen – und die Wärme breitet sich sachte aus."},"ICON-2833":{"nm":"Mayonnaise","de":"Eine Soße, die die Küche noch nicht erreicht hat. Bald wird sie als cremefarbenes Symbol gezeichnet. (in Vorbereitung)"}};